// Set to true to enable verbose Planner rendering diagnostics in the console.
// Toggle here without recompiling business logic.
const bool kDebugPlanner = false;

// ─────────────────────────────────────────────────────────────────────────────
// AppTheme — InheritedWidget that propagates isLight to all descendants.
// Use AppTheme.of(context).isLight to query the current mode anywhere.
// ─────────────────────────────────────────────────────────────────────────────

class AppTheme extends InheritedWidget {
  final bool isLight;
  const AppTheme({super.key, required this.isLight, required super.child});

  static AppTheme of(BuildContext context) {
    final r = context.dependOnInheritedWidgetOfExactType<AppTheme>();
    assert(r != null, 'No AppTheme in context');
    return r!;
  }

  // Convenience getter: SpColors token set for the current mode.
  SpColors get colors => SpColors(isLight);

  @override
  bool updateShouldNotify(AppTheme old) => old.isLight != isLight;
}

// ─────────────────────────────────────────────────────────────────────────────
// SpColors — semantic color tokens that flip between dark and light mode.
// ─────────────────────────────────────────────────────────────────────────────

class SpColors {
  final bool isLight;
  const SpColors(this.isLight);

  // Surfaces
  Color get canvasBg =>
      isLight ? const Color(0xFFF2F3F5) : const Color(0xFF12141A);
  Color get sidebarBg =>
      isLight ? const Color(0xFFE8EAED) : const Color(0xFF1A1C22);
  Color get panelBg =>
      isLight ? const Color(0xFFFFFFFF) : const Color(0xFF1E2124);
  Color get cardBg =>
      isLight ? const Color(0xFFFFFFFF) : const Color(0xFF252830);
  Color get headerBg =>
      isLight ? const Color(0xFFECEDF0) : const Color(0xFF181A1C);
  Color get inputBg =>
      isLight ? const Color(0xFFF5F6F8) : const Color(0xFF1C1F24);
  Color get dividerColor =>
      isLight ? const Color(0xFFDDDFE3) : const Color(0xFF2C2F35);
  Color get overlay =>
      isLight ? const Color(0xFFFFFFFF) : const Color(0xFF252830);

  // Text
  Color get textPrimary => isLight ? const Color(0xFF1A1C22) : Colors.white;
  Color get textSecondary => isLight ? const Color(0xFF555D6B) : Colors.white70;
  Color get textDisabled => isLight ? const Color(0xFF9EA7B3) : Colors.white38;
  Color get textHint =>
      isLight ? const Color(0xFFB0B8C4) : const Color(0x44FFFFFF);

  // Borders
  Color get borderSubtle =>
      isLight ? const Color(0xFFD0D4DA) : Colors.white.withOpacity(0.07);
  Color get borderMed =>
      isLight ? const Color(0xFFBBC0C8) : Colors.white.withOpacity(0.12);

  // Accent (same in both modes)
  Color get accent => const Color(0xFF4FC3F7);

  // Scrim
  Color get scrim =>
      isLight ? Colors.black.withOpacity(0.12) : Colors.black.withOpacity(0.35);
}

// ─────────────────────────────────────────────────────────────────────────────
// Contrast-border helpers (Features 4 & 5).
//   Dark mode:  fill luminance < 0.15  → white outline
//   Light mode: fill luminance > 0.85  → black outline
// ─────────────────────────────────────────────────────────────────────────────

const double _kLowLumThreshold = 0.15;
const double _kHighLumThreshold = 0.85;

Border? adaptiveBorder(Color fill, bool isLight) {
  final lum = fill.computeLuminance();
  if (!isLight && lum < _kLowLumThreshold)
    return Border.all(color: Colors.white, width: 1.5);
  if (isLight && lum > _kHighLumThreshold)
    return Border.all(color: Colors.black, width: 1.5);
  return null;
}

BoxDecoration withAdaptiveBorder(
  BoxDecoration base,
  Color fillColor,
  bool isLight,
) {
  final b = adaptiveBorder(fillColor, isLight);
  return b == null ? base : base.copyWith(border: b);
}

