enum TaskStatus {
  none(
    label: 'None',
    color: Color(0xFF9E9E9E),
    icon: Icons.check_box_outline_blank,
  ),
  todo(
    label: 'To Do',
    color: Color(0xFFFFD600),
    icon: Icons.radio_button_unchecked,
  ),
  inProgress(
    label: 'In Progress',
    color: Color(0xFFE91E63),
    icon: Icons.autorenew,
  ),
  done(label: 'Done', color: Color(0xFF4CAF50), icon: Icons.check_box),
  waiting(
    label: 'Waiting',
    color: Color(0xFFFF9800),
    icon: Icons.hourglass_top,
  ),
  cancelled(
    label: 'Cancelled',
    color: Color(0xFFF44336),
    icon: Icons.cancel_outlined,
  ),
  surpassed(label: 'Surpassed', color: Color(0xFF212121), icon: Icons.block);

  final String label;
  final Color color;
  final IconData icon;

  const TaskStatus({
    required this.label,
    required this.color,
    required this.icon,
  });
}

class Task {
  final String id;
  String title; // mutable – editable from canvas
  bool isDone;
  TaskStatus status; // Multi-status indicator
  String projectId; // mutable – editable from details panel

  // Fields from the JSON structure
  final List<dynamic> subTaskIds;
  final int timeSpentOriginal; // keep original for display fallback
  int timeSpent; // mutable – editable from task details panel
  String? dueDay; // mutable – editable from canvas (date portion)
  int? plannedAt; // SP "planned at" unix-ms timestamp — drives canvas position
  int durationMinutes; // schedule block duration (default 30)
  final List<dynamic> attachments;
  final String? repeatCfgId;
  List<dynamic> tagIds;
  String? notes; // mutable – editable from canvas
  RepeatConfig? repeatConfig; // mutable – set via details panel
  String? repeatParentId; // non-null on auto-generated repeat instances

  // UI State fields
  bool isExpanded;
  double cardWidth;
  double cardHeight;
  Set<String> visibleProperties;
  Map<String, double>
  propertyHeights; // NEW: Stores custom heights for each region

  Task({
    required this.id,
    required this.title,
    required this.isDone,
    this.status = TaskStatus.none,
    required this.projectId,
    required this.subTaskIds,
    required this.timeSpent,
    this.dueDay,
    this.plannedAt,
    this.durationMinutes = 30,
    required this.attachments,
    this.repeatCfgId,
    required this.tagIds,
    this.notes,
    this.repeatParentId,
    this.isExpanded = false,
    this.cardWidth = 250,
    this.cardHeight = 250,
    Set<String>? visibleProperties,
    Map<String, double>? propertyHeights,
  }) : timeSpentOriginal = timeSpent,
       visibleProperties = visibleProperties ?? {},
       propertyHeights = propertyHeights ?? {};

  /// Returns the best DateTime for canvas positioning:
  /// 1. plannedAt (unix ms) — highest priority (set by SP scheduler)
  /// 2. dueDay if it contains a time component (T)
  /// 3. null
  ///
  /// Always returns a local-time DateTime so that .hour/.minute correctly
  /// map to the user's wall-clock time on the canvas time-grid.
  DateTime? get scheduledDateTime {
    if (plannedAt != null && plannedAt! > 0) {
      // isUtc defaults to false, but .toLocal() is explicit insurance against
      // any future path that stores a UTC-mode DateTime's millisecondsSinceEpoch.
      return DateTime.fromMillisecondsSinceEpoch(plannedAt!).toLocal();
    }
    if (dueDay != null && dueDay!.contains('T')) {
      return DateTime.tryParse(dueDay!)?.toLocal();
    }
    return null;
  }

  /// Returns the date portion only (for day-column matching), from either
  /// plannedAt or dueDay.
  DateTime? get scheduledDate {
    final dt = scheduledDateTime;
    if (dt != null) return DateTime(dt.year, dt.month, dt.day);
    if (dueDay != null) {
      final d = DateTime.tryParse(dueDay!);
      if (d != null) return DateTime(d.year, d.month, d.day);
    }
    return null;
  }

  factory Task.fromJson(Map<String, dynamic> json) {
    final isDone = json['isDone'] as bool? ?? false;
    // Prefer an explicit 'status' field (written by toJson / workspace save).
    // Fall back to deriving from isDone for SP __meta_ imports that lack it.
    TaskStatus status;
    if (json['status'] is String) {
      try {
        status = TaskStatus.values.byName(json['status'] as String);
      } catch (_) {
        status = isDone ? TaskStatus.done : TaskStatus.none;
      }
    } else {
      status = isDone ? TaskStatus.done : TaskStatus.none;
    }
    return Task(
      id: json['id'] as String,
      title: json['title'] as String,
      isDone: isDone,
      status: status,
      projectId: json['projectId'] as String? ?? 'INBOX_PROJECT',
      subTaskIds: json['subTaskIds'] as List<dynamic>? ?? [],
      timeSpent: json['timeSpent'] as int? ?? 0,
      dueDay: json['dueDay'] as String?,
      plannedAt: json['plannedAt'] as int?,
      durationMinutes: json['durationMinutes'] as int? ?? 30,
      attachments: json['attachments'] as List<dynamic>? ?? [],
      repeatCfgId: json['repeatCfgId'] as String?,
      tagIds: json['tagIds'] as List<dynamic>? ?? [],
      notes: json['notes'] as String?,
      repeatParentId: json['repeatParentId'] as String?,
    );
  }

  Map<String, dynamic> toJson() {
    return {
      'id': id,
      'title': title,
      'isDone': isDone,
      'status': status.name,
      'projectId': projectId,
      'subTaskIds': subTaskIds,
      'timeSpent': timeSpent,
      if (dueDay != null) 'dueDay': dueDay,
      if (plannedAt != null && plannedAt! > 0) 'plannedAt': plannedAt,
      'durationMinutes': durationMinutes,
      'attachments': attachments,
      if (repeatCfgId != null) 'repeatCfgId': repeatCfgId,
      'tagIds': tagIds,
      if (notes != null && notes!.isNotEmpty) 'notes': notes,
      if (repeatParentId != null) 'repeatParentId': repeatParentId,
    };
  }
}

