enum RepeatPreset {
  everyday,
  weekdays, // Mon–Fri
  everyWeek, // same weekday
  everyMonth, // same day of month
  everyYear, // same dd/mm
  custom,
}

enum RepeatCycle { day, week, month, year }

// ── Task list Sort / Group / Filter ──────────────────────────────────────────
// Legacy enums kept for backward-compat references in existing rendering code.

enum TaskSortOption {
  scheduledDate('Scheduled Date'),
  creationDate('Creation Date'),
  estimatedTime('Estimated Time'),
  timeSpent('Time Spent'),
  tag('Tag'),
  name('Name'),
  status('Status');

  final String label;
  const TaskSortOption(this.label);
}

enum TaskGroupOption {
  none('No Group'),
  tag('Tag'),
  project('Project'),
  scheduledDate('Scheduled Date'),
  status('Status');

  final String label;
  const TaskGroupOption(this.label);
}

enum TaskFilterField {
  none('No Filter'),
  name('Name'),
  tag('Tag'),
  project('Project'),
  scheduledDate('Scheduled Date'),
  estimatedTime('Estimated Time'),
  timeSpent('Time Spent'),
  status('Status');

  final String label;
  const TaskFilterField(this.label);
}

// ── Grist-style stackable Filter / Group / Sort data classes ──────────────────

/// A single filter rule targeting one field.
class FilterRule {
  final String id; // unique uuid for key
  TaskFilterField field;
  // Tag / Project / Status: selected values (empty = no constraint)
  Set<String> selectedValues;
  // Name filter (substring search)
  String nameQuery;
  // Date range
  DateTime? dateFrom;
  DateTime? dateTo;
  // Numeric range (minutes)
  int? numMin;
  int? numMax;

  FilterRule({
    required this.id,
    this.field = TaskFilterField.tag,
    Set<String>? selectedValues,
    this.nameQuery = '',
    this.dateFrom,
    this.dateTo,
    this.numMin,
    this.numMax,
  }) : selectedValues = selectedValues ?? {};

  /// Returns true if this rule has at least one value / bound configured.
  bool get isConfigured {
    switch (field) {
      case TaskFilterField.none:
        return false;
      case TaskFilterField.name:
        return nameQuery.trim().isNotEmpty;
      case TaskFilterField.tag:
      case TaskFilterField.project:
      case TaskFilterField.status:
        return selectedValues.isNotEmpty;
      case TaskFilterField.scheduledDate:
        return dateFrom != null || dateTo != null;
      case TaskFilterField.estimatedTime:
      case TaskFilterField.timeSpent:
        return numMin != null || numMax != null;
    }
  }

  bool matches(Task t, Map<String, Project> projects) {
    switch (field) {
      case TaskFilterField.none:
        return true;
      case TaskFilterField.name:
        final q = nameQuery.trim().toLowerCase();
        if (q.isEmpty) return true;
        return t.title.toLowerCase().contains(q);
      case TaskFilterField.tag:
        if (selectedValues.isEmpty) return true;
        return t.tagIds.map((id) => id.toString()).any(selectedValues.contains);
      case TaskFilterField.project:
        if (selectedValues.isEmpty) return true;
        return selectedValues.contains(t.projectId);
      case TaskFilterField.status:
        if (selectedValues.isEmpty) return true;
        return selectedValues.contains(t.status.name);
      case TaskFilterField.scheduledDate:
        final d = t.scheduledDate;
        if (d == null) return false;
        if (dateFrom != null && d.isBefore(dateFrom!)) return false;
        if (dateTo != null && d.isAfter(dateTo!)) return false;
        return true;
      case TaskFilterField.estimatedTime:
        final dur = t.durationMinutes;
        if (numMin != null && dur < numMin!) return false;
        if (numMax != null && dur > numMax!) return false;
        return true;
      case TaskFilterField.timeSpent:
        final spent = t.timeSpent ~/ 60000;
        if (numMin != null && spent < numMin!) return false;
        if (numMax != null && spent > numMax!) return false;
        return true;
    }
  }
}

/// A single group criterion.
class GroupCriterion {
  final String id;
  TaskGroupOption field;
  bool ascending;

  GroupCriterion({
    required this.id,
    this.field = TaskGroupOption.tag,
    this.ascending = true,
  });

  String keyFor(Task t, Map<String, Project> projects) {
    switch (field) {
      case TaskGroupOption.none:
        return '—';
      case TaskGroupOption.tag:
        return t.tagIds.isNotEmpty ? t.tagIds.first.toString() : '—';
      case TaskGroupOption.project:
        if (t.projectId == 'INBOX_PROJECT') return '__inbox__';
        return projects[t.projectId]?.title ?? t.projectId;
      case TaskGroupOption.scheduledDate:
        final d = t.scheduledDate;
        if (d == null) return 'No date';
        return '${d.year}-${d.month.toString().padLeft(2, '0')}-${d.day.toString().padLeft(2, '0')}';
      case TaskGroupOption.status:
        return t.status.label;
    }
  }
}

/// A single sort criterion.
class SortCriterion {
  final String id;
  TaskSortOption field;
  bool ascending;
  bool emptyLast;

  SortCriterion({
    required this.id,
    this.field = TaskSortOption.scheduledDate,
    this.ascending = true,
    this.emptyLast = true,
  });
}

int _compareBySort(Task a, Task b, SortCriterion s) {
  int result;
  switch (s.field) {
    case TaskSortOption.scheduledDate:
      // Use scheduledDateTime (not scheduledDate) so tasks on the same day are
      // ordered by time (e.g. 09:00 before 15:00). plannedAt takes priority
      // over dueDay, matching the same logic in Task.scheduledDateTime.
      final da =
          a.scheduledDateTime ??
          (a.scheduledDate != null ? a.scheduledDate! : null);
      final db =
          b.scheduledDateTime ??
          (b.scheduledDate != null ? b.scheduledDate! : null);
      if (da == null && db == null) return 0;
      if (da == null) return s.emptyLast ? 1 : -1;
      if (db == null) return s.emptyLast ? -1 : 1;
      result = da.compareTo(db);
      break;
    case TaskSortOption.creationDate:
      result = a.id.compareTo(b.id);
      break;
    case TaskSortOption.estimatedTime:
      result = a.durationMinutes.compareTo(b.durationMinutes);
      if (s.emptyLast && a.durationMinutes == 0) return 1;
      if (s.emptyLast && b.durationMinutes == 0) return -1;
      break;
    case TaskSortOption.timeSpent:
      result = a.timeSpent.compareTo(b.timeSpent);
      if (s.emptyLast && a.timeSpent == 0) return 1;
      if (s.emptyLast && b.timeSpent == 0) return -1;
      break;
    case TaskSortOption.tag:
      final ta = a.tagIds.isNotEmpty ? a.tagIds.first.toString() : '';
      final tb = b.tagIds.isNotEmpty ? b.tagIds.first.toString() : '';
      if (s.emptyLast && ta.isEmpty) return 1;
      if (s.emptyLast && tb.isEmpty) return -1;
      result = ta.compareTo(tb);
      break;
    case TaskSortOption.name:
      result = a.title.compareTo(b.title);
      break;
    case TaskSortOption.status:
      result = a.status.index.compareTo(b.status.index);
      break;
  }
  return s.ascending ? result : -result;
}

/// Apply all sort criteria in order (first = primary, rest = tiebreakers).
List<Task> _applySortCriteria(List<Task> tasks, List<SortCriterion> criteria) {
  if (criteria.isEmpty) return tasks;
  final copy = List<Task>.from(tasks);
  copy.sort((a, b) {
    for (final s in criteria) {
      final r = _compareBySort(a, b, s);
      if (r != 0) return r;
    }
    return 0;
  });
  return copy;
}

int _gristIdSeq = 0;

/// Formats a date for display on task card chips.
/// Shows `dd/MM` when [date] is in the current year, `dd/MM/yyyy` otherwise.
/// Returns 'Today' / 'Tomorrow' for those special cases.
String _fmtDateChip(DateTime date) {
  final now = DateTime.now();
  final today = DateTime(now.year, now.month, now.day);
  final d = DateTime(date.year, date.month, date.day);
  if (d == today) return 'Today';
  if (d == today.add(const Duration(days: 1))) return 'Tomorrow';
  final dd = date.day.toString().padLeft(2, '0');
  final mm = date.month.toString().padLeft(2, '0');
  if (date.year == now.year) return '$dd/$mm';
  return '$dd/$mm/${date.year}';
}

String _gristId() => 'gr${++_gristIdSeq}';

/// Controls how edits made inside the Task Details panel propagate
/// to sibling repeat instances.
enum _RepeatPropagateScope {
  current('Current only', Icons.looks_one_outlined),
  forward('This & future', Icons.arrow_forward_rounded),
  backward('This & past', Icons.arrow_back_rounded),
  all('All instances', Icons.select_all_rounded);

  final String label;
  final IconData icon;
  const _RepeatPropagateScope(this.label, this.icon);
}

class RepeatConfig {
  RepeatPreset preset;
  // Custom fields
  int customEvery; // "every N …"
  RepeatCycle customCycle;
  DateTime customStartDate;
  Set<int> customWeekDays; // 1=Mon … 7=Sun (only for week cycle)
  final bool cleared; // sentinel: user hit "Remove"

  /// The date this repeat segment anchors to.
  /// For the parent task's config: drives the series start (and task's plannedAt/dueDay).
  /// For an instance-level override config: equals that instance's scheduledDate.
  DateTime? anchorDate;

  /// Optional hard end-date for this segment.
  /// When set, no instances are generated beyond this date.
  DateTime? endDate;

  /// How many days into the future to generate instances.
  /// Acts as a rolling horizon unless [endDate] is set (whichever is earlier).
  /// When null, only [endDate] controls the horizon (no days cap).
  int? propagationDays;

  RepeatConfig({
    this.preset = RepeatPreset.everyday,
    this.customEvery = 1,
    this.customCycle = RepeatCycle.day,
    DateTime? customStartDate,
    Set<int>? customWeekDays,
    this.cleared = false,
    this.anchorDate,
    this.endDate,
    this.propagationDays,
  }) : customStartDate = customStartDate ?? DateTime.now(),
       customWeekDays = customWeekDays ?? {DateTime.now().weekday};

  String get label {
    switch (preset) {
      case RepeatPreset.everyday:
        return 'Every day';
      case RepeatPreset.weekdays:
        return 'Mon – Fri';
      case RepeatPreset.everyWeek:
        {
          final days = ['Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat', 'Sun'];
          return 'Every ${days[DateTime.now().weekday - 1]}';
        }
      case RepeatPreset.everyMonth:
        {
          final d = DateTime.now().day;
          final suffix = d == 1 || d == 21 || d == 31
              ? 'st'
              : d == 2 || d == 22
              ? 'nd'
              : d == 3 || d == 23
              ? 'rd'
              : 'th';
          return 'Monthly on the $d$suffix';
        }
      case RepeatPreset.everyYear:
        {
          final now = DateTime.now();
          return 'Yearly on ${now.day.toString().padLeft(2, '0')}/${now.month.toString().padLeft(2, '0')}';
        }
      case RepeatPreset.custom:
        {
          final cycleStr = customEvery == 1
              ? customCycle.name
              : '${customCycle.name}s';
          return 'Every $customEvery $cycleStr';
        }
    }
  }
}

class _SubConnectionsPainter extends CustomPainter {
  final List<TaskRelation> relations;
  final Map<String, Offset> taskPositions;

  _SubConnectionsPainter({
    required this.relations,
    required this.taskPositions,
  });

  @override
  void paint(Canvas canvas, Size size) {
    final linePaint = Paint()
      ..color = Colors.orangeAccent.withOpacity(0.8)
      ..strokeWidth = 1.5
      ..style = PaintingStyle.stroke;

    final arrowPaint = Paint()
      ..color = Colors.orangeAccent.withOpacity(0.8)
      ..style = PaintingStyle.fill;

    for (var rel in relations) {
      // Offset by half the width (50) and half the height (12.5) to center the line
      final start =
          (taskPositions[rel.sourceId] ?? const Offset(10, 10)) +
          const Offset(50, 12.5);
      final end =
          (taskPositions[rel.targetId] ?? const Offset(10, 10)) +
          const Offset(50, 12.5);

      final path = Path()
        ..moveTo(start.dx, start.dy)
        ..lineTo(end.dx, end.dy);
      canvas.drawPath(path, linePaint);

      // Draw simple arrowhead at the end
      final double angle = atan2(end.dy - start.dy, end.dx - start.dx);
      final arrowPath = Path();
      arrowPath.moveTo(end.dx, end.dy);
      arrowPath.lineTo(
        end.dx - 8 * cos(angle - pi / 7),
        end.dy - 8 * sin(angle - pi / 7),
      );
      arrowPath.lineTo(
        end.dx - 8 * cos(angle + pi / 7),
        end.dy - 8 * sin(angle + pi / 7),
      );
      arrowPath.close();
      canvas.drawPath(arrowPath, arrowPaint);
    }
  }

  @override
  bool shouldRepaint(covariant _SubConnectionsPainter oldDelegate) => true;
}

enum LogicalOperator {
  and("AND", "&"),
  or("OR", "≥1"),
  xor("XOR", "=1");

  final String label;
  final String symbol;
  const LogicalOperator(this.label, this.symbol);
}

extension LogicalOperatorExtension on LogicalOperator {}

