class TaskRelation {
  final String sourceId;
  final String targetId;
  Offset sourceLocalPos;
  Offset targetLocalPos;

  List<Offset> handles;
  double thickness;
  Color color;
  double arrowSize; // NEW

  TaskRelation({
    required this.sourceId,
    required this.targetId,
    required this.sourceLocalPos,
    required this.targetLocalPos,
    List<Offset>? handles,
    this.thickness = 2.0,
    this.arrowSize = 10.0, // NEW
    Color? color,
  }) : handles = handles ?? [],
       color = color ?? Colors.orangeAccent.withOpacity(0.8);
}

class Project {
  final String id;
  String title; // mutable – validated before every assignment
  final DateTime? createdAt;

  Project({required this.id, required this.title, this.createdAt});

  factory Project.fromJson(Map<String, dynamic> json) {
    DateTime? createdAt;
    final raw = json['created'] ?? json['createdAt'];
    if (raw is int && raw > 0) {
      createdAt = DateTime.fromMillisecondsSinceEpoch(raw);
    } else if (raw is String) {
      createdAt = DateTime.tryParse(raw);
    }
    return Project(
      id: json['id'] as String,
      title: json['title'] as String,
      createdAt: createdAt,
    );
  }

  Map<String, dynamic> toJson() => {
    'id': id,
    'title': title,
    if (createdAt != null) 'createdAt': createdAt!.millisecondsSinceEpoch,
  };
}

// ── Note model ────────────────────────────────────────────────────────────────

enum NoteType { task, project, common }

class Note {
  final String id;
  NoteType type;
  String title; // mirrors task/project title for bound notes
  String content; // markdown body
  final String? linkedTaskId; // non-null for NoteType.task
  final String? linkedProjectId; // non-null for NoteType.project
  DateTime updatedAt;
  String? folderId; // non-null when note belongs to a common-notes folder

  /// Full heading line texts (e.g. "## My Section") that are collapsed.
  /// Stored as text rather than byte-offsets so they survive content edits.
  List<String> collapsedHeadings;

  Note({
    required this.id,
    required this.type,
    required this.title,
    this.content = '',
    this.linkedTaskId,
    this.linkedProjectId,
    DateTime? updatedAt,
    this.folderId,
    List<String>? collapsedHeadings,
  }) : updatedAt = updatedAt ?? DateTime.now(),
       collapsedHeadings = collapsedHeadings ?? [];
}

