  NoteFolder({required this.id, required this.name});
}

class LogicGatePainter extends CustomPainter {
  final LogicalOperator type;
  final Color color;
  final double scale;
  final bool isSelected;

  LogicGatePainter({
    required this.type,
    required this.color,
    required this.scale,
    this.isSelected = false,
  });

  @override
  void paint(Canvas canvas, Size size) {
    final paint = Paint()
      ..color = color
      ..style = PaintingStyle.fill;

    final borderPaint = Paint()
      ..color = Colors.white.withOpacity(0.6)
      ..style = PaintingStyle.stroke
      ..strokeWidth = 2 * scale;

    final path = Path();

    switch (type) {
      case LogicalOperator.and:
        // Standard D-shape for AND
        path.moveTo(0, 0);
        path.lineTo(size.width * 0.5, 0);
        path.arcToPoint(
          Offset(size.width * 0.5, size.height),
          radius: Radius.circular(size.height / 2),
          clockwise: true,
        );
        path.lineTo(0, size.height);
        path.close();
        break;

      case LogicalOperator.or:
      case LogicalOperator.xor:
        // Shield-shape for OR/XOR
        path.moveTo(0, 0);
        path.quadraticBezierTo(
          size.width * 0.3,
          size.height * 0.5,
          0,
          size.height,
        );
        path.quadraticBezierTo(
          size.width * 0.4,
          size.height,
          size.width,
          size.height * 0.5,
        );
        path.quadraticBezierTo(size.width * 0.4, 0, 0, 0);
        path.close();

        if (type == LogicalOperator.xor) {
          // Add the extra back-curve for XOR
          final xorPath = Path();
          xorPath.moveTo(-5 * scale, 0);
          xorPath.quadraticBezierTo(
            (size.width * 0.3) - (5 * scale),
            size.height * 0.5,
            -5 * scale,
            size.height,
          );
          canvas.drawPath(xorPath, borderPaint);
        }
        break;
    }

    canvas.drawPath(path, paint);
    canvas.drawPath(path, borderPaint);
    if (isSelected) {
      final selPaint = Paint()
        ..color = Colors.white.withOpacity(0.7)
        ..style = PaintingStyle.stroke
        ..strokeWidth = 2.5 * scale;
      canvas.drawPath(path, selPaint);
    }
  }

  @override
  bool shouldRepaint(covariant CustomPainter oldDelegate) => true;
}

// ── RhombusPainter — draws a diamond shape for ConditionalNode ───────────────
class RhombusPainter extends CustomPainter {
  final Color color;
  final bool isSelected;

  const RhombusPainter({required this.color, this.isSelected = false});

  @override
  void paint(Canvas canvas, Size size) {
    final cx = size.width / 2;
    final cy = size.height / 2;

    final path = Path()
      ..moveTo(0, cy) // left vertex  (input side)
      ..lineTo(cx, 0) // top vertex
      ..lineTo(size.width, cy) // right vertex (output side)
      ..lineTo(cx, size.height) // bottom vertex
      ..close();

    canvas.drawPath(path, Paint()..color = color);

    // Subtle inner border
    canvas.drawPath(
      path,
      Paint()
        ..color = Colors.white.withOpacity(0.12)
        ..style = PaintingStyle.stroke
        ..strokeWidth = 1.0,
    );

    if (isSelected) {
      canvas.drawPath(
        path,
        Paint()
          ..color = Colors.white.withOpacity(0.65)
          ..style = PaintingStyle.stroke
          ..strokeWidth = 2.0,
      );
    }
  }

  @override
  bool shouldRepaint(covariant RhombusPainter old) =>
      old.color != color || old.isSelected != isSelected;
}

// ── RhombusPlugZonePainter — border-only tints for the three plug zones of a
//    ConditionalNode diamond:
//      • Left half          → Yellow  (input side)
//      • Right half – top   → Green   (true / yes branch)
//      • Right half – bottom→ Red     (false / no  branch)
//    The right half is split by a horizontal line at the rhombus centre (y=cy),
//    running from the centre point (cx, cy) to the right vertex (w, cy).
//    All tints are painted as strokes along the zone boundaries and clipped to
//    the rhombus path so no colour bleeds outside the diamond.
class RhombusPlugZonePainter extends CustomPainter {
  const RhombusPlugZonePainter();

  // Border-only tint colours.
  static const Color _leftColor = Color(0xCCFFD600); // Yellow
  static const Color _topRightColor = Color(0xCC00E676); // Green
  static const Color _botRightColor = Color(0xCCF44336); // Red

  // Thickness of the coloured border strip (in logical pixels before scale).
  static const double _borderW = 9.0;

  Path _rhombusPath(Size size) {
    final cx = size.width / 2;
    final cy = size.height / 2;
    return Path()
      ..moveTo(0, cy)
      ..lineTo(cx, 0)
      ..lineTo(size.width, cy)
      ..lineTo(cx, size.height)
      ..close();
  }

  @override
  void paint(Canvas canvas, Size size) {
    final cx = size.width / 2;
    final cy = size.height / 2;
    final w = size.width;
    final h = size.height;

    final rhombus = _rhombusPath(size);

    final paint = Paint()
      ..style = PaintingStyle.stroke
      ..strokeWidth = _borderW
      ..strokeCap = StrokeCap.butt;

    // ── LEFT HALF: Yellow ─────────────────────────────────────────────────
    // Strokes along: left→top edge, left→bottom edge, and the centre
    // vertical divider (x = cx). Clipped to the left half of the rhombus.
    final leftClip = Path()
      ..moveTo(0, 0)
      ..lineTo(cx, 0)
      ..lineTo(cx, h)
      ..lineTo(0, h)
      ..close();

    canvas.save();
    canvas.clipPath(rhombus);
    canvas.clipPath(leftClip);
    paint.color = _leftColor;
    canvas.drawPath(
      Path()
        ..moveTo(0, cy)
        ..lineTo(cx, 0) // left→top
        ..moveTo(0, cy)
        ..lineTo(cx, h), // left→bottom
      paint,
    );
    canvas.drawLine(Offset(cx, 0), Offset(cx, h), paint); // centre divider
    canvas.restore();

    // ── RIGHT HALF – TOP: Green ───────────────────────────────────────────
    // Strokes along: top→right edge, centre vertical divider (x = cx, upper
    // half), and horizontal mid-divider (y = cy, from cx to right vertex).
    // Clipped to the top-right quadrant of the rhombus.
    final rightTopClip = Path()
      ..moveTo(cx, 0)
      ..lineTo(w, 0)
      ..lineTo(w, cy)
      ..lineTo(cx, cy)
      ..close();

    canvas.save();
    canvas.clipPath(rhombus);
    canvas.clipPath(rightTopClip);
    paint.color = _topRightColor;
    canvas.drawLine(Offset(cx, 0), Offset(w, cy), paint); // top→right edge
    canvas.drawLine(
      Offset(cx, 0),
      Offset(cx, cy),
      paint,
    ); // centre vertical (upper)
    canvas.drawLine(
      Offset(cx, cy),
      Offset(w, cy),
      paint,
    ); // horizontal mid-divider
    canvas.restore();

    // ── RIGHT HALF – BOTTOM: Red ──────────────────────────────────────────
    // Strokes along: right→bottom edge, centre vertical divider (x = cx,
    // lower half), and horizontal mid-divider (y = cy, from cx to right vertex).
    // Clipped to the bottom-right quadrant of the rhombus.
    final rightBotClip = Path()
      ..moveTo(cx, cy)
      ..lineTo(w, cy)
      ..lineTo(w, h)
      ..lineTo(cx, h)
      ..close();

    canvas.save();
    canvas.clipPath(rhombus);
    canvas.clipPath(rightBotClip);
    paint.color = _botRightColor;
    canvas.drawLine(Offset(w, cy), Offset(cx, h), paint); // right→bottom edge
    canvas.drawLine(
      Offset(cx, cy),
      Offset(cx, h),
      paint,
    ); // centre vertical (lower)
    canvas.drawLine(
      Offset(cx, cy),
      Offset(w, cy),
      paint,
    ); // horizontal mid-divider
    canvas.restore();
  }

  @override
  bool shouldRepaint(covariant RhombusPlugZonePainter old) => false;
}

// ── _DashedRectPainter ──────────────────────────────────────────────────────
class _DashedRectPainter extends CustomPainter {
  final Color color;
  const _DashedRectPainter({this.color = const Color(0xAAFFFFFF)});

  @override
  void paint(Canvas canvas, Size size) {
    final paint = Paint()
      ..color = color
      ..style = PaintingStyle.stroke
      ..strokeWidth = 1.5;

    void dash(Offset a, Offset b) {
      final len = (b - a).distance;
      final dir = (b - a) / len;
      double d = 0;
      bool on = true;
      while (d < len) {
        final next = (d + (on ? 6.0 : 4.0)).clamp(0.0, len);
        if (on) canvas.drawLine(a + dir * d, a + dir * next, paint);
        d = next;
        on = !on;
      }
    }

    final r = Rect.fromLTWH(0, 0, size.width, size.height);
    dash(r.topLeft, r.topRight);
    dash(r.topRight, r.bottomRight);
    dash(r.bottomRight, r.bottomLeft);
    dash(r.bottomLeft, r.topLeft);
  }

  @override
  bool shouldRepaint(covariant _DashedRectPainter old) => old.color != color;
}

const double _kRhombusMinWidth = 60.0;
const double _kRhombusMinHeight = 40.0;
const double _kRhombusHideTextWidth = 78.0;
const double _kRhombusHideTextHeight = 52.0;

// ─────────────────────────────────────────────────────────────────────────────
// Gantt Day-Shadow Painter — draws tinted vertical bands per day behind cards
// ─────────────────────────────────────────────────────────────────────────────

class _DayShadowPainter extends CustomPainter {
  final DateTime referenceDay; // Monday of the reference week (day 0)
  final Offset canvasOffset;
  final double scale;
  final List<Color> weekdayColors;
  final bool proportional;
  final double dayWidth; // proportional mode: base px per day
  final Map<DateTime, double> columnWidths; // date-keyed custom widths

  const _DayShadowPainter({
    required this.referenceDay,
    required this.canvasOffset,
    required this.scale,
    required this.weekdayColors,
    required this.proportional,
    required this.dayWidth,
    required this.columnWidths,
  });

  DateTime _idxToDate(int idx) {
    final d = referenceDay.add(Duration(days: idx));
    return DateTime(d.year, d.month, d.day);
  }

  /// Width of day at dayIndex (0-based from referenceDay)
  double _widthAt(int idx) {
    if (proportional) return dayWidth * scale;
    return (columnWidths[_idxToDate(idx)] ?? dayWidth) * scale;
  }

  /// Screen-X of the left edge of dayIndex segment (handles negative idx).
  double _segmentLeft(int idx) {
    double x = canvasOffset.dx; // screen-X of day 0 left edge
    if (idx >= 0) {
      for (int i = 0; i < idx; i++) x += _widthAt(i);
    } else {
      for (int i = -1; i >= idx; i--) x -= _widthAt(i);
    }
    return x;
  }

  @override
  void paint(Canvas canvas, Size size) {
    // Determine which days are visible
    // Work leftward and rightward from day 0 until out of screen
    final paint = Paint()..style = PaintingStyle.fill;

    // Find first visible day
    double curX = canvasOffset.dx;
    int idx = 0;
    // Walk backward to find leftmost visible day
    while (curX > 0 && idx > -365) {
      idx--;
      curX -= _widthAt(idx);
    }
    // Now draw forward until off-screen
    for (int safety = 0; safety < 1000; safety++) {
      final segLeft = _segmentLeft(idx);
      final segW = _widthAt(idx);
      if (segLeft > size.width) break;
      if (segLeft + segW < 0) {
        idx++;
        continue;
      }
      final day = referenceDay.add(Duration(days: idx));
      final wd = (day.weekday - 1) % 7; // 0=Mon
      final color = weekdayColors[wd % weekdayColors.length];
      paint.color = color.withOpacity(0.09);
      canvas.drawRect(Rect.fromLTWH(segLeft, 0, segW, size.height), paint);
      idx++;
    }
  }

  @override
  bool shouldRepaint(_DayShadowPainter old) =>
      old.canvasOffset != canvasOffset ||
      old.scale != scale ||
      old.proportional != proportional ||
      old.dayWidth != dayWidth ||
      old.columnWidths != columnWidths;
}

// ─────────────────────────────────────────────────────────────────────────────
// _GanttDayBar — pinned day-column header bar
//
// Feature 1 — Shift+Drag column resize:
//   • Both edges of every column show a resize cursor when Shift is held.
//   • Left-edge drag resizes the PREVIOUS column (N-1); right-edge drag
//     resizes the current column (N) — standard table convention.
//   • A highlighted vertical line tracks the dragged edge in real time.
//   • Works in BOTH proportional and free-stretch modes; the custom width
//     is always stored in columnWidths regardless of the toggle.
//
// Feature 2 — Right-click to reset an individual column:
//   • Secondary-tap on any day header shows a popup with "Reset to standard
//     width". If the column already has no custom width the item is greyed.
// ─────────────────────────────────────────────────────────────────────────────

class _GanttDayBar extends StatefulWidget {
  final DateTime referenceDay;
  final Offset canvasOffset;
  final double scale;
  final bool proportional;
  final double dayWidth;
  final Map<DateTime, double> columnWidths; // date-keyed custom widths
  final List<Color> weekdayColors;

  /// Called whenever any column width changes (date of column, new unscaled px width).
  final void Function(DateTime date, double newWidth)? onColumnResize;

  /// Called once when a drag gesture finishes (to trigger a save).
  final VoidCallback? onColumnResizeEnd;

  /// Called to reset a single column back to standard width.
  final void Function(DateTime date)? onColumnReset;

  const _GanttDayBar({
    Key? key,
    required this.referenceDay,
    required this.canvasOffset,
    required this.scale,
    required this.proportional,
    required this.dayWidth,
    required this.columnWidths,
    required this.weekdayColors,
    this.onColumnResize,
    this.onColumnResizeEnd,
    this.onColumnReset,
  }) : super(key: key);

  @override
  State<_GanttDayBar> createState() => _GanttDayBarState();
}

class _GanttDayBarState extends State<_GanttDayBar> {
  // ── Shift+Drag state ───────────────────────────────────────────────────────
  /// The day index whose RIGHT edge is currently being dragged.
  /// Left-edge drag of column N maps to _draggingRightOf = N-1.
  int? _draggingRightOf;
  double _dragStartX = 0;
  double _dragStartWidth = 0;

  /// Screen-X of the drag indicator line (null = hidden).
  double? _dragIndicatorX;

  // ── Hover state for edge highlight ────────────────────────────────────────
  /// Index of the column whose right edge the cursor is near (for highlight).
  int? _hoveredRightEdgeOf;

  // ── Helpers ───────────────────────────────────────────────────────────────
  DateTime _idxToDate(int idx) {
    final d = widget.referenceDay.add(Duration(days: idx));
    return DateTime(d.year, d.month, d.day);
  }

  double _widthAt(int idx) {
    // Custom width always takes precedence when set.
    final custom = widget.columnWidths[_idxToDate(idx)];
    if (custom != null) return custom * widget.scale;
    return widget.dayWidth * widget.scale;
  }

  double _segmentLeft(int idx) {
    double x = widget.canvasOffset.dx;
    if (idx >= 0) {
      for (int i = 0; i < idx; i++) x += _widthAt(i);
    } else {
      for (int i = -1; i >= idx; i--) x -= _widthAt(i);
    }
    return x;
  }

  bool get _shiftHeld => HardwareKeyboard.instance.isShiftPressed;

  // ── Drag lifecycle ────────────────────────────────────────────────────────
  void _startDrag(int rightOfIdx, double globalX) {
    final date = _idxToDate(rightOfIdx);
    final currentUnscaled = widget.columnWidths[date] ?? widget.dayWidth;
    setState(() {
      _draggingRightOf = rightOfIdx;
      _dragStartX = globalX;
      _dragStartWidth = currentUnscaled;
      _dragIndicatorX = _segmentLeft(rightOfIdx) + _widthAt(rightOfIdx);
    });
  }

  void _updateDrag(double globalX) {
    final idx = _draggingRightOf;
    if (idx == null) return;
    final delta = (globalX - _dragStartX) / widget.scale;
    final newW = (_dragStartWidth + delta).clamp(40.0, 2000.0);
    final date = _idxToDate(idx);
    widget.onColumnResize?.call(date, newW);
    setState(() {
      _dragIndicatorX = _segmentLeft(idx) + _widthAt(idx);
    });
  }

  void _endDrag() {
    widget.onColumnResizeEnd?.call();
    setState(() {
      _draggingRightOf = null;
      _dragIndicatorX = null;
    });
  }

  // ── Right-click popup ─────────────────────────────────────────────────────
  void _showResetMenu(BuildContext context, int idx, Offset globalPos) {
    final date = _idxToDate(idx);
    final hasCustom = widget.columnWidths.containsKey(date);

    final RenderBox overlay =
        Overlay.of(context).context.findRenderObject()! as RenderBox;
    final RelativeRect position = RelativeRect.fromRect(
      Rect.fromLTWH(globalPos.dx, globalPos.dy, 0, 0),
      Offset.zero & overlay.size,
    );

    showMenu<String>(
      context: context,
      position: position,
      color: const Color(0xFF252729),
      shape: RoundedRectangleBorder(borderRadius: BorderRadius.circular(6)),
      items: [
        PopupMenuItem<String>(
          value: 'reset',
          enabled: hasCustom,
          child: Row(
            children: [
              Icon(
                Icons.restart_alt_rounded,
                size: 14,
                color: hasCustom ? const Color(0xFF4FC3F7) : Colors.white24,
              ),
              const SizedBox(width: 8),
              Text(
                'Reset to standard width',
                style: TextStyle(
                  fontSize: 12,
                  color: hasCustom ? Colors.white : Colors.white30,
                ),
              ),
            ],
          ),
        ),
      ],
    ).then((val) {
      if (val == 'reset') {
        widget.onColumnReset?.call(date);
      }
    });
  }

  // ── Build ─────────────────────────────────────────────────────────────────
  @override
  Widget build(BuildContext context) {
    const double barH = 28;
    const weekdays = ['Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat', 'Sun'];

    return SizedBox(
      height: barH,
      child: LayoutBuilder(
        builder: (_, constraints) {
          final w = constraints.maxWidth;

          // Find first visible segment
          int startIdx = 0;
          double x = widget.canvasOffset.dx;
          while (x < 0 && startIdx < 10000) {
            x += _widthAt(startIdx);
            startIdx++;
          }
          startIdx = (startIdx - 2).clamp(-365, startIdx);

          final segments = <Widget>[];

          for (int safety = 0; safety < 500; safety++) {
            final idx = startIdx + safety;
            final left = _segmentLeft(idx);
            if (left > w) break;
            final segW = _widthAt(idx);
            if (left + segW < 0) continue;

            final day = widget.referenceDay.add(Duration(days: idx));
            final wd = (day.weekday - 1) % 7;
            final color =
                widget.weekdayColors[wd % widget.weekdayColors.length];
            final label = segW > 80
                ? '${weekdays[wd]} ${day.day}/${day.month}'
                : segW > 44
                ? '${day.day}/${day.month}'
                : '';

            // ── Column body (label + right-click) ──────────────────────────
            segments.add(
              Positioned(
                left: left,
                width: segW,
                top: 0,
                height: barH,
                child: GestureDetector(
                  onSecondaryTapUp: (d) =>
                      _showResetMenu(context, idx, d.globalPosition),
                  child: Container(
                    decoration: BoxDecoration(
                      color: color.withOpacity(0.12),
                      border: Border(
                        right: BorderSide(
                          color: Colors.white.withOpacity(0.12),
                        ),
                        bottom: BorderSide(
                          color: color.withOpacity(0.5),
                          width: 2,
                        ),
                      ),
                    ),
                    child: Center(
                      child: Text(
                        label,
                        style: TextStyle(
                          fontSize: 9,
                          fontWeight: FontWeight.w600,
                          color: color.withOpacity(0.9),
                          letterSpacing: 0.4,
                        ),
                        overflow: TextOverflow.ellipsis,
                      ),
                    ),
                  ),
                ),
              ),
            );

            // ── Left-edge resize handle (resizes column idx-1) ─────────────
            // Visible only when Shift is held.
            segments.add(
              Positioned(
                left: left - 5,
                width: 10,
                top: 0,
                height: barH,
                child: MouseRegion(
                  cursor: _shiftHeld
                      ? SystemMouseCursors.resizeColumn
                      : MouseCursor.defer,
                  onEnter: (_) {
                    if (_shiftHeld) {
                      setState(() => _hoveredRightEdgeOf = idx - 1);
                    }
                  },
                  onExit: (_) => setState(() => _hoveredRightEdgeOf = null),
                  child: GestureDetector(
                    onHorizontalDragStart: (d) {
                      if (!_shiftHeld) return;
                      _startDrag(idx - 1, d.globalPosition.dx);
                    },
                    onHorizontalDragUpdate: (d) {
                      if (_draggingRightOf == idx - 1) {
                        _updateDrag(d.globalPosition.dx);
                      }
                    },
                    onHorizontalDragEnd: (_) {
                      if (_draggingRightOf == idx - 1) _endDrag();
                    },
                    child: Container(color: Colors.transparent),
                  ),
                ),
              ),
            );

            // ── Right-edge resize handle (resizes column idx) ──────────────
            segments.add(
              Positioned(
                left: left + segW - 5,
                width: 10,
                top: 0,
                height: barH,
                child: MouseRegion(
                  cursor: _shiftHeld
                      ? SystemMouseCursors.resizeColumn
                      : MouseCursor.defer,
                  onEnter: (_) {
                    if (_shiftHeld) {
                      setState(() => _hoveredRightEdgeOf = idx);
                    }
                  },
                  onExit: (_) => setState(() => _hoveredRightEdgeOf = null),
                  child: GestureDetector(
                    onHorizontalDragStart: (d) {
                      if (!_shiftHeld) return;
                      _startDrag(idx, d.globalPosition.dx);
                    },
                    onHorizontalDragUpdate: (d) {
                      if (_draggingRightOf == idx) {
                        _updateDrag(d.globalPosition.dx);
                      }
                    },
                    onHorizontalDragEnd: (_) {
                      if (_draggingRightOf == idx) _endDrag();
                    },
                    child: Container(color: Colors.transparent),
                  ),
                ),
              ),
            );

            // ── Edge highlight when hovered (Shift held) ───────────────────
            if (_hoveredRightEdgeOf == idx && _draggingRightOf == null) {
              final edgeX = left + segW;
              segments.add(
                Positioned(
                  left: edgeX - 1,
                  width: 2,
                  top: 0,
                  height: barH,
                  child: IgnorePointer(
                    child: Container(
                      color: const Color(0xFF4FC3F7).withOpacity(0.5),
                    ),
                  ),
                ),
              );
            }
          }

          // ── Live drag indicator line ───────────────────────────────────
          if (_dragIndicatorX != null) {
            segments.add(
              Positioned(
                left: _dragIndicatorX! - 1,
                width: 2,
                top: 0,
                height: barH,
                child: IgnorePointer(
                  child: Container(
                    decoration: BoxDecoration(
                      color: const Color(0xFF4FC3F7),
                      boxShadow: [
                        BoxShadow(
                          color: const Color(0xFF4FC3F7).withOpacity(0.6),
                          blurRadius: 6,
                          spreadRadius: 1,
                        ),
                      ],
                    ),
                  ),
                ),
              ),
            );
          }

          return Container(
            width: w,
            color: const Color(
              0xFF181A1C,
            ), // Gantt header — kept dark intentionally in both modes for contrast with canvas
            child: Stack(clipBehavior: Clip.hardEdge, children: segments),
          );
        },
      ),
    );
  }
}

// ─────────────────────────────────────────────────────────────────────────────
// GanttProjectAxis — left-hand swim-lane strip
// ─────────────────────────────────────────────────────────────────────────────

class _GanttProjectAxis extends StatelessWidget {
  final List<MapEntry<String, String>> projectEntries; // id → title
  final Map<String, Color> projectColors;
  final Map<String, double> laneHeights;
  final double defaultLaneH;
  final Offset canvasOffset;
  final void Function(String projectId, double newHeight) onLaneResize;

  const _GanttProjectAxis({
    Key? key,
    required this.projectEntries,
    required this.projectColors,
    required this.laneHeights,
    required this.defaultLaneH,
    required this.canvasOffset,
    required this.onLaneResize,
  }) : super(key: key);

  @override
  Widget build(BuildContext context) {
    const double axisW = 120;
    return SizedBox(
      width: axisW,
      child: LayoutBuilder(
        builder: (_, constraints) {
          final items = <Widget>[];
          double y = canvasOffset.dy;

          // Inbox lane first
          final allEntries = [
            MapEntry('INBOX_PROJECT', 'Inbox'),
            ...projectEntries,
          ];

          for (final entry in allEntries) {
            final pid = entry.key;
            final title = entry.value;
            final lh = laneHeights[pid] ?? defaultLaneH;
            final color = pid == 'INBOX_PROJECT'
                ? Colors.white38
                : (projectColors[pid] ?? const Color(0xFF4FC3F7));

            items.add(
              Positioned(
                left: 0,
                top: y,
                width: axisW,
                height: lh,
                child: Container(
                  decoration: BoxDecoration(
                    color: color.withOpacity(0.06),
                    border: Border(
                      bottom: BorderSide(color: Colors.white.withOpacity(0.06)),
                      right: BorderSide(color: Colors.white.withOpacity(0.1)),
                    ),
                  ),
                  child: Padding(
                    padding: const EdgeInsets.only(left: 8, top: 6),
                    child: Row(
                      children: [
                        Container(
                          width: 8,
                          height: 8,
                          decoration: BoxDecoration(
                            color: color,
                            shape: BoxShape.circle,
                          ),
                        ),
                        const SizedBox(width: 6),
                        Expanded(
                          child: Text(
                            title,
                            style: TextStyle(
                              fontSize: 10,
                              fontWeight: FontWeight.w600,
                              color: color,
                            ),
                            overflow: TextOverflow.ellipsis,
                          ),
                        ),
                      ],
                    ),
                  ),
                ),
              ),
            );

            // Resize handle
            items.add(
              Positioned(
                left: 0,
                top: y + lh - 8,
                width: axisW,
                height: 10,
                child: MouseRegion(
                  cursor: SystemMouseCursors.resizeRow,
                  child: _LaneResizeHandle(
                    projectId: pid,
                    currentHeight: lh,
                    onResize: (newH) => onLaneResize(pid, newH),
                  ),
                ),
              ),
            );

            y += lh;
          }

          return Container(
            color: const Color(0xFF1A1C1E),
            child: Stack(clipBehavior: Clip.hardEdge, children: items),
          );
        },
      ),
    );
  }
}

class _LaneResizeHandle extends StatefulWidget {
  final String projectId;
  final double currentHeight;
  final void Function(double) onResize;
  const _LaneResizeHandle({
    required this.projectId,
    required this.currentHeight,
    required this.onResize,
  });
  @override
  State<_LaneResizeHandle> createState() => _LaneResizeHandleState();
}

class _LaneResizeHandleState extends State<_LaneResizeHandle> {
  double _startY = 0;
  double _startH = 0;
  @override
  Widget build(BuildContext context) {
    return GestureDetector(
      onVerticalDragStart: (d) {
        _startY = d.globalPosition.dy;
        _startH = widget.currentHeight;
      },
      onVerticalDragUpdate: (d) {
        final delta = d.globalPosition.dy - _startY;
        widget.onResize((_startH + delta).clamp(60.0, 800.0));
      },
      child: Container(color: Colors.transparent),
    );
  }
}

class GridPainter extends CustomPainter {
  final Offset offset;
  final double gridSize;
  final double scale;
  final double thickness;
  final Color color;

  GridPainter({
    required this.offset,
    this.gridSize = 40.0,
    this.scale = 1.0,
    required this.thickness,
    required this.color,
  });

  @override
  void paint(Canvas canvas, Size size) {
    final paint = Paint()
      ..color = color
      ..strokeWidth =
          thickness * scale; // Scale the thickness so it zooms naturally

    double scaledGridSize = gridSize * scale;

    if (scaledGridSize < 5.0) return;

    double startX = offset.dx % scaledGridSize;
    double startY = offset.dy % scaledGridSize;

    // Draw vertical lines
    for (double x = startX; x < size.width; x += scaledGridSize) {
      canvas.drawLine(Offset(x, 0), Offset(x, size.height), paint);
    }
    // Draw horizontal lines
    for (double y = startY; y < size.height; y += scaledGridSize) {
      canvas.drawLine(Offset(0, y), Offset(size.width, y), paint);
    }
  }

  @override
  bool shouldRepaint(GridPainter oldDelegate) =>
      oldDelegate.offset != offset ||
      oldDelegate.scale != scale ||
      oldDelegate.thickness != thickness ||
      oldDelegate.color != color;
}

// --- 3. REUSABLE ITEM SWITCHER DIALOG ---
// ─────────────────────────────────────────────────────────────────────────────
// ItemSwitcherDialog
//
// A generic, searchable, sortable picker modal.  Feed it any list of items and
// it renders the same polished UI used for Workspace switching and Canvas
// switching.
//
// Required:
//   items        – List<Map<String,String>>, each map must contain 'name'.
//                  Optionally include 'subtitle' for a second line.
//   title        – Header label shown at the top of the modal.
//   hintText     – Placeholder text inside the search field.
//   itemIcon     – Icon drawn in the leading avatar of each row.
//   itemIconColor – Colour of that icon / avatar background.
//   onSelect     – Callback receiving the chosen item map.
//
// Optional:
//   selectedName  – 'name' value of the currently active item (shows a check).
//   bottomAction  – Any widget rendered below the list (e.g. "Create New…").
// ─────────────────────────────────────────────────────────────────────────────

class ItemSwitcherDialog extends StatefulWidget {
  final List<Map<String, String>> items;
  final String title;
  final String hintText;
  final IconData itemIcon;
  final Color itemIconColor;
  final String? selectedName;
  final void Function(Map<String, String> item) onSelect;
  final void Function(Map<String, String> item, String newName)? onRename;
  final void Function(Map<String, String> item)? onDelete;
  final Widget? bottomAction;
  final bool allowDismiss;

  const ItemSwitcherDialog({
    super.key,
    required this.items,
    required this.title,
    required this.hintText,
    required this.itemIcon,
    required this.itemIconColor,
    required this.onSelect,
    this.onRename,
    this.onDelete,
    this.selectedName,
    this.bottomAction,
    this.allowDismiss = true,
  });

  @override
  State<ItemSwitcherDialog> createState() => _ItemSwitcherDialogState();
}

class _ItemSwitcherDialogState extends State<ItemSwitcherDialog> {
  String _query = '';
  bool _sortAsc = true;

  void _showRenameDialog(BuildContext context, Map<String, String> item) {
    final TextEditingController ctrl = TextEditingController(
      text: item['name'],
    );
    showDialog(
      context: context,
      builder: (ctx) => AlertDialog(
        backgroundColor: const Color(0xFF252525),
        title: const Text(
          "Rename Item",
          style: TextStyle(color: Colors.white, fontSize: 14),
        ),
        content: TextField(
          controller: ctrl,
          autofocus: true,
          style: const TextStyle(color: Colors.white, fontSize: 13),
          decoration: const InputDecoration(
            enabledBorder: UnderlineInputBorder(
              borderSide: BorderSide(color: Colors.white24),
            ),
            focusedBorder: UnderlineInputBorder(
              borderSide: BorderSide(color: Colors.blueAccent),
            ),
          ),
        ),
        actions: [
          TextButton(
            onPressed: () => Navigator.pop(ctx),
            child: const Text(
              "Cancel",
              style: TextStyle(color: Colors.white38),
            ),
          ),
          TextButton(
            onPressed: () {
              if (ctrl.text.trim().isNotEmpty && widget.onRename != null) {
                widget.onRename!(item, ctrl.text.trim());
                Navigator.pop(ctx);
              }
            },
            child: const Text(
              "Save",
              style: TextStyle(color: Colors.blueAccent),
            ),
          ),
        ],
      ),
    );
  }

  @override
  Widget build(BuildContext context) {
    // Filter then sort
    final filtered =
        widget.items
            .where(
              (i) => (i['name'] ?? '').toLowerCase().contains(
                _query.toLowerCase(),
              ),
            )
            .toList()
          ..sort(
            (a, b) => _sortAsc
                ? (a['name'] ?? '').compareTo(b['name'] ?? '')
                : (b['name'] ?? '').compareTo(a['name'] ?? ''),
          );

    return Dialog(
      backgroundColor: const Color(0xFF252525),
      shape: RoundedRectangleBorder(borderRadius: BorderRadius.circular(8)),
      child: SizedBox(
        width: 400,
        height: 500,
        child: Column(
          children: [
            // ── Header ──────────────────────────────────────────────────────
            Container(
              padding: const EdgeInsets.fromLTRB(16, 14, 8, 14),
              decoration: const BoxDecoration(
                color: Color(0xFF2A2A2A),
                borderRadius: BorderRadius.vertical(top: Radius.circular(8)),
                border: Border(bottom: BorderSide(color: Colors.white10)),
              ),
              child: Row(
                children: [
                  Icon(widget.itemIcon, size: 16, color: widget.itemIconColor),
                  const SizedBox(width: 10),
                  Expanded(
                    child: Text(
                      widget.title.toUpperCase(),
                      style: const TextStyle(
                        color: Colors.white54,
                        fontSize: 10,
                        fontWeight: FontWeight.bold,
                        letterSpacing: 1.2,
                      ),
                    ),
                  ),
                  if (widget.allowDismiss)
                    IconButton(
                      icon: const Icon(
                        Icons.close,
                        size: 16,
                        color: Colors.white38,
                      ),
                      padding: EdgeInsets.zero,
                      constraints: const BoxConstraints(),
                      onPressed: () => Navigator.pop(context),
                    ),
                ],
              ),
            ),

            // ── Search + Sort bar ────────────────────────────────────────────
            Padding(
              padding: const EdgeInsets.fromLTRB(12, 12, 12, 8),
              child: Row(
                children: [
                  Expanded(
                    child: TextField(
                      autofocus: true,
                      onChanged: (v) => setState(() => _query = v),
                      style: const TextStyle(color: Colors.white, fontSize: 13),
                      decoration: InputDecoration(
                        hintText: widget.hintText,
                        hintStyle: const TextStyle(color: Colors.white38),
                        prefixIcon: const Icon(
                          Icons.search,
                          color: Colors.white38,
                          size: 18,
                        ),
                        isDense: true,
                        filled: true,
                        fillColor: const Color(0xFF1E1E1E),
                        border: OutlineInputBorder(
                          borderRadius: BorderRadius.circular(4),
                          borderSide: BorderSide.none,
                        ),
                        contentPadding: const EdgeInsets.symmetric(
                          vertical: 10,
                        ),
                      ),
                    ),
                  ),
                  const SizedBox(width: 8),
                  // Sort toggle button
                  Tooltip(
                    message: _sortAsc ? 'Sort Z → A' : 'Sort A → Z',
                    child: InkWell(
                      borderRadius: BorderRadius.circular(4),
                      onTap: () => setState(() => _sortAsc = !_sortAsc),
                      child: Container(
                        width: 36,
                        height: 36,
                        decoration: BoxDecoration(
                          color: const Color(0xFF1E1E1E),
                          borderRadius: BorderRadius.circular(4),
                        ),
                        child: Center(
                          child: Text(
                            _sortAsc ? 'A↓Z' : 'Z↓A',
                            style: TextStyle(
                              color: widget.itemIconColor,
                              fontSize: 10,
                              fontWeight: FontWeight.bold,
                              letterSpacing: 0.5,
                            ),
                          ),
                        ),
                      ),
                    ),
                  ),
                ],
              ),
            ),

            const Divider(color: Colors.white10, height: 1),

            // ── List ─────────────────────────────────────────────────────────
            Expanded(
              child: filtered.isEmpty
                  ? Center(
                      child: Text(
                        _query.isEmpty
                            ? 'No items'
                            : 'No results for "$_query"',
                        style: const TextStyle(
                          color: Colors.white24,
                          fontSize: 13,
                        ),
                      ),
                    )
                  : ListView.builder(
                      itemCount: filtered.length,
                      itemBuilder: (context, index) {
                        final item = filtered[index];
                        final isSelected = item['name'] == widget.selectedName;
                        return ListTile(
                          dense: true,
                          leading: CircleAvatar(
                            radius: 14,
                            backgroundColor: widget.itemIconColor.withOpacity(
                              0.15,
                            ),
                            child: Icon(
                              widget.itemIcon,
                              size: 14,
                              color: widget.itemIconColor,
                            ),
                          ),
                          title: Text(
                            item['name'] ?? '',
                            style: TextStyle(
                              color: isSelected
                                  ? widget.itemIconColor
                                  : Colors.white,
                              fontSize: 13,
                              fontWeight: isSelected
                                  ? FontWeight.bold
                                  : FontWeight.normal,
                            ),
                          ),
                          subtitle: item['subtitle'] != null
                              ? Text(
                                  item['subtitle']!,
                                  style: const TextStyle(
                                    color: Colors.white38,
                                    fontSize: 11,
                                  ),
                                )
                              : null,
                          trailing: Row(
                            mainAxisSize: MainAxisSize.min,
                            children: [
                              if (isSelected)
                                Icon(
                                  Icons.check_circle,
                                  size: 16,
                                  color: widget.itemIconColor,
                                ),
                              if (widget.onRename != null ||
                                  widget.onDelete != null) ...[
                                if (isSelected) const SizedBox(width: 8),
                                PopupMenuButton<String>(
                                  icon: const Icon(
                                    Icons.more_vert,
                                    size: 16,
                                    color: Colors.white38,
                                  ),
                                  color: const Color(0xFF2A2A2A),
                                  padding: EdgeInsets.zero,
                                  onSelected: (val) {
                                    if (val == 'rename') {
                                      _showRenameDialog(context, item);
                                    } else if (val == 'delete' &&
                                        widget.onDelete != null) {
                                      widget.onDelete!(item);
                                      setState(() {}); // rebuild filtered list
                                    }
                                  },
                                  itemBuilder: (context) => [
                                    if (widget.onRename != null)
                                      const PopupMenuItem(
                                        value: 'rename',
                                        height: 35,
                                        child: Text(
                                          "Rename",
                                          style: TextStyle(
                                            color: Colors.white,
                                            fontSize: 13,
                                          ),
                                        ),
                                      ),
                                    if (widget.onDelete != null)
                                      const PopupMenuItem(
                                        value: 'delete',
                                        height: 35,
                                        child: Text(
                                          "Delete",
                                          style: TextStyle(
                                            color: Colors.redAccent,
                                            fontSize: 13,
                                          ),
                                        ),
                                      ),
                                  ],
                                ),
                              ],
                            ],
                          ),
                          onTap: () {
                            widget.onSelect(item);
                            Navigator.pop(context);
                          },
                        );
                      },
                    ),
            ),

            // ── Optional bottom action ───────────────────────────────────────
            if (widget.bottomAction != null) ...[
              const Divider(color: Colors.white10, height: 1),
              Padding(
                padding: const EdgeInsets.all(12),
                child: widget.bottomAction!,
              ),
            ],
          ],
        ),
      ),
    );
  }
}

