/// Ensures [color] is legible on a dark background by boosting its lightness
/// if it falls below [threshold] (0–1 relative to HSL lightness).
Color ensureAccentVisible(Color color, {double threshold = 0.18}) {
  final hsl = HSLColor.fromColor(color);
  if (hsl.lightness >= threshold) return color;
  return hsl.withLightness(threshold + 0.18).toColor();
}

void main() => runApp(const _ChaosControlApp());

// ─────────────────────────────────────────────────────────────────────────────
// _SplashScreen — shown for ~2.5 s on launch, then fades into the main UI.
// ─────────────────────────────────────────────────────────────────────────────

class _SplashScreen extends StatefulWidget {
  final void Function(bool isLight)? onThemeChange;
  const _SplashScreen({this.onThemeChange});

  @override
  State<_SplashScreen> createState() => _SplashScreenState();
}

class _SplashScreenState extends State<_SplashScreen>
    with SingleTickerProviderStateMixin {
  late final AnimationController _ctrl;
  late final Animation<double> _fadeOut;

  @override
  void initState() {
    super.initState();
    _ctrl = AnimationController(
      vsync: this,
      duration: const Duration(milliseconds: 600),
    );
    _fadeOut = CurvedAnimation(parent: _ctrl, curve: Curves.easeIn);

    // Wait 2.5 s then fade out and navigate.
    Future.delayed(const Duration(milliseconds: 2500), () {
      if (!mounted) return;
      _ctrl.forward().then((_) {
        if (!mounted) return;
        Navigator.of(context).pushReplacement(
          PageRouteBuilder(
            pageBuilder: (_, __, ___) =>
                ResizableScreen(onThemeChange: widget.onThemeChange),
            transitionDuration: Duration.zero,
          ),
        );
      });
    });
  }

  @override
  void dispose() {
    _ctrl.dispose();
    super.dispose();
  }

  @override
  Widget build(BuildContext context) {
    return FadeTransition(
      opacity: ReverseAnimation(_fadeOut),
      child: Scaffold(
        backgroundColor: Colors.black,
        body: SizedBox.expand(
          child: Image.asset('assets/images/splash.png', fit: BoxFit.cover),
        ),
      ),
    );
  }
}

