class TrapeziumPainter extends CustomPainter {
  @override
  void paint(Canvas canvas, Size size) {
    final paint = Paint()
      ..color = Colors.blueGrey.shade800
      ..style = PaintingStyle.fill;
    final borderPaint = Paint()
      ..color = Colors.blueAccent
      ..strokeWidth = 2
      ..style = PaintingStyle.stroke;

    final path = Path()
      ..moveTo(0, 0) // Top Left
      ..lineTo(size.width, size.height * 0.25) // Top Right (smaller)
      ..lineTo(size.width, size.height * 0.75) // Bottom Right (smaller)
      ..lineTo(0, size.height) // Bottom Left
      ..close();

    canvas.drawPath(path, paint);
    canvas.drawPath(path, borderPaint);
  }

  @override
  bool shouldRepaint(covariant CustomPainter oldDelegate) => false;
}

class ConnectionsPainter extends CustomPainter {
  final Set<TaskRelation> relations;
  final Map<String, Offset> taskPositions;
  final List<JunctionNode> junctions;
  final List<ConditionalNode> conditionals; // NEW
  final double scale;
  final Offset canvasOffset;
  final String? connectingSourceId;
  final Offset? connectingSourceLocalPos;
  final Offset? currentCursorLocalPos;
  final String? selectedRelationKey;

  ConnectionsPainter({
    required this.relations,
    required this.taskPositions,
    required this.junctions,
    this.conditionals = const [], // NEW
    required this.scale,
    required this.canvasOffset,
    required this.connectingSourceId,
    required this.connectingSourceLocalPos,
    required this.currentCursorLocalPos,
    this.selectedRelationKey,
  });

  @override
  void paint(Canvas canvas, Size size) {
    final nodePaintSource = Paint()..color = Colors.orangeAccent;
    final nodePaintTarget = Paint()..color = Colors.greenAccent;

    Offset getAbsolutePos(String id, Offset local) {
      if (taskPositions.containsKey(id)) {
        return (taskPositions[id]! * scale) + canvasOffset + (local * scale);
      }
      final jncIdx = junctions.indexWhere((j) => j.id == id);
      if (jncIdx != -1) {
        return (junctions[jncIdx].position * scale) +
            canvasOffset +
            (local * scale);
      }
      final cndIdx = conditionals.indexWhere((c) => c.id == id);
      if (cndIdx != -1) {
        return (conditionals[cndIdx].position * scale) +
            canvasOffset +
            (local * scale);
      }
      // Fallback — should never happen
      return canvasOffset + (local * scale);
    }

    // Draw saved relations
    for (final rel in relations) {
      final start = getAbsolutePos(rel.sourceId, rel.sourceLocalPos);
      final end = getAbsolutePos(rel.targetId, rel.targetLocalPos);

      final String relKey = '${rel.sourceId}→${rel.targetId}';
      final bool isSelected = relKey == selectedRelationKey;

      // Draw selection glow behind the line
      if (isSelected) {
        final glowPaint = Paint()
          ..color = Colors.white.withOpacity(0.25)
          ..strokeWidth = (rel.thickness + 6) * scale
          ..style = PaintingStyle.stroke
          ..strokeCap = StrokeCap.round;
        Path glowPath = Path()..moveTo(start.dx, start.dy);
        if (rel.handles.isEmpty) {
          glowPath.lineTo(end.dx, end.dy);
        } else {
          List<Offset> pts = [start];
          for (var h in rel.handles) pts.add((h * scale) + canvasOffset);
          pts.add(end);
          for (int i = 0; i < pts.length - 1; i++) {
            var p0 = pts[i];
            var p1 = pts[i + 1];
            var mid = Offset((p0.dx + p1.dx) / 2, (p0.dy + p1.dy) / 2);
            if (i == 0)
              glowPath.lineTo(mid.dx, mid.dy);
            else
              glowPath.quadraticBezierTo(p0.dx, p0.dy, mid.dx, mid.dy);
            if (i == pts.length - 2) glowPath.lineTo(p1.dx, p1.dy);
          }
        }
        canvas.drawPath(glowPath, glowPaint);
      }

      final linePaint = Paint()
        ..color = isSelected ? Colors.white : rel.color
        ..strokeWidth = rel.thickness * scale
        ..style = PaintingStyle.stroke;

      final arrowPaint = Paint()
        ..color = isSelected ? Colors.white : rel.color
        ..style = PaintingStyle.fill;

      Path path = Path()..moveTo(start.dx, start.dy);

      if (rel.handles.isEmpty) {
        path.lineTo(end.dx, end.dy);
      } else {
        // Draw Bezier Curve through handles
        // For simplicity, we create a smooth path using the handles as control points
        List<Offset> points = [start];
        for (var h in rel.handles) {
          points.add((h * scale) + canvasOffset);
        }
        points.add(end);

        for (int i = 0; i < points.length - 1; i++) {
          var p0 = points[i];
          var p1 = points[i + 1];
          var mid = Offset((p0.dx + p1.dx) / 2, (p0.dy + p1.dy) / 2);
          if (i == 0) {
            path.lineTo(mid.dx, mid.dy);
          } else {
            path.quadraticBezierTo(p0.dx, p0.dy, mid.dx, mid.dy);
          }
          if (i == points.length - 2) {
            path.lineTo(p1.dx, p1.dy);
          }
        }
      }

      canvas.drawPath(path, linePaint);

      // Draw Arrow Head at the end of the path
      final double distance = (end - start).distance; // Rough approx for arrow
      if (distance > 15.0 * scale) {
        final double arrowSize =
            rel.arrowSize; // NEW: Uses the relation's specific size

        // Determine angle from last segment
        Offset lastPoint = rel.handles.isEmpty
            ? start
            : (rel.handles.last * scale) + canvasOffset;
        final double angle = atan2(
          end.dy - lastPoint.dy,
          end.dx - lastPoint.dx,
        );
        final arrowPath = Path();
        arrowPath.moveTo(end.dx, end.dy);
        arrowPath.lineTo(
          end.dx - arrowSize * scale * cos(angle - pi / 7),
          end.dy - arrowSize * scale * sin(angle - pi / 7),
        );
        arrowPath.lineTo(
          end.dx - arrowSize * scale * cos(angle + pi / 7),
          end.dy - arrowSize * scale * sin(angle + pi / 7),
        );
        arrowPath.close();
        canvas.drawPath(arrowPath, arrowPaint);
      }

      canvas.drawCircle(start, 4 * scale, nodePaintSource);
      canvas.drawCircle(end, 4 * scale, nodePaintTarget);
    }

    // Draw active follower line
    if (connectingSourceId != null &&
        connectingSourceLocalPos != null &&
        currentCursorLocalPos != null) {
      final start = getAbsolutePos(
        connectingSourceId!,
        connectingSourceLocalPos!,
      );
      final followerPaint = Paint()
        ..color = Colors.orangeAccent.withOpacity(0.5)
        ..strokeWidth = 2.0 * scale
        ..style = PaintingStyle.stroke;
      canvas.drawLine(start, currentCursorLocalPos!, followerPaint);
      canvas.drawCircle(start, 4 * scale, nodePaintSource);
    }
  }

  @override
  bool shouldRepaint(covariant ConnectionsPainter oldDelegate) => true;
}

