  @override
  void initState() {
    super.initState();
    _canvasNameController = TextEditingController(text: _currentCanvasName);
    _categoriesGroupNameController = TextEditingController(
      text: _currentCategoriesGroupName,
    );
    // No workspace selected on startup — user picks one from the dialog
    HardwareKeyboard.instance.addHandler(_handleKeyboardEvent);

    // Load general.json first, then either restore the last workspace or
    // show the picker when none is recorded / the folder was moved/deleted.
    WidgetsBinding.instance.addPostFrameCallback((_) async {
      await _loadGeneral();
      if (!mounted) return;

      // Try to auto-open the most-recently used workspace.
      if (_lastWorkspaceId.isNotEmpty) {
        final entry = _savedWorkspaces.firstWhere(
          (w) => w['id'] == _lastWorkspaceId,
          orElse: () => <String, String>{},
        );
        if (entry.isNotEmpty) {
          // The entry was already validated in _loadGeneral (file exists).
          await _loadWorkspaceById(entry);
          return; // skip the dialog entirely
        }
      }

      // No last workspace recorded, or it no longer exists — show the picker.
      _showSwitchWorkspaceDialog(allowDismiss: false);
    });

    // Autosave timer set to trigger every 3 seconds to save layout/modifications
    _autoSaveTimer = Timer.periodic(const Duration(seconds: 3), (_) {
      _saveWorkspace();
    });

    // Schedule view init
    final now = DateTime.now();
    final weekday = now.weekday; // 1=Mon
    _scheduleWeekStart = DateTime(now.year, now.month, now.day - (weekday - 1));
  }

  @override
  void dispose() {
    _autoSaveTimer?.cancel();
    _taskTimer?.cancel();
    _generalTimer?.cancel();
    _generalOverlayEntry?.remove();
    _canvasNameController.dispose();
    _categoriesGroupNameController.dispose();
    _notesOrgTasksSearchCtrl.dispose();
    _notesOrgTasksFolderCtrl.dispose();
    _notesOrgTasksRenameFolderCtrl.dispose();
    _notesOrgNotesSearchCtrl.dispose();
    _notesOrgNotesFolderCtrl.dispose();
    _notesOrgNotesRenameFolderCtrl.dispose();
    HardwareKeyboard.instance.removeHandler(_handleKeyboardEvent);
    super.dispose();
  }

  // --- AUTOSAVE MECHANISMS ---

  double _getGateX(
    double localY,
    double width,
    double height,
    LogicalOperator type,
    bool isInput,
  ) {
    double ny = (localY / height).clamp(0.0, 1.0);

    if (!isInput &&
        (type == LogicalOperator.or || type == LogicalOperator.xor)) {
      ny = ny.clamp(0.35, 0.65);
    }

    if (type == LogicalOperator.and) {
      if (isInput) return 0.0;
      double radius = height / 2;
      double dy = (ny * height) - radius;
      double dx = sqrt(max(0, pow(radius, 2) - pow(dy, 2)));
      return (width * 0.5) +
          dx; // Corrected to match LogicGatePainter (starts at center)
    } else {
      if (isInput) {
        // Concave back curve logic:
        // Midpoint x is 0.15w (coefficient 0.6).
        // For XOR, we subtract 5 to align with the outer visual curve offset.
        double baseX = 0.6 * width * ny * (1 - ny);
        return (type == LogicalOperator.xor) ? baseX - 5 : baseX;
      } else {
        // Use sqrt to correctly invert the quadratic Bezier y-position for the border x-coordinate
        // This ensures the plug follows the convex "tip" of OR/XOR gates
        double t = (ny <= 0.5) ? sqrt(ny / 0.5) : sqrt((1.0 - ny) / 0.5);
        return width * (0.8 * t + 0.2 * t * t);
      }
    }
  }

  /// Recomputes plug positions for every relation that touches [j] after its
  /// operator type has been changed to [newType].  The Y component of each
  /// plug is preserved; only X is recalculated via [_getGateX].
  void _remapJunctionPlugs(JunctionNode j, LogicalOperator newType) {
    for (final rel in _taskRelations) {
      // Incoming: rel.targetId == j.id  →  remap targetLocalPos.dx
      if (rel.targetId == j.id) {
        final newX = _getGateX(
          rel.targetLocalPos.dy,
          j.width,
          j.height,
          newType,
          true, // isInput
        );
        rel.targetLocalPos = Offset(newX, rel.targetLocalPos.dy);
      }
      // Outgoing: rel.sourceId == j.id  →  remap sourceLocalPos.dx
      if (rel.sourceId == j.id) {
        // For OR/XOR the Y is clamped to the output arc range
        double clampedY = (newType == LogicalOperator.and)
            ? rel.sourceLocalPos.dy
            : rel.sourceLocalPos.dy.clamp(j.height * 0.35, j.height * 0.65);
        final newX = _getGateX(
          clampedY,
          j.width,
          j.height,
          newType,
          false, // isOutput
        );
        rel.sourceLocalPos = Offset(newX, clampedY);
      }
    }
  }

  /// Remaps all plugs that belong to [c] onto the new [jnc] after a
  /// ConditionalNode → JunctionNode conversion.
  ///
  /// Because [TaskRelation.sourceId] and [TaskRelation.targetId] are `final`,
  /// each affected relation is replaced with a new object that carries the
  /// updated node-id.  The local Y is normalised from rhombus space (c.height)
  /// to junction space (jnc.height), and X is recomputed via [_getGateX] so
  /// the plug lands correctly on the new gate shape.
  void _remapConditionalToJunctionPlugs(
    ConditionalNode c,
    JunctionNode jnc,
    LogicalOperator opType,
  ) {
    final toAdd = <TaskRelation>[];
    final toRemove = <TaskRelation>[];

    for (final rel in _taskRelations) {
      // ── Incoming plug (relation terminates at the rhombus) ──────────────
      if (rel.targetId == c.id) {
        final normY = (rel.targetLocalPos.dy / c.height).clamp(0.0, 1.0);
        final newDy = normY * jnc.height;
        final newDx = _getGateX(newDy, jnc.width, jnc.height, opType, true);
        toRemove.add(rel);
        toAdd.add(
          TaskRelation(
            sourceId: rel.sourceId,
            targetId: jnc.id,
            sourceLocalPos: rel.sourceLocalPos,
            targetLocalPos: Offset(newDx, newDy),
            handles: List<Offset>.from(rel.handles),
            thickness: rel.thickness,
            arrowSize: rel.arrowSize,
            color: rel.color,
          ),
        );
      }
      // ── Outgoing plug (relation originates from the rhombus) ────────────
      else if (rel.sourceId == c.id) {
        final normY = (rel.sourceLocalPos.dy / c.height).clamp(0.0, 1.0);
        final newDy = normY * jnc.height;
        // For OR/XOR, clamp Y to the output arc range (mirrors _remapJunctionPlugs)
        final clampedDy = (opType == LogicalOperator.and)
            ? newDy
            : newDy.clamp(jnc.height * 0.35, jnc.height * 0.65);
        final newDx = _getGateX(
          clampedDy,
          jnc.width,
          jnc.height,
          opType,
          false,
        );
        toRemove.add(rel);
        toAdd.add(
          TaskRelation(
            sourceId: jnc.id,
            targetId: rel.targetId,
            sourceLocalPos: Offset(newDx, clampedDy),
            targetLocalPos: rel.targetLocalPos,
            handles: List<Offset>.from(rel.handles),
            thickness: rel.thickness,
            arrowSize: rel.arrowSize,
            color: rel.color,
          ),
        );
      }
    }

    for (final r in toRemove) _taskRelations.remove(r);
    _taskRelations.addAll(toAdd);
  }

  /// Shows a compact operator-picker dialog centred on the gate's screen
  /// position.  On confirmation the junction type is updated and all
  /// connected plugs are remapped.
  /// Returns a [LogicalOperator] for AND/OR/XOR, or the string `'if'` when
  /// the user picks the IF (ConditionalNode / rhombus) option.
  void _showOperatorDialog(BuildContext context, JunctionNode j) {
    LogicalOperator selected = j.operatorType;
    bool isIf = false; // true when the IF tile is active

    showDialog<Object>(
      context: context,
      barrierColor: Colors.black38,
      builder: (ctx) {
        return StatefulBuilder(
          builder: (ctx, setDlg) {
            // ── AND / OR / XOR tile ──────────────────────────────────────
            Widget opBtn(LogicalOperator op) {
              final Color col;
              switch (op) {
                case LogicalOperator.or:
                  col = const Color(0xFFFFB74D);
                  break;
                case LogicalOperator.xor:
                  col = const Color(0xFFCE93D8);
                  break;
                case LogicalOperator.and:
                default:
                  col = const Color(0xFF4FC3F7);
              }
              final bool active = !isIf && selected == op;
              return GestureDetector(
                onTap: () => setDlg(() {
                  selected = op;
                  isIf = false;
                }),
                child: AnimatedContainer(
                  duration: const Duration(milliseconds: 120),
                  width: 64,
                  height: 44,
                  decoration: BoxDecoration(
                    color: active
                        ? col.withOpacity(0.18)
                        : Colors.white.withOpacity(0.04),
                    borderRadius: BorderRadius.circular(8),
                    border: Border.all(
                      color: active ? col : Colors.white12,
                      width: active ? 1.5 : 1,
                    ),
                  ),
                  child: Column(
                    mainAxisAlignment: MainAxisAlignment.center,
                    children: [
                      Text(
                        op.label,
                        style: TextStyle(
                          color: active ? col : Colors.white38,
                          fontSize: 12,
                          fontWeight: FontWeight.w700,
                          letterSpacing: 0.5,
                        ),
                      ),
                      Text(
                        op.symbol,
                        style: TextStyle(
                          color: active
                              ? col.withOpacity(0.75)
                              : Colors.white24,
                          fontSize: 10,
                        ),
                      ),
                    ],
                  ),
                ),
              );
            }

            // ── IF tile (converts to ConditionalNode / rhombus) ──────────
            Widget ifBtn() {
              const col = Colors.amberAccent;
              final active = isIf;
              return GestureDetector(
                onTap: () => setDlg(() => isIf = true),
                child: AnimatedContainer(
                  duration: const Duration(milliseconds: 120),
                  width: 64,
                  height: 44,
                  decoration: BoxDecoration(
                    color: active
                        ? col.withOpacity(0.18)
                        : Colors.white.withOpacity(0.04),
                    borderRadius: BorderRadius.circular(8),
                    border: Border.all(
                      color: active ? col : Colors.white12,
                      width: active ? 1.5 : 1,
                    ),
                  ),
                  child: Column(
                    mainAxisAlignment: MainAxisAlignment.center,
                    children: [
                      Icon(
                        Icons.diamond_outlined,
                        size: 14,
                        color: active ? col : Colors.white38,
                      ),
                      const SizedBox(height: 1),
                      Text(
                        'IF',
                        style: TextStyle(
                          color: active ? col : Colors.white38,
                          fontSize: 10,
                          fontWeight: FontWeight.w700,
                          letterSpacing: 0.5,
                        ),
                      ),
                    ],
                  ),
                ),
              );
            }

            return Dialog(
              backgroundColor: const Color(0xFF1E2124),
              insetPadding: EdgeInsets.zero,
              shape: RoundedRectangleBorder(
                borderRadius: BorderRadius.circular(10),
                side: const BorderSide(color: Colors.white12),
              ),
              child: IntrinsicWidth(
                child: Padding(
                  padding: const EdgeInsets.fromLTRB(20, 16, 20, 14),
                  child: Column(
                    mainAxisSize: MainAxisSize.min,
                    crossAxisAlignment: CrossAxisAlignment.start,
                    children: [
                      const Text(
                        'Change operator',
                        style: TextStyle(
                          color: Colors.white70,
                          fontSize: 13,
                          fontWeight: FontWeight.w600,
                        ),
                      ),
                      const SizedBox(height: 14),
                      Row(
                        mainAxisSize: MainAxisSize.min,
                        children: [
                          opBtn(LogicalOperator.and),
                          const SizedBox(width: 8),
                          opBtn(LogicalOperator.or),
                          const SizedBox(width: 8),
                          opBtn(LogicalOperator.xor),
                          const SizedBox(width: 8),
                          ifBtn(),
                        ],
                      ),
                      // Warning shown only when IF is selected, since switching
                      // converts the gate and drops its existing connections.
                      if (isIf) ...[
                        const SizedBox(height: 10),
                        Row(
                          mainAxisSize: MainAxisSize.min,
                          children: [
                            const Icon(
                              Icons.info_outline,
                              size: 11,
                              color: Colors.amberAccent,
                            ),
                            const SizedBox(width: 4),
                            Text(
                              'Existing connections will be removed.',
                              style: TextStyle(
                                fontSize: 10,
                                color: Colors.amberAccent.withOpacity(0.75),
                              ),
                            ),
                          ],
                        ),
                      ],
                      const SizedBox(height: 16),
                      Row(
                        mainAxisAlignment: MainAxisAlignment.spaceBetween,
                        children: [
                          // ── Delete button (left-anchored) ──────────────
                          TextButton.icon(
                            onPressed: () => Navigator.pop(ctx, 'delete'),
                            icon: const Icon(
                              Icons.delete_outline,
                              size: 14,
                              color: Colors.redAccent,
                            ),
                            label: const Text(
                              'Delete',
                              style: TextStyle(color: Colors.redAccent),
                            ),
                            style: TextButton.styleFrom(
                              padding: const EdgeInsets.symmetric(
                                horizontal: 10,
                                vertical: 6,
                              ),
                              shape: RoundedRectangleBorder(
                                borderRadius: BorderRadius.circular(6),
                              ),
                            ),
                          ),
                          // ── Cancel / Apply (right-anchored) ────────────
                          Row(
                            mainAxisSize: MainAxisSize.min,
                            children: [
                              TextButton(
                                onPressed: () => Navigator.pop(ctx),
                                child: const Text(
                                  'Cancel',
                                  style: TextStyle(color: Colors.white38),
                                ),
                              ),
                              const SizedBox(width: 8),
                              TextButton(
                                onPressed: () =>
                                    Navigator.pop(ctx, isIf ? 'if' : selected),
                                style: TextButton.styleFrom(
                                  backgroundColor: const Color(
                                    0xFF4FC3F7,
                                  ).withOpacity(0.12),
                                  shape: RoundedRectangleBorder(
                                    borderRadius: BorderRadius.circular(6),
                                  ),
                                ),
                                child: const Text(
                                  'Apply',
                                  style: TextStyle(
                                    color: Color(0xFF4FC3F7),
                                    fontWeight: FontWeight.w600,
                                  ),
                                ),
                              ),
                            ],
                          ),
                        ],
                      ),
                    ],
                  ),
                ),
              ),
            );
          },
        );
      },
    ).then((result) {
      if (result == null) return;

      if (result == 'delete') {
        // ── Delete the junction and all its connections ───────────────────
        setState(() {
          _junctions.removeWhere((jn) => jn.id == j.id);
          _taskRelations.removeWhere(
            (r) => r.sourceId == j.id || r.targetId == j.id,
          );
          _taskPositions.removeWhere((k, _) => k == j.id);
          if (_selectedJunctionId == j.id) _selectedJunctionId = null;
          _selectedJunctionIds.remove(j.id);
          _selectedRelationKeys.clear();
        });
        _saveWorkspace();
        return;
      }

      if (result == 'if') {
        // ── Convert JunctionNode → ConditionalNode ───────────────────────
        setState(() {
          final cnd = ConditionalNode(
            id: 'cnd_${DateTime.now().millisecondsSinceEpoch}',
            // Centre the rhombus (140×80) on the junction (60×40) position.
            position: j.position - const Offset(40, 20),
          );
          _conditionals.add(cnd);
          _junctions.removeWhere((jn) => jn.id == j.id);
          // Drop connections that pointed to/from this junction — they would
          // need to be re-wired to the new rhombus plugs by the user.
          _taskRelations.removeWhere(
            (r) => r.sourceId == j.id || r.targetId == j.id,
          );
          _selectedConditionalId = cnd.id;
          _selectedConditionalIds = {cnd.id};
          _selectedJunctionId = null;
          _selectedJunctionIds.clear();
        });
        _saveWorkspace();
      } else if (result is LogicalOperator && result != j.operatorType) {
        // ── Stay as JunctionNode, just change the operator ───────────────
        setState(() {
          _remapJunctionPlugs(j, result);
          j.operatorType = result;
        });
        _saveWorkspace();
      }
    });
  }

  /// Same "Change operator" popup, but opened from a [ConditionalNode] (IF /
  /// rhombus).  IF is pre-selected.  Choosing AND / OR / XOR converts the node
  /// back to a [JunctionNode]; Delete removes it entirely.
  void _showConditionalOperatorDialog(BuildContext context, ConditionalNode c) {
    LogicalOperator? selected; // null → IF is active
    bool isIf = true;

    showDialog<Object>(
      context: context,
      barrierColor: Colors.black38,
      builder: (ctx) {
        return StatefulBuilder(
          builder: (ctx, setDlg) {
            Widget opBtn(LogicalOperator op) {
              final Color col;
              switch (op) {
                case LogicalOperator.or:
                  col = const Color(0xFFFFB74D);
                  break;
                case LogicalOperator.xor:
                  col = const Color(0xFFCE93D8);
                  break;
                case LogicalOperator.and:
                default:
                  col = const Color(0xFF4FC3F7);
              }
              final bool active = !isIf && selected == op;
              return GestureDetector(
                onTap: () => setDlg(() {
                  selected = op;
                  isIf = false;
                }),
                child: AnimatedContainer(
                  duration: const Duration(milliseconds: 120),
                  width: 64,
                  height: 44,
                  decoration: BoxDecoration(
                    color: active
                        ? col.withOpacity(0.18)
                        : Colors.white.withOpacity(0.04),
                    borderRadius: BorderRadius.circular(8),
                    border: Border.all(
                      color: active ? col : Colors.white12,
                      width: active ? 1.5 : 1,
                    ),
                  ),
                  child: Column(
                    mainAxisAlignment: MainAxisAlignment.center,
                    children: [
                      Text(
                        op.label,
                        style: TextStyle(
                          color: active ? col : Colors.white38,
                          fontSize: 12,
                          fontWeight: FontWeight.w700,
                          letterSpacing: 0.5,
                        ),
                      ),
                      Text(
                        op.symbol,
                        style: TextStyle(
                          color: active
                              ? col.withOpacity(0.75)
                              : Colors.white24,
                          fontSize: 10,
                        ),
                      ),
                    ],
                  ),
                ),
              );
            }

            Widget ifBtn() {
              const col = Colors.amberAccent;
              final active = isIf;
              return GestureDetector(
                onTap: () => setDlg(() {
                  isIf = true;
                  selected = null;
                }),
                child: AnimatedContainer(
                  duration: const Duration(milliseconds: 120),
                  width: 64,
                  height: 44,
                  decoration: BoxDecoration(
                    color: active
                        ? col.withOpacity(0.18)
                        : Colors.white.withOpacity(0.04),
                    borderRadius: BorderRadius.circular(8),
                    border: Border.all(
                      color: active ? col : Colors.white12,
                      width: active ? 1.5 : 1,
                    ),
                  ),
                  child: Column(
                    mainAxisAlignment: MainAxisAlignment.center,
                    children: [
                      Icon(
                        Icons.diamond_outlined,
                        size: 14,
                        color: active ? col : Colors.white38,
                      ),
                      const SizedBox(height: 1),
                      Text(
                        'IF',
                        style: TextStyle(
                          color: active ? col : Colors.white38,
                          fontSize: 10,
                          fontWeight: FontWeight.w700,
                          letterSpacing: 0.5,
                        ),
                      ),
                    ],
                  ),
                ),
              );
            }

            return Dialog(
              backgroundColor: const Color(0xFF1E2124),
              insetPadding: EdgeInsets.zero,
              shape: RoundedRectangleBorder(
                borderRadius: BorderRadius.circular(10),
                side: const BorderSide(color: Colors.white12),
              ),
              child: IntrinsicWidth(
                child: Padding(
                  padding: const EdgeInsets.fromLTRB(20, 16, 20, 14),
                  child: Column(
                    mainAxisSize: MainAxisSize.min,
                    crossAxisAlignment: CrossAxisAlignment.start,
                    children: [
                      const Text(
                        'Change operator',
                        style: TextStyle(
                          color: Colors.white70,
                          fontSize: 13,
                          fontWeight: FontWeight.w600,
                        ),
                      ),
                      const SizedBox(height: 14),
                      Row(
                        mainAxisSize: MainAxisSize.min,
                        children: [
                          opBtn(LogicalOperator.and),
                          const SizedBox(width: 8),
                          opBtn(LogicalOperator.or),
                          const SizedBox(width: 8),
                          opBtn(LogicalOperator.xor),
                          const SizedBox(width: 8),
                          ifBtn(),
                        ],
                      ),
                      if (!isIf) ...[
                        const SizedBox(height: 10),
                        Row(
                          mainAxisSize: MainAxisSize.min,
                          children: [
                            const Icon(
                              Icons.info_outline,
                              size: 11,
                              color: Color(0xFF4FC3F7),
                            ),
                            const SizedBox(width: 4),
                            Text(
                              'Existing connections will be remapped.',
                              style: TextStyle(
                                fontSize: 10,
                                color: const Color(
                                  0xFF4FC3F7,
                                ).withOpacity(0.75),
                              ),
                            ),
                          ],
                        ),
                      ],
                      const SizedBox(height: 16),
                      Row(
                        mainAxisAlignment: MainAxisAlignment.spaceBetween,
                        children: [
                          TextButton.icon(
                            onPressed: () => Navigator.pop(ctx, 'delete'),
                            icon: const Icon(
                              Icons.delete_outline,
                              size: 14,
                              color: Colors.redAccent,
                            ),
                            label: const Text(
                              'Delete',
                              style: TextStyle(color: Colors.redAccent),
                            ),
                            style: TextButton.styleFrom(
                              padding: const EdgeInsets.symmetric(
                                horizontal: 10,
                                vertical: 6,
                              ),
                              shape: RoundedRectangleBorder(
                                borderRadius: BorderRadius.circular(6),
                              ),
                            ),
                          ),
                          Row(
                            mainAxisSize: MainAxisSize.min,
                            children: [
                              TextButton(
                                onPressed: () => Navigator.pop(ctx),
                                child: const Text(
                                  'Cancel',
                                  style: TextStyle(color: Colors.white38),
                                ),
                              ),
                              const SizedBox(width: 8),
                              TextButton(
                                onPressed: () =>
                                    Navigator.pop(ctx, isIf ? 'if' : selected),
                                style: TextButton.styleFrom(
                                  backgroundColor: const Color(
                                    0xFF4FC3F7,
                                  ).withOpacity(0.12),
                                  shape: RoundedRectangleBorder(
                                    borderRadius: BorderRadius.circular(6),
                                  ),
                                ),
                                child: const Text(
                                  'Apply',
                                  style: TextStyle(
                                    color: Color(0xFF4FC3F7),
                                    fontWeight: FontWeight.w600,
                                  ),
                                ),
                              ),
                            ],
                          ),
                        ],
                      ),
                    ],
                  ),
                ),
              ),
            );
          },
        );
      },
    ).then((result) {
      if (result == null) return;

      if (result == 'delete') {
        setState(() {
          _conditionals.removeWhere((cn) => cn.id == c.id);
          _taskRelations.removeWhere(
            (r) => r.sourceId == c.id || r.targetId == c.id,
          );
          if (_selectedConditionalId == c.id) _selectedConditionalId = null;
          _selectedConditionalIds.remove(c.id);
          _selectedRelationKeys.clear();
        });
        _saveWorkspace();
        return;
      }

      if (result == 'if') return; // already IF — nothing to do

      if (result is LogicalOperator) {
        // Convert ConditionalNode → JunctionNode, remapping existing plugs.
        setState(() {
          final jnc = JunctionNode(
            id: 'jnc_${DateTime.now().millisecondsSinceEpoch}',
            // Centre the gate (60×40) on the rhombus (140×80) position.
            position: c.position + const Offset(40, 20),
            operatorType: result,
          );
          _junctions.add(jnc);
          _conditionals.removeWhere((cn) => cn.id == c.id);
          // Remap plugs from rhombus geometry to the new gate shape instead of
          // dropping them — this preserves all existing connections.
          _remapConditionalToJunctionPlugs(c, jnc, result);
          if (_selectedConditionalId == c.id) _selectedConditionalId = null;
          _selectedConditionalIds.remove(c.id);
          _selectedJunctionId = jnc.id;
          _selectedJunctionIds = {jnc.id};
        });
        _saveWorkspace();
      }
    });
  }

  Widget _buildScheduleTitleBar() {
    final weekEnd =
        _scheduleVisibleEnd ?? _scheduleWeekStart.add(const Duration(days: 6));
    final months = [
      '',
      'Jan',
      'Feb',
      'Mar',
      'Apr',
      'May',
      'Jun',
      'Jul',
      'Aug',
      'Sep',
      'Oct',
      'Nov',
      'Dec',
    ];
    final label =
        '${months[_scheduleWeekStart.month]} ${_scheduleWeekStart.day} – '
        '${months[weekEnd.month]} ${weekEnd.day}, ${weekEnd.year}';
    // ignore: unused_local_variable — kept for potential future use

    return Padding(
      padding: const EdgeInsets.symmetric(horizontal: 12),
      child: Row(
        children: [
          const Text(
            'Schedule',
            style: TextStyle(
              fontSize: 14,
              fontWeight: FontWeight.w600,
              color: Colors.white,
              letterSpacing: 0.3,
            ),
          ),
          const SizedBox(width: 12),
          // View Mode Switcher (Week / 14d / Month / Custom)
          Container(
            height: 24,
            decoration: BoxDecoration(
              color: Colors.white.withOpacity(0.06),
              borderRadius: BorderRadius.circular(6),
              border: Border.all(color: Colors.white12),
            ),
            child: Row(
              mainAxisSize: MainAxisSize.min,
              children: [
                ...['Week', '14d', 'Month'].map((m) {
                  final active = _scheduleViewMode == m;
                  return GestureDetector(
                    onTap: () {
                      setState(() => _scheduleViewMode = m);
                      _scheduleCanvasKey.currentState?.setViewMode(
                        m.toLowerCase(),
                      );
                    },
                    child: AnimatedContainer(
                      duration: const Duration(milliseconds: 120),
                      padding: const EdgeInsets.symmetric(
                        horizontal: 10,
                        vertical: 4,
                      ),
                      decoration: BoxDecoration(
                        color: active
                            ? const Color(0xFF4FC3F7).withOpacity(0.2)
                            : Colors.transparent,
                        borderRadius: BorderRadius.circular(5),
                      ),
                      child: Text(
                        m,
                        style: TextStyle(
                          fontSize: 11,
                          fontWeight: active
                              ? FontWeight.bold
                              : FontWeight.normal,
                          color: active
                              ? const Color(0xFF4FC3F7)
                              : Colors.white38,
                        ),
                      ),
                    ),
                  );
                }),
                // Divider before Custom
                Container(width: 0.5, height: 14, color: Colors.white12),
                // Custom button — label mirrors live visible-day count
                GestureDetector(
                  onTap: _showCustomViewDaysDialog,
                  child: AnimatedContainer(
                    duration: const Duration(milliseconds: 120),
                    padding: const EdgeInsets.symmetric(
                      horizontal: 10,
                      vertical: 4,
                    ),
                    decoration: BoxDecoration(
                      color: _scheduleViewMode == 'Custom'
                          ? const Color(0xFF4FC3F7).withOpacity(0.2)
                          : Colors.transparent,
                      borderRadius: BorderRadius.circular(5),
                    ),
                    child: Text(
                      _scheduleViewMode == 'Custom'
                          ? '${_scheduleVisibleDays}d'
                          : 'Custom',
                      style: TextStyle(
                        fontSize: 11,
                        fontWeight: _scheduleViewMode == 'Custom'
                            ? FontWeight.bold
                            : FontWeight.normal,
                        color: _scheduleViewMode == 'Custom'
                            ? const Color(0xFF4FC3F7)
                            : Colors.white38,
                      ),
                    ),
                  ),
                ),
              ],
            ),
          ),
          const SizedBox(width: 4),
          // Reset view — same height as Week/Month switcher
          Tooltip(
            message: 'Reset view',
            child: GestureDetector(
              onTap: () => _scheduleCanvasKey.currentState?.resetView(),
              child: Container(
                height: 24,
                padding: const EdgeInsets.symmetric(horizontal: 8),
                decoration: BoxDecoration(
                  color: Colors.white.withOpacity(0.04),
                  borderRadius: BorderRadius.circular(6),
                  border: Border.all(color: Colors.white12),
                ),
                child: const Icon(
                  Icons.fit_screen_outlined,
                  size: 13,
                  color: Colors.white38,
                ),
              ),
            ),
          ),
          const SizedBox(width: 16),

          // --- DATE RANGE LABEL (double-click start date to jump) ---
          _buildScheduleDateLabel(
            startPart:
                '${months[_scheduleWeekStart.month]} ${_scheduleWeekStart.day}',
            endPart: '${months[weekEnd.month]} ${weekEnd.day}, ${weekEnd.year}',
          ),
          const SizedBox(width: 24),

          // --- SKIP STEP SELECTOR ---
          _buildSkipStepSelector(),

          const SizedBox(width: 8),

          // --- NAVIGATION ARROWS ---
          _tasksIconBtn(Icons.chevron_left, 'Back $_scheduleSkipStep days', () {
            final newStart = _scheduleWeekStart.subtract(
              Duration(days: _scheduleSkipStep),
            );
            _scheduleCanvasKey.currentState?.navigateTo(newStart);
            setState(() {
              _scheduleWeekStart = newStart;
            });
          }),
          _tasksIconBtn(Icons.today_outlined, 'Today', () {
            final n = DateTime.now();
            final newStart = DateTime(n.year, n.month, n.day - (n.weekday - 1));
            _scheduleCanvasKey.currentState?.navigateTo(newStart);
            setState(() {
              _scheduleWeekStart = newStart;
              _scheduleRangeEnd = null;
            });
          }),
          _tasksIconBtn(
            Icons.chevron_right,
            'Forward $_scheduleSkipStep days',
            () {
              final newStart = _scheduleWeekStart.add(
                Duration(days: _scheduleSkipStep),
              );
              _scheduleCanvasKey.currentState?.navigateTo(newStart);
              setState(() {
                _scheduleWeekStart = newStart;
              });
            },
          ),
          const SizedBox(width: 8),
          // Execution view mode dropdown
          _ExecViewDropdown(
            value: _scheduleExecViewMode,
            onChanged: (v) => setState(() => _scheduleExecViewMode = v),
          ),
          const Spacer(),
        ],
      ),
    );
  }

  // ── Inline start-date editor: shows the date range, start part is
  // double-clickable and becomes a dd/mm/yyyy text field on double-tap.
  Widget _buildScheduleDateLabel({
    required String startPart,
    required String endPart,
  }) {
    const style = TextStyle(
      color: Colors.white,
      fontSize: 13,
      fontWeight: FontWeight.w500,
    );
    return Row(
      mainAxisSize: MainAxisSize.min,
      children: [
        if (_scheduleEditingStartDate)
          SizedBox(
            width: 98,
            height: 22,
            child: TextField(
              controller: _scheduleDateInputCtrl,
              focusNode: _scheduleDateFocusNode,
              style: const TextStyle(color: Colors.white, fontSize: 12),
              decoration: InputDecoration(
                contentPadding: const EdgeInsets.symmetric(
                  horizontal: 6,
                  vertical: 2,
                ),
                isDense: true,
                hintText: 'dd/mm/yyyy',
                hintStyle: const TextStyle(
                  color: Color(0x44FFFFFF),
                  fontSize: 12,
                ),
                filled: true,
                fillColor: Colors.white.withOpacity(0.08),
                border: OutlineInputBorder(
                  borderRadius: BorderRadius.circular(4),
                  borderSide: const BorderSide(
                    color: Color(0xFF4FC3F7),
                    width: 1,
                  ),
                ),
                enabledBorder: OutlineInputBorder(
                  borderRadius: BorderRadius.circular(4),
                  borderSide: const BorderSide(
                    color: Color(0xFF4FC3F7),
                    width: 1,
                  ),
                ),
                focusedBorder: OutlineInputBorder(
                  borderRadius: BorderRadius.circular(4),
                  borderSide: const BorderSide(
                    color: Color(0xFF4FC3F7),
                    width: 1.5,
                  ),
                ),
              ),
              onSubmitted: _onScheduleStartDateSubmitted,
            ),
          )
        else
          GestureDetector(
            onDoubleTap: () {
              final d = _scheduleWeekStart;
              _scheduleDateInputCtrl.text =
                  '${d.day.toString().padLeft(2, '0')}/'
                  '${d.month.toString().padLeft(2, '0')}/'
                  '${d.year}';
              setState(() => _scheduleEditingStartDate = true);
              WidgetsBinding.instance.addPostFrameCallback((_) {
                _scheduleDateFocusNode.requestFocus();
                _scheduleDateInputCtrl.selection = TextSelection(
                  baseOffset: 0,
                  extentOffset: _scheduleDateInputCtrl.text.length,
                );
              });
            },
            child: MouseRegion(
              cursor: SystemMouseCursors.click,
              child: Tooltip(
                message: 'Double-click to jump to date',
                child: Text(startPart, style: style),
              ),
            ),
          ),
        Text(' \u2013 $endPart', style: style),
      ],
    );
  }

  /// Parses a dd/mm/yyyy string and navigates the schedule canvas to that date.
  void _onScheduleStartDateSubmitted(String text) {
    final parts = text.trim().split('/');
    if (parts.length == 3) {
      final day = int.tryParse(parts[0].trim());
      final month = int.tryParse(parts[1].trim());
      final year = int.tryParse(parts[2].trim());
      if (day != null &&
          month != null &&
          year != null &&
          month >= 1 &&
          month <= 12 &&
          day >= 1 &&
          day <= 31 &&
          year >= 1970) {
        final newStart = DateTime(year, month, day);
        _scheduleCanvasKey.currentState?.navigateTo(newStart);
        setState(() {
          _scheduleWeekStart = newStart;
          _scheduleEditingStartDate = false;
        });
        return;
      }
    }
    // Invalid input — just dismiss the field
    setState(() => _scheduleEditingStartDate = false);
  }

  // 3. Helper to build the Skip Step Selector UI
  Widget _buildSkipStepSelector() {
    final options = [7, 14, 30];
    return Container(
      height: 24,
      padding: const EdgeInsets.symmetric(horizontal: 4),
      decoration: BoxDecoration(
        color: Colors.white.withOpacity(0.04),
        borderRadius: BorderRadius.circular(4),
        border: Border.all(color: Colors.white10),
      ),
      child: Row(
        mainAxisSize: MainAxisSize.min,
        children: [
          ...options.map((days) {
            final active = _scheduleSkipStep == days;
            return GestureDetector(
              onTap: () => setState(() => _scheduleSkipStep = days),
              child: Container(
                padding: const EdgeInsets.symmetric(horizontal: 6),
                alignment: Alignment.center,
                child: Text(
                  '$days',
                  style: TextStyle(
                    fontSize: 10,
                    color: active ? const Color(0xFF4FC3F7) : Colors.white38,
                    fontWeight: active ? FontWeight.bold : FontWeight.normal,
                  ),
                ),
              ),
            );
          }),
          const VerticalDivider(
            width: 8,
            color: Colors.white10,
            indent: 6,
            endIndent: 6,
          ),
          GestureDetector(
            onTap: _showCustomSkipDialog,
            child: Padding(
              padding: const EdgeInsets.symmetric(horizontal: 4),
              child: Text(
                !options.contains(_scheduleSkipStep)
                    ? '$_scheduleSkipStep d'
                    : 'Custom',
                style: TextStyle(
                  fontSize: 10,
                  color: !options.contains(_scheduleSkipStep)
                      ? const Color(0xFF4FC3F7)
                      : Colors.white38,
                ),
              ),
            ),
          ),
        ],
      ),
    );
  }

  // 4. Dialog for custom day input
  void _showCustomSkipDialog() {
    final ctrl = TextEditingController(text: _scheduleSkipStep.toString());
    showDialog(
      context: context,
      builder: (ctx) => AlertDialog(
        backgroundColor: const Color(0xFF1E1E1E),
        title: const Text(
          "Custom Skip Step (Days)",
          style: TextStyle(color: Colors.white, fontSize: 14),
        ),
        content: TextField(
          controller: ctrl,
          autofocus: true,
          keyboardType: TextInputType.number,
          style: const TextStyle(color: Colors.white),
          decoration: const InputDecoration(
            suffixText: 'days',
            enabledBorder: UnderlineInputBorder(
              borderSide: BorderSide(color: Colors.white24),
            ),
          ),
        ),
        actions: [
          TextButton(
            onPressed: () => Navigator.pop(ctx),
            child: const Text("Cancel"),
          ),
          TextButton(
            onPressed: () {
              final val = int.tryParse(ctrl.text);
