  void _applyCustomViewDays(int days) {
    const presets = {7: 'Week', 14: '14d', 30: 'Month'};
    final mode = presets[days] ?? 'Custom';
    setState(() {
      _scheduleViewMode = mode;
      _scheduleVisibleDays = days;
    });
    _scheduleCanvasKey.currentState?.setViewDays(days);
  }

