  Widget _buildBezierHandle(TaskRelation rel, int index) {
    final worldPos = rel.handles[index];
    final screenPos = (worldPos * _scale) + _canvasOffset;

    return Positioned(
      left: screenPos.dx - (6 * _scale),
      top: screenPos.dy - (6 * _scale),
      child: MouseRegion(
        cursor: SystemMouseCursors.allScroll,
        child: GestureDetector(
          onPanUpdate: (details) {
            setState(() {
              rel.handles[index] += details.delta / _scale;
            });
          },
          onSecondaryTap: () {
            setState(() {
              rel.handles.removeAt(index);
            });
          },
          child: Container(
            width: 12 * _scale,
            height: 12 * _scale,
            decoration: BoxDecoration(
              color: Colors.white,
              shape: BoxShape.circle,
              border: Border.all(color: rel.color, width: 2 * _scale),
              boxShadow: [
                BoxShadow(
                  color: Colors.black26,
                  blurRadius: 4 * _scale,
                  spreadRadius: 1 * _scale,
                ),
              ],
            ),
          ),
        ),
      ),
    );
  }

  // ── ID generator ─────────────────────────────────────────────────────────

  String _generateId() {
    final t = DateTime.now().millisecondsSinceEpoch;
    final r = (t ^ (t >> 16)) & 0xFFFFFF;
    return '${t.toRadixString(16)}${r.toRadixString(16)}';
  }

  // ── File paths ───────────────────────────────────────────────────────────

  // ── Root paths ──────────────────────────────────────────────────────────
  // general.json is the cross-workspace registry.  It lives under
  // $XDG_CONFIG_HOME/chaos_control/ (defaults to ~/.config/chaos_control/) per the
  // XDG Base Directory Specification, so it is independent of any individual
  // workspace's storage location.
  String get _generalFilePath {
    final xdgConfig = Platform.environment['XDG_CONFIG_HOME'] ?? '';
    if (xdgConfig.isNotEmpty) return '$xdgConfig/chaos_control/general.json';
    final home =
        Platform.environment['HOME'] ??
        Platform.environment['USERPROFILE'] ??
        '';
    if (home.isNotEmpty) return '$home/.config/chaos_control/general.json';
    throw StateError(
      'Cannot determine config directory: neither XDG_CONFIG_HOME nor HOME '
      'are set in the environment.',
    );
  }

  // Per-workspace root: always read from the 'basePath' key that every
  // workspace entry carries since the dynamic-path feature was introduced.
  // Entries without a basePath are treated as corrupt/incomplete and are
  // filtered out during _loadGeneral(), so this should never return empty
  // in practice.
  String _wsRoot(String id) {
    final entry = _savedWorkspaces.firstWhere(
      (w) => w['id'] == id,
      orElse: () => <String, String>{},
    );
    final bp = (entry['basePath'] ?? '').trim();
    assert(bp.isNotEmpty, '_wsRoot: workspace $id has no basePath');
    return bp;
  }

  // metadata/ — app-specific config (not portable on its own)
  String _wsMetaDir(String id) => '${_wsRoot(id)}/metadata';
  String _workspaceFilePath(String id) =>
      '${_wsMetaDir(id)}/workspace_$id.json';

  // files/ — portable user content
  String _wsFilesDir(String id) => '${_wsRoot(id)}/files';

  // ── Notes paths (workspace-scoped) ───────────────────────────────────────
  String get _notesDir => '${_wsFilesDir(_workspaceId)}/notes';
  String get _notesMetaPath => '${_wsMetaDir(_workspaceId)}/notes_meta.json';

  // ── Spec §3: filesystem-safe name helper ────────────────────────────────
  static String _fsSafe(String s) => s
      .replaceAll(RegExp(r'[<>:"/\\|?*\x00-\x1F]'), '_')
      .trim()
      .replaceAll(RegExp(r'\s+'), ' ');

  String _noteFilePath(Note n) {
    final sub = n.type == NoteType.task
        ? 'tasks'
        : n.type == NoteType.project
        ? 'projects'
        : 'notes';

    if (n.type == NoteType.task && n.linkedTaskId != null) {
      // Spec §3: [Task Name] - [Project or Inbox] (YYYY-MM-DD[ - HH-mm]).md
      final task = _allTasks.firstWhere(
        (t) => t.id == n.linkedTaskId,
        orElse: () => Task(
          id: '',
          title: n.title,
          isDone: false,
          projectId: '',
          subTaskIds: const [],
          timeSpent: 0,
          attachments: const [],
          tagIds: const [],
        ),
      );
      final projName = task.projectId.isNotEmpty
          ? (_projects[task.projectId]?.title ?? 'Inbox')
          : 'Inbox';
      final dt = task.scheduledDateTime;
      final dateStr = dt != null
          ? '${dt.year.toString().padLeft(4, '0')}-'
                '${dt.month.toString().padLeft(2, '0')}-'
                '${dt.day.toString().padLeft(2, '0')}'
          : (task.scheduledDate != null
                ? '${task.scheduledDate!.year.toString().padLeft(4, '0')}-'
                      '${task.scheduledDate!.month.toString().padLeft(2, '0')}-'
                      '${task.scheduledDate!.day.toString().padLeft(2, '0')}'
                : null);
      final timeStr = dt != null
          ? '${dt.hour.toString().padLeft(2, '0')}-'
                '${dt.minute.toString().padLeft(2, '0')}'
          : null;
      final datePart = dateStr != null
          ? (timeStr != null ? '$dateStr - $timeStr' : dateStr)
          : null;
      final suffix = datePart != null ? ' ($datePart)' : '';
      final safe = '${_fsSafe(n.title)} - ${_fsSafe(projName)}$suffix';
      return '$_notesDir/$sub/$safe.md';
    }

    // project notes and common notes: use title only
    final safe = _fsSafe(n.title);
    return '$_notesDir/$sub/$safe.md';
  }

  // ── general.json: workspace registry + global preferences ─────────────────

  Future<void> _saveGeneral() async {
    try {
      final data = {
        // Registry: list of {id, name, metaPath?} — metaPath is optional SP import path
        'workspaces': _savedWorkspaces,
        'lastWorkspaceId': _lastWorkspaceId,
        // Global preferences
        'prefAllowDuplicateConnections': _prefAllowDuplicateConnections,
        'prefShowWorkspacePaths': _prefShowWorkspacePaths,
        'prefDefaultOperator': _prefDefaultOperator.name,
        'prefDefaultArrowSize': _prefDefaultArrowSize,
        'prefShowIdOnCards': _prefShowIdOnCards,
        'prefShowProjectName': _prefShowProjectName,
        'prefShowDueDateOnCards': _prefShowDueDateOnCards,
        'prefShowTimeOnCards': _prefShowTimeOnCards,
        'prefStandardVisibleInfos': _prefStandardVisibleInfos.toList(),
        'prefShowDateOnListedTasks': _prefShowDateOnListedTasks,
      };
      final gFile = File(_generalFilePath);
      await gFile.parent.create(recursive: true);
      await gFile.writeAsString(jsonEncode(data));
    } catch (e) {
      debugPrint('SAVE GENERAL ERROR: $e');
    }
  }

  Future<void> _loadGeneral() async {
    try {
      File file = File(_generalFilePath);

      if (!await file.exists()) return;
      final data =
          jsonDecode(await file.readAsString()) as Map<String, dynamic>;

      // Filter the registry: only keep workspaces whose workspace_{id}.json
      // still exists on disk.  We resolve the root directly from the entry's
      // 'basePath' here (we can't use _wsRoot() yet because _savedWorkspaces
      // hasn't been populated at this point in the boot sequence).
      // Entries that carry no basePath are silently skipped — they predate
      // the dynamic-path feature and their on-disk location is unknown.
      List<Map<String, String>> validWorkspaces = [];
      if (data['workspaces'] != null) {
        for (final e in data['workspaces'] as List) {
          final entry = Map<String, String>.from(e);
          final id = entry['id'] ?? '';
          if (id.isEmpty) continue;
          final bp = (entry['basePath'] ?? '').trim();
          if (bp.isEmpty) continue; // no known location — skip
          final wsFile = '$bp/metadata/workspace_$id.json';
          if (await File(wsFile).exists()) {
            validWorkspaces.add(entry);
          }
        }
      }

      setState(() {
        _savedWorkspaces = validWorkspaces;
        // Remember the last-opened workspace so startup can auto-load it
        _lastWorkspaceId = (data['lastWorkspaceId'] as String? ?? '').trim();
        // Preferences
        _prefAllowDuplicateConnections =
            data['prefAllowDuplicateConnections'] ?? false;
        _prefShowWorkspacePaths = data['prefShowWorkspacePaths'] ?? false;
        if (data['prefDefaultOperator'] != null) {
          try {
            _prefDefaultOperator = LogicalOperator.values.byName(
              data['prefDefaultOperator'],
            );
          } catch (_) {}
        }
        _prefDefaultArrowSize =
            (data['prefDefaultArrowSize'] as num?)?.toDouble() ?? 10.0;
        _prefShowIdOnCards = data['prefShowIdOnCards'] ?? true;
        _prefShowProjectName = data['prefShowProjectName'] ?? true;
        _prefShowDueDateOnCards = data['prefShowDueDateOnCards'] ?? false;
        _prefShowTimeOnCards = data['prefShowTimeOnCards'] ?? false;
        if (data['prefStandardVisibleInfos'] != null) {
          _prefStandardVisibleInfos = Set<String>.from(
            data['prefStandardVisibleInfos'],
          );
        }
        _prefShowDateOnListedTasks = data['prefShowDateOnListedTasks'] ?? false;
      });
    } catch (e) {
      debugPrint('LOAD GENERAL ERROR: $e');
    }
  }

  // ── _savePreferences: delegate to _saveGeneral ────────────────────────────
  Future<void> _savePreferences() => _saveGeneral();

  // ── workspace_{id}.json ───────────────────────────────────────────────────

  Map<String, dynamic> _serialiseCanvas(Map<String, dynamic> snap) {
    final tasks = (snap['canvasTasks'] as List<Task>? ?? []);
    final positions = (snap['taskPositions'] as Map<String, Offset>? ?? {});
    final junctions = (snap['junctions'] as List<JunctionNode>? ?? []);
    final conditionals = (snap['conditionals'] as List<ConditionalNode>? ?? []);
    final relations = (snap['taskRelations'] as Set<TaskRelation>? ?? {});
    final scale = snap['scale'] ?? 1.0;
    final offset = snap['canvasOffset'] as Offset? ?? Offset.zero;
    final bgColor = (snap['bgColor'] as Color?)?.value ?? 0xFF121212;

    return {
      'canvasTasks': tasks.map((t) => t.id).toList(),
      'taskPositions': positions.map(
        (k, v) => MapEntry(k, {'dx': v.dx, 'dy': v.dy}),
      ),
      'junctions': junctions
          .map(
            (j) => {
              'id': j.id,
              'dx': j.position.dx,
              'dy': j.position.dy,
              'operatorType': j.operatorType.name,
            },
          )
          .toList(),
      'conditionals': conditionals
          .map(
            (c) => {
              'id': c.id,
              'dx': c.position.dx,
              'dy': c.position.dy,
              'width': c.width,
              'height': c.height,
              'label': c.label,
            },
          )
          .toList(),
      'taskRelations': relations
          .map(
            (r) => {
              'sourceId': r.sourceId,
              'targetId': r.targetId,
              'sdx': r.sourceLocalPos.dx,
              'sdy': r.sourceLocalPos.dy,
              'tdx': r.targetLocalPos.dx,
              'tdy': r.targetLocalPos.dy,
              'arrowSize': r.arrowSize,
              'thickness': r.thickness,
              'color': r.color.value,
              'handles': r.handles
                  .map((h) => {'dx': h.dx, 'dy': h.dy})
                  .toList(),
            },
          )
          .toList(),
      'scale': scale,
      'canvasOffset': {'dx': offset.dx, 'dy': offset.dy},
      'bgColor': bgColor,
      'taskUiStates': Map.fromEntries(
        tasks.map(
          (t) => MapEntry(t.id, {
            'isExpanded': t.isExpanded,
            'cardWidth': t.cardWidth,
            'cardHeight': t.cardHeight,
            'isDone': t.isDone,
            'status': t.status.name,
            'visibleProperties': t.visibleProperties.toList(),
            'propertyHeights': t.propertyHeights,
          }),
        ),
      ),
    };
  }

  Future<void> _saveWorkspace() async {
    if (_workspaceId.isEmpty) return;
    try {
      // Snapshot the currently-active canvas before serialising
      if (_currentCanvasName.isNotEmpty) {
        _canvasStates[_currentCanvasName] = _snapshotCurrentCanvas();
        _canvasColors[_currentCanvasName] = _currentCanvasBackgroundColor;
      }

      final data = {
        // ── Identity ────────────────────────────────────────────────────
        'id': _workspaceId,
        'workspaceName': _workspaceName,
        'workspaceImagePath': _workspaceImagePath,
        // ── Multi-canvas ─────────────────────────────────────────────────
        'savedCanvases': _savedCanvases,
        'savedBoards': _savedBoards,
        'currentBoardId': _currentBoardId,
        'openCanvases': _openCanvases.toList(),
        'currentCanvasName': _currentCanvasName,
        'canvasColors': _canvasColors.map((k, v) => MapEntry(k, v.value)),
        'canvasStates': _canvasStates.map(
          (k, v) => MapEntry(k, _serialiseCanvas(v)),
        ),

        // ── Category groups ──────────────────────────────────────────────
        'categoriesGroups': _categoriesGroups.map(
          (groupName, g) => MapEntry(groupName, {
            'projectColors': (g['projectColors'] as Map? ?? {}).map(
              (k, v) => MapEntry(k.toString(), v),
            ),
            'recentColors': g['recentColors'] ?? [],
            'categoryMappings': g['categoryMappings'] ?? {},
            'sidebarSectionOrder': g['sidebarSectionOrder'] ?? [],
            'favoriteProjectIds': g['favoriteProjectIds'] ?? [],
            'sectionExpandedStates': g['sectionExpandedStates'] ?? {},
            'sectionSortAsc': g['sectionSortAsc'] ?? {},
          }),
        ),
        'currentCategoriesGroupName': _currentCategoriesGroupName,

        // ── Sidebar state ────────────────────────────────────────────────
        'projectColors': _projectColors.map((k, v) => MapEntry(k, v.value)),
        'viewColors': _viewColors.map((k, v) => MapEntry(k, v.value)),
        'projectIcons': _projectIcons,
        'projectBacklogEnabled': _projectBacklogEnabled,
        'projectHiddenFromMenu': _projectHiddenFromMenu,
        'projectFolders': _projectFolders.map(
          (k, v) => MapEntry(k, v.toList()),
        ),
        'tagFolders': _tagFolders.map((k, v) => MapEntry(k, v.toList())),
        'projectFolderOrder': _projectFolderOrder,
        'tagFolderOrder': _tagFolderOrder,
        'tagOrder': _tagOrder,
        'noteProjectOrder': _noteProjectOrder,
        'noteTaskOrder': _noteTaskOrder,
        'hiddenNoteProjects': _hiddenNoteProjects.toList(),
        'hiddenNoteTasks': _hiddenNoteTasks.toList(),
        'hiddenTags': _hiddenTags.toList(),
        'tagColors': _tagColors.map((k, v) => MapEntry(k, v.value)),
        'tagIcons': _tagIcons,
        'showHiddenProjects': _showHiddenProjects,
        'ganttEnabled': _ganttEnabled,
        'ganttProportional': _ganttProportional,
        'ganttDayWidth': _ganttDayWidth,
        'ganttForceTimeAlign': _ganttForceTimeAlign,
        'ganttSnapMinutes': _ganttSnapMinutes,
        'ganttShowProjectAxis': _ganttShowProjectAxis,
        'ganttWeekdayColors': _ganttWeekdayColors.map((c) => c.value).toList(),
        'ganttColumnWidths': _ganttColumnWidths.map(
          (k, v) => MapEntry(k.toIso8601String(), v),
        ),
        'ganttLaneHeights': _ganttLaneHeights,
        'themeMode': _themeMode,
        'appLanguage': _appLanguage,
        'timeLocale': _timeLocale,
        'markParentDoneOnSubtasks': _markParentDoneOnSubtasks,
        'firstDayOfWeek': _firstDayOfWeek,
        'nextDayStartHour': _nextDayStartHour,
        'taskDescTemplate': _taskDescTemplate,
        'defaultTimeEstimateMin': _defaultTimeEstimateMin,
        'defaultSubTimeEstimateMin': _defaultSubTimeEstimateMin,
        'trackNextOnDone': _trackNextOnDone,
        'stagingBlocks': _stagingBlocks
            .map((b) => {'type': b.type.name, 'minutes': b.minutes})
            .toList(),
        'soundVolume': _soundVolume,
        'taskDoneSound': _taskDoneSound,
        'increasePitch': _increasePitch,
        'taskWorkStartSound': _taskWorkStartSound,
        'categoryMappings': _categoryMappings.map(
          (k, v) => MapEntry(k, v.toList()),
        ),
        'sidebarSectionOrder': _sidebarSectionOrder,
        'favoriteProjectIds': _favoriteProjectIds.toList(),
        'customTags': _customTags.toList(),
        'sectionSortAsc': _sectionSortAsc,

        // ── Workspace settings ───────────────────────────────────────────
        'defaultOperator': _defaultOperator.name,
        'defaultArrowSize': _defaultArrowSize,
        'plugZoneThickness': _plugZoneThickness,
        'allowDuplicateConnections': _allowDuplicateConnections,
        'showConnectionPlugs': _showConnectionPlugs,
        'showIdOnCards': _showIdOnCards,
        'showProjectName': _showProjectName,
        'showDueDateOnCards': _showDueDateOnCards,
        'showTimeOnCards': _showTimeOnCards,
        'taskCardHorizPadding': _taskCardHorizPadding,
        'showDateOnListedTasks': _showDateOnListedTasks,
        'standardVisibleInfos': _standardVisibleInfos.toList(),
        'gridThickness': _gridThickness,
        'gridColor': _gridColor.value,

        // ── Tasks & Projects (native — workspace-owned) ──────────────────
        // Always written. Tasks are owned entirely by the workspace file;
        // the __meta_ file is only used for one-time imports.
        'tasks': _allTasks.map((t) => t.toJson()).toList(),
        'projects': _projects.map((k, v) => MapEntry(k, v.toJson())),
        'projectOrder': _projectOrder,

        // ── Notes tab state ──────────────────────────────────────────────
        'openNoteTabs': _openNoteTabs,
        'activeNoteId': _activeNoteId,

        // ── Notes collapsed headers ──────────────────────────────────────
        'notesOrgNotesCollapsed': _notesOrgNotesCollapsed.toList(),
        'notesOrgTasksCollapsed': _notesOrgTasksCollapsed.toList(),

        // ── Sidebar nav collapsed folders ────────────────────────────────
        'collapsedNavProjectFolders': _collapsedNavProjectFolders.toList(),

        // ── Active tab / subtab ──────────────────────────────────────────
        'isTasksView': _isTasksView,
        'isNotesView': _isNotesView,
        'isSettingsView': _isSettingsView,
        'tasksNavSection': _tasksNavSection,
        'notesNavSection': _notesNavSection,
      };

      final wsFile = File(_workspaceFilePath(_workspaceId));
      await wsFile.parent.create(recursive: true);
      await wsFile.writeAsString(jsonEncode(data));
    } catch (e) {
      debugPrint('AUTOSAVE ERROR: $e');
    }
  }

  Map<String, dynamic> _deserialiseCanvas(Map<String, dynamic> snap) {
    final taskIds = snap['canvasTasks'] != null
        ? List<String>.from(snap['canvasTasks'])
        : <String>[];
    final taskUiStates = (snap['taskUiStates'] as Map? ?? {})
        .cast<String, dynamic>();

    final tasks = <Task>[];
    for (final id in taskIds) {
      final task = _allTasks.firstWhere(
        (t) => t.id == id,
        orElse: () => Task(
          id: 'err',
          title: 'err',
          isDone: false,
          projectId: '',
          subTaskIds: [],
          timeSpent: 0,
          attachments: [],
          tagIds: [],
        ),
      );
      if (task.id == 'err') continue;
      if (taskUiStates.containsKey(id)) {
        final s = taskUiStates[id] as Map;
        task.isExpanded = s['isExpanded'] ?? false;
        task.cardWidth = (s['cardWidth'] as num?)?.toDouble() ?? 250.0;
        task.cardHeight = (s['cardHeight'] as num?)?.toDouble() ?? 250.0;
        task.isDone = s['isDone'] ?? task.isDone;
        if (s['status'] != null) {
          try {
            task.status = TaskStatus.values.byName(s['status']);
          } catch (_) {
            task.status = task.isDone ? TaskStatus.done : TaskStatus.none;
          }
        }
        if (s['visibleProperties'] != null) {
          task.visibleProperties = Set<String>.from(s['visibleProperties']);
        }
        if (s['propertyHeights'] != null) {
          task.propertyHeights = Map<String, double>.from(s['propertyHeights']);
        }
      }
      tasks.add(task);
    }

    final positions = <String, Offset>{};
    if (snap['taskPositions'] != null) {
      (snap['taskPositions'] as Map).forEach(
        (k, v) => positions[k] = Offset(
          (v['dx'] as num).toDouble(),
          (v['dy'] as num).toDouble(),
        ),
      );
    }

    final junctions = <JunctionNode>[];
    if (snap['junctions'] != null) {
      for (final j in snap['junctions'] as List) {
        LogicalOperator op = LogicalOperator.and;
        if (j['operatorType'] != null) {
          try {
            op = LogicalOperator.values.byName(j['operatorType']);
          } catch (_) {}
        }
        junctions.add(
          JunctionNode(
            id: j['id'],
            position: Offset(
              (j['dx'] as num).toDouble(),
              (j['dy'] as num).toDouble(),
            ),
            operatorType: op,
          ),
        );
      }
    }

    // ── Load ConditionalNodes ─────────────────────────────────────────────────
    final conditionals = <ConditionalNode>[];
    if (snap['conditionals'] != null) {
      for (final c in snap['conditionals'] as List) {
        conditionals.add(
          ConditionalNode(
            id: c['id'],
            position: Offset(
              (c['dx'] as num).toDouble(),
              (c['dy'] as num).toDouble(),
            ),
            width: (c['width'] as num?)?.toDouble() ?? 140,
            height: (c['height'] as num?)?.toDouble() ?? 80,
            label: (c['label'] as String?) ?? '',
          ),
        );
      }
    }

    final relations = <TaskRelation>{};
    if (snap['taskRelations'] != null) {
      for (final r in snap['taskRelations'] as List) {
        final handles = <Offset>[];
        if (r['handles'] != null) {
          for (final h in r['handles'] as List) {
            handles.add(
              Offset((h['dx'] as num).toDouble(), (h['dy'] as num).toDouble()),
            );
          }
        }
        relations.add(
          TaskRelation(
            sourceId: r['sourceId'],
            targetId: r['targetId'],
            sourceLocalPos: Offset(
              (r['sdx'] as num).toDouble(),
              (r['sdy'] as num).toDouble(),
            ),
            targetLocalPos: Offset(
              (r['tdx'] as num).toDouble(),
              (r['tdy'] as num).toDouble(),
            ),
            arrowSize:
                (r['arrowSize'] as num?)?.toDouble() ?? _defaultArrowSize,
            thickness: (r['thickness'] as num?)?.toDouble() ?? 2.0,
            color: r['color'] != null
                ? Color(r['color'] as int)
                : Colors.orangeAccent.withOpacity(0.8),
            handles: handles,
          ),
        );
      }
    }

    return {
      'canvasTasks': tasks,
      'taskPositions': positions,
      'junctions': junctions,
      'conditionals': conditionals,
      'taskRelations': relations,
      'scale': (snap['scale'] as num?)?.toDouble() ?? 1.0,
      'canvasOffset': snap['canvasOffset'] != null
          ? Offset(
              (snap['canvasOffset']['dx'] as num).toDouble(),
              (snap['canvasOffset']['dy'] as num).toDouble(),
            )
          : Offset.zero,
      'bgColor': snap['bgColor'] != null
          ? Color(snap['bgColor'] as int)
          : const Color(0xFF121212),
    };
  }

  /// Opens a workspace. metaPath is optional — when present it points to
  /// a SuperProductivity __meta_ file for data import via the settings panel.
  Future<bool> _loadWorkspaceById(Map<String, String> entry) async {
    final metaPath = entry['metaPath'] ?? '';
    final id = entry['id'] ?? '';
    final name = entry['name'] ?? '';
    if (id.isEmpty) return false;

    // Set active workspace identity and clear all previous workspace state
    // Clear all previous workspace state
    setState(() {
      _workspaceId = id;
      _workspaceName = name;
      _workspaceNameController.text = name;
      _sourceFilePath = metaPath;
      _dataSourceController.text = metaPath;
      _workspaceImagePath = '';
      // Clear canvas state
      _currentCanvasName = '';
      _canvasNameController.text = '';
      _savedCanvases.clear();
      _openCanvases.clear();
      _canvasStates.clear();
      _canvasColors.clear();
      _canvasTasks.clear();
      _taskPositions.clear();
      _junctions.clear();
      _conditionals.clear();
      _selectedConditionalId = null;
      _selectedConditionalIds.clear();
      _taskRelations.clear();
      // Clear category groups
      _currentCategoriesGroupName = '';
      _categoriesGroupNameController.text = '';
      _categoriesGroups.clear();
      // Clear sidebar/projects
      _allTasks.clear();
      _projects.clear();
      _sidebarSectionOrder.clear();
      _favoriteProjectIds.clear();
      _projectColors.clear();
      _categoryMappings.clear();
      _sectionExpandedStates.clear();
      _sectionSortAsc.clear();
      // Clear notes
      _notes.clear();
      _noteFolders.clear();
      _openNoteTabs.clear();
      _notesDetailOpen = false;
      _activeNoteId = null;
      _notesOrgNotesCollapsed.clear();
      _notesOrgTasksCollapsed.clear();
      _collapsedNavProjectFolders.clear();
    });

    // Load workspace config and notes
    await _loadWorkspace();
    await _loadNotes();

    // Persist this as the most-recently opened workspace so the next
    // app launch can restore it automatically.
    _lastWorkspaceId = id;
    await _saveGeneral();

    return true;
  }

  Future<void> _loadWorkspace() async {
    if (_workspaceId.isEmpty) return;
    try {
      final file = File(_workspaceFilePath(_workspaceId));
      if (!await file.exists()) return;

      final data =
          jsonDecode(await file.readAsString()) as Map<String, dynamic>;

      setState(() {
        // Identity
        if (data['workspaceName'] != null) {
          _workspaceName = data['workspaceName'];
          _workspaceNameController.text = _workspaceName;
        }
        if (data['workspaceImagePath'] != null) {
          _workspaceImagePath = data['workspaceImagePath'];
        }
        // Multi-canvas
        if (data['savedBoards'] != null) {
          _savedBoards = List<Map<String, dynamic>>.from(
            (data['savedBoards'] as List).map(
              (e) => Map<String, dynamic>.from(e as Map),
            ),
          );
        }
        _currentBoardId = data['currentBoardId'] ?? '';
        if (data['savedCanvases'] != null) {
          _savedCanvases = List<Map<String, String>>.from(
            (data['savedCanvases'] as List).map(
              (e) => Map<String, String>.from(e),
            ),
          );
        }
        if (data['openCanvases'] != null) {
          _openCanvases = Set<String>.from(data['openCanvases']);
        }
        if (data['canvasColors'] != null) {
          _canvasColors = (data['canvasColors'] as Map).map(
            (k, v) => MapEntry(k.toString(), Color(v as int)),
          );
        }

        // ── Tasks & Projects must be loaded BEFORE canvas states so that
        // _deserialiseCanvas can resolve task IDs against _allTasks. ─────────
        if (data['projects'] != null) {
          _projects = (data['projects'] as Map).map(
            (k, v) => MapEntry(
              k.toString(),
              Project.fromJson(Map<String, dynamic>.from(v as Map)),
            ),
          );
        }
        if (data['projectOrder'] != null) {
          _projectOrder = List<String>.from(data['projectOrder'] as List);
        }
        if (data['tasks'] != null) {
          _allTasks = (data['tasks'] as List)
              .map((e) => Task.fromJson(Map<String, dynamic>.from(e as Map)))
              .toList();
        }

        if (data['canvasStates'] != null) {
          _canvasStates = {};
          (data['canvasStates'] as Map).forEach((k, v) {
            _canvasStates[k.toString()] = _deserialiseCanvas(
              Map<String, dynamic>.from(v),
            );
          });
        }
        final canvasName = data['currentCanvasName'] ?? '';
        _currentCanvasName = canvasName;
        _canvasNameController.text = canvasName;
        if (canvasName.isNotEmpty && _canvasStates.containsKey(canvasName)) {
          _applyCanvas(_canvasStates[canvasName]!);
        }

        // Category groups
        if (data['categoriesGroups'] != null) {
          _categoriesGroups = (data['categoriesGroups'] as Map).map(
            (k, v) => MapEntry(k.toString(), Map<String, dynamic>.from(v)),
          );
        }
        _currentCategoriesGroupName = data['currentCategoriesGroupName'] ?? '';
        _categoriesGroupNameController.text = _currentCategoriesGroupName;

        // Sidebar
        if (data['projectColors'] != null) {
          _projectColors = (data['projectColors'] as Map).map(
            (k, v) => MapEntry(k.toString(), Color(v as int)),
          );
        }
        if (data['viewColors'] != null) {
          _viewColors = (data['viewColors'] as Map).map(
            (k, v) => MapEntry(k.toString(), Color(v as int)),
          );
        }
        if (data['projectIcons'] != null) {
          _projectIcons = Map<String, String>.from(data['projectIcons'] as Map);
        }
        if (data['projectBacklogEnabled'] != null) {
          _projectBacklogEnabled = Map<String, bool>.from(
            data['projectBacklogEnabled'] as Map,
          );
        }
        if (data['projectHiddenFromMenu'] != null) {
          _projectHiddenFromMenu = Map<String, bool>.from(
            data['projectHiddenFromMenu'] as Map,
          );
        }
        _showHiddenProjects = data['showHiddenProjects'] ?? false;
        _ganttEnabled = data['ganttEnabled'] ?? false;
        _ganttProportional = data['ganttProportional'] ?? true;
        _ganttDayWidth = (data['ganttDayWidth'] as num?)?.toDouble() ?? 200.0;
        _ganttForceTimeAlign = data['ganttForceTimeAlign'] ?? false;
        _ganttSnapMinutes = data['ganttSnapMinutes'] ?? 30;
        _ganttShowProjectAxis = data['ganttShowProjectAxis'] ?? false;
        if (data['ganttWeekdayColors'] != null) {
          final raw = data['ganttWeekdayColors'] as List;
          if (raw.length == 7) {
            _ganttWeekdayColors = raw.map((v) => Color(v as int)).toList();
          }
        }
        if (data['ganttColumnWidths'] != null) {
          _ganttColumnWidths = (data['ganttColumnWidths'] as Map).map(
            (k, v) =>
                MapEntry(DateTime.parse(k.toString()), (v as num).toDouble()),
          );
        } else if (data['ganttSegmentWidths'] != null) {
          // Migrate legacy int-keyed widths → date-keyed on first load
          final ref = _ganttReferenceDay;
          _ganttColumnWidths = (data['ganttSegmentWidths'] as Map).map((k, v) {
            final idx = int.tryParse(k.toString()) ?? 0;
            final d = ref.add(Duration(days: idx));
            return MapEntry(
              DateTime(d.year, d.month, d.day),
              (v as num).toDouble(),
            );
          });
        }
        if (data['ganttLaneHeights'] != null) {
          _ganttLaneHeights = Map<String, double>.from(
            (data['ganttLaneHeights'] as Map).map(
              (k, v) => MapEntry(k.toString(), (v as num).toDouble()),
            ),
          );
        }
        _themeMode = data['themeMode'] ?? 'dark';
        WidgetsBinding.instance.addPostFrameCallback(
          (_) => widget.onThemeChange?.call(_themeMode == 'light'),
        );
        _appLanguage = data['appLanguage'] ?? 'en';
        _timeLocale = data['timeLocale'] ?? 'en_US';
        _markParentDoneOnSubtasks = data['markParentDoneOnSubtasks'] ?? false;
        _firstDayOfWeek = data['firstDayOfWeek'] ?? 1;
        _nextDayStartHour = data['nextDayStartHour'] ?? 0;
        _taskDescTemplate = data['taskDescTemplate'] ?? '';
        _defaultTimeEstimateMin = data['defaultTimeEstimateMin'] ?? 0;
        _defaultSubTimeEstimateMin = data['defaultSubTimeEstimateMin'] ?? 0;
        _trackNextOnDone = data['trackNextOnDone'] ?? false;
        if (data['stagingBlocks'] != null) {
          final raw = data['stagingBlocks'] as List;
          final parsed = <_StagingBlock>[];
          for (final item in raw) {
            final typeStr = item['type'] as String? ?? 'work';
            final mins = (item['minutes'] as num?)?.toInt() ?? 25;
            _StagingType type;
            try {
              type = _StagingType.values.byName(typeStr);
            } catch (_) {
              type = _StagingType.work;
            }
            parsed.add(_StagingBlock(type: type, minutes: mins));
          }
          if (parsed.isNotEmpty) _stagingBlocks = parsed;
        }
        _soundVolume = (data['soundVolume'] as num?)?.toDouble() ?? 0.5;
        _taskDoneSound = data['taskDoneSound'] ?? 'Small Ding';
        _increasePitch = data['increasePitch'] ?? false;
        _taskWorkStartSound = data['taskWorkStartSound'] ?? '';
        if (data['projectFolders'] != null) {
          _projectFolders = (data['projectFolders'] as Map).map(
            (k, v) => MapEntry(k as String, Set<String>.from(v as List)),
          );
        }
        if (data['tagFolders'] != null) {
          _tagFolders = (data['tagFolders'] as Map).map(
            (k, v) => MapEntry(k as String, Set<String>.from(v as List)),
          );
        }
        if (data['projectFolderOrder'] != null) {
          _projectFolderOrder = List<String>.from(
            data['projectFolderOrder'] as List,
          );
        }
        if (data['tagFolderOrder'] != null) {
          _tagFolderOrder = List<String>.from(data['tagFolderOrder'] as List);
        }
        if (data['tagOrder'] != null) {
          _tagOrder = List<String>.from(data['tagOrder'] as List);
        }
        if (data['noteProjectOrder'] != null) {
          _noteProjectOrder = List<String>.from(
            data['noteProjectOrder'] as List,
          );
        }
        if (data['noteTaskOrder'] != null) {
          _noteTaskOrder = List<String>.from(data['noteTaskOrder'] as List);
        }
        if (data['hiddenNoteProjects'] != null) {
          _hiddenNoteProjects = Set<String>.from(
            data['hiddenNoteProjects'] as List,
          );
        }
        if (data['hiddenNoteTasks'] != null) {
          _hiddenNoteTasks = Set<String>.from(data['hiddenNoteTasks'] as List);
        }
        if (data['hiddenTags'] != null) {
          _hiddenTags.addAll(List<String>.from(data['hiddenTags'] as List));
          if (data['tagColors'] != null) {
            _tagColors = (data['tagColors'] as Map).map(
              (k, v) => MapEntry(k.toString(), Color(v as int)),
            );
          }
          if (data['tagIcons'] != null) {
            _tagIcons = Map<String, String>.from(data['tagIcons'] as Map);
          }
        }
        if (data['categoryMappings'] != null) {
          _categoryMappings = (data['categoryMappings'] as Map).map(
            (k, v) => MapEntry(k.toString(), Set<String>.from(v)),
          );
        }
        if (data['sidebarSectionOrder'] != null) {
          _sidebarSectionOrder = List<String>.from(data['sidebarSectionOrder']);
        }
        if (data['favoriteProjectIds'] != null) {
          _favoriteProjectIds = Set<String>.from(data['favoriteProjectIds']);
        }
        if (data['customTags'] != null) {
          _customTags.addAll(List<String>.from(data['customTags']));
        }
        if (data['sectionExpandedStates'] != null) {
          _sectionExpandedStates = Map<String, bool>.from(
            data['sectionExpandedStates'],
          );
        }
        if (data['sectionSortAsc'] != null) {
          _sectionSortAsc = Map<String, bool>.from(data['sectionSortAsc']);
        }

        // Settings
        if (data['defaultOperator'] != null) {
          try {
            _defaultOperator = LogicalOperator.values.byName(
              data['defaultOperator'],
            );
          } catch (_) {}
        }
        _isIfMode = false;
        _defaultArrowSize =
            (data['defaultArrowSize'] as num?)?.toDouble() ?? 10.0;
        _plugZoneThickness =
            (data['plugZoneThickness'] as num?)?.toDouble() ?? 15.0;
        _allowDuplicateConnections = data['allowDuplicateConnections'] ?? false;
        _showConnectionPlugs = data['showConnectionPlugs'] ?? false;
        _showIdOnCards = data['showIdOnCards'] ?? true;
        _showProjectName = data['showProjectName'] ?? true;
        _showDueDateOnCards = data['showDueDateOnCards'] ?? false;
        _showTimeOnCards = data['showTimeOnCards'] ?? false;
        _taskCardHorizPadding =
            (data['taskCardHorizPadding'] as num?)?.toDouble() ?? 12.0;
        _showDateOnListedTasks = data['showDateOnListedTasks'] ?? false;
        if (data['standardVisibleInfos'] != null) {
          _standardVisibleInfos = Set<String>.from(
            data['standardVisibleInfos'],
          );
        }
        _gridThickness = (data['gridThickness'] as num?)?.toDouble() ?? 1.0;
        if (data['gridColor'] != null) {
          _gridColor = Color(data['gridColor'] as int);
        }

        // ── Notes tab state ──────────────────────────────────────────────
        if (data['openNoteTabs'] != null) {
          _openNoteTabs
            ..clear()
            ..addAll(List<String>.from(data['openNoteTabs'] as List));
        }
        if (data['activeNoteId'] != null) {
          _activeNoteId = data['activeNoteId'] as String;
        }

        // ── Notes collapsed headers ──────────────────────────────────────
        if (data['notesOrgNotesCollapsed'] != null) {
          _notesOrgNotesCollapsed
            ..clear()
            ..addAll(List<String>.from(data['notesOrgNotesCollapsed'] as List));
        }
        if (data['notesOrgTasksCollapsed'] != null) {
          _notesOrgTasksCollapsed
            ..clear()
            ..addAll(List<String>.from(data['notesOrgTasksCollapsed'] as List));
        }

        // ── Sidebar nav collapsed folders ────────────────────────────────
        if (data['collapsedNavProjectFolders'] != null) {
          _collapsedNavProjectFolders
            ..clear()
            ..addAll(
              List<String>.from(data['collapsedNavProjectFolders'] as List),
            );
        }

        // ── Restore active tab / subtab ──────────────────────────────────
        if (data['isTasksView'] != null) _isTasksView = data['isTasksView'] as bool;
        if (data['isNotesView'] != null) _isNotesView = data['isNotesView'] as bool;
        if (data['isSettingsView'] != null) _isSettingsView = data['isSettingsView'] as bool;
        if (data['tasksNavSection'] != null) _tasksNavSection = data['tasksNavSection'] as String;
        if (data['notesNavSection'] != null) _notesNavSection = data['notesNavSection'] as String;
      });
    } catch (e) {
      debugPrint('LOAD WORKSPACE ERROR: $e');
    }
  }

  // ── Restore workspace from a .json file picked by the user ────────────────
  Future<void> _restoreWorkspaceFromFile() async {
    // Step 1: pick the backup .json file.
    final result = await FilePicker.platform.pickFiles(
      dialogTitle: 'Restore workspace from file',
      type: FileType.custom,
      allowedExtensions: ['json'],
      allowMultiple: false,
    );
    if (result == null || result.files.single.path == null) return;
    final srcPath = result.files.single.path!;

    Map<String, dynamic> data;
    try {
      data =
          jsonDecode(await File(srcPath).readAsString())
              as Map<String, dynamic>;
    } catch (e) {
      if (mounted) {
        showDialog(
          context: context,
          builder: (_) => AlertDialog(
            backgroundColor: const Color(0xFF252525),
            title: const Text(
              'Invalid file',
              style: TextStyle(color: Colors.white),
            ),
            content: Text(
              'Could not read workspace file: $e',
              style: const TextStyle(color: Colors.white70, fontSize: 13),
            ),
            actions: [
              TextButton(
                onPressed: () => Navigator.pop(context),
                child: const Text('OK'),
              ),
            ],
          ),
        );
      }
      return;
    }

    final id = data['id'] as String? ?? _generateId();
    final name = data['workspaceName'] as String? ?? 'Restored Workspace';
    final meta = data['metaPath'] as String? ?? '';

    // Step 2: ask the user where to place the restored workspace.
    // Pre-select the backup file's grandparent as a sensible default
    // (standard workspace files live at <wsRoot>/metadata/workspace_X.json).
    final destDir = await FilePicker.platform.getDirectoryPath(
      dialogTitle: 'Choose folder for restored workspace',
    );
    if (destDir == null) return;

    final wsRoot = destDir;
    final dest = File('$wsRoot/metadata/workspace_$id.json');
    await dest.parent.create(recursive: true);
    // Only write if the source and destination are different paths.
    if (dest.path != srcPath) {
      await dest.writeAsString(jsonEncode({...data, 'id': id}));
    }

    final entry = {
      'id': id,
      'name': name,
      'metaPath': meta,
      'basePath': wsRoot,
    };

    // Register in workspace list if not already there.
    setState(() {
      if (!_savedWorkspaces.any((w) => w['id'] == id)) {
        _savedWorkspaces.add(entry);
      }
    });
    await _saveGeneral();

    // Close switcher dialog then load — deferred to avoid navigation race.
    if (mounted) Navigator.of(context, rootNavigator: true).pop();
    WidgetsBinding.instance.addPostFrameCallback((_) {
      _loadWorkspaceById(entry);
    });
  }

  TaskRelation? _getRelationAt(Offset localPos) {
    const double threshold = 15.0; // Distance in screen pixels
    final worldPos = (localPos - _canvasOffset) / _scale;

    for (var rel in _taskRelations) {
      // Get absolute world positions of start and end
      Offset start = _getRelationWorldPos(rel.sourceId, rel.sourceLocalPos);
      Offset end = _getRelationWorldPos(rel.targetId, rel.targetLocalPos);

      // Simple segment check (includes handles if any)
      List<Offset> segments = [start, ...rel.handles, end];
      for (int i = 0; i < segments.length - 1; i++) {
        double dist = _distToSegment(worldPos, segments[i], segments[i + 1]);
        if (dist * _scale < threshold) return rel;
      }
    }
    return null;
  }

  double _distToSegment(Offset p, Offset v, Offset w) {
    double l2 = (v - w).distanceSquared;
    if (l2 == 0.0) return (p - v).distance;
    double t =
        ((p.dx - v.dx) * (w.dx - v.dx) + (p.dy - v.dy) * (w.dy - v.dy)) / l2;
    t = t.clamp(0.0, 1.0);
    return (p - Offset(v.dx + t * (w.dx - v.dx), v.dy + t * (w.dy - v.dy)))
        .distance;
  }

  Offset _getRelationWorldPos(String id, Offset local) {
    if (_taskPositions.containsKey(id)) return _taskPositions[id]! + local;
    // ConditionalNode — check before junctions to avoid StateError
    final cnd = _conditionals.firstWhere(
      (c) => c.id == id,
      orElse: () => ConditionalNode(id: '', position: Offset.zero),
    );
    if (cnd.id.isNotEmpty) return cnd.position + local;
    final jnc = _junctions.firstWhere((j) => j.id == id);
    return jnc.position + local;
  }

  /// Projects [pos] (local to ConditionalNode) onto its rhombus border,
  /// clamped to the allowed x-zone.
  ///   isInput  → x ∈ [0,   0.4·w]  (left side)
  ///   isOutput → x ∈ [0.5·w, w]    (right side)
  /// The top/bottom edge is chosen by whether [pos.dy] is above/below centre.
  Offset _snapToConditionalBorder(
    Offset pos,
    double w,
    double h, {
    required bool isInput,
  }) {
    final cx = w / 2;
    final cy = h / 2;
    final minX = isInput ? 0.0 : w * 0.5;
    final maxX = isInput ? w * 0.4 : w;
    final dx = pos.dx.clamp(minX, maxX);
    final preferTop = pos.dy < cy;

    final double dy;
    if (dx <= cx) {
      // Left half of diamond
      dy = preferTop ? cy * (1 - dx / cx) : cy * (1 + dx / cx);
    } else {
      // Right half of diamond
      dy = preferTop ? cy * (dx / cx - 1) : h - cy * (dx / cx - 1);
    }
    return Offset(dx, dy);
  }

  List<Widget> _buildRhombusResizeHandles(ConditionalNode c, Offset sp) {
    const double hs = 12.0; // handle size in pixels (larger = easier to grab)
    final double sw = c.width * _scale;
    final double sh = c.height * _scale;

    // Build a single handle at canvas-space position (cx, cy)
    Widget handle({
      required double cx, // canvas-space center x
      required double cy, // canvas-space center y
      required MouseCursor cursor,
      required void Function(DragUpdateDetails) onPanUpdate,
    }) => Positioned(
      left: sp.dx + cx - hs / 2,
      top: sp.dy + cy - hs / 2,
      child: MouseRegion(
        cursor: cursor,
        child: GestureDetector(
          behavior: HitTestBehavior.opaque,
          onPanUpdate: (d) => setState(() => onPanUpdate(d)),
          child: Container(
            width: hs,
            height: hs,
            decoration: BoxDecoration(
              color: Colors.white,
              border: Border.all(color: const Color(0xFF4FC3F7), width: 1.5),
              borderRadius: BorderRadius.circular(2),
            ),
          ),
        ),
      ),
    );

    return [
      // right
      handle(
        cx: sw,
        cy: sh / 2,
        cursor: SystemMouseCursors.resizeColumn,
        onPanUpdate: (d) => c.width = (c.width + d.delta.dx / _scale).clamp(
          _kRhombusMinWidth,
          9999.0,
        ),
      ),
      // bottom
      handle(
        cx: sw / 2,
        cy: sh,
        cursor: SystemMouseCursors.resizeRow,
        onPanUpdate: (d) => c.height = (c.height + d.delta.dy / _scale).clamp(
          _kRhombusMinHeight,
          9999.0,
        ),
      ),
      // left
      handle(
        cx: 0,
        cy: sh / 2,
        cursor: SystemMouseCursors.resizeColumn,
        onPanUpdate: (d) {
          final dx = d.delta.dx / _scale;
          final nw = (c.width - dx).clamp(_kRhombusMinWidth, 9999.0);
          c.position = Offset(c.position.dx + (c.width - nw), c.position.dy);
          c.width = nw;
        },
      ),
      // top
      handle(
        cx: sw / 2,
        cy: 0,
        cursor: SystemMouseCursors.resizeRow,
        onPanUpdate: (d) {
          final dy = d.delta.dy / _scale;
          final nh = (c.height - dy).clamp(_kRhombusMinHeight, 9999.0);
          c.position = Offset(c.position.dx, c.position.dy + (c.height - nh));
          c.height = nh;
        },
      ),
      // top-left
      handle(
        cx: 0,
        cy: 0,
        cursor: SystemMouseCursors.resizeUpLeft,
        onPanUpdate: (d) {
          final dx = d.delta.dx / _scale;
          final dy = d.delta.dy / _scale;
          final nw = (c.width - dx).clamp(_kRhombusMinWidth, 9999.0);
          final nh = (c.height - dy).clamp(_kRhombusMinHeight, 9999.0);
          c.position = Offset(
            c.position.dx + (c.width - nw),
            c.position.dy + (c.height - nh),
          );
          c.width = nw;
          c.height = nh;
        },
      ),
      // top-right
      handle(
        cx: sw,
        cy: 0,
        cursor: SystemMouseCursors.resizeUpRight,
        onPanUpdate: (d) {
          final dy = d.delta.dy / _scale;
          final nh = (c.height - dy).clamp(_kRhombusMinHeight, 9999.0);
          c.position = Offset(c.position.dx, c.position.dy + (c.height - nh));
          c.height = nh;
          c.width = (c.width + d.delta.dx / _scale).clamp(
            _kRhombusMinWidth,
            9999.0,
          );
        },
      ),
      // bottom-left
      handle(
        cx: 0,
        cy: sh,
        cursor: SystemMouseCursors.resizeDownLeft,
        onPanUpdate: (d) {
          final dx = d.delta.dx / _scale;
          final nw = (c.width - dx).clamp(_kRhombusMinWidth, 9999.0);
          c.position = Offset(c.position.dx + (c.width - nw), c.position.dy);
          c.width = nw;
          c.height = (c.height + d.delta.dy / _scale).clamp(
            _kRhombusMinHeight,
            9999.0,
          );
        },
      ),
      // bottom-right
      handle(
        cx: sw,
        cy: sh,
        cursor: SystemMouseCursors.resizeDownRight,
        onPanUpdate: (d) {
          c.width = (c.width + d.delta.dx / _scale).clamp(
            _kRhombusMinWidth,
            9999.0,
          );
          c.height = (c.height + d.delta.dy / _scale).clamp(
            _kRhombusMinHeight,
            9999.0,
          );
        },
      ),
    ];
  }

