  bool _handleKeyboardEvent(KeyEvent event) {
    // Rebuild when Shift or Ctrl is pressed/released to update resize-mode handles
    if (event.logicalKey == LogicalKeyboardKey.controlLeft ||
        event.logicalKey == LogicalKeyboardKey.controlRight ||
        event.logicalKey == LogicalKeyboardKey.shiftLeft ||
        event.logicalKey == LogicalKeyboardKey.shiftRight) {
      setState(() {});
    }

    // 2. NEW: Allow ESC to cancel an active connection (arrow line)
    if (event is KeyDownEvent &&
        event.logicalKey == LogicalKeyboardKey.escape) {
      // Always defocus any active text field first
      FocusManager.instance.primaryFocus?.unfocus();

      // If editing a conditional label or a task title, exit edit mode only
      if (_editingConditionalId != null || _editingTaskId != null) {
        setState(() {
          _editingConditionalId = null;
          _editingTaskId = null;
        });
        return true;
      }

      // Cancel an in-progress connection drag
      if (_connectingSourceId != null) {
        setState(() {
          _connectingSourceId = null;
          _connectingSourceLocalPos = null;
          _currentCursorLocalPos = null;
        });
        return true;
      }

      // Clear all canvas selections
      if (_selectedTaskIds.isNotEmpty ||
          _selectedJunctionIds.isNotEmpty ||
          _selectedConditionalIds.isNotEmpty ||
          _selectedRelationKey != null ||
          _selectedRelationKeys.isNotEmpty ||
          _selectedCanvasTaskId != null) {
        setState(() {
          _selectedTaskIds.clear();
          _selectedCanvasTaskId = null;
          _selectedJunctionId = null;
          _selectedJunctionIds.clear();
          _selectedConditionalId = null;
          _selectedConditionalIds.clear();
          _selectedRelationKey = null;
          _selectedRelationKeys.clear();
        });
        return true;
      }
    }

    // 3. Delete selected canvas items (task cards or connecting lines)
    if (event is KeyDownEvent &&
        event.logicalKey == LogicalKeyboardKey.delete) {
      // Delete selected relation line (single click-selection)
      if (_selectedRelationKey != null) {
        final parts = _selectedRelationKey!.split('→');
        if (parts.length == 2) {
          setState(() {
            _taskRelations.removeWhere(
              (r) => r.sourceId == parts[0] && r.targetId == parts[1],
            );
            _selectedRelationKey = null;
          });
          _saveWorkspace();
          return true;
        }
      }

      // Delete all marquee-selected relation lines
      if (_selectedRelationKeys.isNotEmpty) {
        setState(() {
          for (final key in _selectedRelationKeys) {
            final parts = key.split('→');
            if (parts.length == 2) {
              _taskRelations.removeWhere(
                (r) => r.sourceId == parts[0] && r.targetId == parts[1],
              );
            }
          }
          _selectedRelationKeys.clear();
        });
        _saveWorkspace();
        return true;
      }

      // Delete all selected nodes (tasks, junctions, conditionals) in one pass
      // so that a mixed marquee-selection removes everything at once.
      if (_selectedTaskIds.isNotEmpty ||
          _selectedJunctionIds.isNotEmpty ||
          _selectedConditionalIds.isNotEmpty) {
        setState(() {
          final removedTasks = Set<String>.from(_selectedTaskIds);
          final removedJunctions = Set<String>.from(_selectedJunctionIds);
          final removedConditionals = Set<String>.from(_selectedConditionalIds);
          final allRemovedIds = {
            ...removedTasks,
            ...removedJunctions,
            ...removedConditionals,
          };

          // Remove task cards and their canvas positions
          _canvasTasks.removeWhere((t) => removedTasks.contains(t.id));
          for (final id in removedTasks) {
            _taskPositions.remove(id);
          }

          // Remove junction nodes
          _junctions.removeWhere((j) => removedJunctions.contains(j.id));
          _taskPositions.removeWhere((k, _) => removedJunctions.contains(k));

          // Remove conditional nodes
          _conditionals.removeWhere((c) => removedConditionals.contains(c.id));

          // Remove every relation that touches any removed node
          _taskRelations.removeWhere(
            (r) =>
                allRemovedIds.contains(r.sourceId) ||
                allRemovedIds.contains(r.targetId),
          );

          // Clear all selection state
          _selectedTaskIds.clear();
          _selectedCanvasTaskId = null;
          _selectedJunctionIds.clear();
          _selectedJunctionId = null;
          _selectedConditionalIds.clear();
          _selectedConditionalId = null;
          _selectedRelationKey = null;
          _selectedRelationKeys.clear();
        });
        _saveWorkspace();
        return true;
      }
    }

    return false;
  }

  Size _viewportSize = Size.zero;

  Rect _getContentBounds() {
    if (_taskPositions.isEmpty) {
      return Rect.fromLTWH(0, 0, _viewportSize.width, _viewportSize.height);
    }
    double minX = 0,
        minY = 0,
        maxX = _viewportSize.width,
        maxY = _viewportSize.height;

    _taskPositions.values.forEach((pos) {
      double scaledX = pos.dx * _scale;
      double scaledY = pos.dy * _scale;

      minX = min(minX, scaledX);
      minY = min(minY, scaledY);
      maxX = max(maxX, scaledX + (220 * _scale)); // 220 is card width
      maxY = max(maxY, scaledY + (60 * _scale)); // 60 is card height
    });
    // Include current pan in bounds to allow scrolling back to origin
    minX = min(minX, -_canvasOffset.dx);
    minY = min(minY, -_canvasOffset.dy);
    maxX = max(maxX, _viewportSize.width - _canvasOffset.dx);
    maxY = max(maxY, _viewportSize.height - _canvasOffset.dy);
    return Rect.fromLTRB(minX, minY, maxX, maxY);
  }

  void _deleteCategory(String sectionName) {
    setState(() {
      _sidebarSectionOrder.remove(sectionName);
      _sectionExpandedStates.remove(sectionName);
      _sectionSortAsc.remove(sectionName);
      _categoryMappings.remove(sectionName);
    });
  }

  // ── Unified color picker ─────────────────────────────────────────────────
  void _showUnifiedColorPicker({
    required String title,
    required Color initialColor,
    required void Function(Color) onApply,
    VoidCallback? onReset,
    bool showRecentColors = false,
    String? colorContext, // Feature 3: e.g. 'projectColor', 'canvasGridColor'
  }) {
    Color pickerColor = initialColor;

    final rController = TextEditingController(text: pickerColor.red.toString());
    final gController = TextEditingController(
      text: pickerColor.green.toString(),
    );
    final bController = TextEditingController(
      text: pickerColor.blue.toString(),
    );
    final hexController = TextEditingController(
      text: pickerColor.value
          .toRadixString(16)
          .padLeft(8, '0')
          .substring(2)
          .toUpperCase(),
    );

    final hsv0 = HSVColor.fromColor(pickerColor);
    final hsl0 = HSLColor.fromColor(pickerColor);
    final hController = TextEditingController(
      text: hsv0.hue.toStringAsFixed(0),
    );
    final sHsvController = TextEditingController(
      text: (hsv0.saturation * 100).toStringAsFixed(0),
    );
    final vController = TextEditingController(
      text: (hsv0.value * 100).toStringAsFixed(0),
    );
    final sHslController = TextEditingController(
      text: (hsl0.saturation * 100).toStringAsFixed(0),
    );
    final lController = TextEditingController(
      text: (hsl0.lightness * 100).toStringAsFixed(0),
    );

    void syncFields(Color c, StateSetter ss) {
      rController.text = c.red.toString();
      gController.text = c.green.toString();
      bController.text = c.blue.toString();
      hexController.text = c.value
          .toRadixString(16)
          .padLeft(8, '0')
          .substring(2)
          .toUpperCase();
      final hsv = HSVColor.fromColor(c);
      final hsl = HSLColor.fromColor(c);
      hController.text = hsv.hue.toStringAsFixed(0);
      sHsvController.text = (hsv.saturation * 100).toStringAsFixed(0);
      vController.text = (hsv.value * 100).toStringAsFixed(0);
      sHslController.text = (hsl.saturation * 100).toStringAsFixed(0);
      lController.text = (hsl.lightness * 100).toStringAsFixed(0);
    }

    showDialog(
      context: context,
      builder: (context) => StatefulBuilder(
        builder: (context, ss) {
          void fromRGB() {
            final c = Color.fromARGB(
              255,
              (int.tryParse(rController.text) ?? 0).clamp(0, 255),
              (int.tryParse(gController.text) ?? 0).clamp(0, 255),
              (int.tryParse(bController.text) ?? 0).clamp(0, 255),
            );
            ss(() => pickerColor = c);
            syncFields(c, ss);
          }

          void fromHex(String hex) {
            final clean = hex.replaceAll('#', '');
            if (clean.length == 6) {
              final value = int.tryParse('FF$clean', radix: 16);
              if (value != null) {
                final c = Color(value);
                ss(() => pickerColor = c);
                syncFields(c, ss);
              }
            }
          }

          void fromHSV() {
            final h = (double.tryParse(hController.text) ?? 0).clamp(
              0.0,
              360.0,
            );
            final s = ((double.tryParse(sHsvController.text) ?? 0) / 100).clamp(
              0.0,
              1.0,
            );
            final v = ((double.tryParse(vController.text) ?? 0) / 100).clamp(
              0.0,
              1.0,
            );
            final c = HSVColor.fromAHSV(1.0, h, s, v).toColor();
            ss(() => pickerColor = c);
            syncFields(c, ss);
          }

          void fromHSL() {
            final h = (double.tryParse(hController.text) ?? 0).clamp(
              0.0,
              360.0,
            );
            final s = ((double.tryParse(sHslController.text) ?? 0) / 100).clamp(
              0.0,
              1.0,
            );
            final l = ((double.tryParse(lController.text) ?? 0) / 100).clamp(
              0.0,
              1.0,
            );
            final c = HSLColor.fromAHSL(1.0, h, s, l).toColor();
            ss(() => pickerColor = c);
            syncFields(c, ss);
          }

          Widget field(
            String label,
            TextEditingController ctrl, {
            bool isHex = false,
            VoidCallback? onSub,
          }) {
            return Column(
              mainAxisSize: MainAxisSize.min,
              children: [
                Text(
                  label,
                  style: const TextStyle(
                    color: Colors.white38,
                    fontSize: 9,
                    fontWeight: FontWeight.bold,
                  ),
                ),
                const SizedBox(height: 4),
                SizedBox(
                  width: isHex ? 110 : 38,
                  child: TextField(
                    controller: ctrl,
                    textAlign: TextAlign.center,
                    style: const TextStyle(color: Colors.white, fontSize: 11),
                    keyboardType: isHex
                        ? TextInputType.text
                        : TextInputType.number,
                    inputFormatters: isHex
                        ? [
                            FilteringTextInputFormatter.allow(
                              RegExp(r'[0-9a-fA-F]'),
                            ),
                            LengthLimitingTextInputFormatter(6),
                          ]
                        : [
                            FilteringTextInputFormatter.digitsOnly,
                            LengthLimitingTextInputFormatter(3),
                          ],
                    decoration: const InputDecoration(
                      isDense: true,
                      contentPadding: EdgeInsets.symmetric(
                        vertical: 8,
                        horizontal: 4,
                      ),
                      enabledBorder: OutlineInputBorder(
                        borderSide: BorderSide(color: Colors.white10),
                      ),
                      focusedBorder: OutlineInputBorder(
                        borderSide: BorderSide(color: Colors.blueAccent),
                      ),
                    ),
                    onChanged: (v) {
                      if (onSub != null) {
                        onSub();
                      } else if (isHex) {
                        fromHex(v);
                      } else {
                        fromRGB();
                      }
                    },
                  ),
                ),
              ],
            );
          }

          return AlertDialog(
            backgroundColor: const Color(0xFF1A1A1A),
            title: Text(
              title,
              style: const TextStyle(color: Colors.white, fontSize: 15),
            ),
            contentPadding: const EdgeInsets.fromLTRB(24, 16, 24, 12),
            content: SizedBox(
              width: 500,
              child: Column(
                mainAxisSize: MainAxisSize.min,
                children: [
                  Row(
                    crossAxisAlignment: CrossAxisAlignment.center,
                    children: [
                      Expanded(
                        flex: 3,
                        child: ColorPicker(
                          pickerColor: pickerColor,
                          onColorChanged: (c) {
                            ss(() => pickerColor = c);
                            syncFields(c, ss);
                          },
                          enableAlpha: true,
                          displayThumbColor: true,
                          pickerAreaHeightPercent: 0.7,
                          hexInputBar: false,
                          showLabel: false,
                          portraitOnly: true,
                        ),
                      ),
                      const SizedBox(width: 16),
                      Expanded(
                        flex: 2,
                        child: Column(
                          mainAxisAlignment: MainAxisAlignment.center,
                          children: [
                            // RGB
                            Row(
                              mainAxisAlignment: MainAxisAlignment.center,
                              children: [
                                field('R', rController),
                                const SizedBox(width: 4),
                                field('G', gController),
                                const SizedBox(width: 4),
                                field('B', bController),
                              ],
                            ),
                            const SizedBox(height: 12),
                            // HSV
                            Row(
                              mainAxisAlignment: MainAxisAlignment.center,
                              children: [
                                field('H', hController, onSub: fromHSV),
                                const SizedBox(width: 4),
                                field('S', sHsvController, onSub: fromHSV),
                                const SizedBox(width: 4),
                                field('V', vController, onSub: fromHSV),
                              ],
                            ),
                            const SizedBox(height: 12),
                            // HSL
                            Row(
                              mainAxisAlignment: MainAxisAlignment.center,
                              children: [
                                field('H', hController, onSub: fromHSL),
                                const SizedBox(width: 4),
                                field('S', sHslController, onSub: fromHSL),
                                const SizedBox(width: 4),
                                field('L', lController, onSub: fromHSL),
                              ],
                            ),
                            const SizedBox(height: 12),
                            field('HEX', hexController, isHex: true),
                          ],
                        ),
                      ),
                    ],
                  ),
                  if (showRecentColors || colorContext != null) ...[
                    const Divider(color: Colors.white10, height: 24),

                    // ── Row 1: Global recent colors ────────────────────
                    if (_recentColors.isNotEmpty) ...[
                      _colorRowLabel('Recent'),
                      const SizedBox(height: 6),
                      SizedBox(
                        height: 28,
                        child: ListView(
                          scrollDirection: Axis.horizontal,
                          children: _recentColors
                              .map(
                                (c) => _colorSwatch(
                                  color: c,
                                  isActive: pickerColor == c,
                                  isFavorite: _favoriteColors.contains(c),
                                  ss: ss,
                                  onTap: () {
                                    ss(() => pickerColor = c);
                                    syncFields(c, ss);
                                  },
                                  onFavToggle: () {
                                    if (_favoriteColors.contains(c)) {
                                      _favoriteColors.remove(c);
                                    } else {
                                      _favoriteColors.insert(0, c);
                                    }
                                    _saveWorkspace();
                                  },
                                  onRemove: () {
                                    _recentColors.remove(c);
                                    _saveWorkspace();
                                  },
                                ),
                              )
                              .toList(),
                        ),
                      ),
                      const SizedBox(height: 10),
                    ],

                    // ── Row 2: Context recent colors ───────────────────
                    if (colorContext != null &&
                        (_contextRecentColors[colorContext]?.isNotEmpty ??
                            false)) ...[
                      _colorRowLabel(
                        'Recent in ${_contextLabel(colorContext!)}',
                      ),
                      const SizedBox(height: 6),
                      SizedBox(
                        height: 28,
                        child: ListView(
                          scrollDirection: Axis.horizontal,
                          children: _contextRecentColors[colorContext]!
                              .map(
                                (c) => _colorSwatch(
                                  color: c,
                                  isActive: pickerColor == c,
                                  isFavorite: _favoriteColors.contains(c),
                                  ss: ss,
                                  onTap: () {
                                    ss(() => pickerColor = c);
                                    syncFields(c, ss);
                                  },
                                  onFavToggle: () {
                                    if (_favoriteColors.contains(c)) {
                                      _favoriteColors.remove(c);
                                    } else {
                                      _favoriteColors.insert(0, c);
                                    }
                                    _saveWorkspace();
                                  },
                                  onRemove: null,
                                ),
                              )
                              .toList(),
                        ),
                      ),
                      const SizedBox(height: 10),
                    ],

                    // ── Row 3: Favorites (unlimited, horizontally scrollable) ─
                    _colorRowLabel('Favorites ★'),
                    const SizedBox(height: 6),
                    SizedBox(
                      height: 28,
                      child: _favoriteColors.isEmpty
                          ? const Text(
                              'No favorites yet — hover a swatch and tap ★',
                              style: TextStyle(
                                fontSize: 10,
                                color: Colors.white24,
                                fontStyle: FontStyle.italic,
                              ),
                            )
                          : ListView(
                              scrollDirection: Axis.horizontal,
                              children: _favoriteColors
                                  .map(
                                    (c) => _colorSwatch(
                                      color: c,
                                      isActive: pickerColor == c,
                                      isFavorite: true,
                                      ss: ss,
                                      onTap: () {
                                        ss(() => pickerColor = c);
                                        syncFields(c, ss);
                                      },
                                      onFavToggle: () {
                                        _favoriteColors.remove(c);
                                        _saveWorkspace();
                                      },
                                      onRemove: () {
                                        _favoriteColors.remove(c);
                                        _saveWorkspace();
                                      },
                                    ),
                                  )
                                  .toList(),
                            ),
                    ),
                  ],
                ],
              ),
            ),
            actions: [
              if (onReset != null)
                TextButton(
                  onPressed: () {
                    onReset();
                    Navigator.pop(context);
                  },
                  child: const Text(
                    'Reset',
                    style: TextStyle(color: Colors.white38),
                  ),
                ),
              TextButton(
                onPressed: () => Navigator.pop(context),
                child: const Text(
                  'Cancel',
                  style: TextStyle(color: Colors.white38),
                ),
              ),
              TextButton(
                onPressed: () {
                  onApply(pickerColor);
                  setState(() {
                    // Global recents
                    _recentColors.remove(pickerColor);
                    _recentColors.insert(0, pickerColor);
                    if (_recentColors.length > 10) _recentColors.removeLast();
                    // Context recents
                    if (colorContext != null) {
                      final list = _contextRecentColors.putIfAbsent(
                        colorContext!,
                        () => [],
                      );
                      list.remove(pickerColor);
                      list.insert(0, pickerColor);
                      if (list.length > 10) list.removeLast();
                    }
                  });
                  _saveWorkspace();
                  Navigator.pop(context);
                },
                child: const Text(
                  'Apply',
                  style: TextStyle(
                    color: Colors.blueAccent,
                    fontWeight: FontWeight.bold,
                  ),
                ),
              ),
            ],
          );
        },
      ),
    );
  }

  // ── Feature 3 helpers ────────────────────────────────────────────────────

  Widget _colorRowLabel(String text) => Text(
    text,
    style: const TextStyle(
      color: Colors.white38,
      fontSize: 10,
      fontWeight: FontWeight.w700,
      letterSpacing: 0.5,
    ),
  );

  String _contextLabel(String ctx) {
    switch (ctx) {
      case 'projectColor':
        return 'Projects';
      case 'canvasGridColor':
        return 'Grid Color';
      case 'canvasBgColor':
        return 'Canvas BG';
      default:
        return ctx;
    }
  }

  /// A 24×24 color swatch with a ★ hover overlay for favorites toggling.
  Widget _colorSwatch({
    required Color color,
    required bool isActive,
    required bool isFavorite,
    required StateSetter ss,
    required VoidCallback onTap,
    required VoidCallback onFavToggle,
    VoidCallback? onRemove,
  }) {
    return Padding(
      padding: const EdgeInsets.only(right: 6),
      child: _HoverColorSwatch(
        color: color,
        isActive: isActive,
        isFavorite: isFavorite,
        onTap: onTap,
        onFavToggle: () {
          ss(() {});
          onFavToggle();
        },
        onRemove: onRemove != null
            ? () {
                ss(() {});
                onRemove();
              }
            : null,
      ),
    );
  }

  void _showColorPicker(String projectId) {
    _showUnifiedColorPicker(
      title: 'Project Color',
      initialColor: _projectColors[projectId] ?? Colors.blueAccent,
      showRecentColors: true,
      colorContext: 'projectColor',
      onApply: (color) => setState(() => _projectColors[projectId] = color),
    );
  }

  void _showProjectSettingsDialog(String projectId) {
    final proj = _projects[projectId];
    if (proj == null) return;
    showDialog(
      context: context,
      builder: (ctx) => _ProjectSettingsDialog(
        projectId: projectId,
        project: proj,
        initialColor: _projectColors[projectId] ?? Colors.blueAccent,
        initialIcon: _projectIcons[projectId] ?? '',
        initialBacklogEnabled: _projectBacklogEnabled[projectId] ?? false,
        initialHiddenFromMenu: _projectHiddenFromMenu[projectId] ?? false,
        onApply:
            ({
              required String newTitle,
              required String newIcon,
              required Color newColor,
              required bool backlogEnabled,
              required bool hiddenFromMenu,
            }) {
              setState(() {
                if (newTitle.isNotEmpty && newTitle != proj.title) {
                  _projects[projectId] = Project(
                    id: proj.id,
                    title: newTitle,
                    createdAt: proj.createdAt,
                  );
                }
                _projectColors[projectId] = newColor;
                if (newIcon.isEmpty) {
                  _projectIcons.remove(projectId);
                } else {
                  _projectIcons[projectId] = newIcon;
                }
                _projectBacklogEnabled[projectId] = backlogEnabled;
                _projectHiddenFromMenu[projectId] = hiddenFromMenu;
              });
              _saveWorkspace();
            },
        onShowColorPicker: (initialColor, onPicked) => _showUnifiedColorPicker(
          title: 'Project Color',
          initialColor: initialColor,
          showRecentColors: true,
          onApply: onPicked,
        ),
      ),
    );
  }

  Future<void> _pickAndCropWorkspaceImage() async {
    // 1. Open file browser — images only
    final result = await FilePicker.platform.pickFiles(
      dialogTitle: 'Select workspace image',
      type: FileType.image,
      allowMultiple: false,
    );
    if (result == null || result.files.single.path == null) return;
    final path = result.files.single.path!;

    // 2. Show custom crop dialog
    if (!mounted) return;
    final cropped = await showDialog<String>(
      context: context,
      barrierDismissible: false,
      builder: (_) => _CropImageDialog(imagePath: path),
    );
    if (cropped != null) setState(() => _workspaceImagePath = cropped);
  }

  void _showGridColorPicker() {
    _showUnifiedColorPicker(
      title: 'Grid Color',
      initialColor: _gridColor,
      showRecentColors: true,
      onReset: () =>
          setState(() => _gridColor = Colors.white.withOpacity(0.05)),
      onApply: (color) => setState(() => _gridColor = color),
    );
  }

  /// One-time import from a SuperProductivity __meta_ backup file.
  ///
  /// Reads tasks and projects from [_sourceFilePath] and populates [_allTasks]
  /// and [_projects] in memory. The caller is responsible for immediately
  /// calling [_saveWorkspace] so the imported data is persisted natively and
  /// the __meta_ file is no longer needed at runtime.
  ///
  /// This is triggered only by the explicit "Import from __meta_" button in
  /// the settings UI — it is NOT called automatically on workspace open.
  Future<void> _loadSpData() async {
    if (_sourceFilePath.isEmpty) return;
    try {
      final file = File(_sourceFilePath);
      if (!await file.exists()) {
        debugPrint('_loadSpData: file not found at $_sourceFilePath');
        return;
      }

      final rawContent = await file.readAsString();
      final jsonStartIndex = rawContent.indexOf('{');
      if (jsonStartIndex == -1) throw Exception('No valid JSON found in file');
      final Map<String, dynamic> data = jsonDecode(
        rawContent.substring(jsonStartIndex),
      );

      // SP stores data either directly at the root, or nested under
      // 'mainModelData'. Try both.
      Map<String, dynamic>? root;
      if (data['task'] is Map && data['project'] is Map) {
        root = data; // flat root structure
      } else if (data['mainModelData'] is Map) {
        root = data['mainModelData'] as Map<String, dynamic>;
      } else {
        // Dump top-level keys to help diagnose the actual structure
        throw Exception(
          'Unrecognised __meta_ structure. Top-level keys: ${data.keys.join(', ')}',
        );
      }

      // Projects
      final projectBlock = root['project'] as Map<String, dynamic>? ?? {};
      final projectEntities =
          projectBlock['entities'] as Map<String, dynamic>? ?? {};
      final Map<String, Project> loadedProjects = {};
      projectEntities.forEach((id, json) {
        try {
          loadedProjects[id] = Project.fromJson(
            Map<String, dynamic>.from(json as Map),
          );
        } catch (e) {
          debugPrint('Project parse error [$id]: $e');
        }
      });

      // Preserve project order from ids array if present
      final rawIds = projectBlock['ids'];
      List<String> loadedOrder;
      if (rawIds is List && rawIds.isNotEmpty) {
        loadedOrder = rawIds.map((e) => e.toString()).toList();
      } else {
        loadedOrder = loadedProjects.keys.toList();
      }

      // Tasks
      final taskBlock = root['task'] as Map<String, dynamic>? ?? {};
      final taskEntities = taskBlock['entities'] as Map<String, dynamic>? ?? {};
      final List<Task> loadedTasks = [];
      taskEntities.forEach((id, json) {
        try {
          loadedTasks.add(
            Task.fromJson(Map<String, dynamic>.from(json as Map)),
          );
        } catch (e) {
          debugPrint('Task parse error [$id]: $e');
        }
      });

      debugPrint(
        '_loadSpData: loaded ${loadedProjects.length} projects, '
        '${loadedTasks.length} tasks',
      );

      setState(() {
        _projects = loadedProjects;
        _allTasks = loadedTasks;
        _projectOrder = loadedOrder;
      });
    } catch (e, st) {
      debugPrint('_loadSpData ERROR: $e\n$st');
      if (mounted) {
        ScaffoldMessenger.of(context).showSnackBar(
          SnackBar(
            content: Text(
              'Failed to load __meta_: $e',
              style: const TextStyle(fontSize: 12),
            ),
            backgroundColor: const Color(0xFF8B0000),
            duration: const Duration(seconds: 6),
          ),
        );
      }
    }
  }

  /// Maps a canvas world-position X to a calendar day via Gantt segment geometry,
  /// then assigns that date to the task's dueDay (preserving any time-of-day from
  /// plannedAt if present).
  /// Returns Monday of the current real-world week, used as Gantt day-0.
  DateTime get _ganttReferenceDay {
    final now = DateTime.now();
    return DateTime(
      now.year,
      now.month,
      now.day,
    ).subtract(Duration(days: now.weekday - 1));
  }

  /// Converts a day index (0 = referenceDay) to a midnight-normalised DateTime.
  DateTime _ganttIdxToDate(int idx) {
    final d = _ganttReferenceDay.add(Duration(days: idx));
    return DateTime(d.year, d.month, d.day);
  }

  /// Effective pixel width of the Gantt day at [idx] (unscaled).
  /// In proportional mode the custom widths are stored but not applied.
  double _ganttEffectiveWidth(int idx) {
    if (_ganttProportional) return _ganttDayWidth;
    return _ganttColumnWidths[_ganttIdxToDate(idx)] ?? _ganttDayWidth;
  }

  /// Screen-X of the left edge of Gantt day [idx] (0 = referenceDay = this Monday).
  /// Handles both positive and negative indices correctly.
  double _ganttSegmentLeft(int idx) {
    double x = _canvasOffset.dx;
    if (idx >= 0) {
      for (int i = 0; i < idx; i++) {
        x += _ganttEffectiveWidth(i) * _scale;
      }
    } else {
      for (int i = -1; i >= idx; i--) {
        x -= _ganttEffectiveWidth(i) * _scale;
      }
    }
    return x;
  }

  /// Centers the canvas horizontally so today's Gantt column is at the viewport mid-point.
  void _centerGanttOnToday() {
    final now = DateTime.now();
    final ref = _ganttReferenceDay;
    final todayIdx = now.difference(ref).inDays;
    // Screen-X of today's left edge when canvasOffset.dx = 0
    double todayScreenX0 = 0;
    if (todayIdx >= 0) {
      for (int i = 0; i < todayIdx; i++) {
        todayScreenX0 += _ganttEffectiveWidth(i) * _scale;
      }
    } else {
      for (int i = -1; i >= todayIdx; i--) {
        todayScreenX0 -= _ganttEffectiveWidth(i) * _scale;
      }
    }
    final todayW = _ganttEffectiveWidth(todayIdx) * _scale;
    // Shift canvasOffset so today is centered
    setState(() {
      _canvasOffset = Offset(
        _viewportSize.width / 2 - (todayScreenX0 + todayW / 2),
        _canvasOffset.dy,
      );
    });
  }

  /// Maps a canvas world-position X to a calendar day via Gantt segment geometry,
  /// then assigns that date to the task's dueDay (preserving any time-of-day from
  /// plannedAt if present).
  void _assignGanttDateFromDrop(Task task, Offset worldOffset) {
    // Convert world X to screen X
    final screenX = worldOffset.dx * _scale + _canvasOffset.dx;

    // Find which day segment contains screenX by walking from day 0 outward
    // using the corrected _ganttSegmentLeft logic.
    // Estimate rough idx first for efficiency
    final approxIdx = _ganttProportional
        ? ((screenX - _canvasOffset.dx) / (_ganttDayWidth * _scale)).floor()
        : 0; // fall back to full walk for free-stretch

    final startIdx = _ganttProportional ? approxIdx : -365;
    final endIdx = _ganttProportional ? approxIdx + 1 : 1000;

    for (int idx = startIdx; idx < endIdx; idx++) {
      final segLeft = _ganttSegmentLeft(idx);
      final segW = _ganttEffectiveWidth(idx) * _scale;
      if (screenX >= segLeft && screenX < segLeft + segW) {
        final day = _ganttReferenceDay.add(Duration(days: idx));
        final isoDate =
            '${day.year}-${day.month.toString().padLeft(2, '0')}-${day.day.toString().padLeft(2, '0')}';
        if (task.plannedAt != null && task.plannedAt! > 0) {
          final existing = DateTime.fromMillisecondsSinceEpoch(task.plannedAt!);
          final updated = DateTime(
            day.year,
            day.month,
            day.day,
            existing.hour,
            existing.minute,
            existing.second,
          );
          task.plannedAt = updated.millisecondsSinceEpoch;
          task.dueDay = isoDate;
        } else {
          task.dueDay = isoDate;
        }
        _saveTaskToMeta(task);
        return;
      }
    }
    // Drop outside all segments — leave date unchanged
  }

  /// Persists any mutation made to [task] back to the workspace file.
  ///
  /// Previously this wrote directly into the SuperProductivity __meta_ JSON.
  /// All task data is now owned internally: _saveWorkspace() serialises
  /// _allTasks into the workspace file so no external file is touched.
  /// The __meta_ file is used only for one-time imports via the settings UI.
  Future<void> _saveTaskToMeta(Task task) async {
    await _saveWorkspace();
  }

  // ─────────────────────────────────────────────────────────────────────────
  // CONNECTION VALIDATION  –  typed-sequence duplicate detection
  // ─────────────────────────────────────────────────────────────────────────
  //
  // Rule summary
  // ────────────
  // A new edge  newSource → newTarget  is allowed when ALL of the following
  // hold:
  //
  //   1. The exact direct edge does not already exist.
  //   2. _allowDuplicateConnections is false  (if true everything is open).
  //   3. Adding the edge would NOT create a typed path sequence that already
  //      exists anywhere in the graph.
  //
  // Typed path sequence
  // ────────────────────
  // Every path through the graph is represented as a list of tokens:
  //   • Task nodes  → their unique ID string  (the "card" token)
  //   • Junction nodes → their operator type string  ("and" | "or" | "xor")
  //
  // Two paths are DUPLICATE if their token lists are identical.
  // This means the specific junction IDs are irrelevant; what matters is the
  // operator TYPE at each step.
  //
  // Examples
  // ────────
  //   BLOCKED  –  D →(OR_1)→ B  already exists.
  //     Proposing D →(OR_2)→ B  (via an OR_2→B edge already in graph):
  //       new sequence = [D, "or", B] = existing sequence → BLOCKED.
  //
  //   ALLOWED  –  (A,C) →(AND_1)→(OR_1)→ B  already exists.
  //     Proposing C →(OR_1)→ B:
  //       new sequence = [C, "or", B] ≠ [C, "and", "or", B] → ALLOWED.
  //
  //   BLOCKED  –  D →(OR_1)→ B  and  D →(OR_2)→ B  both exist.
  //     Proposing D →(OR_3)→ B:
  //       new sequence = [D, "or", B] already in existing set → BLOCKED.
  // ─────────────────────────────────────────────────────────────────────────

  /// Returns the typed token for a node:
  ///   junction  →  operator type name  (e.g. "or", "and", "xor")
  ///   task card →  the task's unique ID
  String _nodeToken(String nodeId) {
    for (final j in _junctions) {
      if (j.id == nodeId) return j.operatorType.name;
    }
    for (final c in _conditionals) {
      if (c.id == nodeId) return 'conditional';
    }
    return nodeId;
  }

  /// All node IDs currently on the canvas (tasks + junctions + conditionals).
  Set<String> _getAllNodeIds() => {
    ..._canvasTasks.map((t) => t.id),
    ..._junctions.map((j) => j.id),
    ..._conditionals.map((c) => c.id),
  };

  /// Builds the complete set of typed-sequence strings for every path of
  /// length ≥ 2 tokens that exists in the current graph.
  /// Each string is tokens joined by ':',  e.g.  "taskA:or:taskB".
  Set<String> _computeAllTypedPathStrings() {
    final Set<String> result = {};
    for (final start in _getAllNodeIds()) {
      _dfsAllPaths(start, [_nodeToken(start)], {start}, result);
    }
    return result;
  }

  void _dfsAllPaths(
    String current,
    List<String> path,
    Set<String> visited,
    Set<String> result,
  ) {
    if (path.length >= 2) result.add(path.join(':'));
    for (final r in _taskRelations.where((r) => r.sourceId == current)) {
      if (!visited.contains(r.targetId)) {
        _dfsAllPaths(
          r.targetId,
          [...path, _nodeToken(r.targetId)],
          {...visited, r.targetId},
          result,
        );
      }
    }
  }

  /// All typed-token sequences that end at [endId] (traversing backward).
  /// Each list is in forward order and ends with token(endId).
  List<List<String>> _typedPrefixesEndingAt(String endId) {
    final List<List<String>> result = [];
    _dfsPrefixes(endId, [_nodeToken(endId)], {endId}, result);
    return result;
  }

  void _dfsPrefixes(
    String current,
    List<String> reversePath,
    Set<String> visited,
    List<List<String>> result,
  ) {
    result.add(reversePath.reversed.toList());
    for (final r in _taskRelations.where((r) => r.targetId == current)) {
      if (!visited.contains(r.sourceId)) {
        _dfsPrefixes(
          r.sourceId,
          [...reversePath, _nodeToken(r.sourceId)],
          {...visited, r.sourceId},
          result,
        );
      }
    }
  }

  /// All typed-token sequences that start at [startId] (traversing forward).
  /// Each list starts with token(startId).
  List<List<String>> _typedSuffixesStartingAt(String startId) {
    final List<List<String>> result = [];
    _dfsSuffixes(startId, [_nodeToken(startId)], {startId}, result);
    return result;
  }

  void _dfsSuffixes(
    String current,
    List<String> path,
    Set<String> visited,
    List<List<String>> result,
  ) {
    result.add(List.from(path));
    for (final r in _taskRelations.where((r) => r.sourceId == current)) {
      if (!visited.contains(r.targetId)) {
        _dfsSuffixes(
          r.targetId,
          [...path, _nodeToken(r.targetId)],
          {...visited, r.targetId},
          result,
        );
      }
    }
  }

  /// Entry point – returns true when it is legal to add an edge source→target.
  bool _canConnect(String source, String target) {
    // ── 1. Block exact direct duplicate ─────────────────────────────────────
    if (_taskRelations.any(
      (r) => r.sourceId == source && r.targetId == target,
    )) {
      return false;
    }

    // ── 2. Global override ───────────────────────────────────────────────────
    if (_allowDuplicateConnections) return true;

    // ── 3. Typed-sequence duplicate check ───────────────────────────────────
    // Snapshot of every path sequence that already exists in the graph.
    final Set<String> existingSeqs = _computeAllTypedPathStrings();

    // All typed prefixes that arrive at `source` (including the trivial one-
    // token prefix [token(source)] when nothing precedes it).
    final List<List<String>> prefixes = _typedPrefixesEndingAt(source);

    // All typed suffixes that depart from `target` (including the trivial
    // one-token suffix [token(target)] when nothing follows it).
    final List<List<String>> suffixes = _typedSuffixesStartingAt(target);

    // Each combination forms a new path through the proposed edge.
    // prefix ends with token(source), suffix starts with token(target).
    // Concatenating them gives the full typed sequence for that path.
    for (final prefix in prefixes) {
      for (final suffix in suffixes) {
        final String seq = [...prefix, ...suffix].join(':');
        if (existingSeqs.contains(seq)) return false;
      }
    }

    return true;
  }

  // --- TOP MENU BAR & MODALS ---

  // ─────────────────────────────────────────────────────────────────────────
  // CUSTOM THREE-REGION TITLE BAR
  //
  // Region 1 (left)   – File / Edit menus when sidebar is wide enough,
  //                      otherwise a single ☰ expand button.
  // Region 2 (centre) – Canvas tabs, each tinted with its background colour.
  //                      A [+] button after the last tab opens the create-
  //                      canvas dialog.
  // Region 3 (right)  – Minimise / Close window buttons.
  // ─────────────────────────────────────────────────────────────────────────
  Widget _buildTopMenuBar() {
    const double barHeight = 36.0;
    // Threshold: sidebar must be visible AND at least this wide to show menus
    const double menuShowThreshold = 140.0;
    final bool showMenus = _isVisible && _sidebarWidth >= menuShowThreshold;

    return Container(
      height: barHeight,
      width: double.infinity,
      decoration: const BoxDecoration(
        color: Color(0xFF1A1A1A),
        border: Border(bottom: BorderSide(color: Colors.white10)),
      ),
      child: Row(
        children: [
          // ── Region 1: File / Edit (or sidebar-expand button) ──────────────
          // Width mirrors the sidebar + drag-handle so tabs always start at
          // the left edge of the canvas area.
          SizedBox(
            width: _isVisible ? _sidebarWidth + 4 : 44,
            child: showMenus
                ? Theme(
                    data: ThemeData.dark().copyWith(
                      menuTheme: const MenuThemeData(
                        style: MenuStyle(
                          backgroundColor: WidgetStatePropertyAll(
                            Color(0xFF2A2A2A),
                          ),
                        ),
                      ),
                    ),
                    child: MenuBar(
                      style: const MenuStyle(
                        elevation: WidgetStatePropertyAll(0),
                        backgroundColor: WidgetStatePropertyAll(
                          Colors.transparent,
                        ),
                        padding: WidgetStatePropertyAll(
                          EdgeInsets.symmetric(horizontal: 6),
                        ),
                      ),
                      children: [
                        SubmenuButton(
                          menuChildren: [
                            MenuItemButton(
                              onPressed: _showCreateWorkspaceDialog,
                              child: const Text('Create New Workspace'),
                            ),
                            MenuItemButton(
                              onPressed: _showSwitchWorkspaceDialog,
                              child: const Text('Switch Workspace'),
                            ),
                            MenuItemButton(
                              onPressed: _showPreferencesDialog,
                              child: const Text('Preferences'),
                            ),
                            MenuItemButton(
                              onPressed: () => exit(0),
                              child: const Text('Quit'),
                            ),
                          ],
                          child: const Text(
                            'File',
                            style: TextStyle(
                              color: Colors.white70,
                              fontSize: 12,
                            ),
                          ),
                        ),
                        SubmenuButton(
                          menuChildren: [
                            MenuItemButton(
                              onPressed: () {},
                              child: const Text('Undo'),
                            ),
                            MenuItemButton(
                              onPressed: () {},
                              child: const Text('Redo'),
                            ),
                            MenuItemButton(
                              onPressed: () {},
                              child: const Text('Cut'),
                            ),
                            MenuItemButton(
                              onPressed: () {},
                              child: const Text('Copy'),
                            ),
                            MenuItemButton(
                              onPressed: () {},
                              child: const Text('Paste'),
                            ),
                            MenuItemButton(
                              onPressed: () {},
                              child: const Text('Delete'),
                            ),
                          ],
                          child: const Text(
                            'Edit',
                            style: TextStyle(
                              color: Colors.white70,
                              fontSize: 12,
                            ),
                          ),
                        ),
                      ],
                    ),
                  )
                : Tooltip(
                    message: _isVisible ? 'Collapse sidebar' : 'Expand sidebar',
                    child: InkWell(
                      onTap: () => setState(() => _isVisible = !_isVisible),
                      child: SizedBox(
                        width: 40,
                        height: barHeight,
                        child: Icon(
                          _isVisible
                              ? Icons.menu_open_rounded
                              : Icons.menu_rounded,
                          size: 16,
                          color: Colors.white54,
                        ),
                      ),
                    ),
                  ),
          ),

          // ── Region 2: Canvas tabs / Tasks title ───────────────────────────
          if (_isTasksView) ...[Expanded(child: _buildTasksTitleBar())],
          if (_isNotesView) ...[Expanded(child: _buildNotesTitleBar())],
          // ── Region 2: Canvas tabs — reorderable ───────────────────────────
          if (!_isTasksView && !_isNotesView) ...[
            // Builder lets us compute openTabs once and share it between
            // onReorder and the children list without leaving the Row.
            Builder(
              builder: (_) {
                final openTabs = _savedCanvases
                    .where((c) => _openCanvases.contains(c['name']))
                    .toList();

                return Expanded(
                  child: SizedBox(
                    height: barHeight,
                    child: ReorderableListView(
                      scrollDirection: Axis.horizontal,
                      buildDefaultDragHandles: false,
                      padding: EdgeInsets.zero,
                      // ── Persist reordered tab positions ───────────────
                      onReorder: (oldIndex, newIndex) {
                        setState(() {
                          // ReorderableListView passes the shifted index —
                          // correct it the standard way.
                          if (newIndex > oldIndex) newIndex -= 1;
                          final tabs = _savedCanvases
                              .where((c) => _openCanvases.contains(c['name']))
                              .toList();
                          final moved = tabs.removeAt(oldIndex);
                          tabs.insert(newIndex, moved);
                          // Rebuild _savedCanvases: open tabs in new order,
                          // closed canvases appended after.
                          final closed = _savedCanvases
                              .where((c) => !_openCanvases.contains(c['name']))
                              .toList();
                          _savedCanvases = [...tabs, ...closed];
                        });
                        unawaited(_saveWorkspace());
                      },
                      // ── [+] New Canvas button (non-draggable footer) ───
                      footer: Tooltip(
                        message: 'New canvas',
                        child: InkWell(
                          onTap: _showSwitchCanvasDialog,
                          child: Container(
                            width: 32,
                            height: barHeight,
                            alignment: Alignment.center,
                            child: const Icon(
                              Icons.add,
                              size: 16,
                              color: Colors.white38,
                            ),
                          ),
                        ),
                      ),
                      // ── One draggable tab per open canvas ──────────────
                      children: openTabs.asMap().entries.map((entry) {
                        final int i = entry.key;
                        final canvas = entry.value;
                        final String name = canvas['name']!;
                        final bool isActive = name == _currentCanvasName;
                        final Color tabBg =
                            _canvasColors[name] ?? const Color(0xFF121212);
                        final double luminance = tabBg.computeLuminance();
                        final Color fg = luminance > 0.35
                            ? Colors.black87
                            : Colors.white70;
                        final Color activeBg =
                            Color.lerp(tabBg, Colors.white, 0.12) ?? tabBg;
                        final Color closeColor = luminance > 0.35
                            ? Colors.black54
                            : Colors.white54;

                        bool hovered = false;
                        // ReorderableDragStartListener — tap still fires
                        // normally; drag kicks in only on pointer movement.
                        return ReorderableDragStartListener(
                          key: ValueKey(name),
                          index: i,
                          child: StatefulBuilder(
                            builder: (_, setTab) {
                              return MouseRegion(
                                cursor: SystemMouseCursors.grab,
                                onEnter: (_) => setTab(() => hovered = true),
                                onExit: (_) => setTab(() => hovered = false),
                                child: GestureDetector(
                                  onTap: () =>
                                      setState(() => _switchToCanvas(name)),
                                  child: AnimatedContainer(
                                    duration: const Duration(milliseconds: 150),
                                    constraints: const BoxConstraints(
                                      maxWidth: 160,
                                      minWidth: 60,
                                    ),
                                    height: barHeight,
                                    padding: const EdgeInsets.symmetric(
                                      horizontal: 12,
                                    ),
                                    decoration: BoxDecoration(
                                      color: isActive ? activeBg : tabBg,
                                      border: Border(
                                        right: const BorderSide(
                                          color: Colors.white10,
                                        ),
                                        bottom: isActive
                                            ? BorderSide(
                                                color: Colors.tealAccent
                                                    .withOpacity(0.8),
                                                width: 2,
                                              )
                                            : BorderSide.none,
                                      ),
                                    ),
                                    child: Row(
                                      mainAxisSize: MainAxisSize.min,
                                      children: [
                                        Container(
                                          width: 8,
                                          height: 8,
                                          margin: const EdgeInsets.only(
                                            right: 6,
                                          ),
                                          decoration: BoxDecoration(
                                            shape: BoxShape.circle,
                                            color: isActive
                                                ? Colors.tealAccent
                                                : fg.withOpacity(0.5),
                                          ),
                                        ),
                                        Flexible(
                                          child: Text(
                                            name,
                                            overflow: TextOverflow.ellipsis,
                                            style: TextStyle(
                                              fontSize: 11,
                                              fontWeight: isActive
                                                  ? FontWeight.bold
                                                  : FontWeight.normal,
                                              color: isActive
                                                  ? (luminance > 0.35
                                                        ? Colors.black
                                                        : Colors.white)
                                                  : fg,
                                              letterSpacing: 0.3,
                                            ),
                                          ),
                                        ),
                                        // Close — hover-only
                                        AnimatedOpacity(
                                          duration: const Duration(
                                            milliseconds: 120,
                                          ),
                                          opacity: hovered ? 1.0 : 0.0,
                                          child: Padding(
                                            padding: const EdgeInsets.only(
                                              left: 4,
                                            ),
                                            child: GestureDetector(
                                              onTap: () {
                                                setState(() {
                                                  if (isActive) {
                                                    _canvasStates[name] =
                                                        _snapshotCurrentCanvas();
                                                    _canvasColors[name] =
                                                        _currentCanvasBackgroundColor;
                                                    _currentCanvasName = '';
                                                    _canvasNameController
                                                        .clear();
                                                    _canvasTasks.clear();
                                                    _taskPositions.clear();
                                                    _junctions.clear();
                                                    _conditionals.clear();
                                                    _selectedConditionalId =
                                                        null;
                                                    _selectedConditionalIds
                                                        .clear();
                                                    _taskRelations.clear();
                                                  }
                                                  _openCanvases.remove(name);
                                                });
                                              },
                                              child: Icon(
                                                Icons.close,
                                                size: 12,
                                                color: closeColor,
                                              ),
                                            ),
                                          ),
                                        ),
                                      ],
                                    ),
                                  ),
                                ),
                              );
                            },
                          ),
                        );
                      }).toList(),
                    ),
                  ),
                );
              },
            ),

            // ── Operator / Conditional toggle — cycles AND → OR → XOR → IF ──
            StatefulBuilder(
              builder: (ctx, setBtn) {
                final isIf = _isIfMode;
                final op = _defaultOperator;

                // Colour
                final Color opColor;
                if (isIf) {
                  opColor = Colors.amberAccent;
                } else {
                  switch (op) {
                    case LogicalOperator.or:
                      opColor = const Color(0xFFFFB74D);
                      break;
                    case LogicalOperator.xor:
                      opColor = const Color(0xFFCE93D8);
                      break;
                    case LogicalOperator.and:
                    default:
                      opColor = const Color(0xFF4FC3F7);
                  }
                }

                // Label & icon
                final String label = isIf ? 'IF' : op.label;
                final IconData icon = isIf
                    ? Icons.diamond_outlined
                    : Icons.account_tree_outlined;

                return Tooltip(
                  message: isIf
                      ? 'Mode: Conditional (IF) — right-click canvas to place ◇\n'
                            'Click to cycle back to AND'
                      : 'Default operator for new nodes: ${op.label}\n'
                            'Click to cycle (AND → OR → XOR → IF)',
                  child: InkWell(
                    onTap: () {
                      setState(() {
                        if (isIf) {
                          // IF → AND
                          _isIfMode = false;
                          _defaultOperator = LogicalOperator.and;
                        } else if (op == LogicalOperator.xor) {
                          // XOR → IF
                          _isIfMode = true;
                        } else {
                          // AND → OR → XOR
                          final next =
                              LogicalOperator.values[(LogicalOperator.values
                                          .indexOf(op) +
                                      1) %
                                  LogicalOperator.values.length];
                          _defaultOperator = next;
                        }
                      });
                      _saveWorkspace();
                    },
                    child: Container(
                      height: barHeight,
                      padding: const EdgeInsets.symmetric(horizontal: 10),
                      decoration: BoxDecoration(
                        border: const Border(
                          left: BorderSide(color: Colors.white10),
                        ),
                        color: opColor.withOpacity(isIf ? 0.12 : 0.07),
                      ),
                      alignment: Alignment.center,
                      child: Row(
                        mainAxisSize: MainAxisSize.min,
                        children: [
                          Icon(icon, size: 13, color: opColor),
                          const SizedBox(width: 5),
                          Text(
                            label,
                            style: TextStyle(
                              fontSize: 11,
                              fontWeight: FontWeight.w700,
                              color: opColor,
                              letterSpacing: 0.5,
                            ),
                          ),
                        ],
                      ),
                    ),
                  ),
                );
              },
            ),

            // ── Feature 6: Filter / Group / Sort — pinned after tabs ──────
            Builder(
              builder: (ctx) {
                final active =
                    _canvasFilterRules.any((r) => r.isConfigured) ||
                    _canvasGroupCriteria.isNotEmpty ||
                    _canvasSortCriteria.isNotEmpty ||
                    _canvasFilterOpen;
                return Tooltip(
                  message: 'Filter / Group / Sort canvas cards',
                  child: InkWell(
                    onTap: () =>
                        setState(() => _canvasFilterOpen = !_canvasFilterOpen),
                    child: Container(
                      width: 36,
                      height: barHeight,
                      alignment: Alignment.center,
                      decoration: BoxDecoration(
                        border: const Border(
                          left: BorderSide(color: Colors.white10),
                        ),
                        color: active
                            ? const Color(0xFF4FC3F7).withOpacity(0.07)
                            : Colors.transparent,
                      ),
                      child: Stack(
                        clipBehavior: Clip.none,
                        children: [
                          Icon(
                            Icons.filter_list_rounded,
                            size: 16,
                            color: active
                                ? const Color(0xFF4FC3F7)
                                : Colors.white38,
                          ),
                          if (active)
                            Positioned(
                              top: -2,
                              right: -4,
                              child: Container(
                                width: 8,
                                height: 8,
                                decoration: const BoxDecoration(
                                  color: Color(0xFF4FC3F7),
                                  shape: BoxShape.circle,
                                ),
                              ),
                            ),
                        ],
                      ),
                    ),
                  ),
                );
              },
            ),
          ],

          // ── Region 3: Window controls ──────────────────────────────────────
          Row(
            mainAxisSize: MainAxisSize.min,
            children: [
              // Minimise
              _windowControlButton(
                icon: Icons.remove,
                hoverColor: Colors.white12,
                onTap: () {
                  /* window_manager minimise – hook if available */
                },
              ),
              // Close
              _windowControlButton(
                icon: Icons.close,
                hoverColor: const Color(0xFFE81123),
                onTap: () => exit(0),
              ),
              const SizedBox(width: 4),
            ],
          ),
        ],
      ),
    );
  }

  /// Small hoverable window-control icon button used in the title bar.
  Widget _windowControlButton({
    required IconData icon,
    required Color hoverColor,
    required VoidCallback onTap,
  }) {
    return StatefulBuilder(
      builder: (_, setBtn) {
        bool hovered = false;
        return MouseRegion(
          onEnter: (_) => setBtn(() => hovered = true),
          onExit: (_) => setBtn(() => hovered = false),
          child: GestureDetector(
            onTap: onTap,
            child: AnimatedContainer(
              duration: const Duration(milliseconds: 100),
              width: 40,
              height: 36,
              color: hovered ? hoverColor : Colors.transparent,
              alignment: Alignment.center,
              child: Icon(icon, size: 14, color: Colors.white70),
            ),
          ),
        );
      },
    );
  }

  void _showCreateWorkspaceDialog() {
    final nameCtrl = TextEditingController();
    // pickedPath is mutated inside StatefulBuilder via setDlg — declared as a
    // one-element list so the inner closure can capture and mutate it.
    final pathHolder = [''];

    showDialog(
      context: context,
      builder: (ctx) => StatefulBuilder(
        builder: (ctx, setDlg) {
          final pickedPath = pathHolder[0];

          Future<void> pickFolder() async {
            final dir = await FilePicker.platform.getDirectoryPath(
              dialogTitle: 'Choose workspace folder',
            );
            if (dir != null) setDlg(() => pathHolder[0] = dir);
          }

          Future<void> doCreate() async {
            if (pathHolder[0].isEmpty) return;
            final id = _generateId();
            final name = nameCtrl.text.isNotEmpty ? nameCtrl.text : 'Untitled';
            final entry = {
              'id': id,
              'name': name,
              'metaPath': '',
              'basePath': pathHolder[0],
            };
            setState(() {
              _savedWorkspaces.add(entry);
              _allowDuplicateConnections = _prefAllowDuplicateConnections;
              _defaultOperator = _prefDefaultOperator;
              _isIfMode = false;
              _defaultArrowSize = _prefDefaultArrowSize;
              _showIdOnCards = _prefShowIdOnCards;
              _showProjectName = _prefShowProjectName;
              _showDueDateOnCards = _prefShowDueDateOnCards;
              _showTimeOnCards = _prefShowTimeOnCards;
              _standardVisibleInfos = Set.from(_prefStandardVisibleInfos);
              _showDateOnListedTasks = _prefShowDateOnListedTasks;
            });
            await _saveGeneral();
            if (ctx.mounted) Navigator.pop(ctx);
            await _loadWorkspaceById(entry);
          }

          return AlertDialog(
            backgroundColor: const Color(0xFF252525),
            title: const Text(
              'Create New Workspace',
              style: TextStyle(color: Colors.white, fontSize: 16),
            ),
            content: Column(
              mainAxisSize: MainAxisSize.min,
              crossAxisAlignment: CrossAxisAlignment.stretch,
              children: [
                // ── Name field ─────────────────────────────────────────────
                TextField(
                  controller: nameCtrl,
                  autofocus: true,
                  style: const TextStyle(color: Colors.white),
                  decoration: const InputDecoration(
                    labelText: 'Workspace Name',
                    labelStyle: TextStyle(color: Colors.white54),
                    enabledBorder: UnderlineInputBorder(
                      borderSide: BorderSide(color: Colors.white24),
                    ),
                    focusedBorder: UnderlineInputBorder(
                      borderSide: BorderSide(color: Colors.blueAccent),
                    ),
                  ),
                  onSubmitted: (_) => doCreate(),
                ),

                const SizedBox(height: 20),

                // ── Location picker ────────────────────────────────────────
                const Text(
                  'LOCATION',
                  style: TextStyle(
                    fontSize: 10,
                    fontWeight: FontWeight.bold,
                    color: Colors.white24,
                    letterSpacing: 1.2,
                  ),
                ),
                const SizedBox(height: 8),
                InkWell(
                  onTap: pickFolder,
                  borderRadius: BorderRadius.circular(6),
                  child: Container(
                    padding: const EdgeInsets.symmetric(
                      horizontal: 12,
                      vertical: 10,
                    ),
                    decoration: BoxDecoration(
                      color: Colors.white.withOpacity(0.05),
                      borderRadius: BorderRadius.circular(6),
                      border: Border.all(
                        color: pickedPath.isEmpty
                            ? Colors.white24
                            : Colors.blueAccent.withOpacity(0.6),
                      ),
                    ),
                    child: Row(
                      children: [
                        Icon(
                          Icons.folder_open_rounded,
                          size: 16,
                          color: pickedPath.isEmpty
                              ? Colors.white38
                              : Colors.blueAccent,
                        ),
                        const SizedBox(width: 10),
                        Expanded(
                          child: Text(
                            pickedPath.isEmpty ? 'Select folder…' : pickedPath,
                            style: TextStyle(
                              fontSize: 12,
                              color: pickedPath.isEmpty
                                  ? Colors.white38
                                  : Colors.white70,
                            ),
                            overflow: TextOverflow.ellipsis,
                          ),
                        ),
                        if (pickedPath.isNotEmpty)
                          GestureDetector(
                            onTap: () => setDlg(() => pathHolder[0] = ''),
                            child: const Icon(
                              Icons.close_rounded,
                              size: 14,
                              color: Colors.white38,
                            ),
                          ),
                      ],
                    ),
                  ),
                ),
              ],
            ),
            actions: [
              TextButton(
                onPressed: () => Navigator.pop(ctx),
                child: const Text(
                  'Cancel',
                  style: TextStyle(color: Colors.white38),
                ),
              ),
              TextButton(
                onPressed: pickedPath.isEmpty ? null : doCreate,
                child: Text(
                  'Create',
                  style: TextStyle(
                    color: pickedPath.isEmpty
                        ? Colors.white24
                        : Colors.blueAccent,
                  ),
                ),
              ),
            ],
          );
        },
      ),
    );
  }

  // ── Workspace switcher ───────────────────────────────────────────────────
  void _showSwitchWorkspaceDialog({bool allowDismiss = true}) {
    showDialog(
      context: context,
      barrierDismissible: allowDismiss,
      builder: (ctx) => PopScope(
        canPop: allowDismiss,
        child: _WorkspaceSwitcherDialog(
          workspaces: _savedWorkspaces,
          currentId: _workspaceId,
          workspaceFilePath: _workspaceFilePath,
          allowDismiss: allowDismiss,
          onSelect: (item) {
            WidgetsBinding.instance.addPostFrameCallback((_) {
              _loadWorkspaceById(item);
            });
          },
          onRename: (item, newName) {
            setState(() {
              if (_workspaceId == item['id']) {
                _workspaceName = newName;
                _workspaceNameController.text = newName;
              }
              for (final w in _savedWorkspaces) {
                if (w['id'] == item['id']) {
                  w['name'] = newName;
                  break;
                }
              }
              item['name'] = newName;
            });
            _saveGeneral();
            _saveWorkspace();
          },
          onDelete: (item) {
            setState(() {
              _savedWorkspaces.removeWhere((w) => w['id'] == item['id']);
              if (_workspaceId == item['id']) {
                _workspaceId = '';
                _workspaceName = '';
                _sourceFilePath = '';
                _workspaceImagePath = '';
                _workspaceNameController.text = '';
                _dataSourceController.text = '';
                _currentCanvasName = '';
                _canvasNameController.text = '';
                _savedCanvases.clear();
                _openCanvases.clear();
                _canvasStates.clear();
                _canvasColors.clear();
                _canvasTasks.clear();
                _taskPositions.clear();
                _junctions.clear();
                _conditionals.clear();
                _selectedConditionalId = null;
                _selectedConditionalIds.clear();
                _taskRelations.clear();
                _currentCategoriesGroupName = '';
                _categoriesGroupNameController.text = '';
                _categoriesGroups.clear();
                _allTasks.clear();
                _projects.clear();
                _sidebarSectionOrder.clear();
                _favoriteProjectIds.clear();
                _projectColors.clear();
                _categoryMappings.clear();
                _sectionExpandedStates.clear();
                _sectionSortAsc.clear();
                _isSettingsView = false;
              }
            });
            _saveGeneral();
          },
          onCreateNew: () {
            Navigator.pop(ctx);
            _showCreateWorkspaceDialog();
          },
          onRestoreFromFile: _restoreWorkspaceFromFile,
        ),
      ),
    );
  }

  // ── Category switcher ─────────────────────────────────────────────────────
  void _showSwitchCategoryDialog() {
    final categoryItems = _sidebarSectionOrder
        .where((s) => s != 'Favorites' && s != 'All')
        .map((s) => {'name': s})
        .toList();
    showDialog(
      context: context,
      builder: (_) => ItemSwitcherDialog(
        items: categoryItems,
        title: 'Switch Category',
        hintText: 'Search categories…',
        itemIcon: Icons.folder_outlined,
        itemIconColor: Colors.purpleAccent,
        selectedName: _currentCategoryName,
        onSelect: (item) {
          setState(() => _currentCategoryName = item['name']!);
        },
      ),
    );
  }

  // ── Category Group helpers ──────────────────────────────────────────────
  Map<String, dynamic> _snapshotCurrentGroup() {
    final customOrder = _sidebarSectionOrder
        .where((s) => s != 'Favorites' && s != 'All')
        .toList();
    final customMappings = Map<String, List<dynamic>>.fromEntries(
      _categoryMappings.entries
          .where((e) => e.key != 'Favorites' && e.key != 'All')
          .map((e) => MapEntry(e.key, e.value.toList())),
    );
    return {
      'projectColors': _projectColors.map((k, v) => MapEntry(k, v.value)),
      'recentColors': _recentColors.map((c) => c.value).toList(),
      'contextRecentColors': _contextRecentColors.map(
        (k, v) => MapEntry(k, v.map((c) => c.value).toList()),
      ),
      'favoriteColors': _favoriteColors.map((c) => c.value).toList(),
      'categoryMappings': customMappings,
      'sidebarSectionOrder': customOrder,
      'favoritesIndex': _sidebarSectionOrder.indexOf('Favorites'),
      'allIndex': _sidebarSectionOrder.indexOf('All'),
      'favoriteProjectIds': _favoriteProjectIds.toList(),
      'sectionExpandedStates': Map<String, bool>.from(_sectionExpandedStates),
      'sectionSortAsc': Map<String, bool>.from(_sectionSortAsc),
    };
  }

  void _applyGroup(Map<String, dynamic> g) {
    if (g['projectColors'] != null) {
      _projectColors = (g['projectColors'] as Map).map(
        (k, v) => MapEntry(k.toString(), Color(v as int)),
      );
    }
    if (g['recentColors'] != null) {
      _recentColors = (g['recentColors'] as List)
          .map((v) => Color(v as int))
          .toList();
    }
    if (g['contextRecentColors'] != null) {
      _contextRecentColors = (g['contextRecentColors'] as Map).map(
        (k, v) => MapEntry(
          k.toString(),
          (v as List).map((c) => Color(c as int)).toList(),
        ),
      );
    }
    if (g['favoriteColors'] != null) {
      _favoriteColors = (g['favoriteColors'] as List)
          .map((v) => Color(v as int))
          .toList();
    }
    if (g['categoryMappings'] != null) {
      final restored = (g['categoryMappings'] as Map).map(
        (k, v) => MapEntry(k.toString(), Set<String>.from(v)),
      );
      restored.remove('Favorites');
      restored.remove('All');
      _categoryMappings = restored;
    }
    if (g['sidebarSectionOrder'] != null) {
      final custom = List<String>.from(g['sidebarSectionOrder'])
        ..remove('Favorites')
        ..remove('All');
      final favPos = (g['favoritesIndex'] as int? ?? 0).clamp(0, custom.length);
      custom.insert(favPos, 'Favorites');
      final allPos = (g['allIndex'] as int? ?? custom.length).clamp(
        0,
        custom.length,
      );
      custom.insert(allPos, 'All');
      _sidebarSectionOrder = custom;
    }
    if (g['favoriteProjectIds'] != null) {
      _favoriteProjectIds = Set<String>.from(g['favoriteProjectIds']);
    }
    if (g['sectionExpandedStates'] != null) {
      _sectionExpandedStates = Map<String, bool>.from(
        g['sectionExpandedStates'],
      );
    }
    _sectionExpandedStates['Favorites'] ??= true;
    _sectionExpandedStates['All'] ??= true;
    if (g['sectionSortAsc'] != null) {
      _sectionSortAsc = Map<String, bool>.from(g['sectionSortAsc']);
    }
    _sectionSortAsc['Favorites'] ??= true;
    _sectionSortAsc['All'] ??= true;
  }

  void _switchToCategoriesGroup(String name) {
    // Save current state back into the current group before switching
    if (_currentCategoriesGroupName.isNotEmpty) {
      _categoriesGroups[_currentCategoriesGroupName] = _snapshotCurrentGroup();
    }
    _currentCategoriesGroupName = name;
    _categoriesGroupNameController.text = name;
    if (_categoriesGroups.containsKey(name)) {
      _applyGroup(_categoriesGroups[name]!);
    }
  }

  void _createCategoriesGroup(String name) {
    if (name.isEmpty || _categoriesGroups.containsKey(name)) return;
    if (_currentCategoriesGroupName.isNotEmpty) {
      _categoriesGroups[_currentCategoriesGroupName] = _snapshotCurrentGroup();
    }
    _categoriesGroups[name] = {
      'projectColors': <String, int>{},
      'recentColors': <int>[],
      'categoryMappings': <String, List<dynamic>>{},
      'sidebarSectionOrder': <String>[],
      'favoritesIndex': 0,
      'allIndex': 1,
      'favoriteProjectIds': <String>[],
      'sectionExpandedStates': <String, bool>{'Favorites': true, 'All': true},
      'sectionSortAsc': <String, bool>{'Favorites': true, 'All': true},
    };
    _currentCategoriesGroupName = name;
    _categoriesGroupNameController.text = name;
    _applyGroup(_categoriesGroups[name]!);
  }

  void _showCreateCategoriesGroupDialog() {
    final controller = TextEditingController();
    showDialog(
      context: context,
      builder: (ctx) => AlertDialog(
        backgroundColor: const Color(0xFF252525),
        shape: RoundedRectangleBorder(borderRadius: BorderRadius.circular(8)),
        title: const Text(
          'New Category Group',
          style: TextStyle(color: Colors.white70, fontSize: 14),
        ),
        content: TextField(
          controller: controller,
          autofocus: true,
          style: const TextStyle(color: Colors.white),
