  void _showSwitchCategoriesGroupDialog() {
    final items = _categoriesGroups.keys
        .where((k) => !_subcanvasGroupNames.contains(k))
        .map((k) => {'name': k})
        .toList();
    showDialog(
      context: context,
      builder: (_) => ItemSwitcherDialog(
        items: items,
        title: 'Switch Category Group',
        hintText: 'Search groups…',
        itemIcon: Icons.folder_outlined,
        itemIconColor: Colors.purpleAccent,
        selectedName: _currentCategoriesGroupName,
        onRename: (item, newName) {
          setState(() {
            String oldName = item['name']!;
            if (_currentCategoriesGroupName == oldName) {
              _currentCategoriesGroupName = newName;
              _categoriesGroupNameController.text = newName;
            }
            // Move key in the map
            if (_categoriesGroups.containsKey(oldName)) {
              _categoriesGroups[newName] = _categoriesGroups.remove(oldName)!;
            }
            item['name'] = newName;
          });
        },
        onDelete: (item) {
          setState(() {
            _categoriesGroups.remove(item['name']);
            items.removeWhere((i) => i['name'] == item['name']);
            if (_currentCategoriesGroupName == item['name']) {
              _currentCategoriesGroupName = _categoriesGroups.keys.isNotEmpty
                  ? _categoriesGroups.keys.first
                  : "";
              _categoriesGroupNameController.text = _currentCategoriesGroupName;
            }
          });
        },
        onSelect: (item) {
          setState(() => _switchToCategoriesGroup(item['name']!));
        },
        bottomAction: ElevatedButton.icon(
          style: ElevatedButton.styleFrom(
            backgroundColor: Colors.purpleAccent.withOpacity(0.1),
            foregroundColor: Colors.purpleAccent,
            elevation: 0,
            minimumSize: const Size(double.infinity, 40),
          ),
          icon: const Icon(Icons.add),
          label: const Text('Create New Category Group'),
          onPressed: () {
            Navigator.pop(context);
            _showCreateCategoriesGroupDialog();
          },
        ),
      ),
    );
  }

  // ── Canvas switcher ──────────────────────────────────────────────────────
  // ── Canvas State Helpers ─────────────────────────────────────────────────
  Map<String, dynamic> _snapshotCurrentCanvas() {
    return {
      'canvasTasks': List<Task>.from(_canvasTasks),
      'taskPositions': Map<String, Offset>.from(_taskPositions),
      'junctions': List<JunctionNode>.from(_junctions),
      'conditionals': List<ConditionalNode>.from(_conditionals),
      'taskRelations': Set<TaskRelation>.from(_taskRelations),
      'scale': _scale,
      'canvasOffset': Offset(_canvasOffset.dx, _canvasOffset.dy),
      'bgColor': _currentCanvasBackgroundColor,
    };
  }

  void _applyCanvas(Map<String, dynamic> data) {
    _canvasTasks.clear();
    if (data['canvasTasks'] != null) _canvasTasks.addAll(data['canvasTasks']);

    _taskPositions.clear();
    if (data['taskPositions'] != null)
      _taskPositions.addAll(data['taskPositions']);

    _junctions = data['junctions'] != null
        ? List<JunctionNode>.from(data['junctions'])
        : [];
    _conditionals = data['conditionals'] != null
        ? List<ConditionalNode>.from(data['conditionals'])
        : [];
    _selectedConditionalId = null;
    _selectedConditionalIds.clear();
    _taskRelations = data['taskRelations'] != null
        ? Set<TaskRelation>.from(data['taskRelations'])
        : <TaskRelation>{};
    _scale = data['scale'] ?? 1.0;
    _canvasOffset = data['canvasOffset'] ?? Offset.zero;
    _currentCanvasBackgroundColor = data['bgColor'] ?? const Color(0xFF121212);

    // Bug 3: When Gantt is enabled and this is a fresh load (canvasOffset still
    // at zero), center today's column after the first frame so _viewportSize
    // is populated. Skip if user has already panned (offset != zero).
    if (_ganttEnabled && _canvasOffset == Offset.zero) {
      WidgetsBinding.instance.addPostFrameCallback((_) {
        if (mounted) _centerGanttOnToday();
      });
    }
  }

  void _switchToCanvas(String name) {
    // 1. Save current canvas + category group
    if (_currentCanvasName.isNotEmpty) {
      _canvasStates[_currentCanvasName] = _snapshotCurrentCanvas();
      _canvasColors[_currentCanvasName] = _currentCanvasBackgroundColor;
    }
    // If we're leaving a subcanvas, save its group and restore the previous one
    final bool leavingSubcanvas = _currentCanvasName.endsWith(' - Subcanvas');
    final bool enteringSubcanvas = name.endsWith(' - Subcanvas');

    // 2. Change canvas reference
    _currentCanvasName = name;
    _canvasNameController.text = name;
    _openCanvases.add(name);

    // 3. Load or reset canvas state
    if (_canvasStates.containsKey(name)) {
      _applyCanvas(_canvasStates[name]!);
    } else {
      _canvasTasks.clear();
      _taskPositions.clear();
      _junctions.clear();
      _conditionals.clear();
      _selectedConditionalId = null;
      _selectedConditionalIds.clear();
      _taskRelations.clear();
      _scale = 1.0;
      _canvasOffset = Offset.zero;
      _currentCanvasBackgroundColor =
          _canvasColors[name] ?? const Color(0xFF121212);
    }

    // 4. Handle category group switching
    if (enteringSubcanvas) {
      // Auto-create the bound group if it doesn't exist yet
      if (!_categoriesGroups.containsKey(name)) {
        // Save current group first
        if (_currentCategoriesGroupName.isNotEmpty) {
          _categoriesGroups[_currentCategoriesGroupName] =
              _snapshotCurrentGroup();
        }
        _categoriesGroups[name] = {
          'projectColors': <String, int>{},
          'recentColors': <int>[],
          'categoryMappings': <String, List<dynamic>>{},
          'sidebarSectionOrder': <String>[],
          'favoritesIndex': 0,
          'allIndex': 1,
          'favoriteProjectIds': <String>[],
          'sectionExpandedStates': <String, bool>{
            'Favorites': true,
            'All': true,
          },
          'sectionSortAsc': <String, bool>{'Favorites': true, 'All': true},
        };
        _subcanvasGroupNames.add(name);
      }
      _switchToCategoriesGroup(name);
    } else if (leavingSubcanvas) {
      // Restore the first non-subcanvas group, or clear
      final nonSubGroup = _categoriesGroups.keys.firstWhere(
        (k) => !_subcanvasGroupNames.contains(k),
        orElse: () => '',
      );
      if (nonSubGroup.isNotEmpty) {
        _switchToCategoriesGroup(nonSubGroup);
      } else {
        _currentCategoriesGroupName = '';
        _categoriesGroupNameController.text = '';
      }
    }
  }

  void _createCanvas(String name, {Color bgColor = const Color(0xFF121212)}) {
    if (name.isEmpty || _savedCanvases.any((c) => c['name'] == name)) return;
    setState(() {
      _savedCanvases.add({"name": name});
      _canvasColors[name] = bgColor;
      _switchToCanvas(name);
    });
  }

