  // ── Canvas switcher ──────────────────────────────────────────────────────
  void _showSwitchCanvasDialog() {
    showDialog(
      context: context,
      builder: (_) => ItemSwitcherDialog(
        items: _savedCanvases,
        title: 'Switch Canvas',
        hintText: 'Search canvases…',
        itemIcon: Icons.layers_outlined,
        itemIconColor: Colors.tealAccent,
        selectedName: _currentCanvasName,
        onRename: (item, newName) {
          setState(() {
            String oldName = item['name']!;
            item['name'] = newName;
            if (_currentCanvasName == oldName) {
              _currentCanvasName = newName;
              _canvasNameController.text = newName;
            }
            if (_canvasStates.containsKey(oldName)) {
              _canvasStates[newName] = _canvasStates.remove(oldName)!;
            }
          });
        },
        onDelete: (item) {
          setState(() {
            String nameToDelete = item['name']!;
            _savedCanvases.removeWhere((c) => c['name'] == nameToDelete);
            _canvasStates.remove(nameToDelete);
            if (_currentCanvasName == nameToDelete) {
              if (_savedCanvases.isNotEmpty) {
                _switchToCanvas(_savedCanvases.first['name']!);
              } else {
                _currentCanvasName = "";
                _canvasNameController.clear();
              }
            }
          });
        },
        onSelect: (item) {
          setState(() => _switchToCanvas(item['name']!));
        },
        bottomAction: ElevatedButton.icon(
          style: ElevatedButton.styleFrom(
            backgroundColor: Colors.tealAccent.withOpacity(0.1),
            foregroundColor: Colors.tealAccent,
            elevation: 0,
            minimumSize: const Size(double.infinity, 40),
          ),
          icon: const Icon(Icons.add),
          label: const Text('Create New Canvas'),
          onPressed: () {
            Navigator.pop(context);
            _showCreateCanvasDialog();
          },
        ),
      ),
    );
  }

