                                                child: InkWell(
                                                  borderRadius:
                                                      BorderRadius.circular(4),
                                                  onTap: () => setState(
                                                    () => _ganttOptionsOpen =
                                                        !_ganttOptionsOpen,
                                                  ),
                                                  child: Container(
                                                    padding:
                                                        const EdgeInsets.symmetric(
                                                          horizontal: 8,
                                                          vertical: 4,
                                                        ),
                                                    decoration: BoxDecoration(
                                                      color:
                                                          (_ganttEnabled ||
                                                              _ganttOptionsOpen)
                                                          ? const Color(
                                                              0xFF4FC3F7,
                                                            ).withOpacity(0.15)
                                                          : Colors.transparent,
                                                      borderRadius:
                                                          BorderRadius.circular(
                                                            4,
                                                          ),
                                                      border: Border.all(
                                                        color:
                                                            (_ganttEnabled ||
                                                                _ganttOptionsOpen)
                                                            ? const Color(
                                                                0xFF4FC3F7,
                                                              ).withOpacity(0.4)
                                                            : Colors.white12,
                                                      ),
                                                    ),
                                                    child: Row(
                                                      mainAxisSize:
                                                          MainAxisSize.min,
                                                      children: [
                                                        Icon(
                                                          Icons
                                                              .grid_on_outlined,
                                                          size: 13,
                                                          color:
                                                              (_ganttEnabled ||
                                                                  _ganttOptionsOpen)
                                                              ? const Color(
                                                                  0xFF4FC3F7,
                                                                )
                                                              : Colors.white38,
                                                        ),
                                                        const SizedBox(
                                                          width: 5,
                                                        ),
                                                        Text(
                                                          'Gantt',
                                                          style: TextStyle(
                                                            fontSize: 10,
                                                            fontWeight:
                                                                FontWeight.w600,
                                                            color:
                                                                (_ganttEnabled ||
                                                                    _ganttOptionsOpen)
                                                                ? const Color(
                                                                    0xFF4FC3F7,
                                                                  )
                                                                : Colors
                                                                      .white38,
                                                          ),
                                                        ),
                                                      ],
                                                    ),
                                                  ),
                                                ),
                                              ),
                                            const SizedBox(width: 8),
                                          ], // ← closes Row's children: []
                                        ), // ← closes Row
                                      ), // ← closes Container
                                  ],
                                ),
                              ),
                              // ── Global Filter/Group/Sort sidebar ─────────────
                              // Placed here (outside individual tabs) so it is
                              // rendered regardless of which tab is currently active.
                              _buildFilterSidebar(),
                            ],
                          ),
                        ),
                        // RIGHT SIDEBAR (Details Panel)
                        if (_showDetails) _buildDetailsPanel(),
                      ],
                    );
                  },
                ),
              ),
            ],
          ),
          // ── Feature 6: Canvas Filter/Group/Sort panel ─────────────────────
          if (_canvasFilterOpen && !_isTasksView && !_isNotesView)
            Positioned(
              top: 4,
              right: (_showDetails ? 300 : 0) + 8,
              width: 320,
              child: Material(
                color: Colors.transparent,
                child: _buildCanvasFilterPanel(),
              ),
            ),
          // ── Per-section Filter/Group/Sort panel ───────────────────────────
          if (_activeSectionFilter != null && !_isTasksView && !_isNotesView)
            Positioned(
              top: 4,
              left: _sidebarWidth + 8,
              width: 300,
              child: Material(
                color: Colors.transparent,
                child: _buildSectionFilterPanel(_activeSectionFilter!),
              ),
            ),
          // ── Selection filter popup (bottom-left, above bottom bar) ────────
          if (_selectionFilterOpen &&
              !_isTasksView &&
              !_isNotesView &&
              !_isSettingsView)
            Positioned(
              left: (_isVisible ? _sidebarWidth : 0) + 12,
              bottom: 42,
              child: Material(
                color: Colors.transparent,
                child: _buildSelectionFilterPanel(),
              ),
            ),
          // ── Full-screen Preferences overlay ─────────────────────────────
          if (_isPreferencesView) _buildPreferencesPage(),
          // ── Gantt Options Panel (floating bottom-right) ──────────────────
          if (_ganttOptionsOpen &&
              !_isTasksView &&
              !_isNotesView &&
              !_isSettingsView)
            Positioned(
              right: (_showDetails ? 300 : 0) + 12,
              bottom: 42,
              width: 300,
              child: Material(
                color: Colors.transparent,
                child: _buildGanttOptionsPanel(),
              ),
            ),
        ],
      ),
    );
  }

  Widget _buildSelectionFilterPanel() {
    const bg = Color(0xFF1A1C1F);
    const surface = Color(0xFF22252A);
    const accent = Color(0xFF4FC3F7);
    const border = Color(0xFF2C2F35);

    Widget checkRow({
      required IconData icon,
      required String label,
      required bool value,
      required ValueChanged<bool> onChanged,
    }) {
      return InkWell(
        onTap: () => setState(() => onChanged(!value)),
        borderRadius: BorderRadius.circular(5),
        child: Padding(
          padding: const EdgeInsets.symmetric(horizontal: 10, vertical: 7),
          child: Row(
            mainAxisSize: MainAxisSize.min,
            children: [
              AnimatedContainer(
                duration: const Duration(milliseconds: 120),
                width: 16,
                height: 16,
                decoration: BoxDecoration(
                  color: value ? accent.withOpacity(0.2) : Colors.transparent,
                  borderRadius: BorderRadius.circular(4),
                  border: Border.all(
                    color: value ? accent : Colors.white24,
                    width: 1.5,
                  ),
                ),
                child: value
                    ? const Icon(Icons.check_rounded, size: 11, color: accent)
                    : null,
              ),
              const SizedBox(width: 10),
              Icon(
                icon,
                size: 13,
                color: value ? Colors.white70 : Colors.white30,
              ),
              const SizedBox(width: 7),
              Text(
                label,
                style: TextStyle(
                  fontSize: 12,
                  color: value ? Colors.white70 : Colors.white30,
                  fontWeight: FontWeight.w500,
                ),
              ),
            ],
          ),
        ),
      );
    }

    return Container(
      decoration: BoxDecoration(
        color: bg,
        borderRadius: BorderRadius.circular(8),
        border: Border.all(color: border),
        boxShadow: [
          BoxShadow(
            color: Colors.black.withOpacity(0.45),
            blurRadius: 14,
            offset: const Offset(0, 4),
          ),
        ],
      ),
      child: IntrinsicWidth(
        child: Column(
          mainAxisSize: MainAxisSize.min,
          crossAxisAlignment: CrossAxisAlignment.stretch,
          children: [
            // ── Header ────────────────────────────────────────────────────
            Container(
              padding: const EdgeInsets.fromLTRB(12, 9, 12, 8),
              decoration: const BoxDecoration(
                color: surface,
                borderRadius: BorderRadius.vertical(top: Radius.circular(8)),
              ),
              child: const Text(
                'Area-selection targets',
                style: TextStyle(
                  fontSize: 11,
                  fontWeight: FontWeight.w700,
                  color: Colors.white54,
                  letterSpacing: 0.4,
                ),
              ),
            ),
            const Divider(height: 1, color: border),
            // ── Options ───────────────────────────────────────────────────
            Padding(
              padding: const EdgeInsets.symmetric(vertical: 4),
              child: Column(
                mainAxisSize: MainAxisSize.min,
                crossAxisAlignment: CrossAxisAlignment.stretch,
                children: [
                  checkRow(
                    icon: Icons.crop_square_rounded,
                    label: 'Cards',
                    value: _marqueeSelectCards,
                    onChanged: (v) => _marqueeSelectCards = v,
                  ),
                  checkRow(
                    icon: Icons.timeline_rounded,
                    label: 'Lines',
                    value: _marqueeSelectLines,
                    onChanged: (v) => _marqueeSelectLines = v,
                  ),
                  checkRow(
                    icon: Icons.account_tree_outlined,
                    label: 'Operators',
                    value: _marqueeSelectOperators,
                    onChanged: (v) => _marqueeSelectOperators = v,
                  ),
                ],
              ),
            ),
          ],
        ),
      ),
    );
  }

  Widget _buildGanttOptionsPanel() {
    const accent = Color(0xFF4FC3F7);
    const bg = Color(0xFF1A1C1F);
    const surface = Color(0xFF22252A);
    const dividerColor = Color(0xFF2C2F35);

    Widget sectionLabel(String text) => Padding(
      padding: const EdgeInsets.fromLTRB(14, 12, 14, 4),
      child: Text(
        text,
        style: const TextStyle(
          fontSize: 9,
          fontWeight: FontWeight.w700,
          letterSpacing: 0.9,
          color: Colors.white38,
        ),
      ),
    );

    Widget row(Widget child) => Padding(
      padding: const EdgeInsets.symmetric(horizontal: 14, vertical: 3),
      child: child,
    );

    Widget toggleRow(String label, bool value, void Function(bool) onChanged) =>
        row(
          Row(
            children: [
              Expanded(
                child: Text(
                  label,
                  style: const TextStyle(fontSize: 11, color: Colors.white70),
                ),
              ),
              Switch(
                value: value,
                onChanged: (v) {
                  setState(() => onChanged(v));
                  _saveWorkspace();
                },
                activeColor: accent,
                materialTapTargetSize: MaterialTapTargetSize.shrinkWrap,
              ),
            ],
          ),
        );

    return Container(
      decoration: BoxDecoration(
        color: bg,
        borderRadius: BorderRadius.circular(10),
        border: Border.all(color: Colors.white.withOpacity(0.1)),
        boxShadow: [
          BoxShadow(
            color: Colors.black.withOpacity(0.5),
            blurRadius: 20,
            offset: const Offset(0, 4),
          ),
        ],
      ),
      child: Column(
        mainAxisSize: MainAxisSize.min,
        crossAxisAlignment: CrossAxisAlignment.stretch,
        children: [
          // ── Header ────────────────────────────────────────────────────────
          Container(
            padding: const EdgeInsets.fromLTRB(14, 10, 10, 10),
            decoration: BoxDecoration(
              border: Border(
                bottom: BorderSide(color: Colors.white.withOpacity(0.07)),
              ),
            ),
            child: Row(
              children: [
                const Icon(Icons.grid_on_outlined, size: 13, color: accent),
                const SizedBox(width: 8),
                const Expanded(
                  child: Text(
                    'Gantt-Like Diagram Options',
                    style: TextStyle(
                      fontSize: 11,
                      fontWeight: FontWeight.w600,
                      color: Colors.white70,
                    ),
                  ),
                ),
                GestureDetector(
                  onTap: () => setState(() => _ganttOptionsOpen = false),
                  child: const Icon(
                    Icons.close_rounded,
                    size: 15,
                    color: Colors.white38,
                  ),
                ),
              ],
            ),
          ),

          // ── Master enable ─────────────────────────────────────────────────
          toggleRow(
            'Enable Time Gradation',
            _ganttEnabled,
            (v) => _ganttEnabled = v,
          ),

          const Divider(color: dividerColor, height: 1),

          // ── Segment Width Mode ────────────────────────────────────────────
          sectionLabel('SEGMENT WIDTH'),
          row(
            Row(
              children: [
                Expanded(
                  child: Text(
                    _ganttProportional
                        ? 'Proportional (equal widths)'
                        : 'Free-Stretch',
                    style: const TextStyle(fontSize: 11, color: Colors.white70),
                  ),
                ),
                GestureDetector(
                  onTap: () {
                    setState(() => _ganttProportional = !_ganttProportional);
                    _saveWorkspace();
                  },
                  child: Container(
                    padding: const EdgeInsets.symmetric(
                      horizontal: 8,
                      vertical: 4,
                    ),
                    decoration: BoxDecoration(
                      color: accent.withOpacity(0.12),
                      borderRadius: BorderRadius.circular(4),
                      border: Border.all(color: accent.withOpacity(0.3)),
                    ),
                    child: Text(
                      _ganttProportional ? 'Proportional' : 'Free-Stretch',
                      style: const TextStyle(
                        fontSize: 9,
                        color: accent,
                        fontWeight: FontWeight.w600,
                      ),
                    ),
                  ),
                ),
              ],
            ),
          ),
          if (_ganttProportional)
            row(
              Row(
                children: [
                  const Text(
                    'Day width',
                    style: TextStyle(fontSize: 11, color: Colors.white54),
                  ),
                  Expanded(
                    child: Slider(
                      value: _ganttDayWidth.clamp(60.0, 600.0),
                      min: 60,
                      max: 600,
                      divisions: 54,
                      activeColor: accent,
                      onChanged: (v) {
                        setState(() => _ganttDayWidth = v);
                        _saveWorkspace();
                      },
                    ),
                  ),
                  Text(
                    '${_ganttDayWidth.round()}px',
                    style: const TextStyle(fontSize: 10, color: Colors.white38),
                  ),
                ],
              ),
            ),

          const Divider(color: dividerColor, height: 1),

          // ── Weekday Colors ────────────────────────────────────────────────
          sectionLabel('WEEKDAY COLORS'),
          Padding(
            padding: const EdgeInsets.fromLTRB(14, 4, 14, 8),
            child: Row(
              mainAxisAlignment: MainAxisAlignment.spaceBetween,
              children: List.generate(7, (i) {
                const labels = ['M', 'T', 'W', 'T', 'F', 'S', 'S'];
                return Tooltip(
                  message: ['Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat', 'Sun'][i],
                  child: GestureDetector(
                    onTap: () {
                      _showUnifiedColorPicker(
                        title:
                            'Weekday color: ${['Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat', 'Sun'][i]}',
                        initialColor: _ganttWeekdayColors[i],
                        onApply: (c) {
                          setState(() {
                            _ganttWeekdayColors = List.from(_ganttWeekdayColors)
                              ..[i] = c;
                          });
                          _saveWorkspace();
                        },
                      );
                    },
                    child: Container(
                      width: 30,
                      height: 30,
                      decoration: BoxDecoration(
                        color: _ganttWeekdayColors[i],
                        borderRadius: BorderRadius.circular(6),
                        border: Border.all(
                          color: Colors.white.withOpacity(0.2),
                        ),
                      ),
                      child: Center(
                        child: Text(
                          labels[i],
                          style: TextStyle(
                            fontSize: 10,
                            fontWeight: FontWeight.w700,
                            color:
                                _ganttWeekdayColors[i].computeLuminance() > 0.5
                                ? Colors.black87
                                : Colors.white,
                          ),
                        ),
                      ),
                    ),
                  ),
                );
              }),
            ),
          ),

          const Divider(color: dividerColor, height: 1),

          // ── Force Time Alignment ──────────────────────────────────────────
          toggleRow(
            'Force Time Alignment',
            _ganttForceTimeAlign,
            (v) => _ganttForceTimeAlign = v,
          ),
          if (_ganttForceTimeAlign)
            row(
              Row(
                children: [
                  const Text(
                    'Snap',
                    style: TextStyle(fontSize: 11, color: Colors.white54),
                  ),
                  const SizedBox(width: 10),
                  ...([15, 30, 60]).map((min) {
                    final active = _ganttSnapMinutes == min;
                    return GestureDetector(
                      onTap: () {
                        setState(() => _ganttSnapMinutes = min);
                        _saveWorkspace();
                      },
                      child: Container(
                        margin: const EdgeInsets.only(right: 6),
                        padding: const EdgeInsets.symmetric(
                          horizontal: 10,
                          vertical: 4,
                        ),
                        decoration: BoxDecoration(
                          color: active
                              ? accent.withOpacity(0.18)
                              : Colors.white.withOpacity(0.05),
                          borderRadius: BorderRadius.circular(4),
                          border: Border.all(
                            color: active
                                ? accent.withOpacity(0.6)
                                : Colors.white12,
                          ),
                        ),
                        child: Text(
                          '${min}m',
                          style: TextStyle(
                            fontSize: 10,
                            color: active ? accent : Colors.white54,
                            fontWeight: active
                                ? FontWeight.w600
                                : FontWeight.normal,
                          ),
                        ),
                      ),
                    );
                  }),
                ],
              ),
            ),

          const Divider(color: dividerColor, height: 1),

          // ── Project Axis ──────────────────────────────────────────────────
          toggleRow(
            'Show Project Axis',
            _ganttShowProjectAxis,
            (v) => _ganttShowProjectAxis = v,
          ),

          const Divider(color: dividerColor, height: 1),

          // ── Reset ─────────────────────────────────────────────────────────
          Padding(
            padding: const EdgeInsets.fromLTRB(14, 8, 14, 12),
            child: GestureDetector(
              onTap: () {
                setState(() {
                  _ganttProportional = true;
                  _ganttDayWidth = 200.0;
                  _ganttForceTimeAlign = false;
                  _ganttSnapMinutes = 30;
                  _ganttShowProjectAxis = false;
                  _ganttColumnWidths.clear();
                  _ganttLaneHeights.clear();
                  _ganttWeekdayColors = [
                    const Color(0xFFEF5350),
                    const Color(0xFFFF9800),
                    const Color(0xFFFFD600),
                    const Color(0xFF4CAF50),
                    const Color(0xFF4FC3F7),
                    const Color(0xFF1565C0),
                    const Color(0xFF9C27B0),
                  ];
                });
                _saveWorkspace();
              },
              child: Container(
                padding: const EdgeInsets.symmetric(vertical: 8),
                decoration: BoxDecoration(
                  color: Colors.red.withOpacity(0.06),
                  borderRadius: BorderRadius.circular(5),
                  border: Border.all(color: Colors.red.withOpacity(0.2)),
                ),
                child: const Center(
                  child: Text(
                    'Reset to Defaults',
                    style: TextStyle(
                      fontSize: 11,
                      color: Colors.redAccent,
                      fontWeight: FontWeight.w600,
                    ),
                  ),
                ),
              ),
            ),
          ),
        ],
      ),
    );
  }

  Widget _buildPreferencesPage() {
    // ── Sidebar category definitions (mirrors Settings sidebar style) ──────
    const items = [
      ('general', Icons.tune_rounded, 'General'),
      ('connection', Icons.cable_rounded, 'Connections'),
      ('appearance', Icons.palette_outlined, 'Appearance'),
      ('cards', Icons.style_outlined, 'Cards'),
      ('tasks', Icons.check_circle_outline, 'Task List'),
    ];

    Widget sidebarItem(String id, IconData icon, String label) {
      final active = _prefActiveSection == id;
      return InkWell(
        onTap: () => setState(() => _prefActiveSection = id),
        child: AnimatedContainer(
          duration: const Duration(milliseconds: 120),
          margin: const EdgeInsets.symmetric(horizontal: 8, vertical: 2),
          padding: const EdgeInsets.symmetric(horizontal: 10, vertical: 8),
          decoration: BoxDecoration(
            color: active
                ? Colors.blueAccent.withOpacity(0.12)
                : Colors.transparent,
            borderRadius: BorderRadius.circular(6),
            border: Border.all(
              color: active
                  ? Colors.blueAccent.withOpacity(0.3)
                  : Colors.transparent,
            ),
          ),
          child: Row(
            children: [
              Icon(
                icon,
                size: 14,
                color: active ? Colors.blueAccent : Colors.white38,
              ),
              const SizedBox(width: 10),
              Text(
                label,
                style: TextStyle(
                  fontSize: 12,
                  fontWeight: active ? FontWeight.w600 : FontWeight.normal,
                  color: active ? Colors.white : Colors.white54,
                ),
              ),
            ],
          ),
        ),
      );
    }

    Widget contentFor(String section) {
      switch (section) {
        case 'general':
          return ListView(
            padding: const EdgeInsets.symmetric(vertical: 24, horizontal: 24),
            children: [
              SwitchListTile(
                secondary: const Icon(
                  Icons.work_outline,
                  color: Colors.blueAccent,
                  size: 20,
                ),
                title: const Text(
                  'Show Workspace File Path',
                  style: TextStyle(color: Colors.white70, fontSize: 13),
                ),
                subtitle: const Text(
                  'Display workspace .json file path in the workspace list',
                  style: TextStyle(color: Colors.white38, fontSize: 11),
                ),
                value: _prefShowWorkspacePaths,
                activeColor: Colors.blueAccent,
                onChanged: (v) {
                  setState(() => _prefShowWorkspacePaths = v);
                  _savePreferences();
                },
              ),
            ],
          );

        case 'connection':
          return ListView(
            padding: const EdgeInsets.symmetric(vertical: 24, horizontal: 24),
            children: [
              _prefSection(
                icon: Icons.cable_rounded,
                label: 'Connection Options',
                expanded: _prefShowConnectionOptions,
                onToggle: () => setState(
                  () =>
                      _prefShowConnectionOptions = !_prefShowConnectionOptions,
                ),
                children: [
                  SwitchListTile(
                    contentPadding: const EdgeInsets.only(left: 48, right: 16),
                    title: const Text(
                      'Allow Duplicate Indirect Connections',
                      style: TextStyle(color: Colors.white70, fontSize: 12),
                    ),
                    subtitle: const Text(
                      'Permit connecting cards via junctions if a path already exists.',
                      style: TextStyle(color: Colors.white38, fontSize: 11),
                    ),
                    value: _prefAllowDuplicateConnections,
                    activeColor: Colors.blueAccent,
                    onChanged: (v) {
                      setState(() => _prefAllowDuplicateConnections = v);
                      _savePreferences();
                    },
                  ),
                ],
              ),
            ],
          );

        case 'appearance':
          return ListView(
            padding: const EdgeInsets.symmetric(vertical: 24, horizontal: 24),
            children: [
              _prefSection(
                icon: Icons.palette_outlined,
                label: 'Connection Appearance',
                expanded: _prefShowConnectionAppearance,
                onToggle: () => setState(
                  () => _prefShowConnectionAppearance =
                      !_prefShowConnectionAppearance,
                ),
                children: const [
                  Padding(
                    padding: EdgeInsets.fromLTRB(48, 8, 16, 8),
                    child: Text(
                      'Connection appearance options',
                      style: TextStyle(color: Colors.white38, fontSize: 12),
                    ),
                  ),
                ],
              ),
            ],
          );

        case 'cards':
          return ListView(
            padding: const EdgeInsets.symmetric(vertical: 24, horizontal: 24),
            children: [
              _prefSection(
                icon: Icons.style_outlined,
                label: 'Card Appearance',
                expanded: _prefShowCardAppearance,
                onToggle: () => setState(
                  () => _prefShowCardAppearance = !_prefShowCardAppearance,
                ),
                children: [
                  SwitchListTile(
                    contentPadding: const EdgeInsets.only(left: 48, right: 16),
                    title: const Text(
                      'Show ID on Cards',
                      style: TextStyle(color: Colors.white70, fontSize: 12),
                    ),
                    value: _prefShowIdOnCards,
                    activeColor: Colors.blueAccent,
                    onChanged: (v) {
                      setState(() => _prefShowIdOnCards = v);
                      _savePreferences();
                    },
                  ),
                  SwitchListTile(
                    contentPadding: const EdgeInsets.only(left: 48, right: 16),
                    title: const Text(
                      'Show Project Name on Cards',
                      style: TextStyle(color: Colors.white70, fontSize: 12),
                    ),
                    value: _prefShowProjectName,
                    activeColor: Colors.blueAccent,
                    onChanged: (v) {
                      setState(() => _prefShowProjectName = v);
                      _savePreferences();
                    },
                  ),
                  SwitchListTile(
                    contentPadding: const EdgeInsets.only(left: 48, right: 16),
                    title: const Text(
                      'Show Due Date on Cards',
                      style: TextStyle(color: Colors.white70, fontSize: 12),
                    ),
                    value: _prefShowDueDateOnCards,
                    activeColor: Colors.blueAccent,
                    onChanged: (v) {
                      setState(() => _prefShowDueDateOnCards = v);
                      _savePreferences();
                    },
                  ),
                  SwitchListTile(
                    contentPadding: const EdgeInsets.only(left: 48, right: 16),
                    title: const Text(
                      'Show Time on Cards',
                      style: TextStyle(color: Colors.white70, fontSize: 12),
                    ),
                    value: _prefShowTimeOnCards,
                    activeColor: Colors.blueAccent,
                    onChanged: (v) {
                      setState(() => _prefShowTimeOnCards = v);
                      _savePreferences();
                    },
                  ),
                ],
              ),
              _prefSection(
                icon: Icons.info_outline,
                label: 'Card Info',
                expanded: _prefShowCardInfo,
                onToggle: () =>
                    setState(() => _prefShowCardInfo = !_prefShowCardInfo),
                children: const [
                  Padding(
                    padding: EdgeInsets.fromLTRB(48, 8, 16, 16),
                    child: Text(
                      'Card info options',
                      style: TextStyle(color: Colors.white38, fontSize: 12),
                    ),
                  ),
                ],
              ),
            ],
          );

        case 'tasks':
          return ListView(
            padding: const EdgeInsets.symmetric(vertical: 24, horizontal: 24),
            children: [
              _prefSection(
                icon: Icons.list_alt_rounded,
                label: 'Task List',
                expanded: _prefShowListedTasks,
                onToggle: () => setState(
                  () => _prefShowListedTasks = !_prefShowListedTasks,
                ),
                children: [
                  SwitchListTile(
