  // --- CANVAS COMPONENT ---
  Widget _buildRightScrollbar() {
    Rect bounds = _getContentBounds();
    double extentRatio = (_viewportSize.height / bounds.height).clamp(0.0, 1.0);
    double thumbHeight = _viewportSize.height * extentRatio;
    double scrollProgress =
        (-_canvasOffset.dy - bounds.top) /
        (bounds.height - _viewportSize.height);
    double thumbTop =
        (_viewportSize.height - thumbHeight) *
        (scrollProgress.isNaN ? 0 : scrollProgress.clamp(0.0, 1.0));

    return Positioned(
      right: 0,
      top: 0,
      bottom: 0,
      child: Container(
        width: 12,
        color: Colors.white.withOpacity(0.02),
        child: Stack(
          children: [
            Positioned(
              top: thumbTop,
              child: GestureDetector(
                onVerticalDragUpdate: (d) {
                  double scrollDelta =
                      (d.delta.dy / (_viewportSize.height - thumbHeight)) *
                      (bounds.height - _viewportSize.height);
                  setState(
                    () => _canvasOffset = Offset(
                      _canvasOffset.dx,
                      _canvasOffset.dy - (scrollDelta.isNaN ? 0 : scrollDelta),
                    ),
                  );
                },
                child: Container(
                  width: 8,
                  height: thumbHeight,
                  margin: EdgeInsets.all(2),
                  decoration: BoxDecoration(
                    color: Colors.blueAccent.withOpacity(0.5),
                    borderRadius: BorderRadius.circular(4),
                  ),
                ),
              ),
            ),
          ],
        ),
      ),
    );
  }

  Widget _buildBottomScrollbar() {
    Rect bounds = _getContentBounds();
    double extentRatio = (_viewportSize.width / bounds.width).clamp(0.0, 1.0);
    double thumbWidth = _viewportSize.width * extentRatio;
    double scrollProgress =
        (-_canvasOffset.dx - bounds.left) /
        (bounds.width - _viewportSize.width);
    double thumbLeft =
        (_viewportSize.width - thumbWidth) *
        (scrollProgress.isNaN ? 0 : scrollProgress.clamp(0.0, 1.0));

    return Positioned(
      bottom: 0,
      left: 0, // Simplified because it's already inside the Expanded column
      right: 12, // Leave room for the vertical scrollbar
      child: Container(
        height: 12,
        color: Colors.white.withOpacity(0.02),
        child: Stack(
          children: [
            Positioned(
              left: thumbLeft,
              child: GestureDetector(
                onHorizontalDragUpdate: (d) {
                  double scrollDelta =
                      (d.delta.dx / (_viewportSize.width - thumbWidth)) *
                      (bounds.width - _viewportSize.width);
                  setState(
                    () => _canvasOffset = Offset(
                      _canvasOffset.dx - (scrollDelta.isNaN ? 0 : scrollDelta),
                      _canvasOffset.dy,
                    ),
                  );
                },
                child: Container(
                  height: 8,
                  width: thumbWidth,
                  margin: EdgeInsets.all(2),
                  decoration: BoxDecoration(
                    color: Colors.blueAccent.withOpacity(0.5),
                    borderRadius: BorderRadius.circular(4),
                  ),
                ),
              ),
            ),
          ],
        ),
      ),
    );
  }

