  Rect _taskWorldRect(String id) {
    final pos = _taskPositions[id] ?? Offset.zero;
    final task = _canvasTasks.firstWhere(
      (t) => t.id == id,
      orElse: () => Task(
        id: id,
        title: '',
        isDone: false,
        projectId: '',
        subTaskIds: [],
        timeSpent: 0,
        attachments: [],
        tagIds: [],
      ),
    );
    return Rect.fromLTWH(pos.dx, pos.dy, task.cardWidth, task.cardHeight);
  }

  Rect _junctionWorldRect(JunctionNode j) =>
      Rect.fromLTWH(j.position.dx, j.position.dy, j.width, j.height);

  Rect _conditionalWorldRect(ConditionalNode c) =>
      Rect.fromLTWH(c.position.dx, c.position.dy, c.width, c.height);

  /// Returns true if [localPos] (in canvas widget local coordinates) falls
  /// inside any task card or junction node currently on the canvas.
  bool _isPointerOverCardOrJunction(Offset localPos) {
    final worldPos = (localPos - _canvasOffset) / _scale;
    for (final task in _canvasTasks) {
      if (_taskWorldRect(task.id).contains(worldPos)) return true;
    }
    for (final j in _junctions) {
      if (_junctionWorldRect(j).contains(worldPos)) return true;
    }
    // Rhombus hit-test: a point is inside the diamond when the sum of its
    // normalised distances from the centre is ≤ 1.
    for (final c in _conditionals) {
      final cx = c.position.dx + c.width / 2;
      final cy = c.position.dy + c.height / 2;
      final dx = (worldPos.dx - cx).abs() / (c.width / 2);
      final dy = (worldPos.dy - cy).abs() / (c.height / 2);
      if (dx + dy <= 1.0) return true;
    }
    // Resize-handle hit-test: handles are rendered in screen space at the
    // corners/edges of selected rhombuses when Shift is held.  If the pointer
    // lands on one of those 12×12 squares we must NOT start a marquee.
    if (_shiftHeld) {
      const double hs = 12.0;
      for (final c in _conditionals) {
        if (!_selectedConditionalIds.contains(c.id)) continue;
        final sp = (c.position * _scale) + _canvasOffset;
        final sw = c.width * _scale;
        final sh = c.height * _scale;
        final handleCenters = [
          Offset(sp.dx + sw, sp.dy + sh / 2), // right
          Offset(sp.dx + sw / 2, sp.dy + sh), // bottom
          Offset(sp.dx, sp.dy + sh / 2), // left
          Offset(sp.dx + sw / 2, sp.dy), // top
          Offset(sp.dx, sp.dy), // top-left
          Offset(sp.dx + sw, sp.dy), // top-right
          Offset(sp.dx, sp.dy + sh), // bottom-left
          Offset(sp.dx + sw, sp.dy + sh), // bottom-right
        ];
        for (final hc in handleCenters) {
          if (Rect.fromCenter(
            center: hc,
            width: hs,
            height: hs,
          ).contains(localPos)) {
            return true;
          }
        }
      }
    }
    return false;
  }

  void _applyMarquee(Rect marqueeWorld) {
    final bool shift = HardwareKeyboard.instance.isControlPressed;
    setState(() {
      // ── Cards ────────────────────────────────────────────────────────────
      final newTasks = _marqueeSelectCards
          ? _canvasTasks
                .where((t) => marqueeWorld.overlaps(_taskWorldRect(t.id)))
                .map((t) => t.id)
                .toSet()
          : <String>{};

      // ── Operators (junctions) ────────────────────────────────────────────
      final newJunctions = _marqueeSelectOperators
          ? _junctions
                .where((j) => marqueeWorld.overlaps(_junctionWorldRect(j)))
                .map((j) => j.id)
                .toSet()
          : <String>{};

      // ── Operators (conditionals / rhombus) ──────────────────────────────
      final newConditionals = _marqueeSelectOperators
          ? _conditionals
                .where((c) => marqueeWorld.overlaps(_conditionalWorldRect(c)))
                .map((c) => c.id)
                .toSet()
          : <String>{};

      // ── Lines (relations) ────────────────────────────────────────────────
      // A line is "inside" the marquee when both its endpoints fall within it.
      final newRelKeys = _marqueeSelectLines
          ? _taskRelations
                .where((r) {
                  try {
                    final src = _getRelationWorldPos(
                      r.sourceId,
                      r.sourceLocalPos,
                    );
                    final tgt = _getRelationWorldPos(
                      r.targetId,
                      r.targetLocalPos,
                    );
                    return marqueeWorld.contains(src) &&
                        marqueeWorld.contains(tgt);
                  } catch (_) {
                    return false;
                  }
                })
                .map((r) => '${r.sourceId}→${r.targetId}')
                .toSet()
          : <String>{};

      if (shift) {
        _selectedTaskIds.addAll(newTasks);
        _selectedJunctionIds.addAll(newJunctions);
        _selectedConditionalIds.addAll(newConditionals);
        _selectedRelationKeys.addAll(newRelKeys);
      } else {
        _selectedTaskIds = newTasks;
        _selectedJunctionIds = newJunctions;
        _selectedConditionalIds = newConditionals;
        _selectedRelationKeys = newRelKeys;
        _selectedRelationKey = null; // clear single-click selection
      }

      if (_selectedTaskIds.length == 1) {
        _selectedCanvasTaskId = _selectedTaskIds.first;
      } else {
        _selectedCanvasTaskId = null;
      }
      if (_selectedJunctionIds.length == 1) {
        _selectedJunctionId = _selectedJunctionIds.first;
      } else if (_selectedJunctionIds.isEmpty) {
        _selectedJunctionId = null;
      }
      if (_selectedConditionalIds.length == 1) {
        _selectedConditionalId = _selectedConditionalIds.first;
      } else if (_selectedConditionalIds.isEmpty) {
        _selectedConditionalId = null;
      }
    });
  }

  Widget _buildMainCanvas() {
    return SizedBox.expand(
      child: DragTarget<Task>(
        onAcceptWithDetails: (details) {
          final RenderBox? box =
              _canvasKey.currentContext?.findRenderObject() as RenderBox?;
          if (box != null) {
            final localScreenOffset = box.globalToLocal(details.offset);
            final worldOffset = (localScreenOffset - _canvasOffset) / _scale;
            setState(() {
              final task = details.data;
              if (!_canvasTasks.any((t) => t.id == task.id)) {
                task.visibleProperties = Set.from(_standardVisibleInfos);
                _canvasTasks.add(task);
              }

              // NEW: Detach from parent if it was dragged out of a subcanvas
              for (var parent in _allTasks) {
                if (parent.subTaskIds.any((id) => id.toString() == task.id)) {
                  parent.subTaskIds.remove(task.id);
                  _saveTaskToMeta(parent); // Persist removal
                }
              }

              // Multi-select drag: move all selected tasks by the same delta
              // Multi-select drag: move all selected tasks by the same delta
              if (_selectedTaskIds.contains(task.id) &&
                  _selectedTaskIds.length > 1 &&
                  _dragAnchorWorld != null) {
                final delta = worldOffset - _dragAnchorWorld!;
                for (final id in _selectedTaskIds) {
                  if (id != task.id) {
                    final prev = _taskPositions[id];
                    if (prev != null) _taskPositions[id] = prev + delta;
                  }
                }
              }
              _taskPositions[task.id] = worldOffset;

              // ── Gantt: date acquisition from drop position ─────────────
              if (_ganttEnabled) {
                _assignGanttDateFromDrop(task, worldOffset);
              }
            });
          }
        },
        builder: (context, _, __) => MouseRegion(
          cursor: (_isPanMode || _isMiddleMousePanning)
              ? SystemMouseCursors.grab
              : MouseCursor.defer,
          onHover: (event) {
            if (_connectingSourceId != null)
              setState(() => _currentCursorLocalPos = event.localPosition);
          },
          child: GestureDetector(
            behavior: HitTestBehavior.opaque,
            // 1. LEFT CLICK: Instantly create Operator Node
            onTapUp: (details) {
              if (_connectingSourceId != null) {
                setState(() {
                  final worldPos =
                      (details.localPosition - _canvasOffset) / _scale;
                  final newJunction = JunctionNode(
                    id: "jnc_${DateTime.now().millisecondsSinceEpoch}",
                    position: worldPos,
                    operatorType:
                        _defaultOperator, // NEW: Apply the default setting
                  );
                  _junctions.add(newJunction);

                  final double centerH = newJunction.height / 2;

                  _taskRelations.add(
                    TaskRelation(
                      arrowSize: _defaultArrowSize,
                      sourceId: _connectingSourceId!,
                      targetId: newJunction.id,
                      sourceLocalPos: _connectingSourceLocalPos!,
                      targetLocalPos: Offset(
                        _getGateX(
                          centerH,
                          newJunction.width,
                          newJunction.height,
                          newJunction.operatorType,
                          true,
                        ),
                        centerH,
                      ),
                    ),
                  );

                  _connectingSourceId = newJunction.id;
                  _connectingSourceLocalPos = Offset(
                    _getGateX(
                      centerH,
                      newJunction.width,
                      newJunction.height,
                      newJunction.operatorType,
                      false,
                    ),
                    centerH,
                  );
                });
              }
            },
            onDoubleTapDown: (details) {
              final rel = _getRelationAt(details.localPosition);
              if (rel != null) {
                if (HardwareKeyboard.instance.isShiftPressed) {
                  setState(() {
                    final worldPos =
                        (details.localPosition - _canvasOffset) / _scale;
                    rel.handles.add(worldPos);
                  });
                } else {
                  _showLineStyleEditor(rel);
                }
              }
            },
            onTapDown: (details) {
              FocusManager.instance.primaryFocus?.unfocus();
              // Always exit any active inline-edit mode on any canvas tap.
              if (_editingConditionalId != null || _editingTaskId != null) {
                setState(() {
                  _editingConditionalId = null;
                  _editingTaskId = null;
                });
              }
              if (_connectingSourceId != null) return;
              final rel = _getRelationAt(details.localPosition);
              final ctrl = HardwareKeyboard.instance.isControlPressed;
              setState(() {
                if (rel != null) {
                  final relKey = '${rel.sourceId}→${rel.targetId}';
                  if (ctrl) {
                    // Toggle this line in the multi-selection set.
                    if (_selectedRelationKeys.contains(relKey)) {
                      _selectedRelationKeys.remove(relKey);
                    } else {
                      _selectedRelationKeys.add(relKey);
                    }
                    // _selectedRelationKey tracks the "last clicked" line for
                    // single-item operations; null when multiple are selected.
                    _selectedRelationKey = _selectedRelationKeys.length == 1
                        ? _selectedRelationKeys.first
                        : null;
                  } else {
                    // Plain click → replace entire selection with this line.
                    _selectedRelationKey = relKey;
                    _selectedRelationKeys = {relKey};
                    _selectedCanvasTaskId = null;
                    _selectedJunctionId = null;
                    _selectedTaskIds.clear();
                    _selectedJunctionIds.clear();
                  }
                } else {
                  if (ctrl) {
                    // Ctrl+click on empty space: keep existing selection.
                  } else if (!_isPointerOverCardOrJunction(
                    details.localPosition,
                  )) {
                    // Plain click on empty canvas (not over a card/junction):
                    // clear everything. Guard mirrors Listener.onPointerDown so
                    // the canvas GestureDetector never wipes _selectedTaskIds
                    // when the tap lands on a card, which would prevent Delete
                    // from working on the selected card.
                    _selectedRelationKey = null;
                    _selectedRelationKeys.clear();
                    _selectedCanvasTaskId = null;
                    _selectedJunctionId = null;
                    _selectedTaskIds.clear();
                    _selectedJunctionIds.clear();
                    _selectedConditionalId = null;
                    _selectedConditionalIds.clear();
                  }
                }
              });
            },
            onSecondaryTapDown: (details) {
              // Cancel an in-progress connection drag first.
              if (_connectingSourceId != null) {
                setState(() {
                  _connectingSourceId = null;
                  _connectingSourceLocalPos = null;
                  _currentCursorLocalPos = null;
                });
                return;
              }

              // Right-click on empty canvas → create a junction node with the
              // current standard operator at the clicked world position.
              // When IF mode is active, create a ConditionalNode instead.
              final rel = _getRelationAt(details.localPosition);
              if (rel == null &&
                  !_isPointerOverCardOrJunction(details.localPosition)) {
                final worldPos =
                    (details.localPosition - _canvasOffset) / _scale;
                setState(() {
                  if (_isIfMode) {
                    final c = ConditionalNode(
                      id: 'cnd_${DateTime.now().millisecondsSinceEpoch}',
                      position: worldPos - const Offset(70, 40),
                    );
                    _conditionals.add(c);
                    _selectedConditionalId = c.id;
                    _selectedConditionalIds = {c.id};
                    _selectedJunctionId = null;
                    _selectedJunctionIds.clear();
                    _selectedCanvasTaskId = null;
                    _selectedRelationKey = null;
                  } else {
                    final newJunction = JunctionNode(
                      id: 'jnc_${DateTime.now().millisecondsSinceEpoch}',
                      position: worldPos,
                      operatorType: _defaultOperator,
                    );
                    _junctions.add(newJunction);
                    // Select the new node so it can be immediately wired up or
                    // deleted with the Delete key.
                    _selectedJunctionIds = {newJunction.id};
                    _selectedJunctionId = newJunction.id;
                    _selectedTaskIds.clear();
                    _selectedCanvasTaskId = null;
                    _selectedRelationKey = null;
                  }
                });
                _saveWorkspace();
              }
            },
            child: Listener(
              onPointerDown: (event) {
                if (event.buttons == 4) {
                  setState(() => _isMiddleMousePanning = true);
                  return;
                }
                if (event.buttons == 1 &&
                    !_isPanMode &&
                    _connectingSourceId == null &&
                    !_isPlugDragging &&
                    _selectedRelationKey == null &&
                    !_isPointerOverCardOrJunction(event.localPosition)) {
                  setState(() {
                    _marqueeStart = event.localPosition;
                    _marqueeEnd = event.localPosition;
                    _isMarqueeActive = false;
                  });
                }
              },
              onPointerMove: (event) {
                if (_isMiddleMousePanning) {
                  setState(() => _canvasOffset += event.delta);
                  return;
                }
                if (_isPanMode && event.buttons == 1) {
                  setState(() => _canvasOffset += event.delta);
                  return;
                }
                if (_marqueeStart != null &&
                    event.buttons == 1 &&
                    !_isPanMode) {
                  setState(() {
                    _marqueeEnd = event.localPosition;
                    _isMarqueeActive = true;
                  });
                }
              },
              onPointerUp: (event) {
                if (_isMiddleMousePanning && (event.buttons & 4) == 0) {
                  setState(() => _isMiddleMousePanning = false);
                  return;
                }
                if (_isMarqueeActive &&
                    _marqueeStart != null &&
                    _marqueeEnd != null) {
                  final screenRect = Rect.fromPoints(
                    _marqueeStart!,
                    _marqueeEnd!,
                  );
                  final worldTL = (screenRect.topLeft - _canvasOffset) / _scale;
                  final worldBR =
                      (screenRect.bottomRight - _canvasOffset) / _scale;
                  _applyMarquee(Rect.fromPoints(worldTL, worldBR));
                }
                setState(() {
                  _marqueeStart = null;
                  _marqueeEnd = null;
                  _isMarqueeActive = false;
                });
              },
              onPointerSignal: (pointerSignal) {
                if (pointerSignal is PointerScrollEvent) {
                  final isAltPressed = HardwareKeyboard.instance.isAltPressed;
                  final isShiftPressed =
                      HardwareKeyboard.instance.isShiftPressed;
                  setState(() {
                    if (isAltPressed) {
                      double zoomFactor = 0.05;
                      double scrollDir = pointerSignal.scrollDelta.dy > 0
                          ? -1
                          : 1;
                      double newScale = (_scale + (zoomFactor * scrollDir))
                          .clamp(0.2, 3.0);
                      final focalPointWorld =
                          (pointerSignal.localPosition - _canvasOffset) /
                          _scale;
                      _canvasOffset =
                          pointerSignal.localPosition -
                          (focalPointWorld * newScale);
                      _scale = newScale;
                    } else if (!_isHoveringCardScrollable) {
                      if (isShiftPressed) {
                        _canvasOffset = Offset(
                          _canvasOffset.dx - pointerSignal.scrollDelta.dy,
                          _canvasOffset.dy,
                        );
                      } else {
                        _canvasOffset = Offset(
                          _canvasOffset.dx,
                          _canvasOffset.dy - pointerSignal.scrollDelta.dy,
                        );
                      }
                    }
                  });
                }
              },
              child: Container(
                key: _canvasKey,
                decoration: BoxDecoration(color: _currentCanvasBackgroundColor),
                clipBehavior: Clip.hardEdge,
                child: Stack(
                  children: [
                    // ── Gantt Day Bar (pinned to top, scrolls with X) ─
                    if (_ganttEnabled)
                      Positioned(
                        top: 0,
                        left: _ganttShowProjectAxis ? 120 : 0,
                        right: 0,
                        height: 28,
                        child: _GanttDayBar(
                          referenceDay: _ganttReferenceDay,
                          canvasOffset: _canvasOffset,
                          scale: _scale,
                          proportional: _ganttProportional,
                          dayWidth: _ganttDayWidth,
                          columnWidths: _ganttColumnWidths,
                          weekdayColors: _ganttWeekdayColors,
                          onColumnResize: (date, w) {
                            setState(() => _ganttColumnWidths[date] = w);
                          },
                          onColumnResizeEnd: _saveWorkspace,
                          onColumnReset: (date) {
                            setState(() => _ganttColumnWidths.remove(date));
                            _saveWorkspace();
                          },
                        ),
                      ),

                    // Marquee selection rectangle overlay
                    if (_isMarqueeActive &&
                        _marqueeStart != null &&
                        _marqueeEnd != null)
                      Positioned.fill(
                        child: IgnorePointer(
                          child: CustomPaint(
                            painter: _MarqueePainter(
                              start: _marqueeStart!,
                              end: _marqueeEnd!,
                            ),
                          ),
                        ),
                      ),
                    Positioned.fill(
                      child: CustomPaint(
                        painter: GridPainter(
                          offset: _canvasOffset,
                          scale: _scale,
                          thickness: _gridThickness,
                          color: _gridColor,
                        ),
                      ),
                    ),

                    // ── Gantt Day Shadow (behind cards, above grid) ────────
                    if (_ganttEnabled)
                      Positioned.fill(
                        child: IgnorePointer(
                          child: CustomPaint(
                            painter: _DayShadowPainter(
                              referenceDay: _ganttReferenceDay,
                              canvasOffset: _canvasOffset,
                              scale: _scale,
                              weekdayColors: _ganttWeekdayColors,
                              proportional: _ganttProportional,
                              dayWidth: _ganttDayWidth,
                              columnWidths: _ganttColumnWidths,
                            ),
                          ),
                        ),
                      ),

                    // ── Gantt Project Axis (left strip, scrolls vertically) ─
                    if (_ganttEnabled && _ganttShowProjectAxis)
                      Positioned(
                        left: 0,
                        top: _ganttEnabled ? 28 : 0,
                        bottom: 0,
                        width: 120,
                        child: IgnorePointer(
                          ignoring: false,
                          child: _GanttProjectAxis(
                            projectEntries: _projectOrder
                                .map(
                                  (id) =>
                                      MapEntry(id, _projects[id]?.title ?? id),
                                )
                                .toList(),
                            projectColors: _projectColors,
                            laneHeights: _ganttLaneHeights,
                            defaultLaneH: 120,
                            canvasOffset: _canvasOffset,
                            onLaneResize: (pid, h) =>
                                setState(() => _ganttLaneHeights[pid] = h),
                          ),
                        ),
                      ),

                    Positioned.fill(
                      child: CustomPaint(
                        painter: ConnectionsPainter(
                          relations: _taskRelations,
                          taskPositions: _taskPositions,
                          junctions: _junctions,
                          conditionals: _conditionals,
                          scale: _scale,
                          canvasOffset: _canvasOffset,
                          connectingSourceId: _connectingSourceId,
                          connectingSourceLocalPos: _connectingSourceLocalPos,
                          currentCursorLocalPos: _currentCursorLocalPos,
                          selectedRelationKey: _selectedRelationKey,
                        ),
                      ),
                    ),
                    // Draggable Bezier Handles — only for the selected line
                    ..._taskRelations.expand((rel) {
                      final String relKey = '${rel.sourceId}→${rel.targetId}';
                      if (relKey != _selectedRelationKey) return <Widget>[];
                      return List.generate(
                        rel.handles.length,
                        (index) => _buildBezierHandle(rel, index),
                      );
                    }),

                    // Inside _buildMainCanvas, replace the section mapping _junctions:
                    ..._junctions.map((j) {
                      final screenPos = (j.position * _scale) + _canvasOffset;
                      final incoming = _taskRelations
                          .where((r) => r.targetId == j.id)
                          .toList();
                      final outgoing = _taskRelations
                          .where((r) => r.sourceId == j.id)
                          .toList();

                      return Positioned(
                        left: screenPos.dx,
                        top: screenPos.dy,
                        child: SizedBox(
                          width: j.width * _scale,
                          height: j.height * _scale,
                          child: Stack(
                            clipBehavior: Clip.none,
                            children: [
                              GestureDetector(
                                behavior: HitTestBehavior.opaque,
                                onPanUpdate: (d) => setState(() {
                                  final delta = d.delta / _scale;
                                  // Group move: if this junction is part of a
                                  // multi-selection, move all selected nodes.
                                  if (_selectedJunctionIds.contains(j.id) &&
                                      (_selectedJunctionIds.length > 1 ||
                                          _selectedConditionalIds.isNotEmpty ||
                                          _selectedTaskIds.isNotEmpty)) {
                                    for (final jj in _junctions) {
                                      if (_selectedJunctionIds.contains(jj.id))
                                        jj.position += delta;
                                    }
                                    for (final cc in _conditionals) {
                                      if (_selectedConditionalIds.contains(
                                        cc.id,
                                      ))
                                        cc.position += delta;
                                    }
                                    for (final tid in _selectedTaskIds) {
                                      final prev = _taskPositions[tid];
                                      if (prev != null)
                                        _taskPositions[tid] = prev + delta;
                                    }
                                  } else {
                                    j.position += delta;
                                  }
                                }),
                                onTap: () {
                                  final ctrl = HardwareKeyboard
                                      .instance
                                      .isControlPressed;
                                  setState(() {
                                    // Selecting an operator always clears
                                    // the line selection.
                                    _selectedRelationKey = null;
                                    _selectedRelationKeys.clear();
                                    _selectedCanvasTaskId = null;
                                    if (ctrl) {
                                      // Toggle this junction in/out of the
                                      // multi-selection.
                                      if (_selectedJunctionIds.contains(j.id)) {
                                        _selectedJunctionIds.remove(j.id);
                                      } else {
                                        _selectedJunctionIds.add(j.id);
                                      }
                                    } else {
                                      _selectedJunctionIds = {j.id};
                                      _selectedTaskIds.clear();
                                      _selectedConditionalIds.clear();
                                      _selectedConditionalId = null;
                                    }
                                    _selectedJunctionId =
                                        _selectedJunctionIds.length == 1
                                        ? _selectedJunctionIds.first
                                        : null;
                                  });
                                },
                                onSecondaryTap: () {
                                  _showOperatorDialog(context, j);
                                },
                                onTapUp: (details) {
                                  final double localX =
                                      details.localPosition.dx / _scale;
                                  final double localY =
                                      (details.localPosition.dy / _scale).clamp(
                                        0,
                                        j.height,
                                      );

                                  setState(() {
                                    // INPUT: Only accept if clicking the left half
                                    if (_connectingSourceId != null &&
                                        _connectingSourceId != j.id &&
                                        localX < (j.width / 2)) {
                                      if (_canConnect(
                                        _connectingSourceId!,
                                        j.id,
                                      )) {
                                        double snapX = _getGateX(
                                          localY,
                                          j.width,
                                          j.height,
                                          j.operatorType,
                                          true,
                                        );
                                        _taskRelations.add(
                                          TaskRelation(
                                            arrowSize: _defaultArrowSize,
                                            sourceId: _connectingSourceId!,
                                            targetId: j.id,
                                            sourceLocalPos:
                                                _connectingSourceLocalPos!,
                                            targetLocalPos: Offset(
                                              snapX,
                                              localY,
                                            ),
                                          ),
                                        );
                                        _connectingSourceId = null;
                                      }
                                    }
                                    // OUTPUT: Only start if clicking the right half
                                    else if (_connectingSourceId == null &&
                                        localX >= (j.width / 2)) {
                                      double snapX = _getGateX(
                                        localY,
                                        j.width,
                                        j.height,
                                        j.operatorType,
                                        false,
                                      );
                                      // For OR/XOR, localY is internally clamped by _getGateX
                                      double clampedY =
                                          (j.operatorType ==
                                              LogicalOperator.and)
                                          ? localY
                                          : localY.clamp(
                                              j.height * 0.35,
                                              j.height * 0.65,
                                            );

                                      _connectingSourceId = j.id;
                                      _connectingSourceLocalPos = Offset(
                                        snapX,
                                        clampedY,
                                      );
                                    }
                                  });
                                },
                                child: CustomPaint(
                                  size: Size(
                                    j.width * _scale,
                                    j.height * _scale,
                                  ),
                                  painter: LogicGatePainter(
                                    type: j.operatorType,
                                    color: _selectedJunctionIds.contains(j.id)
                                        ? const Color(0xFF4A4A5A)
                                        : const Color(0xFF2A2A2A),
                                    scale: _scale,
                                    isSelected: _selectedJunctionIds.contains(
                                      j.id,
                                    ),
                                  ),
                                  child: Center(
                                    child: Padding(
                                      padding: EdgeInsets.only(
                                        left:
                                            j.operatorType ==
                                                LogicalOperator.and
                                            ? 0
                                            : 8.0 * _scale,
                                      ),
                                      child: Text(
                                        j.operatorType.symbol,
                                        style: TextStyle(
                                          color: Colors.white60,
                                          fontSize: 15 * _scale,
                                          fontWeight: FontWeight.bold,
                                        ),
                                      ),
                                    ),
                                  ),
                                ),
                              ),
                              // Incoming/Outgoing Plugs
                              ...incoming.map((rel) {
                                final relKey =
                                    '${rel.sourceId}→${rel.targetId}';
                                final visible =
                                    _showConnectionPlugs ||
                                    _selectedJunctionIds.contains(j.id) ||
                                    _selectedRelationKey == relKey;
                                if (!visible) return const SizedBox.shrink();
                                return Positioned(
                                  left:
                                      (rel.targetLocalPos.dx * _scale) -
                                      (12 * _scale),
                                  top:
                                      (rel.targetLocalPos.dy * _scale) -
                                      (12 * _scale),
                                  child: _buildDraggablePlug(
                                    rel,
                                    isTarget: true,
                                    junction: j,
                                  ),
                                );
                              }),
                              ...outgoing.map((rel) {
                                final relKey =
                                    '${rel.sourceId}→${rel.targetId}';
                                final visible =
                                    _showConnectionPlugs ||
                                    _selectedJunctionIds.contains(j.id) ||
                                    _selectedRelationKey == relKey;
                                if (!visible) return const SizedBox.shrink();
                                return Positioned(
                                  left:
                                      (rel.sourceLocalPos.dx * _scale) -
                                      (12 * _scale),
                                  top:
                                      (rel.sourceLocalPos.dy * _scale) -
                                      (12 * _scale),
                                  child: _buildDraggablePlug(
                                    rel,
                                    isTarget: false,
                                    junction: j,
                                  ),
                                );
                              }),
                            ],
                          ),
                        ),
                      );
                    }),

                    // ── CONDITIONAL NODES (rhombus) ─────────────────────────
                    ..._conditionals.map((c) {
                      final sp = (c.position * _scale) + _canvasOffset;
                      final isSel = _selectedConditionalIds.contains(c.id);
                      final incoming = _taskRelations
                          .where((r) => r.targetId == c.id)
                          .toList();
                      final outgoing = _taskRelations
                          .where((r) => r.sourceId == c.id)
                          .toList();

                      return Positioned(
                        left: sp.dx,
                        top: sp.dy,
                        child: SizedBox(
                          width: c.width * _scale,
                          height: c.height * _scale,
                          child: Stack(
                            clipBehavior: Clip.none,
                            children: [
                              // ── Shape + drag + tap interactions ────────────
                              GestureDetector(
                                behavior: HitTestBehavior.opaque,
                                onPanUpdate: (d) => setState(() {
                                  final delta = d.delta / _scale;
                                  // Group move: if part of multi-selection move
                                  // all selected nodes together.
                                  if (_selectedConditionalIds.contains(c.id) &&
                                      (_selectedConditionalIds.length > 1 ||
                                          _selectedJunctionIds.isNotEmpty ||
                                          _selectedTaskIds.isNotEmpty)) {
                                    for (final cc in _conditionals) {
                                      if (_selectedConditionalIds.contains(
                                        cc.id,
                                      ))
                                        cc.position += delta;
                                    }
                                    for (final jj in _junctions) {
                                      if (_selectedJunctionIds.contains(jj.id))
                                        jj.position += delta;
                                    }
                                    for (final tid in _selectedTaskIds) {
                                      final prev = _taskPositions[tid];
                                      if (prev != null)
                                        _taskPositions[tid] = prev + delta;
                                    }
                                  } else {
                                    c.position += delta;
                                  }
                                }),
                                onSecondaryTap: () =>
                                    _showConditionalOperatorDialog(context, c),
                                onDoubleTap: () => setState(() {
                                  _editingConditionalId = c.id;
                                }),
                                onTap: () => setState(() {
                                  final ctrl = HardwareKeyboard
                                      .instance
                                      .isControlPressed;
                                  _editingConditionalId = null;
                                  _selectedRelationKey = null;
                                  _selectedRelationKeys.clear();
                                  _selectedCanvasTaskId = null;
                                  if (ctrl) {
                                    // Ctrl+click: toggle this conditional
                                    // in/out of the multi-selection.
                                    if (_selectedConditionalIds.contains(
                                      c.id,
                                    )) {
                                      _selectedConditionalIds.remove(c.id);
                                    } else {
                                      _selectedConditionalIds.add(c.id);
                                    }
                                    _selectedConditionalId =
                                        _selectedConditionalIds.length == 1
                                        ? _selectedConditionalIds.first
                                        : null;
                                  } else {
                                    _selectedJunctionId = null;
                                    _selectedJunctionIds.clear();
                                    _selectedTaskIds.clear();
                                    _selectedConditionalId = c.id;
                                    _selectedConditionalIds = {c.id};
                                  }
                                }),
                                onTapUp: (details) {
                                  final lx = details.localPosition.dx / _scale;
                                  setState(() {
                                    // INPUT zone: left border, up to 40% of width
                                    if (_connectingSourceId != null &&
                                        _connectingSourceId != c.id &&
                                        lx <= c.width * 0.40) {
                                      if (_canConnect(
                                        _connectingSourceId!,
                                        c.id,
                                      )) {
                                        _taskRelations.add(
                                          TaskRelation(
                                            sourceId: _connectingSourceId!,
                                            targetId: c.id,
                                            sourceLocalPos:
                                                _connectingSourceLocalPos!,
                                            targetLocalPos:
                                                _snapToConditionalBorder(
                                                  Offset(
                                                    lx,
                                                    details.localPosition.dy /
                                                        _scale,
                                                  ),
                                                  c.width,
                                                  c.height,
                                                  isInput: true,
                                                ),
                                            arrowSize: _defaultArrowSize,
                                          ),
                                        );
                                        _connectingSourceId = null;
                                        _connectingSourceLocalPos = null;
                                      }
                                    }
                                    // OUTPUT zone: right 50% of width
                                    else if (_connectingSourceId == null &&
                                        lx >= c.width * 0.50) {
                                      final snapPos = _snapToConditionalBorder(
                                        Offset(
                                          lx,
                                          details.localPosition.dy / _scale,
                                        ),
                                        c.width,
                                        c.height,
                                        isInput: false,
                                      );
                                      _connectingSourceId = c.id;
                                      _connectingSourceLocalPos = snapPos;
                                    }
                                  });
                                },
                                child: CustomPaint(
                                  size: Size(
                                    c.width * _scale,
                                    c.height * _scale,
                                  ),
                                  painter: RhombusPainter(
                                    color: isSel
                                        ? const Color(0xFF3A3F5A)
                                        : const Color(0xFF252A3A),
                                    isSelected: isSel,
                                  ),
                                ),
                              ),
                              // ── Plug-zone colour overlay ───────────────────
                              // Shown when the node is selected or global plug
                              // visibility is on.  Green tint = input (left),
                              // amber tint = output (right).
                              if (isSel || _showConnectionPlugs)
                                IgnorePointer(
                                  child: CustomPaint(
                                    size: Size(
                                      c.width * _scale,
                                      c.height * _scale,
                                    ),
                                    painter: const RhombusPlugZonePainter(),
                                  ),
                                ),
                              // ── Resize overlay: dashed rect ────────────────
                              // Visible when node is selected AND Shift is held.
                              // Handles are rendered at canvas level (see below).
                              if (isSel && _shiftHeld)
                                Positioned.fill(
                                  child: IgnorePointer(
                                    child: CustomPaint(
                                      painter: const _DashedRectPainter(),
                                    ),
                                  ),
                                ),
                              // ── Editable label inside the rhombus ──────────
                              Positioned.fill(
                                child: Center(
                                  child: SizedBox(
                                    width: c.width * _scale * 0.52,
                                    child: _editingConditionalId == c.id
                                        ? TextField(
                                            autofocus: true,
                                            onChanged: (v) =>
                                                setState(() => c.label = v),
                                            onSubmitted: (_) => setState(
                                              () =>
                                                  _editingConditionalId = null,
                                            ),
                                            onTapOutside: (_) => setState(
                                              () =>
                                                  _editingConditionalId = null,
                                            ),
                                            controller:
                                                TextEditingController(
                                                    text: c.label,
                                                  )
                                                  ..selection =
                                                      TextSelection.collapsed(
                                                        offset: c.label.length,
                                                      ),
                                            style: TextStyle(
                                              color: Colors.white70,
                                              fontSize: 11 * _scale,
                                              fontWeight: FontWeight.w500,
                                            ),
                                            textAlign: TextAlign.center,
                                            maxLines: (c.height / 2 / 15.4)
                                                .floor()
                                                .clamp(1, 6),
                                            decoration: InputDecoration(
                                              border: InputBorder.none,
                                              hintText: '?',
                                              hintStyle: TextStyle(
                                                color: Colors.white24,
                                                fontSize: 11 * _scale,
                                              ),
                                              isDense: true,
                                              contentPadding: EdgeInsets.zero,
                                            ),
                                          )
                                        // Display mode: wrap in a GestureDetector
                                        // so the Text (which absorbs hit-tests as
                                        // a RenderParagraph) still forwards select,
                                        // drag, and double-tap to the node logic.
                                        : (c.width < _kRhombusHideTextWidth ||
                                              c.height <
                                                  _kRhombusHideTextHeight)
                                        ? const SizedBox.shrink()
                                        : GestureDetector(
                                            behavior:
                                                HitTestBehavior.translucent,
                                            onPanUpdate: (d) => setState(() {
                                              final delta = d.delta / _scale;
                                              if (_selectedConditionalIds
                                                      .contains(c.id) &&
                                                  (_selectedConditionalIds
                                                              .length >
                                                          1 ||
                                                      _selectedJunctionIds
                                                          .isNotEmpty ||
                                                      _selectedTaskIds
                                                          .isNotEmpty)) {
                                                for (final cc
                                                    in _conditionals) {
                                                  if (_selectedConditionalIds
                                                      .contains(cc.id))
                                                    cc.position += delta;
                                                }
                                                for (final jj in _junctions) {
                                                  if (_selectedJunctionIds
                                                      .contains(jj.id))
                                                    jj.position += delta;
                                                }
                                                for (final tid
                                                    in _selectedTaskIds) {
                                                  final prev =
                                                      _taskPositions[tid];
                                                  if (prev != null)
                                                    _taskPositions[tid] =
                                                        prev + delta;
                                                }
                                              } else {
                                                c.position += delta;
                                              }
                                            }),
                                            onDoubleTap: () => setState(
                                              () =>
                                                  _editingConditionalId = c.id,
                                            ),
                                            onSecondaryTap: () =>
                                                _showConditionalOperatorDialog(
                                                  context,
                                                  c,
                                                ),
                                            onTap: () => setState(() {
                                              final ctrl = HardwareKeyboard
                                                  .instance
                                                  .isControlPressed;
                                              _editingConditionalId = null;
                                              _selectedRelationKey = null;
                                              _selectedRelationKeys.clear();
                                              _selectedCanvasTaskId = null;
                                              if (ctrl) {
                                                if (_selectedConditionalIds
                                                    .contains(c.id)) {
                                                  _selectedConditionalIds
                                                      .remove(c.id);
                                                } else {
                                                  _selectedConditionalIds.add(
                                                    c.id,
                                                  );
                                                }
                                                _selectedConditionalId =
                                                    _selectedConditionalIds
                                                            .length ==
                                                        1
                                                    ? _selectedConditionalIds
                                                          .first
                                                    : null;
                                              } else {
                                                _selectedJunctionId = null;
                                                _selectedJunctionIds.clear();
                                                _selectedTaskIds.clear();
                                                _selectedConditionalId = c.id;
                                                _selectedConditionalIds = {
                                                  c.id,
                                                };
                                              }
                                            }),
                                            child: Text(
                                              c.label.isEmpty ? '?' : c.label,
                                              textAlign: TextAlign.center,
                                              maxLines: (c.height / 2 / 15.4)
                                                  .floor()
                                                  .clamp(1, 6),
                                              overflow: TextOverflow.ellipsis,
                                              style: TextStyle(
                                                color: c.label.isEmpty
                                                    ? Colors.white24
                                                    : Colors.white70,
                                                fontSize: 11 * _scale,
                                                fontWeight: FontWeight.w500,
                                              ),
                                            ),
                                          ),
                                  ),
                                ),
                              ),
                              // ── Outgoing plugs with case-label field above ──
                              ...outgoing.map((rel) {
                                final relKey =
                                    '${rel.sourceId}→${rel.targetId}';
                                final visible =
                                    _showConnectionPlugs ||
                                    isSel ||
                                    _selectedRelationKey == relKey;
                                if (!visible) return const SizedBox.shrink();
                                return Positioned(
                                  left:
                                      (rel.sourceLocalPos.dx * _scale) -
                                      (12 * _scale),
                                  top:
                                      (rel.sourceLocalPos.dy * _scale) -
                                      (12 * _scale),
                                  child: _buildDraggablePlugForConditional(
                                    rel,
                                    isTarget: false,
                                    conditional: c,
                                  ),
                                );
                              }),
                              // ── Incoming plugs ─────────────────────────────
                              ...incoming.map((rel) {
                                final relKey =
                                    '${rel.sourceId}→${rel.targetId}';
                                final visible =
                                    _showConnectionPlugs ||
                                    isSel ||
                                    _selectedRelationKey == relKey;
                                if (!visible) return const SizedBox.shrink();
                                return Positioned(
                                  left:
                                      (rel.targetLocalPos.dx * _scale) -
                                      (12 * _scale),
                                  top:
                                      (rel.targetLocalPos.dy * _scale) -
                                      (12 * _scale),
                                  child: _buildDraggablePlugForConditional(
                                    rel,
                                    isTarget: true,
                                    conditional: c,
                                  ),
                                );
                              }),
                            ],
                          ),
                        ),
                      );
                    }),

                    // ── Canvas-level resize handles for conditionals ──────────
                    // Rendered outside the rhombus SizedBox so hit-testing works
                    // at edge/corner positions without being clipped by bounds.
                    if (_shiftHeld)
                      ..._conditionals
                          .where((c) => _selectedConditionalIds.contains(c.id))
                          .expand((c) {
                            final sp = (c.position * _scale) + _canvasOffset;
                            return _buildRhombusResizeHandles(c, sp);
                          }),

                    // TASK CARDS
                    ..._canvasTasks
                        .where((task) {
                          // Global canvas filter rules
                          final globalActive = _canvasFilterRules
                              .where((r) => r.isConfigured)
                              .toList();
                          if (globalActive.isNotEmpty &&
                              !globalActive.every(
                                (r) => r.matches(task, _projects),
                              )) {
                            return false;
                          }
                          // Per-section filter rules: find which section(s) this
                          // task belongs to and apply their filters if configured.
                          for (final entry in _sectionFilterRules.entries) {
                            final sectionName = entry.key;
                            final rules = entry.value
                                .where((r) => r.isConfigured)
                                .toList();
                            if (rules.isEmpty) continue;
                            // Determine if this task's project belongs to the section
                            final pid = task.projectId;
                            bool inSection;
                            if (sectionName == 'All') {
                              inSection = true;
                            } else if (sectionName == 'Favorites') {
                              inSection = _favoriteProjectIds.contains(pid);
                            } else {
                              inSection = (_categoryMappings[sectionName] ?? {})
                                  .contains(pid);
                            }
                            if (!inSection) continue;
                            if (!rules.every(
                              (r) => r.matches(task, _projects),
                            )) {
                              return false;
                            }
                          }
                          return true;
                        })
                        .map((task) {
                          final worldPos =
                              _taskPositions[task.id] ?? Offset.zero;
                          final screenPos = (worldPos * _scale) + _canvasOffset;
                          final incoming = _taskRelations
                              .where((r) => r.targetId == task.id)
                              .toList();
                          final outgoing = _taskRelations
                              .where((r) => r.sourceId == task.id)
                              .toList();

                          final Color? pColor = _projectColors[task.projectId];
                          final double borderWidth = pColor != null ? 2.0 : 1.0;

                          final bool hasTimeStr =
                              (task.plannedAt != null && task.plannedAt! > 0) ||
                              (task.dueDay != null &&
                                  (task.dueDay!.contains('T') ||
                                      task.dueDay!.contains(' ')));

                          final double baseHeight =
                              46.0 +
                              (_showIdOnCards ? 14.0 : 0) +
                              (_showProjectName ? 14.0 : 0) +
                              (_showDueDateOnCards ? 14.0 : 0) +
                              ((_showDueDateOnCards && hasTimeStr) ? 14.0 : 0) +
                              (borderWidth * 2);

                          final double w = task.cardWidth;
                          final double h = task.isExpanded
                              ? task.cardHeight
                              : baseHeight;

                          final bool isTaskSelected =
                              _selectedCanvasTaskId == task.id ||
                              _selectedTaskIds.contains(task.id);
                          return Positioned(
                            left: screenPos.dx,
                            top: screenPos.dy,
                            child: MouseRegion(
                              onEnter: (_) =>
                                  setState(() => _hoveredTaskId = task.id),
                              onExit: (_) => setState(() {
                                if (_hoveredTaskId == task.id)
                                  _hoveredTaskId = null;
                              }),
                              child: SizedBox(
                                width: w * _scale,
                                height: h * _scale,
                                child: Stack(
                                  clipBehavior: Clip.none,
                                  children: [
                                    // Selection glow ring
                                    if (isTaskSelected)
                                      Positioned.fill(
                                        child: IgnorePointer(
                                          child: Container(
                                            decoration: BoxDecoration(
                                              borderRadius:
                                                  BorderRadius.circular(9),
                                              boxShadow: [
                                                BoxShadow(
                                                  color: Colors.white
                                                      .withOpacity(0.5),
                                                  blurRadius: 12 * _scale,
                                                  spreadRadius: 2 * _scale,
                                                ),
                                              ],
                                              border: Border.all(
                                                color: Colors.white.withOpacity(
                                                  0.8,
                                                ),
                                                width: 1.5,
                                              ),
                                            ),
                                          ),
                                        ),
                                      ),
                                    Positioned(
                                      left: 0,
                                      top: 0,
                                      width: w,
                                      height: h,
                                      child: Transform.scale(
                                        scale: _scale,
                                        alignment: Alignment.topLeft,
                                        child: Draggable<Task>(
                                          data: task,
                                          maxSimultaneousDrags:
                                              (HardwareKeyboard
                                                      .instance
                                                      .isShiftPressed ||
                                                  _isResizingCard ||
                                                  _tapDownInPlugZone)
                                              ? 0
                                              : 1,
                                          onDragStarted: () => setState(() {
                                            _tapDownInPlugZone = false;
                                            _isDraggingCard = true;
                                            _dragAnchorWorld =
                                                _taskPositions[task.id];
                                            _marqueeStart = null;
                                            _marqueeEnd = null;
                                            _isMarqueeActive = false;
                                          }),
                                          onDragEnd: (_) => setState(() {
                                            _isDraggingCard = false;
                                            _dragAnchorWorld = null;
                                          }),
                                          onDraggableCanceled: (_, __) =>
                                              setState(() {
                                                _isDraggingCard = false;
                                                _dragAnchorWorld = null;
                                              }),
                                          // The feedback is rendered in
                                          // Flutter's Overlay, which strips
                                          // all ancestor transforms — so the
                                          // parent Transform.scale(_scale) is
                                          // NOT applied to it. We must
                                          // replicate the scale here so the
                                          // ghost matches the card's on-canvas
                                          // visual size exactly.
                                          feedback: Material(
                                            color: Colors.transparent,
                                            child: SizedBox(
                                              width: w * _scale,
                                              height: h * _scale,
                                              child: OverflowBox(
                                                alignment: Alignment.topLeft,
                                                maxWidth: double.infinity,
                                                maxHeight: double.infinity,
                                                child: Transform.scale(
                                                  scale: _scale,
                                                  alignment: Alignment.topLeft,
                                                  child: _taskCardUI(
                                                    task,
                                                    isDragging: true,
                                                  ),
                                                ),
                                              ),
                                            ),
                                          ),
                                          // The default childDragAnchorStrategy
                                          // returns coords in the child's
                                          // (unscaled) layout space, which no
                                          // longer matches the feedback's
                                          // (w*_scale × h*_scale) layout.
                                          // Instead, return the cursor offset
                                          // from the card's visual top-left so
                                          // the ghost stays pinned under the
                                          // exact pixel the user grabbed.
                                          dragAnchorStrategy:
                                              (draggable, ctx, position) {
                                                final RenderBox rb =
                                                    ctx.findRenderObject()!
                                                        as RenderBox;
                                                return position -
                                                    rb.localToGlobal(
                                                      Offset.zero,
                                                    );
                                              },
                                          childWhenDragging: Opacity(
                                            opacity: 0.2,
                                            child: _taskCardUI(task),
                                          ),
                                          child: GestureDetector(
                                            // onTapDown fires immediately on
                                            // press, before the gesture arena
                                            // resolves. This guarantees
                                            // _selectedTaskIds is set even
                                            // when the Draggable wrapper wins
                                            // the arena and onTap never fires.
                                            // When the tap is inside the plug
                                            // zone (card border band) we skip
                                            // selection so connector-creation
                                            // gets full priority.
                                            onTapDown: (details) {
                                              if (_connectingSourceId != null)
                                                return;
                                              // ── Plug-zone check ──────────
                                              final lx =
                                                  details.localPosition.dx;
                                              final ly =
                                                  details.localPosition.dy;
                                              if (ly <= baseHeight) {
                                                final dL = lx;
                                                final dR = w - lx;
                                                final dT = ly;
                                                final dB = baseHeight - ly;
                                                final minD = [dL, dR, dT, dB]
                                                    .reduce(
                                                      (a, b) => a < b ? a : b,
                                                    );
                                                if (minD <=
                                                        _plugZoneThickness &&
                                                    !HardwareKeyboard
                                                        .instance
                                                        .isShiftPressed) {
                                                  // In plug zone — rebuild
                                                  // with maxSimultaneousDrags=0
                                                  // so the Draggable cannot
                                                  // win the arena and eat
                                                  // onTapUp.
                                                  setState(() {
                                                    _tapDownInPlugZone = true;
                                                  });
                                                  return;
                                                }
                                              }
                                              _tapDownInPlugZone = false;
                                              // ─────────────────────────────
                                              final ctrl = HardwareKeyboard
                                                  .instance
                                                  .isControlPressed;
                                              setState(() {
                                                _selectedRelationKey = null;
                                                _selectedRelationKeys.clear();
                                                if (ctrl) {
                                                  if (_selectedTaskIds.contains(
                                                    task.id,
                                                  )) {
                                                    _selectedTaskIds.remove(
                                                      task.id,
                                                    );
                                                  } else {
                                                    _selectedTaskIds.add(
                                                      task.id,
                                                    );
                                                    _selectedJunctionIds
                                                        .clear();
                                                    _selectedJunctionId = null;
                                                  }
                                                  _selectedCanvasTaskId =
                                                      _selectedTaskIds.length ==
                                                          1
                                                      ? _selectedTaskIds.first
                                                      : null;
                                                } else {
                                                  _selectedTaskIds = {task.id};
                                                  _selectedCanvasTaskId =
                                                      task.id;
                                                  _selectedJunctionIds.clear();
                                                  _selectedJunctionId = null;
                                                }
                                              });
                                            },
                                            onTapUp: (details) {
                                              final double localX =
                                                  details.localPosition.dx;
                                              final double localY =
                                                  details.localPosition.dy;

                                              // Plug creation is only valid within
                                              // the card's base header body.
                                              // Clicks in the expanded details region
                                              // (localY > baseHeight) are ignored.
                                              if (localY > baseHeight) return;

                                              double snapLimitY = baseHeight;

                                              double snapX = localX.clamp(
                                                0.0,
                                                w,
                                              );
                                              double snapY = localY.clamp(
                                                0.0,
                                                snapLimitY,
                                              );

                                              double dL = snapX;
                                              double dR = w - snapX;
                                              double dT = snapY;
                                              double dB = snapLimitY - snapY;

                                              double minD = [
                                                dL,
                                                dR,
                                                dT,
                                                dB,
                                              ].reduce((a, b) => a < b ? a : b);

                                              if (minD <= _plugZoneThickness &&
                                                  !HardwareKeyboard
                                                      .instance
                                                      .isShiftPressed) {
                                                if (minD == dL)
                                                  snapX = 0.0;
                                                else if (minD == dR)
                                                  snapX = w;
                                                else if (minD == dT)
                                                  snapY = 0.0;
                                                else if (minD == dB)
                                                  snapY = snapLimitY;

                                                setState(() {
                                                  _tapDownInPlugZone = false;
                                                  if (_connectingSourceId !=
                                                          null &&
                                                      _connectingSourceId !=
                                                          task.id) {
                                                    if (_canConnect(
                                                      _connectingSourceId!,
                                                      task.id,
                                                    )) {
                                                      _taskRelations.add(
                                                        TaskRelation(
                                                          arrowSize:
                                                              _defaultArrowSize,
                                                          sourceId:
                                                              _connectingSourceId!,
                                                          targetId: task.id,
                                                          sourceLocalPos:
                                                              _connectingSourceLocalPos!,
                                                          targetLocalPos:
                                                              Offset(
                                                                snapX,
                                                                snapY,
                                                              ),
                                                        ),
                                                      );
                                                      _connectingSourceId =
                                                          null;
                                                    } else {
                                                      _connectingSourceId =
                                                          null;
                                                      ScaffoldMessenger.of(
                                                        context,
                                                      ).showSnackBar(
                                                        const SnackBar(
                                                          content: Text(
                                                            'Connection blocked: Path already exists.',
                                                          ),
                                                          duration: Duration(
                                                            seconds: 2,
                                                          ),
                                                        ),
                                                      );
                                                    }
                                                  } else if (_connectingSourceId ==
                                                      null) {
                                                    _connectingSourceId =
                                                        task.id;
                                                    _connectingSourceLocalPos =
                                                        Offset(snapX, snapY);
                                                  }
                                                });
                                              }
                                            },
                                            onTap: () {
                                              // If the tap began in the plug
                                              // zone, onTapUp already handled
                                              // connector creation; don't
                                              // override that by selecting card.
                                              if (_tapDownInPlugZone) {
                                                _tapDownInPlugZone = false;
                                                return;
                                              }
                                              final ctrl = HardwareKeyboard
                                                  .instance
                                                  .isControlPressed;
                                              setState(() {
                                                // Selecting a card always
                                                // clears the line selection.
                                                _selectedRelationKey = null;
                                                _selectedRelationKeys.clear();
                                                if (ctrl) {
                                                  // Toggle this card in/out
                                                  // of the multi-selection.
                                                  if (_selectedTaskIds.contains(
                                                    task.id,
                                                  )) {
                                                    _selectedTaskIds.remove(
                                                      task.id,
                                                    );
                                                  } else {
                                                    _selectedTaskIds.add(
                                                      task.id,
                                                    );
                                                    _selectedJunctionIds
                                                        .clear();
                                                    _selectedJunctionId = null;
                                                  }
                                                  _selectedCanvasTaskId =
                                                      _selectedTaskIds.length ==
                                                          1
                                                      ? _selectedTaskIds.first
                                                      : null;
                                                } else {
                                                  _selectedTaskIds = {task.id};
                                                  _selectedCanvasTaskId =
                                                      task.id;
                                                  _selectedJunctionIds.clear();
                                                  _selectedJunctionId = null;
                                                }
                                              });
                                            },
                                            child: ClipRect(
                                              child: _taskCardUI(task),
                                            ),
                                          ),
                                        ),
                                      ),
                                    ),
                                    ...incoming.map((rel) {
                                      final relKey =
                                          '${rel.sourceId}→${rel.targetId}';
                                      final visible =
                                          _showConnectionPlugs ||
                                          _selectedCanvasTaskId == task.id ||
                                          _selectedRelationKey == relKey;
                                      if (!visible)
                                        return const SizedBox.shrink();
                                      return Positioned(
                                        left:
                                            (rel.targetLocalPos.dx * _scale) -
                                            (14 * _scale),
                                        top:
                                            (rel.targetLocalPos.dy * _scale) -
                                            (14 * _scale),
                                        child: _buildCardPlug(
                                          rel,
                                          isTarget: true,
                                          task: task,
                                        ),
                                      );
                                    }),
                                    ...outgoing.map((rel) {
                                      final relKey =
                                          '${rel.sourceId}→${rel.targetId}';
                                      final visible =
                                          _showConnectionPlugs ||
                                          _selectedCanvasTaskId == task.id ||
                                          _selectedRelationKey == relKey;
                                      if (!visible)
                                        return const SizedBox.shrink();
                                      return Positioned(
                                        left:
                                            (rel.sourceLocalPos.dx * _scale) -
                                            (14 * _scale),
                                        top:
                                            (rel.sourceLocalPos.dy * _scale) -
                                            (14 * _scale),
                                        child: _buildCardPlug(
                                          rel,
                                          isTarget: false,
                                          task: task,
                                        ),
                                      );
                                    }),
                                  ],
                                ),
                              ),
                            ), // close SizedBox (MouseRegion child)
                          );
                        }),
                  ],
                ),
              ),
            ),
          ),
        ),
      ),
    );
  }

  Widget _buildDraggablePlug(
    TaskRelation rel, {
    required bool isTarget,
    required JunctionNode junction,
  }) {
    return MouseRegion(
      cursor: SystemMouseCursors.grab,
      child: GestureDetector(
        onSecondaryTap: () => setState(() => _taskRelations.remove(rel)),
        child: SizedBox(
          width: 24 * _scale,
          height: 24 * _scale,
          child: Draggable<String>(
            data: "${rel.sourceId}_${rel.targetId}_${isTarget ? 'T' : 'S'}",
            onDragStarted: () => setState(() => _isPlugDragging = true),
            onDragEnd: (_) => setState(() => _isPlugDragging = false),
            onDraggableCanceled: (_, __) =>
                setState(() => _isPlugDragging = false),
            feedback: Container(
              width: 12 * _scale,
              height: 12 * _scale,
              decoration: BoxDecoration(
                color: Colors.white.withOpacity(0.5),
                shape: BoxShape.circle,
              ),
            ),
            onDragUpdate: (details) {
              setState(() {
                final RenderBox box =
                    _canvasKey.currentContext!.findRenderObject() as RenderBox;
                final localPos =
                    (box.globalToLocal(details.globalPosition) -
                        _canvasOffset) /
                    _scale;

                double rawY = (localPos.dy - junction.position.dy).clamp(
                  0.0,
                  junction.height,
                );
                double snappedX = _getGateX(
                  rawY,
                  junction.width,
                  junction.height,
                  junction.operatorType,
                  isTarget,
                );

                double finalY = rawY;
                if (!isTarget &&
                    (junction.operatorType == LogicalOperator.or ||
                        junction.operatorType == LogicalOperator.xor)) {
                  finalY = rawY.clamp(
                    junction.height * 0.35,
                    junction.height * 0.65,
                  );
                }

                if (isTarget) {
                  rel.targetLocalPos = Offset(snappedX, finalY);
                } else {
                  rel.sourceLocalPos = Offset(snappedX, finalY);
                }
              });
            },
            child: SizedBox(
              width: 24 * _scale,
              height: 24 * _scale,
              child: Center(
                child: Container(
                  width: 12 * _scale,
                  height: 12 * _scale,
                  decoration: BoxDecoration(
                    color: isTarget ? Colors.greenAccent : Colors.orangeAccent,
                    shape: BoxShape.circle,
                    border: Border.all(
                      color: Colors.white,
                      width: 1.5 * _scale,
                    ),
                    boxShadow: [
                      BoxShadow(color: Colors.black45, blurRadius: 2 * _scale),
                    ],
                  ),
                ),
              ),
            ),
          ),
        ),
      ),
    );
  }

  // ── Plug builder for ConditionalNode ───────────────────────────────────────
  // Input plugs snap to x=0 (left vertex); output plugs snap to x=width (right
  // vertex). The y coordinate is clamped to the node bounds.
  Widget _buildDraggablePlugForConditional(
    TaskRelation rel, {
    required bool isTarget,
    required ConditionalNode conditional,
  }) {
    return MouseRegion(
      cursor: SystemMouseCursors.grab,
      child: GestureDetector(
        onSecondaryTap: () => setState(() => _taskRelations.remove(rel)),
        child: SizedBox(
          width: 24 * _scale,
          height: 24 * _scale,
          child: Draggable<String>(
            data: "${rel.sourceId}_${rel.targetId}_${isTarget ? 'T' : 'S'}",
            onDragStarted: () => setState(() => _isPlugDragging = true),
            onDragEnd: (_) => setState(() => _isPlugDragging = false),
            onDraggableCanceled: (_, __) =>
                setState(() => _isPlugDragging = false),
            feedback: Container(
              width: 12 * _scale,
              height: 12 * _scale,
              decoration: BoxDecoration(
                color: Colors.white.withOpacity(0.5),
                shape: BoxShape.circle,
              ),
            ),
            onDragUpdate: (details) {
              setState(() {
                final RenderBox box =
                    _canvasKey.currentContext!.findRenderObject() as RenderBox;
                final localPos =
                    (box.globalToLocal(details.globalPosition) -
                        _canvasOffset) /
                    _scale;
                final insideCard = localPos - conditional.position;
                final snapped = _snapToConditionalBorder(
                  insideCard,
                  conditional.width,
                  conditional.height,
                  isInput: isTarget,
                );
                if (isTarget) {
                  rel.targetLocalPos = snapped;
                } else {
                  rel.sourceLocalPos = snapped;
                }
              });
            },
            child: SizedBox(
              width: 24 * _scale,
              height: 24 * _scale,
              child: Center(
                child: Container(
                  width: 12 * _scale,
                  height: 12 * _scale,
                  decoration: BoxDecoration(
                    color: isTarget ? Colors.greenAccent : Colors.amberAccent,
                    shape: BoxShape.circle,
                    border: Border.all(
                      color: Colors.white,
                      width: 1.5 * _scale,
                    ),
                    boxShadow: [
                      BoxShadow(color: Colors.black45, blurRadius: 2 * _scale),
                    ],
                  ),
                ),
              ),
            ),
          ),
        ),
      ),
    );
  }

  Widget _buildCardPlug(
    TaskRelation rel, {
    required bool isTarget,
    required Task task,
  }) {
    return MouseRegion(
      cursor: SystemMouseCursors.allScroll,
      child: GestureDetector(
        onSecondaryTap: () => setState(() => _taskRelations.remove(rel)),
        // Expanded hit area: the visible dot is 12px but we give 28px to grab
        child: SizedBox(
          width: 28 * _scale,
          height: 28 * _scale,
          child: Draggable<String>(
            data: "${rel.sourceId}_${rel.targetId}_${isTarget ? 'T' : 'S'}",
            onDragStarted: () => setState(() => _isPlugDragging = true),
            onDragEnd: (_) => setState(() => _isPlugDragging = false),
            onDraggableCanceled: (_, __) =>
                setState(() => _isPlugDragging = false),
            feedback: Container(
              width: 12 * _scale,
              height: 12 * _scale,
              decoration: BoxDecoration(
                color: (isTarget ? Colors.greenAccent : Colors.orangeAccent)
                    .withOpacity(0.5),
                shape: BoxShape.circle,
              ),
            ),
            onDragUpdate: (details) {
              setState(() {
                final RenderBox box =
                    _canvasKey.currentContext!.findRenderObject() as RenderBox;
                final localPos =
                    (box.globalToLocal(details.globalPosition) -
                        _canvasOffset) /
                    _scale;

                final worldPos = _taskPositions[task.id] ?? Offset.zero;
                final localInsideCard = localPos - worldPos;

                final Color? pColor = _projectColors[task.projectId];
                final double borderWidth = pColor != null ? 2.0 : 1.0;

                final bool hasTimeStr =
                    (task.plannedAt != null && task.plannedAt! > 0) ||
                    (task.dueDay != null &&
                        (task.dueDay!.contains('T') ||
                            task.dueDay!.contains(' ')));

                double w = task.cardWidth;
                double h = task.isExpanded
                    ? task.cardHeight
                    : (46.0 +
                          (_showIdOnCards ? 14.0 : 0) +
                          (_showProjectName ? 14.0 : 0) +
                          (_showDueDateOnCards ? 14.0 : 0) +
                          ((_showDueDateOnCards && hasTimeStr) ? 14.0 : 0) +
                          (borderWidth * 2));

                double snapX = localInsideCard.dx.clamp(0.0, w);
                double snapY = localInsideCard.dy.clamp(0.0, h);

                double dL = snapX;
                double dR = w - snapX;
                double dT = snapY;
                double dB = h - snapY;

                double minD = [dL, dR, dT, dB].reduce(min);

                if (minD == dL)
                  snapX = 0;
                else if (minD == dR)
                  snapX = w;
                else if (minD == dT)
                  snapY = 0;
                else
                  snapY = h;

                if (isTarget) {
                  rel.targetLocalPos = Offset(snapX, snapY);
                } else {
                  rel.sourceLocalPos = Offset(snapX, snapY);
                }
              });
            },
            child: SizedBox(
              width: 28 * _scale,
              height: 28 * _scale,
              child: Center(
                child: Container(
                  width: 12 * _scale,
                  height: 12 * _scale,
                  decoration: BoxDecoration(
                    color: isTarget ? Colors.greenAccent : Colors.orangeAccent,
                    shape: BoxShape.circle,
                    border: Border.all(color: Colors.white, width: 1 * _scale),
                  ),
                ),
              ),
            ),
          ),
        ),
      ),
    );
  }

  Widget _buildCanvasCard(Task task) {
    final basePos = _taskPositions[task.id] ?? Offset.zero;
    final pannedPos = basePos + _canvasOffset;

    return Positioned(
      left: pannedPos.dx,
      top: pannedPos.dy,
      child: Draggable<Task>(
        data: task,
        dragAnchorStrategy: childDragAnchorStrategy,
        feedback: _taskCardUI(task, isDragging: true),
        childWhenDragging: Opacity(opacity: 0.2, child: _taskCardUI(task)),
        child: _taskCardUI(task),
      ),
    );
  }

  Widget _buildPanToggleButton() {
    final Color bg = _isMiddleMousePanning
        ? Colors.orangeAccent
        : _isPanMode
        ? Colors.blueAccent
        : Colors.grey[800]!;
    return Positioned(
      bottom: 30,
      left: (_isVisible ? _sidebarWidth : 0) + 20,
      child: FloatingActionButton.extended(
        backgroundColor: bg,
        onPressed: () => setState(() => _isPanMode = !_isPanMode),
        label: Text(
          _isMiddleMousePanning
              ? "Panning Mode (MMB)"
              : _isPanMode
              ? "Panning Mode: ON"
              : "Move Items Mode",
        ),
        icon: Icon(
          (_isPanMode || _isMiddleMousePanning) ? Icons.pan_tool : Icons.mouse,
        ),
      ),
    );
  }

  // --- NEW RIGHT-SIDE BAR DESIGN ---

  Widget _buildRightEdgeBar() {
    return Positioned(
      right: 0,
      top: 0,
      bottom: 0,
      child: GestureDetector(
        onVerticalDragUpdate: (details) {
          setState(() {
            // Dragging down on the bar moves the camera "up" (canvas moves down)
            _canvasOffset = Offset(
              _canvasOffset.dx,
              _canvasOffset.dy - details.delta.dy * 2.5,
            );
          });
        },
        child: Container(
          width: 16,
          decoration: BoxDecoration(
            color: const Color(0xFF1E1E1E),
            border: Border(
              left: BorderSide(color: Colors.white.withOpacity(0.05)),
            ),
          ),
          child: Stack(
            alignment: Alignment.center,
            children: [
              // Vertical Track Line
              Container(width: 1, color: Colors.white10),
