                  child: _currentCategoriesGroupName.isEmpty
                      ? const Text(
                          'No Category Group',
                          style: TextStyle(
                            color: Colors.white24,
                            fontSize: 11,
                            fontWeight: FontWeight.bold,
                            letterSpacing: 0.5,
                          ),
                        )
                      : TextField(
                          controller: _categoriesGroupNameController,
                          style: const TextStyle(
                            color: Colors.white,
                            fontSize: 11,
                            fontWeight: FontWeight.bold,
                            letterSpacing: 0.5,
                          ),
                          decoration: const InputDecoration(
                            isDense: true,
                            contentPadding: EdgeInsets.symmetric(vertical: 4),
                            border: InputBorder.none,
                          ),
                          onChanged: (val) {
                            if (val.trim().isEmpty) return;
                            setState(() {
                              final oldName = _currentCategoriesGroupName;
                              _currentCategoriesGroupName = val;
                              // Rename the key in the groups map
                              if (_categoriesGroups.containsKey(oldName)) {
                                _categoriesGroups[val] = _categoriesGroups
                                    .remove(oldName)!;
                              }
                            });
                          },
                        ),
                ),
                GestureDetector(
                  onTap: _showSwitchCategoriesGroupDialog,
                  child: const Padding(
                    padding: EdgeInsets.all(4),
                    child: Icon(
                      Icons.swap_horiz_rounded,
                      size: 18,
                      color: Colors.white38,
                    ),
                  ),
                ),
              ],
            ),
          ),
          // ── Current Canvas Row ──────────────────────────────────────────
          Container(
            padding: const EdgeInsets.symmetric(horizontal: 12, vertical: 6),
            decoration: const BoxDecoration(color: Color(0xFF252525)),
            child: Row(
              children: [
                Icon(
                  Icons.layers_outlined,
                  size: 16,
                  color: _currentCanvasName.isEmpty
                      ? Colors.white24
                      : Colors.tealAccent,
                ),
                const SizedBox(width: 10),
                Expanded(
                  child: _currentCanvasName.isEmpty
                      ? const Text(
                          'No Canvas',
                          style: TextStyle(
                            color: Colors.white24,
                            fontSize: 11,
                            fontWeight: FontWeight.bold,
                            letterSpacing: 0.5,
                          ),
                        )
                      : TextField(
                          controller: _canvasNameController,
                          style: const TextStyle(
                            color: Colors.white,
                            fontSize: 11,
                            fontWeight: FontWeight.bold,
                            letterSpacing: 0.5,
                          ),
                          decoration: const InputDecoration(
                            isDense: true,
                            contentPadding: EdgeInsets.symmetric(vertical: 4),
                            border: InputBorder.none,
                          ),
                          onChanged: (val) {
                            setState(() {
                              if (val.trim().isEmpty) return;

                              String oldName = _currentCanvasName;
                              _currentCanvasName = val;

                              // 1. Update list for the selector
                              int idx = _savedCanvases.indexWhere(
                                (c) => c['name'] == oldName,
                              );
                              if (idx != -1) {
                                _savedCanvases[idx]['name'] = val;
                              } else {
                                _savedCanvases.add({'name': val});
                              }

                              // 2. Transfer saved states map key so we don't lose the canvas info
                              if (_canvasStates.containsKey(oldName)) {
                                _canvasStates[val] = _canvasStates.remove(
                                  oldName,
                                )!;
                              }
                            });
                          },
                        ),
                ),
                GestureDetector(
                  onTap: _showSwitchCanvasDialog,
                  child: const Icon(
                    Icons.swap_horiz_rounded,
                    size: 18,
                    color: Colors.white38,
                  ),
                ),
              ],
            ),
          ),
        ],
      ),
    );
