  // NOTES TAB
  // ══════════════════════════════════════════════════════════════════════════

  static const Color _notesBg = Color(0xFF2E3440); // Nord base
  static const Color _notesSurface = Color(0xFF3B4252); // Nord base1
  static const Color _notesBorder = Color(0xFF3B4252); // Nord divider
  static const Color _notesAccent = Color(0xFF88C0D0); // Nord cyan

  // ── Sync helpers ──────────────────────────────────────────────────────────

  /// Ensures every task and project has a matching Note entry. Call whenever
  /// tasks or projects change and after loading data.
  // ══════════════════════════════════════════════════════════════════════════
  // NOTES  –  File I/O
  // ══════════════════════════════════════════════════════════════════════════

  /// Loads all .md files from the notes directory and rebuilds _notes.
  /// Must be called after a workspace is opened.
  Future<void> _loadNotes() async {
    if (_workspaceId.isEmpty) return;
    try {
      final dir = Directory(_notesDir);
      if (!await dir.exists()) return;

      // Read sidecar for metadata not stored in the .md content.
      // Supports both old flat format (Map<path, meta>) and new nested format
      // with 'notes' and 'folders' keys.
      final Map<String, dynamic> meta = {};
      final metaFile = File(_notesMetaPath);
      if (await metaFile.exists()) {
        try {
          final decoded =
              jsonDecode(await metaFile.readAsString()) as Map<String, dynamic>;
          if (decoded.containsKey('notes')) {
            // New nested format
            meta.addAll(decoded['notes'] as Map<String, dynamic>);
            // Load folders
            final foldersRaw = decoded['folders'] as List<dynamic>? ?? [];
            for (final f in foldersRaw) {
              final fm = f as Map<String, dynamic>;
              final fid = fm['id'] as String;
              _noteFolders[fid] = NoteFolder(
                id: fid,
                name: fm['name'] as String? ?? '',
              );
            }
            // Load folder order (Notes section — independent of projectFolderOrder)
            if (decoded['folderOrder'] != null) {
              _noteFolderOrder = List<String>.from(
                decoded['folderOrder'] as List,
              );
            }
          } else {
            // Old flat format — all keys are note paths
            meta.addAll(decoded);
          }
        } catch (_) {}
      }

      final newNotes = <String, Note>{};

      await for (final entity in dir.list(recursive: true)) {
        if (entity is! File) continue;
        if (!entity.path.endsWith('.md')) continue;

        final relativePath = entity.path.substring(_notesDir.length + 1);
        final parts = relativePath.split(Platform.pathSeparator);
        if (parts.length < 2) continue;

        final subdir = parts[0]; // tasks / projects / notes
        NoteType type;
        switch (subdir) {
          case 'tasks':
            type = NoteType.task;
            break;
          case 'projects':
            type = NoteType.project;
            break;
          default:
            type = NoteType.common;
            break;
        }

        final rawContent = await entity.readAsString();
        // Spec §3-4: title is derived strictly from the filename (stripping
        // the .md extension). The file body is the full raw content — no
        // "# Title" header line is expected or consumed.
        // Legacy guard: if an old file still starts with a "# Title" header
        // (written by a previous version of the app), strip it transparently
        // so the editor never shows a duplicate title in the document body.
        String body = rawContent;
        final firstNewline = rawContent.indexOf('\n');
        if (firstNewline > 0) {
          final firstLine = rawContent.substring(0, firstNewline);
          if (firstLine.startsWith('# ')) {
            // Old-format file: drop the header line and the blank line that
            // followed it (if present) so the content area is clean.
            body = rawContent
                .substring(firstNewline + 1)
                .replaceFirst(RegExp(r'^\n'), '');
          }
        } else if (rawContent.startsWith('# ') && firstNewline < 0) {
          // Edge case: entire file is just "# Title" with no newline.
          body = '';
        }
        // Title always comes from the filename, never from file content.
        final String title = parts.last
            .replaceAll('.md', '')
            // For task notes the filename is "[Task] - [Project] (date).md";
            // strip everything after " - " to recover the bare task name that
            // was used as the Note.title when the file was written.
            // For common and project notes the filename IS the title.
            .split(' - ')
            .first
            .trim();

        // Retrieve sidecar metadata by path key
        final key = relativePath.replaceAll('\\', '/');
        final sideMeta = meta[key] as Map<String, dynamic>? ?? {};
        final noteId =
            sideMeta['id'] as String? ??
            '${subdir}:${DateTime.now().millisecondsSinceEpoch}';
        final linkedTask = sideMeta['linkedTaskId'] as String?;
        final linkedProject = sideMeta['linkedProjectId'] as String?;
        final updatedAt = sideMeta['updatedAt'] != null
            ? DateTime.fromMillisecondsSinceEpoch(sideMeta['updatedAt'] as int)
            : (await entity.stat()).modified;

        final folderId = sideMeta['folderId'] as String?;
        final collapsedHeadings = sideMeta['collapsedHeadings'] != null
            ? List<String>.from(sideMeta['collapsedHeadings'] as List)
            : <String>[];
        newNotes[noteId] = Note(
          id: noteId,
          type: type,
          title: title,
          content: body,
          linkedTaskId: linkedTask,
          linkedProjectId: linkedProject,
          updatedAt: updatedAt,
          folderId: folderId,
          collapsedHeadings: collapsedHeadings,
        );
      }

      setState(() => _notes.addAll(newNotes));
    } catch (e, st) {
      debugPrint('_loadNotes ERROR: $e\n$st');
    }
  }

  /// Writes a note to its .md file and updates notes_meta.json.
  Future<void> _saveNote(Note note) async {
    if (_workspaceId.isEmpty) return;
    try {
      // ── Write .md file ──────────────────────────────────────────────────
      final filePath = _noteFilePath(note);
      final file = File(filePath);
      await file.parent.create(recursive: true);

      // Spec §1-2: write body only — title lives exclusively in the filename
      // and in notes_meta.json. No "# Title" header is injected so the file
      // content starts immediately with the user's text.
      await file.writeAsString(note.content);

      // ── Update sidecar ──────────────────────────────────────────────────
      await _saveNotesMeta();
    } catch (e) {
      debugPrint('_saveNote ERROR: $e');
    }
  }

  /// Removes a note's .md file and cleans up notes_meta.json.
  Future<void> _deleteNoteFile(Note note) async {
    if (_workspaceId.isEmpty) return;
    try {
      final file = File(_noteFilePath(note));
      if (await file.exists()) await file.delete();
      await _saveNotesMeta();
    } catch (e) {
      debugPrint('_deleteNoteFile ERROR: $e');
    }
  }

  /// Serialises the full _notes map and folder list into notes_meta.json.
  Future<void> _saveNotesMeta() async {
    try {
      final metaFile = File(_notesMetaPath);
      await metaFile.parent.create(recursive: true);

      final notesMap = <String, dynamic>{};
      for (final note in _notes.values) {
        final relativePath = _noteFilePath(
          note,
        ).substring(_notesDir.length + 1).replaceAll('\\', '/');
        notesMap[relativePath] = {
          'id': note.id,
          'type': note.type.name,
          'linkedTaskId': note.linkedTaskId,
          'linkedProjectId': note.linkedProjectId,
          'updatedAt': note.updatedAt.millisecondsSinceEpoch,
          if (note.folderId != null) 'folderId': note.folderId,
          if (note.collapsedHeadings.isNotEmpty)
            'collapsedHeadings': note.collapsedHeadings,
        };
      }

      final foldersJson = _noteFolders.values
          .map((f) => {'id': f.id, 'name': f.name})
          .toList();

      await metaFile.writeAsString(
        const JsonEncoder.withIndent('  ').convert({
          'notes': notesMap,
          'folders': foldersJson,
          'folderOrder': _noteFolderOrder,
        }),
      );
    } catch (e) {
      debugPrint('_saveNotesMeta ERROR: $e');
    }
  }

  void _syncNotes() {
    // Task notes — title always mirrors task title; content is the .md body.
    for (final t in _allTasks) {
      final noteId = 'task:${t.id}';
      if (_notes.containsKey(noteId)) {
        // Keep title in sync with task name; content was loaded from .md
        final prev = _notes[noteId]!;
        if (prev.title != t.title) {
          prev.title = t.title;
          _saveNote(prev); // rename .md if title changed
        }
      } else {
        final note = Note(
          id: noteId,
          type: NoteType.task,
          title: t.title,
          content: t.notes ?? '',
          linkedTaskId: t.id,
        );
        _notes[noteId] = note;
        _saveNote(note); // create the .md file for new tasks
      }
    }
    // Remove task notes for deleted tasks
    final deleted = _notes.entries
        .where(
          (e) =>
              e.value.type == NoteType.task &&
              !_allTasks.any((t) => 'task:${t.id}' == e.key),
        )
        .toList();
    for (final e in deleted) {
      _deleteNoteFile(e.value);
      _notes.remove(e.key);
    }

    // Project notes
    for (final entry in _projects.entries) {
      final noteId = 'proj:${entry.key}';
      if (_notes.containsKey(noteId)) {
        final prev = _notes[noteId]!;
        if (prev.title != entry.value.title) {
          prev.title = entry.value.title;
          _saveNote(prev);
        }
      } else {
        final note = Note(
          id: noteId,
          type: NoteType.project,
          title: entry.value.title,
          content: '',
          linkedProjectId: entry.key,
        );
        _notes[noteId] = note;
        _saveNote(note);
      }
    }
    final deletedProj = _notes.entries
        .where(
          (e) =>
              e.value.type == NoteType.project &&
              !_projects.containsKey(e.value.linkedProjectId),
        )
        .toList();
    for (final e in deletedProj) {
      _deleteNoteFile(e.value);
      _notes.remove(e.key);
    }
  }

  // ── Title bar ─────────────────────────────────────────────────────────────

  Widget _buildNotesTitleBar() {
    // ── Org sub-page title bar ────────────────────────────────────────────
    if (_notesNavSection == 'notes_org_notes') {
      return Row(
        children: [
          const SizedBox(width: 14),
          const Icon(Icons.folder_outlined, size: 14, color: Color(0xFF88C0D0)),
          const SizedBox(width: 8),
          const Expanded(
            child: Text(
              'Notes Folders',
              style: TextStyle(
                fontSize: 12,
                color: Color(0xFF8896AC),
                fontWeight: FontWeight.w500,
              ),
            ),
          ),
          TextButton.icon(
            onPressed: () => setState(() => _notesNavSection = 'editor'),
            icon: const Icon(
              Icons.arrow_back_rounded,
              size: 13,
              color: Colors.white54,
            ),
            label: const Text(
              'Back',
              style: TextStyle(color: Colors.white54, fontSize: 12),
            ),
          ),
          const SizedBox(width: 8),
        ],
      );
    }

    if (_notesNavSection == 'org_projects') {
      return Row(
        children: [
          InkWell(
            onTap: () => setState(() => _notesNavSection = 'editor'),
            borderRadius: BorderRadius.circular(4),
            child: const Padding(
              padding: EdgeInsets.symmetric(horizontal: 8, vertical: 4),
              child: Icon(
                Icons.arrow_back_rounded,
                size: 15,
                color: Colors.white54,
              ),
            ),
          ),
          const SizedBox(width: 4),
          const Icon(Icons.settings_outlined, size: 14, color: Colors.white38),
          const SizedBox(width: 8),
          const Text(
            'Projects Settings',
            style: TextStyle(
              fontSize: 14,
              fontWeight: FontWeight.w600,
              color: Colors.white,
            ),
          ),
          const Spacer(),
        ],
      );
    }

    if (_notesNavSection == 'org_tasks') {
      return Row(
        children: [
          InkWell(
            onTap: () => setState(() => _notesNavSection = 'editor'),
            borderRadius: BorderRadius.circular(4),
            child: const Padding(
              padding: EdgeInsets.symmetric(horizontal: 8, vertical: 4),
              child: Icon(
                Icons.arrow_back_rounded,
                size: 15,
                color: Colors.white54,
              ),
            ),
          ),
          const SizedBox(width: 4),
          const Icon(Icons.settings_outlined, size: 14, color: Colors.white38),
          const SizedBox(width: 8),
          const Text(
            'Tasks Settings',
            style: TextStyle(
              fontSize: 14,
              fontWeight: FontWeight.w600,
              color: Colors.white,
            ),
          ),
          const Spacer(),
        ],
      );
    }

    final note = _activeNoteId != null ? _notes[_activeNoteId] : null;
    Color typeColor = const Color(0xFF88C0D0);
    if (note != null) {
      switch (note.type) {
        case NoteType.task:
          typeColor = const Color(0xFFA3BE8C);
          break;
        case NoteType.project:
          typeColor = const Color(0xFFEBCB8B);
          break;
        case NoteType.common:
          typeColor = const Color(0xFF88C0D0);
          break;
      }
    }

    // Detail panel toggle — only enabled for task/project notes
    final canShowDetail =
        note != null &&
        (note.type == NoteType.task || note.type == NoteType.project);

    // ── Tab bar ──────────────────────────────────────────────────────────────
    Widget tabBar = const SizedBox.shrink();
    if (_openNoteTabs.isNotEmpty) {
      tabBar = SizedBox(
        height: double.infinity,
        // 9g: ReorderableListView enables drag-to-reorder tabs horizontally.
        child: ReorderableListView.builder(
          scrollDirection: Axis.horizontal,
          shrinkWrap: true,
          buildDefaultDragHandles: false,
          onReorder: (oldIdx, newIdx) {
            setState(() {
              if (newIdx > oldIdx) newIdx--;
              final tab = _openNoteTabs.removeAt(oldIdx);
              _openNoteTabs.insert(newIdx, tab);
            });
          },
          itemCount: _openNoteTabs.length,
          itemBuilder: (_, i) {
            final tid = _openNoteTabs[i];
            final tn = _notes[tid];
            final isActive = tid == _activeNoteId;
            return ReorderableDragStartListener(
              key: ValueKey(tid),
              index: i,
              child: GestureDetector(
                onTap: () => setState(() => _activeNoteId = tid),
                child: AnimatedContainer(
                  duration: const Duration(milliseconds: 120),
                  constraints: const BoxConstraints(maxWidth: 160),
                  margin: const EdgeInsets.only(right: 1),
                  padding: const EdgeInsets.symmetric(horizontal: 10),
                  decoration: BoxDecoration(
                    color: isActive
                        ? const Color(0xFF1E2124)
                        : const Color(0xFF161819),
                    border: Border(
                      bottom: BorderSide(
                        color: isActive
                            ? const Color(0xFF4FC3F7)
                            : Colors.transparent,
                        width: 2,
                      ),
                    ),
                  ),
                  child: Row(
                    mainAxisSize: MainAxisSize.min,
                    children: [
                      Flexible(
                        child: Text(
                          tn?.title ?? 'Note',
                          maxLines: 1,
                          overflow: TextOverflow.ellipsis,
                          style: TextStyle(
                            fontSize: 11,
                            color: isActive
                                ? const Color(0xFFECEFF4)
                                : const Color(0xFF6B7080),
                            fontWeight: isActive
                                ? FontWeight.w600
                                : FontWeight.normal,
                          ),
                        ),
                      ),
                      const SizedBox(width: 6),
                      GestureDetector(
                        onTap: () => setState(() {
                          _openNoteTabs.removeAt(i);
                          if (_activeNoteId == tid) {
                            _activeNoteId = _openNoteTabs.isEmpty
                                ? null
                                : _openNoteTabs.last;
                          }
                        }),
                        child: const Icon(
                          Icons.close_rounded,
                          size: 12,
                          color: Color(0xFF4A4F58),
                        ),
                      ),
                    ],
                  ),
                ),
              ),
            );
          },
        ),
      );
    }

    return Row(
      children: [
        const SizedBox(width: 14),
        const Icon(Icons.article_outlined, size: 15, color: Color(0xFF8896AC)),
        const SizedBox(width: 8),
        // Tab bar expands in the middle
        Expanded(child: tabBar),
        if (note != null) ...[
          const SizedBox(width: 8),
          Container(
            padding: const EdgeInsets.symmetric(horizontal: 6, vertical: 2),
            decoration: BoxDecoration(
              color: typeColor.withOpacity(0.12),
              borderRadius: BorderRadius.circular(4),
              border: Border.all(color: typeColor.withOpacity(0.3)),
            ),
            child: Text(
              note.type == NoteType.task
                  ? 'Task'
                  : note.type == NoteType.project
                  ? 'Project'
                  : 'Note',
              style: TextStyle(
                fontSize: 9,
                fontWeight: FontWeight.w600,
                color: typeColor,
                letterSpacing: 0.5,
              ),
            ),
          ),
          const SizedBox(width: 6),
        ],
        // Details panel toggle button
        Tooltip(
          message: canShowDetail
              ? (_notesDetailOpen ? 'Hide details' : 'Show details')
              : 'No details for this note type',
          child: Opacity(
            opacity: canShowDetail ? 1.0 : 0.3,
            child: InkWell(
              onTap: canShowDetail
                  ? () {
                      if (note.type == NoteType.task &&
                          note.linkedTaskId != null) {
                        try {
                          final task = _allTasks.firstWhere(
                            (t) => t.id == note.linkedTaskId,
                          );
                          setState(() {
                            _notesDetailOpen = !_notesDetailOpen;
                            _taskListDetailTask = task;
                            _taskListDetailOpen = _notesDetailOpen;
                            // 9h fix: drive the shared right-sidebar so
                            // TaskDetailsPanel actually appears.
                            _selectedTask = _notesDetailOpen
                                ? task
                                : _selectedTask;
                            _showDetails = _notesDetailOpen;
                          });
                        } catch (_) {}
                      } else {
                        setState(() => _notesDetailOpen = !_notesDetailOpen);
                      }
                    }
                  : null,
              borderRadius: BorderRadius.circular(4),
              child: Container(
                width: 26,
                height: 26,
                decoration: BoxDecoration(
                  color: _notesDetailOpen
                      ? const Color(0xFF4FC3F7).withOpacity(0.15)
                      : Colors.transparent,
                  borderRadius: BorderRadius.circular(4),
                  border: Border.all(
                    color: _notesDetailOpen
                        ? const Color(0xFF4FC3F7).withOpacity(0.4)
                        : Colors.transparent,
                  ),
                ),
                child: Icon(
                  Icons.info_outline_rounded,
                  size: 14,
                  color: _notesDetailOpen
                      ? const Color(0xFF4FC3F7)
                      : const Color(0xFF6B7080),
                ),
              ),
            ),
          ),
        ),
        const SizedBox(width: 8),
      ],
    );
  }

  // ── Sidebar nav content ───────────────────────────────────────────────────

  Widget _buildNotesNavContent() {
    _syncNotes();

    final taskNotes =
        _notes.values.where((n) => n.type == NoteType.task).toList()
          ..sort((a, b) => a.title.compareTo(b.title));
    final projectNotes =
        _notes.values.where((n) => n.type == NoteType.project).toList()
          ..sort((a, b) => a.title.compareTo(b.title));
    final commonNotes =
        _notes.values.where((n) => n.type == NoteType.common).toList()
          ..sort((a, b) => b.updatedAt.compareTo(a.updatedAt));

    return _NotesSidebar(
      taskNotes: taskNotes,
      projectNotes: projectNotes,
      commonNotes: commonNotes,
      activeNoteId: _activeNoteId,
      allTasks: _allTasks,
      noteFolders: _noteFolders,
      filterRules: List<FilterRule>.from(_filterRules),
      sortCriteria: List<SortCriterion>.from(_sortCriteria),
      onSelectNote: (id) => setState(() {
        _activeNoteId = id;
        if (!_openNoteTabs.contains(id)) _openNoteTabs.add(id);
      }),
      onNewNote: () async {
        // Spec §4: find the next available "Untitled [N]" title.
        // Checks both in-memory notes (title collision) and the filesystem
        // (file collision) so renaming an old Untitled note doesn't block
        // creation of a new one.
        String candidateTitle = 'Untitled';
        int counter = 0;
        while (true) {
          final titleUsed = _notes.values.any(
            (n) => n.title == candidateTitle && n.type == NoteType.common,
          );
          final candidateNote = Note(
            id: 'tmp',
            type: NoteType.common,
            title: candidateTitle,
          );
          final filePath = _noteFilePath(candidateNote);
          final fileUsed = File(filePath).existsSync();
          if (!titleUsed && !fileUsed) break;
          counter++;
          candidateTitle = 'Untitled $counter';
        }
        final id = 'common:${DateTime.now().millisecondsSinceEpoch}';
        final note = Note(
          id: id,
          type: NoteType.common,
          title: candidateTitle,
          content: '',
        );
        _saveNote(note);
        setState(() {
          _notes[id] = note;
          _activeNoteId = id;
        });
      },
      onCreateFolder: (name) async {
        final fid = 'folder:${DateTime.now().millisecondsSinceEpoch}';
        setState(() => _noteFolders[fid] = NoteFolder(id: fid, name: name));
        // Feature 12: create the corresponding directory on disk
        try {
          final folderDir = Directory('$_notesDir/notes/$name');
          if (!await folderDir.exists()) {
            await folderDir.create(recursive: true);
          }
        } catch (e) {
          debugPrint('onCreateFolder mkdir error: $e');
        }
        _saveNotesMeta();
      },
      onAssignFolder: (noteId, folderId) async {
        final note = _notes[noteId];
        if (note == null) return;
        // Capture the old path before mutating folderId.
        final oldPath = _noteFilePath(note);
        setState(() => note.folderId = folderId);
        // Physically move the .md file into the target folder's directory.
        if (note.type == NoteType.common) {
          final targetFolder = folderId != null ? _noteFolders[folderId] : null;
          try {
            final src = File(oldPath);
            final fileName = src.uri.pathSegments.last;
            final destDir = targetFolder != null
                ? '$_notesDir/notes/${targetFolder.name}'
                : '$_notesDir/notes';
            final destPath = '$destDir/$fileName';
            if (await src.exists() && oldPath != destPath) {
              // Ensure destination directory exists.
              await Directory(destDir).create(recursive: true);
              await src.rename(destPath);
            }
          } catch (e) {
            debugPrint('onAssignFolder file move error: $e');
          }
        }
        _saveNote(note);
      },
      onRenameFolder: (folderId, newName) async {
        final oldFolder = _noteFolders[folderId];
        final oldName = oldFolder?.name ?? '';
        setState(() => _noteFolders[folderId]?.name = newName);
        // 9d: rename the backing directory on disk
        if (oldName.isNotEmpty && newName.isNotEmpty && oldName != newName) {
          try {
            final oldDir = Directory('$_notesDir/notes/$oldName');
            final newDir = Directory('$_notesDir/notes/$newName');
            if (await oldDir.exists()) await oldDir.rename(newDir.path);
          } catch (e) {
            debugPrint('onRenameFolder rename dir error: $e');
          }
        }
        _saveNotesMeta();
      },
      onDeleteFolder: (folderId) async {
        final folder = _noteFolders[folderId];
        final folderName = folder?.name ?? '';
        setState(() {
          _noteFolders.remove(folderId);
          for (final n in _notes.values) {
            if (n.folderId == folderId) n.folderId = null;
          }
        });
        // 9d: move contained files back to the root notes dir, then delete dir.
        if (folderName.isNotEmpty) {
          try {
            final folderDir = Directory('$_notesDir/notes/$folderName');
            final rootNotesDir = Directory('$_notesDir/notes');
            if (await folderDir.exists()) {
              await for (final entity in folderDir.list()) {
                if (entity is File) {
                  final dest =
                      '${rootNotesDir.path}/${entity.uri.pathSegments.last}';
                  await entity.copy(dest);
                  await entity.delete();
                }
              }
              await folderDir.delete();
            }
          } catch (e) {
            debugPrint('onDeleteFolder rmdir error: $e');
          }
        }
        _saveNotesMeta();
      },
      onFilterGroupSort: (scope) => setState(() {
        _filterSidebarTitle = scope;
        _filterSidebarOpen = true;
      }),

      tagColors: _tagColors,
      onNoteTaskAction: (action, task, ctx) async {
        final now = DateTime.now();
        final today = DateTime(now.year, now.month, now.day);

        if (action.startsWith('tag_toggle:')) {
          final tagId = action.split(':').last;
          setState(() {
            if (task.tagIds.contains(tagId))
              task.tagIds.remove(tagId);
            else
              task.tagIds.add(tagId);
          });
          _saveTaskToMeta(task);
          return;
        }
        if (action.startsWith('move:')) {
          final projId = action.split(':').last;
          final moved = Task(
            id: task.id,
            title: task.title,
            isDone: task.isDone,
            status: task.status,
            projectId: projId,
            subTaskIds: task.subTaskIds,
            timeSpent: task.timeSpent,
            dueDay: task.dueDay,
            durationMinutes: task.durationMinutes,
            attachments: task.attachments,
            tagIds: task.tagIds,
            notes: task.notes,
          );
          setState(() {
            final idx = _allTasks.indexOf(task);
            if (idx >= 0) _allTasks[idx] = moved;
          });
          _saveTaskToMeta(moved);
          return;
        }

        switch (action) {
          case 'sched_today':
            setState(
              () => task.dueDay = today.toIso8601String().split('T').first,
            );
            _saveTaskToMeta(task);
            break;
          case 'sched_tomorrow':
            final tmr = today.add(const Duration(days: 1));
            setState(
              () => task.dueDay = tmr.toIso8601String().split('T').first,
            );
            _saveTaskToMeta(task);
            break;
          case 'sched_nextweek':
            final nw = today.add(Duration(days: 8 - today.weekday));
            setState(() => task.dueDay = nw.toIso8601String().split('T').first);
            _saveTaskToMeta(task);
            break;
          case 'sched_reschedule':
            final pickedDate = await showDatePicker(
              context: ctx,
              initialDate: task.dueDay != null
                  ? (DateTime.tryParse(task.dueDay!) ?? today)
                  : today,
              firstDate: today,
              lastDate: today.add(const Duration(days: 365 * 5)),
              builder: (c, child) => Theme(
                data: Theme.of(c).copyWith(
                  colorScheme: const ColorScheme.dark(
                    primary: Color(0xFF4FC3F7),
                    surface: Color(0xFF1E2124),
                  ),
                ),
                child: child!,
              ),
            );
            if (pickedDate != null && mounted) {
              final pickedTime = await showTimePicker(
                context: ctx,
                initialTime: task.plannedAt != null
                    ? TimeOfDay.fromDateTime(
                        DateTime.fromMillisecondsSinceEpoch(task.plannedAt!),
                      )
                    : TimeOfDay.now(),
                builder: (c, child) => Theme(
                  data: Theme.of(c).copyWith(
                    colorScheme: const ColorScheme.dark(
                      primary: Color(0xFF4FC3F7),
                      surface: Color(0xFF1E2124),
                    ),
                    timePickerTheme: const TimePickerThemeData(
                      backgroundColor: Color(0xFF1E2124),
                    ),
                  ),
                  child: child!,
                ),
              );
              setState(() {
                task.dueDay = pickedDate.toIso8601String().split('T').first;
                if (pickedTime != null) {
                  task.plannedAt = DateTime(
                    pickedDate.year,
                    pickedDate.month,
                    pickedDate.day,
                    pickedTime.hour,
                    pickedTime.minute,
                  ).millisecondsSinceEpoch;
                }
              });
              _saveTaskToMeta(task);
            }
            break;
          case 'sched_unschedule':
            setState(() => task.dueDay = null);
            _saveTaskToMeta(task);
            break;
          case 'start_focus':
            _showFocusPopup();
            break;
          case 'details':
            setState(() {
              _taskListDetailTask = task;
              _taskListDetailOpen = true;
            });
            break;
          case 'duplicate':
            final dup = Task(
              id: DateTime.now().millisecondsSinceEpoch.toString(),
              title: '${task.title} (copy)',
              isDone: false,
              status: TaskStatus.none,
              projectId: task.projectId,
              subTaskIds: [],
              timeSpent: 0,
              dueDay: task.dueDay,
              durationMinutes: task.durationMinutes,
              attachments: [],
              tagIds: List.from(task.tagIds),
              notes: task.notes,
            );
            setState(() {
              final idx = _allTasks.indexOf(task);
              _allTasks.insert(idx >= 0 ? idx + 1 : _allTasks.length, dup);
            });
            _saveTaskToMeta(dup);
            break;
          case 'subtask':
            await _showTaskContextMenu(ctx, task, Offset.zero);
            break;
          case 'convert_to_parent':
            setState(() {
              for (final t in _allTasks) {
                if (t.subTaskIds.any((id) => id.toString() == task.id)) {
                  t.subTaskIds.remove(task.id);
                  _saveTaskToMeta(t);
                }
              }
            });
            break;
          case 'delete':
            setState(() {
              final subIds = List<String>.from(
                task.subTaskIds.map((s) => s.toString()),
              );
              _allTasks.removeWhere((t) => subIds.contains(t.id));
              _clearRepeatInstances(task.id);
              for (final t in _allTasks) {
                if (t.subTaskIds.any((id) => id.toString() == task.id)) {
                  t.subTaskIds.remove(task.id);
                  _saveTaskToMeta(t);
                }
              }
              _allTasks.remove(task);
            });
            _saveTaskToMeta(task);
            break;
        }
      },

      // 9f: delete a note from the sidebar right-click context menu
      onDeleteNote: (noteId) async {
        final note = _notes[noteId];
        if (note == null) return;
        await _deleteNoteFile(note);
        setState(() {
          _notes.remove(noteId);
          _openNoteTabs.remove(noteId);
          if (_activeNoteId == noteId) {
            _activeNoteId = _openNoteTabs.isEmpty ? null : _openNoteTabs.last;
          }
        });
      },
      // 9e: persist note order after drag-to-reorder
      onReorderNotes: (_) => _saveNotesMeta(),
      // Parity: task/project note reordering
      onReorderProjectNotes: (orderedIds) {
        // The Notes sidebar sends a '__folderOrder__' prefix when the user
        // reorders folder groups rather than individual notes.
        if (orderedIds.isNotEmpty && orderedIds.first == '__folderOrder__') {
          setState(() => _projectFolderOrder = orderedIds.skip(1).toList());
        } else {
          setState(() => _noteProjectOrder = orderedIds);
        }
        _saveWorkspace();
      },
      onReorderTaskNotes: (orderedIds) {
        // '__taskFolderOrder__' prefix means the Notes sidebar reordered
        // task-note folder groups — update _projectFolderOrder, same as
        // the Projects section does with '__folderOrder__'.
        if (orderedIds.isNotEmpty &&
            orderedIds.first == '__taskFolderOrder__') {
          setState(() => _projectFolderOrder = orderedIds.skip(1).toList());
        } else {
          setState(() => _noteTaskOrder = orderedIds);
        }
        _saveWorkspace();
      },
      // Parity: visibility toggles
      onToggleProjectVisibility: (linkedId) {
        setState(() {
          _projectHiddenFromMenu[linkedId] =
              !(_projectHiddenFromMenu[linkedId] ?? false);
        });
        _saveWorkspace();
      },
      onToggleTaskVisibility: (linkedId) {
        setState(() {
          if (_hiddenNoteTasks.contains(linkedId)) {
            _hiddenNoteTasks.remove(linkedId);
          } else {
            _hiddenNoteTasks.add(linkedId);
          }
        });
        _saveWorkspace();
      },
      // Parity: pass current hidden sets and order lists
      hiddenNoteProjects: _projectHiddenFromMenu.entries
          .where((e) => e.value)
          .map((e) => e.key)
          .toSet(),
      hiddenNoteTasks: _hiddenNoteTasks,
      noteProjectOrder: _noteProjectOrder,
      noteTaskOrder: _noteTaskOrder,
      // Projects header buttons
      onAddProject: _showCreateProjectDialog,
      // Settings gear → projects settings replaces the notes region (stays in Notes tab)
      onProjectSettings: () =>
          setState(() => _notesNavSection = 'org_projects'),
      onTaskSettings: () => setState(() => _notesNavSection = 'org_tasks'),
      // Notes section: gear button → folder settings sub-page
      onNotesSettings: () =>
          setState(() => _notesNavSection = 'notes_org_notes'),
      // Note-folder order (independent from projectFolderOrder)
      noteFolderOrder: _noteFolderOrder,
      onReorderNoteFolders: (orderedIds) {
        setState(() => _noteFolderOrder = orderedIds);
        _saveNotesMeta();
      },
      // Project-folder parity — same references as the Tasks sidebar uses.
      projectFolders: _projectFolders,
      projectFolderOrder: _projectFolderOrder,
      projects: _projects,
      projectHiddenFromMenu: _projectHiddenFromMenu,
      // Right-click on a project note → same popup as Tasks sidebar projects.
      onNoteProjectContextMenu: (details, projectId) {
        final projColor = _projectColors[projectId];
        final textColor = projColor != null
            ? (projColor.computeLuminance() > 0.5
                  ? Colors.black87
                  : Colors.white)
            : Colors.white.withOpacity(0.88);
        final iconColor = projColor != null ? textColor : Colors.white24;
        _showProjectFolderMenu(
          details: details,
          projectId: projectId,
          projColor: projColor,
          textColor: textColor,
          iconColor: iconColor,
        );
      },
    );
  }

  // ── Main area ─────────────────────────────────────────────────────────────

  Widget _buildNotesMainArea() {
    _syncNotes();
    // Sub-page routing: settings page for Notes folders
    if (_notesNavSection == 'notes_org_notes') {
      return _buildNotesOrgNotesView();
    }
    // Sub-page routing: Projects Settings rendered in the notes region
    if (_notesNavSection == 'org_projects') {
      return _buildOrgView(
        isProjects: true,
        onBack: () => setState(() => _notesNavSection = 'editor'),
      );
    }
    // Sub-page routing: Tasks Settings rendered in the notes region
    if (_notesNavSection == 'org_tasks') {
      return _buildNotesOrgTasksView(
        onBack: () => setState(() => _notesNavSection = 'editor'),
      );
    }
    final note = _activeNoteId != null ? _notes[_activeNoteId] : null;

    return _NotesEditor(
      key: ValueKey(_activeNoteId ?? '__empty__'),
      note: note,
      projects: _projects,
      projectIcons: _projectIcons,
      allTasks: _allTasks,
      isTitleTaken: (newTitle, currentId) => _notes.values.any(
        (n) =>
            n.type == NoteType.common &&
            n.id != currentId &&
            n.title.trim() == newTitle.trim(),
      ),
      onNoteChanged: (updatedNote) {
        // Save content to .md file (source of truth for all note types)
        _saveNote(updatedNote);
        // For task notes: also keep task.notes in sync so the Task Details
        // panel and SP export still see the latest description.
        if (updatedNote.linkedTaskId != null) {
          final idx = _allTasks.indexWhere(
            (t) => t.id == updatedNote.linkedTaskId,
          );
          if (idx >= 0) {
            _allTasks[idx].notes = updatedNote.content.isEmpty
                ? null
                : updatedNote.content;
            _saveTaskToMeta(_allTasks[idx]);
          }
        }
        // Update in-memory map without full setState to avoid editor rebuild
        _notes[updatedNote.id] = updatedNote;
      },
      onDeleteNote:
          _activeNoteId != null &&
              (_notes[_activeNoteId]?.type == NoteType.common)
          ? () {
              final note = _notes[_activeNoteId];
              if (note != null) _deleteNoteFile(note);
              setState(() {
                _notes.remove(_activeNoteId);
                _activeNoteId = null;
              });
            }
          : null,
      onFoldsChanged: (noteId, headings) {
        // Update the in-memory note and persist to notes_meta.json only —
        // no .md rewrite needed since fold state is sidecar-only.
        final target = _notes[noteId];
        if (target != null) {
          target.collapsedHeadings = headings;
          _saveNotesMeta();
        }
      },
    );
  }

  // ══════════════════════════════════════════════════════════════════════════
  // TASKS TAB
  // ══════════════════════════════════════════════════════════════════════════

  static const Color _tasksAccent = Color(0xFF4FC3F7); // light blue highlight
  static const Color _tasksBg = Color(0xFF181A1B);
  static const Color _tasksSurface = Color(0xFF212426);
  static const Color _tasksBorder = Color(0xFF2C2F32);

  /// Ensures [color] is legible on a dark background — delegates to top-level helper.
  static Color _ensureVisible(Color color) => ensureAccentVisible(color);

  /// Returns the project color for the current nav section, falling back to
  /// the default Tasks accent so all project views are themed consistently.
  /// The returned color is always legible on dark backgrounds.
  Color get _activeProjectAccent {
    String? pid;
    final s = _tasksNavSection;
    if (s.startsWith('proj:')) {
      pid = s.substring(5);
    } else if (s.startsWith('metrics:proj:')) {
      pid = s.substring(13);
    } else if (s.startsWith('worklog:proj:')) {
      pid = s.substring(13);
    } else if (s.startsWith('quick_history:proj:')) {
      pid = s.substring(19);
    } else if (s.startsWith('settings:proj:')) {
      pid = s.substring(14);
    }
    if (pid != null) {
      final c = _projectColors[pid];
      if (c != null) return _ensureVisible(c);
    }
    // Check per-view accent for Today / Inbox (and their sub-sections)
    for (final viewId in ['Today', 'Inbox']) {
      if (s == viewId ||
          s == 'settings:$viewId' ||
          s == 'quick_history:$viewId' ||
          s == 'worklog:$viewId' ||
          s == 'metrics:$viewId') {
        final c = _viewColors[viewId];
        if (c != null) return _ensureVisible(c);
      }
    }
    return _tasksAccent;
  }

  /// Left sidebar navigation for the Tasks tab.

  Widget _buildPlannerTitleBar() {
    return Padding(
      padding: const EdgeInsets.symmetric(horizontal: 16),
      child: Row(
        children: [
          const Icon(Icons.view_week_outlined, size: 15, color: Colors.white54),
          const SizedBox(width: 8),
          const Text(
            'Planner',
            style: TextStyle(
              fontSize: 14,
              fontWeight: FontWeight.w600,
              color: Colors.white,
              letterSpacing: 0.3,
            ),
          ),
        ],
      ),
    );
  }

  Widget _buildPlannerView() {
    return _PlannerView(
      allTasks: _allTasks,
      projects: _projects,
      projectColors: _projectColors,
      onAddTask: (dueDay, task) {
        // Task was fully built in the column — just register it.
        setState(() => _allTasks.add(task));
        _saveTaskToMeta(task);
      },
      onTaskTap: (task) {
        setState(() {
          _selectedTask = task;
          _showDetails = true;
        });
      },
      onStatusToggle: (task) {
        setState(() {
          if (task.status == TaskStatus.done) {
            task.status = TaskStatus.none;
            task.isDone = false;
          } else {
            task.status = TaskStatus.done;
            task.isDone = true;
          }
        });
        _saveTaskToMeta(task);
      },
      onStatusSelect: (task, status) {
        setState(() {
          task.status = status;
          task.isDone = status == TaskStatus.done;
        });
        _saveTaskToMeta(task);
      },
      onReschedule: (task, newDueDay, newPlannedAt) {
        setState(() {
          task.dueDay = newDueDay;
          task.plannedAt = newPlannedAt;
        });
        _saveTaskToMeta(task);
      },
      onDelete: (task) {
        setState(() {
          final subIds = task.subTaskIds.map((s) => s.toString()).toSet();
          final deletedIds = <String>{task.id, ...subIds};

          _allTasks.removeWhere((t) => deletedIds.contains(t.id));

          // ── Remove from the active canvas ──────────────────────────────
          _canvasTasks.removeWhere((t) => deletedIds.contains(t.id));
          _taskPositions.removeWhere((k, _) => deletedIds.contains(k));
          _taskRelations.removeWhere(
            (r) =>
                deletedIds.contains(r.sourceId) ||
                deletedIds.contains(r.targetId),
          );
          if (deletedIds.contains(_selectedCanvasTaskId)) {
            _selectedCanvasTaskId = null;
          }
          _selectedTaskIds.removeAll(deletedIds);

          // ── Remove from every saved canvas state ───────────────────────
          for (final state in _canvasStates.values) {
            final tasks = state['canvasTasks'];
            if (tasks is List<Task>) {
              tasks.removeWhere((t) => deletedIds.contains(t.id));
            }
            final positions = state['taskPositions'];
            if (positions is Map<String, Offset>) {
              positions.removeWhere((k, _) => deletedIds.contains(k));
            }
            final relations = state['taskRelations'];
            if (relations is Set<TaskRelation>) {
              relations.removeWhere(
                (r) =>
                    deletedIds.contains(r.sourceId) ||
                    deletedIds.contains(r.targetId),
              );
            }
          }
        });
      },
      onToggleTag: (task, tag) {
        setState(() {
          if (task.tagIds.contains(tag)) {
            task.tagIds.remove(tag);
          } else {
            task.tagIds.add(tag);
          }
        });
        _saveTaskToMeta(task);
      },
      onMoveToProject: (task, projectId) {
        setState(() {
          // Task.projectId is final — reassign via a workaround isn't possible,
          // so we note this as a known limitation; full support requires making projectId mutable.
        });
        _saveTaskToMeta(task);
      },
      onStartFocus: (task) {
        _startGeneralTimer(task.id);
      },
      onContextMenu: (task, offset) =>
          _showTaskContextMenu(context, task, offset),
    );
  }

  // ── Boards ─────────────────────────────────────────────────────────────────

  Widget _buildBoardsTitleBar() {
    return Row(
      children: [
        const SizedBox(width: 14),
