  Widget _buildBoardsView() {
    const accent = Color(0xFF4FC3F7);
    const bg = Color(0xFF141618);
    const tabBar = Color(0xFF1A1C1F);
    const border = Color(0xFF2A2D30);
    const double barH = 36;

    return Column(
      crossAxisAlignment: CrossAxisAlignment.stretch,
      children: [
        // ── Tab bar ─────────────────────────────────────────────────────
        Container(
          height: barH,
          color: tabBar,
          child: Row(
            children: [
              Expanded(
                child: SingleChildScrollView(
                  scrollDirection: Axis.horizontal,
                  child: Row(
                    children: [
                      ..._savedBoards.map((board) {
                        final id = board['id'] as String;
                        final title = board['title'] as String? ?? 'Board';
                        final isActive = id == _currentBoardId;
                        bool hovered = false;
                        return StatefulBuilder(
                          builder: (_, setTab) {
                            return MouseRegion(
                              onEnter: (_) => setTab(() => hovered = true),
                              onExit: (_) => setTab(() => hovered = false),
                              child: GestureDetector(
                                onTap: () =>
                                    setState(() => _currentBoardId = id),
                                child: AnimatedContainer(
                                  duration: const Duration(milliseconds: 150),
                                  constraints: const BoxConstraints(
                                    maxWidth: 180,
                                    minWidth: 60,
                                  ),
                                  height: barH,
                                  padding: const EdgeInsets.symmetric(
                                    horizontal: 14,
                                  ),
                                  decoration: BoxDecoration(
                                    color: isActive
                                        ? bg
                                        : (hovered
                                              ? Colors.white.withOpacity(0.04)
                                              : Colors.transparent),
                                    border: Border(
                                      right: const BorderSide(
                                        color: Color(0xFF2A2D30),
                                      ),
                                      bottom: isActive
                                          ? const BorderSide(
                                              color: accent,
                                              width: 2,
                                            )
                                          : BorderSide.none,
                                    ),
                                  ),
                                  child: Row(
                                    mainAxisSize: MainAxisSize.min,
                                    children: [
                                      Icon(
                                        Icons.dashboard_outlined,
                                        size: 12,
                                        color: isActive
                                            ? accent
                                            : Colors.white38,
                                      ),
                                      const SizedBox(width: 7),
                                      Flexible(
                                        child: Text(
                                          title,
                                          overflow: TextOverflow.ellipsis,
                                          style: TextStyle(
                                            fontSize: 11,
                                            fontWeight: isActive
                                                ? FontWeight.w600
                                                : FontWeight.normal,
                                            color: isActive
                                                ? Colors.white
                                                : Colors.white54,
                                          ),
                                        ),
                                      ),
                                      AnimatedOpacity(
                                        duration: const Duration(
                                          milliseconds: 120,
                                        ),
                                        opacity: hovered ? 1 : 0,
                                        child: Padding(
                                          padding: const EdgeInsets.only(
                                            left: 6,
                                          ),
                                          child: GestureDetector(
                                            onTap: () => setState(() {
                                              _savedBoards.removeWhere(
                                                (b) => b['id'] == id,
                                              );
                                              if (_currentBoardId == id) {
                                                _currentBoardId =
                                                    _savedBoards.isNotEmpty
                                                    ? _savedBoards.last['id']
                                                          as String
                                                    : '';
                                              }
                                            }),
                                            child: const Icon(
                                              Icons.close,
                                              size: 11,
                                              color: Colors.white38,
                                            ),
                                          ),
                                        ),
                                      ),
                                    ],
                                  ),
                                ),
                              ),
                            );
                          },
                        );
                      }),
                    ],
                  ),
                ),
              ),
              // ── Sync button for active board ──────────────────────────
              if (_savedBoards.isNotEmpty)
                Tooltip(
                  message: 'Sync active board',
                  child: InkWell(
                    onTap: () => _boardViewKey.currentState?.sync(),
                    child: Container(
                      width: 36,
                      height: barH,
                      alignment: Alignment.center,
                      child: const Icon(
                        Icons.sync_rounded,
                        size: 15,
                        color: Colors.white38,
                      ),
                    ),
                  ),
                ),
              // ── [+] new board button ──────────────────────────────────
              Tooltip(
                message: 'New board',
                child: InkWell(
                  onTap: _showNewBoardDialog,
                  child: Container(
                    width: 36,
                    height: barH,
                    alignment: Alignment.center,
                    child: const Icon(
                      Icons.add,
                      size: 16,
                      color: Colors.white38,
                    ),
                  ),
                ),
              ),
            ],
          ),
        ),

        // ── Board content ────────────────────────────────────────────────
        Expanded(
          child: _savedBoards.isEmpty
              ? _buildBoardsEmptyState()
              : () {
                  final board = _savedBoards.firstWhere(
                    (b) => b['id'] == _currentBoardId,
                    orElse: () => _savedBoards.first,
                  );
                  return _BoardView(
                    key: _boardViewKey,
                    board: board,
                    projects: _projects,
                    projectOrder: _projectOrder,
                    onBoardUpdated: (updated) => setState(() {
                      final idx = _savedBoards.indexWhere(
                        (b) => b['id'] == updated['id'],
                      );
                      if (idx >= 0) _savedBoards[idx] = updated;
                    }),
                    onTasksUpserted: (tasks) {
                      setState(() {
                        for (final t in tasks) {
                          final existing = _allTasks.indexWhere(
                            (x) => x.id == t.id,
                          );
                          if (existing >= 0) {
                            _allTasks[existing].title = t.title;
                            _allTasks[existing].notes = t.notes;
                            _allTasks[existing].isDone = t.isDone;
                            _allTasks[existing].status = t.status;
                            _allTasks[existing].dueDay = t.dueDay;
                          } else {
                            _allTasks.add(t);
                          }
                        }
                      });
                    },
                    onConvertTask: (id, isCard, cardData, checklists) {
                      setState(() {
                        final projectId =
                            board['projectId'] as String? ?? 'INBOX_PROJECT';

                        // upsert: add or replace task by id
                        void upsert(Task t) {
                          final i = _allTasks.indexWhere((x) => x.id == t.id);
                          if (i >= 0)
                            _allTasks[i] = t;
                          else
                            _allTasks.add(t);
                        }

                        // collect all descendant ids (for cascade-remove on toggle off)
                        Set<String> descendants(String rootId) {
                          final result = <String>{};
                          final queue = [rootId];
                          while (queue.isNotEmpty) {
                            final cur = queue.removeLast();
                            final t = _allTasks.firstWhere(
                              (x) => x.id == cur,
                              orElse: () => Task(
                                id: '',
                                title: '',
                                isDone: false,
                                projectId: '',
                                subTaskIds: [],
                                timeSpent: 0,
                                attachments: [],
                                tagIds: [],
                              ),
                            );
                            for (final sub in t.subTaskIds) {
                              if (result.add(sub as String)) queue.add(sub);
                            }
                          }
                          return result;
                        }

                        final alreadyExists = _allTasks.any((x) => x.id == id);
                        if (alreadyExists) {
                          // Toggle off — remove this task and all its descendants
                          final toRemove = {id, ...descendants(id)};
                          _allTasks.removeWhere((x) => toRemove.contains(x.id));
                          return;
                        }

                        // ── Situation 1: Card ─────────────────────────────────
                        // A → Task
                        // A1 (each checklist) → Subtask of A
                        // A1.1 (each item) → Sub-subtask of A1
                        if (isCard && cardData != null) {
                          final cardSubIds = <String>[];

                          for (final cl in (checklists ?? [])) {
                            final clId = cl['id'] as String;
                            final clName = cl['name'] as String? ?? '';
                            final clIntId = 'trello_checklist_$clId';
                            final clRaws = (cl['checkItems'] as List? ?? [])
                                .map((r) => Map<String, dynamic>.from(r as Map))
                                .toList();
                            final clSubIds = clRaws
                                .map((i) => 'trello_item_${i['id']}')
                                .toList();
                            final clDone =
                                clRaws.isNotEmpty &&
                                clRaws.every(
                                  (i) => (i['state'] as String?) == 'complete',
                                );

                            // A1.1 → sub-subtask
                            for (final item in clRaws) {
                              final itemDone =
                                  (item['state'] as String?) == 'complete';
                              upsert(
                                Task(
                                  id: 'trello_item_${item['id']}',
                                  title: item['name'] as String? ?? '',
                                  isDone: itemDone,
                                  status: itemDone
                                      ? TaskStatus.done
                                      : TaskStatus.none,
                                  projectId: projectId,
                                  subTaskIds: [],
                                  timeSpent: 0,
                                  attachments: [],
                                  tagIds: [],
                                ),
                              );
                            }

                            // A1 → subtask
                            upsert(
                              Task(
                                id: clIntId,
                                title: clName,
                                isDone: clDone,
                                status: clDone
                                    ? TaskStatus.done
                                    : TaskStatus.none,
                                projectId: projectId,
                                subTaskIds: clSubIds,
                                timeSpent: 0,
                                attachments: [],
                                tagIds: [],
                              ),
                            );
                            cardSubIds.add(clIntId);
                          }

                          // A → task
                          upsert(
                            Task(
                              id: id,
                              title: cardData['name'] as String? ?? '',
                              isDone:
                                  (cardData['dueComplete'] as bool?) ?? false,
                              status: TaskStatus.none,
                              projectId: projectId,
                              subTaskIds: cardSubIds,
                              timeSpent: 0,
                              attachments: [],
                              tagIds: [],
                              notes: cardData['desc'] as String?,
                            ),
                          );
                          return;
                        }

                        // ── Situation 2: Checklist ────────────────────────────
                        // A1 → Task
                        // A1.1 (each item) → Subtask of A1
                        if (checklists != null && checklists.isNotEmpty) {
                          final cl = checklists.first;
                          final clName =
                              (cardData?['name'] as String?)?.isNotEmpty == true
                              ? cardData!['name'] as String
                              : cl['name'] as String? ?? id;
                          final clRaws = (cl['checkItems'] as List? ?? [])
                              .map((r) => Map<String, dynamic>.from(r as Map))
                              .toList();
                          final clSubIds = clRaws
                              .map((i) => 'trello_item_${i['id']}')
                              .toList();

                          // A1.1 → subtask
                          for (final item in clRaws) {
                            final itemDone =
                                (item['state'] as String?) == 'complete';
                            upsert(
                              Task(
                                id: 'trello_item_${item['id']}',
                                title: item['name'] as String? ?? '',
                                isDone: itemDone,
                                status: itemDone
                                    ? TaskStatus.done
                                    : TaskStatus.none,
                                projectId: projectId,
                                subTaskIds: [],
                                timeSpent: 0,
                                attachments: [],
                                tagIds: [],
                              ),
                            );
                          }

                          // A1 → task
                          upsert(
                            Task(
                              id: id,
                              title: clName,
                              isDone: false,
                              projectId: projectId,
                              subTaskIds: clSubIds,
                              timeSpent: 0,
                              attachments: [],
                              tagIds: [],
                            ),
                          );
                          return;
                        }

                        // ── Situation 3: Checklist item ───────────────────────
                        // A1.1 → standalone Task
                        final raw = cardData?['name'] as String?;
                        upsert(
                          Task(
                            id: id,
                            title: (raw != null && raw.isNotEmpty) ? raw : id,
                            isDone: false,
                            projectId: projectId,
                            subTaskIds: [],
                            timeSpent: 0,
                            attachments: [],
                            tagIds: [],
                          ),
                        );
                      });
                    },
                    onRemoveTask: (id) {
                      setState(() => _allTasks.removeWhere((x) => x.id == id));
                    },
                    allTasks: _allTasks,
                  );
                }(),
        ),
      ],
    );
  }

