  Widget _buildScheduleView() {
    return _ScheduleCanvas(
      key: _scheduleCanvasKey,
      allTasks: _allTasks.where((t) => t.dueDay != null).toList(),
      weekStart: _scheduleWeekStart,
      rangeEnd: _scheduleRangeEnd,
      projects: _projects,
      projectColors: _projectColors,
      taskSessions: _taskSessions,
      execViewMode: _scheduleExecViewMode,
      onTaskUpdated: (task) {
        setState(() {});
        _saveTaskToMeta(task);
      },
      onCreateRequest: _showScheduleCreateDialog,
      onVisibleRangeChanged: (start, end, {required bool shiftPanning}) {
        bool changed = false;
        if (_scheduleVisibleEnd != end) {
          _scheduleVisibleEnd = end;
          changed = true;
        }
        // Range boundary only grows — zoom-in must never shrink it.
        if (_scheduleRangeEnd == null || end.isAfter(_scheduleRangeEnd!)) {
          _scheduleRangeEnd = end;
          changed = true;
        }
        // Only update the top-bar start date when Shift is held.
        if (shiftPanning && start != _scheduleWeekStart) {
          _scheduleWeekStart = start;
          changed = true;
        }
        // Keep visible-day count in sync for the Custom button label.
        final days = end.difference(start).inDays + 1;
        if (_scheduleVisibleDays != days) {
          _scheduleVisibleDays = days;
          changed = true;
        }
        // If the canvas shows a day count that doesn't match a preset,
        // switch the mode indicator to Custom.
        const presets = {7, 14, 30};
        final newMode = presets.contains(days)
            ? (days == 7
                  ? 'Week'
                  : days == 14
                  ? '14d'
                  : 'Month')
            : 'Custom';
        if (_scheduleViewMode != newMode) {
          _scheduleViewMode = newMode;
          changed = true;
        }
        if (changed) setState(() {});
      },
      onContextMenu: (task, pos) => setState(() {
        _taskListDetailTask = task;
        _taskListDetailOpen = true;
      }),
    );
  }

