                                      border: Border.all(
                                        color: active
                                            ? const Color(
                                                0xFF4FC3F7,
                                              ).withOpacity(0.6)
                                            : Colors.white12,
                                      ),
                                    ),
                                    child: Text(
                                      label,
                                      style: TextStyle(
                                        fontSize: 12,
                                        fontWeight: active
                                            ? FontWeight.w600
                                            : FontWeight.normal,
                                        color: active
                                            ? const Color(0xFF4FC3F7)
                                            : Colors.white54,
                                      ),
                                    ),
                                  ),
                                );
                              }).toList(),
                            ),
                          ],
                        ),
                      ),
                      Padding(
                        padding: const EdgeInsets.fromLTRB(16, 14, 16, 14),
                        child: Row(
                          mainAxisAlignment: MainAxisAlignment.end,
                          children: [
                            TextButton(
                              onPressed: () => Navigator.pop(ctx),
                              style: TextButton.styleFrom(
                                foregroundColor: Colors.white38,
                                padding: const EdgeInsets.symmetric(
                                  horizontal: 14,
                                  vertical: 8,
                                ),
                                minimumSize: Size.zero,
                                tapTargetSize: MaterialTapTargetSize.shrinkWrap,
                              ),
                              child: const Text(
                                'Cancel',
                                style: TextStyle(fontSize: 12),
                              ),
                            ),
                            const SizedBox(width: 8),
                            ElevatedButton.icon(
                              onPressed: () {
                                if (titleCtrl.text.trim().isEmpty) return;
                                Navigator.pop(ctx);
                                _commitScheduleTask(
                                  titleCtrl.text.trim(),
                                  slot,
                                  selectedDuration,
                                  projectId: selectedProjectId,
                                );
                              },
                              icon: const Icon(
                                Icons.calendar_month_outlined,
                                size: 13,
                              ),
                              label: const Text(
                                'Schedule',
                                style: TextStyle(
                                  fontSize: 12,
                                  fontWeight: FontWeight.w600,
                                ),
                              ),
                              style: ElevatedButton.styleFrom(
                                backgroundColor: const Color(0xFF2E7D32),
                                foregroundColor: Colors.white,
                                elevation: 0,
                                padding: const EdgeInsets.symmetric(
                                  horizontal: 14,
                                  vertical: 8,
                                ),
                                minimumSize: Size.zero,
                                tapTargetSize: MaterialTapTargetSize.shrinkWrap,
                              ),
                            ),
                          ],
                        ),
                      ),
                    ],
                  ),
                ),
              ),
            );
          },
        );
      },
    );
  }

  void _commitScheduleTask(
    String title,
    DateTime slot,
    int durationMinutes, {
    String projectId = 'INBOX_PROJECT',
  }) {
    final newTask = Task(
      id: DateTime.now().millisecondsSinceEpoch.toString(),
      title: title,
      isDone: false,
      projectId: projectId.isNotEmpty ? projectId : 'INBOX_PROJECT',
      subTaskIds: [],
      timeSpent: 0,
      attachments: [],
      tagIds: [],
      dueDay: slot.toIso8601String().split('T').first,
      plannedAt: slot.millisecondsSinceEpoch,
      durationMinutes: durationMinutes,
    );
    setState(() => _allTasks.add(newTask));
    _saveTaskToMeta(newTask);
  }

  /// Update mutable display properties on all instances when the parent changes.
  void _syncRepeatInstances(Task parent) {
    final children = _allTasks
        .where((t) => t.repeatParentId == parent.id)
        .toList();
    if (children.isEmpty) return;
    setState(() {
      for (final child in children) {
        child.title = parent.title;
        child.notes = parent.notes;
        child.durationMinutes = parent.durationMinutes;
        // Keep isDone/status independent per instance
      }
    });
  }

  // ── Repeat propagation ────────────────────────────────────────────────────

  /// Remove every auto-generated instance belonging to [parentId].
  void _clearRepeatInstances(String parentId) {
    _allTasks.removeWhere((t) => t.repeatParentId == parentId);
  }

  /// Anchor-segment-aware repeat propagation.
  ///
  /// The series is divided into segments by "anchor tasks" — the parent task
  /// plus any instance that carries its own [repeatConfig] override. Each
  /// anchor defines the rule for its segment, bounded by the next anchor's
  /// date (exclusive) or its own [endDate]/[propagationDays] horizon.
  ///
  /// All non-anchor instances are cleared and regenerated so the timeline
  /// always reflects the current set of rules.
  void _propagateRepeat(Task parent) {
    if (parent.repeatConfig == null || parent.repeatConfig!.cleared) {
      setState(() => _clearRepeatInstances(parent.id));
      return;
    }

    // All tasks in the series, sorted chronologically.
    final allSeries =
        _allTasks
            .where((t) => t.id == parent.id || t.repeatParentId == parent.id)
            .toList()
          ..sort((a, b) {
            final da = a.scheduledDate ?? DateTime(2099);
            final db = b.scheduledDate ?? DateTime(2099);
            return da.compareTo(db);
          });

    // Anchor tasks define segment boundaries.
    final anchorTasks = allSeries
        .where((t) => t.repeatConfig != null && !t.repeatConfig!.cleared)
        .toList();

    // Remove all non-anchor instances — they will be regenerated.
    setState(() {
      _allTasks.removeWhere((t) {
        if (t.repeatParentId != parent.id) return false;
        return t.repeatConfig == null || t.repeatConfig!.cleared;
      });
    });

    final today = DateTime.now();
    final timeOfDay = parent.plannedAt != null
        ? Duration(
            hours: DateTime.fromMillisecondsSinceEpoch(parent.plannedAt!).hour,
            minutes: DateTime.fromMillisecondsSinceEpoch(
              parent.plannedAt!,
            ).minute,
          )
        : null;

    // Dates already occupied (anchors must never be overwritten).
    final existingDates = _allTasks
        .where((t) => t.id == parent.id || t.repeatParentId == parent.id)
        .map((t) => t.scheduledDate)
        .whereType<DateTime>()
        .toSet();

    final newTasks = <Task>[];

    for (int i = 0; i < anchorTasks.length; i++) {
      final anchorTask = anchorTasks[i];
      final cfg = anchorTask.repeatConfig!;

      final segStart = anchorTask.scheduledDate;
      if (segStart == null) continue;

      // Horizon = min(segStart + propagationDays?, cfg.endDate, next anchor – 1 day).
      // propagationDays is null when the field is left empty → only endDate caps.
      DateTime? horizon;
      if (cfg.propagationDays != null) {
        horizon = segStart.add(Duration(days: cfg.propagationDays!));
      }
      if (cfg.endDate != null) {
        final ed = DateTime(
          cfg.endDate!.year,
          cfg.endDate!.month,
          cfg.endDate!.day,
        );
        if (horizon == null || ed.isBefore(horizon)) horizon = ed;
      }
      // If neither days nor endDate is set, fall through without a horizon cap
      // (next-anchor bound below still limits the segment).
      horizon ??= segStart.add(const Duration(days: 3650)); // 10-year safety cap
      if (i + 1 < anchorTasks.length) {
        final nextStart = anchorTasks[i + 1].scheduledDate;
        if (nextStart != null) {
          final bound = nextStart.subtract(const Duration(days: 1));
          if (bound.isBefore(horizon)) horizon = bound;
        }
      }

      DateTime cursor = segStart;
      while (!cursor.isAfter(horizon)) {
        final next = _nextRepeatDate(cfg, cursor);
        if (next == null) break;
        cursor = next;
        if (cursor.isAfter(segStart) &&
            !cursor.isAfter(horizon) &&
            !existingDates.contains(cursor)) {
          final id = 'repeat_${parent.id}_${cursor.millisecondsSinceEpoch}';
          newTasks.add(
            Task(
              id: id,
              title: parent.title,
              isDone: false,
              status: TaskStatus.none,
              projectId: parent.projectId,
              subTaskIds: [],
              timeSpent: 0,
              dueDay: cursor.toIso8601String().split('T').first,
              plannedAt: timeOfDay != null
                  ? cursor.add(timeOfDay).millisecondsSinceEpoch
                  : null,
              durationMinutes: parent.durationMinutes,
              attachments: [],
              tagIds: List.from(parent.tagIds),
              notes: parent.notes,
              repeatParentId: parent.id,
            ),
          );
          existingDates.add(cursor);
        }
        if (newTasks.length > 500) break;
      }
    }

    setState(() => _allTasks.addAll(newTasks));
  }

  /// Delegates to full [_propagateRepeat] so all segments stay consistent.
  void _propagateRepeatFromInstance(Task instance) {
    final parentId = instance.repeatParentId;
    if (parentId == null) return;
    final parent = _allTasks.firstWhere(
      (t) => t.id == parentId,
      orElse: () => instance,
    );
    _propagateRepeat(parent);
  }

  /// Called when an instance user chooses "Apply from here" with a new config.
  ///
  /// The instance becomes an **anchor point**: [newCfg] is stored directly on
  /// it. All non-anchor future instances are pruned, then [_propagateRepeat]
  /// regenerates every segment (past anchor segments are untouched).
  void _applyForwardFromInstance(Task instance, RepeatConfig newCfg) {
    final parentId = instance.repeatParentId;
    if (parentId == null) return;

    final instanceDate = instance.scheduledDate;

    setState(() {
      // Store config on the instance — it becomes an anchor.
      instance.repeatConfig = newCfg;

      // Prune non-anchor instances strictly after this instance's date.
      _allTasks.removeWhere((t) {
        if (t.repeatParentId != parentId) return false;
        if (t.id == instance.id) return false;
        if (t.repeatConfig != null && !t.repeatConfig!.cleared) return false;
        final tDate = t.scheduledDate;
        if (tDate == null || instanceDate == null) return false;
        return tDate.isAfter(instanceDate);
      });
    });

    final parent = _allTasks.firstWhere(
      (t) => t.id == parentId,
      orElse: () => instance,
    );
    _propagateRepeat(parent);
  }

  /// Called when the parent task's "Apply Changes To" button is tapped.
  /// Updates the config on the parent and propagates field changes to
  /// sibling instances that fall within [scope]:
  ///   - current  → only the parent task itself (no siblings)
  ///   - forward  → parent + all instances on or after today
  ///   - backward → parent + all instances before today
  ///   - all      → every task in the series
  /// Then re-runs full propagation so the timeline reflects the new config.
  void _applyFromParentScoped(
    Task parent,
    RepeatConfig newCfg,
    _RepeatPropagateScope scope,
  ) {
    final today = DateTime(
      DateTime.now().year,
      DateTime.now().month,
      DateTime.now().day,
    );

    setState(() {
      parent.repeatConfig = newCfg;

      if (scope != _RepeatPropagateScope.current) {
        final series = _allTasks
            .where((t) => t.repeatParentId == parent.id)
            .toList();

        for (final t in series) {
          final tDate = t.scheduledDate;
          bool include = false;
          switch (scope) {
            case _RepeatPropagateScope.forward:
              include = tDate == null || !tDate.isBefore(today);
              break;
            case _RepeatPropagateScope.backward:
              include = tDate == null || tDate.isBefore(today);
              break;
            case _RepeatPropagateScope.all:
              include = true;
              break;
            case _RepeatPropagateScope.current:
              break;
          }
          if (include) {
            t.title = parent.title;
            t.notes = parent.notes;
            t.durationMinutes = parent.durationMinutes;
          }
        }
      }
    });

    _propagateRepeat(parent);
  }

  /// Sync mutable fields from [instance] to siblings according to [scope].
  void _propagateScopedRepeat(
    Task instance,
    _RepeatPropagateScope scope,
    Set<String> fields,
  ) {
    if (scope == _RepeatPropagateScope.current) return;
    final parentId = instance.repeatParentId ?? instance.id;

    final series = _allTasks
        .where((t) => t.id == parentId || t.repeatParentId == parentId)
        .toList();

    final instanceDate = instance.scheduledDate;

    setState(() {
      for (final t in series) {
        if (t.id == instance.id) continue;
        final tDate = t.scheduledDate;
        bool include = false;
        switch (scope) {
          case _RepeatPropagateScope.current:
            break;
          case _RepeatPropagateScope.forward:
            include =
                tDate == null ||
                instanceDate == null ||
                !tDate.isBefore(instanceDate);
            break;
          case _RepeatPropagateScope.backward:
            include =
                tDate == null ||
                instanceDate == null ||
                !tDate.isAfter(instanceDate);
            break;
          case _RepeatPropagateScope.all:
            include = true;
            break;
        }
        if (include) {
          if (fields.contains('title')) t.title = instance.title;
          if (fields.contains('status')) {
            t.status = instance.status;
            t.isDone = instance.isDone;
          }
          if (fields.contains('time')) t.plannedAt = instance.plannedAt;
          if (fields.contains('duration'))
            t.durationMinutes = instance.durationMinutes;
          if (fields.contains('notes')) t.notes = instance.notes;
          if (fields.contains('tags')) t.tagIds = List.from(instance.tagIds);
          if (fields.contains('subtasks')) t.subTaskIds.clear();
        }
      }
    });
  }

  /// Compute the next occurrence date after [from] given [cfg].
  /// Returns null if no next date is determinable.
  DateTime? _nextRepeatDate(RepeatConfig cfg, DateTime from) {
    switch (cfg.preset) {
      case RepeatPreset.everyday:
        return from.add(const Duration(days: 1));

      case RepeatPreset.weekdays:
        var d = from.add(const Duration(days: 1));
        while (d.weekday == DateTime.saturday || d.weekday == DateTime.sunday) {
          d = d.add(const Duration(days: 1));
        }
        return d;

      case RepeatPreset.everyWeek:
        return from.add(const Duration(days: 7));

      case RepeatPreset.everyMonth:
        final target = from.day;
        var y = from.year;
        var m = from.month + 1;
        if (m > 12) {
          m = 1;
          y++;
        }
        final daysInMonth = DateTime(y, m + 1, 0).day;
        return DateTime(y, m, target.clamp(1, daysInMonth));

      case RepeatPreset.everyYear:
        return DateTime(from.year + 1, from.month, from.day);

      case RepeatPreset.custom:
        switch (cfg.customCycle) {
          case RepeatCycle.day:
            return from.add(Duration(days: cfg.customEvery));
          case RepeatCycle.week:
            // Find next matching weekday(s) within the cycle
            if (cfg.customWeekDays.isEmpty) return null;
            // Walk day-by-day until we hit a matching weekday within the period
            var d = from.add(const Duration(days: 1));
            final limit = from.add(Duration(days: cfg.customEvery * 7 + 7));
            while (d.isBefore(limit)) {
              if (cfg.customWeekDays.contains(d.weekday)) return d;
              d = d.add(const Duration(days: 1));
            }
            return null;
          case RepeatCycle.month:
            var y = from.year;
            var mo = from.month + cfg.customEvery;
            while (mo > 12) {
              mo -= 12;
              y++;
            }
            final daysInMonth = DateTime(y, mo + 1, 0).day;
            return DateTime(y, mo, from.day.clamp(1, daysInMonth));
          case RepeatCycle.year:
            return DateTime(from.year + cfg.customEvery, from.month, from.day);
        }
    }
    return null;
  }

  String _fmt12h(int hour, int minute) {
    final period = hour < 12 ? 'AM' : 'PM';
    final h = hour == 0 ? 12 : (hour > 12 ? hour - 12 : hour);
    return "$h:${minute.toString().padLeft(2, '0')} $period";
  }

  Widget _buildTasksNavContent() {
    // Compute counts
    final now = DateTime.now();
    final today = DateTime(now.year, now.month, now.day);

    final allSubtaskIds = _allTasks
        .expand((t) => t.subTaskIds.map((id) => id.toString()))
        .toSet();
    final rootTasks = _allTasks
        .where((t) => !allSubtaskIds.contains(t.id))
        .toList();

    int todayCount = 0, overdueCount = 0, inboxCount = 0;
    for (final t in rootTasks) {
      if (t.status == TaskStatus.done || t.status == TaskStatus.cancelled)
        continue;
      if (t.projectId == 'INBOX_PROJECT') inboxCount++;
      if (t.dueDay == null) continue;
      final due = DateTime.tryParse(t.dueDay!);
      if (due == null) continue;
      final dueDate = DateTime(due.year, due.month, due.day);
      if (dueDate.isBefore(today))
        overdueCount++;
      else if (dueDate == today)
        todayCount++;
    }

