              child: _projectMenuRow(
                Icons.delete_outline,
                'Delete Project',
                const Color(0xFFEF5350),
                labelColor: const Color(0xFFEF5350),
              ),
            ),
            PopupMenuItem<String>(
              value: 'toggle_hide',
              height: 38,
              child: _projectMenuRow(
                (_projectHiddenFromMenu[projectId] ?? false)
                    ? Icons.visibility_outlined
                    : Icons.visibility_off_outlined,
                (_projectHiddenFromMenu[projectId] ?? false)
                    ? 'Show in Sidebar'
                    : 'Hide from Sidebar',
                const Color(0xFF9E9E9E),
              ),
            ),
          ],
        );
        if (choice == null || !mounted) return;
        if (choice == 'filter_group_sort' && projectId != null) {
          final projTitle = _projects[projectId]?.title ?? projectId;
          setState(() {
            _filterSidebarTitle = 'Project: $projTitle';
            _filterSidebarOpen = true;
          });
        } else if (choice == 'delete' && projectId != null) {
          _confirmDeleteProject(projectId);
        } else if (choice == 'toggle_hide' && projectId != null) {
          setState(() {
            _projectHiddenFromMenu[projectId] =
                !(_projectHiddenFromMenu[projectId] ?? false);
          });
          _saveWorkspace();
        } else if (choice == 'quick_history' && projectId != null) {
          setState(() => _tasksNavSection = 'quick_history:proj:$projectId');
        } else if (choice == 'worklog' && projectId != null) {
          setState(() => _tasksNavSection = 'worklog:proj:$projectId');
        } else if (choice == 'metrics' && projectId != null) {
          setState(() => _tasksNavSection = 'metrics:proj:$projectId');
        } else if (choice == 'settings' && projectId != null) {
          setState(() => _tasksNavSection = 'settings:proj:$projectId');
        }
      }

      return MouseRegion(
        onEnter: (_) => setState(() => _hoveredProjectIds.add(id)),
        onExit: (_) => setState(() => _hoveredProjectIds.remove(id)),
        child: GestureDetector(
          onSecondaryTapDown: isProject
              ? showProjectMenu
              : isTodayOrInbox
              ? showTodayInboxMenu
              : null,
          child: InkWell(
            onTap: () => setState(() => _tasksNavSection = id),
            child: AnimatedContainer(
              duration: const Duration(milliseconds: 150),
              margin: const EdgeInsets.symmetric(horizontal: 8, vertical: 2),
              padding: const EdgeInsets.symmetric(horizontal: 10, vertical: 9),
              decoration: BoxDecoration(
                color: active
                    ? _activeProjectAccent.withOpacity(0.12)
                    : Colors.transparent,
                borderRadius: BorderRadius.circular(8),
                border: Border.all(
                  color: active
                      ? _activeProjectAccent.withOpacity(0.3)
                      : Colors.transparent,
                ),
              ),
              child: Row(
                children: [
                  SizedBox(
                    width: 16,
                    height: 16,
                    child:
                        (isProject &&
                            projectId != null &&
                            (_projectIcons[projectId] ?? '').isNotEmpty)
                        ? Center(
                            child: Text(
                              _projectIcons[projectId]!,
                              style: const TextStyle(
                                fontSize: 13,
                                fontFamilyFallback: [
                                  'NotoColorEmoji',
                                  'Apple Color Emoji',
                                  'Segoe UI Emoji',
                                ],
                              ),
                            ),
                          )
                        : (isTag &&
                              tagName != null &&
                              (_tagIcons[tagName] ?? '').isNotEmpty)
                        ? Center(
                            child: Text(
                              _tagIcons[tagName]!,
                              style: const TextStyle(
                                fontSize: 13,
                                fontFamilyFallback: [
                                  'NotoColorEmoji',
                                  'Apple Color Emoji',
                                  'Segoe UI Emoji',
                                ],
                              ),
                            ),
                          )
                        : Icon(
                            icon,
                            size: 16,
                            color: active
                                ? _activeProjectAccent
                                : Colors.white38,
                          ),
                  ),
                  const SizedBox(width: 10),
                  Expanded(
                    child: Text(
                      label,
                      style: TextStyle(
                        fontSize: 12,
                        fontWeight: active
                            ? FontWeight.w600
                            : FontWeight.normal,
                        color: active ? _activeProjectAccent : Colors.white60,
                        letterSpacing: 0.2,
                      ),
                    ),
                  ),
                  // For project rows: show three-dot on hover, count badge otherwise
                  if (isProject)
                    AnimatedSwitcher(
                      duration: const Duration(milliseconds: 150),
                      child: isHovered
                          ? GestureDetector(
                              key: const ValueKey('menu'),
                              onTapDown: showProjectMenu,
                              child: const Padding(
                                padding: EdgeInsets.only(left: 2),
                                child: Icon(
                                  Icons.more_vert,
                                  size: 15,
                                  color: Colors.white54,
                                ),
                              ),
                            )
                          : (count > 0
                                ? Container(
                                    key: const ValueKey('badge'),
                                    padding: const EdgeInsets.symmetric(
                                      horizontal: 6,
                                      vertical: 2,
                                    ),
                                    decoration: BoxDecoration(
                                      color: active
                                          ? _activeProjectAccent.withOpacity(
                                              0.2,
                                            )
                                          : Colors.white.withOpacity(0.08),
                                      borderRadius: BorderRadius.circular(10),
                                    ),
                                    child: Text(
                                      '$count',
                                      style: TextStyle(
                                        fontSize: 10,
                                        fontWeight: FontWeight.bold,
                                        color: active
                                            ? _activeProjectAccent
                                            : Colors.white38,
                                      ),
                                    ),
                                  )
                                : const SizedBox.shrink(
                                    key: ValueKey('empty'),
                                  )),
                    )
                  // For tag rows: show three-dot on hover, count badge otherwise
                  else if (isTag)
                    AnimatedSwitcher(
                      duration: const Duration(milliseconds: 150),
                      child: isHovered
                          ? GestureDetector(
                              key: const ValueKey('menu'),
                              onTapDown: showTagMenu,
                              child: const Padding(
                                padding: EdgeInsets.only(left: 2),
                                child: Icon(
                                  Icons.more_vert,
                                  size: 15,
                                  color: Colors.white54,
                                ),
                              ),
                            )
                          : (count > 0
                                ? Container(
                                    key: const ValueKey('badge'),
                                    padding: const EdgeInsets.symmetric(
                                      horizontal: 6,
                                      vertical: 2,
                                    ),
                                    decoration: BoxDecoration(
                                      color: active
                                          ? _activeProjectAccent.withOpacity(
                                              0.2,
                                            )
                                          : Colors.white.withOpacity(0.08),
                                      borderRadius: BorderRadius.circular(10),
                                    ),
                                    child: Text(
                                      '$count',
                                      style: TextStyle(
                                        fontSize: 10,
                                        fontWeight: FontWeight.bold,
                                        color: active
                                            ? _activeProjectAccent
                                            : Colors.white38,
                                      ),
                                    ),
                                  )
                                : const SizedBox.shrink(
                                    key: ValueKey('empty'),
                                  )),
                    )
                  // For Today/Inbox: three-dot on hover, count badge otherwise
                  else if (isTodayOrInbox)
                    AnimatedSwitcher(
                      duration: const Duration(milliseconds: 150),
                      child: isHovered
                          ? GestureDetector(
                              key: const ValueKey('menu'),
                              onTapDown: showTodayInboxMenu,
                              child: const Padding(
                                padding: EdgeInsets.only(left: 2),
                                child: Icon(
                                  Icons.more_vert,
                                  size: 15,
                                  color: Colors.white54,
                                ),
                              ),
                            )
                          : (count > 0
                                ? Container(
                                    key: const ValueKey('badge'),
                                    padding: const EdgeInsets.symmetric(
                                      horizontal: 6,
                                      vertical: 2,
                                    ),
                                    decoration: BoxDecoration(
                                      color: active
                                          ? _activeProjectAccent.withOpacity(
                                              0.2,
                                            )
                                          : Colors.white.withOpacity(0.08),
                                      borderRadius: BorderRadius.circular(10),
                                    ),
                                    child: Text(
                                      '$count',
                                      style: TextStyle(
                                        fontSize: 10,
                                        fontWeight: FontWeight.bold,
                                        color: active
                                            ? _activeProjectAccent
                                            : Colors.white38,
                                      ),
                                    ),
                                  )
                                : const SizedBox.shrink(
                                    key: ValueKey('empty'),
                                  )),
                    )
                  // For non-project/non-tag/non-today-inbox rows: plain count badge
                  else if (count > 0)
                    Container(
                      padding: const EdgeInsets.symmetric(
                        horizontal: 6,
                        vertical: 2,
                      ),
                      decoration: BoxDecoration(
                        color: active
                            ? _activeProjectAccent.withOpacity(0.2)
                            : Colors.white.withOpacity(0.08),
                        borderRadius: BorderRadius.circular(10),
                      ),
                      child: Text(
                        '$count',
                        style: TextStyle(
                          fontSize: 10,
                          fontWeight: FontWeight.bold,
                          color: active ? _activeProjectAccent : Colors.white38,
                        ),
                      ),
                    ),
                ],
              ),
            ),
          ),
        ),
      );
    }

    Widget sectionHeader(String label, {VoidCallback? onAdd}) => Padding(
      padding: const EdgeInsets.fromLTRB(18, 14, 4, 4),
      child: Row(
        children: [
          Expanded(
            child: Text(
              label.toUpperCase(),
              style: const TextStyle(
                fontSize: 9,
                fontWeight: FontWeight.bold,
                color: Colors.white24,
                letterSpacing: 1.2,
              ),
            ),
          ),
          if (onAdd != null)
            InkWell(
              onTap: onAdd,
              borderRadius: BorderRadius.circular(4),
              child: const Padding(
                padding: EdgeInsets.all(4),
                child: Icon(Icons.add, size: 14, color: Colors.white38),
              ),
            ),
          const SizedBox(width: 4),
        ],
      ),
    );
    return Container(
      color: _tasksBg,
      child: ListView(
        padding: const EdgeInsets.only(top: 8, bottom: 12),
        children: [
          navItem(
            'Today',
            Icons.wb_sunny_outlined,
            'Today',
            todayCount + overdueCount,
          ),
          navItem('Inbox', Icons.inbox_outlined, 'Inbox', inboxCount),
          navItem('Schedule', Icons.calendar_view_week_outlined, 'Schedule', 0),
          navItem('Planner', Icons.view_week_outlined, 'Planner', 0),
          navItem('Boards', Icons.dashboard_outlined, 'Boards', 0),
          const SizedBox(height: 4),
          Divider(color: _tasksBorder, height: 1, indent: 0, endIndent: 0),
          // ── Projects collapsible header ─────────────────────────────
          _sidebarCategoryHeader(
            label: 'Projects',
            expanded: _projectsSectionExpanded,
            onToggle: () => setState(
              () => _projectsSectionExpanded = !_projectsSectionExpanded,
            ),
            onAdd: _showCreateProjectDialog,
            onFilterGroupSort: () => setState(() {
              _filterSidebarTitle = 'All Projects';
              _filterSidebarOpen = true;
            }),
            onSettings: () => setState(() => _tasksNavSection = 'org_projects'),
          ),
          if (_projectsSectionExpanded) ...[
            // ── Projects: shared _buildSidebarFolder + Standard catch-all ────
            () {
              const accent = Color(0xFF4FC3F7);

              final placedPids = {for (final s in _projectFolders.values) ...s};
              final unfoldered = _projectOrder
                  .where(
                    (pid) =>
                        !placedPids.contains(pid) &&
                        _projects.containsKey(pid) &&
                        (!(_projectHiddenFromMenu[pid] ?? false) ||
                            _showHiddenProjects),
                  )
                  .toList();

              // ── Elevated drag feedback (shared with Tags section) ──────
              Widget projFeedback(String title) => Material(
                color: Colors.transparent,
                child: Container(
                  padding: const EdgeInsets.symmetric(
                    horizontal: 12,
                    vertical: 7,
                  ),
                  decoration: BoxDecoration(
                    color: const Color(0xFF1C1F23),
                    borderRadius: BorderRadius.circular(8),
                    border: Border.all(color: accent.withOpacity(0.55)),
                    boxShadow: [
                      BoxShadow(
                        color: Colors.black.withOpacity(0.50),
                        blurRadius: 14,
                        offset: const Offset(0, 5),
                      ),
                      BoxShadow(
                        color: accent.withOpacity(0.08),
                        blurRadius: 10,
                        spreadRadius: 1,
                      ),
                    ],
                  ),
                  child: Row(
                    mainAxisSize: MainAxisSize.min,
                    children: [
                      Icon(
                        Icons.drag_indicator_rounded,
                        size: 12,
                        color: accent,
                      ),
                      const SizedBox(width: 6),
                      Text(
                        title,
                        style: const TextStyle(fontSize: 12, color: accent),
                      ),
                    ],
                  ),
                ),
              );

              // ── Reorder strip (Action B) ───────────────────────────────
              Widget reorderStrip(int insertBefore) => DragTarget<String>(
                onWillAcceptWithDetails: (d) => _projects.containsKey(d.data),
                onAcceptWithDetails: (d) {
                  final pid = d.data;
                  setState(() {
                    for (final s in _projectFolders.values) s.remove(pid);
                    _projectOrder.remove(pid);
                    _projectOrder.insert(
                      insertBefore.clamp(0, _projectOrder.length),
                      pid,
                    );
                  });
                  _saveWorkspace();
                },
                builder: (ctx, candidates, _) {
                  final hot = candidates.isNotEmpty;
                  return AnimatedContainer(
                    duration: const Duration(milliseconds: 100),
                    height: hot ? 4 : 2,
                    margin: const EdgeInsets.symmetric(horizontal: 12),
                    decoration: BoxDecoration(
                      color: hot
                          ? accent.withOpacity(0.75)
                          : Colors.transparent,
                      borderRadius: BorderRadius.circular(2),
                    ),
                  );
                },
              );

              // ── Helper: project row widget ─────────────────────────────
              Widget projItem(String pid) {
                final proj = _projects[pid]!;
                final isHidden = _projectHiddenFromMenu[pid] ?? false;
                final projCount = rootTasks
                    .where(
                      (t) =>
                          t.projectId == pid &&
                          t.status != TaskStatus.done &&
                          t.status != TaskStatus.cancelled,
                    )
                    .length;
                final item = navItem(
                  'proj:$pid',
                  Icons.folder_outlined,
                  isHidden ? '${proj.title} 👁' : proj.title,
                  projCount,
                );
                return Draggable<String>(
                  key: ValueKey('proj_drag_$pid'),
                  data: pid,
                  feedback: projFeedback(proj.title),
                  childWhenDragging: Opacity(opacity: 0.3, child: item),
                  child: item,
                );
              }

              // ── Build the ordered list of folder keys ─────────────────
              // All named folders + '__standard__' sentinel (when needed).
              const standardKey = '__standard__';
              final allProjFolderKeys = <String>[
                ..._projectFolders.keys,
                if (unfoldered.isNotEmpty) standardKey,
              ];

              // Reconcile _projectFolderOrder: keep saved positions, append
              // any new keys that aren't yet tracked, drop stale ones.
              final reconciled = <String>[
                ..._projectFolderOrder.where(allProjFolderKeys.contains),
                ...allProjFolderKeys.where(
                  (k) => !_projectFolderOrder.contains(k),
                ),
              ];
              if (reconciled.join() != _projectFolderOrder.join()) {
                // Update lazily — safe inside build because we only write
                // when the list actually changed.
                WidgetsBinding.instance.addPostFrameCallback((_) {
                  if (mounted) setState(() => _projectFolderOrder = reconciled);
                });
              }
              final effectiveProjOrder = reconciled;

              // ── Builder for a single named-folder widget ───────────────
              Widget buildNamedProjFolder(String folderName, int listIdx) {
                final folderPids = _projectFolders[folderName] ?? {};
                final isCollapsed = _collapsedNavProjectFolders.contains(
                  folderName,
                );
                return DragTarget<String>(
                  key: ValueKey('proj_folder_named_$folderName'),
                  onWillAcceptWithDetails: (d) =>
                      !folderPids.contains(d.data) &&
                      _projects.containsKey(d.data),
                  onAcceptWithDetails: (d) {
                    setState(() {
                      for (final s in _projectFolders.values) s.remove(d.data);
                      _projectFolders
                          .putIfAbsent(folderName, () => {})
                          .add(d.data);
                    });
                    _saveWorkspace();
                  },
                  builder: (ctx, candidateData, _) => _buildSidebarFolder(
                    folderKey: folderName,
                    displayName: folderName,
                    isOver: candidateData.isNotEmpty,
                    isCollapsed: isCollapsed,
                    showDragHandle: true,
                    dragHandleIndex: listIdx,
                    onToggle: () {
                      setState(() {
                        if (isCollapsed)
                          _collapsedNavProjectFolders.remove(folderName);
                        else
                          _collapsedNavProjectFolders.add(folderName);
                      });
                      unawaited(_saveWorkspace());
                    },
                    children: folderPids
                        .where((pid) => _projects.containsKey(pid))
                        .where(
                          (pid) =>
                              !(_projectHiddenFromMenu[pid] ?? false) ||
                              _showHiddenProjects,
                        )
                        .map(projItem)
                        .toList(),
                  ),
                );
              }

              // ── Builder for the Standard (catch-all) folder ───────────
              Widget buildStandardProjFolder(int listIdx) {
                final isCollapsed = _collapsedNavProjectFolders.contains(
                  standardKey,
                );
                final standardChildren = <Widget>[];
                for (int i = 0; i <= unfoldered.length; i++) {
                  final insertPos = i < unfoldered.length
                      ? _projectOrder.indexOf(unfoldered[i])
                      : _projectOrder.length;
                  standardChildren.add(reorderStrip(insertPos));
                  if (i < unfoldered.length) {
                    standardChildren.add(projItem(unfoldered[i]));
                  }
                }
                return DragTarget<String>(
                  key: const ValueKey('proj_folder___standard__'),
                  onWillAcceptWithDetails: (d) =>
                      _projects.containsKey(d.data) &&
                      placedPids.contains(d.data),
                  onAcceptWithDetails: (d) {
                    setState(() {
                      for (final s in _projectFolders.values) s.remove(d.data);
                    });
                    _saveWorkspace();
                  },
                  builder: (ctx, candidateData, _) => _buildSidebarFolder(
                    folderKey: standardKey,
                    displayName: 'Standard',
                    isOver: candidateData.isNotEmpty,
                    isCollapsed: isCollapsed,
                    isStandard: true,
                    showDragHandle: true,
                    dragHandleIndex: listIdx,
                    onToggle: () {
                      setState(() {
                        if (isCollapsed)
                          _collapsedNavProjectFolders.remove(standardKey);
                        else
                          _collapsedNavProjectFolders.add(standardKey);
                      });
                      unawaited(_saveWorkspace());
                    },
                    children: standardChildren,
                  ),
                );
              }

              // ── ReorderableListView wrapping all folder groups ─────────
              return ReorderableListView.builder(
                shrinkWrap: true,
                physics: const NeverScrollableScrollPhysics(),
                buildDefaultDragHandles: false,
                itemCount: effectiveProjOrder.length,
                itemBuilder: (ctx, i) {
                  final key = effectiveProjOrder[i];
                  final child = key == standardKey
                      ? buildStandardProjFolder(i)
                      : buildNamedProjFolder(key, i);
                  return KeyedSubtree(
                    key: ValueKey('proj_reorder_$key'),
                    child: child,
                  );
                },
                onReorder: (oldIdx, newIdx) {
                  setState(() {
                    if (newIdx > oldIdx) newIdx--;
                    final updated = List<String>.from(effectiveProjOrder);
                    final moved = updated.removeAt(oldIdx);
                    updated.insert(newIdx, moved);
                    _projectFolderOrder = updated;
                  });
                  _saveWorkspace();
                },
              );
            }(),
          ],
          const SizedBox(height: 4),
          Divider(color: _tasksBorder, height: 1, indent: 0, endIndent: 0),
          // ── Tags collapsible header ────────────────────────────────
          _sidebarCategoryHeader(
            label: 'Tags',
            expanded: _tagsSectionExpanded,
            onToggle: () =>
                setState(() => _tagsSectionExpanded = !_tagsSectionExpanded),
            onAdd: _showCreateTagDialog,
            onFilterGroupSort: () => setState(() {
              _filterSidebarTitle = 'All Tags';
              _filterSidebarOpen = true;
            }),
            onSettings: () => setState(() => _tasksNavSection = 'org_tags'),
          ),
          if (!_tagsSectionExpanded) const SizedBox.shrink(),
          if (_tagsSectionExpanded)
            ...() {
              const accent = Color(0xFF4FC3F7);

              final allTagStrings = <String>{
                for (final t in _allTasks)
                  ...t.tagIds.map((id) => id.toString()),
                ..._customTags,
              };
              final placedTags = <String>{
                for (final s in _tagFolders.values) ...s,
              };
              final unfolderedTags = allTagStrings
                  .where((t) => !placedTags.contains(t))
                  .toSet();

              // ── Elevated drag feedback ──────────────────────────────────
              Widget tagFeedback(String tag) => Material(
                color: Colors.transparent,
                child: Container(
                  padding: const EdgeInsets.symmetric(
                    horizontal: 12,
                    vertical: 7,
                  ),
                  decoration: BoxDecoration(
                    color: const Color(0xFF1C1F23),
                    borderRadius: BorderRadius.circular(8),
                    border: Border.all(color: accent.withOpacity(0.55)),
                    boxShadow: [
                      BoxShadow(
                        color: Colors.black.withOpacity(0.50),
                        blurRadius: 14,
                        offset: const Offset(0, 5),
                      ),
                      BoxShadow(
                        color: accent.withOpacity(0.08),
                        blurRadius: 10,
                        spreadRadius: 1,
                      ),
                    ],
                  ),
                  child: Row(
                    mainAxisSize: MainAxisSize.min,
                    children: [
                      Icon(
                        Icons.drag_indicator_rounded,
                        size: 12,
                        color: accent,
                      ),
                      const SizedBox(width: 6),
                      Text(
                        tag,
                        style: const TextStyle(fontSize: 12, color: accent),
                      ),
                    ],
                  ),
                ),
              );

              // ── Draggable tag item ──────────────────────────────────────
              Widget tagNavItem(String tag) {
                if (_hiddenTags.contains(tag)) return const SizedBox.shrink();
                final tagCount = rootTasks
                    .where(
                      (t) =>
                          t.tagIds.contains(tag) &&
                          t.status != TaskStatus.done &&
                          t.status != TaskStatus.cancelled,
                    )
                    .length;
                final item = navItem(
                  'tag:$tag',
                  Icons.label_outline,
                  tag,
                  tagCount,
                );
                return Draggable<String>(
                  data: tag,
                  feedback: tagFeedback(tag),
                  childWhenDragging: Opacity(opacity: 0.3, child: item),
                  child: item,
                );
              }

              // ── Reorder strip ───────────────────────────────────────────
              Widget tagReorderStrip(int insertBefore) => DragTarget<String>(
                onWillAcceptWithDetails: (d) => allTagStrings.contains(d.data),
                onAcceptWithDetails: (d) {
                  final tag = d.data;
                  setState(() {
                    for (final s in _tagFolders.values) s.remove(tag);
                    for (final t in unfolderedTags) {
                      if (!_tagOrder.contains(t)) _tagOrder.add(t);
                    }
                    _tagOrder.removeWhere((t) => !allTagStrings.contains(t));
                    _tagOrder.remove(tag);
                    _tagOrder.insert(
                      insertBefore.clamp(0, _tagOrder.length),
                      tag,
                    );
                  });
                  _saveWorkspace();
                },
                builder: (ctx, candidates, _) {
                  final hot = candidates.isNotEmpty;
                  return AnimatedContainer(
                    duration: const Duration(milliseconds: 100),
                    height: hot ? 4 : 2,
                    margin: const EdgeInsets.symmetric(horizontal: 12),
                    decoration: BoxDecoration(
                      color: hot
                          ? accent.withOpacity(0.75)
                          : Colors.transparent,
                      borderRadius: BorderRadius.circular(2),
                    ),
                  );
                },
              );

              // ── Folder block via shared _buildSidebarFolder ─────────────
              // listIdx is the position inside the ReorderableListView so the
              // drag handle can pass the correct index to
              // ReorderableDragStartListener.
              Widget tagFolderWidget({
                required String folderKey,
                required Set<String> tags,
                Widget? dot,
                bool isStandard = false,
                int listIdx = 0,
              }) {
                final collapsed = _collapsedTagCategories.contains(folderKey);
                return DragTarget<String>(
                  onWillAcceptWithDetails: (d) => !tags.contains(d.data),
                  onAcceptWithDetails: (d) {
                    final tag = d.data;
                    for (final s in _tagFolders.values) s.remove(tag);
                    if (!isStandard) {
                      _tagFolders.putIfAbsent(folderKey, () => {}).add(tag);
                    }
                    setState(() {});
                    _saveWorkspace();
                  },
                  builder: (ctx, candidates, _) => _buildSidebarFolder(
                    folderKey: folderKey,
                    displayName: isStandard ? 'Standard' : folderKey,
                    isOver: candidates.isNotEmpty,
                    isCollapsed: collapsed,
                    isStandard: isStandard,
                    dot: dot,
                    showDragHandle: true,
                    dragHandleIndex: listIdx,
                    onToggle: () => setState(() {
                      if (collapsed)
                        _collapsedTagCategories.remove(folderKey);
                      else
                        _collapsedTagCategories.add(folderKey);
                    }),
                    children: isStandard
                        ? () {
                            for (final t in unfolderedTags) {
                              if (!_tagOrder.contains(t)) _tagOrder.add(t);
                            }
                            _tagOrder.removeWhere(
                              (t) => !unfolderedTags.contains(t),
                            );
                            final ordered = _tagOrder
                                .where((t) => !_hiddenTags.contains(t))
                                .toList();
                            return <Widget>[
                              for (int i = 0; i <= ordered.length; i++) ...[
                                tagReorderStrip(i),
                                if (i < ordered.length) tagNavItem(ordered[i]),
                              ],
                            ];
                          }()
                        : tags.map(tagNavItem).toList(),
                  ),
                );
              }

              // ── Determine the reorderable set of tag folder keys ────────
              // Reorderable: '__unfoldered__' sentinel + user-created folders.
              // Trello board folders are pinned at the bottom (outside the
              // ReorderableListView) because they are externally managed.
              const unfolderedKey = '__unfoldered__';
              final trelloBoardNames = _savedBoards
                  .map((b) => b['title'] as String? ?? '')
                  .where((n) => n.isNotEmpty)
                  .toSet();

              final reorderableTagKeys = <String>[
                if (unfolderedTags.isNotEmpty) unfolderedKey,
                ..._tagFolders.keys.where((k) => !trelloBoardNames.contains(k)),
              ];

              // Reconcile _tagFolderOrder with the live key set.
              final reconciledTags = <String>[
                ..._tagFolderOrder.where(reorderableTagKeys.contains),
                ...reorderableTagKeys.where(
                  (k) => !_tagFolderOrder.contains(k),
                ),
              ];
              if (reconciledTags.join() != _tagFolderOrder.join()) {
                WidgetsBinding.instance.addPostFrameCallback((_) {
                  if (mounted) setState(() => _tagFolderOrder = reconciledTags);
                });
              }
              final effectiveTagOrder = reconciledTags;

              // Trello pinned folders (always rendered below reorderable list)
              final trelloPinned = <Widget>[
                for (final b in _savedBoards) ...[
                  () {
                    final boardName = b['title'] as String? ?? '';
                    if (boardName.isEmpty) return const SizedBox.shrink();
                    final boardTags = _tagFolders[boardName] ?? {};
                    if (boardTags.isEmpty) return const SizedBox.shrink();
                    return tagFolderWidget(
                      folderKey: boardName,
                      tags: boardTags,
                      dot: Container(
                        width: 8,
                        height: 8,
                        decoration: BoxDecoration(
                          color: const Color(0xFF0052CC).withOpacity(0.7),
                          shape: BoxShape.circle,
                        ),
                      ),
                      listIdx: 0, // handle hidden for pinned Trello folders
                    );
                  }(),
                ],
              ];

              // ── Build final widget list ─────────────────────────────────
              // ReorderableListView for user-controlled folders +
              // non-reorderable Trello folders pinned below.
              return [
                ReorderableListView.builder(
                  shrinkWrap: true,
                  physics: const NeverScrollableScrollPhysics(),
                  buildDefaultDragHandles: false,
                  itemCount: effectiveTagOrder.length,
                  itemBuilder: (ctx, i) {
                    final key = effectiveTagOrder[i];
                    final child = key == unfolderedKey
                        ? tagFolderWidget(
                            folderKey: unfolderedKey,
                            tags: unfolderedTags,
                            isStandard: true,
                            listIdx: i,
                          )
                        : tagFolderWidget(
                            folderKey: key,
                            tags: _tagFolders[key] ?? {},
                            listIdx: i,
                          );
                    return KeyedSubtree(
                      key: ValueKey('tag_reorder_$key'),
                      child: child,
                    );
                  },
                  onReorder: (oldIdx, newIdx) {
                    setState(() {
                      if (newIdx > oldIdx) newIdx--;
                      final updated = List<String>.from(effectiveTagOrder);
                      final moved = updated.removeAt(oldIdx);
                      updated.insert(newIdx, moved);
                      _tagFolderOrder = updated;
                    });
                    _saveWorkspace();
                  },
                ),
                ...trelloPinned,
              ];
            }(),
        ],
      ),
    );
  }

  /// Main content area for the Tasks tab.
  Widget _buildTasksMainArea() {
    if (_tasksNavSection == 'Schedule') {
      return Row(
        crossAxisAlignment: CrossAxisAlignment.stretch,
        children: [
          Expanded(child: _buildScheduleView()),
          // Sliding detail panel — same as task-list view
          AnimatedContainer(
            duration: const Duration(milliseconds: 200),
            curve: Curves.easeOut,
            width: _taskListDetailOpen ? 300.0 : 0.0,
            child: _taskListDetailOpen && _taskListDetailTask != null
                ? _TaskDetailsPanel(
                    key: ValueKey(_taskListDetailTask!.id),
                    task: _taskListDetailTask!,
                    onSave: (t) async {
                      await _saveTaskToMeta(t);
                      _syncRepeatInstances(t);
                    },
                    onClose: () => setState(() {
                      _taskListDetailOpen = false;
                      _taskListDetailTask = null;
                      _taskDetailExpanded.clear();
                    }),
                    projectColors: _projectColors,
                    projects: _projects,
                    stagingBlocks: _stagingBlocks,
                    activeStagingTaskId: _activeStagingTaskId,
                    stagingPhaseIndex: _stagingPhaseIndex,
                    stagingPhaseStarted: _stagingPhaseStarted,
                    executionSessions:
                        _taskSessions[_taskListDetailTask!.id] ?? [],
                    allTags: {
                      for (final t in _allTasks)
                        ...t.tagIds.map((id) => id.toString()),
                    }.toList(),
                    allTasks: _allTasks,
                    onSubTaskCreated: (sub) => setState(() {
                      _allTasks.add(sub);
                      _saveTaskToMeta(sub);
                    }),
                    activeGeneralTaskId: _activeGeneralTaskId,
                    generalTimerStartedAt: _generalTimerStartedAt,
                    onStartGeneral: _startGeneralTimer,
                    onCancelGeneral: _stopGeneralTimer,
                    onFocusOverlayGeneral: _activeGeneralTaskId != null
                        ? () => _showGeneralOverlay(_activeGeneralTaskId!)
                        : null,
                    onStartStaging: _taskListDetailTask != null
                        ? () => _startTaskStaging(_taskListDetailTask!.id)
                        : null,
                    onStartFlowtime: _taskListDetailTask != null
                        ? () {
                            if (_activeStagingTaskId != null)
                              _stopTaskStaging();
                            if (_activeGeneralTaskId != null)
                              _stopGeneralTimer();
                            _startFlowtimeTimer(_taskListDetailTask!.id);
                          }
                        : null,
                    onRepeatChanged: (t) {
                      if (t.repeatParentId != null) {
                        _propagateRepeatFromInstance(t);
                      } else {
                        _propagateRepeat(t);
                      }
                    },
                    onPropagateScoped: _propagateScopedRepeat,
                    onApplyForward: _applyForwardFromInstance,
                    onApplyScoped: _applyFromParentScoped,
                    onOpenTaskNote: (noteId) => setState(() {
                      _isNotesView = true;
                      _isTasksView = false;
                      _isSettingsView = false;
                      _notesNavSection = 'editor';
                      _activeNoteId = noteId;
                      if (!_openNoteTabs.contains(noteId))
                        _openNoteTabs.add(noteId);
                    }),
                  )
                : const SizedBox.shrink(),
          ),
        ],
      );
    }
    if (_tasksNavSection == 'Planner') return _buildPlannerView();
    if (_tasksNavSection == 'Boards') return _buildBoardsView();
    if (_tasksNavSection.startsWith('quick_history:')) {
      return _buildQuickHistoryView(_tasksNavSection.substring(14));
    }
    if (_tasksNavSection.startsWith('worklog:')) {
      return _buildWorklogView(_tasksNavSection.substring(8));
    }
    if (_tasksNavSection.startsWith('metrics:')) {
      return _buildMetricsView(_tasksNavSection.substring(8));
    }
    if (_tasksNavSection == 'org_projects')
      return _buildOrgView(isProjects: true);
    if (_tasksNavSection == 'org_tags') return _buildOrgView(isProjects: false);
    // Notes org views — routes set by Notes sidebar settings gear
    if (_tasksNavSection == 'notes_org_projects')
      return _buildNotesOrgView(isProjects: true);
    if (_tasksNavSection == 'notes_org_tasks')
      return _buildNotesOrgView(isProjects: false);
    // Canvas category settings — route set by _CanvasSectionMenuPanel Settings
    if (_tasksNavSection.startsWith('canvas_category_settings:')) {
      final cat = _tasksNavSection.substring(
        'canvas_category_settings:'.length,
      );
      return _buildCanvasCategorySettingsView(cat);
    }
    if (_tasksNavSection.startsWith('settings:')) {
      final ctx = _tasksNavSection.substring(9);
      if (ctx == 'Today' || ctx == 'Inbox') {
        return _buildViewThemeSettingsView(ctx);
      }
      if (ctx.startsWith('tag:')) {
        return _buildTagSettingsView(ctx.substring(4));
      }
      return _buildProjectSettingsView(ctx);
    }
    return Row(
      children: [
        Expanded(
          child: Container(
            decoration: BoxDecoration(
              color: _tasksBg,
              border: Border(
                top: BorderSide(
                  color: _activeProjectAccent.withOpacity(0.35),
                  width: 2,
                ),
              ),
            ),
            child: Column(
              crossAxisAlignment: CrossAxisAlignment.stretch,
              children: [
                if (_activeStagingTaskId != null) _buildStagingBar(),
                if (_activeGeneralTaskId != null) _buildGeneralBar(),
                if (_activeFlowtimeTaskId != null) _buildFlowtimeBar(),
                Expanded(
                  child: Row(
                    crossAxisAlignment: CrossAxisAlignment.stretch,
                    children: [Expanded(child: _buildTasksList())],
                  ),
                ),
              ],
            ),
          ),
        ),
        // Sliding detail panel
        AnimatedContainer(
          duration: const Duration(milliseconds: 200),
          curve: Curves.easeOut,
          width: _taskListDetailOpen ? 300.0 : 0.0,
          child: _taskListDetailOpen && _taskListDetailTask != null
              ? _TaskDetailsPanel(
                  key: ValueKey(_taskListDetailTask!.id),
                  task: _taskListDetailTask!,
                  onSave: (t) async {
                    await _saveTaskToMeta(t);
                    _syncRepeatInstances(t);
                  },
                  onClose: () => setState(() {
                    _taskListDetailOpen = false;
                    _taskListDetailTask = null;
                    _taskDetailExpanded.clear();
                  }),
                  projectColors: _projectColors,
                  projects: _projects,
                  stagingBlocks: _stagingBlocks,
                  activeStagingTaskId: _activeStagingTaskId,
                  stagingPhaseIndex: _stagingPhaseIndex,
                  stagingPhaseStarted: _stagingPhaseStarted,
                  executionSessions:
                      _taskSessions[_taskListDetailTask!.id] ?? [],
                  allTags: {
                    for (final t in _allTasks)
                      ...t.tagIds.map((id) => id.toString()),
                  }.toList(),
                  allTasks: _allTasks,
                  onSubTaskCreated: (sub) => setState(() {
                    _allTasks.add(sub);
                    _saveTaskToMeta(sub);
                  }),
                  activeGeneralTaskId: _activeGeneralTaskId,
                  generalTimerStartedAt: _generalTimerStartedAt,
                  onStartGeneral: _startGeneralTimer,
                  onCancelGeneral: _stopGeneralTimer,
                  onFocusOverlayGeneral: _activeGeneralTaskId != null
                      ? () => _showGeneralOverlay(_activeGeneralTaskId!)
                      : null,
                  onStartStaging: _taskListDetailTask != null
                      ? () => _startTaskStaging(_taskListDetailTask!.id)
                      : null,
                  onStartFlowtime: _taskListDetailTask != null
                      ? () {
                          if (_activeStagingTaskId != null) _stopTaskStaging();
                          if (_activeGeneralTaskId != null) _stopGeneralTimer();
                          _startFlowtimeTimer(_taskListDetailTask!.id);
                        }
                      : null,
                  onRepeatChanged: (t) {
                    if (t.repeatParentId != null) {
                      _propagateRepeatFromInstance(t);
                    } else {
                      _propagateRepeat(t);
                    }
                  },
                  onPropagateScoped: _propagateScopedRepeat,
                  onApplyForward: _applyForwardFromInstance,
                  onApplyScoped: _applyFromParentScoped,
                  onOpenTaskNote: (noteId) => setState(() {
                    _isNotesView = true;
                    _isTasksView = false;
                    _isSettingsView = false;
                    _notesNavSection = 'editor';
                    _activeNoteId = noteId;
                    if (!_openNoteTabs.contains(noteId))
                      _openNoteTabs.add(noteId);
                  }),
                )
              : const SizedBox.shrink(),
        ),
      ],
    );
