  Widget _buildStagingBar() {
    if (_activeStagingTaskId == null || _stagingPhaseStarted == null) {
      return const SizedBox.shrink();
    }
    final task = _allTasks.firstWhere(
      (t) => t.id == _activeStagingTaskId,
      orElse: () => Task(
        id: '',
        title: '…',
        isDone: false,
        projectId: '',
        subTaskIds: [],
        timeSpent: 0,
        attachments: [],
        tagIds: [],
      ),
    );
    final blocks = _stagingBlocks.isEmpty
        ? [
            _StagingBlock(type: _StagingType.work, minutes: 25),
            _StagingBlock(type: _StagingType.rest, minutes: 5),
          ]
        : _stagingBlocks;
    final phaseIdx = _stagingPhaseIndex % blocks.length;
    final currentBlock = blocks[phaseIdx];
    final isWork = currentBlock.type == _StagingType.work;
    final phaseColor = isWork
        ? const Color(0xFF4FC3F7)
        : const Color(0xFF81C784);
    final phaseLabel = isWork ? 'WORK' : 'REST';

    final elapsed = DateTime.now().difference(_stagingPhaseStarted!).inSeconds;
    final total = currentBlock.minutes * 60;
    final remaining = (total - elapsed).clamp(0, total);
    final mm = (remaining ~/ 60).toString().padLeft(2, '0');
    final ss = (remaining % 60).toString().padLeft(2, '0');
    final progress = (elapsed / total).clamp(0.0, 1.0);

    return Container(
      height: 52,
      decoration: BoxDecoration(
        color: const Color(0xFF131618),
        border: Border(
          top: BorderSide(color: phaseColor.withOpacity(0.2), width: 1),
          bottom: BorderSide(color: Colors.white.withOpacity(0.05), width: 1),
        ),
      ),
      child: Stack(
        children: [
          // Progress fill
          FractionallySizedBox(
            widthFactor: progress,
            child: Container(
              decoration: BoxDecoration(
                gradient: LinearGradient(
                  colors: [
                    phaseColor.withOpacity(0.08),
                    phaseColor.withOpacity(0.04),
                  ],
                ),
              ),
            ),
          ),
          // Content row
          Center(
            child: Padding(
              padding: const EdgeInsets.symmetric(horizontal: 16),
              child: Row(
                children: [
                  // Phase icon + label
                  Container(
                    padding: const EdgeInsets.symmetric(
                      horizontal: 7,
                      vertical: 2,
                    ),
                    decoration: BoxDecoration(
                      color: phaseColor.withOpacity(0.1),
                      borderRadius: BorderRadius.circular(10),
                      border: Border.all(color: phaseColor.withOpacity(0.2)),
                    ),
                    child: Row(
                      mainAxisSize: MainAxisSize.min,
                      children: [
                        Icon(
                          isWork ? Icons.timer_outlined : Icons.coffee_outlined,
                          size: 11,
                          color: phaseColor.withOpacity(0.8),
                        ),
                        const SizedBox(width: 4),
                        Text(
                          phaseLabel,
                          style: TextStyle(
                            fontSize: 9,
                            fontWeight: FontWeight.w700,
                            letterSpacing: 0.8,
                            color: phaseColor.withOpacity(0.8),
                          ),
                        ),
                      ],
                    ),
                  ),
                  const SizedBox(width: 10),
                  // Countdown
                  Text(
                    '$mm:$ss',
                    style: const TextStyle(
                      fontSize: 13,
                      fontWeight: FontWeight.w300,
                      color: Colors.white70,
                      letterSpacing: 1.5,
                      fontFeatures: [FontFeature.tabularFigures()],
                    ),
                  ),
                  const SizedBox(width: 8),
                  Text(
                    '– ${task.title} is running',
                    style: const TextStyle(
                      fontSize: 11,
                      color: Color(0xFF5A6070),
                    ),
                    overflow: TextOverflow.ellipsis,
                  ),
                  const Spacer(),
                  // Stop button
                  GestureDetector(
                    onTap: _stopTaskStaging,
                    child: const Text(
                      'Stop',
                      style: TextStyle(fontSize: 11, color: Color(0xFF5A6070)),
                    ),
                  ),
                  const SizedBox(width: 16),
                  // Return to overlay button
                  GestureDetector(
                    onTap: () => _showStagingOverlay(_activeStagingTaskId!),
                    child: Text(
                      'To Focus Overlay',
                      style: TextStyle(
                        fontSize: 11,
                        color: phaseColor.withOpacity(0.7),
                      ),
                    ),
                  ),
                  const SizedBox(width: 4),
                ],
              ),
            ),
          ),
        ],
      ),
    );
  }

  Widget _buildGeneralBar() {
    if (_activeGeneralTaskId == null || _generalTimerStartedAt == null) {
      return const SizedBox.shrink();
    }
    final task = _allTasks.firstWhere(
      (t) => t.id == _activeGeneralTaskId,
      orElse: () => Task(
        id: '',
        title: '…',
        isDone: false,
        projectId: '',
        subTaskIds: [],
        timeSpent: 0,
        attachments: [],
        tagIds: [],
      ),
    );

    const barColor = Color(0xFF4CAF50); // matches "Start Countdown" button
    final spentMs = task.timeSpent; // updated live by timer
    final spentSecs = spentMs ~/ 1000;
    final durationSecs = task.durationMinutes * 60;
    final hasPlan = durationSecs > 0;
    final progress = hasPlan ? (spentSecs / durationSecs).clamp(0.0, 1.0) : 0.0;
    final overrun = hasPlan && spentSecs > durationSecs;
    final displaySecs = hasPlan ? (durationSecs - spentSecs).abs() : spentSecs;
    final sign = overrun ? '+' : '';
    final absDisplay = displaySecs.abs();
    final mm = (absDisplay ~/ 60).toString().padLeft(2, '0');
    final ss = (absDisplay % 60).toString().padLeft(2, '0');

    return Container(
      height: 52,
      decoration: BoxDecoration(
        color: const Color(0xFF131618),
        border: Border(
          top: BorderSide(
            color: (overrun ? const Color(0xFFEF5350) : barColor).withOpacity(
              0.2,
            ),
            width: 1,
          ),
          bottom: BorderSide(color: Colors.white.withOpacity(0.05), width: 1),
        ),
      ),
      child: Stack(
        children: [
          // Progress fill
          FractionallySizedBox(
            widthFactor: progress,
            child: Container(
              decoration: BoxDecoration(
                gradient: LinearGradient(
                  colors: [
                    (overrun ? const Color(0xFFEF5350) : barColor).withOpacity(
                      0.08,
                    ),
                    (overrun ? const Color(0xFFEF5350) : barColor).withOpacity(
                      0.03,
                    ),
                  ],
                ),
              ),
            ),
          ),
          // Content
          Center(
            child: Padding(
              padding: const EdgeInsets.symmetric(horizontal: 16),
              child: Row(
                children: [
                  // Badge
                  Container(
                    padding: const EdgeInsets.symmetric(
                      horizontal: 7,
                      vertical: 2,
                    ),
                    decoration: BoxDecoration(
                      color: barColor.withOpacity(0.1),
                      borderRadius: BorderRadius.circular(10),
                      border: Border.all(color: barColor.withOpacity(0.2)),
                    ),
                    child: Row(
                      mainAxisSize: MainAxisSize.min,
                      children: [
                        Icon(
                          Icons.radio_button_checked,
                          size: 9,
                          color: barColor.withOpacity(0.8),
                        ),
                        const SizedBox(width: 4),
                        Text(
                          'COUNTDOWN',
                          style: TextStyle(
                            fontSize: 9,
                            fontWeight: FontWeight.w700,
                            letterSpacing: 0.8,
                            color: barColor.withOpacity(0.8),
                          ),
                        ),
                      ],
                    ),
                  ),
                  const SizedBox(width: 10),
                  // Elapsed / countdown
                  Text(
                    '$sign$mm:$ss',
                    style: TextStyle(
                      fontSize: 13,
                      fontWeight: FontWeight.w300,
                      color: overrun ? const Color(0xFFEF5350) : Colors.white70,
                      letterSpacing: 1.5,
                      fontFeatures: const [FontFeature.tabularFigures()],
                    ),
                  ),
                  const SizedBox(width: 8),
                  Text(
                    '– ${task.title} is running',
                    style: const TextStyle(
                      fontSize: 11,
                      color: Color(0xFF5A6070),
                    ),
                    overflow: TextOverflow.ellipsis,
                  ),
                  const Spacer(),
                  GestureDetector(
                    onTap: _stopGeneralTimer,
                    child: const Text(
                      'Stop',
                      style: TextStyle(fontSize: 11, color: Color(0xFF5A6070)),
                    ),
                  ),
                  const SizedBox(width: 16),
                  GestureDetector(
                    onTap: () => _showGeneralOverlay(_activeGeneralTaskId!),
                    child: Text(
                      'To Focus Overlay',
                      style: TextStyle(
                        fontSize: 11,
                        color: barColor.withOpacity(0.7),
                      ),
                    ),
                  ),
                  const SizedBox(width: 4),
                ],
              ),
            ),
          ),
        ],
      ),
    );
  }

