  /// Worklog view — delegates to the refactored StatefulWidget.
  Widget _buildWorklogView(String ctx) {
    final List<Task> tasks;
    if (ctx.startsWith('proj:')) {
      final pid = ctx.substring(5);
      tasks = _allTasks.where((t) => t.projectId == pid).toList();
    } else if (ctx.startsWith('tag:')) {
      final tag = ctx.substring(4);
      tasks = _allTasks.where((t) => t.tagIds.contains(tag)).toList();
    } else {
      tasks = List.from(_allTasks);
    }
    return _WorklogView(
      tasks: tasks,
      taskSessions: _taskSessions,
      accentColor: _activeProjectAccent,
    );
  }

  /// Metrics view — delegates to _MetricsView StatefulWidget.
  Widget _buildMetricsView(String ctx) {
    final List<Task> tasks;
    String contextLabel;
    DateTime? projectCreatedAt;
    if (ctx.startsWith('proj:')) {
      final pid = ctx.substring(5);
      tasks = _allTasks.where((t) => t.projectId == pid).toList();
      contextLabel = _projects[pid]?.title ?? 'Project';
      projectCreatedAt = _projects[pid]?.createdAt;
    } else if (ctx.startsWith('tag:')) {
      final tag = ctx.substring(4);
      tasks = _allTasks.where((t) => t.tagIds.contains(tag)).toList();
      contextLabel = '#$tag';
    } else {
      tasks = List.from(_allTasks);
      contextLabel = 'All Tasks';
    }
    return _MetricsView(
      tasks: tasks,
      taskSessions: _taskSessions,
      contextLabel: contextLabel,
      projectCreatedAt: projectCreatedAt,
      accentColor: _activeProjectAccent,
    );
  }

  /// Theme-only settings page for Today / Inbox views.
  Widget _buildViewThemeSettingsView(String viewId) {
    final label = viewId; // 'Today' or 'Inbox'
    final icon = viewId == 'Today'
        ? Icons.wb_sunny_outlined
        : Icons.inbox_outlined;
    return _ViewThemeSettingsView(
      key: ValueKey('view-settings:$viewId'),
      viewId: viewId,
      label: label,
      icon: icon,
      initialColor: _viewColors[viewId] ?? _tasksAccent,
      onApply: (Color newColor) {
        setState(() => _viewColors[viewId] = newColor);
        _saveWorkspace();
      },
      onShowColorPicker: (initialColor, onPicked) => _showUnifiedColorPicker(
        title: '$label Color',
        initialColor: initialColor,
        showRecentColors: true,
        onApply: onPicked,
      ),
      onBack: () => setState(() => _tasksNavSection = viewId),
    );
  }

  /// Project Settings full-page view — replaces the old popup dialog.
  Widget _buildProjectSettingsView(String ctx) {
    if (!ctx.startsWith('proj:')) return const SizedBox.shrink();
    final pid = ctx.substring(5);
    final proj = _projects[pid];
    if (proj == null) return const SizedBox.shrink();
    return _ProjectSettingsView(
      key: ValueKey('proj-settings:$pid'),
      projectId: pid,
      project: proj,
      initialColor: _projectColors[pid] ?? Colors.blueAccent,
      initialIcon: _projectIcons[pid] ?? '',
      initialBacklogEnabled: _projectBacklogEnabled[pid] ?? false,
      initialHiddenFromMenu: _projectHiddenFromMenu[pid] ?? false,
      onApply:
          ({
            required String newTitle,
            required String newIcon,
            required Color newColor,
            required bool backlogEnabled,
            required bool hiddenFromMenu,
          }) {
            setState(() {
              if (newTitle.isNotEmpty && newTitle != proj.title) {
                _projects[pid] = Project(
                  id: proj.id,
                  title: newTitle,
                  createdAt: proj.createdAt,
                );
              }
              _projectColors[pid] = newColor;
              if (newIcon.isEmpty) {
                _projectIcons.remove(pid);
              } else {
                _projectIcons[pid] = newIcon;
              }
              _projectBacklogEnabled[pid] = backlogEnabled;
              _projectHiddenFromMenu[pid] = hiddenFromMenu;
            });
            _saveWorkspace();
          },
      onShowColorPicker: (initialColor, onPicked) => _showUnifiedColorPicker(
        title: 'Project Color',
        initialColor: initialColor,
        showRecentColors: true,
        onApply: onPicked,
      ),
      onBack: () => setState(() => _tasksNavSection = 'proj:$pid'),
    );
  }

  /// Quick History view — shows sessions grouped by week then by day.
  /// Quick History view — delegates to _QuickHistoryView StatefulWidget.
  Widget _buildQuickHistoryView(String ctx) {
    final List<Task> tasks;
    if (ctx.startsWith('proj:')) {
      final pid = ctx.substring(5);
      tasks = _allTasks.where((t) => t.projectId == pid).toList();
    } else if (ctx.startsWith('tag:')) {
      final tag = ctx.substring(4);
      tasks = _allTasks.where((t) => t.tagIds.contains(tag)).toList();
    } else {
      tasks = List.from(_allTasks);
    }
    return _QuickHistoryView(
      tasks: tasks,
      taskSessions: _taskSessions,
      projectColors: _projectColors,
      accentColor: _activeProjectAccent,
    );
  }

