  // ── Spec §3+4: shared folder widget — identical styling for Projects & Tags ─
  //
  // Parameters
  //   folderKey      — collapse-state key (unique per folder)
  //   displayName    — rendered label (may differ from folderKey)
  //   isOver         — true while a Draggable hovers over the DragTarget wrapper
  //   isCollapsed    — whether the folder body is hidden
  //   onToggle       — flip collapsed/expanded
  //   children       — the item rows inside this folder
  //   dot            — optional badge (e.g. Trello colour dot)
  //   isStandard     — true for the implicit "Standard" catch-all folder
  Widget _buildSidebarFolder({
    required String folderKey,
    required String displayName,
    required bool isOver,
    required bool isCollapsed,
    required VoidCallback onToggle,
    required List<Widget> children,
    Widget? dot,
    bool isStandard = false,
    // When true a drag-indicator handle is prepended to the header row so the
    // folder can be grabbed for ReorderableListView reordering.
    bool showDragHandle = false,
    int dragHandleIndex = 0,
  }) {
    // ── Colour tokens ──────────────────────────────────────────────────────
    const accent = Color(0xFF4FC3F7);
    const folderYellow = Color(0xFFEBCB8B);

    return AnimatedContainer(
      duration: const Duration(milliseconds: 120),
      margin: const EdgeInsets.only(top: 1),
      decoration: isOver
          ? BoxDecoration(
              color: accent.withOpacity(0.07),
              borderRadius: BorderRadius.circular(6),
              border: Border.all(color: accent.withOpacity(0.30), width: 1),
            )
          : const BoxDecoration(),
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.stretch,
        children: [
          // ── Header row ────────────────────────────────────────────────
          InkWell(
            onTap: onToggle,
            hoverColor: Colors.white.withOpacity(0.04),
            borderRadius: BorderRadius.circular(5),
            child: Padding(
              padding: const EdgeInsets.fromLTRB(12, 6, 10, 6),
              child: Row(
                children: [
                  // ── Reorder handle (only when inside a ReorderableListView) ──
                  if (showDragHandle)
                    ReorderableDragStartListener(
                      index: dragHandleIndex,
                      child: MouseRegion(
                        cursor: SystemMouseCursors.grab,
                        child: Padding(
                          padding: const EdgeInsets.only(right: 5),
                          child: Icon(
                            Icons.drag_indicator_rounded,
                            size: 13,
                            color: Colors.white.withOpacity(0.18),
                          ),
                        ),
                      ),
                    ),
                  // Leading icon
                  if (dot != null) ...[dot, const SizedBox(width: 5)],
                  Icon(
                    isOver
                        ? Icons.folder_open
                        : isCollapsed
                        ? Icons.folder_outlined
                        : Icons.folder_open_outlined,
                    size: 13,
                    color: isOver
                        ? accent
                        : isStandard
                        ? Colors.white24
                        : folderYellow,
                  ),
                  const SizedBox(width: 7),
                  // Name
                  Expanded(
                    child: Text(
                      displayName,
                      overflow: TextOverflow.ellipsis,
                      style: TextStyle(
                        fontSize: 11,
                        fontWeight: FontWeight.w600,
                        letterSpacing: isStandard ? 0.6 : 0.0,
                        color: isOver
                            ? accent
                            : isStandard
                            ? Colors.white38
                            : Colors.white70,
                      ),
                    ),
                  ),
                  // Trailing — drop hint or chevron
                  if (isOver)
                    Icon(
                      Icons.add_rounded,
                      size: 12,
                      color: accent.withOpacity(0.75),
                    )
                  else
                    AnimatedRotation(
                      turns: isCollapsed ? 0.0 : 0.25,
                      duration: const Duration(milliseconds: 150),
                      child: const Icon(
                        Icons.chevron_right_rounded,
                        size: 13,
                        color: Color(0xFF4B5563),
                      ),
                    ),
                ],
              ),
            ),
          ),
          // ── Children (16px left indent) ────────────────────────────────
          if (!isCollapsed)
            Padding(
              padding: const EdgeInsets.only(left: 14),
              child: Column(
                crossAxisAlignment: CrossAxisAlignment.stretch,
                children: children,
              ),
            ),
        ],
      ),
    );
  }

