  Widget _buildTagSettingsView(String tagName) {
    return _TagSettingsView(
      key: ValueKey('tag_settings:$tagName'),
      tagName: tagName,
      initialColor: _tagColors[tagName],
      initialIcon: _tagIcons[tagName] ?? '',
      isHidden: _hiddenTags.contains(tagName),
      tagFolders: _tagFolders,
      onChanged:
          ({
            required String newName,
            required Color? color,
            required String icon,
            required bool hidden,
          }) {
            setState(() {
              // Rename: update all references
              if (newName != tagName) {
                // tasks
                for (final t in _allTasks) {
                  final idx = t.tagIds.indexOf(tagName);
                  if (idx >= 0) t.tagIds[idx] = newName;
                }
                // customTags
                if (_customTags.remove(tagName)) _customTags.add(newName);
                // hiddenTags
                if (_hiddenTags.remove(tagName)) _hiddenTags.add(newName);
                // tagFolders
                for (final s in _tagFolders.values) {
                  if (s.remove(tagName)) s.add(newName);
                }
                // tagColors / tagIcons
                if (_tagColors.containsKey(tagName)) {
                  _tagColors[newName] = _tagColors.remove(tagName)!;
                }
                if (_tagIcons.containsKey(tagName)) {
                  _tagIcons[newName] = _tagIcons.remove(tagName)!;
                }
                // navigate to new name
                _tasksNavSection = 'settings:tag:$newName';
              }
              // color
              if (color != null)
                _tagColors[newName] = color;
              else
                _tagColors.remove(newName);
              // icon
              if (icon.isNotEmpty)
                _tagIcons[newName] = icon;
              else
                _tagIcons.remove(newName);
              // visibility
              if (hidden)
                _hiddenTags.add(newName);
              else
                _hiddenTags.remove(newName);
            });
            _saveWorkspace();
          },
    );
  }

