  // ── Notes Settings: folder organiser (Projects Settings design) ────────────
  Widget _buildNotesOrgNotesView() {
    // Reconcile _noteFolderOrder with current _noteFolders keys.
    final folderIds = _noteFolders.keys.toSet();
    _noteFolderOrder.removeWhere((id) => !folderIds.contains(id));
    for (final id in _noteFolders.keys) {
      if (!_noteFolderOrder.contains(id)) _noteFolderOrder.add(id);
    }

    const bg = Color(0xFF181A1B);
    const surface = Color(0xFF212426);
    const border = Color(0xFF2C2F32);
    const accent = Color(0xFF4FC3F7);
    const folderBlue = Color(0xFF88C0D0);

    // ── Filter folders by search query ────────────────────────────────────
    final filteredOrder = _notesOrgNotesSearchQuery.isEmpty
        ? List<String>.from(_noteFolderOrder)
        : _noteFolderOrder.where((fid) {
            final f = _noteFolders[fid];
            return f != null &&
                f.name.toLowerCase().contains(
                  _notesOrgNotesSearchQuery.toLowerCase(),
                );
          }).toList();

    // ── Single note row inside a folder ───────────────────────────────────
    Widget noteRow(Note note) {
      IconData noteIcon;
      switch (note.type) {
        case NoteType.task:
          noteIcon = Icons.task_alt_rounded;
          break;
        case NoteType.project:
          noteIcon = Icons.folder_outlined;
          break;
        default:
          noteIcon = Icons.description_outlined;
      }
      return Container(
        margin: const EdgeInsets.symmetric(horizontal: 12, vertical: 2),
        padding: const EdgeInsets.fromLTRB(10, 7, 8, 7),
        decoration: BoxDecoration(
          color: surface,
          borderRadius: BorderRadius.circular(6),
          border: Border.all(color: border),
        ),
        child: Row(
          children: [
            Icon(noteIcon, size: 13, color: Colors.white38),
            const SizedBox(width: 9),
            Expanded(
              child: Text(
                note.title.isEmpty ? '(Untitled)' : note.title,
                style: const TextStyle(fontSize: 12, color: Colors.white70),
                maxLines: 1,
                overflow: TextOverflow.ellipsis,
              ),
            ),
          ],
        ),
      );
    }

    // ── Standard folder block (read-only — no rename / delete) ───────────
    Widget standardBlock() {
      const kStdKey = '__standard__';
      final notesInFolder = _notes.values
          .where((n) => n.folderId == null)
          .toList();
      final isCollapsed = _notesOrgNotesCollapsed.contains(kStdKey);

      return AnimatedContainer(
        key: const ValueKey('notesorg_folder___standard__'),
        duration: const Duration(milliseconds: 100),
        margin: const EdgeInsets.fromLTRB(12, 6, 12, 0),
        decoration: BoxDecoration(
          color: surface.withOpacity(0.5),
          borderRadius: BorderRadius.circular(8),
          border: Border.all(color: border),
        ),
        child: Column(
          crossAxisAlignment: CrossAxisAlignment.stretch,
          children: [
            // ── Header row ───────────────────────────────────────────────
            InkWell(
              onTap: () {
                setState(() {
                  if (isCollapsed) {
                    _notesOrgNotesCollapsed.remove(kStdKey);
                  } else {
                    _notesOrgNotesCollapsed.add(kStdKey);
                  }
                });
                unawaited(_saveWorkspace());
              },
              borderRadius: const BorderRadius.vertical(
                top: Radius.circular(8),
              ),
              child: Padding(
                padding: const EdgeInsets.fromLTRB(10, 8, 8, 8),
                child: Row(
                  children: [
                    AnimatedRotation(
                      turns: isCollapsed ? -0.25 : 0,
                      duration: const Duration(milliseconds: 150),
                      child: const Icon(
                        Icons.expand_more_rounded,
                        size: 13,
                        color: Colors.white30,
                      ),
                    ),
                    const SizedBox(width: 5),
                    Icon(Icons.folder_rounded, size: 13, color: Colors.white24),
                    const SizedBox(width: 7),
                    const Expanded(
                      child: Text(
                        'Standard',
                        style: TextStyle(
                          fontSize: 12,
                          fontWeight: FontWeight.w600,
                          color: Colors.white38,
                          letterSpacing: 0.3,
                        ),
                      ),
                    ),
                    // Count badge
                    Container(
                      padding: const EdgeInsets.symmetric(
                        horizontal: 5,
                        vertical: 1,
                      ),
                      decoration: BoxDecoration(
                        color: Colors.white.withOpacity(0.06),
                        borderRadius: BorderRadius.circular(8),
                      ),
                      child: Text(
                        '${notesInFolder.length}',
                        style: const TextStyle(
                          fontSize: 9,
                          fontWeight: FontWeight.bold,
                          color: Colors.white30,
                        ),
                      ),
                    ),
                    // Read-only label instead of rename/delete buttons
                    const SizedBox(width: 6),
                    const Tooltip(
                      message: 'Built-in folder — cannot be renamed or deleted',
                      child: Padding(
                        padding: EdgeInsets.all(4),
                        child: Icon(
                          Icons.lock_outline_rounded,
                          size: 11,
                          color: Colors.white12,
                        ),
                      ),
                    ),
                  ],
                ),
              ),
            ),
            // ── Notes — animate in/out on collapse ───────────────────────
            AnimatedSize(
              duration: const Duration(milliseconds: 180),
              curve: Curves.easeInOut,
              alignment: Alignment.topCenter,
              child: isCollapsed
                  ? const SizedBox.shrink()
                  : Column(
                      crossAxisAlignment: CrossAxisAlignment.stretch,
                      children: [
                        if (notesInFolder.isNotEmpty)
                          const Divider(color: border, height: 1),
                        ...notesInFolder.map(noteRow),
                        if (notesInFolder.isEmpty)
                          Padding(
                            padding: const EdgeInsets.fromLTRB(14, 8, 14, 10),
                            child: Text(
                              'No notes in this folder',
                              style: TextStyle(
                                fontSize: 11,
                                color: Colors.white.withOpacity(0.24),
                                fontStyle: FontStyle.italic,
                              ),
                            ),
                          ),
                      ],
                    ),
            ),
          ],
        ),
      );
    }

    // ── Named folder block (Projects Settings _folderBlock design) ────────
    Widget folderBlock(String fid) {
      final folder = _noteFolders[fid];
      if (folder == null) return const SizedBox.shrink();

      final notesInFolder = _notes.values
          .where((n) => n.folderId == fid)
          .toList();
      final isCollapsed = _notesOrgNotesCollapsed.contains(fid);
      final isRenaming = _notesOrgNotesRenamingFolder == fid;

      return AnimatedContainer(
        key: ValueKey('notesorg_folder_$fid'),
        duration: const Duration(milliseconds: 100),
        margin: const EdgeInsets.fromLTRB(12, 6, 12, 0),
        decoration: BoxDecoration(
          color: surface.withOpacity(0.5),
          borderRadius: BorderRadius.circular(8),
          border: Border.all(color: border),
        ),
        child: Column(
          crossAxisAlignment: CrossAxisAlignment.stretch,
          children: [
            // ── Header row — tappable to collapse ───────────────────────
            InkWell(
              onTap: () {
                setState(() {
                  if (isCollapsed) {
                    _notesOrgNotesCollapsed.remove(fid);
                  } else {
                    _notesOrgNotesCollapsed.add(fid);
                  }
                });
                unawaited(_saveWorkspace());
              },
              borderRadius: const BorderRadius.vertical(
                top: Radius.circular(8),
              ),
              child: Padding(
                padding: const EdgeInsets.fromLTRB(10, 8, 8, 8),
                child: Row(
                  children: [
                    // Collapse chevron
                    AnimatedRotation(
                      turns: isCollapsed ? -0.25 : 0,
                      duration: const Duration(milliseconds: 150),
                      child: const Icon(
                        Icons.expand_more_rounded,
                        size: 13,
                        color: Colors.white30,
                      ),
                    ),
                    const SizedBox(width: 5),
                    Icon(
                      Icons.folder_rounded,
                      size: 13,
                      color: folderBlue.withOpacity(0.7),
                    ),
                    const SizedBox(width: 7),
                    // Name / inline rename field
                    Expanded(
                      child: isRenaming
                          ? TextField(
                              controller: _notesOrgNotesRenameFolderCtrl,
                              autofocus: true,
                              style: const TextStyle(
                                fontSize: 12,
                                color: Colors.white,
                              ),
                              decoration: const InputDecoration(
                                isDense: true,
                                contentPadding: EdgeInsets.zero,
                                border: InputBorder.none,
                              ),
                              onSubmitted: (v) async {
                                final n = v.trim();
                                if (n.isNotEmpty && n != folder.name) {
                                  final oldName = folder.name;
                                  setState(() => _noteFolders[fid]?.name = n);
                                  try {
                                    final oldDir = Directory(
                                      '$_notesDir/notes/$oldName',
                                    );
                                    final newDir = Directory(
                                      '$_notesDir/notes/$n',
                                    );
                                    if (await oldDir.exists()) {
                                      await oldDir.rename(newDir.path);
                                    }
                                  } catch (e) {
                                    debugPrint(
                                      'notesOrg inline rename error: $e',
                                    );
                                  }
                                  _saveNotesMeta();
                                }
                                setState(
                                  () => _notesOrgNotesRenamingFolder = null,
                                );
                              },
                            )
                          : Text(
                              folder.name,
                              style: const TextStyle(
                                fontSize: 12,
                                fontWeight: FontWeight.w600,
                                color: Colors.white70,
                              ),
                            ),
                    ),
                    // Count badge
                    Container(
                      padding: const EdgeInsets.symmetric(
                        horizontal: 5,
                        vertical: 1,
                      ),
                      decoration: BoxDecoration(
                        color: Colors.white.withOpacity(0.06),
                        borderRadius: BorderRadius.circular(8),
                      ),
                      child: Text(
                        '${notesInFolder.length}',
                        style: const TextStyle(
                          fontSize: 9,
                          fontWeight: FontWeight.bold,
                          color: Colors.white30,
                        ),
                      ),
                    ),
                    const SizedBox(width: 4),
                    // Rename
                    Tooltip(
                      message: 'Rename folder',
                      child: InkWell(
                        onTap: () {
                          _notesOrgNotesRenameFolderCtrl.text = folder.name;
                          setState(() => _notesOrgNotesRenamingFolder = fid);
                        },
                        borderRadius: BorderRadius.circular(4),
                        child: const Padding(
                          padding: EdgeInsets.all(4),
                          child: Icon(
                            Icons.edit_outlined,
                            size: 12,
                            color: Colors.white24,
                          ),
                        ),
                      ),
                    ),
                    // Delete (keeps confirmation dialog + file-system logic)
                    Tooltip(
                      message: 'Delete folder (notes move to root)',
                      child: InkWell(
                        onTap: () async {
                          final confirmed = await showDialog<bool>(
                            context: context,
                            builder: (ctx) => AlertDialog(
                              backgroundColor: const Color(0xFF2E3440),
                              title: const Text(
                                'Delete folder?',
                                style: TextStyle(
                                  color: Colors.white,
                                  fontSize: 14,
                                ),
                              ),
                              content: Text(
                                'Notes inside "${folder.name}" will be '
                                'moved to the root.',
                                style: const TextStyle(
                                  color: Colors.white70,
                                  fontSize: 12,
                                ),
                              ),
                              actions: [
                                TextButton(
                                  onPressed: () => Navigator.of(ctx).pop(false),
                                  child: const Text(
                                    'Cancel',
                                    style: TextStyle(color: Colors.white54),
                                  ),
                                ),
                                TextButton(
                                  onPressed: () => Navigator.of(ctx).pop(true),
                                  child: const Text(
                                    'Delete',
                                    style: TextStyle(color: Colors.redAccent),
                                  ),
                                ),
                              ],
                            ),
                          );
                          if (confirmed != true) return;
                          final folderName = folder.name;
                          setState(() {
                            _noteFolders.remove(fid);
                            _noteFolderOrder.remove(fid);
                            _notesOrgNotesCollapsed.remove(fid);
                            for (final n in _notes.values) {
                              if (n.folderId == fid) n.folderId = null;
                            }
                          });
                          if (folderName.isNotEmpty) {
                            try {
                              final folderDir = Directory(
                                '$_notesDir/notes/$folderName',
                              );
                              final rootNotesDir = Directory(
                                '$_notesDir/notes',
                              );
                              if (await folderDir.exists()) {
                                await for (final entity in folderDir.list()) {
                                  if (entity is File) {
                                    final dest =
                                        '${rootNotesDir.path}/'
                                        '${entity.uri.pathSegments.last}';
                                    await entity.copy(dest);
                                    await entity.delete();
                                  }
                                }
                                await folderDir.delete();
                              }
                            } catch (e) {
                              debugPrint('notesOrg delete dir error: $e');
                            }
                          }
                          _saveNotesMeta();
                        },
                        borderRadius: BorderRadius.circular(4),
                        child: Padding(
                          padding: const EdgeInsets.all(4),
                          child: Icon(
                            Icons.delete_outline,
                            size: 12,
                            color: Colors.redAccent.withOpacity(0.55),
                          ),
                        ),
                      ),
                    ),
                  ],
                ),
              ),
            ),
            // ── Notes — animate in/out on collapse ───────────────────────
            AnimatedSize(
              duration: const Duration(milliseconds: 180),
              curve: Curves.easeInOut,
              alignment: Alignment.topCenter,
              child: isCollapsed
                  ? const SizedBox.shrink()
                  : Column(
                      crossAxisAlignment: CrossAxisAlignment.stretch,
                      children: [
                        if (notesInFolder.isNotEmpty)
                          const Divider(color: border, height: 1),
                        ...notesInFolder.map(noteRow),
                        if (notesInFolder.isEmpty)
                          Padding(
                            padding: const EdgeInsets.fromLTRB(14, 8, 14, 10),
                            child: Text(
                              'No notes in this folder',
                              style: TextStyle(
                                fontSize: 11,
                                color: Colors.white.withOpacity(0.24),
                                fontStyle: FontStyle.italic,
                              ),
                            ),
                          ),
                      ],
                    ),
            ),
          ],
        ),
      );
    }

    return Container(
      color: bg,
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.stretch,
        children: [
          // ── Toolbar ─────────────────────────────────────────────────────
          Container(
            padding: const EdgeInsets.fromLTRB(16, 10, 16, 10),
            decoration: const BoxDecoration(
              color: surface,
              border: Border(bottom: BorderSide(color: border)),
            ),
            child: Row(
              children: [
                // Animated search field
                AnimatedContainer(
                  duration: const Duration(milliseconds: 180),
                  width: _notesOrgNotesSearchActive ? 200 : 0,
                  curve: Curves.easeInOut,
                  child: _notesOrgNotesSearchActive
                      ? Container(
                          height: 28,
                          decoration: BoxDecoration(
                            color: bg,
                            borderRadius: BorderRadius.circular(6),
                            border: Border.all(color: accent.withOpacity(0.3)),
                          ),
                          child: Row(
                            children: [
                              const SizedBox(width: 7),
                              const Icon(
                                Icons.search_rounded,
                                size: 13,
                                color: Colors.white38,
                              ),
                              const SizedBox(width: 5),
                              Expanded(
                                child: TextField(
                                  controller: _notesOrgNotesSearchCtrl,
                                  autofocus: true,
                                  style: const TextStyle(
                                    fontSize: 11,
                                    color: Colors.white,
                                  ),
                                  decoration: const InputDecoration(
                                    hintText: 'Search folders…',
                                    hintStyle: TextStyle(
                                      fontSize: 11,
                                      color: Colors.white30,
                                    ),
                                    isDense: true,
                                    contentPadding: EdgeInsets.zero,
                                    border: InputBorder.none,
                                  ),
                                  onChanged: (v) => setState(
                                    () => _notesOrgNotesSearchQuery = v,
                                  ),
                                ),
                              ),
                              if (_notesOrgNotesSearchQuery.isNotEmpty)
                                GestureDetector(
                                  onTap: () => setState(() {
                                    _notesOrgNotesSearchQuery = '';
                                    _notesOrgNotesSearchCtrl.clear();
                                  }),
                                  child: const Padding(
                                    padding: EdgeInsets.symmetric(
                                      horizontal: 4,
                                    ),
                                    child: Icon(
                                      Icons.close_rounded,
                                      size: 13,
                                      color: Colors.white38,
                                    ),
                                  ),
                                ),
                              const SizedBox(width: 4),
                            ],
                          ),
                        )
                      : const SizedBox.shrink(),
                ),
                if (_notesOrgNotesSearchActive) const SizedBox(width: 6),
                // Magnifying glass toggle
                Tooltip(
                  message: _notesOrgNotesSearchActive
                      ? 'Close search'
                      : 'Search',
                  child: InkWell(
                    onTap: () => setState(() {
                      _notesOrgNotesSearchActive = !_notesOrgNotesSearchActive;
                      if (!_notesOrgNotesSearchActive) {
                        _notesOrgNotesSearchQuery = '';
                        _notesOrgNotesSearchCtrl.clear();
                      }
                    }),
                    borderRadius: BorderRadius.circular(5),
                    child: Padding(
                      padding: const EdgeInsets.all(5),
                      child: Icon(
                        _notesOrgNotesSearchActive
                            ? Icons.search_off_rounded
                            : Icons.search_rounded,
                        size: 15,
                        color: _notesOrgNotesSearchActive
                            ? accent
                            : Colors.white38,
                      ),
                    ),
                  ),
                ),
                if (!_notesOrgNotesSearchActive) ...[
                  const SizedBox(width: 4),
                  Text(
                    '${_noteFolders.length + 1} folders',
                    style: const TextStyle(fontSize: 11, color: Colors.white38),
                  ),
                ],
                const Spacer(),
                // New Folder button
                TextButton.icon(
                  style: TextButton.styleFrom(
                    foregroundColor: accent,
                    textStyle: const TextStyle(fontSize: 11),
                    padding: const EdgeInsets.symmetric(
                      horizontal: 10,
                      vertical: 6,
                    ),
                  ),
                  icon: const Icon(Icons.create_new_folder_outlined, size: 14),
                  label: const Text('New Folder'),
                  onPressed: () => setState(() {
                    _notesOrgNotesAddingFolder = true;
                    _notesOrgNotesSearchActive = false;
                    _notesOrgNotesSearchQuery = '';
                    _notesOrgNotesSearchCtrl.clear();
                  }),
                ),
                // Close button
                const SizedBox(width: 4),
                Tooltip(
                  message: 'Close',
                  child: InkWell(
                    onTap: () => setState(() => _notesNavSection = 'editor'),
                    borderRadius: BorderRadius.circular(5),
                    child: const Padding(
                      padding: EdgeInsets.all(5),
                      child: Icon(
                        Icons.close_rounded,
                        size: 15,
                        color: Colors.white38,
                      ),
                    ),
                  ),
                ),
              ],
            ),
          ),
          // ── New Folder inline input ──────────────────────────────────────
          if (_notesOrgNotesAddingFolder)
            Container(
              color: surface,
              padding: const EdgeInsets.fromLTRB(14, 10, 14, 10),
              child: Row(
                children: [
                  const Icon(
                    Icons.create_new_folder_outlined,
                    size: 14,
                    color: accent,
                  ),
                  const SizedBox(width: 8),
                  Expanded(
                    child: TextField(
                      controller: _notesOrgNotesFolderCtrl,
                      autofocus: true,
                      style: const TextStyle(fontSize: 12, color: Colors.white),
                      decoration: const InputDecoration(
                        hintText: 'Folder name…',
                        hintStyle: TextStyle(
                          fontSize: 12,
                          color: Colors.white30,
                        ),
                        isDense: true,
                        contentPadding: EdgeInsets.zero,
                        border: InputBorder.none,
                      ),
                      onSubmitted: (name) async {
                        final n = name.trim();
                        if (n.isNotEmpty) {
                          final fid =
                              'folder:${DateTime.now().millisecondsSinceEpoch}';
                          setState(() {
                            _noteFolders[fid] = NoteFolder(id: fid, name: n);
                            _noteFolderOrder.add(fid);
                          });
                          try {
                            final dir = Directory('$_notesDir/notes/$n');
                            if (!await dir.exists()) {
                              await dir.create(recursive: true);
                            }
                          } catch (e) {
                            debugPrint('notesOrg create folder error: $e');
