            ),
          ),
          // ── Folder list / empty state ────────────────────────────────────
          // Standard is always present, so there's no true "empty" state.
          Expanded(
            child: ListView(
              padding: const EdgeInsets.only(top: 4, bottom: 12),
              children: [
                ...filteredOrder.map(folderBlock),
                // Standard folder — shown when search is empty or matches 'standard'
                if (_notesOrgNotesSearchQuery.isEmpty ||
                    'standard'.contains(
                      _notesOrgNotesSearchQuery.toLowerCase(),
                    ))
                  standardBlock(),
                if (filteredOrder.isEmpty &&
                    _notesOrgNotesSearchQuery.isNotEmpty &&
                    !'standard'.contains(
                      _notesOrgNotesSearchQuery.toLowerCase(),
                    ))
                  Padding(
                    padding: const EdgeInsets.all(24),
                    child: Text(
                      'No folders match "${_notesOrgNotesSearchQuery}"',
                      style: TextStyle(
                        fontSize: 12,
                        color: Colors.white.withOpacity(0.35),
                      ),
                      textAlign: TextAlign.center,
                    ),
                  ),
              ],
            ),
          ),
        ],
      ),
    );
  }

  // ── Notes Org view: reorder/hide task and project notes  ──────────────────
  Widget _buildNotesOrgView({required bool isProjects, VoidCallback? onBack}) {
    _syncNotes();
    final label = isProjects ? 'Project Notes' : 'Task Notes';
    final notes = isProjects
        ? _notes.values.where((n) => n.type == NoteType.project).toList()
        : _notes.values.where((n) => n.type == NoteType.task).toList();
    final orderList = isProjects ? _noteProjectOrder : _noteTaskOrder;
    final hiddenSet = isProjects ? _hiddenNoteProjects : _hiddenNoteTasks;

    // Sync order with current notes list
    final noteIds = notes.map((n) => n.id).toSet();
    orderList.removeWhere((id) => !noteIds.contains(id));
    for (final n in notes) {
      if (!orderList.contains(n.id)) orderList.add(n.id);
    }

    return Container(
      color: const Color(0xFF181A1B),
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.stretch,
        children: [
          // ── Header ──────────────────────────────────────────────────────
          Container(
            padding: const EdgeInsets.fromLTRB(20, 14, 20, 14),
            decoration: const BoxDecoration(
              color: Color(0xFF1E2124),
              border: Border(bottom: BorderSide(color: Color(0xFF2C2F32))),
            ),
            child: Row(
              children: [
                Expanded(
                  child: Text(
                    'Organize: $label',
                    style: const TextStyle(
                      color: Colors.white,
                      fontSize: 15,
                      fontWeight: FontWeight.w600,
                    ),
                  ),
                ),
                TextButton.icon(
                  onPressed:
                      onBack ??
                      () => setState(() => _tasksNavSection = 'Today'),
                  icon: const Icon(
                    Icons.arrow_back_rounded,
                    size: 13,
                    color: Colors.white54,
                  ),
                  label: const Text(
                    'Back',
                    style: TextStyle(color: Colors.white54, fontSize: 12),
                  ),
                ),
              ],
            ),
          ),
          // ── Hint bar ────────────────────────────────────────────────────
          Padding(
            padding: const EdgeInsets.fromLTRB(16, 10, 16, 4),
            child: Text(
              'Drag ≡ to reorder · tap 👁 to hide an entry from the sidebar',
              style: TextStyle(
                fontSize: 10,
                color: Colors.white.withOpacity(0.35),
              ),
            ),
          ),
          // ── Reorderable list ─────────────────────────────────────────────
          Expanded(
            child: ReorderableListView(
              padding: const EdgeInsets.symmetric(vertical: 4),
              buildDefaultDragHandles: false,
              onReorder: (oldIdx, newIdx) {
                setState(() {
                  if (newIdx > oldIdx) newIdx -= 1;
                  final id = orderList.removeAt(oldIdx);
                  orderList.insert(newIdx, id);
                  if (isProjects) {
                    _noteProjectOrder = orderList;
                  } else {
                    _noteTaskOrder = orderList;
                  }
                });
                _saveWorkspace();
              },
              children: orderList.asMap().entries.map((entry) {
                final idx = entry.key;
                final id = entry.value;
                final note = notes.firstWhere(
                  (n) => n.id == id,
                  orElse: () => notes.first,
                );
                final linkedId = isProjects
                    ? (note.linkedProjectId ?? '')
                    : (note.linkedTaskId ?? '');
                final isHidden = hiddenSet.contains(linkedId);
                return Container(
                  key: ValueKey('notesorg_$id'),
                  margin: const EdgeInsets.symmetric(
                    horizontal: 12,
                    vertical: 1,
                  ),
                  decoration: BoxDecoration(
                    color: const Color(0xFF212426),
                    borderRadius: BorderRadius.circular(5),
                    border: Border.all(color: const Color(0xFF2C2F32)),
                  ),
                  child: Row(
                    children: [
                      // Drag handle
                      ReorderableDragStartListener(
                        index: idx,
                        child: const Padding(
                          padding: EdgeInsets.symmetric(horizontal: 10),
                          child: Icon(
                            Icons.drag_indicator_rounded,
                            size: 14,
                            color: Colors.white24,
                          ),
                        ),
                      ),
                      Expanded(
                        child: Padding(
                          padding: const EdgeInsets.symmetric(vertical: 10),
                          child: Text(
                            note.title,
                            style: TextStyle(
                              fontSize: 12,
                              color: isHidden ? Colors.white30 : Colors.white70,
                            ),
                          ),
                        ),
                      ),
                      // Hide toggle
                      Tooltip(
                        message: isHidden
                            ? 'Show in sidebar'
                            : 'Hide from sidebar',
                        child: InkWell(
                          onTap: () {
                            setState(() {
                              if (isHidden) {
                                hiddenSet.remove(linkedId);
                              } else {
                                hiddenSet.add(linkedId);
                              }
                              if (isProjects) {
                                _hiddenNoteProjects = hiddenSet;
                              } else {
                                _hiddenNoteTasks = hiddenSet;
                              }
                            });
                            _saveWorkspace();
                          },
                          borderRadius: BorderRadius.circular(4),
                          child: Padding(
                            padding: const EdgeInsets.all(8),
                            child: Icon(
                              isHidden
                                  ? Icons.visibility_off_rounded
                                  : Icons.visibility_rounded,
                              size: 14,
                              color: isHidden ? Colors.white30 : Colors.white54,
                            ),
                          ),
                        ),
                      ),
                      const SizedBox(width: 4),
                    ],
                  ),
                );
              }).toList(),
            ),
          ),
        ],
      ),
    );
  }

  // ── Notes > Tasks Settings view — folder-grouped task list ────────────────
  Widget _buildNotesOrgTasksView({VoidCallback? onBack}) {
    const bg = Color(0xFF181A1B);
    const surface = Color(0xFF212426);
    const border = Color(0xFF2C2F32);
    const folderYellow = Color(0xFFEBCB8B);

    // Build projectId → folder-name lookup
    final pidToFolder = <String, String>{};
    for (final entry in _projectFolders.entries) {
      for (final pid in entry.value) {
        pidToFolder[pid] = entry.key;
      }
    }

    // Group tasks by folder name (Standard = no folder)
    final Map<String, List<Task>> folderTasks = {};
    final List<Task> standardTasks = [];
    for (final task in _allTasks) {
      final fn = pidToFolder[task.projectId];
      if (fn != null) {
        folderTasks.putIfAbsent(fn, () => []).add(task);
      } else {
        standardTasks.add(task);
      }
    }

    // Honour _projectFolderOrder, append any un-ordered folders at the end
    final allFolderKeys = [
      ..._projectFolderOrder.where(_projectFolders.containsKey),
      ..._projectFolders.keys.where((f) => !_projectFolderOrder.contains(f)),
    ];

    // ── Single task row ────────────────────────────────────────────────────
    Widget taskRow(Task task) {
      final isHidden = _hiddenNoteTasks.contains(task.id);
      return Container(
        key: ValueKey('orgtask_${task.id}'),
        margin: const EdgeInsets.symmetric(horizontal: 12, vertical: 2),
        padding: const EdgeInsets.fromLTRB(10, 7, 8, 7),
        decoration: BoxDecoration(
          color: surface,
          borderRadius: BorderRadius.circular(6),
          border: Border.all(color: border),
        ),
        child: Row(
          children: [
            Icon(
              Icons.task_alt_rounded,
              size: 13,
              color: isHidden ? Colors.white12 : Colors.white38,
            ),
            const SizedBox(width: 9),
            Expanded(
              child: Text(
                task.title,
                style: TextStyle(
                  fontSize: 12,
                  color: isHidden ? Colors.white24 : Colors.white70,
                  fontStyle: isHidden ? FontStyle.italic : FontStyle.normal,
                ),
              ),
            ),
            Tooltip(
              message: isHidden ? 'Show in sidebar' : 'Hide from sidebar',
              child: InkWell(
                onTap: () {
                  setState(() {
                    if (isHidden) {
                      _hiddenNoteTasks.remove(task.id);
                    } else {
                      _hiddenNoteTasks.add(task.id);
                    }
                  });
                  _saveWorkspace();
                },
                borderRadius: BorderRadius.circular(4),
                child: Padding(
                  padding: const EdgeInsets.all(4),
                  child: Icon(
                    isHidden
                        ? Icons.visibility_off_outlined
                        : Icons.visibility_outlined,
                    size: 14,
                    color: isHidden ? Colors.white24 : Colors.white38,
                  ),
                ),
              ),
            ),
          ],
        ),
      );
    }

    // ── Folder block (mirrors Projects Settings _folderBlock) ─────────────
    Widget folderBlock(
      String folderKey,
      List<Task> tasks, {
      bool isStandard = false,
    }) {
      final isCollapsed = _notesOrgTasksCollapsed.contains(folderKey);
      final isRenaming = _notesOrgTasksRenamingFolder == folderKey;
      final allHidden =
          tasks.isNotEmpty &&
          tasks.every((t) => _hiddenNoteTasks.contains(t.id));

      return AnimatedContainer(
        duration: const Duration(milliseconds: 100),
        margin: const EdgeInsets.fromLTRB(12, 6, 12, 0),
        decoration: BoxDecoration(
          color: surface.withOpacity(0.5),
          borderRadius: BorderRadius.circular(8),
          border: Border.all(color: border),
        ),
        child: Column(
          crossAxisAlignment: CrossAxisAlignment.stretch,
          children: [
            // ── Header row — tappable to collapse ─────────────────────────
            InkWell(
              onTap: () {
                setState(() {
                  if (isCollapsed) {
                    _notesOrgTasksCollapsed.remove(folderKey);
                  } else {
                    _notesOrgTasksCollapsed.add(folderKey);
                  }
                });
                unawaited(_saveWorkspace());
              },
              borderRadius: const BorderRadius.vertical(
                top: Radius.circular(8),
              ),
              child: Padding(
                padding: const EdgeInsets.fromLTRB(10, 8, 8, 8),
                child: Row(
                  children: [
                    // Collapse chevron
                    AnimatedRotation(
                      turns: isCollapsed ? -0.25 : 0,
                      duration: const Duration(milliseconds: 150),
                      child: const Icon(
                        Icons.expand_more_rounded,
                        size: 13,
                        color: Colors.white30,
                      ),
                    ),
                    const SizedBox(width: 5),
                    Icon(
                      isStandard ? Icons.inbox_outlined : Icons.folder_rounded,
                      size: 13,
                      color: isStandard
                          ? Colors.white24
                          : folderYellow.withOpacity(0.7),
                    ),
                    const SizedBox(width: 7),
                    // Folder name / inline rename field
                    Expanded(
                      child: isRenaming
                          ? TextField(
                              controller: _notesOrgTasksRenameFolderCtrl,
                              autofocus: true,
                              style: const TextStyle(
                                fontSize: 12,
                                color: Colors.white,
                              ),
                              decoration: const InputDecoration(
                                isDense: true,
                                contentPadding: EdgeInsets.zero,
                                border: InputBorder.none,
                              ),
                              onSubmitted: (v) {
                                final n = v.trim();
                                if (n.isNotEmpty && n != folderKey) {
                                  final items =
                                      _projectFolders.remove(folderKey) ?? {};
                                  _projectFolders[n] = items;
                                  final idx = _projectFolderOrder.indexOf(
                                    folderKey,
                                  );
                                  if (idx >= 0) _projectFolderOrder[idx] = n;
                                  if (_notesOrgTasksCollapsed.remove(
                                    folderKey,
                                  )) {
                                    _notesOrgTasksCollapsed.add(n);
                                  }
                                  _saveWorkspace();
                                }
                                setState(
                                  () => _notesOrgTasksRenamingFolder = null,
                                );
                              },
                            )
                          : Text(
                              isStandard ? 'Standard' : folderKey,
                              style: TextStyle(
                                fontSize: 12,
                                fontWeight: FontWeight.w600,
                                color: isStandard
                                    ? Colors.white38
                                    : Colors.white70,
                              ),
                            ),
                    ),
                    // Item count badge
                    Container(
                      padding: const EdgeInsets.symmetric(
                        horizontal: 5,
                        vertical: 1,
                      ),
                      decoration: BoxDecoration(
                        color: Colors.white.withOpacity(0.06),
                        borderRadius: BorderRadius.circular(8),
                      ),
                      child: Text(
                        '${tasks.length}',
                        style: const TextStyle(
                          fontSize: 9,
                          fontWeight: FontWeight.bold,
                          color: Colors.white30,
                        ),
                      ),
                    ),
                    const SizedBox(width: 4),
                    // Eye — hide / show all tasks in this folder
                    if (!isStandard) ...[
                      Tooltip(
                        message: allHidden
                            ? 'Show all in sidebar'
                            : 'Hide all from sidebar',
                        child: InkWell(
                          onTap: () {
                            setState(() {
                              for (final t in tasks) {
                                if (allHidden) {
                                  _hiddenNoteTasks.remove(t.id);
                                } else {
                                  _hiddenNoteTasks.add(t.id);
                                }
                              }
                            });
                            _saveWorkspace();
                          },
                          borderRadius: BorderRadius.circular(4),
                          child: Padding(
                            padding: const EdgeInsets.all(4),
                            child: Icon(
                              allHidden
                                  ? Icons.visibility_off_outlined
                                  : Icons.visibility_outlined,
                              size: 13,
                              color: allHidden
                                  ? Colors.white24
                                  : Colors.white30,
                            ),
                          ),
                        ),
                      ),
                      // Rename
                      Tooltip(
                        message: 'Rename folder',
                        child: InkWell(
                          onTap: () {
                            _notesOrgTasksRenameFolderCtrl.text = folderKey;
                            setState(
                              () => _notesOrgTasksRenamingFolder = folderKey,
                            );
                          },
                          borderRadius: BorderRadius.circular(4),
                          child: const Padding(
                            padding: EdgeInsets.all(4),
                            child: Icon(
                              Icons.edit_outlined,
                              size: 12,
                              color: Colors.white24,
                            ),
                          ),
                        ),
                      ),
                      // Delete
                      Tooltip(
                        message: 'Delete folder (tasks move to Standard)',
                        child: InkWell(
                          onTap: () {
                            _projectFolders.remove(folderKey);
                            _projectFolderOrder.remove(folderKey);
                            _notesOrgTasksCollapsed.remove(folderKey);
                            _saveWorkspace();
                            setState(() {});
                          },
                          borderRadius: BorderRadius.circular(4),
                          child: Padding(
                            padding: const EdgeInsets.all(4),
                            child: Icon(
                              Icons.delete_outline,
                              size: 12,
                              color: Colors.redAccent.withOpacity(0.55),
                            ),
                          ),
                        ),
                      ),
                    ],
                  ],
                ),
              ),
            ),
            // ── Task rows — animate in/out on collapse ─────────────────────
            AnimatedSize(
              duration: const Duration(milliseconds: 180),
              curve: Curves.easeInOut,
              alignment: Alignment.topCenter,
              child: isCollapsed
                  ? const SizedBox.shrink()
                  : Column(
                      crossAxisAlignment: CrossAxisAlignment.stretch,
                      children: [
                        if (tasks.isNotEmpty)
                          const Divider(color: Color(0xFF2C2F32), height: 1),
                        ...tasks.map(taskRow),
                        if (tasks.isEmpty && !isStandard)
                          Padding(
                            padding: const EdgeInsets.fromLTRB(14, 8, 14, 10),
                            child: Text(
                              'No tasks in this folder',
                              style: TextStyle(
                                fontSize: 11,
                                color: Colors.white.withOpacity(0.24),
                                fontStyle: FontStyle.italic,
                              ),
                            ),
                          ),
                      ],
                    ),
            ),
          ],
        ),
      );
    }

    // ── Filtered tasks helper (applied across all groups) ─────────────────
    List<Task> filterTasks(List<Task> tasks) {
      List<Task> result = tasks;

      // Text search
      if (_notesOrgTasksSearchQuery.isNotEmpty) {
        final q = _notesOrgTasksSearchQuery.toLowerCase();
        result = result
            .where((t) => t.title.toLowerCase().contains(q))
            .toList();
      }

      // Apply the same Filter rules that are active in the project Tasks view
      final activeFilters = _filterRules.where((r) => r.isConfigured).toList();
      if (activeFilters.isNotEmpty) {
        result = result
            .where((t) => activeFilters.every((r) => r.matches(t, _projects)))
            .toList();
      }

      // Apply the same Sort criteria that are active in the project Tasks view
      if (_sortCriteria.isNotEmpty) {
        result = _applySortCriteria(result, _sortCriteria);
      }

      return result;
    }

    return Container(
      color: bg,
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.stretch,
        children: [
          // ── Toolbar (mirrors Projects Settings) ───────────────────────────
          Container(
            padding: const EdgeInsets.fromLTRB(16, 10, 16, 10),
            decoration: const BoxDecoration(
              color: Color(0xFF212426),
              border: Border(bottom: BorderSide(color: Color(0xFF2C2F32))),
            ),
            child: Row(
              children: [
                // ── Animated search field ──────────────────────────────────
                AnimatedContainer(
                  duration: const Duration(milliseconds: 180),
                  width: _notesOrgTasksSearchActive ? 200 : 0,
                  curve: Curves.easeInOut,
                  child: _notesOrgTasksSearchActive
                      ? Container(
                          height: 28,
                          decoration: BoxDecoration(
                            color: bg,
                            borderRadius: BorderRadius.circular(6),
                            border: Border.all(
                              color: const Color(0xFF4FC3F7).withOpacity(0.3),
                            ),
                          ),
                          child: Row(
                            children: [
                              const SizedBox(width: 7),
                              const Icon(
                                Icons.search_rounded,
                                size: 13,
                                color: Colors.white38,
                              ),
                              const SizedBox(width: 5),
                              Expanded(
                                child: TextField(
                                  controller: _notesOrgTasksSearchCtrl,
                                  autofocus: true,
                                  style: const TextStyle(
                                    fontSize: 11,
                                    color: Colors.white,
                                  ),
                                  decoration: const InputDecoration(
                                    hintText: 'Search tasks…',
                                    hintStyle: TextStyle(
                                      fontSize: 11,
                                      color: Colors.white30,
                                    ),
                                    isDense: true,
                                    contentPadding: EdgeInsets.zero,
                                    border: InputBorder.none,
                                  ),
                                  onChanged: (v) => setState(
                                    () => _notesOrgTasksSearchQuery = v,
                                  ),
                                ),
                              ),
                              if (_notesOrgTasksSearchQuery.isNotEmpty)
                                GestureDetector(
                                  onTap: () => setState(() {
                                    _notesOrgTasksSearchQuery = '';
                                    _notesOrgTasksSearchCtrl.clear();
                                  }),
                                  child: const Padding(
                                    padding: EdgeInsets.symmetric(
                                      horizontal: 4,
                                    ),
                                    child: Icon(
                                      Icons.close_rounded,
                                      size: 13,
                                      color: Colors.white38,
                                    ),
                                  ),
                                ),
                              const SizedBox(width: 4),
                            ],
                          ),
                        )
                      : const SizedBox.shrink(),
                ),
                if (_notesOrgTasksSearchActive) const SizedBox(width: 6),
                // ── Magnifying glass toggle ────────────────────────────────
                Tooltip(
                  message: _notesOrgTasksSearchActive
                      ? 'Close search'
                      : 'Search',
                  child: InkWell(
                    onTap: () => setState(() {
                      _notesOrgTasksSearchActive = !_notesOrgTasksSearchActive;
                      if (!_notesOrgTasksSearchActive) {
                        _notesOrgTasksSearchQuery = '';
                        _notesOrgTasksSearchCtrl.clear();
                      }
                    }),
                    borderRadius: BorderRadius.circular(5),
                    child: Padding(
                      padding: const EdgeInsets.all(5),
                      child: Icon(
                        _notesOrgTasksSearchActive
                            ? Icons.search_off_rounded
