                    ),
                  ),
                ],
              ],
            ),
          ),
          // ── New Folder inline input ────────────────────────────────────────
          if (_notesOrgTasksAddingFolder)
            Container(
              color: surface,
              padding: const EdgeInsets.fromLTRB(14, 10, 14, 10),
              child: Row(
                children: [
                  const Icon(
                    Icons.create_new_folder_outlined,
                    size: 14,
                    color: Color(0xFF4FC3F7),
                  ),
                  const SizedBox(width: 8),
                  Expanded(
                    child: TextField(
                      controller: _notesOrgTasksFolderCtrl,
                      autofocus: true,
                      style: const TextStyle(fontSize: 12, color: Colors.white),
                      decoration: const InputDecoration(
                        hintText: 'Folder name…',
                        hintStyle: TextStyle(
                          fontSize: 12,
                          color: Colors.white30,
                        ),
                        isDense: true,
                        contentPadding: EdgeInsets.zero,
                        border: InputBorder.none,
                      ),
                      onSubmitted: (name) {
                        final n = name.trim();
                        if (n.isNotEmpty) {
                          setState(() {
                            _projectFolders.putIfAbsent(n, () => {});
                            if (!_projectFolderOrder.contains(n)) {
                              _projectFolderOrder.add(n);
                            }
                            _notesOrgTasksAddingFolder = false;
                          });
                          _notesOrgTasksFolderCtrl.clear();
                          _saveWorkspace();
                        } else {
                          _notesOrgTasksFolderCtrl.clear();
                          setState(() => _notesOrgTasksAddingFolder = false);
                        }
                      },
                    ),
                  ),
                  const SizedBox(width: 12),
                  TextButton(
                    onPressed: () {
                      final n = _notesOrgTasksFolderCtrl.text.trim();
                      if (n.isNotEmpty) {
                        setState(() {
                          _projectFolders.putIfAbsent(n, () => {});
                          if (!_projectFolderOrder.contains(n)) {
                            _projectFolderOrder.add(n);
                          }
                          _notesOrgTasksAddingFolder = false;
                        });
                        _notesOrgTasksFolderCtrl.clear();
                        _saveWorkspace();
                      } else {
                        _notesOrgTasksFolderCtrl.clear();
                        setState(() => _notesOrgTasksAddingFolder = false);
                      }
                    },
                    child: const Text(
                      'Create',
                      style: TextStyle(fontSize: 11, color: Color(0xFF4FC3F7)),
                    ),
                  ),
                  TextButton(
                    onPressed: () {
                      _notesOrgTasksFolderCtrl.clear();
                      setState(() => _notesOrgTasksAddingFolder = false);
                    },
                    child: const Text(
                      'Cancel',
                      style: TextStyle(fontSize: 11, color: Colors.white38),
                    ),
                  ),
                ],
              ),
            ),
          // ── Hint ──────────────────────────────────────────────────────────
          Padding(
            padding: const EdgeInsets.fromLTRB(16, 10, 16, 4),
            child: Text(
              'Tap 👁 to hide a task · Folders mirror Projects Settings',
              style: TextStyle(
                fontSize: 10,
                color: Colors.white.withOpacity(0.35),
              ),
            ),
          ),
          // ── Folder-grouped list ───────────────────────────────────────────
          Expanded(
            child: ListView(
              padding: const EdgeInsets.symmetric(vertical: 4),
              children: [
                ...allFolderKeys
                    .where((f) {
                      final filtered = filterTasks(folderTasks[f] ?? []);
                      // Show the folder if it has matching tasks, OR if it
                      // simply exists (e.g. newly created and still empty).
                      return filtered.isNotEmpty ||
                          _projectFolders.containsKey(f);
                    })
                    .map(
                      (f) => folderBlock(f, filterTasks(folderTasks[f] ?? [])),
                    ),
                if (filterTasks(standardTasks).isNotEmpty)
                  folderBlock(
                    'Standard',
                    filterTasks(standardTasks),
                    isStandard: true,
                  ),
                if (_notesOrgTasksSearchQuery.isNotEmpty &&
                    allFolderKeys
                        .where(
                          (f) => filterTasks(folderTasks[f] ?? []).isNotEmpty,
                        )
                        .isEmpty &&
                    filterTasks(standardTasks).isEmpty)
                  Padding(
                    padding: const EdgeInsets.all(24),
                    child: Text(
                      'No tasks match "${_notesOrgTasksSearchQuery}"',
                      style: TextStyle(
                        fontSize: 12,
                        color: Colors.white.withOpacity(0.35),
                      ),
                      textAlign: TextAlign.center,
                    ),
                  ),
              ],
            ),
          ),
        ],
      ),
    );
  }

  // ── Canvas category settings view ─────────────────────────────────────────
  Widget _buildCanvasCategorySettingsView(String categoryName) {
    final catProjects = _projectOrder
        .where(
          (id) =>
              (_categoryMappings[categoryName] ?? {}).contains(id) &&
              _projects.containsKey(id),
        )
        .toList();

    return Container(
      color: const Color(0xFF181A1B),
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.stretch,
        children: [
          // ── Header ──────────────────────────────────────────────────────
          Container(
            padding: const EdgeInsets.fromLTRB(20, 14, 20, 14),
            decoration: const BoxDecoration(
              color: Color(0xFF1E2124),
              border: Border(bottom: BorderSide(color: Color(0xFF2C2F32))),
            ),
            child: Row(
              children: [
                Expanded(
                  child: Text(
                    'Category: $categoryName',
                    style: const TextStyle(
                      color: Colors.white,
                      fontSize: 15,
                      fontWeight: FontWeight.w600,
                    ),
                  ),
                ),
                TextButton.icon(
                  onPressed: () => setState(() => _tasksNavSection = 'Today'),
                  icon: const Icon(
                    Icons.arrow_back_rounded,
                    size: 13,
                    color: Colors.white54,
                  ),
                  label: const Text(
                    'Back',
                    style: TextStyle(color: Colors.white54, fontSize: 12),
                  ),
                ),
              ],
            ),
          ),
          Padding(
            padding: const EdgeInsets.fromLTRB(16, 10, 16, 4),
            child: Text(
              'Projects in this category — drag ≡ to reorder, toggle 👁 to hide',
              style: TextStyle(
                fontSize: 10,
                color: Colors.white.withOpacity(0.35),
              ),
            ),
          ),
          Expanded(
            child: ReorderableListView(
              padding: const EdgeInsets.symmetric(vertical: 4),
              buildDefaultDragHandles: false,
              onReorder: (oldIdx, newIdx) {
                setState(() {
                  if (newIdx > oldIdx) newIdx -= 1;
                  final movedId = catProjects.removeAt(oldIdx);
                  catProjects.insert(newIdx, movedId);
                  // Reflect new order within _projectOrder
                  for (final id in catProjects.reversed) {
                    _projectOrder.remove(id);
                    final insertAt = _projectOrder.indexWhere(
                      (pid) =>
                          (_categoryMappings[categoryName] ?? {}).contains(pid),
                    );
                    _projectOrder.insert(
                      insertAt < 0 ? _projectOrder.length : insertAt,
                      id,
                    );
                  }
                });
                _saveWorkspace();
              },
              children: catProjects.asMap().entries.map((entry) {
                final idx = entry.key;
                final pid = entry.value;
                final proj = _projects[pid];
                final title = proj?.title ?? pid;
                final color = _projectColors[pid] ?? Colors.blueAccent;
                final isHidden = _projectHiddenFromMenu[pid] ?? false;
                return Container(
                  key: ValueKey('catset_$pid'),
                  margin: const EdgeInsets.symmetric(
                    horizontal: 12,
                    vertical: 1,
                  ),
                  decoration: BoxDecoration(
                    color: const Color(0xFF212426),
                    borderRadius: BorderRadius.circular(5),
                    border: Border.all(color: const Color(0xFF2C2F32)),
                  ),
                  child: Row(
                    children: [
                      ReorderableDragStartListener(
                        index: idx,
                        child: const Padding(
                          padding: EdgeInsets.symmetric(horizontal: 10),
                          child: Icon(
                            Icons.drag_indicator_rounded,
                            size: 14,
                            color: Colors.white24,
                          ),
                        ),
                      ),
                      // Color dot
                      Container(
                        width: 9,
                        height: 9,
                        margin: const EdgeInsets.only(right: 8),
                        decoration: BoxDecoration(
                          color: color,
                          shape: BoxShape.circle,
                        ),
                      ),
                      Expanded(
                        child: Text(
                          title,
                          style: TextStyle(
                            fontSize: 12,
                            color: isHidden ? Colors.white30 : Colors.white70,
                          ),
                        ),
                      ),
                      // Color picker shortcut
                      Tooltip(
                        message: 'Change color',
                        child: InkWell(
                          onTap: () {
                            _showUnifiedColorPicker(
                              title: 'Project Color',
                              initialColor: color,
                              onApply: (c) {
                                setState(() => _projectColors[pid] = c);
                                _saveWorkspace();
                              },
                              colorContext: 'projectColor',
                            );
                          },
                          borderRadius: BorderRadius.circular(4),
                          child: Padding(
                            padding: const EdgeInsets.all(8),
                            child: Icon(
                              Icons.color_lens_outlined,
                              size: 14,
                              color: Colors.white38,
                            ),
                          ),
                        ),
                      ),
                      // Visibility toggle
                      Tooltip(
                        message: isHidden
                            ? 'Show in sidebar'
                            : 'Hide from sidebar',
                        child: InkWell(
                          onTap: () {
                            setState(() {
                              _projectHiddenFromMenu[pid] = !isHidden;
                            });
                            _saveWorkspace();
                          },
                          borderRadius: BorderRadius.circular(4),
                          child: Padding(
                            padding: const EdgeInsets.all(8),
                            child: Icon(
                              isHidden
                                  ? Icons.visibility_off_rounded
                                  : Icons.visibility_rounded,
                              size: 14,
                              color: isHidden ? Colors.white30 : Colors.white54,
                            ),
                          ),
                        ),
                      ),
                      const SizedBox(width: 4),
                    ],
                  ),
                );
              }).toList(),
            ),
          ),
        ],
      ),
    );
  }

  Widget _buildTasksTitleBar() {
    if (_tasksNavSection == 'org_projects')
      return _buildOrgTitleBar('Projects');
    if (_tasksNavSection == 'org_tags') return _buildOrgTitleBar('Tags');
    if (_tasksNavSection == 'notes_org_projects')
      return _buildOrgTitleBar('Project Notes');
    if (_tasksNavSection == 'notes_org_tasks')
      return _buildOrgTitleBar('Task Notes');
    if (_tasksNavSection.startsWith('canvas_category_settings:')) {
      final cat = _tasksNavSection.substring(
        'canvas_category_settings:'.length,
      );
      return _buildOrgTitleBar('Category: $cat');
    }
    if (_tasksNavSection == 'Schedule') return _buildScheduleTitleBar();
    if (_tasksNavSection == 'Planner') return _buildPlannerTitleBar();
    if (_tasksNavSection == 'Boards') return _buildBoardsTitleBar();

    final title = () {
      if (_tasksNavSection == 'Today') return 'Today';
      if (_tasksNavSection == 'Inbox') return 'Inbox';
      if (_tasksNavSection.startsWith('quick_history:')) {
        final ctx = _tasksNavSection.substring(14);
        if (ctx.startsWith('proj:')) {
          final pid = ctx.substring(5);
          return _projects[pid]?.title ?? 'Project';
        }
        if (ctx.startsWith('tag:')) return '#${ctx.substring(4)}';
        return 'Quick History';
      }
      if (_tasksNavSection.startsWith('worklog:')) {
        final ctx = _tasksNavSection.substring(8);
        if (ctx.startsWith('proj:')) {
          final pid = ctx.substring(5);
          return _projects[pid]?.title ?? 'Project';
        }
        if (ctx.startsWith('tag:')) return '#${ctx.substring(4)}';
        return 'Worklog';
      }
      if (_tasksNavSection.startsWith('metrics:')) {
        final ctx = _tasksNavSection.substring(8);
        if (ctx.startsWith('proj:')) {
          final pid = ctx.substring(5);
          return _projects[pid]?.title ?? 'Project';
        }
        if (ctx.startsWith('tag:')) return '#${ctx.substring(4)}';
        return 'Metrics';
      }
      if (_tasksNavSection.startsWith('settings:')) {
        final ctx = _tasksNavSection.substring(9);
        if (ctx.startsWith('proj:')) {
          final pid = ctx.substring(5);
          return _projects[pid]?.title ?? 'Project';
        }
        if (ctx.startsWith('tag:')) return '#${ctx.substring(4)}';
        return 'Settings';
      }
      if (_tasksNavSection.startsWith('proj:')) {
        final pid = _tasksNavSection.substring(5);
        return _projects[pid]?.title ?? 'Project';
      }
      if (_tasksNavSection.startsWith('tag:'))
        return '#${_tasksNavSection.substring(4)}';
      return _tasksNavSection;
    }();

    // ── Close Task Details button (always trailing) ──────────────────────
    final hasDetail =
        _taskListDetailOpen ||
        _showDetails ||
        _taskDetailExpanded.values.any((v) => v);
    final closeDetailsBtn = Tooltip(
      message: hasDetail ? 'Close Task Details' : 'No task details open',
      child: InkWell(
        onTap: hasDetail
            ? () => setState(() {
                _taskListDetailOpen = false;
                _taskListDetailTask = null;
                _showDetails = false;
                _taskDetailExpanded.clear();
              })
            : null,
        borderRadius: BorderRadius.circular(6),
        child: Container(
          width: 32,
          height: 32,
          decoration: BoxDecoration(
            color: hasDetail
                ? Colors.white.withOpacity(0.04)
                : Colors.transparent,
            borderRadius: BorderRadius.circular(6),
            border: Border.all(
              color: hasDetail
                  ? Colors.white12
                  : Colors.white.withOpacity(0.06),
            ),
          ),
          child: Icon(
            Icons.close_rounded,
            size: 15,
            color: hasDetail ? Colors.white54 : Colors.white.withOpacity(0.24),
          ),
        ),
      ),
    );

    return Padding(
      padding: const EdgeInsets.symmetric(horizontal: 16),
      child: _OverflowTopBar(
        leading: [
          Text(
            title,
            style: TextStyle(
              fontSize: 14,
              fontWeight: FontWeight.w600,
              color: _activeProjectAccent == _tasksAccent
                  ? Colors.white
                  : _activeProjectAccent,
              letterSpacing: 0.3,
            ),
          ),
        ],
        collapsible: [
          _OverflowItem(
            button: _tasksIconBtn(
              Icons.add,
              'New Task',
              () => _showAddTaskOverlay(),
              key: _addTaskBtnKey,
            ),
            icon: Icons.add,
            label: 'New Task',
            onTap: _showAddTaskOverlay,
          ),
          _OverflowItem(
            button: _buildFilterBtn(),
            icon: Icons.filter_list,
            label: 'Filter / Group / Sort',
            onTap: () => setState(() {
              _filterSidebarTitle = _computeFilterSidebarTitle();
              _filterSidebarOpen = !_filterSidebarOpen;
            }),
          ),
          _OverflowItem(
            button: _tasksIconBtn(
              Icons.center_focus_strong_outlined,
              'Focus',
              _showFocusPopup,
              key: _focusBtnKey,
            ),
            icon: Icons.center_focus_strong_outlined,
            label: 'Focus',
            onTap: _showFocusPopup,
          ),
          _OverflowItem(
            button: _tasksIconBtn(
              Icons.timeline_outlined,
              'Time Tracking',
              _showTimeTrackingPopup,
              key: _timeTrackingBtnKey,
            ),
            icon: Icons.timeline_outlined,
            label: 'Time Tracking',
            onTap: _showTimeTrackingPopup,
          ),
        ],
        trailing: [closeDetailsBtn],
      ),
    );
  }

  void _showTimeTrackingPopup() {
    final box =
        _timeTrackingBtnKey.currentContext?.findRenderObject() as RenderBox?;
    if (box == null) return;
    final pos = box.localToGlobal(Offset.zero);
    final size = box.size;
    final screen = MediaQuery.of(context).size;

    const popupW = 680.0;
    const popupH = 220.0;
    double left = pos.dx + size.width / 2 - popupW / 2;
    if (left + popupW > screen.width - 8) left = screen.width - popupW - 8;
    if (left < 8) left = 8;
    double top = pos.dy + size.height + 6;
    if (top + popupH > screen.height - 8) top = pos.dy - popupH - 6;

    showGeneralDialog(
      context: context,
      barrierDismissible: true,
      barrierLabel: 'TimeTracking',
      barrierColor: Colors.transparent,
      transitionDuration: const Duration(milliseconds: 140),
      transitionBuilder: (ctx, anim, _, child) => FadeTransition(
        opacity: CurvedAnimation(parent: anim, curve: Curves.easeOut),
        child: SlideTransition(
          position: Tween<Offset>(
            begin: const Offset(0, -0.04),
            end: Offset.zero,
          ).animate(CurvedAnimation(parent: anim, curve: Curves.easeOut)),
          child: child,
        ),
      ),
      pageBuilder: (ctx, _, __) => Stack(
        children: [
          Positioned(
            left: left,
            top: top,
            width: popupW,
            child: Material(
              color: Colors.transparent,
              child: _TimeTrackingPanel(
                allTasks: _allTasks,
                activeTimerTaskId: _activeTimerTaskId,
                timerStartedAt: _timerStartedAt,
                projects: _projects,
                execViewMode: _scheduleExecViewMode,
                taskSessions: _taskSessions,
              ),
            ),
          ),
        ],
      ),
    );
  }

  /// Returns the topmost undone task visible in the current list view.
  Task? _getTopmostTask() {
    final now = DateTime.now();
    final today = DateTime(now.year, now.month, now.day);
    final allSubtaskIds = _allTasks
        .expand((t) => t.subTaskIds.map((id) => id.toString()))
        .toSet();

    try {
      return _allTasks.firstWhere((t) {
        if (allSubtaskIds.contains(t.id)) return false;
        if (t.status == TaskStatus.done || t.status == TaskStatus.cancelled) {
          return false;
        }
        if (_tasksNavSection == 'Today') {
          if (t.dueDay == null) return false;
          final due = DateTime.tryParse(t.dueDay!);
          if (due == null) return false;
          return !DateTime(due.year, due.month, due.day).isAfter(today);
        }
        if (_tasksNavSection == 'Inbox') return t.projectId == 'INBOX_PROJECT';
        if (_tasksNavSection.startsWith('proj:'))
          return t.projectId == _tasksNavSection.substring(5);
        if (_tasksNavSection.startsWith('tag:'))
          return t.tagIds.contains(_tasksNavSection.substring(4));
        return true;
      });
    } catch (_) {
      return null;
    }
  }

  void _showFocusPopup() {
    // If a focus session is already running, go straight to its overlay.
    if (_activeStagingTaskId != null) {
      _showStagingOverlay(_activeStagingTaskId!);
      return;
    }
    if (_activeFlowtimeTaskId != null) {
      _showFlowtimeOverlay(_activeFlowtimeTaskId!);
      return;
    }
    if (_activeGeneralTaskId != null) {
      _showGeneralOverlay(_activeGeneralTaskId!);
      return;
    }

    final task = _getTopmostTask();
    showGeneralDialog(
      context: context,
      barrierDismissible: true,
      barrierLabel: 'FocusPopup',
      barrierColor: Colors.black.withOpacity(0.45),
      transitionDuration: const Duration(milliseconds: 180),
      transitionBuilder: (ctx, anim, _, child) => FadeTransition(
        opacity: CurvedAnimation(parent: anim, curve: Curves.easeOut),
        child: ScaleTransition(
          scale: Tween<double>(
            begin: 0.92,
            end: 1.0,
          ).animate(CurvedAnimation(parent: anim, curve: Curves.easeOutBack)),
          child: child,
        ),
      ),
      pageBuilder: (ctx, _, __) => Center(
        child: Material(
          color: Colors.transparent,
          child: _FocusModePopup(
            task: task,
            onCountdown: task != null
                ? () {
                    Navigator.of(ctx).pop();
                    _startGeneralTimer(task.id);
                  }
                : null,
            onPomodoro: task != null
                ? () {
                    Navigator.of(ctx).pop();
                    _startTaskStaging(task.id);
                  }
                : null,
            onFlowtime: task != null
                ? () {
                    Navigator.of(ctx).pop();
                    _startFlowtimeTimer(task.id);
                  }
                : null,
          ),
        ),
      ),
    );
  }

  // ── Filter button (icon-only, opens scoped sidebar) ────────────────────────
  /// Computes the display title for the sidebar based on the current nav section.
  String _computeFilterSidebarTitle() {
    final s = _tasksNavSection;
    if (s == 'Today') return 'Today';
    if (s == 'Inbox') return 'Inbox';
    if (s.startsWith('proj:')) {
      final pid = s.substring(5);
      return 'Project: ${_projects[pid]?.title ?? pid}';
    }
    if (s.startsWith('tag:')) return 'Tag: ${s.substring(4)}';
    return 'All Tasks';
  }

  Widget _buildFilterBtn() {
    final totalRules =
        _filterRules.where((r) => r.isConfigured).length +
        _groupCriteria.length +
        _sortCriteria.length;
    final isActive = _filterSidebarOpen || totalRules > 0;

    return Stack(
      clipBehavior: Clip.none,
      children: [
        _HoverLabelBtn(
          key: _filterBtnKey,
          icon: Icons.filter_list,
          hoverLabel: 'Filter / Group / Sort',
          isActive: isActive,
          onTap: () => setState(() {
            _filterSidebarTitle = _computeFilterSidebarTitle();
            _filterSidebarOpen = !_filterSidebarOpen;
          }),
        ),
        if (totalRules > 0)
          Positioned(
            top: 2,
            right: 2,
            child: Container(
              width: 14,
              height: 14,
              decoration: const BoxDecoration(
                color: Color(0xFF4FC3F7),
                shape: BoxShape.circle,
              ),
              child: Center(
                child: Text(
                  '$totalRules',
                  style: const TextStyle(
                    fontSize: 8,
                    fontWeight: FontWeight.w700,
                    color: Colors.black,
                  ),
                ),
              ),
            ),
          ),
      ],
    );
  }

  // ── Grist-style Filter / Group / Sort sidebar ─────────────────────────────
  // ── Feature 6: Canvas Filter / Group / Sort panel ───────────────────────────
  Widget _buildCanvasFilterPanel() {
    const accent = Color(0xFF4FC3F7);
    const bg = Color(0xFF1A1C1F);
    const surface = Color(0xFF22252A);
    const borderColor = Color(0xFF2C2F35);

    final allTags = {
      for (final t in _canvasTasks) ...t.tagIds.map((id) => id.toString()),
    }.toList()..sort();
    final allProjects = _projects.entries.toList();

    Widget chip({
      required String label,
      required bool active,
      required VoidCallback onTap,
    }) {
      return GestureDetector(
        onTap: onTap,
        child: AnimatedContainer(
          duration: const Duration(milliseconds: 100),
          margin: const EdgeInsets.only(right: 4, bottom: 4),
          padding: const EdgeInsets.symmetric(horizontal: 8, vertical: 4),
          decoration: BoxDecoration(
            color: active ? accent.withOpacity(0.15) : surface,
            borderRadius: BorderRadius.circular(5),
            border: Border.all(
              color: active ? accent.withOpacity(0.5) : borderColor,
            ),
          ),
          child: Text(
            label,
            style: TextStyle(
              fontSize: 11,
              color: active ? accent : Colors.white54,
              fontWeight: active ? FontWeight.w600 : FontWeight.normal,
            ),
          ),
        ),
      );
    }

    return Container(
      decoration: BoxDecoration(
        color: bg,
        borderRadius: BorderRadius.circular(10),
        border: Border.all(color: borderColor),
        boxShadow: [
          BoxShadow(color: Colors.black.withOpacity(0.45), blurRadius: 20),
        ],
      ),
      child: Column(
        mainAxisSize: MainAxisSize.min,
        crossAxisAlignment: CrossAxisAlignment.stretch,
        children: [
          // Header
          Container(
            padding: const EdgeInsets.fromLTRB(14, 10, 10, 10),
            decoration: const BoxDecoration(
              color: surface,
              borderRadius: BorderRadius.vertical(top: Radius.circular(10)),
              border: Border(bottom: BorderSide(color: borderColor)),
            ),
            child: Row(
              children: [
                const Icon(Icons.filter_list_rounded, size: 14, color: accent),
                const SizedBox(width: 8),
                const Text(
                  'Canvas Filter / Sort',
                  style: TextStyle(
                    fontSize: 12,
                    fontWeight: FontWeight.w600,
                    color: Colors.white,
                  ),
                ),
                const Spacer(),
                if (_canvasFilterRules.any((r) => r.isConfigured) ||
                    _canvasSortCriteria.isNotEmpty ||
                    _canvasGroupCriteria.isNotEmpty)
                  GestureDetector(
                    onTap: () => setState(() {
                      _canvasFilterRules.clear();
                      _canvasSortCriteria.clear();
                      _canvasGroupCriteria.clear();
                    }),
                    child: const Text(
                      'Clear all',
                      style: TextStyle(fontSize: 10, color: accent),
                    ),
                  ),
                const SizedBox(width: 8),
                GestureDetector(
                  onTap: () => setState(() => _canvasFilterOpen = false),
                  child: const Icon(
                    Icons.close_rounded,
                    size: 14,
                    color: Colors.white38,
                  ),
                ),
              ],
            ),
          ),

          // Filter by Status
          Padding(
            padding: const EdgeInsets.fromLTRB(14, 12, 14, 4),
            child: Text(
              'FILTER BY STATUS',
              style: TextStyle(
                fontSize: 9,
                letterSpacing: 1.0,
                fontWeight: FontWeight.w700,
                color: Colors.white38,
              ),
            ),
          ),
          Padding(
            padding: const EdgeInsets.fromLTRB(14, 4, 14, 8),
            child: Wrap(
              children: TaskStatus.values.map((s) {
                final rule = _canvasFilterRules.firstWhere(
                  (r) => r.field == TaskFilterField.status,
                  orElse: () {
                    final r = FilterRule(
                      id: _gristId(),
                      field: TaskFilterField.status,
                    );
                    _canvasFilterRules.add(r);
                    return r;
                  },
                );
                final active = rule.selectedValues.contains(s.name);
                return chip(
                  label: s.label,
                  active: active,
                  onTap: () => setState(() {
                    if (active) {
                      rule.selectedValues.remove(s.name);
                    } else {
                      rule.selectedValues.add(s.name);
                    }
                  }),
                );
              }).toList(),
            ),
          ),

          // Filter by Tag
          if (allTags.isNotEmpty) ...[
            Padding(
              padding: const EdgeInsets.fromLTRB(14, 4, 14, 4),
              child: Text(
                'FILTER BY TAG',
                style: TextStyle(
                  fontSize: 9,
                  letterSpacing: 1.0,
                  fontWeight: FontWeight.w700,
                  color: Colors.white38,
                ),
              ),
            ),
            Padding(
              padding: const EdgeInsets.fromLTRB(14, 4, 14, 8),
              child: Wrap(
                children: allTags.map((tag) {
                  final rule = _canvasFilterRules.firstWhere(
                    (r) => r.field == TaskFilterField.tag,
