          ],

          // Filter by Project
          if (allProjects.isNotEmpty) ...[
            Padding(
              padding: const EdgeInsets.fromLTRB(14, 4, 14, 4),
              child: Text(
                'FILTER BY PROJECT',
                style: TextStyle(
                  fontSize: 9,
                  letterSpacing: 1.0,
                  fontWeight: FontWeight.w700,
                  color: Colors.white38,
                ),
