          ],

          // Sort
          const Divider(color: borderColor, height: 1),
          Padding(
            padding: const EdgeInsets.fromLTRB(14, 10, 14, 4),
            child: Text(
              'SORT',
              style: TextStyle(
                fontSize: 9,
                letterSpacing: 1.0,
                fontWeight: FontWeight.w700,
                color: Colors.white38,
              ),
            ),
          ),
          Padding(
            padding: const EdgeInsets.fromLTRB(14, 4, 14, 12),
            child: Wrap(
              children: TaskSortOption.values.map((opt) {
                final active =
                    _canvasSortCriteria.isNotEmpty &&
                    _canvasSortCriteria.first.field == opt;
                final asc = active && _canvasSortCriteria.first.ascending;
                return GestureDetector(
                  onTap: () => setState(() {
                    if (active) {
                      if (asc) {
