  /// Per-section Filter / Sort panel — mirrors _buildCanvasFilterPanel but
  /// uses [_sectionFilterRules], [_sectionSortCriteria] keyed by [section].
  Widget _buildSectionFilterPanel(String section) {
    const accent = Color(0xFF4FC3F7);
    const bg = Color(0xFF1A1C1F);
    const surface = Color(0xFF22252A);
    const borderColor = Color(0xFF2C2F35);

    // Lazy-init lists for this section
    final filterRules = _sectionFilterRules.putIfAbsent(section, () => []);
    final sortCriteria = _sectionSortCriteria.putIfAbsent(section, () => []);

    // Tasks visible in this section
    List<String> sectionIds;
    if (section == 'Favorites') {
      sectionIds = _projectOrder
          .where((id) => _favoriteProjectIds.contains(id))
          .toList();
    } else if (section == 'All') {
      sectionIds = List.from(_projectOrder);
    } else {
      sectionIds = _projectOrder
          .where((id) => (_categoryMappings[section] ?? {}).contains(id))
          .toList();
    }
    final sectionProjects = _projects.entries
        .where((e) => sectionIds.contains(e.key))
        .toList();
    final allTags = {
      for (final t in _canvasTasks.where(
        (t) => sectionIds.contains(t.projectId),
      ))
        ...t.tagIds.map((id) => id.toString()),
    }.toList()..sort();

    final hasActiveFilters =
        filterRules.any((r) => r.isConfigured) || sortCriteria.isNotEmpty;

    Widget chip({
      required String label,
      required bool active,
      required VoidCallback onTap,
    }) {
      return GestureDetector(
        onTap: onTap,
        child: AnimatedContainer(
          duration: const Duration(milliseconds: 100),
          margin: const EdgeInsets.only(right: 4, bottom: 4),
          padding: const EdgeInsets.symmetric(horizontal: 8, vertical: 4),
          decoration: BoxDecoration(
            color: active ? accent.withOpacity(0.15) : surface,
            borderRadius: BorderRadius.circular(5),
            border: Border.all(
              color: active ? accent.withOpacity(0.5) : borderColor,
            ),
          ),
          child: Text(
            label,
            style: TextStyle(
              fontSize: 11,
              color: active ? accent : Colors.white54,
              fontWeight: active ? FontWeight.w600 : FontWeight.normal,
            ),
          ),
        ),
      );
    }

    return Container(
      decoration: BoxDecoration(
        color: bg,
        borderRadius: BorderRadius.circular(10),
        border: Border.all(color: borderColor),
        boxShadow: [
          BoxShadow(color: Colors.black.withOpacity(0.45), blurRadius: 20),
        ],
      ),
