                          style: TextStyle(
                            fontSize: 11,
                            color: active ? accent : Colors.white54,
                            fontWeight: active
                                ? FontWeight.w600
                                : FontWeight.normal,
                          ),
                        ),
                        if (active) ...[
                          const SizedBox(width: 4),
                          Icon(
                            asc
                                ? Icons.arrow_upward_rounded
                                : Icons.arrow_downward_rounded,
                            size: 11,
                            color: accent,
                          ),
                        ],
                      ],
                    ),
                  ),
                );
              }).toList(),
            ),
          ),
        ],
      ),
    );
  }

  Widget _buildFilterSidebar() {
    if (!_filterSidebarOpen) return const SizedBox.shrink();

    final allTags = {
      for (final t in _allTasks) ...t.tagIds.map((id) => id.toString()),
    }.toList()..sort();
    final allProjects = _projects.entries.toList();

    // ── shared helpers ──────────────────────────────────────────────────────
    const accent = Color(0xFF4FC3F7);
    const bg = Color(0xFF1A1C1F);
    const surface = Color(0xFF22252A);
    const border = Color(0xFF2C2F35);

    Widget sectionHeader(String title, VoidCallback onClearAll) {
      return Padding(
        padding: const EdgeInsets.fromLTRB(14, 14, 10, 6),
        child: Row(
          children: [
            Text(
              title,
              style: const TextStyle(
                fontSize: 10,
                fontWeight: FontWeight.w700,
                letterSpacing: 1.0,
                color: Colors.white60,
              ),
            ),
            const Spacer(),
            GestureDetector(
              onTap: onClearAll,
              child: const Text(
                'Clear All',
                style: TextStyle(fontSize: 9, color: accent),
              ),
            ),
          ],
        ),
      );
    }

    Widget fieldDropdown<T>({
      required T value,
      required List<T> items,
      required String Function(T) label,
      required void Function(T) onChanged,
    }) {
      return GestureDetector(
        onTap: () => showDialog<T>(
          context: context,
          barrierColor: Colors.transparent,
          builder: (_) => _DropdownDialog<T>(
            current: value,
            items: items,
            itemLabel: label,
            onSelected: (v) {
              onChanged(v);
              Navigator.of(context).pop();
            },
          ),
        ),
        child: Container(
          padding: const EdgeInsets.symmetric(horizontal: 8, vertical: 6),
          decoration: BoxDecoration(
            color: surface,
            borderRadius: BorderRadius.circular(5),
            border: Border.all(color: border),
          ),
          child: Row(
            mainAxisSize: MainAxisSize.min,
            children: [
              Flexible(
                child: Text(
                  label(value),
                  overflow: TextOverflow.ellipsis,
                  style: const TextStyle(fontSize: 11, color: Colors.white70),
                ),
              ),
              const SizedBox(width: 4),
              const Icon(
                Icons.expand_more_rounded,
                size: 12,
                color: Colors.white38,
              ),
            ],
          ),
        ),
      );
    }

    Widget dirBtn(
      bool asc,
      void Function(bool) onTap, {
      String? ascLabel,
      String? descLabel,
    }) {
      return GestureDetector(
        onTap: () => onTap(!asc),
        child: Container(
          padding: const EdgeInsets.symmetric(horizontal: 6, vertical: 5),
          decoration: BoxDecoration(
            color: accent.withOpacity(0.12),
            borderRadius: BorderRadius.circular(4),
            border: Border.all(color: accent.withOpacity(0.3)),
          ),
          child: Text(
            asc ? (ascLabel ?? '↑ Asc') : (descLabel ?? '↓ Desc'),
            style: const TextStyle(
              fontSize: 9,
              color: accent,
              fontWeight: FontWeight.w600,
            ),
          ),
        ),
      );
    }

    Widget removeBtn(VoidCallback onTap) => GestureDetector(
      onTap: onTap,
      child: const Padding(
        padding: EdgeInsets.only(left: 4),
        child: Icon(Icons.close_rounded, size: 14, color: Colors.white30),
      ),
    );

    // ── FILTER value widget per rule ────────────────────────────────────────
    Widget filterValueWidget(FilterRule rule) {
      switch (rule.field) {
        case TaskFilterField.none:
          return const SizedBox.shrink();

        case TaskFilterField.name:
          return _NameFilterField(
            initialValue: rule.nameQuery,
            onChanged: (v) => setState(() => rule.nameQuery = v),
          );

        case TaskFilterField.tag:
        case TaskFilterField.project:
        case TaskFilterField.status:
          final items = rule.field == TaskFilterField.tag
              ? allTags
              : rule.field == TaskFilterField.project
              ? allProjects.map((e) => e.key).toList()
              : TaskStatus.values.map((s) => s.name).toList();
          String labelFor(String v) {
            if (rule.field == TaskFilterField.project) {
              return _projects[v]?.title ?? v;
            }
            if (rule.field == TaskFilterField.status) {
              try {
                return TaskStatus.values.byName(v).label;
              } catch (_) {
                return v;
              }
            }
            return v;
          }

          return Column(
            crossAxisAlignment: CrossAxisAlignment.stretch,
            children: [
              ...items.map((v) {
                final checked = rule.selectedValues.contains(v);
                return GestureDetector(
                  onTap: () => setState(() {
                    if (checked)
                      rule.selectedValues.remove(v);
                    else
                      rule.selectedValues.add(v);
                  }),
                  child: Padding(
                    padding: const EdgeInsets.symmetric(vertical: 3),
                    child: Row(
                      children: [
                        AnimatedContainer(
                          duration: const Duration(milliseconds: 100),
                          width: 14,
                          height: 14,
                          decoration: BoxDecoration(
                            color: checked
                                ? accent.withOpacity(0.2)
                                : Colors.transparent,
                            borderRadius: BorderRadius.circular(3),
                            border: Border.all(
                              color: checked ? accent : Colors.white30,
                              width: 1.2,
                            ),
                          ),
                          child: checked
                              ? const Icon(
                                  Icons.check_rounded,
                                  size: 10,
                                  color: accent,
                                )
                              : null,
                        ),
                        const SizedBox(width: 8),
                        if (rule.field == TaskFilterField.status) ...[
                          Builder(
                            builder: (_) {
                              try {
                                final s = TaskStatus.values.byName(v);
                                return Row(
                                  children: [
                                    Icon(s.icon, size: 11, color: s.color),
                                    const SizedBox(width: 4),
                                  ],
                                );
                              } catch (_) {
                                return const SizedBox.shrink();
                              }
                            },
                          ),
                        ],
                        Expanded(
                          child: Text(
                            labelFor(v),
                            style: TextStyle(
                              fontSize: 11,
                              color: checked ? Colors.white : Colors.white60,
                            ),
                          ),
                        ),
                      ],
                    ),
                  ),
                );
              }),
            ],
          );

        case TaskFilterField.scheduledDate:
          String fmt(DateTime? d) => d == null
              ? 'Any'
              : '${d.day.toString().padLeft(2, '0')}/${d.month.toString().padLeft(2, '0')}/${d.year}';

          Widget datePick(
            String label,
            DateTime? val,
            void Function(DateTime) onPick,
          ) {
            return Row(
              children: [
                SizedBox(
                  width: 36,
                  child: Text(
                    label,
                    style: const TextStyle(fontSize: 10, color: Colors.white38),
                  ),
                ),
                Expanded(
                  child: GestureDetector(
                    onTap: () async {
                      final p = await showDatePicker(
                        context: context,
                        initialDate: val ?? DateTime.now(),
                        firstDate: DateTime(2020),
                        lastDate: DateTime(2040),
                        builder: (ctx, c) => Theme(
                          data: Theme.of(ctx).copyWith(
                            colorScheme: const ColorScheme.dark(
                              primary: accent,
                              surface: Color(0xFF1E2124),
                            ),
                          ),
                          child: c!,
                        ),
                      );
                      if (p != null) onPick(p);
                    },
                    child: Container(
                      padding: const EdgeInsets.symmetric(
                        horizontal: 8,
                        vertical: 5,
                      ),
                      decoration: BoxDecoration(
                        color: surface,
                        borderRadius: BorderRadius.circular(4),
                        border: Border.all(color: border),
                      ),
                      child: Text(
                        fmt(val),
                        style: const TextStyle(
                          fontSize: 10,
                          color: Colors.white70,
                        ),
                      ),
                    ),
                  ),
                ),
                if (val != null)
                  GestureDetector(
                    onTap: () => setState(() {
                      if (label == 'From')
                        rule.dateFrom = null;
                      else
                        rule.dateTo = null;
                    }),
                    child: const Padding(
                      padding: EdgeInsets.only(left: 4),
                      child: Icon(
                        Icons.close_rounded,
                        size: 12,
                        color: Colors.white30,
                      ),
                    ),
                  ),
              ],
            );
          }

          return Column(
            crossAxisAlignment: CrossAxisAlignment.stretch,
            children: [
              datePick(
                'From',
                rule.dateFrom,
                (d) => setState(() => rule.dateFrom = d),
              ),
              const SizedBox(height: 5),
              datePick(
                'To',
                rule.dateTo,
                (d) => setState(() => rule.dateTo = d),
              ),
            ],
          );

        case TaskFilterField.estimatedTime:
        case TaskFilterField.timeSpent:
          return Row(
            children: [
              Expanded(
                child: _MinuteInput(
                  label: 'Min',
                  value: rule.numMin,
                  onChanged: (v) => setState(() => rule.numMin = v),
                ),
              ),
              const SizedBox(width: 6),
              Expanded(
                child: _MinuteInput(
                  label: 'Max',
                  value: rule.numMax,
                  onChanged: (v) => setState(() => rule.numMax = v),
                ),
              ),
            ],
          );
      }
    }

    // ── Build section ──────────────────────────────────────────────────────
    return Container(
      width: 264,
      decoration: BoxDecoration(
        color: bg,
        border: Border(left: BorderSide(color: Colors.white.withOpacity(0.07))),
      ),
      child: Column(
