  OverlayEntry? _stagingOverlayEntry;
  bool _stagingOverlayVisible = false;

  void _startTaskStaging(String taskId) {
    _stagingTimer?.cancel();
    // Stop general timer and flowtime if running
    if (_activeGeneralTaskId != null) _stopGeneralTimer();
    if (_activeFlowtimeTaskId != null) _stopFlowtimeTimer();
    // Create a new execution session
    final session = _ExecutionSession(
      id: DateTime.now().millisecondsSinceEpoch.toString(),
      startTime: DateTime.now(),
      blocksSnapshot: _stagingBlocks.map((b) => b.copy()).toList(),
    );
    _taskSessions.putIfAbsent(taskId, () => []).add(session);
    // If continuing an interrupted session, restore phase/elapsed
    final isContinuing = _interruptedTaskId == taskId;
    final resumePhase = isContinuing ? _interruptedPhaseIndex : 0;
    final elapsedAlreadySeconds = isContinuing
        ? _interruptedPhaseElapsedSeconds
        : 0;
    final adjustedStart = DateTime.now().subtract(
      Duration(seconds: elapsedAlreadySeconds),
    );

    // Snapshot the task's current timeSpent so we can add live elapsed on top
    final taskToStage = _allTasks.firstWhere(
      (t) => t.id == taskId,
      orElse: () => Task(
        id: '',
        title: '',
        isDone: false,
        projectId: '',
        subTaskIds: [],
        timeSpent: 0,
        attachments: [],
        tagIds: [],
      ),
    );
    _timerBaseSpentMs = taskToStage.id.isNotEmpty ? taskToStage.timeSpent : 0;
    final stagingStartedAt = DateTime.now();

    setState(() {
      _activeStagingTaskId = taskId;
      _currentSessionId = session.id;
      _stagingPhaseIndex = resumePhase;
      _stagingPhaseStarted = adjustedStart;
      // Clear saved interruption
      _interruptedTaskId = null;
      _interruptedPhaseIndex = 0;
      _interruptedPhaseElapsedSeconds = 0;
    });
    _stagingTimer = Timer.periodic(const Duration(seconds: 1), (_) {
      if (!mounted) return;
      if (_stagingBlocks.isEmpty || _stagingPhaseStarted == null) return;
      final phaseIdx = _stagingPhaseIndex % _stagingBlocks.length;
      final block = _stagingBlocks[phaseIdx];
      final elapsed = DateTime.now()
          .difference(_stagingPhaseStarted!)
          .inSeconds;

      // Update task.timeSpent live so the overlay's task-remaining countdown
      // progresses in real time (same pattern as the simple timer).
      final t = _allTasks.firstWhere(
        (t) => t.id == _activeStagingTaskId,
        orElse: () => Task(
          id: '',
          title: '',
          isDone: false,
          projectId: '',
          subTaskIds: [],
          timeSpent: 0,
          attachments: [],
          tagIds: [],
        ),
      );
      if (t.id.isNotEmpty) {
        final totalElapsed = DateTime.now()
            .difference(stagingStartedAt)
            .inMilliseconds;
        t.timeSpent = _timerBaseSpentMs + totalElapsed;
      }

      if (elapsed >= block.minutes * 60) {
        setState(() {
          _stagingPhaseIndex++;
          _stagingPhaseStarted = DateTime.now();
        });
      } else {
        setState(() {});
      }
      _stagingOverlayEntry?.markNeedsBuild();
    });
    _showStagingOverlay(taskId);
  }

  void _interruptStaging() {
    _stagingTimer?.cancel();
    _stagingTimer = null;
    // Finalize session as interrupted
    final sessions = _taskSessions[_activeStagingTaskId];
    if (sessions != null && sessions.isNotEmpty) {
      final session = sessions.lastWhere(
        (s) => s.id == _currentSessionId,
        orElse: () => sessions.last,
      );
      setState(() {
        session.endTime = DateTime.now();
        session.status = _SessionStatus.interrupted;
      });
    }
    // Save exact phase + elapsed so we can resume from the same point
    final elapsedInPhase = _stagingPhaseStarted != null
        ? DateTime.now().difference(_stagingPhaseStarted!).inSeconds
        : 0;
    final blocks = _stagingBlocks.isEmpty
        ? [
            _StagingBlock(type: _StagingType.work, minutes: 25),
            _StagingBlock(type: _StagingType.rest, minutes: 5),
          ]
        : _stagingBlocks;
    final phaseIdx = _stagingPhaseIndex % blocks.length;
    final phaseTotalSecs = blocks[phaseIdx].minutes * 60;
    _stagingOverlayEntry?.remove();
    _stagingOverlayEntry = null;
    setState(() {
      _interruptedTaskId = _activeStagingTaskId;
      _interruptedPhaseIndex = _stagingPhaseIndex;
      // Clamp so we don't overshoot the phase on resume
      _interruptedPhaseElapsedSeconds = elapsedInPhase.clamp(
        0,
        phaseTotalSecs - 1,
      );
      _activeStagingTaskId = null;
      _currentSessionId = null;
      _stagingPhaseIndex = 0;
      _stagingPhaseStarted = null;
      _stagingOverlayVisible = false;
    });
  }

  void _showStagingOverlay(String taskId) {
    _stagingOverlayEntry?.remove();
    _stagingOverlayVisible = true;
    _stagingOverlayEntry = OverlayEntry(
      builder: (ctx) {
        final task = _allTasks.firstWhere(
          (t) => t.id == _activeStagingTaskId,
          orElse: () => Task(
            id: '',
            title: taskId,
            isDone: false,
            projectId: '',
            subTaskIds: [],
            timeSpent: 0,
            attachments: [],
            tagIds: [],
          ),
        );
        return _StagingOverlay(
          task: task,
          stagingBlocks: _stagingBlocks,
          phaseIndex: _stagingPhaseIndex,
          phaseStarted: _stagingPhaseStarted,
          onStop: () {
            _stagingOverlayEntry?.remove();
            _stagingOverlayEntry = null;
            setState(() => _stagingOverlayVisible = false);
          },
          onInterrupt: _interruptStaging,
          onComplete: () {
            setState(() {
              task.status = TaskStatus.done;
              task.isDone = true;
            });
            _saveTaskToMeta(task);
            _stopTaskStaging(completed: true);
          },
        );
      },
    );
    if (mounted) Overlay.of(context).insert(_stagingOverlayEntry!);
  }

  void _stopTaskStaging({bool completed = false}) {
    _stagingTimer?.cancel();
    _stagingTimer = null;
    // Finalize running session
    final sessions = _taskSessions[_activeStagingTaskId];
    if (sessions != null && sessions.isNotEmpty) {
      final session = sessions.lastWhere(
        (s) => s.id == _currentSessionId,
        orElse: () => sessions.last,
      );
      setState(() {
        session.endTime = DateTime.now();
        session.status = completed
            ? _SessionStatus.completed
            : _SessionStatus.interrupted;
      });
    }
    _stagingOverlayEntry?.remove();
    _stagingOverlayEntry = null;
    _timerBaseSpentMs = 0;
    setState(() {
      _activeStagingTaskId = null;
      _currentSessionId = null;
      _stagingPhaseIndex = 0;
      _stagingPhaseStarted = null;
      _stagingOverlayVisible = false;
    });
  }

  void _startTaskTimer(String taskId) {
    // Stop any running timer first
    if (_activeTimerTaskId != null) _stopTaskTimer();
    final task = _allTasks.firstWhere(
      (t) => t.id == taskId,
      orElse: () => Task(
        id: '',
        title: '',
        isDone: false,
        projectId: '',
        subTaskIds: [],
        timeSpent: 0,
        attachments: [],
        tagIds: [],
      ),
    );
    _timerBaseSpentMs = task.id.isNotEmpty ? task.timeSpent : 0;
    setState(() {
      _activeTimerTaskId = taskId;
      _timerStartedAt = DateTime.now();
    });
    // Tick every second — update task.timeSpent live so UI and timeline reflect it
    _taskTimer = Timer.periodic(const Duration(seconds: 1), (_) {
      if (!mounted) return;
      final t = _allTasks.firstWhere(
        (t) => t.id == _activeTimerTaskId,
        orElse: () => Task(
          id: '',
          title: '',
          isDone: false,
          projectId: '',
          subTaskIds: [],
          timeSpent: 0,
          attachments: [],
          tagIds: [],
        ),
      );
      if (t.id.isNotEmpty && _timerStartedAt != null) {
        final elapsed = DateTime.now()
            .difference(_timerStartedAt!)
            .inMilliseconds;
        t.timeSpent = _timerBaseSpentMs + elapsed;
      }
      setState(() {});
    });
  }

  void _stopTaskTimer() {
    _taskTimer?.cancel();
    _taskTimer = null;
    if (_activeTimerTaskId != null && _timerStartedAt != null) {
      final elapsed = DateTime.now()
          .difference(_timerStartedAt!)
          .inMilliseconds;
      final task = _allTasks.firstWhere(
        (t) => t.id == _activeTimerTaskId,
        orElse: () => Task(
          id: '',
          title: '',
          isDone: false,
          projectId: '',
          subTaskIds: [],
          timeSpent: 0,
          attachments: [],
          tagIds: [],
        ),
      );
      if (task.id.isNotEmpty) {
        task.timeSpent = _timerBaseSpentMs + elapsed;
        _saveTaskToMeta(task);
      }
    }
    _timerBaseSpentMs = 0;
    setState(() {
      _activeTimerTaskId = null;
      _timerStartedAt = null;
    });
  }

  // ── General (non-segmented) timer ─────────────────────────────────────────

  void _startGeneralTimer(String taskId) {
    _stopGeneralTimer();
    // Also stop staging and flowtime if running
    if (_activeStagingTaskId != null) _interruptStaging();
    if (_activeFlowtimeTaskId != null) _stopFlowtimeTimer();

    final task = _allTasks.firstWhere(
      (t) => t.id == taskId,
      orElse: () => Task(
        id: '',
        title: '',
        isDone: false,
        projectId: '',
        subTaskIds: [],
        timeSpent: 0,
        attachments: [],
        tagIds: [],
      ),
    );
    final session = _ExecutionSession(
      id: 'general_${DateTime.now().millisecondsSinceEpoch}',
      startTime: DateTime.now(),
      blocksSnapshot: [], // no W/R segmentation
    );
    _taskSessions.putIfAbsent(taskId, () => []).add(session);
    _timerBaseSpentMs = task.id.isNotEmpty ? task.timeSpent : 0;
    final now = DateTime.now();
    setState(() {
      _activeGeneralTaskId = taskId;
      _generalTimerStartedAt = now;
      _currentSessionId = session.id;
      // Mirror into _activeTimerTaskId / _timerStartedAt so the task-card
      // button shows its active state and _formatElapsed() works correctly.
      _activeTimerTaskId = taskId;
      _timerStartedAt = now;
    });

    _generalTimer = Timer.periodic(const Duration(seconds: 1), (_) {
      if (!mounted) return;
      final t = _allTasks.firstWhere(
        (t) => t.id == _activeGeneralTaskId,
        orElse: () => Task(
          id: '',
          title: '',
          isDone: false,
          projectId: '',
          subTaskIds: [],
          timeSpent: 0,
          attachments: [],
          tagIds: [],
        ),
      );
      if (t.id.isNotEmpty && _generalTimerStartedAt != null) {
        final elapsed = DateTime.now()
            .difference(_generalTimerStartedAt!)
            .inMilliseconds;
        t.timeSpent = _timerBaseSpentMs + elapsed;
      }
      setState(() {});
      _generalOverlayEntry?.markNeedsBuild();
    });

    _showGeneralOverlay(taskId);
  }

  void _stopGeneralTimer() {
    _generalTimer?.cancel();
    _generalTimer = null;
    _generalOverlayEntry?.remove();
    _generalOverlayEntry = null;

    if (_activeGeneralTaskId != null && _generalTimerStartedAt != null) {
      // Finalize session
      final sessions = _taskSessions[_activeGeneralTaskId];
      if (sessions != null && sessions.isNotEmpty) {
        final session = sessions.lastWhere(
          (s) => s.id == _currentSessionId,
          orElse: () => sessions.last,
        );
        session.endTime = DateTime.now();
        session.status = _SessionStatus.completed;
      }
      final elapsed = DateTime.now()
          .difference(_generalTimerStartedAt!)
          .inMilliseconds;
      final task = _allTasks.firstWhere(
        (t) => t.id == _activeGeneralTaskId,
        orElse: () => Task(
          id: '',
          title: '',
          isDone: false,
          projectId: '',
          subTaskIds: [],
          timeSpent: 0,
          attachments: [],
          tagIds: [],
        ),
      );
      if (task.id.isNotEmpty) {
        task.timeSpent = _timerBaseSpentMs + elapsed;
        _saveTaskToMeta(task);
      }
    }
    _timerBaseSpentMs = 0;
    setState(() {
      _activeGeneralTaskId = null;
      _generalTimerStartedAt = null;
      _currentSessionId = null;
      // Clear the mirrored task-card active state too.
      _activeTimerTaskId = null;
      _timerStartedAt = null;
    });
  }

  /// Flowtime: fully independent elapsed-up timer — does NOT share state with
