  String _formatElapsed() {
    if (_timerStartedAt == null) return '0:00';
    final s = DateTime.now().difference(_timerStartedAt!).inSeconds;
    final m = s ~/ 60;
    final sec = s % 60;
    return '$m:${sec.toString().padLeft(2, '0')}';
  }

  void _dismissAddTaskOverlay() {
    _addTaskOverlay?.remove();
    _addTaskOverlay = null;
    _addTaskCtrl.clear();
    _addTaskProjectId = null;
    _addTaskDueDay = null;
    _addTaskTags.clear();
  }

  // Spec §2: returns true and shows a snackbar if [title] already exists in
  // [projectId] (case-insensitive). Pass null projectId to skip the check.
  bool _taskTitleConflict(String title, String? projectId) {
    if (projectId == null || projectId.isEmpty) return false;
    final conflict = _allTasks.any(
      (t) =>
          t.projectId == projectId &&
          t.title.toLowerCase() == title.toLowerCase(),
    );
    if (conflict) {
      final projName = _projects[projectId]?.title ?? 'this project';
      ScaffoldMessenger.of(context).showSnackBar(
        SnackBar(
          content: Text('A task named "$title" already exists in $projName.'),
          backgroundColor: const Color(0xFFB71C1C),
          duration: const Duration(seconds: 3),
        ),
      );
    }
    return conflict;
  }

  void _commitAddTask() {
    final title = _addTaskCtrl.text.trim();
    if (title.isEmpty) {
      _dismissAddTaskOverlay();
      return;
    }
    // Parse inline #tag and @time from title
    String cleanTitle = title;
    final tagMatches = RegExp(r'#(\S+)').allMatches(title);
    final timeMatch = RegExp(r'@(\S+)').firstMatch(title);
    final inlineTags = tagMatches.map((m) => m.group(1)!).toList();
    cleanTitle = cleanTitle
        .replaceAll(RegExp(r'#\S+'), '')
        .replaceAll(RegExp(r'@\S+'), '')
        .trim();

    final resolvedTitle = cleanTitle.isEmpty ? title : cleanTitle;
    // Spec §1: strip reserved chars from the final title.
    final safeTitle = resolvedTitle.replaceAll(RegExp(r'[/\\:]'), '').trim();
    if (safeTitle.isEmpty) {
      _dismissAddTaskOverlay();
      return;
    }

    final resolvedProjectId =
        _addTaskProjectId ??
        (_tasksNavSection.startsWith('proj:')
            ? _tasksNavSection.substring(5)
            : (_projectOrder.isNotEmpty ? _projectOrder.first : ''));

    // Spec §2: block duplicate task names within the same project.
    if (_taskTitleConflict(safeTitle, resolvedProjectId)) {
      return;
    }

    final newTask = Task(
      id: DateTime.now().millisecondsSinceEpoch.toString(),
      title: safeTitle,
      isDone: false,
      projectId: resolvedProjectId,
      subTaskIds: [],
      timeSpent: 0,
      attachments: [],
      tagIds: [
        ...inlineTags,
        ..._addTaskTags,
        // Feature 2: auto-assign the current tag when creating from a tag page
        if (_tasksNavSection.startsWith('tag:') &&
            !_addTaskTags.contains(_tasksNavSection.substring(4)) &&
            !inlineTags.contains(_tasksNavSection.substring(4)))
          _tasksNavSection.substring(4),
      ],
      dueDay:
          _addTaskDueDay ??
          (timeMatch != null ? DateTime.now().toIso8601String() : null),
    );
    setState(() => _allTasks.add(newTask));
    _saveTaskToMeta(newTask);
    _dismissAddTaskOverlay();
  }

  void _showAddTaskOverlay() {
    if (_addTaskOverlay != null) {
      _dismissAddTaskOverlay();
      return;
    }

    // Pre-populate the current tag when opening from a tag page.
    if (_tasksNavSection.startsWith('tag:')) {
      final currentTag = _tasksNavSection.substring(4);
      if (!_addTaskTags.contains(currentTag)) {
        _addTaskTags.add(currentTag);
      }
    }

    // Find position of the action bar to anchor the popup below it
    final RenderBox? btnBox =
        _addTaskBtnKey.currentContext?.findRenderObject() as RenderBox?;

    double top = 52; // fallback: height of action bar
    double left = 0;
    double width = 480;

    if (btnBox != null) {
      // Use globalToLocal-free absolute position — safe across rebuilds
      final btnGlobal = btnBox.localToGlobal(Offset.zero);
      top = btnGlobal.dy + btnBox.size.height + 4;
      left = btnGlobal.dx - 400;
      if (left < 8) left = 8;
    }

    _addTaskOverlay = OverlayEntry(
      builder: (ctx) {
        return _AddTaskOverlay(
          top: top,
          left: left,
          width: width,
          controller: _addTaskCtrl,
          projects: _projects,
          projectOrder: _projectOrder,
          selectedProjectId: _addTaskProjectId,
          selectedDueDay: _addTaskDueDay,
          selectedTags: _addTaskTags,
          allTags: _allTasks
              .expand((t) => t.tagIds.map((id) => id.toString()))
              .toSet()
              .toList(),
          onProjectChanged: (id) {
            _addTaskProjectId = id;
            _addTaskOverlay?.markNeedsBuild();
          },
          onDueDayChanged: (d) {
            _addTaskDueDay = d;
            _addTaskOverlay?.markNeedsBuild();
          },
          onTagToggled: (tag) {
            if (_addTaskTags.contains(tag)) {
              _addTaskTags.remove(tag);
            } else {
              _addTaskTags.add(tag);
            }
            _addTaskOverlay?.markNeedsBuild();
          },
          onCommit: _commitAddTask,
          onDismiss: _dismissAddTaskOverlay,
        );
      },
    );
    if (mounted) Overlay.of(context).insert(_addTaskOverlay!);
    // focus is handled inside _AddTaskOverlay
  }

  void _commitInlineTask() {
    final title = _inlineAddCtrl.text.trim();
    if (title.isEmpty) {
      setState(() {
        _inlineAddActive = false;
        _inlineAddProjectId = null;
        _inlineAddDueDay = null;
        _inlineAddTags.clear();
      });
      return;
    }
    // Parse inline #tag, @time, and %project from title
    String cleanTitle = title;
    final tagMatches = RegExp(r'#(\S+)').allMatches(title);
    final timeMatch = RegExp(r'@(\S+)').firstMatch(title);
    final projectMatch = RegExp(r'%(\S+)').firstMatch(title);
    final inlineTags = tagMatches.map((m) => m.group(1)!).toList();
    cleanTitle = cleanTitle
        .replaceAll(RegExp(r'#\S+'), '')
        .replaceAll(RegExp(r'@\S+'), '')
        .replaceAll(RegExp(r'%\S+'), '')
        .trim();

    // Project: % inline token > explicit pill selection > page context
    String? inlineProjectId;
    if (projectMatch != null) {
      final query = projectMatch.group(1)!.toLowerCase();
      final match = _projects.entries.firstWhere(
        (e) => e.value.title.toLowerCase().startsWith(query),
        orElse: () => MapEntry('', Project(id: '', title: '')),
      );
      if (match.key.isNotEmpty) inlineProjectId = match.key;
    }

    // Project: % inline token > explicit pill selection > page context
    // When in Today (a cross-project view), default to Inbox rather than
    // the first project — the user hasn't indicated a project.
    final String contextProjectId = _tasksNavSection.startsWith('proj:')
        ? _tasksNavSection.substring(5)
        : 'INBOX_PROJECT';
    final String projectId =
        inlineProjectId ?? _inlineAddProjectId ?? contextProjectId;

    final String? dueDay =
        _inlineAddDueDay ??
        (_tasksNavSection == 'Today'
            ? DateTime.now().toIso8601String()
            : timeMatch != null
            ? DateTime.now().toIso8601String()
            : null);

    final safeInlineTitle = (cleanTitle.isEmpty ? title : cleanTitle)
        .replaceAll(RegExp(r'[/\\:]'), '')
        .trim();
    if (safeInlineTitle.isEmpty) {
      setState(() {
        _inlineAddActive = false;
        _inlineAddCtrl.clear();
        _inlineAddProjectId = null;
        _inlineAddDueDay = null;
        _inlineAddTags.clear();
      });
      return;
    }

    // Spec §2: block duplicate task names within the same project.
    if (_taskTitleConflict(safeInlineTitle, projectId)) return;

    final newTask = Task(
      id: DateTime.now().millisecondsSinceEpoch.toString(),
      title: safeInlineTitle,
      isDone: false,
      projectId: projectId,
      subTaskIds: [],
      timeSpent: 0,
      attachments: [],
      tagIds: [
        ...inlineTags,
        ..._inlineAddTags,
        // Auto-assign the current tag when creating from a tag page.
        if (_tasksNavSection.startsWith('tag:') &&
            !_inlineAddTags.contains(_tasksNavSection.substring(4)) &&
            !inlineTags.contains(_tasksNavSection.substring(4)))
          _tasksNavSection.substring(4),
      ],
      dueDay: dueDay,
    );
    setState(() {
      _allTasks.add(newTask);
      _inlineAddCtrl.clear();
      _inlineAddActive = false;
      _inlineAddProjectId = null;
      _inlineAddDueDay = null;
      _inlineAddTags.clear();
    });
    _saveTaskToMeta(newTask);
  }

  Widget _buildTasksList() {
    final now = DateTime.now();
    final today = DateTime(now.year, now.month, now.day);

    final allSubtaskIds = _allTasks
        .expand((t) => t.subTaskIds.map((id) => id.toString()))
        .toSet();

    List<Task> pool = _allTasks.where((t) {
      // Never show a subtask at the root level — it belongs under its parent
      if (allSubtaskIds.contains(t.id)) return false;
      // Repeat instances are filtered out in Today/Inbox (only 1 per series
      // would show there anyway). In project/tag/All views they are included
      // so the bucket-level grouping can display them under their series.
      if (t.repeatParentId != null &&
          (_tasksNavSection == 'Today' || _tasksNavSection == 'Inbox')) {
        return false;
      }
      if (_tasksNavSection == 'Today') {
        // Cross-project smart view: only tasks that have a date and are
        // due today or overdue. Undated tasks belong in their own project
        // or Inbox — not in Today.
        if (t.dueDay == null) return false;
        final due = DateTime.tryParse(t.dueDay!);
        if (due == null) return false;
        return !DateTime(due.year, due.month, due.day).isAfter(today);
      }
      if (_tasksNavSection == 'Inbox') return t.projectId == 'INBOX_PROJECT';
      if (_tasksNavSection.startsWith('proj:'))
        return t.projectId == _tasksNavSection.substring(5);
      if (_tasksNavSection.startsWith('tag:'))
        return t.tagIds.contains(_tasksNavSection.substring(4));
      return true;
    }).toList();

    // ── Apply Grist-style Filter (AND of all active rules) ───────────────────
    final activeFilters = _filterRules.where((r) => r.isConfigured).toList();
    if (activeFilters.isNotEmpty) {
      pool = pool
          .where((t) => activeFilters.every((r) => r.matches(t, _projects)))
          .toList();
    }

    // ── Apply Grist-style Sort (ordered criteria, first = primary) ────────────
    if (_sortCriteria.isNotEmpty) {
      pool = _applySortCriteria(pool, _sortCriteria);
    } else {
      // Default: scheduled date ascending
      pool.sort((a, b) {
        final da = a.scheduledDate ?? DateTime(9999);
        final db = b.scheduledDate ?? DateTime(9999);
        return da.compareTo(db);
      });
    }

    // Split into buckets
    List<Task> overdue = [], todayTasks = [], inbox = [], doneTasks = [];
    for (final t in pool) {
      if (t.status == TaskStatus.done || t.status == TaskStatus.cancelled) {
        doneTasks.add(t);
        continue;
      }
      if (_tasksNavSection == 'Inbox') {
        // Split into overdue vs active, matching Project page structure.
        // Use scheduledDate so plannedAt-based tasks are also classified.
        final dueDate = t.scheduledDate;
        if (dueDate != null && dueDate.isBefore(today)) {
          overdue.add(t);
          continue;
        }
        inbox.add(t);
        continue;
      }
      // Today and project/tag views.
      // Use scheduledDate (which honours plannedAt first, then dueDay) so that
      // tasks scheduled via the canvas planner are classified correctly as
      // overdue or today — not silently dumped into the undated bucket.
      final dueDate = t.scheduledDate;
      if (dueDate == null) {
        // No scheduled date at all → undated tasks go into the main list
        todayTasks.add(t);
        continue;
      }
      if (dueDate.isBefore(today))
        overdue.add(t);
      else if (dueDate == today || _tasksNavSection != 'Today')
        todayTasks.add(t);
    }

    // Whether the current view should use bucket-level repeat grouping
    final bool useGroupedBuckets = _tasksNavSection != 'Inbox';

    Widget sectionBlock(
      String title,
      List<Task> tasks,
      bool expanded,
      VoidCallback toggle, {
      bool isOverdue = false,
      bool fixed = false,
      Widget Function(List<Task>)? contentBuilder,
    }) {
      final header = Container(
        padding: const EdgeInsets.symmetric(horizontal: 16, vertical: 10),
        decoration: BoxDecoration(
          border: Border(bottom: BorderSide(color: _tasksBorder, width: 0.5)),
        ),
        child: Row(
          children: [
            if (!fixed)
              Icon(
                expanded
                    ? Icons.keyboard_arrow_down
                    : Icons.keyboard_arrow_right,
                size: 14,
                color: isOverdue ? const Color(0xFFEF5350) : Colors.white38,
              ),
            if (!fixed) const SizedBox(width: 6),
            Text(
              title,
              style: TextStyle(
                fontSize: 11,
                fontWeight: FontWeight.w600,
                letterSpacing: 0.8,
                color: isOverdue ? const Color(0xFFEF5350) : Colors.white54,
              ),
            ),
            const SizedBox(width: 8),
            Container(
              padding: const EdgeInsets.symmetric(horizontal: 6, vertical: 1),
              decoration: BoxDecoration(
                color: isOverdue
                    ? const Color(0xFFEF5350).withOpacity(0.15)
                    : Colors.white.withOpacity(0.06),
                borderRadius: BorderRadius.circular(8),
              ),
              child: Text(
                '${tasks.length}',
                style: TextStyle(
                  fontSize: 10,
                  fontWeight: FontWeight.bold,
                  color: isOverdue ? const Color(0xFFEF5350) : Colors.white38,
                ),
              ),
            ),
          ],
        ),
      );

      return Column(
        crossAxisAlignment: CrossAxisAlignment.stretch,
        children: [
          // Section header — tappable toggle if not fixed, static otherwise
          if (fixed) header else InkWell(onTap: toggle, child: header),
          if (fixed || expanded)
            contentBuilder != null
                ? contentBuilder(tasks)
                : _buildReorderableTaskList(tasks, today, allSubtaskIds),
        ],
      );
    }

    // ── Stats bar ─────────────────────────────────────────────────────────
    final undoneTasks = [...todayTasks, ...overdue, ...inbox]
        .where(
          (t) =>
              t.status != TaskStatus.done && t.status != TaskStatus.cancelled,
        )
        .toList();

    final estimateMs = undoneTasks.fold<int>(
      0,
      (s, t) => s + t.durationMinutes * 60000,
    );
    final spentMs = undoneTasks.fold<int>(0, (s, t) => s + t.timeSpent);

    // Net focused time = total timeSpent minus rest intervals from Pomodoro sessions
    final totalRestMs = undoneTasks.fold<int>(0, (sum, t) {
      final sessions = _taskSessions[t.id] ?? [];
      return sum + sessions.fold<int>(0, (s, e) => s + e.restMs);
    });
    final netWorkMs = (spentMs - totalRestMs).clamp(0, spentMs);

    String durFmt(int ms) {
      if (ms <= 0) return '—';
      final h = ms ~/ 3600000;
      final m = (ms % 3600000) ~/ 60000;
      if (h > 0 && m > 0) return '~${h}h ${m}m';
      if (h > 0) return '~${h}h';
      return '~${m}m';
    }

    Widget statChip(String label, String value, IconData icon) {
      final hasValue = value != '—';
      final accent = _activeProjectAccent;
      return Row(
        mainAxisSize: MainAxisSize.min,
        children: [
          Text(
            '$label ',
            style: const TextStyle(fontSize: 10, color: Color(0xFF5A6070)),
          ),
          Text(
            value,
            style: TextStyle(
              fontSize: 10,
              fontWeight: FontWeight.w600,
              color: hasValue
                  ? accent.withOpacity(0.8)
                  : const Color(0xFF404550),
            ),
          ),
          const SizedBox(width: 3),
          Icon(
            icon,
            size: 11,
            color: hasValue ? accent.withOpacity(0.5) : const Color(0xFF353840),
          ),
        ],
      );
    }

    final statsBar = Padding(
      padding: const EdgeInsets.fromLTRB(16, 0, 16, 8),
      child: Row(
        children: [
          statChip(
            'Estimate remaining:',
            durFmt(estimateMs),
            Icons.hourglass_bottom_outlined,
          ),
          const SizedBox(width: 16),
          statChip('Working today:', durFmt(spentMs), Icons.timer_outlined),
          const SizedBox(width: 16),
          statChip('Without break:', durFmt(netWorkMs), Icons.coffee_outlined),
        ],
      ),
    );

    return ListView(
      padding: const EdgeInsets.only(top: 25, bottom: 30),
      children: [
        statsBar,
        // ── Inline quick-add bar ──────────────────────────────────────────
        Padding(
          padding: const EdgeInsets.fromLTRB(16, 0, 16, 12),
          child: _InlineAddTaskCard(
            active: _inlineAddActive,
            controller: _inlineAddCtrl,
            projects: _projects,
            projectOrder: _projectOrder,
            selectedProjectId: _inlineAddProjectId,
            selectedDueDay: _inlineAddDueDay,
            selectedTags: _inlineAddTags,
            allTags: _allTasks
                .expand((t) => t.tagIds.map((id) => id.toString()))
                .toSet()
                .toList(),
            onActivate: () => setState(() => _inlineAddActive = true),
            onProjectChanged: (id) => setState(() => _inlineAddProjectId = id),
            onDueDayChanged: (d) => setState(() => _inlineAddDueDay = d),
            onTagToggled: (tag) => setState(() {
              if (_inlineAddTags.contains(tag)) {
                _inlineAddTags.remove(tag);
              } else {
                _inlineAddTags.add(tag);
              }
            }),
            onCommit: _commitInlineTask,
            onDismiss: () => setState(() {
              _inlineAddCtrl.clear();
              _inlineAddActive = false;
              _inlineAddProjectId = null;
              _inlineAddDueDay = null;
              _inlineAddTags.clear();
            }),
          ),
        ),
        // Custom group selected: render all non-done tasks in custom groups
        if (_groupOption != TaskGroupOption.none)
          _buildGroupedByOption(
            pool
                .where(
                  (t) =>
                      t.status != TaskStatus.done &&
                      t.status != TaskStatus.cancelled,
                )
                .toList(),
            today,
            allSubtaskIds,
          ),
        // Inbox view: flat list of active tasks (no section header), matching
        // Project page structure. Overdue is handled below as a collapsible section.
        if (_groupOption == TaskGroupOption.none &&
            _tasksNavSection == 'Inbox' &&
            inbox.isNotEmpty)
          _buildReorderableTaskList(inbox, today, allSubtaskIds),
        // Today / project / tag views: flat reorderable list, no section header
        if (_groupOption != TaskGroupOption.none)
          const SizedBox.shrink() // already rendered above
        else if (todayTasks.isNotEmpty &&
            (_tasksNavSection == 'Today' ||
                _tasksNavSection.startsWith('proj:') ||
                _tasksNavSection.startsWith('tag:')))
          _buildReorderableTaskList(todayTasks, today, allSubtaskIds)
        else if (todayTasks.isNotEmpty)
          sectionBlock(
            'TASKS',
            todayTasks,
            _tasksTodayExpanded,
            () => setState(() => _tasksTodayExpanded = !_tasksTodayExpanded),
            contentBuilder: useGroupedBuckets
                ? (ts) => _buildGroupedBucketList(ts, today, allSubtaskIds)
                : null,
          ),
        // Spacer between tasks and OVERDUE (both Inbox and other views)
        if (_groupOption == TaskGroupOption.none && overdue.isNotEmpty)
          const SizedBox(height: 64),
        if (_groupOption == TaskGroupOption.none && overdue.isNotEmpty)
          sectionBlock(
            'OVERDUE',
            overdue,
            _tasksOverdueExpanded,
            () =>
                setState(() => _tasksOverdueExpanded = !_tasksOverdueExpanded),
            isOverdue: true,
            contentBuilder: useGroupedBuckets
                ? (ts) => _buildGroupedBucketList(ts, today, allSubtaskIds)
                : null,
          ),
        if (_groupOption == TaskGroupOption.none && doneTasks.isNotEmpty)
          sectionBlock(
            'DONE',
            doneTasks,
            _tasksDoneExpanded,
            () => setState(() => _tasksDoneExpanded = !_tasksDoneExpanded),
            contentBuilder: useGroupedBuckets
                ? (ts) => _buildGroupedBucketList(ts, today, allSubtaskIds)
                : null,
          ),
        if (pool.isEmpty)
          Padding(
            padding: const EdgeInsets.only(top: 80),
            child: Column(
              mainAxisSize: MainAxisSize.min,
              children: [
                Icon(
                  Icons.check_circle_outline,
                  size: 40,
                  color: Colors.white12,
                ),
                const SizedBox(height: 12),
                const Text(
                  'All clear',
                  style: TextStyle(color: Colors.white24, fontSize: 14),
                ),
              ],
            ),
          ),
      ],
    );
  }

  Widget _buildTaskRow(
    Task task,
    DateTime today,
    Set<String> allSubtaskIds, {
    Widget? dragHandle,
    bool inGroupedBucketView = false,
    int?
    bucketGroupChildCount, // number of same-bucket series children (for toggle label)
    String? bucketGroupKey, // series key for _repeatGroupsExpanded
  }) {
    final subtasks = _allTasks
        .where((t) => task.subTaskIds.any((id) => id.toString() == t.id))
        .toList();
    final isExpanded = _subtasksExpanded[task.id] ?? false;

    // Repeat instances: future occurrences belonging to this parent, sorted by date
    final repeatInstances =
        _allTasks.where((t) => t.repeatParentId == task.id).toList()
          ..sort((a, b) {
            final da = DateTime.tryParse(a.dueDay ?? '') ?? DateTime(9999);
            final db = DateTime.tryParse(b.dueDay ?? '') ?? DateTime(9999);
            return da.compareTo(db);
          });
    final repeatExpanded = _repeatInstancesExpanded[task.id] ?? false;

    return Column(
      key: ValueKey(task.id),
      mainAxisSize: MainAxisSize.min,
      crossAxisAlignment: CrossAxisAlignment.stretch,
      children: [
        _TaskRow(
          task: task,
          today: today,
          allSubtaskIds: allSubtaskIds,
          projects: _projects,
          projectIcons: _projectIcons,
          allTasks: _allTasks,
          activeTimerTaskId: _activeTimerTaskId,
          activeStagingTaskId: _activeStagingTaskId,
          onStopStaging: _activeStagingTaskId == task.id
              ? () => _stopTaskStaging()
              : null,
          activeFlowtimeTaskId: _activeFlowtimeTaskId,
          onFlowtimeToggle: () {
            if (_activeFlowtimeTaskId == task.id) {
              _stopFlowtimeTimer();
            } else {
              if (_activeStagingTaskId != null) _stopTaskStaging();
              if (_activeGeneralTaskId != null) _stopGeneralTimer();
              _startFlowtimeTimer(task.id);
            }
          },
          taskDetailExpanded: _taskDetailExpanded,
          formatElapsed: _formatElapsed,
          dragHandle: dragHandle,
          // If this task has subtasks, aggregate their values for display
          effectiveTimeSpentMs: subtasks.isNotEmpty
              ? subtasks.fold<int>(0, (s, t) => s + t.timeSpent)
              : null,
          effectiveDurationMinutes: subtasks.isNotEmpty
              ? subtasks.fold<int>(0, (s, t) => s + t.durationMinutes)
              : null,
          onStatusToggle: () => setState(() {
            if (task.status == TaskStatus.done) {
              task.status = TaskStatus.none;
              task.isDone = false;
            } else {
              task.status = TaskStatus.done;
              task.isDone = true;
              // Cascade to subtasks
              for (final sub in _allTasks.where(
                (t) => task.subTaskIds.any((sid) => sid.toString() == t.id),
              )) {
                sub.status = TaskStatus.done;
                sub.isDone = true;
                _saveTaskToMeta(sub);
              }
            }
          }),
          onStatusSelect: (status) => setState(() {
            task.status = status;
            task.isDone = status == TaskStatus.done;
            if (status == TaskStatus.done) {
              for (final sub in _allTasks.where(
                (t) => task.subTaskIds.any((sid) => sid.toString() == t.id),
              )) {
                sub.status = TaskStatus.done;
                sub.isDone = true;
                _saveTaskToMeta(sub);
              }
            }
          }),
          onTimerToggle: () {
            if (_activeTimerTaskId == task.id) {
              _stopGeneralTimer();
            } else if (_activeStagingTaskId == task.id) {
              // Stop staging and immediately begin simple timer for same task
              _stopTaskStaging();
              _startGeneralTimer(task.id);
            } else {
              _startGeneralTimer(task.id);
            }
          },
          onStagingToggle: () => _startTaskStaging(task.id),
          stagingWasInterrupted: _interruptedTaskId == task.id,
          onDetailToggle: () => setState(() {
            final isAlreadyOpen =
                _taskListDetailOpen && _taskListDetailTask?.id == task.id;
            _taskDetailExpanded.clear();
            if (isAlreadyOpen) {
              _taskListDetailOpen = false;
              _taskListDetailTask = null;
            } else {
              _taskListDetailTask = task;
              _taskListDetailOpen = true;
              _taskDetailExpanded[task.id] = true;
            }
          }),
          onSubtasksToggle: subtasks.isEmpty
              ? null
              : () => setState(() {
                  _subtasksExpanded[task.id] = !isExpanded;
                }),
          subtasksExpanded: isExpanded,
          onRepeatInstancesToggle: inGroupedBucketView
              ? (bucketGroupChildCount != null && bucketGroupChildCount > 0
                    ? () => setState(() {
                        _repeatGroupsExpanded[bucketGroupKey!] =
                            !(_repeatGroupsExpanded[bucketGroupKey] ?? true);
                      })
                    : null)
              : (repeatInstances.isEmpty
                    ? null
                    : () => setState(() {
                        _repeatInstancesExpanded[task.id] = !repeatExpanded;
                      })),
          repeatInstancesExpanded: inGroupedBucketView
              ? (_repeatGroupsExpanded[bucketGroupKey ?? ''] ?? true)
              : repeatExpanded,
          repeatInstanceCount: inGroupedBucketView
              ? (bucketGroupChildCount ?? 0)
              : repeatInstances.length,
          onContextMenu: (pos) => _showTaskContextMenu(context, task, pos),
          onRename: (newTitle) {
            // Spec §1: strip reserved chars.
            final safeTitle = newTitle.replaceAll(RegExp(r'[/\\:]'), '').trim();
            if (safeTitle.isEmpty) return;
            // Spec §2: block duplicate names within the same project.
            if (_taskTitleConflict(safeTitle, task.projectId)) return;
            setState(() => task.title = safeTitle);
            _saveTaskToMeta(task);
          },
          horizPadding: _taskCardHorizPadding,
          onDateChanged: (isoDay, newPlannedAt) {
            setState(() {
              task.dueDay = isoDay;
              task.plannedAt = newPlannedAt;
            });
            _saveTaskToMeta(task);
          },
        ),
        // Subtask region — tab from behind; cards are inset inside the container
        if (isExpanded && subtasks.isNotEmpty)
          Container(
            margin: const EdgeInsets.only(left: 24, right: 12, bottom: 6),
            padding: const EdgeInsets.symmetric(horizontal: 8, vertical: 4),
            decoration: BoxDecoration(
              color: const Color(0xFF212426),
              borderRadius: const BorderRadius.only(
                bottomLeft: Radius.circular(8),
                bottomRight: Radius.circular(8),
              ),
              border: Border(
                left: BorderSide(color: const Color(0xFF2C2F32)),
                right: BorderSide(color: const Color(0xFF2C2F32)),
                bottom: BorderSide(color: const Color(0xFF2C2F32)),
              ),
            ),
            child: Column(
              mainAxisSize: MainAxisSize.min,
              crossAxisAlignment: CrossAxisAlignment.stretch,
              children: subtasks
                  .map((sub) => _buildTaskRow(sub, today, allSubtaskIds))
                  .toList(),
            ),
          ),
        // Repeat instance rows — only shown in non-grouped mode (Today/Inbox).
        // In project/tag/All views the bucket grouping handles this.
        if (!inGroupedBucketView &&
            repeatExpanded &&
            repeatInstances.isNotEmpty)
          Padding(
            padding: const EdgeInsets.only(left: 24),
            child: IntrinsicHeight(
              child: Row(
                crossAxisAlignment: CrossAxisAlignment.stretch,
                children: [
                  Container(
                    width: 1,
                    margin: const EdgeInsets.only(left: 7, top: 0, bottom: 4),
                    color: Colors.white.withOpacity(0.07),
                  ),
                  const SizedBox(width: 0),
                  Expanded(
                    child: Column(
                      mainAxisSize: MainAxisSize.min,
                      crossAxisAlignment: CrossAxisAlignment.stretch,
                      children: repeatInstances
                          .map(
                            (inst) => _buildTaskRow(inst, today, allSubtaskIds),
                          )
                          .toList(),
                    ),
                  ),
                ],
              ),
            ),
          ),
      ],
    );
  }

  /// Builds a reorderable list of task rows, applying and persisting manual order.
  Widget _buildReorderableTaskList(
    List<Task> tasks,
    DateTime today,
    Set<String> allSubtaskIds,
  ) {
    // When the user has active sort criteria the incoming list is already
    // ordered correctly by _applySortCriteria — do NOT re-sort by manual
    // order, as that would silently discard the chosen sort.
    final bool criteriaActive = _sortCriteria.isNotEmpty;

    late final List<Task> sorted;
    if (criteriaActive) {
      // Honour the criteria-sorted order passed in; manual order is irrelevant.
      sorted = List<Task>.from(tasks);
    } else {
      // No sort criteria — fall back to manual drag-and-drop order.
      for (int i = 0; i < tasks.length; i++) {
        _taskManualOrder.putIfAbsent(tasks[i].id, () => i * 100);
      }
      sorted = List<Task>.from(tasks)
        ..sort(
          (a, b) => (_taskManualOrder[a.id] ?? 0).compareTo(
            _taskManualOrder[b.id] ?? 0,
          ),
        );
    }

    return ReorderableListView.builder(
      key: ValueKey(_subtasksExpanded.toString()),
      shrinkWrap: true,
      physics: const NeverScrollableScrollPhysics(),
      buildDefaultDragHandles: false,
      proxyDecorator: (child, index, animation) =>
          Material(color: Colors.transparent, elevation: 8, child: child),
      onReorder: criteriaActive
          ? (_, __) {} // Sort criteria are active — drag reorder is a no-op.
          : (oldIndex, newIndex) {
              setState(() {
                if (newIndex > oldIndex) newIndex--;
                final moved = sorted.removeAt(oldIndex);
                sorted.insert(newIndex, moved);
                // Reassign order values based on new positions.
                for (int i = 0; i < sorted.length; i++) {
                  _taskManualOrder[sorted[i].id] = i * 100;
                }
              });
            },
      itemCount: sorted.length,
      itemBuilder: (context, index) {
        final task = sorted[index];
        // Hide the drag handle when a sort criterion is active so the user
        // is not misled into thinking manual reordering will work.
        final handle = criteriaActive
            ? null
            : ReorderableDragStartListener(
                index: index,
                child: MouseRegion(
                  cursor: SystemMouseCursors.grab,
                  child: Padding(
                    padding: const EdgeInsets.symmetric(horizontal: 8),
                    child: Icon(
                      Icons.drag_indicator,
                      size: 14,
                      color: Colors.white38,
                    ),
                  ),
                ),
              );
        return _buildTaskRow(task, today, allSubtaskIds, dragHandle: handle);
      },
    );
  }

  /// Builds a bucket list that groups repeat-series members under a dedicated
  /// header row (similar to the OVERDUE/DONE section headers).
  /// Series with >1 member in this bucket get: header → indented task rows
  /// (subtask-style). Standalone tasks render normally.
  Widget _buildGroupedBucketList(
    List<Task> tasks,
    DateTime today,
    Set<String> allSubtaskIds,
  ) {
    if (tasks.isEmpty) return const SizedBox.shrink();

    // ── 1. Build series membership map ─────────────────────────────────────
    final Map<String, List<Task>> seriesMap = {};
    for (final t in tasks) {
      final key = t.repeatParentId ?? (t.repeatConfig != null ? t.id : null);
      if (key != null) seriesMap.putIfAbsent(key, () => []).add(t);
    }

    // Sort each series internally. If the user has active sort criteria, honour
    // them; otherwise fall back to scheduled date ascending (earliest → latest).
    for (final list in seriesMap.values) {
      if (_sortCriteria.isNotEmpty) {
        list.sort((a, b) {
          for (final s in _sortCriteria) {
            final r = _compareBySort(a, b, s);
            if (r != 0) return r;
          }
          return 0;
        });
      } else {
        list.sort((a, b) {
          final da = a.scheduledDate ?? DateTime(9999);
          final db = b.scheduledDate ?? DateTime(9999);
          return da.compareTo(db);
        });
      }
    }

    // IDs that belong to a multi-member series
    final groupedIds = <String>{};
    for (final entry in seriesMap.entries) {
      if (entry.value.length > 1) {
        for (final t in entry.value) groupedIds.add(t.id);
      }
    }

    // ── 2. Render ──────────────────────────────────────────────────────────
    final processedKeys = <String>{};
    final widgets = <Widget>[];

    for (final t in tasks) {
      if (!groupedIds.contains(t.id)) {
        // Standalone task — render normally
        widgets.add(_buildTaskRow(t, today, allSubtaskIds));
        continue;
      }

      // This task belongs to a multi-member series — handle the group once
      final key = t.repeatParentId ?? t.id;
      if (processedKeys.contains(key)) continue;
      processedKeys.add(key);

      final series = seriesMap[key]!;
      final groupExpanded = _repeatGroupsExpanded[key] ?? true;

      // Look up the parent task for its title (fall back to first series member)
      final parent = _allTasks.firstWhere(
        (p) => p.id == key,
        orElse: () => series.first,
      );

      // Date-range label  e.g.  "12/3 → 10/4"
      final firstDate = DateTime.tryParse(series.first.dueDay ?? '');
      final lastDate = DateTime.tryParse(series.last.dueDay ?? '');
      String dateRange = '';
      if (firstDate != null && lastDate != null) {
        dateRange = '${_fmtDateChip(firstDate)} → ${_fmtDateChip(lastDate)}';
      }

      widgets.add(
        Column(
          key: ValueKey('rg_$key'),
          mainAxisSize: MainAxisSize.min,
          crossAxisAlignment: CrossAxisAlignment.stretch,
          children: [
            // ── Special group header ─────────────────────────────────────────
            GestureDetector(
              onTap: () =>
                  setState(() => _repeatGroupsExpanded[key] = !groupExpanded),
              child: Container(
                margin: const EdgeInsets.fromLTRB(12, 6, 12, 0),
                padding: const EdgeInsets.symmetric(
                  horizontal: 10,
                  vertical: 7,
                ),
                decoration: BoxDecoration(
                  color: const Color(0xFF4FC3F7).withOpacity(0.05),
                  borderRadius: BorderRadius.circular(6),
                  border: Border.all(
                    color: const Color(0xFF4FC3F7).withOpacity(0.18),
                  ),
                ),
                child: Row(
                  children: [
                    Icon(
                      groupExpanded
                          ? Icons.keyboard_arrow_down
                          : Icons.keyboard_arrow_right,
                      size: 13,
                      color: const Color(0xFF4FC3F7).withOpacity(0.65),
                    ),
                    const SizedBox(width: 6),
                    Icon(
                      Icons.repeat_rounded,
                      size: 11,
                      color: const Color(0xFF4FC3F7).withOpacity(0.75),
                    ),
                    const SizedBox(width: 7),
                    Expanded(
                      child: Text(
                        parent.title,
                        style: const TextStyle(
                          fontSize: 11,
                          fontWeight: FontWeight.w600,
                          color: Color(0xFF9BBFD8),
                          letterSpacing: 0.3,
                        ),
                        overflow: TextOverflow.ellipsis,
                      ),
                    ),
                    if (dateRange.isNotEmpty) ...[
                      const SizedBox(width: 8),
                      Text(
                        dateRange,
                        style: const TextStyle(
                          fontSize: 10,
                          color: Colors.white24,
                        ),
                      ),
                    ],
                    const SizedBox(width: 8),
                    Container(
                      padding: const EdgeInsets.symmetric(
                        horizontal: 6,
                        vertical: 1,
                      ),
                      decoration: BoxDecoration(
                        color: const Color(0xFF4FC3F7).withOpacity(0.12),
                        borderRadius: BorderRadius.circular(8),
                      ),
                      child: Text(
                        '${series.length}',
                        style: const TextStyle(
                          fontSize: 10,
                          fontWeight: FontWeight.bold,
                          color: Color(0xFF4FC3F7),
                        ),
                      ),
                    ),
                  ],
                ),
              ),
            ),

            // ── Collapsible task rows (subtask-style indent + vertical line) ─
            if (groupExpanded)
              Padding(
                padding: const EdgeInsets.only(left: 24),
                child: IntrinsicHeight(
                  child: Row(
                    crossAxisAlignment: CrossAxisAlignment.stretch,
                    children: [
                      Container(
                        width: 1,
                        margin: const EdgeInsets.only(
                          left: 7,
                          top: 0,
                          bottom: 4,
                        ),
                        color: const Color(0xFF4FC3F7).withOpacity(0.12),
                      ),
                      Expanded(
                        child: Column(
                          mainAxisSize: MainAxisSize.min,
                          crossAxisAlignment: CrossAxisAlignment.stretch,
                          children: series
                              .map(
                                (c) => _buildTaskRow(
                                  c,
                                  today,
                                  allSubtaskIds,
                                  inGroupedBucketView: true,
                                ),
                              )
                              .toList(),
                        ),
                      ),
                    ],
                  ),
                ),
              ),
          ],
        ),
      );
    }

    return Column(
      mainAxisSize: MainAxisSize.min,
      crossAxisAlignment: CrossAxisAlignment.stretch,
      children: widgets,
    );
  }

  Future<void> _showTaskContextMenu(
    BuildContext context,
    Task task,
    Offset globalPos,
  ) async {
    // Helper to build a menu item row
    Widget _item(
      IconData icon,
      String label, {
      Color iconColor = const Color(0xFF9AA3B0),
      Color labelColor = const Color(0xFFD0D4DC),
      Widget? trailing,
      String? shortcut,
    }) {
      return Row(
        children: [
          Icon(icon, size: 15, color: iconColor),
          const SizedBox(width: 12),
          Expanded(
            child: Text(
              label,
              style: TextStyle(fontSize: 12.5, color: labelColor),
            ),
          ),
          if (trailing != null) trailing,
          if (shortcut != null) ...[
            const SizedBox(width: 8),
            Container(
              padding: const EdgeInsets.symmetric(horizontal: 5, vertical: 2),
              decoration: BoxDecoration(
                color: const Color(0xFF2C2F35),
                borderRadius: BorderRadius.circular(4),
                border: Border.all(color: Colors.white12),
              ),
              child: Text(
                shortcut,
                style: const TextStyle(fontSize: 10, color: Colors.white38),
              ),
            ),
          ],
        ],
      );
    }

    Widget _badge(int n) => Container(
      padding: const EdgeInsets.symmetric(horizontal: 5, vertical: 1),
      decoration: BoxDecoration(
        color: const Color(0xFF2C3040),
        borderRadius: BorderRadius.circular(10),
      ),
      child: Text(
        '$n',
        style: const TextStyle(fontSize: 10, color: Colors.white38),
      ),
    );

    const _arrow = Icon(Icons.chevron_right, size: 14, color: Colors.white24);

    final pos = RelativeRect.fromLTRB(
      globalPos.dx,
      globalPos.dy,
      globalPos.dx + 1,
      globalPos.dy + 1,
    );

    const menuStyle = Color(0xFF1E2124);
    const menuBorder = Color(0xFF2C2F35);

    final choice = await showMenu<String>(
      context: context,
      position: pos,
      color: menuStyle,
      elevation: 12,
      shape: RoundedRectangleBorder(
        borderRadius: BorderRadius.circular(10),
        side: const BorderSide(color: menuBorder, width: 0.8),
      ),
      items: [
        // ── Schedule quick-action row ─────────────────────────────────────────
        PopupMenuItem(
          value: '__schedule_row__',
          enabled: false,
          height: 48,
          padding: const EdgeInsets.symmetric(horizontal: 8),
          child: _ScheduleIconRow(
            task: task,
            onSchedule: (value) {
              Navigator.of(context).pop(value);
            },
          ),
        ),
        PopupMenuItem(
          value: 'start_focus',
          height: 36,
          child: _item(
            Icons.center_focus_strong_outlined,
            'Start Focus',
            iconColor: const Color(0xFFFFB74D),
            labelColor: const Color(0xFFFFB74D),
          ),
        ),
        PopupMenuItem(
          value: 'details',
          height: 36,
          child: _item(
            Icons.info_outline_rounded,
            'Details',
            iconColor: const Color(0xFF4FC3F7),
            labelColor: const Color(0xFF4FC3F7),
          ),
        ),
        PopupMenuItem(
          value: 'duplicate',
          height: 36,
          child: _item(Icons.content_copy_outlined, 'Duplicate'),
        ),
        PopupMenuItem(
          value: 'subtask',
          height: 36,
          child: _item(
            Icons.add_task_outlined,
            'Add sub task',
            trailing: task.subTaskIds.isNotEmpty
                ? _badge(task.subTaskIds.length)
                : null,
          ),
        ),
        // Tags — annexed submenu
        PopupMenuItem(
          value: '__tags__',
          height: 36,
          child: _AnnexedMenuItem(
            icon: Icons.label_outline,
            label: 'Add Tags',
            badge: task.tagIds.isNotEmpty ? task.tagIds.length : null,
            items: () {
              // Use the global tag map (all known tags, not just ones on this task)
              final allKnownTags = {
                ..._tagColors.keys,
                ..._allTasks.expand((t) => t.tagIds.map((id) => id.toString())),
              }.toList()..sort();
              return allKnownTags.map((tagId) {
                final has = task.tagIds.contains(tagId);
                final tagColor = _tagColors[tagId] ?? const Color(0xFF9AA3B0);
                return _AnnexedItem(
                  value: tagId,
                  label: tagId,
                  icon: has ? Icons.label : Icons.label_outline,
                  iconColor: tagColor,
                  active: has,
                );
              }).toList();
            }(),
            onSelect: (tagId) {
              setState(() {
                if (task.tagIds.contains(tagId)) {
                  task.tagIds.remove(tagId);
                } else {
                  task.tagIds.add(tagId);
                }
              });
              _saveTaskToMeta(task);
            },
          ),
        ),
        // Move to Project — annexed submenu
        PopupMenuItem(
          value: '__move__',
          height: 36,
          child: _AnnexedMenuItem(
            icon: Icons.drive_file_move_outline,
            label: 'Move to Project',
            badge: _projects.isNotEmpty ? _projects.length : null,
            items: [
              _AnnexedItem(
                value: 'INBOX_PROJECT',
                label: 'Inbox',
                icon: Icons.inbox_outlined,
                active: task.projectId == 'INBOX_PROJECT',
              ),
              ..._projects.entries.map(
                (e) => _AnnexedItem(
                  value: e.key,
                  label: e.value.title,
                  icon: Icons.folder_outlined,
                  active: task.projectId == e.key,
                ),
              ),
            ],
            onSelect: (projId) {
              final moved = Task(
                id: task.id,
                title: task.title,
                isDone: task.isDone,
                status: task.status,
                projectId: projId,
                subTaskIds: task.subTaskIds,
                timeSpent: task.timeSpent,
                dueDay: task.dueDay,
                durationMinutes: task.durationMinutes,
                attachments: task.attachments,
                tagIds: task.tagIds,
                notes: task.notes,
              );
              setState(() {
                final idx = _allTasks.indexOf(task);
                if (idx >= 0) _allTasks[idx] = moved;
              });
              _saveTaskToMeta(moved);
            },
          ),
        ),
        // "Convert to Parent Task" — only shown when this task is a subtask
        if (_allTasks.any(
          (t) => t.subTaskIds.any((id) => id.toString() == task.id),
        ))
          PopupMenuItem(
            value: 'convert_to_parent',
            height: 36,
            child: _item(Icons.upgrade_outlined, 'Convert to Parent Task'),
          ),
        PopupMenuItem(
          value: 'delete',
          height: 36,
          child: _item(
            Icons.delete_outline,
            'Delete Task',
            iconColor: const Color(0xFFEF5350),
            labelColor: const Color(0xFFEF5350),
            shortcut: 'Backspace',
          ),
        ),
      ],
    );

    if (choice == null || !mounted) return;

    final now = DateTime.now();
    final today = DateTime(now.year, now.month, now.day);

    switch (choice) {
      case 'details':
        setState(() {
          _taskListDetailTask = task;
          _taskListDetailOpen = true;
          // Drive the shared right-sidebar so TaskDetailsPanel appears
          // regardless of which tab (Tasks / Notes / Canvases) is active.
          _selectedTask = task;
          _showDetails = true;
        });
        break;

      case 'sched_today':
        setState(() => task.dueDay = today.toIso8601String().split('T').first);
        _saveTaskToMeta(task);
        break;

      case 'sched_tomorrow':
        final tmr = today.add(const Duration(days: 1));
        setState(() => task.dueDay = tmr.toIso8601String().split('T').first);
        _saveTaskToMeta(task);
        break;

      case 'sched_nextweek':
        final nw = today.add(Duration(days: 8 - today.weekday));
        setState(() => task.dueDay = nw.toIso8601String().split('T').first);
        _saveTaskToMeta(task);
        break;

      case 'sched_reschedule':
        final pickedDate = await showDatePicker(
          context: context,
          initialDate: task.dueDay != null
              ? (DateTime.tryParse(task.dueDay!) ?? today)
              : today,
          firstDate: today,
          lastDate: today.add(const Duration(days: 365 * 5)),
          builder: (ctx, child) => Theme(
            data: Theme.of(ctx).copyWith(
              colorScheme: const ColorScheme.dark(
                primary: Color(0xFF4FC3F7),
                surface: Color(0xFF1E2124),
              ),
            ),
            child: child!,
          ),
        );
        if (pickedDate != null && mounted) {
          // Also ask for time
          final pickedTime = await showTimePicker(
            context: context,
            initialTime: task.plannedAt != null
                ? TimeOfDay.fromDateTime(
                    DateTime.fromMillisecondsSinceEpoch(task.plannedAt!),
                  )
                : TimeOfDay.now(),
            builder: (ctx, child) => Theme(
              data: Theme.of(ctx).copyWith(
                colorScheme: const ColorScheme.dark(
                  primary: Color(0xFF4FC3F7),
                  surface: Color(0xFF1E2124),
                ),
                timePickerTheme: const TimePickerThemeData(
                  backgroundColor: Color(0xFF1E2124),
                ),
              ),
              child: child!,
            ),
          );
          setState(() {
            task.dueDay = pickedDate.toIso8601String().split('T').first;
            if (pickedTime != null) {
              task.plannedAt = DateTime(
                pickedDate.year,
                pickedDate.month,
                pickedDate.day,
                pickedTime.hour,
                pickedTime.minute,
              ).millisecondsSinceEpoch;
            }
          });
          _saveTaskToMeta(task);
        }
        break;

      case 'sched_unschedule':
        setState(() => task.dueDay = null);
        _saveTaskToMeta(task);
        break;

      case 'start_focus':
        _showFocusPopup();
        break;

      case 'duplicate':
        final dup = Task(
          id: DateTime.now().millisecondsSinceEpoch.toString(),
          title: '${task.title} (copy)',
          isDone: false,
          status: TaskStatus.none,
          projectId: task.projectId,
          subTaskIds: [],
          timeSpent: 0,
          dueDay: task.dueDay,
          durationMinutes: task.durationMinutes,
          attachments: [],
          tagIds: List.from(task.tagIds),
          notes: task.notes,
        );
        setState(() {
          final idx = _allTasks.indexOf(task);
          _allTasks.insert(idx + 1, dup);
        });
        _saveTaskToMeta(dup);
        break;

      case 'subtask':
        // 1. Just use a simple string variable instead of a controller
        String enteredText = '';

        final subName = await showDialog<String>(
          context: context,
          barrierColor: Colors.black45,
          builder: (ctx) {
            void commit() {
              final t = enteredText.trim();
              Navigator.of(ctx).pop(t.isEmpty ? null : t);
            }

            return Dialog(
              backgroundColor: const Color(0xFF1E2124),
              insetPadding: const EdgeInsets.symmetric(
                horizontal: 40,
                vertical: 24,
              ),
              shape: RoundedRectangleBorder(
                borderRadius: BorderRadius.circular(10),
                side: const BorderSide(color: Color(0xFF2C2F35), width: 0.8),
              ),
              child: SizedBox(
                width: 340,
                child: Padding(
                  padding: const EdgeInsets.fromLTRB(20, 20, 20, 16),
                  child: Column(
                    mainAxisSize: MainAxisSize.min,
                    crossAxisAlignment: CrossAxisAlignment.start,
                    children: [
                      const Text(
                        'New sub-task',
                        style: TextStyle(
                          fontSize: 13,
                          fontWeight: FontWeight.w600,
                          color: Colors.white70,
                        ),
                      ),
                      const SizedBox(height: 12),
                      CallbackShortcuts(
                        bindings: {
                          const SingleActivator(LogicalKeyboardKey.enter):
                              commit,
                          const SingleActivator(LogicalKeyboardKey.numpadEnter):
                              commit,
                        },
                        child: TextField(
                          // 2. Remove the controller parameter entirely
                          onChanged: (val) =>
                              enteredText = val, // 3. Track text here
                          autofocus: true,
                          maxLines: 1,
                          textInputAction: TextInputAction.done,
                          style: const TextStyle(
                            color: Colors.white,
                            fontSize: 13,
                          ),
                          decoration: InputDecoration(
                            hintText: 'Sub-task name…',
                            hintStyle: const TextStyle(
                              color: Colors.white24,
                              fontSize: 12,
                            ),
                            filled: true,
                            fillColor: const Color(0xFF252729),
                            isDense: true,
                            contentPadding: const EdgeInsets.symmetric(
                              horizontal: 10,
                              vertical: 10,
                            ),
                            border: OutlineInputBorder(
                              borderRadius: BorderRadius.circular(6),
                              borderSide: const BorderSide(
                                color: Colors.white10,
                              ),
                            ),
                            focusedBorder: OutlineInputBorder(
                              borderRadius: BorderRadius.circular(6),
                              borderSide: const BorderSide(
                                color: Color(0xFF4FC3F7),
                                width: 1.0,
                              ),
                            ),
                          ),
                          onSubmitted: (_) => commit(),
                        ),
                      ),
                      const SizedBox(height: 14),
                      Row(
                        mainAxisAlignment: MainAxisAlignment.end,
                        children: [
                          TextButton(
                            onPressed: () => Navigator.of(ctx).pop(null),
                            child: const Text(
                              'Cancel',
                              style: TextStyle(
                                color: Colors.white38,
                                fontSize: 12,
                              ),
                            ),
                          ),
                          const SizedBox(width: 8),
                          TextButton(
                            onPressed: commit,
                            child: const Text(
                              'Add',
                              style: TextStyle(
                                color: Color(0xFF4FC3F7),
                                fontSize: 12,
                              ),
                            ),
                          ),
                        ],
                      ),
                    ],
                  ),
                ),
              ),
            );
          },
        );

        // 4. No controller means no need to call .dispose() down here at all!

        if (!mounted || subName == null || subName.isEmpty) break;

        final sub = Task(
          id: DateTime.now().millisecondsSinceEpoch.toString(),
          title: subName,
          isDone: false,
          status: TaskStatus.none,
          projectId: task.projectId,
          subTaskIds: [],
          timeSpent: 0,
          attachments: [],
          tagIds: [],
        );

        setState(() {
          task.subTaskIds.add(sub.id);
          _allTasks.add(sub);
          _subtasksExpanded[task.id] = true;
        });
        _saveTaskToMeta(task);
        _saveTaskToMeta(sub);
        break;

      case 'delete':
        setState(() {
          // Delete all subtasks of this task first
          final subIds = List<String>.from(
            task.subTaskIds.map((s) => s.toString()),
          );
          _allTasks.removeWhere((t) => subIds.contains(t.id));
          // Cascade-delete repeat instances if this is a repeat parent
          _clearRepeatInstances(task.id);
          // Remove this task from any parent's subTaskIds
          for (final t in _allTasks) {
            if (t.subTaskIds.any((id) => id.toString() == task.id)) {
              t.subTaskIds.remove(task.id);
              _saveTaskToMeta(t);
            }
          }
          _allTasks.remove(task);

          // ── Remove from the active canvas ──────────────────────────────
          final deletedIds = <String>{task.id, ...subIds};
          _canvasTasks.removeWhere((t) => deletedIds.contains(t.id));
          _taskPositions.removeWhere((k, _) => deletedIds.contains(k));
          _taskRelations.removeWhere(
            (r) =>
                deletedIds.contains(r.sourceId) ||
                deletedIds.contains(r.targetId),
          );
          if (deletedIds.contains(_selectedCanvasTaskId)) {
            _selectedCanvasTaskId = null;
          }
          _selectedTaskIds.removeAll(deletedIds);

          // ── Remove from every saved (non-active) canvas state ──────────
          for (final state in _canvasStates.values) {
            final tasks = state['canvasTasks'];
            if (tasks is List<Task>) {
              tasks.removeWhere((t) => deletedIds.contains(t.id));
            }
            final positions = state['taskPositions'];
            if (positions is Map<String, Offset>) {
              positions.removeWhere((k, _) => deletedIds.contains(k));
            }
            final relations = state['taskRelations'];
            if (relations is Set<TaskRelation>) {
              relations.removeWhere(
                (r) =>
                    deletedIds.contains(r.sourceId) ||
                    deletedIds.contains(r.targetId),
              );
            }
          }
        });
        _saveTaskToMeta(task);
        break;

      case 'convert_to_parent':
        // Remove this task from its parent's subTaskIds list
        setState(() {
          for (final t in _allTasks) {
            if (t.subTaskIds.any((id) => id.toString() == task.id)) {
              t.subTaskIds.remove(task.id);
              _saveTaskToMeta(t);
            }
          }
        });
        break;
    }
  }

  /// Renders Today's tasks grouped by project, identical visual style to a
  /// normal project view. Each project with tasks due today gets a collapsible
  /// header; tasks without a project fall under "Inbox".
  /// Renders [tasks] grouped by [_groupOption] into collapsible sections.
  Widget _buildGroupedByOption(
    List<Task> tasks,
    DateTime today,
    Set<String> allSubtaskIds,
  ) {
    if (tasks.isEmpty) {
      return const Padding(
        padding: EdgeInsets.only(top: 60),
        child: Center(
          child: Text('No tasks', style: TextStyle(color: Colors.white24)),
        ),
      );
    }

    // Build a map of groupKey → tasks
    Map<String, List<Task>> groups = {};
    const ungrouped = '—';

    // Use first GroupCriterion for primary grouping (legacy _groupOption shim
    // still works for the existing rendering paths via the getter).
    final primaryGroup = _groupCriteria.isNotEmpty
        ? _groupCriteria.first
        : null;
    for (final t in tasks) {
      final String key = primaryGroup != null
          ? primaryGroup.keyFor(t, _projects)
          : ungrouped;
      groups.putIfAbsent(key, () => []).add(t);
    }

    final sortedKeys = groups.keys.toList();
    // Sort group keys by the criterion direction
    if (primaryGroup != null) {
      sortedKeys.sort(
        (a, b) => primaryGroup.ascending ? a.compareTo(b) : b.compareTo(a),
      );
    } else {
      sortedKeys.sort();
    }
    // Put ungrouped / no-date at the end regardless of direction
    if (sortedKeys.remove(ungrouped)) sortedKeys.add(ungrouped);
    if (sortedKeys.remove('No date')) sortedKeys.add('No date');

    return Column(
      crossAxisAlignment: CrossAxisAlignment.stretch,
      children: sortedKeys.map((key) {
        final groupTasks = groups[key]!;
        final expanded = !_collapsedGroups.contains(key);
        return Column(
          crossAxisAlignment: CrossAxisAlignment.stretch,
          children: [
            InkWell(
              onTap: () => setState(() {
                if (expanded)
                  _collapsedGroups.add(key);
                else
                  _collapsedGroups.remove(key);
              }),
              child: Container(
                padding: const EdgeInsets.symmetric(
                  horizontal: 16,
                  vertical: 10,
                ),
                decoration: BoxDecoration(
                  border: Border(
                    bottom: BorderSide(color: _tasksBorder, width: 0.5),
                  ),
                ),
                child: Row(
                  children: [
                    Icon(
                      expanded
                          ? Icons.keyboard_arrow_down
                          : Icons.keyboard_arrow_right,
                      size: 14,
                      color: Colors.white38,
                    ),
                    const SizedBox(width: 6),
                    Expanded(
                      child: Text(
                        key == '__inbox__' ? 'Inbox' : key,
                        style: const TextStyle(
                          fontSize: 11,
                          fontWeight: FontWeight.w600,
                          letterSpacing: 0.8,
                          color: Colors.white54,
                        ),
                      ),
                    ),
                    Container(
                      padding: const EdgeInsets.symmetric(
                        horizontal: 6,
                        vertical: 1,
                      ),
                      decoration: BoxDecoration(
                        color: Colors.white.withOpacity(0.06),
                        borderRadius: BorderRadius.circular(8),
                      ),
                      child: Text(
                        '${groupTasks.length}',
                        style: const TextStyle(
                          fontSize: 10,
                          fontWeight: FontWeight.bold,
                          color: Colors.white38,
                        ),
                      ),
                    ),
                  ],
                ),
              ),
            ),
            if (expanded)
              _buildReorderableTaskList(groupTasks, today, allSubtaskIds),
          ],
        );
      }).toList(),
    );
  }

  Widget _buildTodayByProject(
    List<Task> tasks,
    DateTime today,
    Set<String> allSubtaskIds,
  ) {
    if (tasks.isEmpty) return const SizedBox.shrink();

    // Group by projectId
    final Map<String, List<Task>> byProject = {};
    for (final t in tasks) {
      byProject.putIfAbsent(t.projectId, () => []).add(t);
    }

    // Order: follow _projectOrder, then any leftover (e.g. INBOX_PROJECT)
    final orderedIds = [
      ..._projectOrder.where((id) => byProject.containsKey(id)),
      ...byProject.keys.where((id) => !_projectOrder.contains(id)),
    ];

    return Column(
      crossAxisAlignment: CrossAxisAlignment.stretch,
      children: [
        for (final pid in orderedIds) ...[
          _buildTodayProjectSection(pid, byProject[pid]!, today, allSubtaskIds),
        ],
      ],
    );
  }

  Widget _buildTodayProjectSection(
    String projectId,
    List<Task> tasks,
    DateTime today,
    Set<String> allSubtaskIds,
  ) {
    final proj = _projects[projectId];
    final label = projectId == 'INBOX_PROJECT'
        ? 'Inbox'
        : (proj?.title ?? projectId);
    final color = _projectColors[projectId] ?? _tasksAccent;
    final icon = _projectIcons[projectId] ?? '';
    final expandKey = 'today_proj_$projectId';
    final expanded = _repeatGroupsExpanded[expandKey] ?? true;

    return Column(
      crossAxisAlignment: CrossAxisAlignment.stretch,
      children: [
        // ── Project header ──────────────────────────────────────────────
        InkWell(
          onTap: () =>
              setState(() => _repeatGroupsExpanded[expandKey] = !expanded),
          child: Container(
            padding: const EdgeInsets.symmetric(horizontal: 16, vertical: 8),
            decoration: BoxDecoration(
              border: Border(
                bottom: BorderSide(color: _tasksBorder, width: 0.5),
              ),
            ),
            child: Row(
              children: [
                Icon(
                  expanded
                      ? Icons.keyboard_arrow_down
                      : Icons.keyboard_arrow_right,
                  size: 14,
                  color: Colors.white38,
                ),
                const SizedBox(width: 6),
                // Project icon
                SizedBox(
                  width: 14,
                  height: 14,
                  child: icon.isNotEmpty
                      ? Text(
                          icon,
                          style: const TextStyle(
                            fontSize: 12,
                            fontFamilyFallback: [
                              'NotoColorEmoji',
                              'Apple Color Emoji',
                              'Segoe UI Emoji',
                            ],
                          ),
                        )
                      : Icon(Icons.folder_outlined, size: 12, color: color),
                ),
                const SizedBox(width: 6),
                Text(
                  label.toUpperCase(),
                  style: TextStyle(
                    fontSize: 10,
                    fontWeight: FontWeight.w700,
                    letterSpacing: 0.8,
                    color: ensureAccentVisible(color).withOpacity(0.8),
                  ),
                ),
                const SizedBox(width: 8),
                Container(
                  padding: const EdgeInsets.symmetric(
                    horizontal: 6,
                    vertical: 1,
                  ),
                  decoration: BoxDecoration(
                    color: Colors.white.withOpacity(0.06),
                    borderRadius: BorderRadius.circular(8),
                  ),
                  child: Text(
                    '${tasks.length}',
                    style: const TextStyle(
                      fontSize: 10,
                      fontWeight: FontWeight.bold,
                      color: Colors.white38,
                    ),
                  ),
                ),
              ],
            ),
          ),
        ),
        if (expanded) _buildGroupedBucketList(tasks, today, allSubtaskIds),
      ],
    );
  }

