  void _showAddCategoryDialog() {
    final TextEditingController controller = TextEditingController();
    showDialog(
      context: context,
      builder: (context) => AlertDialog(
        backgroundColor: const Color(0xFF252525),
        title: const Text(
          "New Project Category",
          style: TextStyle(color: Colors.white, fontSize: 16),
        ),
        content: TextField(
          controller: controller,
          autofocus: true,
          style: const TextStyle(color: Colors.white),
          decoration: const InputDecoration(
            hintText: "Category name (e.g. Work, Ideas...)",
            hintStyle: TextStyle(color: Colors.white24, fontSize: 13),
            enabledBorder: UnderlineInputBorder(
              borderSide: BorderSide(color: Colors.white10),
            ),
            focusedBorder: UnderlineInputBorder(
              borderSide: BorderSide(color: Colors.blueAccent),
            ),
          ),
        ),
        actions: [
          TextButton(
            onPressed: () => Navigator.pop(context),
            child: const Text(
              "CANCEL",
              style: TextStyle(color: Colors.white38),
            ),
          ),
          TextButton(
            onPressed: () {
              if (controller.text.isNotEmpty) {
                setState(() {
                  final name = controller.text;
                  // Insert before the 'All' section if it exists
                  int insertIndex = _sidebarSectionOrder.indexOf('All');
                  if (insertIndex == -1)
                    insertIndex = _sidebarSectionOrder.length;

                  _sidebarSectionOrder.insert(insertIndex, name);
                  _sectionExpandedStates[name] = true;
                  _sectionSortAsc[name] = true;
                  _categoryMappings[name] = {};
                });
                Navigator.pop(context);
              }
            },
            child: const Text(
              "CREATE",
              style: TextStyle(color: Colors.blueAccent),
            ),
          ),
        ],
      ),
    );
  }

  // ── Inbox pseudo-project entry in the All sidebar section ──────────────────
  // Inbox is not a real Project object, but tasks without an explicit project
  // live under projectId == 'INBOX_PROJECT'.  This entry gives those tasks a
  // draggable source on the canvas sidebar so they can be placed on the canvas.
  Widget _buildInboxProjectSection() {
    const inboxId = 'INBOX_PROJECT';
    // Inbox uses a warm amber accent to distinguish it from real projects.
    const inboxColor = Color(0xFFFFB300);
    const iconColor = Colors.white;
    const textColor = Colors.white;

    // Collect subtask ids so we can suppress them (same logic as _buildProjectSection).
    final allSubtaskIds = _allTasks
        .expand((t) => t.subTaskIds.map((id) => id.toString()))
        .toSet();

    final bool onSubcanvas = _currentCanvasName.endsWith(' - Subcanvas');
    final Set<String> subcanvasTaskIds = onSubcanvas
        ? _canvasTasks.map((t) => t.id).toSet()
        : const {};

    final rawTasks = _allTasks.where((t) {
      if (t.projectId != inboxId) return false;
      if (onSubcanvas) return subcanvasTaskIds.contains(t.id);
      return !allSubtaskIds.contains(t.id);
    }).toList();

    // Apply canvas-level filter rules.
    final activeFilters = _canvasFilterRules
        .where((r) => r.isConfigured)
        .toList();
    List<Task> tasks = activeFilters.isNotEmpty
        ? rawTasks
              .where((t) => activeFilters.every((r) => r.matches(t, _projects)))
              .toList()
        : List<Task>.from(rawTasks);

    // Apply canvas sort criteria.
    if (_canvasSortCriteria.isNotEmpty) {
      tasks = _applySortCriteria(tasks, _canvasSortCriteria);
    }

    // Apply the inline search query (typed in the three-dot menu search field).
    final String _searchQuery = (_projectSearchQuery[inboxId] ?? '')
        .toLowerCase();
    final List<Task> filteredTasks = _searchQuery.isEmpty
        ? tasks
        : tasks
              .where((t) => t.title.toLowerCase().contains(_searchQuery))
              .toList();

    final bool expanded = _projectFolderExpanded[inboxId] ?? true;

    return MouseRegion(
      onEnter: (_) => setState(() => _hoveredProjectIds.add(inboxId)),
      onExit: (_) => setState(() => _hoveredProjectIds.remove(inboxId)),
      child: Column(
        mainAxisSize: MainAxisSize.min,
        children: [
          // ── Header row ────────────────────────────────────────────────────
          Container(
            height: 36,
            color: inboxColor.withOpacity(0.85),
            padding: const EdgeInsets.symmetric(horizontal: 4),
            child: Row(
              children: [
                // Collapse toggle
                GestureDetector(
                  onTap: () => setState(
                    () => _projectFolderExpanded[inboxId] = !expanded,
                  ),
                  child: SizedBox(
                    width: 24,
                    height: 24,
                    child: Center(
                      child: AnimatedRotation(
                        turns: expanded ? 0 : -0.25,
                        duration: const Duration(milliseconds: 150),
                        child: const Icon(
                          Icons.keyboard_arrow_down,
                          size: 14,
                          color: iconColor,
                        ),
                      ),
                    ),
                  ),
                ),
                const Icon(Icons.inbox_rounded, color: iconColor, size: 16),
                const SizedBox(width: 8),
                Expanded(
                  child: GestureDetector(
                    onTap: () => setState(
                      () => _projectFolderExpanded[inboxId] = !expanded,
                    ),
                    behavior: HitTestBehavior.opaque,
                    child: const Text(
                      'INBOX',
                      style: TextStyle(
                        color: textColor,
                        fontSize: 11,
                        fontWeight: FontWeight.bold,
                      ),
                      overflow: TextOverflow.ellipsis,
                    ),
                  ),
                ),
                // Active-search dot — visible whenever a search query is set
                if (_searchQuery.isNotEmpty)
                  Container(
                    width: 8,
                    height: 8,
                    margin: const EdgeInsets.only(right: 4),
                    decoration: const BoxDecoration(
                      color: Color(0xFF4FC3F7),
                      shape: BoxShape.circle,
                    ),
                  ),
                // Count badge — hidden when hovered (three-dot takes its place)
                if (filteredTasks.isNotEmpty &&
                    !_hoveredProjectIds.contains(inboxId))
                  Container(
                    margin: const EdgeInsets.only(right: 6),
                    padding: const EdgeInsets.symmetric(
                      horizontal: 6,
                      vertical: 1,
                    ),
                    decoration: BoxDecoration(
                      color: Colors.black26,
                      borderRadius: BorderRadius.circular(8),
                    ),
                    child: Text(
                      '${filteredTasks.length}',
                      style: const TextStyle(
                        fontSize: 10,
                        color: Colors.white,
                        fontWeight: FontWeight.w600,
                      ),
                    ),
                  ),
                // Three-dot menu — hover-only, same dimensions when hidden
                AnimatedOpacity(
                  opacity: _hoveredProjectIds.contains(inboxId) ? 1.0 : 0.0,
                  duration: const Duration(milliseconds: 150),
                  child: GestureDetector(
                    onTapDown: _hoveredProjectIds.contains(inboxId)
                        ? (details) => _showInboxFolderMenu(details: details)
                        : null,
                    child: const SizedBox(
                      width: 24,
                      height: 24,
                      child: Center(
                        child: Icon(
                          Icons.more_horiz,
                          size: 14,
                          color: Colors.white70,
                        ),
                      ),
                    ),
                  ),
                ),
                const SizedBox(width: 4),
              ],
            ),
          ),
          // ── Task tiles ────────────────────────────────────────────────────
          if (expanded)
            Container(
              margin: const EdgeInsets.only(left: 8.0),
              decoration: BoxDecoration(
                color: inboxColor.withOpacity(0.05),
                border: Border(
                  left: BorderSide(
                    color: inboxColor.withOpacity(0.45),
                    width: 2.5,
                  ),
                ),
              ),
              child: filteredTasks.isEmpty
                  ? Padding(
                      padding: const EdgeInsets.symmetric(
                        vertical: 10,
                        horizontal: 12,
                      ),
                      child: Text(
                        _searchQuery.isNotEmpty
                            ? 'No matching tasks'
                            : 'No inbox tasks',
                        style: const TextStyle(
                          color: Colors.white24,
                          fontSize: 11,
                        ),
                      ),
                    )
                  : Column(
                      mainAxisSize: MainAxisSize.min,
                      children: filteredTasks
                          .map((t) => _sidebarTaskTile(t, inboxColor))
                          .toList(),
                    ),
            ),
        ],
      ),
    );
  }

  Widget _buildProjectSection(String projectId) {
    final project = _projects[projectId];
    if (project == null) return const SizedBox.shrink();

    // Collect all subtask IDs across all tasks
    final allSubtaskIds = _allTasks
        .expand((t) => t.subTaskIds.map((id) => id.toString()))
        .toSet();

    // When viewing a subcanvas, only show tasks that are in that canvas.
    final bool onSubcanvas = _currentCanvasName.endsWith(' - Subcanvas');
    final Set<String> subcanvasTaskIds = onSubcanvas
        ? _canvasTasks.map((t) => t.id).toSet()
        : const {};

    // Filter tasks: on a subcanvas show only canvas tasks; otherwise hide subtasks
    final _rawProjectTasks = _allTasks.where((t) {
      if (t.projectId != projectId) return false;
      if (onSubcanvas) return subcanvasTaskIds.contains(t.id);
      return !allSubtaskIds.contains(t.id);
    }).toList();

    // Apply the same canvas Filter rules that hide cards on the canvas itself
    final _activeCanvasFilters = _canvasFilterRules
        .where((r) => r.isConfigured)
        .toList();
    List<Task> projectTasks = _activeCanvasFilters.isNotEmpty
        ? _rawProjectTasks
              .where(
                (t) =>
                    _activeCanvasFilters.every((r) => r.matches(t, _projects)),
              )
              .toList()
        : List<Task>.from(_rawProjectTasks);

    // Apply canvas Sort criteria so the sidebar order matches the canvas
    if (_canvasSortCriteria.isNotEmpty) {
      projectTasks = _applySortCriteria(projectTasks, _canvasSortCriteria);
    }

    // Also apply the project-level Filter/Sort rules (set via Tasks tab F/G/S).
    // This keeps the sidebar task list consistent with what Tasks> shows.
    final _activeProjectFilters = _filterRules
        .where((r) => r.isConfigured)
        .toList();
    if (_activeProjectFilters.isNotEmpty) {
      projectTasks = projectTasks
          .where(
            (t) => _activeProjectFilters.every((r) => r.matches(t, _projects)),
          )
          .toList();
    }
    if (_sortCriteria.isNotEmpty) {
      projectTasks = _applySortCriteria(projectTasks, _sortCriteria);
    }

    bool isFav = _favoriteProjectIds.contains(projectId);

    // NEW: Get color and calculate readable text
    Color? projColor = _projectColors[projectId];
    Color textColor = projColor != null
        ? (projColor.computeLuminance() > 0.5 ? Colors.black87 : Colors.white)
        : (isFav ? Colors.white : const Color.fromARGB(200, 255, 255, 255));
    Color iconColor = projColor != null
        ? textColor
        : (isFav ? Colors.amber.withOpacity(0.8) : Colors.white24);

    return GestureDetector(
      key: ValueKey("project_item_$projectId"),
      onSecondaryTapDown: (details) => _showProjectFolderMenu(
        details: details,
        projectId: projectId,
        projColor: projColor,
        textColor: textColor,
        iconColor: iconColor,
      ),
      child: MouseRegion(
        onEnter: (_) => setState(() => _hoveredProjectIds.add(projectId)),
        onExit: (_) => setState(() => _hoveredProjectIds.remove(projectId)),
        child: Column(
          mainAxisSize: MainAxisSize.min,
          children: [
            // ── Project folder header ──────────────────────────────────────
            Container(
              height: 36,
              color: projColor ?? const Color(0xFF1E1E1E),
              padding: const EdgeInsets.symmetric(horizontal: 4),
              child: Row(
                children: [
                  // Collapse button — always visible, left of label
                  GestureDetector(
                    onTap: () => setState(() {
                      _projectFolderExpanded[projectId] =
                          !(_projectFolderExpanded[projectId] ?? true);
                    }),
                    child: SizedBox(
                      width: 24,
                      height: 24,
                      child: Center(
                        child: AnimatedRotation(
                          turns: (_projectFolderExpanded[projectId] ?? true)
                              ? 0
                              : -0.25,
                          duration: const Duration(milliseconds: 150),
                          child: Icon(
                            Icons.keyboard_arrow_down,
                            size: 14,
                            color: iconColor.withOpacity(0.7),
                          ),
                        ),
                      ),
                    ),
                  ),
                  // Folder icon
                  Icon(
                    isFav ? Icons.star : Icons.folder_open,
                    color: iconColor,
                    size: 16,
                  ),
                  const SizedBox(width: 8),
                  // Folder label — tapping also toggles collapse
                  Expanded(
                    child: GestureDetector(
                      onTap: () => setState(() {
                        _projectFolderExpanded[projectId] =
                            !(_projectFolderExpanded[projectId] ?? true);
                      }),
                      behavior: HitTestBehavior.opaque,
                      child: Text(
                        project.title.toUpperCase(),
                        style: TextStyle(
                          color: textColor,
                          fontSize: 11,
                          fontWeight: FontWeight.bold,
                        ),
                        overflow: TextOverflow.ellipsis,
                      ),
                    ),
                  ),
                  // Active-state dot — visible whenever a search query is set
                  if ((_projectSearchQuery[projectId] ?? '').isNotEmpty)
                    Container(
                      width: 8,
                      height: 8,
                      margin: const EdgeInsets.only(right: 4),
                      decoration: const BoxDecoration(
                        color: Color(0xFF4FC3F7),
                        shape: BoxShape.circle,
                      ),
                    ),
                  // Three-dot menu — hover-only (same dimensions when hidden)
                  AnimatedOpacity(
                    opacity: _hoveredProjectIds.contains(projectId) ? 1.0 : 0.0,
                    duration: const Duration(milliseconds: 150),
                    child: GestureDetector(
                      onTapDown: _hoveredProjectIds.contains(projectId)
                          ? (details) => _showProjectFolderMenu(
                              details: details,
                              projectId: projectId,
                              projColor: projColor,
                              textColor: textColor,
                              iconColor: iconColor,
                            )
                          : null,
                      child: SizedBox(
                        width: 24,
                        height: 24,
                        child: Center(
                          child: Icon(
                            Icons.more_horiz,
                            size: 14,
                            color: iconColor.withOpacity(0.7),
                          ),
                        ),
                      ),
                    ),
                  ),
                  const SizedBox(width: 4),
                ],
              ),
            ),
            // ── Project folder children ────────────────────────────────────
            // Wrapped in a Container that provides:
            //   • left-indentation margin (8 px) to visually nest children
            //   • a left-side accent border whose color is derived from the
            //     project colour (or the global accent when no colour is set)
            //   • a very subtle tinted background so the group reads as one unit
            if (_projectFolderExpanded[projectId] ?? true)
              Container(
                margin: const EdgeInsets.only(left: 8.0),
                decoration: BoxDecoration(
                  // Tint: 5 % opacity of the folder colour keeps it readable
                  // without drowning the tile backgrounds underneath.
                  color: (projColor ?? const Color(0xFF4FC3F7)).withOpacity(
                    0.05,
                  ),
                  border: Border(
                    left: BorderSide(
                      // 45 % opacity gives a clear-but-not-harsh accent stripe
                      color: (projColor ?? const Color(0xFF4FC3F7)).withOpacity(
                        0.45,
                      ),
                      width: 2.5,
                    ),
                  ),
                ),
                child: Column(
                  mainAxisSize: MainAxisSize.min,
                  children: projectTasks
                      .where((t) {
                        final q = (_projectSearchQuery[projectId] ?? '')
                            .toLowerCase();
                        return q.isEmpty || t.title.toLowerCase().contains(q);
                      })
                      .map((task) => _sidebarTaskTile(task, projColor))
                      .toList(),
                ),
              ),
          ],
        ),
      ),
    );
  }

  /// Helper: builds a row for the project three-dot dropdown menu.
