  // ── Canvas section (category) three-dot menu ──────────────────────────────

  /// Opens a custom positioned dropdown for a category header row.
  /// Contains: inline search field, FGS button, delete (if custom category).
  void _showCanvasSectionMenu({
    required TapDownDetails details,
    required String sectionName,
    required bool isFav,
    required bool isAll,
  }) {
    showDialog<void>(
      context: context,
      barrierColor: Colors.transparent,
      barrierDismissible: true,
      builder: (ctx) {
        final screen = MediaQuery.of(ctx).size;
        double left = details.globalPosition.dx - 10;
        double top = details.globalPosition.dy + 4;
        if (left + 214 > screen.width) left = screen.width - 218;
        if (left < 4) left = 4;
        return Stack(
          children: [
            Positioned(
              left: left,
              top: top,
              width: 214,
              child: Material(
                color: Colors.transparent,
                child: _CanvasSectionMenuPanel(
                  sectionName: sectionName,
                  isFav: isFav,
                  isAll: isAll,
                  initialQuery: _sectionSearchQuery[sectionName] ?? '',
                  sortAsc: _sectionSortAsc[sectionName] ?? true,
                  onQueryChanged: (q) =>
                      setState(() => _sectionSearchQuery[sectionName] = q),
                  onFilterGroupSort: () {
                    Navigator.of(ctx).pop();
                    setState(() => _activeSectionFilter = sectionName);
                  },
                  onSettings: (!isFav && !isAll)
                      ? () {
                          Navigator.of(ctx).pop();
                          setState(
                            () => _tasksNavSection =
                                'canvas_category_settings:$sectionName',
                          );
                        }
                      : null,
                  onDelete: (!isFav && !isAll)
                      ? () {
                          Navigator.of(ctx).pop();
                          _deleteCategory(sectionName);
                        }
                      : null,
                ),
              ),
            ),
          ],
        );
      },
    );
  }

  // ── Project folder three-dot menu ─────────────────────────────────────────

  /// Opens a custom positioned dropdown for a project folder header row.
  /// Contains: inline search field, then existing project actions.
  void _showProjectFolderMenu({
    required TapDownDetails details,
    required String projectId,
    required Color? projColor,
    required Color textColor,
    required Color iconColor,
  }) {
    final bool isFav = _favoriteProjectIds.contains(projectId);
    final customCategories = _sidebarSectionOrder
        .where((s) => s != 'Favorites' && s != 'All')
        .toList();
    final Map<String, bool> catMembership = {
      for (final cat in customCategories)
        cat: _categoryMappings[cat]?.contains(projectId) ?? false,
    };

    showDialog<void>(
      context: context,
      barrierColor: Colors.transparent,
      barrierDismissible: true,
      builder: (ctx) {
        final screen = MediaQuery.of(ctx).size;
        const double panelWidth = 214;
        const double edgePad = 8;

        double left = details.globalPosition.dx - 10;
        double top = details.globalPosition.dy + 4;

        // Keep horizontally on-screen
        if (left + panelWidth > screen.width)
          left = screen.width - panelWidth - edgePad;
        if (left < edgePad) left = edgePad;

        // Available vertical room below the click point; flip above if tight
        final double roomBelow = screen.height - top - edgePad;
        final double roomAbove = details.globalPosition.dy - edgePad;
        const double minComfortableHeight = 260;
        if (roomBelow < minComfortableHeight && roomAbove > roomBelow) {
          // Anchor the bottom of the popup to just above the click point
          top = details.globalPosition.dy - 4;
          final double maxH = roomAbove.clamp(
            minComfortableHeight,
            screen.height - edgePad * 2,
          );
          return _buildPopupStack(
            ctx,
            left: left,
            bottom: screen.height - top,
            width: panelWidth,
            maxHeight: maxH,
            projectId: projectId,
            isFav: isFav,
            customCategories: customCategories,
            catMembership: catMembership,
          );
        }

        final double maxHeight = roomBelow.clamp(
          minComfortableHeight,
          screen.height - edgePad * 2,
        );
        return _buildPopupStack(
          ctx,
          left: left,
          top: top,
          width: panelWidth,
          maxHeight: maxHeight,
          projectId: projectId,
          isFav: isFav,
          customCategories: customCategories,
          catMembership: catMembership,
        );
      },
    );
  }

  // ── Inbox folder three-dot menu ───────────────────────────────────────────

  /// Opens the project-folder dropdown for the Inbox pseudo-project.
  /// Identical to [_showProjectFolderMenu] but omits canvas-specific actions
  /// (Favorite, Change Color, Add to Category) and the Delete row, since
  /// Inbox is not a real Project.
  void _showInboxFolderMenu({required TapDownDetails details}) {
    const String inboxId = 'INBOX_PROJECT';

    showDialog<void>(
      context: context,
      barrierColor: Colors.transparent,
      barrierDismissible: true,
      builder: (ctx) {
        final screen = MediaQuery.of(ctx).size;
        const double panelWidth = 214;
        const double edgePad = 8;

        double left = details.globalPosition.dx - 10;
        double top = details.globalPosition.dy + 4;

        if (left + panelWidth > screen.width)
          left = screen.width - panelWidth - edgePad;
        if (left < edgePad) left = edgePad;

        final double roomBelow = screen.height - top - edgePad;
        final double roomAbove = details.globalPosition.dy - edgePad;
        const double minComfortableHeight = 200;

        if (roomBelow < minComfortableHeight && roomAbove > roomBelow) {
          final double maxH = roomAbove.clamp(
            minComfortableHeight,
            screen.height - edgePad * 2,
          );
          return _buildPopupStack(
            ctx,
            left: left,
            bottom: screen.height - (details.globalPosition.dy - 4),
            width: panelWidth,
            maxHeight: maxH,
            projectId: inboxId,
            isFav: false,
            customCategories: const [],
            catMembership: const {},
            showDelete: false,
            showCanvasActions: false,
          );
        }

        final double maxHeight = roomBelow.clamp(
          minComfortableHeight,
          screen.height - edgePad * 2,
        );
        return _buildPopupStack(
          ctx,
          left: left,
          top: top,
          width: panelWidth,
          maxHeight: maxHeight,
          projectId: inboxId,
          isFav: false,
          customCategories: const [],
          catMembership: const {},
          showDelete: false,
          showCanvasActions: false,
        );
      },
    );
  }

  Widget _buildPopupStack(
    BuildContext ctx, {
    required double left,
    double? top,
    double? bottom,
    required double width,
    required double maxHeight,
    required String projectId,
    required bool isFav,
    required List<String> customCategories,
    required Map<String, bool> catMembership,
    bool showDelete = true,
    bool showCanvasActions = true,
  }) {
    return Stack(
      children: [
        Positioned(
          left: left,
          top: top,
          bottom: bottom,
          width: width,
          child: Material(
            color: Colors.transparent,
            child: ConstrainedBox(
              constraints: BoxConstraints(maxHeight: maxHeight),
              child: SingleChildScrollView(
                physics: const ClampingScrollPhysics(),
                child: _ProjectFolderMenuPanel(
                  projectId: projectId,
                  initialQuery: _projectSearchQuery[projectId] ?? '',
                  onQueryChanged: (q) =>
                      setState(() => _projectSearchQuery[projectId] = q),
                  // ── Canvas-specific ──────────────────────────────────────
                  isFav: isFav,
                  categories: customCategories,
                  categoryMembership: catMembership,
                  showDelete: showDelete,
                  onToggleFavorite: showCanvasActions
                      ? () => setState(() {
                          if (_favoriteProjectIds.contains(projectId)) {
                            _favoriteProjectIds.remove(projectId);
                          } else {
                            _favoriteProjectIds.add(projectId);
                          }
                          _saveWorkspace();
                        })
                      : null,
                  onChangeColor: showCanvasActions
                      ? () {
                          Navigator.of(ctx).pop();
                          Future.delayed(
                            const Duration(milliseconds: 10),
                            () => _showColorPicker(projectId),
                          );
                        }
                      : null,
                  onToggleCategory: showCanvasActions
                      ? (cat, nowIn) => setState(() {
                          if (nowIn) {
                            (_categoryMappings[cat] ??= {}).add(projectId);
                          } else {
                            _categoryMappings[cat]?.remove(projectId);
                          }
                          _saveWorkspace();
                        })
                      : null,
                  // ── Shared actions ───────────────────────────────────────
                  onFilterGroupSort: () {
                    Navigator.of(ctx).pop();
                    final projTitle = _projects[projectId]?.title ?? projectId;
                    setState(() {
                      _filterSidebarTitle = 'Project: $projTitle';
                      _filterSidebarOpen = true;
                    });
                  },
                  onAction: (action) {
                    Navigator.of(ctx).pop();
                    switch (action) {
                      case 'delete':
                        _confirmDeleteProject(projectId);
                        break;
                      case 'settings':
                        _showProjectSettingsDialog(projectId);
                        break;
                      case 'quick_history':
                        setState(
                          () => _tasksNavSection =
                              'quick_history:proj:$projectId',
                        );
                        break;
                      case 'worklog':
                        setState(
                          () => _tasksNavSection = 'worklog:proj:$projectId',
                        );
                        break;
                      case 'metrics':
                        setState(
                          () => _tasksNavSection = 'metrics:proj:$projectId',
                        );
                        break;
                    }
                  },
                ),
              ),
            ),
          ),
        ),
      ],
    );
  }

  /// Dialog to create a new Project from the Tasks sidebar.
  void _showCreateProjectDialog() {
    final controller = TextEditingController();
    Color pickedColor = Colors.blueAccent;

    showDialog<void>(
      context: context,
      builder: (ctx) => StatefulBuilder(
        builder: (ctx, setDlg) => AlertDialog(
          backgroundColor: const Color(0xFF1E2124),
          shape: RoundedRectangleBorder(
            borderRadius: BorderRadius.circular(12),
          ),
          title: const Text(
            'New Project',
            style: TextStyle(color: Colors.white, fontSize: 15),
          ),
          content: Column(
            mainAxisSize: MainAxisSize.min,
            crossAxisAlignment: CrossAxisAlignment.start,
            children: [
              TextField(
                controller: controller,
                autofocus: true,
                style: const TextStyle(color: Colors.white, fontSize: 13),
                decoration: InputDecoration(
                  hintText: 'Project name',
                  hintStyle: const TextStyle(color: Colors.white38),
                  filled: true,
                  fillColor: Colors.white.withOpacity(0.06),
                  border: OutlineInputBorder(
                    borderRadius: BorderRadius.circular(8),
                    borderSide: BorderSide.none,
                  ),
                  contentPadding: const EdgeInsets.symmetric(
                    horizontal: 12,
                    vertical: 10,
                  ),
                ),
              ),
              const SizedBox(height: 14),
              const Text(
                'COLOR',
                style: TextStyle(
                  fontSize: 9,
                  fontWeight: FontWeight.bold,
                  color: Colors.white24,
                  letterSpacing: 1.2,
                ),
              ),
              const SizedBox(height: 8),
              Wrap(
                spacing: 8,
                children:
                    [
                      Colors.blueAccent,
                      const Color(0xFF4CAF50),
                      const Color(0xFFE91E63),
                      const Color(0xFFFF9800),
                      const Color(0xFF9C27B0),
                      const Color(0xFF00BCD4),
                      const Color(0xFFFFD600),
                      Colors.white24,
                    ].map((c) {
                      final selected = pickedColor == c;
                      return GestureDetector(
                        onTap: () => setDlg(() => pickedColor = c),
                        child: Container(
                          width: 24,
                          height: 24,
                          decoration: BoxDecoration(
                            color: c,
                            shape: BoxShape.circle,
                            border: Border.all(
                              color: selected
                                  ? Colors.white
                                  : Colors.transparent,
                              width: 2,
                            ),
                          ),
                        ),
                      );
                    }).toList(),
              ),
            ],
          ),
          actions: [
            TextButton(
              onPressed: () => Navigator.of(ctx).pop(),
              child: const Text(
                'Cancel',
                style: TextStyle(color: Colors.white38),
              ),
            ),
            TextButton(
              onPressed: () {
                final name = controller.text.trim();
                if (name.isEmpty) return;
                final id = 'proj_${DateTime.now().millisecondsSinceEpoch}';
                setState(() {
                  _projects[id] = Project(id: id, title: name);
                  _projectOrder.add(id);
                  _projectColors[id] = pickedColor;
                });
                _saveWorkspace();
                Navigator.of(ctx).pop();
              },
              child: const Text(
                'Create',
                style: TextStyle(color: Color(0xFF4FC3F7)),
              ),
            ),
          ],
        ),
      ),
    );
  }

  /// Dialog to create a new Tag from the Tasks sidebar.
  void _showCreateTagDialog() {
    final controller = TextEditingController();

    showDialog<void>(
      context: context,
      builder: (ctx) => AlertDialog(
        backgroundColor: const Color(0xFF1E2124),
        shape: RoundedRectangleBorder(borderRadius: BorderRadius.circular(12)),
        title: const Text(
          'New Tag',
          style: TextStyle(color: Colors.white, fontSize: 15),
        ),
        content: TextField(
          controller: controller,
          autofocus: true,
          style: const TextStyle(color: Colors.white, fontSize: 13),
          decoration: InputDecoration(
            hintText: 'Tag name',
            hintStyle: const TextStyle(color: Colors.white38),
            filled: true,
            fillColor: Colors.white.withOpacity(0.06),
            border: OutlineInputBorder(
              borderRadius: BorderRadius.circular(8),
              borderSide: BorderSide.none,
            ),
            contentPadding: const EdgeInsets.symmetric(
              horizontal: 12,
              vertical: 10,
            ),
          ),
          onSubmitted: (_) {
            final name = controller.text.trim();
            if (name.isEmpty) return;
            setState(() {
              // Add the tag to every task that is selected, or just register
              // it by assigning to a transient task list. Since tags are
              // derived from tasks, we store the new tag in a dedicated set
              // so the sidebar shows it even with no tasks yet.
              _customTags.add(name);
            });
            _saveWorkspace();
            Navigator.of(ctx).pop();
          },
        ),
        actions: [
          TextButton(
            onPressed: () => Navigator.of(ctx).pop(),
            child: const Text(
              'Cancel',
              style: TextStyle(color: Colors.white38),
            ),
          ),
          TextButton(
            onPressed: () {
              final name = controller.text.trim();
              if (name.isEmpty) return;
              setState(() => _customTags.add(name));
              _saveWorkspace();
              Navigator.of(ctx).pop();
            },
            child: const Text(
              'Create',
              style: TextStyle(color: Color(0xFF4FC3F7)),
            ),
          ),
        ],
      ),
    );
  }

  /// Confirm + execute tag deletion.
  void _confirmDeleteTag(String tagName) {
    showDialog<bool>(
      context: context,
      builder: (ctx) => AlertDialog(
        backgroundColor: const Color(0xFF1E2124),
        shape: RoundedRectangleBorder(borderRadius: BorderRadius.circular(10)),
        title: const Text(
          'Delete Tag',
          style: TextStyle(color: Colors.white, fontSize: 15),
        ),
        content: Text(
          'Remove the "$tagName" tag? It will be detached from all tasks.',
          style: const TextStyle(color: Colors.white70, fontSize: 13),
        ),
        actions: [
          TextButton(
            onPressed: () => Navigator.of(ctx).pop(false),
            child: const Text(
              'Cancel',
              style: TextStyle(color: Colors.white38),
            ),
          ),
          TextButton(
            onPressed: () => Navigator.of(ctx).pop(true),
            child: const Text(
              'Delete',
              style: TextStyle(color: Color(0xFFEF5350)),
            ),
          ),
        ],
      ),
    ).then((confirmed) {
      if (confirmed != true || !mounted) return;
      setState(() {
        _customTags.remove(tagName);
        // Also strip from all tasks
        for (final t in _allTasks) {
          t.tagIds.remove(tagName);
        }
        if (_tasksNavSection == 'tag:$tagName') {
          _tasksNavSection = 'Today';
        }
      });
      _saveWorkspace();
    });
  }

  /// Dialog to rename an existing tag.
  void _showRenameTagDialog(String oldName) {
    final controller = TextEditingController(text: oldName);
    showDialog<void>(
      context: context,
      builder: (ctx) => AlertDialog(
        backgroundColor: const Color(0xFF1E2124),
        shape: RoundedRectangleBorder(borderRadius: BorderRadius.circular(12)),
        title: const Text(
          'Rename Tag',
          style: TextStyle(color: Colors.white, fontSize: 15),
        ),
        content: TextField(
          controller: controller,
          autofocus: true,
          style: const TextStyle(color: Colors.white, fontSize: 13),
          decoration: InputDecoration(
            hintText: 'Tag name',
            hintStyle: const TextStyle(color: Colors.white38),
            filled: true,
            fillColor: Colors.white.withOpacity(0.06),
            border: OutlineInputBorder(
              borderRadius: BorderRadius.circular(8),
              borderSide: BorderSide.none,
            ),
            contentPadding: const EdgeInsets.symmetric(
              horizontal: 12,
              vertical: 10,
            ),
          ),
        ),
        actions: [
          TextButton(
            onPressed: () => Navigator.of(ctx).pop(),
            child: const Text(
              'Cancel',
              style: TextStyle(color: Colors.white38),
            ),
          ),
          TextButton(
            onPressed: () {
              final newName = controller.text.trim();
              if (newName.isEmpty || newName == oldName) {
                Navigator.of(ctx).pop();
                return;
              }
              setState(() {
                // Rename in customTags
                if (_customTags.contains(oldName)) {
                  _customTags.remove(oldName);
                  _customTags.add(newName);
                }
                // Rename on all tasks
                for (final t in _allTasks) {
                  final idx = t.tagIds.indexOf(oldName);
                  if (idx >= 0) t.tagIds[idx] = newName;
                }
                if (_tasksNavSection == 'tag:$oldName') {
                  _tasksNavSection = 'tag:$newName';
                }
              });
              _saveWorkspace();
              Navigator.of(ctx).pop();
            },
            child: const Text(
              'Rename',
              style: TextStyle(color: Color(0xFF4FC3F7)),
            ),
          ),
        ],
      ),
    );
  }

  /// Confirm + execute project deletion from the three-dot menu.
  void _confirmDeleteProject(String projectId) {
    final proj = _projects[projectId];
    if (proj == null) return;
    showDialog<bool>(
      context: context,
      builder: (ctx) => AlertDialog(
        backgroundColor: const Color(0xFF1E2124),
        shape: RoundedRectangleBorder(borderRadius: BorderRadius.circular(10)),
        title: const Text(
          'Delete Project',
          style: TextStyle(color: Colors.white, fontSize: 15),
        ),
        content: Text(
          'Delete "${proj.title}" and all its tasks? This cannot be undone.',
          style: const TextStyle(color: Colors.white70, fontSize: 13),
        ),
        actions: [
          TextButton(
            onPressed: () => Navigator.of(ctx).pop(false),
            child: const Text(
              'Cancel',
              style: TextStyle(color: Colors.white38),
            ),
          ),
          TextButton(
            onPressed: () => Navigator.of(ctx).pop(true),
            child: const Text(
              'Delete',
              style: TextStyle(color: Color(0xFFEF5350)),
            ),
          ),
        ],
      ),
    ).then((confirmed) {
      if (confirmed != true || !mounted) return;
      setState(() {
        _allTasks.removeWhere((t) => t.projectId == projectId);
        _projects.remove(projectId);
        _projectOrder.remove(projectId);
        _projectColors.remove(projectId);
        _projectIcons.remove(projectId);
        _projectBacklogEnabled.remove(projectId);
        _projectHiddenFromMenu.remove(projectId);
        _favoriteProjectIds.remove(projectId);
        for (final cat in _categoryMappings.values) {
          cat.remove(projectId);
        }
      });
      _saveWorkspace();
    });
  }

  Widget _sidebarTaskTile(Task task, Color? projColor) {
    return Draggable<Task>(
      data: task,
      feedback: _taskCardUI(task, isDragging: true),
      childWhenDragging: Opacity(
        opacity: 0.3,
        child: _buildTileUI(task, projColor),
      ),
      child: _buildTileUI(task, projColor),
    );
  }

  Widget _buildTileUI(Task task, Color? projColor) {
    final isLight = AppTheme.of(context).isLight;

    // Task tiles sit inside a container whose background is panelBg with only
    // a 5 % tint of projColor on top (see withOpacity(0.05) in the parent).
    // Computing luminance on raw projColor gives the wrong answer when the
    // project colour is bright (e.g. yellow): the tinted bg is still very
    // dark, but the check would select black text.  Fix: blend the tint over
    // the actual panel background first, then check that blended luminance.
    final Color panelBg = isLight
        ? const Color(0xFFFFFFFF)
        : const Color(0xFF1E2124);

    Color textColor;
    if (projColor != null) {
      final Color effectiveBg = Color.alphaBlend(
        projColor.withOpacity(0.05),
        panelBg,
      );
      textColor = effectiveBg.computeLuminance() > 0.5
          ? Colors.black87
          : Colors.white;
    } else {
      textColor = isLight ? Colors.black54 : Colors.white70;
    }

    return ListTile(
      dense: true,
      contentPadding: const EdgeInsets.only(left: 44, right: 8),
      title: Column(
        crossAxisAlignment: CrossAxisAlignment.start,
        mainAxisSize: MainAxisSize.min,
        children: [
          Text(task.title, style: TextStyle(color: textColor, fontSize: 12)),
          // Conditionally show the date (and time if available) if toggled
          if (_showDateOnListedTasks && task.dueDay != null)
            Padding(
              padding: const EdgeInsets.only(top: 2),
              child: Builder(
                builder: (context) {
                  String dateStr = task.dueDay!;
                  final parsed = DateTime.tryParse(task.dueDay!);
                  if (parsed != null) {
                    dateStr =
                        "${parsed.year}-${parsed.month.toString().padLeft(2, '0')}-${parsed.day.toString().padLeft(2, '0')}";
                  } else if (task.dueDay!.contains(' ')) {
                    dateStr = task.dueDay!.split(' ').first;
                  }
                  String? timeStr;
                  if (task.plannedAt != null && task.plannedAt! > 0) {
                    final dt = DateTime.fromMillisecondsSinceEpoch(
                      task.plannedAt!,
                    ).toLocal();
                    timeStr =
                        "${dt.hour.toString().padLeft(2, '0')}:${dt.minute.toString().padLeft(2, '0')}";
                  } else if (task.dueDay!.contains('T')) {
                    final dt = DateTime.tryParse(task.dueDay!);
                    if (dt != null) {
                      timeStr =
                          "${dt.hour.toString().padLeft(2, '0')}:${dt.minute.toString().padLeft(2, '0')}";
                    }
                  } else if (task.dueDay!.contains(' ')) {
                    timeStr = task.dueDay!.split(' ').skip(1).join(' ');
                  }
                  final Color metaColor = projColor != null
                      ? textColor.withOpacity(0.7)
                      : Colors.white38;
                  return Row(
                    children: [
                      Text(
                        dateStr,
                        style: TextStyle(fontSize: 10, color: metaColor),
                      ),
                      if (timeStr != null) ...[
                        Text(
                          '  |  ',
                          style: TextStyle(
                            fontSize: 10,
                            color: metaColor.withOpacity(0.5),
                          ),
                        ),
                        Text(
                          timeStr,
                          style: TextStyle(fontSize: 10, color: metaColor),
                        ),
                      ],
                    ],
                  );
                },
              ),
            ),
        ],
      ),
      trailing: IconButton(
        icon: Icon(
          Icons.info_outline,
          size: 16,
          color: projColor != null
              ? textColor.withOpacity(0.5)
              : Colors.white24,
        ),
        onPressed: () => setState(() {
          _selectedTask = task;
          _showDetails = true;
        }),
      ),
    );
  }

  Widget _buildSidebarTaskItem(Task task) {
    return Draggable<Task>(
      data: task,
      dragAnchorStrategy: childDragAnchorStrategy,
      feedback: _taskFeedback(task),
      child: ListTile(
        contentPadding: const EdgeInsets.only(left: 44, right: 8),
        dense: true,
        title: Text(
          task.title,
          style: const TextStyle(color: Colors.white, fontSize: 13),
        ),
        trailing: IconButton(
          icon: const Icon(
            Icons.chevron_right,
            color: Colors.white24,
            size: 18,
          ),
          onPressed: () => setState(() {
            _selectedTask = task;
            _showDetails = true;
          }),
        ),
      ),
    );
  }

  Widget _buildProjectListContent() {
    return SingleChildScrollView(
      child: Column(
        mainAxisSize: MainAxisSize.min,
        children: [
          // ── Reorderable project sections ────────────────────────────────────
          ReorderableListView(
            buildDefaultDragHandles: false,
            padding: EdgeInsets.zero,
            shrinkWrap: true,
            physics: const NeverScrollableScrollPhysics(),
            onReorder: (oldIndex, newIndex) {
              setState(() {
                if (newIndex > oldIndex) newIndex -= 1;
                final item = _sidebarSectionOrder.removeAt(oldIndex);
                _sidebarSectionOrder.insert(newIndex, item);
              });
            },
            children: _sidebarSectionOrder.map((section) {
              bool isFav = section == 'Favorites';
              bool isAll = section == 'All';

              return _buildSidebarRegion(
                key: ValueKey('region_$section'),
                title: section.toUpperCase(),
                sectionName: section,
                isFavoriteSection: isFav,
                isAllSection: isAll,
                isExpanded: _sectionExpandedStates[section] ?? true,
                onToggle: () => setState(
                  () => _sectionExpandedStates[section] =
                      !(_sectionExpandedStates[section] ?? true),
                ),
              );
            }).toList(),
          ),
        ],
      ),
    );
  }

  Widget _buildSidebarRegion({
    required Key key,
    required String title,
    required String sectionName,
    required bool isFavoriteSection,
    required bool isAllSection,
    required bool isExpanded,
    required VoidCallback onToggle,
  }) {
    // 1. Filtering Logic
    List<String> ids;
    if (isFavoriteSection) {
      ids = _projectOrder
          .where((id) => _favoriteProjectIds.contains(id))
          .toList();
    } else if (isAllSection) {
      ids = List.from(_projectOrder);
    } else {
      ids = _projectOrder
          .where((id) => (_categoryMappings[sectionName] ?? {}).contains(id))
          .toList();
    }

    // 2. Sorting Logic
    ids.sort((a, b) {
      final tA = _projects[a]?.title ?? "";
      final tB = _projects[b]?.title ?? "";
      bool asc = _sectionSortAsc[sectionName] ?? true;
      return asc ? tA.compareTo(tB) : tB.compareTo(tA);
    });

    return ReorderableDragStartListener(
      key: key,
      index: _sidebarSectionOrder.indexOf(sectionName),
      child: Column(
        mainAxisSize: MainAxisSize.min,
        children: [
          // REGION HEADER — hover-gated three-dot, always-visible collapse
          MouseRegion(
            onEnter: (_) => setState(() => _hoveredSectionIds.add(sectionName)),
            onExit: (_) =>
                setState(() => _hoveredSectionIds.remove(sectionName)),
            child: Container(
              height: 32,
              decoration: const BoxDecoration(
                color: Color(0xFF252525),
                border: Border(
                  top: BorderSide(color: Colors.white10, width: 0.5),
                  bottom: BorderSide(color: Colors.white10, width: 0.5),
                ),
              ),
              child: Row(
                children: [
                  // Collapse toggle — always visible
                  GestureDetector(
                    onTap: onToggle,
                    child: SizedBox(
                      width: 32,
                      height: 32,
                      child: Center(
                        child: AnimatedRotation(
                          turns: isExpanded ? 0 : -0.25,
                          duration: const Duration(milliseconds: 150),
                          child: const Icon(
                            Icons.keyboard_arrow_down,
                            size: 14,
                            color: Colors.white38,
                          ),
                        ),
                      ),
                    ),
                  ),
                  // Category label — tapping also toggles
                  Expanded(
                    child: GestureDetector(
                      onTap: onToggle,
                      behavior: HitTestBehavior.opaque,
                      child: Text(
                        title,
                        style: const TextStyle(
                          color: Colors.white38,
                          fontSize: 10,
                          fontWeight: FontWeight.bold,
                          letterSpacing: 1.1,
                        ),
                      ),
                    ),
                  ),
                  // Active-state dot — visible whenever a search query is set
                  if ((_sectionSearchQuery[sectionName] ?? '').isNotEmpty)
                    Container(
                      width: 8,
                      height: 8,
                      margin: const EdgeInsets.only(right: 4),
                      decoration: const BoxDecoration(
                        color: Color(0xFF4FC3F7),
                        shape: BoxShape.circle,
                      ),
                    ),
                  // Filter-active dot — visible when a section filter is configured
                  if ((_sectionFilterRules[sectionName] ?? []).any(
                        (r) => r.isConfigured,
                      ) ||
                      (_sectionSortCriteria[sectionName] ?? []).isNotEmpty)
                    Tooltip(
                      message: 'Filter / Sort active',
                      child: Container(
                        width: 8,
                        height: 8,
                        margin: const EdgeInsets.only(right: 4),
                        decoration: BoxDecoration(
                          color: Colors.orangeAccent.withOpacity(0.9),
                          shape: BoxShape.circle,
                        ),
                      ),
                    ),
                  // Three-dot button — hover-only, same dimensions when hidden
                  AnimatedOpacity(
                    opacity: _hoveredSectionIds.contains(sectionName)
                        ? 1.0
                        : 0.0,
                    duration: const Duration(milliseconds: 150),
                    child: GestureDetector(
                      onTapDown: _hoveredSectionIds.contains(sectionName)
                          ? (details) => _showCanvasSectionMenu(
                              details: details,
                              sectionName: sectionName,
                              isFav: isFavoriteSection,
                              isAll: isAllSection,
                            )
                          : null,
                      child: const SizedBox(
                        width: 24,
                        height: 24,
                        child: Center(
                          child: Icon(
                            Icons.more_horiz,
                            size: 14,
                            color: Colors.white38,
                          ),
                        ),
                      ),
                    ),
                  ),
                  const SizedBox(width: 4),
                ],
              ),
            ),
          ),
          if (isExpanded) ...[
            if (ids.isEmpty)
              Padding(
                padding: const EdgeInsets.symmetric(vertical: 20),
                child: Center(
                  child: Text(
                    isFavoriteSection
                        ? "No favorites yet"
                        : "No projects in this category",
                    style: const TextStyle(color: Colors.white24, fontSize: 11),
                  ),
                ),
              ),
            // ── Inbox entry — pinned at the top of the All section only ──
            if (isAllSection) _buildInboxProjectSection(),
            ...ids
                .where((id) {
                  // Respect hide-from-menu flag (same as Tasks sidebar)
                  if ((_projectHiddenFromMenu[id] ?? false) &&
                      !_showHiddenProjects) {
                    return false;
                  }
                  final q = (_sectionSearchQuery[sectionName] ?? '')
                      .toLowerCase();
                  if (q.isEmpty) return true;
                  return (_projects[id]?.title ?? '').toLowerCase().contains(q);
                })
                .map((id) => _buildProjectSection(id)),
          ],
        ],
      ),
    );
  }

  Widget _buildSettingsMainArea() {
    const labels = {
      'general': 'General',
      'tasks': 'Tasks',
      'notes': 'Notes',
      'canvas': 'Canvas',
      'projects': 'Projects',
    };
    final label = labels[_settingsSection] ?? 'Settings';

    return Container(
      color: const Color(0xFF181A1B),
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.stretch,
        children: [
          // ── Section header bar ──────────────────────────────────────────
          Container(
            padding: const EdgeInsets.fromLTRB(20, 14, 20, 14),
            decoration: const BoxDecoration(
              color: Color(0xFF1E2124),
              border: Border(bottom: BorderSide(color: Color(0xFF2C2F32))),
            ),
            child: Text(
              label,
              style: const TextStyle(
                color: Colors.white,
                fontSize: 16,
                fontWeight: FontWeight.w600,
              ),
            ),
          ),
          // ── Section content ─────────────────────────────────────────────
          Expanded(child: _buildSettingsSectionContent(_settingsSection)),
        ],
      ),
    );
  }

  Widget _buildSettingsSectionContent(String section) {
    switch (section) {
      case 'general':
        return _buildSettingsSectionGeneral();
      case 'tasks':
        return _buildSettingsSectionTasks();
      case 'notes':
        return _buildSettingsSectionNotes();
      case 'canvas':
        return _buildSettingsSectionCanvas();
      case 'projects':
        return _buildSettingsSectionProjects();
      default:
        return _buildSettingsSectionGeneral();
    }
  }

  // ── Settings section scaffold ─────────────────────────────────────────────
  Widget _settingsPage({required List<Widget> cards}) {
    return ListView(
      padding: const EdgeInsets.symmetric(horizontal: 0, vertical: 0),
      children: cards,
    );
  }

  // ── Collapsible card (mirrors the screenshot style) ───────────────────────
  Widget _settingsCard({
    required String label,
    required bool expanded,
    required VoidCallback onTap,
    required List<Widget> children,
  }) {
    return Container(
      margin: const EdgeInsets.fromLTRB(16, 0, 16, 1),
      decoration: BoxDecoration(
        color: const Color(0xFF212426),
        borderRadius: BorderRadius.circular(6),
        border: Border.all(
          color: expanded
              ? Colors.blueAccent.withOpacity(0.25)
              : const Color(0xFF2C2F32),
        ),
      ),
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.stretch,
        children: [
          InkWell(
            onTap: onTap,
            borderRadius: BorderRadius.vertical(
              top: const Radius.circular(6),
              bottom: expanded ? Radius.zero : const Radius.circular(6),
            ),
            child: Padding(
              padding: const EdgeInsets.symmetric(horizontal: 16, vertical: 14),
              child: Row(
                children: [
                  AnimatedRotation(
                    turns: expanded ? 0 : -0.25,
                    duration: const Duration(milliseconds: 150),
                    child: Icon(
                      Icons.expand_more_rounded,
                      size: 16,
                      color: expanded
                          ? Colors.blueAccent.withOpacity(0.8)
                          : Colors.white38,
                    ),
                  ),
                  const SizedBox(width: 10),
                  Text(
                    label,
                    style: TextStyle(
                      fontSize: 13,
                      fontWeight: FontWeight.w600,
                      color: expanded ? Colors.white : Colors.white70,
                    ),
                  ),
                ],
              ),
            ),
          ),
          AnimatedSize(
            duration: const Duration(milliseconds: 200),
            curve: Curves.easeInOut,
            child: expanded
                ? Column(
                    crossAxisAlignment: CrossAxisAlignment.stretch,
                    children: [
                      const Divider(color: Color(0xFF2C2F32), height: 1),
                      ...children,
                    ],
                  )
                : const SizedBox.shrink(),
          ),
        ],
      ),
    );
  }

  Widget _buildSettingsContent() {
    const items = [
      ('general', Icons.tune_rounded, 'General'),
      ('tasks', Icons.check_circle_outline, 'Tasks'),
      ('notes', Icons.notes_rounded, 'Notes'),
      ('canvas', Icons.dashboard_outlined, 'Canvas'),
      ('projects', Icons.folder_outlined, 'Projects'),
    ];
    return Column(
      crossAxisAlignment: CrossAxisAlignment.stretch,
      children: [
        Padding(
          padding: const EdgeInsets.fromLTRB(16, 20, 16, 10),
          child: Text(
            'SETTINGS',
            style: TextStyle(
              color: Colors.white38,
              fontSize: 10,
              fontWeight: FontWeight.bold,
              letterSpacing: 1.5,
            ),
          ),
        ),
        const Divider(color: Colors.white10, height: 1),
        Expanded(
          child: ListView(
            padding: const EdgeInsets.symmetric(vertical: 6),
            children: items.map((item) {
              final (id, icon, label) = item;
              final active = _settingsSection == id;
              return InkWell(
                onTap: () => setState(() => _settingsSection = id),
                child: AnimatedContainer(
                  duration: const Duration(milliseconds: 120),
                  margin: const EdgeInsets.symmetric(
                    horizontal: 8,
                    vertical: 2,
                  ),
                  padding: const EdgeInsets.symmetric(
                    horizontal: 10,
                    vertical: 8,
                  ),
                  decoration: BoxDecoration(
                    color: active
                        ? Colors.blueAccent.withOpacity(0.12)
                        : Colors.transparent,
                    borderRadius: BorderRadius.circular(6),
                    border: Border.all(
                      color: active
                          ? Colors.blueAccent.withOpacity(0.3)
                          : Colors.transparent,
                    ),
                  ),
                  child: Row(
                    children: [
                      Icon(
                        icon,
                        size: 14,
                        color: active ? Colors.blueAccent : Colors.white38,
                      ),
                      const SizedBox(width: 10),
                      Text(
                        label,
                        style: TextStyle(
                          fontSize: 12,
                          fontWeight: active
                              ? FontWeight.w600
                              : FontWeight.normal,
                          color: active ? Colors.white : Colors.white54,
                        ),
                      ),
                    ],
                  ),
                ),
              );
            }).toList(),
          ),
        ),
      ],
    );
  }

