      ('fr', 'Français'),
      ('de', 'Deutsch'),
      ('it', 'Italiano'),
      ('ja', '日本語'),
      ('zh', '中文'),
      ('ko', '한국어'),
    ];
    const locales = [
      ('en_US', 'English (US) – 12h'),
      ('en_GB', 'English (UK) – 24h'),
      ('pt_BR', 'Português (BR) – 24h'),
      ('de_DE', 'Deutsch – 24h'),
      ('fr_FR', 'Français – 24h'),
      ('ja_JP', '日本語 – 24h'),
    ];

    return _settingsPage(
      cards: [
        // ── Workspace ─────────────────────────────────────────────────────
        _settingsCard(
          label: 'Workspace',
          expanded: _settingsGeneralExpanded,
          onTap: () => setState(
            () => _settingsGeneralExpanded = !_settingsGeneralExpanded,
          ),
          children: [
            Padding(
              padding: const EdgeInsets.fromLTRB(16, 12, 16, 16),
              child: TextField(
                controller: _workspaceNameController,
                style: const TextStyle(color: Colors.white70, fontSize: 13),
                decoration: const InputDecoration(
                  labelText: 'Workspace name',
                  labelStyle: TextStyle(color: Colors.white38),
                  enabledBorder: UnderlineInputBorder(
                    borderSide: BorderSide(color: Colors.white24),
                  ),
                  focusedBorder: UnderlineInputBorder(
                    borderSide: BorderSide(color: Colors.blueAccent),
                  ),
                ),
                onChanged: (val) {
                  setState(() {
                    _workspaceName = val;
                    // Keep the registry entry in sync so the switcher shows
                    // the updated name immediately.
                    for (final w in _savedWorkspaces) {
                      if (w['id'] == _workspaceId) {
                        w['name'] = val;
                        break;
                      }
                    }
                  });
                  _saveWorkspace();
                  _saveGeneral();
                },
              ),
            ),
          ],
        ),
        // ── Dark Mode ─────────────────────────────────────────────────────
        _settingsCard(
          label: 'Dark Mode',
          expanded: true,
          onTap: () {},
          children: [
            Padding(
              padding: const EdgeInsets.fromLTRB(16, 8, 16, 16),
              child: SegmentedButton<String>(
                style: SegmentedButton.styleFrom(
                  backgroundColor: const Color(0xFF1A1C1E),
                  foregroundColor: Colors.white54,
                  selectedForegroundColor: Colors.white,
                  selectedBackgroundColor: Colors.blueAccent.withOpacity(0.25),
                  side: const BorderSide(color: Color(0xFF2C2F32)),
                  textStyle: const TextStyle(fontSize: 12),
                ),
                segments: const [
                  ButtonSegment(
                    value: 'system',
                    label: Text('System'),
                    icon: Icon(Icons.brightness_auto_rounded, size: 15),
