                  ButtonSegment(
                    value: 'dark',
                    label: Text('Dark'),
                    icon: Icon(Icons.dark_mode_rounded, size: 15),
                  ),
                  ButtonSegment(
                    value: 'light',
                    label: Text('Light'),
                    icon: Icon(Icons.light_mode_rounded, size: 15),
                  ),
                ],
                selected: {_themeMode},
                onSelectionChanged: (s) {
                  setState(() => _themeMode = s.first);
                  widget.onThemeChange?.call(_themeMode == 'light');
                  _saveWorkspace();
                },
              ),
            ),
          ],
        ),
        // ── Language & Region ─────────────────────────────────────────────
        _settingsCard(
          label: 'Language & Region',
          expanded: _showWorkspaceAppearance,
          onTap: () => setState(
            () => _showWorkspaceAppearance = !_showWorkspaceAppearance,
          ),
