  Widget _taskFeedback(Task task) => Material(
    color: Colors.transparent,
    child: Container(
      padding: const EdgeInsets.all(8),
      decoration: BoxDecoration(
        color: Colors.blueAccent,
        borderRadius: BorderRadius.circular(4),
      ),
      child: Text(
        task.title,
        style: const TextStyle(color: Colors.white, fontSize: 12),
      ),
    ),
  );

  Widget _taskCardUI(Task task, {bool isDragging = false}) {
    final effectiveProperties = task.visibleProperties.where((prop) {
      if (_showDueDateOnCards && prop == 'Planned at') return false;
      return true;
    }).toList();

    final bool isShiftHeld = HardwareKeyboard.instance.isShiftPressed;
    // Resize mode activates whenever the pointer is over this card AND Shift is held.
    // No click required — hover is enough.
    final bool isCtrlPressed =
        isShiftHeld && (_hoveredTaskId == task.id || _isResizingCard);

    final Color? pColor = _projectColors[task.projectId];
    final double borderWidth = pColor != null ? 2.0 : 1.0;
    final Color borderColor = isDragging
        ? Colors.blueAccent
        : (pColor ?? Colors.white10);

    String displayDate = "Not scheduled";
    String displayTime = "";
    bool hasTimeStr = false;

    if (task.dueDay != null) {
      final parsed = DateTime.tryParse(task.dueDay!);
      if (parsed != null) {
        displayDate =
            "${parsed.year}-${parsed.month.toString().padLeft(2, '0')}-${parsed.day.toString().padLeft(2, '0')}";
      } else if (task.dueDay!.contains(' ')) {
        displayDate = task.dueDay!.split(' ').first;
      } else {
        displayDate = task.dueDay!;
      }
    }

    if (task.plannedAt != null && task.plannedAt! > 0) {
      final dt = DateTime.fromMillisecondsSinceEpoch(task.plannedAt!).toLocal();
      displayTime =
          "${dt.hour.toString().padLeft(2, '0')}:${dt.minute.toString().padLeft(2, '0')}";
      hasTimeStr = true;
    } else if (task.dueDay != null && task.dueDay!.contains('T')) {
      final dt = DateTime.tryParse(task.dueDay!);
      if (dt != null) {
        displayTime =
            "${dt.hour.toString().padLeft(2, '0')}:${dt.minute.toString().padLeft(2, '0')}";
        hasTimeStr = true;
      }
    } else if (task.dueDay != null && task.dueDay!.contains(' ')) {
      displayTime = task.dueDay!.split(' ').skip(1).join(' ');
      hasTimeStr = true;
    }

    return Material(
      type: MaterialType.transparency,
      child: Stack(
        clipBehavior: Clip.none,
        children: [
          GestureDetector(
            onSecondaryTapDown: (details) =>
                _showContextMenu(context, details.globalPosition, task),
            child: Container(
              width: task.cardWidth,
              height: task.isExpanded ? task.cardHeight : null,
              decoration: BoxDecoration(
                color: const Color(0xFF2A2A2A),
                borderRadius: BorderRadius.circular(8),
                border: Border.all(color: borderColor, width: borderWidth),
                boxShadow: [
                  BoxShadow(
                    color: Colors.black.withOpacity(0.3),
                    blurRadius: 8,
                    offset: const Offset(0, 4),
                  ),
                ],
              ),
              child: Column(
                mainAxisSize: MainAxisSize.min,
                crossAxisAlignment: CrossAxisAlignment.start,
                children: [
                  // CARD HEADER WITH CONNECTION NODES
                  StatefulBuilder(
                    builder: (context, setHeaderState) {
                      bool isHovered = false;
                      Offset? localHoverPos;

                      // Calculate header dimensions
                      double headerHeight =
                          46.0 +
                          (_showIdOnCards ? 14.0 : 0) +
                          (_showProjectName ? 14.0 : 0) +
                          (_showDueDateOnCards ? 14.0 : 0) +
                          ((_showDueDateOnCards && hasTimeStr) ? 14.0 : 0);

                      double fullHeight = task.isExpanded
                          ? task.cardHeight
                          : headerHeight + (borderWidth * 2);

                      double snapLimitY = headerHeight + (borderWidth * 2);

                      // Calculates if the pointer is within the plug-zone band of any edge
                      bool isNearBorder(Offset pos) {
                        double w = task.cardWidth;
                        return [
                              pos.dy,
                              snapLimitY - pos.dy,
                              pos.dx,
                              w - pos.dx,
                            ].reduce(min) <=
                            _plugZoneThickness;
                      }

                      Offset snapToBorder(Offset pos) {
                        double w = task.cardWidth;
                        double dt = pos.dy,
                            db = snapLimitY - pos.dy,
                            dl = pos.dx,
                            dr = w - pos.dx;
                        double m = [dt, db, dl, dr].reduce(min);
                        if (m == dt) return Offset(pos.dx.clamp(0.0, w), 0);
                        if (m == db)
                          return Offset(pos.dx.clamp(0.0, w), snapLimitY);
                        if (m == dl)
                          return Offset(0, pos.dy.clamp(0.0, snapLimitY));
                        return Offset(w, pos.dy.clamp(0.0, snapLimitY));
                      }

                      return MouseRegion(
                        onEnter: (e) => setHeaderState(() {
                          isHovered = true;
                          localHoverPos = e.localPosition;
                        }),
                        onHover: (e) => setHeaderState(
                          () => localHoverPos = e.localPosition,
                        ),
                        onExit: (e) => setHeaderState(() => isHovered = false),
                        child: GestureDetector(
                          behavior: HitTestBehavior.opaque,
                          onTapUp: (details) {
                            // If clicking the inner region, focus the card (highlight only)
                            if (!isNearBorder(details.localPosition)) {
                              setState(() {
                                _selectedCanvasTaskId = task.id;
                                _selectedTask = task;
                                // Note: We do NOT set _showDetails = true here,
                                // so the sidebar won't open, only the highlight appears.
                              });
                              return;
                            }

                            final snapPos = snapToBorder(details.localPosition);
                            if (_connectingSourceId == null) {
                              setState(() {
                                _connectingSourceId = task.id;
                                _connectingSourceLocalPos = snapPos;
                              });
                            } else if (_connectingSourceId != task.id) {
                              if (_canConnect(_connectingSourceId!, task.id)) {
                                setState(() {
                                  _taskRelations.add(
                                    TaskRelation(
                                      sourceId: _connectingSourceId!,
                                      targetId: task.id,
                                      sourceLocalPos:
                                          _connectingSourceLocalPos!,
                                      targetLocalPos: snapPos,
                                      arrowSize: _defaultArrowSize,
                                    ),
                                  );
                                  _connectingSourceId = null;
                                  _connectingSourceLocalPos = null;
                                  _currentCursorLocalPos = null;
                                });
                              } else {
                                setState(() {
                                  _connectingSourceId = null;
                                  _connectingSourceLocalPos = null;
                                  _currentCursorLocalPos = null;
                                });
                                ScaffoldMessenger.of(context).showSnackBar(
                                  const SnackBar(
                                    content: Text(
                                      'Connection blocked: Path already exists.',
                                    ),
                                    duration: Duration(seconds: 2),
                                  ),
                                );
                              }
                            } else {
                              setState(() {
                                _connectingSourceId = null;
                                _connectingSourceLocalPos = null;
                                _currentCursorLocalPos = null;
                              });
                            }
                          },
                          child: Stack(
                            clipBehavior: Clip.none,
                            children: [
                              Container(
                                height: headerHeight,
                                padding: const EdgeInsets.symmetric(
                                  horizontal: 8.0,
                                  vertical: 6.0,
                                ),
                                // Tint header background with project color
                                decoration: BoxDecoration(
                                  color: pColor != null
                                      ? pColor.withOpacity(0.15)
                                      : Colors.transparent,
                                  borderRadius: const BorderRadius.vertical(
                                    top: Radius.circular(7),
                                  ),
                                ),
                                child: Row(
                                  children: [
                                    // ── STATUS INDICATOR ──────────────────────────────────
                                    // Left-click the icon to pick a status.
                                    // Entire widget to copy/replace as needed:
                                    PopupMenuButton<TaskStatus>(
                                      padding: EdgeInsets.zero,
                                      color: const Color(0xFF2A2A2A),
                                      tooltip: 'Change status',
                                      offset: const Offset(0, 28),
                                      onSelected: (s) => setState(() {
                                        task.status = s;
                                        task.isDone = s == TaskStatus.done;
                                      }),
                                      itemBuilder: (_) => TaskStatus.values
                                          .map(
                                            (s) => PopupMenuItem<TaskStatus>(
                                              value: s,
                                              height: 36,
                                              padding:
                                                  const EdgeInsets.symmetric(
                                                    horizontal: 12,
                                                  ),
                                              child: SizedBox(
                                                width: 160,
                                                child: Row(
                                                  mainAxisSize:
                                                      MainAxisSize.max,
                                                  children: [
                                                    Icon(
                                                      s.icon,
                                                      size: 16,
                                                      color: s.color,
                                                    ),
                                                    const SizedBox(width: 8),
                                                    Expanded(
                                                      child: Text(
                                                        s.label,
                                                        style: const TextStyle(
                                                          color: Colors.white,
                                                          fontSize: 13,
                                                        ),
                                                      ),
                                                    ),
                                                    if (task.status == s)
                                                      const Icon(
                                                        Icons.check,
                                                        size: 14,
                                                        color: Colors.white38,
                                                      ),
                                                  ],
                                                ),
                                              ),
                                            ),
                                          )
                                          .toList(),
                                      child: SizedBox(
                                        width: 32,
                                        height: 32,
                                        child: Center(
                                          child: Icon(
                                            task.status.icon,
                                            size: 22,
                                            color: task.status.color,
                                          ),
                                        ),
                                      ),
                                    ),
                                    // ── END STATUS INDICATOR ──────────────────────────────
                                    const SizedBox(width: 4),
                                    Expanded(
                                      child: Column(
                                        crossAxisAlignment:
                                            CrossAxisAlignment.start,
                                        mainAxisAlignment:
                                            MainAxisAlignment.center,
                                        children: [
                                          if (_showProjectName)
                                            Padding(
                                              padding: const EdgeInsets.only(
                                                bottom: 2,
                                              ),
                                              child: Text(
                                                (task.projectId ==
                                                            'INBOX_PROJECT'
                                                        ? 'Inbox'
                                                        : _projects[task
                                                                      .projectId]
                                                                  ?.title ??
                                                              'Inbox')
                                                    .toUpperCase(),
                                                style: TextStyle(
                                                  color:
                                                      pColor ??
                                                      Colors.blueAccent
                                                          .withOpacity(0.8),
                                                  fontSize: 9,
                                                  fontWeight: FontWeight.bold,
                                                  letterSpacing: 0.5,
                                                ),
                                              ),
                                            ),
                                          // Inline title editor – double-tap to edit
                                          _editingTaskId == task.id
                                              ? TextField(
                                                  autofocus: true,
                                                  controller:
                                                      TextEditingController(
                                                          text: task.title,
                                                        )
                                                        ..selection =
                                                            TextSelection.collapsed(
                                                              offset: task
                                                                  .title
                                                                  .length,
                                                            ),
                                                  style: const TextStyle(
                                                    color: Colors.white,
                                                    fontWeight: FontWeight.w600,
                                                    fontSize: 14,
                                                  ),
                                                  decoration:
                                                      const InputDecoration(
                                                        isDense: true,
                                                        contentPadding:
                                                            EdgeInsets.zero,
                                                        border:
                                                            InputBorder.none,
                                                      ),
                                                  onChanged: (v) {
                                                    task.title = v;
                                                    _saveTaskToMeta(task);
                                                  },
                                                  onSubmitted: (_) => setState(
                                                    () => _editingTaskId = null,
                                                  ),
                                                  onTapOutside: (_) => setState(
                                                    () => _editingTaskId = null,
                                                  ),
                                                )
                                              : GestureDetector(
                                                  onDoubleTap: () => setState(
                                                    () => _editingTaskId =
                                                        task.id,
                                                  ),
                                                  child: Text(
                                                    task.title,
                                                    maxLines: 1,
                                                    overflow:
                                                        TextOverflow.ellipsis,
                                                    style: TextStyle(
                                                      color:
                                                          task.status ==
                                                              TaskStatus.done
                                                          ? Colors.white54
                                                          : task.status ==
                                                                TaskStatus
                                                                    .cancelled
                                                          ? Colors.white38
                                                          : Colors.white,
                                                      fontWeight:
                                                          FontWeight.w600,
                                                      fontSize: 14,
                                                      decoration:
                                                          task.status ==
                                                              TaskStatus.done
                                                          ? TextDecoration
                                                                .lineThrough
                                                          : task.status ==
                                                                TaskStatus
                                                                    .cancelled
                                                          ? TextDecoration
                                                                .lineThrough
                                                          : null,
                                                      decorationColor:
                                                          Colors.white38,
                                                    ),
                                                  ),
                                                ),
                                          if (_showIdOnCards)
                                            Padding(
                                              padding: const EdgeInsets.only(
                                                top: 2,
                                              ),
                                              child: Text(
                                                "ID: ${task.id}",
                                                style: TextStyle(
                                                  color: Colors.white
                                                      .withOpacity(0.3),
                                                  fontSize: 9,
                                                  fontFamily: 'monospace',
                                                ),
                                              ),
                                            ),
                                          if (_showDueDateOnCards)
                                            Padding(
                                              padding: const EdgeInsets.only(
                                                top: 2,
                                              ),
                                              child: Row(
                                                children: [
                                                  Icon(
                                                    Icons
                                                        .calendar_today_outlined,
                                                    size: 9,
                                                    color:
                                                        pColor ??
                                                        Colors.blueAccent,
                                                  ),
                                                  const SizedBox(width: 4),
                                                  Text(
                                                    displayDate,
                                                    style: TextStyle(
                                                      color: Colors.white
                                                          .withOpacity(0.5),
                                                      fontSize: 9,
                                                    ),
                                                  ),
                                                ],
                                              ),
                                            ),
                                          // NEW: Render the Time below Due Date
                                          if (_showDueDateOnCards && hasTimeStr)
                                            Padding(
                                              padding: const EdgeInsets.only(
                                                top: 2,
                                              ),
                                              child: Row(
                                                children: [
                                                  Icon(
                                                    Icons.access_time_rounded,
                                                    size: 9,
                                                    color:
                                                        pColor ??
                                                        Colors.blueAccent,
                                                  ),
                                                  const SizedBox(width: 4),
                                                  Text(
                                                    displayTime,
                                                    style: TextStyle(
                                                      color: Colors.white
                                                          .withOpacity(0.5),
                                                      fontSize: 9,
                                                    ),
                                                  ),
                                                ],
                                              ),
                                            ),
                                        ],
                                      ),
                                    ),
                                    IconButton(
                                      icon: Icon(
                                        task.isExpanded
                                            ? Icons.unfold_less
                                            : Icons.unfold_more,
                                        size: 18,
                                        color: Colors.white38,
                                      ),
                                      onPressed: () => setState(() {
                                        final expanding = !task.isExpanded;
                                        _remapPlugsForExpansionChange(
                                          task,
                                          expanding: expanding,
                                        );
                                        task.isExpanded = expanding;
                                      }),
                                      constraints: const BoxConstraints(),
                                      padding: const EdgeInsets.all(4),
                                    ),
                                  ],
                                ),
                              ),

                              if (isHovered &&
                                  localHoverPos != null &&
                                  isNearBorder(
                                    localHoverPos!,
                                  ) && // Only show plug if hovering the edge
                                  (_connectingSourceId == null ||
                                      _connectingSourceId != task.id))
                                Positioned(
                                  left: snapToBorder(localHoverPos!).dx - 5,
                                  top: snapToBorder(localHoverPos!).dy - 5,
                                  child: Container(
                                    width: 10,
                                    height: 10,
                                    decoration: BoxDecoration(
                                      color: _connectingSourceId == null
                                          ? Colors.orangeAccent.withOpacity(0.5)
                                          : Colors.greenAccent,
                                      shape: BoxShape.circle,
                                      border: Border.all(
                                        color: Colors.white,
                                        width: 1.5,
                                      ),
                                    ),
                                  ),
                                ),
                            ],
                          ),
                        ),
                      );
                    },
                  ),

                  // EXPANDED BODY — wrapped in a GestureDetector that
                  // absorbs tap/pan events so clicks inside the details
                  // region never focus the card or start a drag.
                  if (task.isExpanded) ...[
                    const Divider(
                      color: Colors.white38,
                      thickness: 1.5,
                      height: 1.5,
                    ),
                    Expanded(
                      child: GestureDetector(
                        behavior: HitTestBehavior.opaque,
                        onTap: () {}, // absorb — prevent card selection
                        onPanStart: (_) {}, // absorb — prevent card drag
                        child: MouseRegion(
                          onEnter: (_) => _isHoveringCardScrollable = true,
                          onExit: (_) => _isHoveringCardScrollable = false,
                          child: Scrollbar(
                            child: SingleChildScrollView(
                              child: Column(
                                crossAxisAlignment: CrossAxisAlignment.start,
                                children: effectiveProperties.isNotEmpty
                                    ? effectiveProperties
                                          .map(
                                            (prop) =>
                                                _buildResizablePropertyRegion(
                                                  prop,
                                                  task,
                                                ),
                                          )
                                          .toList()
                                    : [
                                        const Padding(
                                          padding: EdgeInsets.all(12),
                                          child: Text(
                                            "No details visible",
                                            style: TextStyle(
                                              color: Colors.white24,
                                              fontSize: 11,
                                            ),
                                          ),
                                        ),
                                      ],
                              ),
                            ),
                          ),
                        ), // close MouseRegion
                      ), // close GestureDetector
                    ),
                  ],
                ],
              ),
            ),
          ),

          // OVERALL CARD RESIZE HANDLERS
          if (task.isExpanded && isCtrlPressed && !isDragging) ...[
            // 1. Right Edge Resize
            Positioned(
              right: -8,
              top: 0,
              bottom: 16,
              child: MouseRegion(
                cursor: SystemMouseCursors.resizeLeftRight,
                child: _ResizeHandle(
                  width: 20,
                  height: null,
                  onDelta: (dx, dy) => setState(() {
                    final oldW = task.cardWidth;
                    task.cardWidth = (task.cardWidth + dx / _scale).clamp(
                      200.0,
                      1000.0,
                    );
                    _adjustAnchorsForWidthChange(task, oldW, task.cardWidth);
                  }),
                  onActiveChanged: (active) =>
                      setState(() => _isResizingCard = active),
                ),
              ),
            ),
            // 2. Bottom Edge Resize
            Positioned(
              left: 0,
              right: 16,
              bottom: -8,
              child: MouseRegion(
                cursor: SystemMouseCursors.resizeUpDown,
                child: _ResizeHandle(
                  width: null,
                  height: 20,
                  onDelta: (dx, dy) => setState(() {
                    task.cardHeight = (task.cardHeight + dy / _scale).clamp(
                      100.0,
                      1000.0,
                    );
                  }),
                  onActiveChanged: (active) =>
                      setState(() => _isResizingCard = active),
                ),
              ),
            ),
            // 3. Corner Resize
            Positioned(
              right: -8,
              bottom: -8,
              child: MouseRegion(
                cursor: SystemMouseCursors.resizeDownRight,
                child: _ResizeHandle(
                  width: 30,
                  height: 30,
                  onDelta: (dx, dy) => setState(() {
                    final oldW = task.cardWidth;
                    task.cardWidth = (task.cardWidth + dx / _scale).clamp(
                      200.0,
                      1000.0,
                    );
                    task.cardHeight = (task.cardHeight + dy / _scale).clamp(
                      100.0,
                      1000.0,
                    );
                    _adjustAnchorsForWidthChange(task, oldW, task.cardWidth);
                  }),
                  onActiveChanged: (active) =>
                      setState(() => _isResizingCard = active),
                ),
              ),
            ),
          ],
        ],
      ),
    );
  }

  // Helper logic to keep plugs attached to the correct border relative to width
  void _adjustAnchorsForWidthChange(
    Task task,
    double oldWidth,
    double newWidth,
  ) {
    if (oldWidth == newWidth) return;

    // Adjust all established relations
    for (var rel in _taskRelations) {
      if (rel.sourceId == task.id) {
        rel.sourceLocalPos = Offset(
          (rel.sourceLocalPos.dx / oldWidth) * newWidth,
          rel.sourceLocalPos.dy,
        );
      }
      if (rel.targetId == task.id) {
        rel.targetLocalPos = Offset(
          (rel.targetLocalPos.dx / oldWidth) * newWidth,
          rel.targetLocalPos.dy,
        );
      }
    }

    // Adjust the active "follower" line if it's currently originating from this task
    if (_connectingSourceId == task.id && _connectingSourceLocalPos != null) {
      _connectingSourceLocalPos = Offset(
        (_connectingSourceLocalPos!.dx / oldWidth) * newWidth,
        _connectingSourceLocalPos!.dy,
      );
    }
  }

  // ── Plug-remap helpers for card expand / collapse ─────────────────────────

  double _computeCardCoreHeight(Task task) {
    final bool hasTimeStr =
        (task.plannedAt != null && task.plannedAt! > 0) ||
        (task.dueDay != null &&
            (task.dueDay!.contains('T') || task.dueDay!.contains(' ')));
    final Color? pColor = _projectColors[task.projectId];
    final double borderWidth = pColor != null ? 2.0 : 1.0;
    return 46.0 +
        (_showIdOnCards ? 14.0 : 0) +
        (_showProjectName ? 14.0 : 0) +
        (_showDueDateOnCards ? 14.0 : 0) +
        ((_showDueDateOnCards && hasTimeStr) ? 14.0 : 0) +
        (borderWidth * 2);
  }

  void _remapPlugsForExpansionChange(Task task, {required bool expanding}) {
    final double coreH = _computeCardCoreHeight(task);
    final double expandedH = task.cardHeight;

    void remapY(Offset pos, void Function(Offset) apply) {
      if (expanding) {
        if ((pos.dy - coreH).abs() < 0.5) apply(Offset(pos.dx, expandedH));
      } else {
        if (pos.dy > coreH - 0.5) apply(Offset(pos.dx, coreH));
      }
    }

    for (final rel in _taskRelations) {
      if (rel.sourceId == task.id)
        remapY(rel.sourceLocalPos, (o) => rel.sourceLocalPos = o);
      if (rel.targetId == task.id)
        remapY(rel.targetLocalPos, (o) => rel.targetLocalPos = o);
    }
    if (_connectingSourceId == task.id && _connectingSourceLocalPos != null)
      remapY(_connectingSourceLocalPos!, (o) => _connectingSourceLocalPos = o);
  }

  /// Delegates to the rich Planner context menu so Inbox, Today, and
  /// project task lists all share the same right-click experience.
  void _showContextMenu(BuildContext context, Offset globalPos, Task task) {
    _showTaskContextMenu(context, task, globalPos);
  }

  // Helper for the Menu Actions (View Details / Reset)
  Widget _buildMenuAction({
    required IconData icon,
    required String label,
    required Color color,
    required VoidCallback onTap,
  }) {
    return InkWell(
      onTap: onTap,
      child: Padding(
        padding: const EdgeInsets.symmetric(horizontal: 12, vertical: 10),
        child: Row(
          children: [
            Icon(icon, size: 18, color: color),
            const SizedBox(width: 10),
            Text(label, style: TextStyle(color: color, fontSize: 12)),
          ],
        ),
      ),
    );
  }

  Widget _buildResizablePropertyRegion(String key, Task task) {
    // Retrieve custom height or default to a reasonable starting height
    double currentHeight = task.propertyHeights[key] ?? 60.0;

    String label = key.toUpperCase();
    String value = "None";

    // Value mapping
    switch (key) {
      case 'SubTasks':
        value = task.subTaskIds.isEmpty
            ? "No subtasks"
            : "${task.subTaskIds.length} items";
        break;
      case 'Planned at':
        value = task.dueDay ?? "Not scheduled";
        break;
      case 'Description':
        value = (task.notes != null && task.notes!.isNotEmpty)
            ? task.notes!
            : "No description provided";
        break;
      case 'Attachment':
        value = task.attachments.isEmpty
            ? "No files"
            : "${task.attachments.length} attachments";
        break;
      case 'Repeat':
        value = task.repeatCfgId != null ? "Recurring Task" : "One-time";
        break;
      case 'Tag':
        value = task.tagIds.isEmpty ? "No tags" : task.tagIds.join(", ");
        break;
    }

    // For SubTasks, build the section header (with toggle) separately
    // from the content, so the toggle button sits inline with the label.
    if (key == 'SubTasks') {
      final showCanvas = _subtaskShowCanvas[task.id] ?? false;
      // Independent height per view mode
      final heightKey = showCanvas ? 'SubTasks_canvas' : 'SubTasks_list';
      final double subtaskHeight =
          task.propertyHeights[heightKey] ?? (showCanvas ? 160.0 : 120.0);
      final subtasks = _allTasks
          .where((t) => task.subTaskIds.any((id) => id.toString() == t.id))
          .toList();

      return Column(
        mainAxisSize: MainAxisSize.min,
        crossAxisAlignment: CrossAxisAlignment.start,
        children: [
          // ── Header row: label + toggle button ──────────────────────────
          Padding(
            padding: const EdgeInsets.fromLTRB(12, 8, 12, 4),
            child: Row(
              children: [
                Expanded(
                  child: Text(
                    'SUBTASKS',
                    style: TextStyle(
                      color: Colors.white.withOpacity(0.3),
                      fontSize: 9,
                      fontWeight: FontWeight.bold,
                      letterSpacing: 0.5,
                    ),
                  ),
                ),
                if (subtasks.isNotEmpty)
                  GestureDetector(
                    onTap: () => setState(
                      () => _subtaskShowCanvas[task.id] = !showCanvas,
                    ),
                    child: Container(
                      padding: const EdgeInsets.symmetric(
                        horizontal: 7,
                        vertical: 3,
                      ),
                      decoration: BoxDecoration(
                        color: showCanvas
                            ? Colors.blueAccent.withOpacity(0.15)
                            : Colors.white.withOpacity(0.06),
                        borderRadius: BorderRadius.circular(4),
                        border: Border.all(
                          color: showCanvas
                              ? Colors.blueAccent.withOpacity(0.5)
                              : Colors.white12,
                        ),
                      ),
                      child: Row(
                        mainAxisSize: MainAxisSize.min,
                        children: [
                          Icon(
                            showCanvas
                                ? Icons.list
                                : Icons.account_tree_outlined,
                            size: 10,
                            color: showCanvas
                                ? Colors.blueAccent
                                : Colors.white38,
                          ),
                          const SizedBox(width: 4),
                          Text(
                            showCanvas ? 'Show List' : 'Show Subcanvas',
                            style: TextStyle(
                              fontSize: 9,
                              fontWeight: FontWeight.bold,
                              letterSpacing: 0.4,
                              color: showCanvas
                                  ? Colors.blueAccent
                                  : Colors.white38,
                            ),
                          ),
                        ],
                      ),
                    ),
                  ),
              ],
            ),
          ),

          // ── Content ────────────────────────────────────────────────────
          Container(
            height: subtaskHeight,
            width: double.infinity,
            padding: const EdgeInsets.fromLTRB(12, 0, 12, 0),
            child: subtasks.isEmpty
                ? const Align(
                    alignment: Alignment.centerLeft,
                    child: Text(
                      'No subtasks',
                      style: TextStyle(color: Colors.white38, fontSize: 12),
                    ),
                  )
                : showCanvas
                ? _SubCanvasWidget(
                    height: subtaskHeight.clamp(80.0, 400.0),
                    parentTask: task,
                    subtasks: subtasks,
                    taskPositions: _taskPositions,
                    onPositionChanged: (id, pos) {
                      setState(() => _taskPositions[id] = pos);
                    },
                    onPromote: (promotedTask, globalPos) {
                      setState(() {
                        task.subTaskIds.remove(promotedTask.id);
                        _saveTaskToMeta(task);
                        if (!_canvasTasks.any((t) => t.id == promotedTask.id)) {
                          promotedTask.visibleProperties = Set.from(
                            _standardVisibleInfos,
                          );
                          _canvasTasks.add(promotedTask);
                        }
                        final box =
                            _canvasKey.currentContext?.findRenderObject()
                                as RenderBox?;
                        if (box != null) {
                          final local = box.globalToLocal(globalPos);
                          _taskPositions[promotedTask.id] =
                              (local - _canvasOffset) / _scale;
                        }
                      });
                    },
                    cardBuilder: (st) => _buildMiniSubtaskCard(st),
                  )
                : Scrollbar(
                    thumbVisibility: true,
                    child: ListView.separated(
                      itemCount: subtasks.length,
                      separatorBuilder: (_, __) =>
                          const Divider(color: Colors.white10, height: 1),
                      itemBuilder: (_, i) {
                        final st = subtasks[i];
                        return Padding(
                          padding: const EdgeInsets.symmetric(vertical: 5),
                          child: Row(
                            children: [
                              Icon(
                                st.status.icon,
                                size: 13,
                                color: st.status.color,
                              ),
                              const SizedBox(width: 8),
                              Expanded(
                                child: Text(
                                  st.title,
                                  style: const TextStyle(
                                    color: Colors.white70,
                                    fontSize: 12,
                                  ),
                                  overflow: TextOverflow.ellipsis,
                                ),
                              ),
                            ],
                          ),
                        );
                      },
                    ),
                  ),
          ),

          // DRAGGABLE WEAK SEPARATOR (SubTasks branch)
          if (subtasks.isNotEmpty && showCanvas)
            Padding(
              padding: const EdgeInsets.fromLTRB(12, 4, 12, 4),
              child: Align(
                alignment: Alignment.centerRight,
                child: TextButton.icon(
                  onPressed: () {
                    final canvasName = '${task.title} - Subcanvas';
                    setState(() {
                      if (!_savedCanvases.any((c) => c['name'] == canvasName)) {
                        final subs = _allTasks
                            .where(
                              (t) => task.subTaskIds.any(
                                (id) => id.toString() == t.id,
                              ),
                            )
                            .toList();
                        final Map<String, Offset> positions = {};
                        double sx = 60;
                        for (final st in subs) {
                          positions[st.id] = Offset(sx, 80);
                          sx += 160;
                        }
                        _savedCanvases.add({'name': canvasName});
                        _canvasStates[canvasName] = {
                          'canvasTasks': List<Task>.from(subs),
                          'taskPositions': Map<String, Offset>.from(positions),
                          'junctions': <JunctionNode>[],
                          'taskRelations': <TaskRelation>{},
                          'scale': 1.0,
                          'canvasOffset': Offset.zero,
                          'bgColor': const Color(0xFF0D0F19),
                        };
                        _canvasColors[canvasName] = const Color(0xFF0D0F19);
                      }
                      _openCanvases.add(canvasName);
                      _switchToCanvas(canvasName);
                    });
                  },
                  icon: const Icon(
                    Icons.fullscreen,
                    size: 14,
                    color: Colors.white54,
                  ),
                  label: const Text(
                    'Open Full Canvas',
                    style: TextStyle(color: Colors.white54, fontSize: 11),
                  ),
                  style: TextButton.styleFrom(
                    backgroundColor: Colors.white.withOpacity(0.05),
                    padding: const EdgeInsets.symmetric(
                      horizontal: 10,
                      vertical: 6,
                    ),
                    minimumSize: Size.zero,
                    tapTargetSize: MaterialTapTargetSize.shrinkWrap,
                  ),
                ),
              ),
            ),
          _buildResizeSeparator(heightKey, task),
        ],
      );
    }

    // ── All other property keys ───────────────────────────────────────────
    return Column(
      mainAxisSize: MainAxisSize.min,
      crossAxisAlignment: CrossAxisAlignment.start,
      children: [
        Container(
          height: currentHeight,
          width: double.infinity,
          padding: const EdgeInsets.fromLTRB(12, 8, 12, 4),
          child: Scrollbar(
            thumbVisibility: true,
            child: SingleChildScrollView(
              child: Column(
                crossAxisAlignment: CrossAxisAlignment.start,
                children: [
                  Text(
                    label,
                    style: TextStyle(
                      color: Colors.white.withOpacity(0.3),
                      fontSize: 9,
                      fontWeight: FontWeight.bold,
                      letterSpacing: 0.5,
                    ),
                  ),
                  const SizedBox(height: 4),
                  Text(
                    value,
                    style: const TextStyle(color: Colors.white, fontSize: 12),
                  ),
                ],
              ),
            ),
          ),
        ),
        _buildResizeSeparator(key, task),
      ],
    );
  }

  Widget _buildResizeSeparator(String key, Task task) {
    return MouseRegion(
      cursor: SystemMouseCursors.resizeUpDown,
      child: _VerticalDragListener(
        onDelta: (dy) => setState(() {
          final newHeight = (task.propertyHeights[key] ?? 60.0) + dy;
          task.propertyHeights[key] = newHeight.clamp(30.0, 500.0);
        }),
        child: Container(
          height: 12,
          alignment: Alignment.center,
          child: Container(height: 1, color: Colors.white10),
        ),
      ),
    );
  }

  Widget _buildMiniSubtaskCard(Task st, {bool isDragging = false}) {
    return Container(
      width: 120,
      padding: const EdgeInsets.symmetric(horizontal: 8, vertical: 6),
      decoration: BoxDecoration(
        color: isDragging
            ? Colors.blueAccent.withOpacity(0.8)
            : const Color(0xFF333333),
        border: Border.all(
          color: isDragging
              ? Colors.blueAccent
              : st.status.color.withOpacity(0.5),
        ),
        borderRadius: BorderRadius.circular(4),
        boxShadow: const [
          BoxShadow(color: Colors.black26, blurRadius: 4, offset: Offset(0, 2)),
        ],
      ),
      child: Column(
        mainAxisSize: MainAxisSize.min,
        crossAxisAlignment: CrossAxisAlignment.start,
        children: [
          Text(
            st.title,
            style: const TextStyle(
              color: Colors.white,
              fontSize: 11,
              fontWeight: FontWeight.bold,
            ),
            maxLines: 1,
            overflow: TextOverflow.ellipsis,
          ),
          const SizedBox(height: 6),
          GestureDetector(
            onTap: () {
              setState(() {
                final statuses = TaskStatus.values;
                final nextIndex =
                    (statuses.indexOf(st.status) + 1) % statuses.length;
                st.status = statuses[nextIndex];
                st.isDone = (st.status == TaskStatus.done);
                _saveTaskToMeta(st);
              });
            },
            child: Row(
              mainAxisSize: MainAxisSize.min,
              children: [
                Icon(st.status.icon, size: 12, color: st.status.color),
                const SizedBox(width: 4),
                Expanded(
                  child: Text(
                    st.status.label,
                    style: TextStyle(color: st.status.color, fontSize: 9),
                    overflow: TextOverflow.ellipsis,
                  ),
                ),
              ],
            ),
          ),
        ],
      ),
    );
  }

  Widget _buildDetailsPanel() {
    if (_selectedTask == null) return const SizedBox.shrink();
    return _TaskDetailsPanel(
      key: ValueKey(_selectedTask!.id),
      task: _selectedTask!,
      onSave: (t) async {
        await _saveTaskToMeta(t);
        _syncRepeatInstances(t);
      },
      onClose: () => setState(() {
        _showDetails = false;
        _notesDetailOpen = false; // 9h: keep notes detail flag in sync
      }),
      projectColors: _projectColors,
      projects: _projects,
      stagingBlocks: _stagingBlocks,
      activeStagingTaskId: _activeStagingTaskId,
      stagingPhaseIndex: _stagingPhaseIndex,
      stagingPhaseStarted: _stagingPhaseStarted,
      executionSessions: _taskSessions[_selectedTask!.id] ?? [],
      allTags: {
        for (final t in _allTasks) ...t.tagIds.map((id) => id.toString()),
      }.toList(),
      allTasks: _allTasks,
      onSubTaskCreated: (sub) => setState(() {
        _allTasks.add(sub);
        _saveTaskToMeta(sub);
      }),
      activeGeneralTaskId: _activeGeneralTaskId,
      generalTimerStartedAt: _generalTimerStartedAt,
      onStartGeneral: _startGeneralTimer,
      onCancelGeneral: _stopGeneralTimer,
      onFocusOverlayGeneral: _activeGeneralTaskId != null
          ? () => _showGeneralOverlay(_activeGeneralTaskId!)
          : null,
      onStartStaging: _selectedTask != null
          ? () => _startTaskStaging(_selectedTask!.id)
          : null,
      onStartFlowtime: _selectedTask != null
          ? () {
              if (_activeStagingTaskId != null) _stopTaskStaging();
              if (_activeGeneralTaskId != null) _stopGeneralTimer();
              _startFlowtimeTimer(_selectedTask!.id);
            }
          : null,
      onRepeatChanged: (t) {
        if (t.repeatParentId != null) {
          _propagateRepeatFromInstance(t);
        } else {
          _propagateRepeat(t);
        }
      },
      onPropagateScoped: _propagateScopedRepeat,
      onApplyForward: _applyForwardFromInstance,
      onApplyScoped: _applyFromParentScoped,
      onOpenTaskNote: (noteId) => setState(() {
        _isNotesView = true;
        _isTasksView = false;
        _isSettingsView = false;
        _notesNavSection = 'editor';
        _activeNoteId = noteId;
        if (!_openNoteTabs.contains(noteId)) _openNoteTabs.add(noteId);
      }),
    );
  }

  Widget _buildDetailRow(IconData icon, String label, String value) {
    return Padding(
      padding: const EdgeInsets.only(bottom: 16),
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.start,
        children: [
          Row(
            children: [
              Icon(icon, size: 14, color: Colors.white24),
              const SizedBox(width: 6),
              Text(
                label,
                style: const TextStyle(
                  color: Colors.white38,
                  fontSize: 11,
                  fontWeight: FontWeight.bold,
                ),
              ),
            ],
          ),
          Padding(
            padding: const EdgeInsets.only(left: 20, top: 3),
            child: Text(
              value,
              style: const TextStyle(color: Colors.white54, fontSize: 12),
            ),
          ),
        ],
      ),
    );
  }

  Widget _buildDetailsHeader() => Container(
    padding: const EdgeInsets.fromLTRB(20, 48, 12, 20),
    child: Row(
      children: [
        Expanded(
          child: Text(
            _selectedTask!.title,
            style: const TextStyle(
              color: Colors.white,
              fontWeight: FontWeight.bold,
            ),
          ),
        ),
        IconButton(
          icon: const Icon(Icons.close, color: Colors.white38),
          onPressed: () => setState(() => _showDetails = false),
        ),
      ],
    ),
  );

  Widget _detailButton(IconData icon, String label) => ListTile(
    leading: Icon(icon, color: Colors.blueAccent, size: 20),
    title: Text(
      label,
      style: const TextStyle(color: Colors.white70, fontSize: 14),
    ),
  );

  Widget _buildSidebarHeader() {
    return Column(
      mainAxisSize: MainAxisSize.min,
      children: [
        // Horizontal separator at the top of the footer
        const Divider(color: Colors.white10, height: 1, thickness: 1),

        Container(
          padding: const EdgeInsets.fromLTRB(12, 8, 8, 8),
          child: Row(
            children: [
              // 1. Circular Image/Icon (Clickable to go to Settings)
              GestureDetector(
                onTap: () => setState(() => _isSettingsView = true),
                child: CircleAvatar(
                  radius: 14,
                  backgroundColor: Colors.blueAccent.withOpacity(0.2),
                  backgroundImage: _workspaceImagePath.isNotEmpty
                      ? FileImage(File(_workspaceImagePath))
                      : null,
                  child: _workspaceImagePath.isEmpty
                      ? const Icon(
                          Icons.work,
                          color: Colors.blueAccent,
                          size: 14,
                        )
                      : null,
                ),
              ),
              const SizedBox(width: 12),

              // 2. Editable Workspace Name
              Expanded(
                child: TextField(
                  controller: _workspaceId.isEmpty
                      ? (TextEditingController(text: 'NO WORKSPACE'))
                      : _workspaceNameController,
                  readOnly: _workspaceId.isEmpty,
                  cursorColor: Colors.blueAccent,
                  style: TextStyle(
                    color: _workspaceId.isEmpty ? Colors.white24 : Colors.white,
                    fontWeight: FontWeight.w900,
                    fontSize: 12,
                    letterSpacing: 1.1,
                  ),
                  decoration: const InputDecoration(
                    isDense: true,
                    contentPadding: EdgeInsets.symmetric(vertical: 8),
                    border: InputBorder.none,
                    hintText: "WORKSPACE",
                    hintStyle: TextStyle(color: Colors.white24),
                  ),
                  onChanged: _workspaceId.isEmpty
                      ? null
                      : (val) {
                          setState(() {
                            _workspaceName = val;
                            // Keep the registry entry in sync so the switcher
                            // shows the updated name immediately.
                            for (final w in _savedWorkspaces) {
                              if (w['id'] == _workspaceId) {
                                w['name'] = val;
                                break;
                              }
                            }
                          });
                          _saveWorkspace();
                          _saveGeneral();
                        },
                ),
              ),

              // 4. Settings/Back Button
              IconButton(
                icon: Icon(
                  _isSettingsView ? Icons.arrow_back : Icons.settings,
                  color: _isSettingsView
                      ? Colors.blueAccent
                      : (_workspaceId.isEmpty
                            ? Colors.white12
                            : Colors.white38),
                  size: 18,
                ),
                tooltip: _isSettingsView
                    ? "Back to Workspace"
                    : (_workspaceId.isEmpty
                          ? "No workspace active"
                          : "Settings"),
                onPressed: _workspaceId.isEmpty && !_isSettingsView
                    ? null
                    : () => setState(() => _isSettingsView = !_isSettingsView),
                constraints: const BoxConstraints(),
                padding: const EdgeInsets.all(8),
              ),
            ],
          ),
        ),
      ],
    );
  }

  Widget _buildDragHandle() {
    return _SidebarResizeHandle(
      onDrag: (dx) => setState(() {
        _sidebarWidth = (_sidebarWidth + dx).clamp(80.0, 520.0);
        if (_sidebarWidth <= 90) {
          _isVisible = false;
          _sidebarWidth = 260; // reset for next expand
        }
      }),
      onDoubleTap: () => setState(() => _isVisible = !_isVisible),
    );
  }
} // end of _ResizableScreenState

// ─────────────────────────────────────────────────────────────────────────────
// _ProjectSettingsView  –  Project settings as a full page inside the Tasks tab
// ─────────────────────────────────────────────────────────────────────────────

class _ProjectSettingsView extends StatefulWidget {
  final String projectId;
  final Project project;
  final Color initialColor;
  final String initialIcon;
  final bool initialBacklogEnabled;
  final bool initialHiddenFromMenu;
  final void Function({
    required String newTitle,
    required String newIcon,
    required Color newColor,
    required bool backlogEnabled,
    required bool hiddenFromMenu,
  })
  onApply;
  final void Function(Color initial, void Function(Color) onPicked)
  onShowColorPicker;
  final VoidCallback onBack;

  const _ProjectSettingsView({
    super.key,
    required this.projectId,
    required this.project,
    required this.initialColor,
    required this.initialIcon,
    required this.initialBacklogEnabled,
    required this.initialHiddenFromMenu,
    required this.onApply,
    required this.onShowColorPicker,
    required this.onBack,
  });

  @override
  State<_ProjectSettingsView> createState() => _ProjectSettingsViewState();
}

class _ProjectSettingsViewState extends State<_ProjectSettingsView> {
  late TextEditingController _nameCtrl;
  late TextEditingController _iconCtrl;
  late Color _color;
  late bool _backlogEnabled;
  late bool _hiddenFromMenu;

  bool _basicExpanded = true;
  bool _themeExpanded = true;

  static const _bg = Color(0xFF1A1C1E);
  static const _cardBg = Color(0xFF1E2124);
  static const _border = Color(0xFF2A2D30);
  // Accent tracks the project color live as the user adjusts it
  Color get _accent => ensureAccentVisible(_color);

  @override
  void initState() {
    super.initState();
    _nameCtrl = TextEditingController(text: widget.project.title);
    _iconCtrl = TextEditingController(text: widget.initialIcon);
    _iconCtrl.addListener(() => setState(() {}));
    _color = widget.initialColor;
    _backlogEnabled = widget.initialBacklogEnabled;
    _hiddenFromMenu = widget.initialHiddenFromMenu;
  }

  @override
  void dispose() {
    _nameCtrl.dispose();
    _iconCtrl.dispose();
    super.dispose();
  }

  Widget _sectionHeader(
    String label,
    IconData icon,
    bool expanded,
    VoidCallback onTap,
  ) {
    return GestureDetector(
      onTap: onTap,
      child: Container(
        padding: const EdgeInsets.symmetric(horizontal: 14, vertical: 10),
        decoration: BoxDecoration(
          color: expanded ? _accent.withOpacity(0.05) : Colors.transparent,
          border: Border(
            left: BorderSide(
              color: expanded ? _accent.withOpacity(0.6) : Colors.transparent,
              width: 2,
            ),
          ),
        ),
        child: Row(
          children: [
            Icon(icon, size: 14, color: expanded ? _accent : Colors.white38),
            const SizedBox(width: 8),
            Text(
              label.toUpperCase(),
              style: TextStyle(
                fontSize: 10,
                fontWeight: FontWeight.w700,
                letterSpacing: 1.2,
                color: expanded ? _accent.withOpacity(0.9) : Colors.white38,
              ),
            ),
            const Spacer(),
            AnimatedRotation(
              turns: expanded ? 0.5 : 0,
              duration: const Duration(milliseconds: 150),
              child: const Icon(
                Icons.keyboard_arrow_down_rounded,
                size: 14,
                color: Colors.white24,
              ),
            ),
          ],
        ),
      ),
    );
  }

  Widget _settingsRow(Widget leading, Widget trailing) => Container(
    margin: const EdgeInsets.only(bottom: 1),
    padding: const EdgeInsets.symmetric(horizontal: 14, vertical: 10),
    decoration: BoxDecoration(
      color: _bg,
      border: Border(bottom: BorderSide(color: _border)),
    ),
    child: Row(
      children: [
        Expanded(child: leading),
        trailing,
      ],
    ),
  );

  Widget _toggleRow(String label, bool value, ValueChanged<bool> onChanged) =>
      _settingsRow(
        Text(
          label,
          style: const TextStyle(color: Colors.white70, fontSize: 12),
        ),
        Transform.scale(
          scale: 0.8,
          child: Switch(
            value: value,
            onChanged: onChanged,
            activeColor: _accent,
            inactiveTrackColor: Colors.white12,
            trackOutlineColor: WidgetStateProperty.all(Colors.transparent),
          ),
        ),
      );

  @override
  Widget build(BuildContext context) {
    return Container(
      color: _bg,
      child: Center(
        child: ConstrainedBox(
          constraints: const BoxConstraints(maxWidth: 640),
          child: ListView(
            padding: const EdgeInsets.fromLTRB(24, 32, 24, 48),
            children: [
              // ── Page header ────────────────────────────────────────────
              Padding(
                padding: const EdgeInsets.only(bottom: 24),
                child: Column(
                  crossAxisAlignment: CrossAxisAlignment.start,
                  children: [
                    Row(
                      children: [
                        // Gear icon on the left
                        Icon(
                          Icons.settings_outlined,
                          size: 18,
                          color: _accent.withOpacity(0.7),
                        ),
                        const SizedBox(width: 10),
                        // "PROJECT SETTINGS" title
                        const Text(
                          'PROJECT SETTINGS',
                          style: TextStyle(
                            color: Colors.white,
                            fontSize: 16,
                            fontWeight: FontWeight.w700,
                            letterSpacing: 1.5,
                          ),
                        ),
                      ],
                    ),
                    const SizedBox(height: 8),
                    // Project icon + project name on the same line
                    Row(
                      children: [
                        Container(
                          width: 18,
                          height: 18,
                          decoration: BoxDecoration(
                            color: _color.withOpacity(0.2),
                            borderRadius: BorderRadius.circular(4),
                          ),
                          child: _iconCtrl.text.trim().isNotEmpty
                              ? Center(
                                  child: Text(
                                    _iconCtrl.text.trim(),
                                    style: const TextStyle(
                                      fontSize: 12,
                                      fontFamilyFallback: [
                                        'NotoColorEmoji',
                                        'Apple Color Emoji',
                                        'Segoe UI Emoji',
                                      ],
                                    ),
                                  ),
                                )
                              : Icon(
                                  Icons.folder_outlined,
                                  size: 11,
                                  color: _color,
                                ),
                        ),
                        const SizedBox(width: 6),
                        Text(
                          widget.project.title,
                          style: TextStyle(
                            fontSize: 12,
                            color: Colors.white.withOpacity(0.4),
                          ),
                        ),
                      ],
                    ),
                    const SizedBox(height: 20),
                    Container(height: 1, color: Colors.white.withOpacity(0.06)),
                  ],
                ),
              ),

              // ── Card ───────────────────────────────────────────────────
              Container(
                decoration: BoxDecoration(
                  color: _cardBg,
                  borderRadius: BorderRadius.circular(10),
                  border: Border.all(color: _border),
                ),
                clipBehavior: Clip.hardEdge,
                child: Column(
                  crossAxisAlignment: CrossAxisAlignment.stretch,
                  children: [
                    // SECTION: Basic Settings
                    _sectionHeader(
                      'Basic Settings',
                      Icons.settings_outlined,
                      _basicExpanded,
                      () => setState(() => _basicExpanded = !_basicExpanded),
                    ),
                    if (_basicExpanded) ...[
                      Container(
                        decoration: BoxDecoration(
                          color: _bg,
                          border: Border(
                            top: BorderSide(color: _border),
                            bottom: BorderSide(color: _border),
                          ),
                        ),
                        child: TextField(
                          controller: _nameCtrl,
                          style: const TextStyle(
                            color: Colors.white,
                            fontSize: 13,
                          ),
                          decoration: InputDecoration(
                            labelText: 'Project Name *',
                            labelStyle: TextStyle(
                              color: Colors.white.withOpacity(0.35),
                              fontSize: 11,
                            ),
                            contentPadding: const EdgeInsets.fromLTRB(
                              14,
                              20,
                              14,
                              8,
                            ),
                            border: InputBorder.none,
                          ),
                        ),
                      ),
                      Container(
                        decoration: BoxDecoration(
                          color: _bg,
                          border: Border(bottom: BorderSide(color: _border)),
                        ),
                        child: Column(
                          crossAxisAlignment: CrossAxisAlignment.start,
                          children: [
                            Row(
                              crossAxisAlignment: CrossAxisAlignment.center,
                              children: [
                                Expanded(
                                  child: TextField(
                                    controller: _iconCtrl,
                                    onChanged: (v) {
                                      final trimmed = v.characters.isEmpty
                                          ? ''
                                          : v.characters.first;
                                      if (trimmed != v) {
                                        _iconCtrl.value = TextEditingValue(
                                          text: trimmed,
                                          selection: TextSelection.collapsed(
                                            offset: trimmed.length,
                                          ),
                                        );
                                      }
                                      setState(() {});
                                    },
                                    style: const TextStyle(
                                      color: Colors.white,
                                      fontSize: 13,
                                      fontFamilyFallback: [
                                        'NotoColorEmoji',
                                        'Apple Color Emoji',
                                        'Segoe UI Emoji',
                                      ],
                                    ),
                                    decoration: InputDecoration(
                                      labelText: 'Icon',
                                      labelStyle: TextStyle(
                                        color: Colors.white.withOpacity(0.35),
                                        fontSize: 11,
                                      ),
                                      contentPadding: const EdgeInsets.fromLTRB(
                                        14,
                                        20,
                                        14,
                                        8,
