// ─────────────────────────────────────────────────────────────────────────────
// _QuickHistoryView  –  collapsible Year > Month > Week > Day session log
// ─────────────────────────────────────────────────────────────────────────────

class _QuickHistoryView extends StatefulWidget {
  final List<Task> tasks;
  final Map<String, List<_ExecutionSession>> taskSessions;
  final Map<String, Color> projectColors;
  final Color accentColor;

  const _QuickHistoryView({
    required this.tasks,
    required this.taskSessions,
    required this.projectColors,
    this.accentColor = const Color(0xFF4FC3F7),
  });

  @override
  State<_QuickHistoryView> createState() => _QuickHistoryViewState();
}

class _QuickHistoryViewState extends State<_QuickHistoryView> {
  final Set<String> _expanded = {};

  Color get _accent => ensureAccentVisible(widget.accentColor);
  static const _bg = Color(0xFF181A1B);

  static const _monthNames = [
    'January',
    'February',
    'March',
    'April',
    'May',
    'June',
    'July',
    'August',
    'September',
    'October',
    'November',
    'December',
  ];
  static const _monthShort = [
    'Jan',
    'Feb',
    'Mar',
    'Apr',
    'May',
    'Jun',
    'Jul',
    'Aug',
    'Sep',
    'Oct',
    'Nov',
    'Dec',
  ];
  static const _dayShort = ['Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat', 'Sun'];

  static const _yearColors = [
    Color(0xFF4FC3F7),
    Color(0xFFAB47BC),
    Color(0xFF26A69A),
    Color(0xFFEF5350),
    Color(0xFFFFA726),
  ];

  int _isoWeek(DateTime d) {
    final jan4 = DateTime(d.year, 1, 4);
    final startOfWeek1 = jan4.subtract(Duration(days: jan4.weekday - 1));
    return ((d.difference(startOfWeek1).inDays) ~/ 7) + 1;
  }

  DateTime _dayKey(DateTime d) => DateTime(d.year, d.month, d.day);

  String _fmt(Duration dur) {
    final h = dur.inHours;
    final m = dur.inMinutes % 60;
    final s = dur.inSeconds % 60;
    if (h > 0) return '${h}h ${m.toString().padLeft(2, '0')}m';
    if (m > 0) return '${m}m ${s.toString().padLeft(2, '0')}s';
    return '${s}s';
  }

  String _fmtHms(DateTime d) {
    String p(int n) => n.toString().padLeft(2, '0');
    return '${p(d.hour)}:${p(d.minute)}:${p(d.second)}';
  }

  void _toggle(String key) => setState(
    () => _expanded.contains(key) ? _expanded.remove(key) : _expanded.add(key),
  );

  bool _isExpanded(String key) => _expanded.contains(key);

  @override
  Widget build(BuildContext context) {
    // ── Build tree: year > month > weekNum > dayKey > sessions ──────────
    final Map<
      int,
      Map<
        int,
        Map<int, Map<DateTime, List<({Task task, _ExecutionSession session})>>>
      >
    >
    tree = {};

    for (final task in widget.tasks) {
      for (final s in (widget.taskSessions[task.id] ?? [])) {
        if (s.endTime == null && s.status != _SessionStatus.running) continue;
        final d = s.startTime;
        final dk = _dayKey(d);
        final wk = _isoWeek(d);
        tree
            .putIfAbsent(d.year, () => {})
            .putIfAbsent(d.month, () => {})
            .putIfAbsent(wk, () => {})
            .putIfAbsent(dk, () => [])
            .add((task: task, session: s));
      }
    }

    if (tree.isEmpty) {
      return Container(
        color: _bg,
        child: Center(
          child: Column(
            mainAxisSize: MainAxisSize.min,
            children: [
              Icon(
                Icons.history_rounded,
                size: 48,
                color: Colors.white.withOpacity(0.08),
              ),
              const SizedBox(height: 16),
              Text(
                'No sessions recorded yet',
                style: TextStyle(
                  color: Colors.white.withOpacity(0.25),
                  fontSize: 14,
                ),
              ),
              const SizedBox(height: 6),
              Text(
                'Start a timer on any task to see your history here.',
                style: TextStyle(
                  color: Colors.white.withOpacity(0.13),
                  fontSize: 11,
                ),
              ),
            ],
          ),
        ),
      );
    }

    // ── Summary totals ───────────────────────────────────────────────────
    Duration totalDur = Duration.zero;
    int totalDays = 0;
    final Set<String> totalTasks = {};
    for (final ym in tree.values) {
      for (final wm in ym.values) {
        for (final dm in wm.values) {
          for (final dayEntries in dm.values) {
            totalDays++;
            for (final e in dayEntries) {
              totalTasks.add(e.task.id);
              totalDur += e.session.duration;
            }
          }
        }
      }
    }

    final years = tree.keys.toList()..sort((a, b) => b.compareTo(a));

    return Container(
      color: _bg,
      child: ListView.builder(
        padding: const EdgeInsets.fromLTRB(20, 20, 20, 48),
        itemCount: years.length + 1,
        itemBuilder: (ctx, idx) {
          if (idx == 0)
            return _buildHeader(totalTasks.length, totalDays, totalDur);
          final year = years[idx - 1];
          return _buildYear(year, tree[year]!, idx - 1);
        },
      ),
    );
  }

  // ── Header ────────────────────────────────────────────────────────────
  Widget _buildHeader(int taskCount, int dayCount, Duration totalDur) =>
      Padding(
        padding: const EdgeInsets.only(bottom: 24),
        child: Column(
          crossAxisAlignment: CrossAxisAlignment.start,
          children: [
            Row(
              children: [
                Icon(Icons.history_rounded, size: 18, color: _accent),
                const SizedBox(width: 10),
                const Text(
                  'QUICK HISTORY',
                  style: TextStyle(
                    color: Colors.white,
                    fontSize: 16,
                    fontWeight: FontWeight.w700,
                    letterSpacing: 1.5,
                  ),
                ),
              ],
            ),
            const SizedBox(height: 16),
            Row(
              children: [
                _summaryChip(Icons.task_alt_rounded, '$taskCount', 'tasks'),
                const SizedBox(width: 8),
                _summaryChip(Icons.calendar_today_rounded, '$dayCount', 'days'),
                const SizedBox(width: 8),
                _summaryChip(
                  Icons.timer_rounded,
                  totalDur.inSeconds > 0 ? _fmt(totalDur) : '—',
                  'total',
                ),
              ],
            ),
            const SizedBox(height: 20),
            Container(height: 1, color: Colors.white.withOpacity(0.06)),
          ],
        ),
      );

  Widget _summaryChip(IconData icon, String value, String label) => Expanded(
    child: Container(
      padding: const EdgeInsets.symmetric(vertical: 12, horizontal: 12),
      decoration: BoxDecoration(
        color: Colors.white.withOpacity(0.04),
        borderRadius: BorderRadius.circular(10),
        border: Border.all(color: Colors.white.withOpacity(0.07)),
      ),
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.start,
        children: [
          Icon(icon, size: 13, color: _accent.withOpacity(0.7)),
          const SizedBox(height: 6),
          Text(
            value,
            style: const TextStyle(
              color: Colors.white,
              fontSize: 15,
              fontWeight: FontWeight.w700,
            ),
          ),
          Text(
            label,
            style: TextStyle(
              color: Colors.white.withOpacity(0.35),
              fontSize: 10,
              letterSpacing: 0.3,
            ),
          ),
        ],
      ),
    ),
  );

  // ── Year ──────────────────────────────────────────────────────────────
  Widget _buildYear(
    int year,
    Map<
      int,
      Map<int, Map<DateTime, List<({Task task, _ExecutionSession session})>>>
    >
    monthMap,
    int colorIdx,
  ) {
    final yKey = '$year';
    final open = _isExpanded(yKey);
    final color = _yearColors[colorIdx % _yearColors.length];

    Duration yDur = Duration.zero;
    final Set<String> yTasks = {};
    int yDays = 0;
    for (final wm in monthMap.values) {
      for (final dm in wm.values) {
        for (final dayEntries in dm.values) {
          yDays++;
          for (final e in dayEntries) {
            yTasks.add(e.task.id);
            yDur += e.session.duration;
          }
        }
      }
    }

    final months = monthMap.keys.toList()..sort((a, b) => b.compareTo(a));

    return Padding(
      padding: const EdgeInsets.only(bottom: 8),
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.stretch,
        children: [
          GestureDetector(
            onTap: () => _toggle(yKey),
            child: Container(
              padding: const EdgeInsets.fromLTRB(14, 12, 14, 12),
              decoration: BoxDecoration(
                color: color.withOpacity(0.07),
                borderRadius: BorderRadius.circular(10),
                border: Border.all(color: color.withOpacity(0.2)),
              ),
              child: Row(
                children: [
                  Container(
                    padding: const EdgeInsets.symmetric(
                      horizontal: 10,
                      vertical: 4,
                    ),
                    decoration: BoxDecoration(
                      color: color.withOpacity(0.18),
                      borderRadius: BorderRadius.circular(6),
                    ),
                    child: Text(
                      '$year',
                      style: TextStyle(
                        color: color,
                        fontSize: 18,
                        fontWeight: FontWeight.w800,
                        letterSpacing: 0.5,
                      ),
                    ),
                  ),
                  const SizedBox(width: 14),
                  Expanded(
                    child: Wrap(
                      spacing: 8,
                      runSpacing: 4,
                      children: [
                        _pill('${monthMap.length}mo', color),
                        _pill('$yDays days', color),
                        if (yDur.inSeconds > 0) _pill(_fmt(yDur), color),
                        _pill('${yTasks.length} tasks', color),
                      ],
                    ),
                  ),
                  const SizedBox(width: 8),
                  AnimatedRotation(
                    turns: open ? 0.5 : 0,
                    duration: const Duration(milliseconds: 200),
                    child: Icon(
                      Icons.keyboard_arrow_down_rounded,
                      size: 20,
                      color: color.withOpacity(0.7),
                    ),
                  ),
                ],
              ),
            ),
          ),
          AnimatedCrossFade(
            firstChild: const SizedBox.shrink(),
            secondChild: Padding(
              padding: const EdgeInsets.only(top: 6, left: 12),
              child: Column(
                children: months
                    .map((m) => _buildMonth(year, m, monthMap[m]!, color))
                    .toList(),
              ),
            ),
            crossFadeState: open
                ? CrossFadeState.showSecond
                : CrossFadeState.showFirst,
            duration: const Duration(milliseconds: 200),
          ),
        ],
      ),
    );
  }

  Widget _pill(String text, Color color) => Container(
    padding: const EdgeInsets.symmetric(horizontal: 8, vertical: 3),
    decoration: BoxDecoration(
      color: color.withOpacity(0.1),
      borderRadius: BorderRadius.circular(5),
      border: Border.all(color: color.withOpacity(0.2)),
    ),
    child: Text(
      text,
      style: TextStyle(
        color: color.withOpacity(0.8),
        fontSize: 10,
        fontWeight: FontWeight.w600,
      ),
    ),
  );

  // ── Month ─────────────────────────────────────────────────────────────
  Widget _buildMonth(
    int year,
    int month,
    Map<int, Map<DateTime, List<({Task task, _ExecutionSession session})>>>
    weekMap,
    Color yearColor,
  ) {
    final mKey = '$year-$month';
    final open = _isExpanded(mKey);

    Duration mDur = Duration.zero;
    final Set<String> mTasks = {};
    int mDays = 0;
    for (final dm in weekMap.values) {
      for (final dayEntries in dm.values) {
        mDays++;
        for (final e in dayEntries) {
          mTasks.add(e.task.id);
          mDur += e.session.duration;
        }
      }
    }

    final weeks = weekMap.keys.toList()..sort((a, b) => b.compareTo(a));

    return Padding(
      padding: const EdgeInsets.only(bottom: 4),
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.stretch,
        children: [
          GestureDetector(
            onTap: () => _toggle(mKey),
            child: Container(
              padding: const EdgeInsets.fromLTRB(12, 10, 12, 10),
              decoration: BoxDecoration(
                border: Border(
                  left: BorderSide(color: yearColor.withOpacity(0.4), width: 2),
                ),
                color: Colors.white.withOpacity(0.02),
              ),
              child: Row(
                children: [
                  Expanded(
                    child: Row(
                      children: [
                        Text(
                          _monthNames[month - 1],
                          style: TextStyle(
                            color: Colors.white.withOpacity(0.75),
                            fontSize: 12,
                            fontWeight: FontWeight.w600,
                          ),
                        ),
                        const SizedBox(width: 6),
                        Text(
                          '$year',
                          style: TextStyle(
                            color: Colors.white.withOpacity(0.25),
                            fontSize: 11,
                          ),
                        ),
                        const SizedBox(width: 12),
                        Text(
                          '${mTasks.length} tasks',
                          style: TextStyle(
                            color: Colors.white.withOpacity(0.3),
                            fontSize: 10,
                          ),
                        ),
                        const SizedBox(width: 8),
                        Text(
                          '$mDays days',
                          style: TextStyle(
                            color: Colors.white.withOpacity(0.3),
                            fontSize: 10,
                          ),
                        ),
                        if (mDur.inSeconds > 0) ...[
                          const SizedBox(width: 8),
                          Text(
                            _fmt(mDur),
                            style: TextStyle(
                              color: Colors.white.withOpacity(0.45),
                              fontSize: 10,
                              fontWeight: FontWeight.w600,
                            ),
                          ),
                        ],
                      ],
                    ),
                  ),
                  AnimatedRotation(
                    turns: open ? 0.5 : 0,
                    duration: const Duration(milliseconds: 200),
                    child: Icon(
                      Icons.keyboard_arrow_down_rounded,
                      size: 16,
                      color: Colors.white.withOpacity(0.3),
                    ),
                  ),
                ],
              ),
            ),
          ),
          AnimatedCrossFade(
            firstChild: const SizedBox.shrink(),
            secondChild: Padding(
              padding: const EdgeInsets.only(top: 3, left: 12),
              child: Column(
                children: weeks
                    .map(
                      (w) => _buildWeek(year, month, w, weekMap[w]!, yearColor),
                    )
                    .toList(),
              ),
            ),
            crossFadeState: open
                ? CrossFadeState.showSecond
                : CrossFadeState.showFirst,
            duration: const Duration(milliseconds: 160),
          ),
        ],
      ),
    );
  }

  // ── Week ──────────────────────────────────────────────────────────────
  Widget _buildWeek(
    int year,
    int month,
    int weekNum,
    Map<DateTime, List<({Task task, _ExecutionSession session})>> dayMap,
    Color yearColor,
  ) {
    final wKey = '$year-$month-$weekNum';
    final open = _isExpanded(wKey);

    Duration wDur = Duration.zero;
    final Set<String> wTasks = {};
    for (final dayEntries in dayMap.values) {
      for (final e in dayEntries) {
        wTasks.add(e.task.id);
        wDur += e.session.duration;
      }
    }

    // Build all 7 days of this ISO week
    final jan4 = DateTime(year, 1, 4);
    final startOfWeek1 = jan4.subtract(Duration(days: jan4.weekday - 1));
    final weekMonday = startOfWeek1.add(Duration(days: (weekNum - 1) * 7));
    final weekDates = List.generate(
      7,
      (i) => weekMonday.add(Duration(days: i)),
    );

    final today = DateTime.now();
    final todayKey = DateTime(today.year, today.month, today.day);

    final days = dayMap.keys.toList()..sort((a, b) => b.compareTo(a));

    return Padding(
      padding: const EdgeInsets.only(bottom: 4),
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.stretch,
        children: [
          GestureDetector(
            onTap: () => _toggle(wKey),
            child: Container(
              padding: const EdgeInsets.fromLTRB(12, 9, 12, 9),
              decoration: BoxDecoration(
                color: Colors.white.withOpacity(0.02),
                borderRadius: BorderRadius.circular(8),
                border: Border.all(color: Colors.white.withOpacity(0.05)),
              ),
              child: Row(
                children: [
                  Container(
                    padding: const EdgeInsets.symmetric(
                      horizontal: 7,
                      vertical: 3,
                    ),
                    decoration: BoxDecoration(
                      color: yearColor.withOpacity(0.1),
                      borderRadius: BorderRadius.circular(5),
                      border: Border.all(color: yearColor.withOpacity(0.25)),
                    ),
                    child: Text(
                      'W$weekNum',
                      style: TextStyle(
                        color: yearColor.withOpacity(0.8),
                        fontSize: 10,
                        fontWeight: FontWeight.w700,
                        letterSpacing: 0.5,
                      ),
                    ),
                  ),
                  const SizedBox(width: 10),
                  // 7-day strip
                  ...weekDates.map((wd) {
                    final wdk = DateTime(wd.year, wd.month, wd.day);
                    final hasData = dayMap.containsKey(wdk);
                    final isToday = wdk == todayKey;
                    final isWeekend = wd.weekday >= 6;
                    final labelColor = hasData
                        ? (isToday ? yearColor : Colors.white.withOpacity(0.75))
                        : (isWeekend
                              ? Colors.white.withOpacity(0.24)
                              : Colors.white.withOpacity(0.22));
                    final bgColor = hasData
                        ? yearColor.withOpacity(0.12)
                        : Colors.transparent;

                    Duration dayDur = Duration.zero;
                    if (hasData) {
                      for (final e in dayMap[wdk]!)
                        dayDur += e.session.duration;
                    }
                    final maxSecs = dayMap.values.fold<int>(0, (mx, entries) {
                      final ds = entries.fold<int>(
                        0,
                        (sum, e) => sum + e.session.duration.inSeconds,
                      );
                      return ds > mx ? ds : mx;
                    });
                    final barFill = (maxSecs > 0 && dayDur.inSeconds > 0)
                        ? (dayDur.inSeconds / maxSecs).clamp(0.0, 1.0)
                        : 0.0;

                    return Padding(
                      padding: const EdgeInsets.only(right: 4),
                      child: Column(
                        mainAxisSize: MainAxisSize.min,
                        children: [
                          Text(
                            _dayShort[wd.weekday - 1][0],
                            style: TextStyle(
                              color: labelColor,
                              fontSize: 9,
                              fontWeight: hasData
                                  ? FontWeight.w700
                                  : FontWeight.normal,
                            ),
                          ),
                          const SizedBox(height: 3),
                          Container(
                            width: 22,
                            height: 22,
                            decoration: BoxDecoration(
                              color: bgColor,
                              shape: BoxShape.circle,
                              border: isToday
                                  ? Border.all(
                                      color: yearColor.withOpacity(0.7),
                                      width: 1.5,
                                    )
                                  : null,
                            ),
                            child: Center(
                              child: Text(
                                '${wd.day}',
                                style: TextStyle(
                                  color: labelColor,
                                  fontSize: 10,
                                  fontWeight: hasData
                                      ? FontWeight.w700
                                      : FontWeight.normal,
                                ),
                              ),
                            ),
                          ),
                          const SizedBox(height: 3),
                          Container(
                            width: 22,
                            height: 3,
                            decoration: BoxDecoration(
                              borderRadius: BorderRadius.circular(2),
                              color: Colors.white.withOpacity(0.06),
                            ),
                            child: Align(
                              alignment: Alignment.centerLeft,
                              child: FractionallySizedBox(
                                widthFactor: barFill,
                                child: Container(
                                  decoration: BoxDecoration(
                                    borderRadius: BorderRadius.circular(2),
                                    color: hasData
                                        ? yearColor.withOpacity(0.75)
                                        : Colors.transparent,
                                  ),
                                ),
                              ),
                            ),
                          ),
                        ],
                      ),
                    );
                  }),
                  const Spacer(),
                  if (wTasks.isNotEmpty) ...[
                    Text(
                      '${wTasks.length} tasks',
                      style: TextStyle(
                        color: Colors.white.withOpacity(0.35),
                        fontSize: 10,
                      ),
                    ),
                    const SizedBox(width: 6),
                    Container(
                      width: 1,
                      height: 10,
                      color: Colors.white.withOpacity(0.1),
                    ),
                    const SizedBox(width: 6),
                  ],
                  if (wDur.inSeconds > 0)
                    Text(
                      _fmt(wDur),
                      style: TextStyle(
                        color: Colors.white.withOpacity(0.55),
                        fontSize: 10,
                        fontWeight: FontWeight.w600,
                      ),
                    ),
                  const SizedBox(width: 8),
                  AnimatedRotation(
                    turns: open ? 0.5 : 0,
                    duration: const Duration(milliseconds: 200),
                    child: Icon(
                      Icons.keyboard_arrow_down_rounded,
                      size: 16,
                      color: Colors.white.withOpacity(0.25),
                    ),
                  ),
                ],
              ),
            ),
          ),
          AnimatedCrossFade(
            firstChild: const SizedBox.shrink(),
            secondChild: Padding(
              padding: const EdgeInsets.only(top: 3, left: 14),
              child: Column(
                children: days
                    .map((d) => _buildDay(d, dayMap[d]!, yearColor))
                    .toList(),
              ),
            ),
            crossFadeState: open
                ? CrossFadeState.showSecond
                : CrossFadeState.showFirst,
            duration: const Duration(milliseconds: 160),
          ),
        ],
      ),
    );
  }

  // ── Day ───────────────────────────────────────────────────────────────
  Widget _buildDay(
    DateTime day,
    List<({Task task, _ExecutionSession session})> entries,
    Color yearColor,
  ) {
    final today = DateTime.now();
    final isToday =
        day.year == today.year &&
        day.month == today.month &&
        day.day == today.day;

    const dayNames = ['Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat', 'Sun'];
    const monthShort = [
      'Jan',
      'Feb',
      'Mar',
      'Apr',
      'May',
      'Jun',
      'Jul',
      'Aug',
      'Sep',
      'Oct',
      'Nov',
      'Dec',
    ];
    final dayLabel =
        '${dayNames[day.weekday - 1]}, ${monthShort[day.month - 1]} ${day.day}';

    Duration dayDur = Duration.zero;
    for (final e in entries) dayDur += e.session.duration;

    return Padding(
      padding: const EdgeInsets.only(bottom: 8),
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.stretch,
        children: [
          // Day header row
          Padding(
            padding: const EdgeInsets.only(bottom: 6),
            child: Row(
              children: [
                Container(
                  width: 28,
                  height: 28,
                  decoration: BoxDecoration(
                    shape: BoxShape.circle,
                    color: isToday
                        ? yearColor.withOpacity(0.15)
                        : Colors.white.withOpacity(0.04),
                    border: Border.all(
                      color: isToday
                          ? yearColor.withOpacity(0.5)
                          : Colors.white.withOpacity(0.08),
                    ),
                  ),
                  child: Center(
                    child: Text(
                      '${day.day}',
                      style: TextStyle(
                        color: isToday
                            ? yearColor
                            : Colors.white.withOpacity(0.6),
                        fontSize: 11,
                        fontWeight: FontWeight.w700,
                      ),
                    ),
                  ),
                ),
                const SizedBox(width: 8),
                Text(
                  dayLabel,
                  style: TextStyle(
                    color: Colors.white.withOpacity(isToday ? 0.85 : 0.55),
                    fontSize: 11,
                    fontWeight: FontWeight.w600,
                  ),
                ),
                if (isToday) ...[
                  const SizedBox(width: 6),
                  Container(
                    padding: const EdgeInsets.symmetric(
                      horizontal: 5,
                      vertical: 2,
                    ),
                    decoration: BoxDecoration(
                      color: yearColor.withOpacity(0.15),
                      borderRadius: BorderRadius.circular(4),
                    ),
                    child: Text(
                      'TODAY',
                      style: TextStyle(
                        color: yearColor,
                        fontSize: 8,
                        fontWeight: FontWeight.w800,
                        letterSpacing: 0.5,
                      ),
                    ),
                  ),
                ],
                const Spacer(),
                Text(
                  '${entries.length} sessions',
                  style: TextStyle(
                    color: Colors.white.withOpacity(0.3),
                    fontSize: 10,
                  ),
                ),
                const SizedBox(width: 8),
                if (dayDur.inSeconds > 0)
                  Text(
                    _fmt(dayDur),
                    style: TextStyle(
                      color: Colors.white.withOpacity(0.5),
                      fontSize: 10,
                      fontWeight: FontWeight.w600,
                    ),
                  ),
              ],
            ),
          ),
          // Session cards
          ...entries.map(
            (e) => _buildSessionCard(e.task, e.session, yearColor),
          ),
        ],
      ),
    );
  }

  Widget _buildSessionCard(
    Task task,
    _ExecutionSession session,
    Color yearColor,
  ) {
    final start = session.startTime;
    final end = session.endTime ?? DateTime.now();
    final dur = session.duration;
    final projColor =
        widget.projectColors[task.projectId] ?? const Color(0xFF2A2D31);
    final isDark = projColor.computeLuminance() < 0.2;

    return Container(
      margin: const EdgeInsets.only(bottom: 5),
      padding: const EdgeInsets.symmetric(horizontal: 14, vertical: 10),
      decoration: BoxDecoration(
        color: isDark
            ? Colors.white.withOpacity(0.04)
            : projColor.withOpacity(0.12),
        borderRadius: BorderRadius.circular(8),
        border: Border.all(
          color: isDark
              ? Colors.white.withOpacity(0.07)
              : projColor.withOpacity(0.25),
        ),
      ),
      child: Row(
        children: [
          Expanded(
            child: Text(
              task.title,
              style: TextStyle(
                fontSize: 12,
                color: Colors.white.withOpacity(0.75),
                fontWeight: FontWeight.w400,
              ),
              overflow: TextOverflow.ellipsis,
            ),
          ),
          const SizedBox(width: 12),
          Text(
            '${_fmtHms(start)} – ${_fmtHms(end)}',
            style: TextStyle(
              fontSize: 11,
              color: Colors.white.withOpacity(0.35),
              fontFeatures: const [FontFeature.tabularFigures()],
            ),
          ),
          const SizedBox(width: 10),
          Container(
            padding: const EdgeInsets.symmetric(horizontal: 8, vertical: 3),
            decoration: BoxDecoration(
              color: Colors.white.withOpacity(0.06),
              borderRadius: BorderRadius.circular(6),
            ),
            child: Text(
              _fmt(dur),
              style: const TextStyle(
                fontSize: 10,
                color: Colors.white54,
                fontWeight: FontWeight.w600,
              ),
            ),
          ),
        ],
      ),
    );
  }
}

class _MetricsView extends StatefulWidget {
  final List<Task> tasks;
  final Map<String, List<_ExecutionSession>> taskSessions;
  final String contextLabel;
  final DateTime? projectCreatedAt;
  final Color accentColor;

  const _MetricsView({
    required this.tasks,
    required this.taskSessions,
    required this.contextLabel,
    this.projectCreatedAt,
    this.accentColor = const Color(0xFF4FC3F7),
  });

  @override
  State<_MetricsView> createState() => _MetricsViewState();
}

class _MetricsViewState extends State<_MetricsView> {
  static const _bg = Color(0xFF181A1B);
  Color get _accent => ensureAccentVisible(widget.accentColor);
  static const _cardBg = Color(0xFF1E2124);
  static const _rowEven = Color(0xFF1A1D20);
  static const _rowOdd = Color(0xFF1E2124);
  static const _border = Color(0xFF2A2D30);

  // Date range filter
  DateTime? _from;
  DateTime? _to;

  @override
  void initState() {
    super.initState();
    _resetToDefault();
  }

  void _resetToDefault() {
    // Prefer explicit project creation date; fall back to earliest session.
    DateTime? earliest = widget.projectCreatedAt != null
        ? DateTime(
            widget.projectCreatedAt!.year,
            widget.projectCreatedAt!.month,
            widget.projectCreatedAt!.day,
          )
        : null;

    if (earliest == null) {
      for (final task in widget.tasks) {
        for (final s in (widget.taskSessions[task.id] ?? [])) {
          if (earliest == null || s.startTime.isBefore(earliest)) {
            earliest = DateTime(
              s.startTime.year,
              s.startTime.month,
              s.startTime.day,
            );
          }
        }
      }
    }

    setState(() {
      _from = earliest;
      _to = DateTime.now();
    });
  }

  // ── Formatting helpers ────────────────────────────────────────────────
  String _fmtDur(Duration d) {
    final h = d.inHours;
    final m = d.inMinutes % 60;
    final s = d.inSeconds % 60;
    if (d.inSeconds == 0) return '—';
    if (h > 0) return '${h}h ${m.toString().padLeft(2, '0')}m';
    if (m > 0) return '${m}m ${s.toString().padLeft(2, '0')}s';
    return '${s}s';
  }

  String _fmtDate(DateTime d) =>
      '${d.year}-${d.month.toString().padLeft(2, '0')}-${d.day.toString().padLeft(2, '0')}';

  Future<void> _pickDate(bool isFrom) async {
    final initial = isFrom
        ? (_from ?? DateTime.now())
        : (_to ?? DateTime.now());
    final picked = await showDatePicker(
      context: context,
      initialDate: initial,
      firstDate: DateTime(2020),
      lastDate: DateTime(2040),
      builder: (ctx, child) => Theme(
        data: Theme.of(ctx).copyWith(
          colorScheme: ColorScheme.dark(
            primary: _accent,
            surface: const Color(0xFF1E2124),
          ),
        ),
        child: child!,
      ),
    );
    if (picked == null) return;
    setState(() {
      if (isFrom) {
        _from = DateTime(picked.year, picked.month, picked.day);
      } else {
        _to = DateTime(
          picked.year,
          picked.month,
          picked.day,
          23,
          59,
          59,
        ); // inclusive end
      }
    });
  }

  // ── Compute metrics ───────────────────────────────────────────────────
  _MetricsData _compute() {
    final from = _from;
    final to = _to;

    // Sessions within range
    final List<({Task task, _ExecutionSession session})> entries = [];
    for (final task in widget.tasks) {
      for (final s in (widget.taskSessions[task.id] ?? [])) {
        if (from != null && s.startTime.isBefore(from)) continue;
        if (to != null && s.startTime.isAfter(to)) continue;
        entries.add((task: task, session: s));
      }
    }

    // Total time spent (work time only from sessions with blocks, full duration otherwise)
    Duration totalSpent = Duration.zero;
    Duration totalRest = Duration.zero;
    int totalBreaks = 0;
    for (final e in entries) {
      totalSpent += Duration(milliseconds: e.session.workMs);
      final restMs = e.session.restMs;
      if (restMs > 0) {
        totalRest += Duration(milliseconds: restMs);
        totalBreaks++;
      }
    }

    // Time estimated = sum of durationMinutes for tasks in range
    final tasksInRange = widget.tasks.where((t) {
      if (from == null && to == null) return true;
      // Include task if it has at least one session in range OR its dueDay in range
      final hasSessions = entries.any((e) => e.task.id == t.id);
      return hasSessions;
    }).toSet();

    Duration totalEstimated = Duration.zero;
    for (final t in tasksInRange) {
      totalEstimated += Duration(minutes: t.durationMinutes);
    }

    // Tasks done vs created
    final tasksDone = widget.tasks
        .where((t) => t.isDone || t.status == TaskStatus.done)
        .length;
    final tasksCreated = widget.tasks.length;

    // Days worked (distinct calendar days with at least one session)
    final Set<String> workedDayKeys = {};
    for (final e in entries) {
      final d = e.session.startTime;
      workedDayKeys.add('${d.year}-${d.month}-${d.day}');
    }
    final daysWorked = workedDayKeys.length;

    // Avg tasks per day worked
    final Set<String> taskIdsWorked = entries.map((e) => e.task.id).toSet();
    final avgTasksPerDay = daysWorked > 0
        ? taskIdsWorked.length / daysWorked
        : 0.0;

    // Avg breaks per day
    final avgBreaksPerDay = daysWorked > 0 ? totalBreaks / daysWorked : 0.0;

    // Avg time spent per day
    final avgTimePerDay = daysWorked > 0
        ? totalSpent ~/ daysWorked
        : Duration.zero;

    // Avg time spent per task
    final avgTimePerTask = taskIdsWorked.isNotEmpty
        ? totalSpent ~/ taskIdsWorked.length
        : Duration.zero;

    // Avg time spent per task counting subtasks
    final allSubIds = widget.tasks
        .expand((t) => t.subTaskIds.map((id) => id.toString()))
        .toSet();
    final rootTasksWorked = taskIdsWorked
        .where((id) => !allSubIds.contains(id))
        .length;
    final avgTimePerTaskWithSubs = rootTasksWorked > 0
        ? totalSpent ~/ rootTasksWorked
        : Duration.zero;

    // Avg time on breaks
    final avgTimeOnBreaks = daysWorked > 0
        ? totalRest ~/ daysWorked
        : Duration.zero;

    return _MetricsData(
      totalSpent: totalSpent,
      totalEstimated: totalEstimated,
      tasksDone: tasksDone,
      tasksCreated: tasksCreated,
      daysWorked: daysWorked,
      avgTasksPerDay: avgTasksPerDay,
      avgBreaksPerDay: avgBreaksPerDay,
      avgTimePerDay: avgTimePerDay,
      avgTimePerTask: avgTimePerTask,
      avgTimePerTaskWithSubs: avgTimePerTaskWithSubs,
      avgTimeOnBreaks: avgTimeOnBreaks,
    );
  }

  @override
  Widget build(BuildContext context) {
    final m = _compute();

    final rows = <_MetricRow>[
      _MetricRow('Time Spent', _fmtDur(m.totalSpent)),
      _MetricRow('Time Estimated', _fmtDur(m.totalEstimated)),
      _MetricRow('Tasks (done/created)', '${m.tasksDone} / ${m.tasksCreated}'),
      _MetricRow('Days worked', '${m.daysWorked}'),
      _MetricRow(
        'Avg. tasks per day worked',
        m.daysWorked > 0 ? m.avgTasksPerDay.toStringAsFixed(1) : '—',
      ),
      _MetricRow(
        'Avg. breaks per day',
        m.daysWorked > 0 ? m.avgBreaksPerDay.toStringAsFixed(1) : '—',
      ),
      _MetricRow('Avg. time spent per day', _fmtDur(m.avgTimePerDay)),
      _MetricRow('Avg. time spent per task', _fmtDur(m.avgTimePerTask)),
      _MetricRow(
        'Avg. time spent per task\n(counting subtasks)',
        _fmtDur(m.avgTimePerTaskWithSubs),
      ),
      _MetricRow('Avg. time spent on breaks', _fmtDur(m.avgTimeOnBreaks)),
    ];

    return Container(
      color: _bg,
      child: Center(
        child: ConstrainedBox(
          constraints: const BoxConstraints(maxWidth: 640),
          child: ListView(
            padding: const EdgeInsets.fromLTRB(24, 32, 24, 48),
            children: [
              // ── Header (Worklog-style) ──────────────────────────────
              Padding(
                padding: const EdgeInsets.only(bottom: 24),
                child: Column(
                  crossAxisAlignment: CrossAxisAlignment.start,
                  children: [
                    Row(
                      children: [
                        Icon(Icons.bar_chart_rounded, size: 18, color: _accent),
                        const SizedBox(width: 10),
                        const Text(
                          'METRICS',
                          style: TextStyle(
                            color: Colors.white,
                            fontSize: 16,
                            fontWeight: FontWeight.w700,
                            letterSpacing: 1.5,
                          ),
                        ),
                      ],
                    ),
                    const SizedBox(height: 16),
                    Row(
                      children: [
                        _summaryChip(
                          Icons.timer_rounded,
                          _fmtDur(m.totalSpent),
                          'time spent',
                        ),
                        const SizedBox(width: 8),
                        _summaryChip(
                          Icons.task_alt_rounded,
                          '${m.tasksDone}/${m.tasksCreated}',
                          'tasks done',
                        ),
                        const SizedBox(width: 8),
                        _summaryChip(
                          Icons.calendar_today_rounded,
                          '${m.daysWorked}',
                          'days worked',
                        ),
                      ],
                    ),
                    const SizedBox(height: 20),
                    Container(height: 1, color: Colors.white.withOpacity(0.06)),
                  ],
                ),
              ),

              // ── Date range picker ────────────────────────────────────
              Container(
                padding: const EdgeInsets.symmetric(
                  horizontal: 14,
                  vertical: 10,
                ),
                decoration: BoxDecoration(
                  color: _cardBg,
                  borderRadius: BorderRadius.circular(8),
                  border: Border.all(color: _border),
                ),
                child: Row(
                  children: [
                    const Icon(
                      Icons.date_range_rounded,
                      size: 14,
                      color: Colors.white38,
                    ),
                    const SizedBox(width: 8),
                    _dateChip(
                      _from != null ? _fmtDate(_from!) : 'Start',
                      () => _pickDate(true),
                    ),
                    Padding(
                      padding: const EdgeInsets.symmetric(horizontal: 8),
                      child: Text(
                        '–',
                        style: TextStyle(
                          color: Colors.white.withOpacity(0.3),
                          fontSize: 13,
                        ),
                      ),
                    ),
                    _dateChip(
                      _to != null ? _fmtDate(_to!) : 'End',
                      () => _pickDate(false),
                    ),
                    const Spacer(),
                    // Quick presets
                    _presetChip('7d', () {
                      final now = DateTime.now();
                      setState(() {
                        _to = now;
                        _from = now.subtract(const Duration(days: 6));
                      });
                    }),
                    const SizedBox(width: 6),
                    _presetChip('30d', () {
                      final now = DateTime.now();
                      setState(() {
                        _to = now;
                        _from = now.subtract(const Duration(days: 29));
                      });
                    }),
                    const SizedBox(width: 6),
                    _presetChip('All', () {
                      setState(() {
                        _from = null;
                        _to = null;
                      });
                    }),
                    const SizedBox(width: 8),
                    Container(
                      width: 1,
                      height: 14,
                      color: Colors.white.withOpacity(0.1),
                    ),
                    const SizedBox(width: 8),
                    Tooltip(
                      message: widget.projectCreatedAt != null
                          ? 'Reset to creation date → today'
                          : 'Reset to default range',
                      child: GestureDetector(
                        onTap: _resetToDefault,
                        child: Container(
                          padding: const EdgeInsets.all(5),
                          decoration: BoxDecoration(
                            color: Colors.white.withOpacity(0.05),
                            borderRadius: BorderRadius.circular(4),
                            border: Border.all(
                              color: Colors.white.withOpacity(0.1),
                            ),
                          ),
                          child: Icon(
                            Icons.restart_alt_rounded,
                            size: 13,
                            color: Colors.white.withOpacity(0.45),
                          ),
                        ),
                      ),
                    ),
                  ],
                ),
              ),
              const SizedBox(height: 24),

              // ── Metrics table ────────────────────────────────────────
              Container(
                decoration: BoxDecoration(
                  color: _cardBg,
                  borderRadius: BorderRadius.circular(10),
                  border: Border.all(color: _border),
                ),
                clipBehavior: Clip.antiAlias,
                child: Column(
                  children: [
                    // Table header
                    Container(
                      padding: const EdgeInsets.symmetric(
                        horizontal: 16,
                        vertical: 10,
                      ),
                      color: Colors.white.withOpacity(0.03),
                      child: Row(
                        children: [
                          Expanded(
                            flex: 3,
                            child: Text(
                              'METRIC',
                              style: TextStyle(
                                color: Colors.white.withOpacity(0.3),
                                fontSize: 10,
                                fontWeight: FontWeight.w700,
                                letterSpacing: 1,
                              ),
                            ),
                          ),
                          Text(
                            'VALUE',
                            style: TextStyle(
                              color: Colors.white.withOpacity(0.3),
                              fontSize: 10,
                              fontWeight: FontWeight.w700,
