                            ),
                          ),
                        ],
                      ),
                    ),
                    Container(height: 1, color: _border),
                    // Rows
                    ...rows.asMap().entries.map((entry) {
                      final i = entry.key;
                      final row = entry.value;
                      final isEven = i % 2 == 0;
                      return Column(
                        children: [
                          Container(
                            color: isEven ? _rowEven : _rowOdd,
