// ── Metrics data model ────────────────────────────────────────────────────────
class _MetricsData {
  final Duration totalSpent;
  final Duration totalEstimated;
  final int tasksDone;
  final int tasksCreated;
  final int daysWorked;
  final double avgTasksPerDay;
  final double avgBreaksPerDay;
  final Duration avgTimePerDay;
  final Duration avgTimePerTask;
  final Duration avgTimePerTaskWithSubs;
  final Duration avgTimeOnBreaks;

  const _MetricsData({
    required this.totalSpent,
    required this.totalEstimated,
    required this.tasksDone,
    required this.tasksCreated,
    required this.daysWorked,
    required this.avgTasksPerDay,
    required this.avgBreaksPerDay,
    required this.avgTimePerDay,
    required this.avgTimePerTask,
    required this.avgTimePerTaskWithSubs,
    required this.avgTimeOnBreaks,
  });
}

class _MetricRow {
  final String label;
  final String value;
  const _MetricRow(this.label, this.value);
}

// ─────────────────────────────────────────────────────────────────────────────
// _WorklogView  –  collapsible Year > Month > Week > Day worklog
// ─────────────────────────────────────────────────────────────────────────────

class _WorklogView extends StatefulWidget {
  final List<Task> tasks;
  final Map<String, List<_ExecutionSession>> taskSessions;
  final Color accentColor;

  const _WorklogView({
    required this.tasks,
    required this.taskSessions,
    this.accentColor = const Color(0xFF4FC3F7),
  });

  @override
  State<_WorklogView> createState() => _WorklogViewState();
}

class _WorklogViewState extends State<_WorklogView> {
  // Expansion state: key = "year", "year-month", "year-month-week"
  final Set<String> _expanded = {};

  Color get _accent => ensureAccentVisible(widget.accentColor);
  static const _bg = Color(0xFF181A1B);

  static const _monthNames = [
    'January',
    'February',
    'March',
    'April',
    'May',
    'June',
    'July',
    'August',
    'September',
    'October',
    'November',
    'December',
  ];
  static const _monthShort = [
    'Jan',
    'Feb',
    'Mar',
    'Apr',
    'May',
    'Jun',
    'Jul',
    'Aug',
    'Sep',
    'Oct',
    'Nov',
    'Dec',
  ];
  static const _dayShort = ['Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat', 'Sun'];

  // Accent color per year position (cycles)
  static const _yearColors = [
    Color(0xFF4FC3F7), // blue
    Color(0xFFAB47BC), // purple
    Color(0xFF26A69A), // teal
    Color(0xFFEF5350), // red
    Color(0xFFFFA726), // orange
  ];

  int _isoWeek(DateTime d) {
    final jan4 = DateTime(d.year, 1, 4);
    final startOfWeek1 = jan4.subtract(Duration(days: jan4.weekday - 1));
    return ((d.difference(startOfWeek1).inDays) ~/ 7) + 1;
  }

  DateTime _dayKey(DateTime d) => DateTime(d.year, d.month, d.day);

  String _fmt(Duration dur) {
    final h = dur.inHours;
    final m = dur.inMinutes % 60;
    final s = dur.inSeconds % 60;
    if (h > 0) return '${h}h ${m.toString().padLeft(2, '0')}m';
    if (m > 0) return '${m}m ${s.toString().padLeft(2, '0')}s';
    return '${s}s';
  }

  void _toggle(String key) => setState(
    () => _expanded.contains(key) ? _expanded.remove(key) : _expanded.add(key),
  );

  bool _isExpanded(String key) => _expanded.contains(key);

  @override
  Widget build(BuildContext context) {
    // ── Build aggregation tree ──────────────────────────────────────────
    // Map<year, Map<month, Map<weekNum, Map<dayKey, _DayData>>>>
    final Map<int, Map<int, Map<int, Map<DateTime, _WlDayData>>>> tree = {};

    for (final task in widget.tasks) {
      for (final s in (widget.taskSessions[task.id] ?? [])) {
        final d = s.startTime;
        final dk = _dayKey(d);
        final wk = _isoWeek(d);
        tree
            .putIfAbsent(d.year, () => {})
            .putIfAbsent(d.month, () => {})
            .putIfAbsent(wk, () => {})
            .update(
              dk,
              (v) {
                v.sessions.add(
                  _WlSession(
                    taskId: task.id,
                    taskTitle: task.title,
                    duration: s.duration,
                  ),
                );
                return v;
              },
              ifAbsent: () => _WlDayData(
                sessions: [
                  _WlSession(
                    taskId: task.id,
                    taskTitle: task.title,
                    duration: s.duration,
                  ),
                ],
              ),
            );
      }
    }

    if (tree.isEmpty) {
      return Container(
        color: _bg,
        child: Center(
          child: Column(
            mainAxisSize: MainAxisSize.min,
            children: [
              Icon(
                Icons.history_toggle_off_rounded,
                size: 48,
                color: Colors.white.withOpacity(0.08),
              ),
              const SizedBox(height: 16),
              Text(
                'No sessions recorded yet',
                style: TextStyle(
                  color: Colors.white.withOpacity(0.25),
                  fontSize: 14,
                  letterSpacing: 0.2,
                ),
              ),
              const SizedBox(height: 6),
              Text(
                'Start a timer on any task to see your worklog here.',
                style: TextStyle(
                  color: Colors.white.withOpacity(0.13),
                  fontSize: 11,
                ),
              ),
            ],
          ),
        ),
      );
    }

    final years = tree.keys.toList()..sort((a, b) => b.compareTo(a));

    return Container(
      color: _bg,
      child: ListView.builder(
        padding: const EdgeInsets.fromLTRB(20, 20, 20, 48),
        itemCount: years.length + 1, // +1 for header
        itemBuilder: (ctx, idx) {
          if (idx == 0) return _buildHeader(tree);
          final year = years[idx - 1];
          return _buildYear(year, tree[year]!, idx - 1);
        },
      ),
    );
  }

  // ── Top summary header ────────────────────────────────────────────────
  Widget _buildHeader(
    Map<int, Map<int, Map<int, Map<DateTime, _WlDayData>>>> tree,
  ) {
    // Total across all
    Duration totalDur = Duration.zero;
    int totalDays = 0;
    final Set<String> totalTasks = {};
    for (final ym in tree.values) {
      for (final wm in ym.values) {
        for (final dm in wm.values) {
          for (final day in dm.values) {
            totalDays++;
            for (final s in day.sessions) {
              totalTasks.add(s.taskId);
              totalDur += s.duration;
            }
          }
        }
      }
    }

    return Padding(
      padding: const EdgeInsets.only(bottom: 24),
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.start,
        children: [
          Row(
            children: [
              Icon(Icons.query_stats_rounded, size: 18, color: _accent),
              const SizedBox(width: 10),
              const Text(
                'WORKLOG',
                style: TextStyle(
                  color: Colors.white,
                  fontSize: 16,
                  fontWeight: FontWeight.w700,
                  letterSpacing: 1.5,
                ),
              ),
            ],
          ),
          const SizedBox(height: 16),
          Row(
            children: [
              _summaryChip(
                Icons.task_alt_rounded,
                '${totalTasks.length}',
                'tasks',
              ),
              const SizedBox(width: 8),
              _summaryChip(Icons.calendar_today_rounded, '$totalDays', 'days'),
              const SizedBox(width: 8),
              _summaryChip(
                Icons.timer_rounded,
                totalDur.inSeconds > 0 ? _fmt(totalDur) : '—',
                'total',
              ),
            ],
          ),
          const SizedBox(height: 20),
          Container(height: 1, color: Colors.white.withOpacity(0.06)),
        ],
      ),
    );
  }

