  }

  // ── Year block ────────────────────────────────────────────────────────
  Widget _buildYear(
    int year,
    Map<int, Map<int, Map<DateTime, _WlDayData>>> monthMap,
    int colorIdx,
  ) {
    final yKey = '$year';
    final open = _isExpanded(yKey);
    final color = _yearColors[colorIdx % _yearColors.length];

    // Aggregate year
    Duration yDur = Duration.zero;
    int yDays = 0;
    final Set<String> yTasks = {};
    for (final wm in monthMap.values) {
      for (final dm in wm.values) {
        for (final d in dm.values) {
          yDays++;
          for (final s in d.sessions) {
            yTasks.add(s.taskId);
            yDur += s.duration;
          }
        }
      }
    }

    final months = monthMap.keys.toList()..sort((a, b) => b.compareTo(a));

    return Padding(
      padding: const EdgeInsets.only(bottom: 12),
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.stretch,
        children: [
          // ── Year header row ──
          GestureDetector(
            onTap: () => _toggle(yKey),
            child: Container(
              padding: const EdgeInsets.fromLTRB(16, 14, 16, 14),
              decoration: BoxDecoration(
                color: color.withOpacity(0.07),
                borderRadius: BorderRadius.circular(12),
                border: Border.all(color: color.withOpacity(0.22)),
              ),
              child: Row(
                children: [
                  // Year badge
                  Container(
                    padding: const EdgeInsets.symmetric(
                      horizontal: 10,
                      vertical: 4,
                    ),
                    decoration: BoxDecoration(
                      color: color.withOpacity(0.18),
                      borderRadius: BorderRadius.circular(6),
                    ),
                    child: Text(
                      '$year',
                      style: TextStyle(
                        color: color,
                        fontSize: 18,
                        fontWeight: FontWeight.w800,
                        letterSpacing: 0.5,
                      ),
                    ),
                  ),
                  const SizedBox(width: 14),
                  // Stats
                  Expanded(
                    child: Wrap(
                      spacing: 8,
                      runSpacing: 4,
                      children: [
                        _statPill('${monthMap.length}mo', color),
                        _statPill('$yDays days', color),
                        if (yDur.inSeconds > 0) _statPill(_fmt(yDur), color),
                        _statPill('${yTasks.length} tasks', color),
                      ],
                    ),
                  ),
                  const SizedBox(width: 8),
                  AnimatedRotation(
                    turns: open ? 0.5 : 0,
                    duration: const Duration(milliseconds: 200),
                    child: Icon(
                      Icons.keyboard_arrow_down_rounded,
                      size: 20,
                      color: color.withOpacity(0.7),
                    ),
                  ),
                ],
              ),
            ),
          ),

          // ── Month list (animated) ──
          AnimatedCrossFade(
            firstChild: const SizedBox.shrink(),
            secondChild: Padding(
              padding: const EdgeInsets.only(top: 6, left: 12),
              child: Column(
                children: months
                    .map((m) => _buildMonth(year, m, monthMap[m]!, color))
                    .toList(),
              ),
            ),
            crossFadeState: open
                ? CrossFadeState.showSecond
                : CrossFadeState.showFirst,
            duration: const Duration(milliseconds: 200),
          ),
        ],
      ),
    );
  }

  // ── Month block ───────────────────────────────────────────────────────
  Widget _buildMonth(
    int year,
    int month,
    Map<int, Map<DateTime, _WlDayData>> weekMap,
    Color yearColor,
  ) {
    final mKey = '$year-$month';
    final open = _isExpanded(mKey);

    Duration mDur = Duration.zero;
    int mDays = 0;
    final Set<String> mTasks = {};
    for (final dm in weekMap.values) {
      for (final d in dm.values) {
        mDays++;
        for (final s in d.sessions) {
          mTasks.add(s.taskId);
          mDur += s.duration;
        }
      }
    }

    final weeks = weekMap.keys.toList()..sort((a, b) => b.compareTo(a));

    return Padding(
      padding: const EdgeInsets.only(bottom: 6),
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.stretch,
        children: [
          // ── Month header ──
          GestureDetector(
            onTap: () => _toggle(mKey),
            child: Container(
              padding: const EdgeInsets.fromLTRB(14, 11, 14, 11),
              decoration: BoxDecoration(
                color: Colors.white.withOpacity(0.03),
                borderRadius: BorderRadius.circular(9),
                border: Border.all(color: Colors.white.withOpacity(0.07)),
              ),
              child: Row(
                children: [
                  // Left accent bar
                  Container(
                    width: 3,
                    height: 32,
                    decoration: BoxDecoration(
                      color: yearColor.withOpacity(0.5),
                      borderRadius: BorderRadius.circular(2),
                    ),
                  ),
                  const SizedBox(width: 12),
                  // Month name + year
                  Column(
                    crossAxisAlignment: CrossAxisAlignment.start,
                    children: [
                      Text(
                        _monthNames[month - 1],
                        style: const TextStyle(
                          color: Colors.white,
                          fontSize: 13,
                          fontWeight: FontWeight.w600,
                        ),
                      ),
                      Text(
                        '$year',
                        style: TextStyle(
                          color: Colors.white.withOpacity(0.3),
                          fontSize: 10,
                        ),
                      ),
                    ],
                  ),
                  const SizedBox(width: 12),
                  // Stats row
                  Expanded(
                    child: Row(
                      mainAxisAlignment: MainAxisAlignment.end,
                      children: [
                        _inlineStat(
                          Icons.task_alt_rounded,
                          '${mTasks.length}',
                          yearColor,
                        ),
                        const SizedBox(width: 10),
                        _inlineStat(
                          Icons.calendar_today_rounded,
                          '$mDays d',
                          yearColor,
                        ),
                        const SizedBox(width: 10),
                        if (mDur.inSeconds > 0)
                          _inlineStat(
                            Icons.timer_outlined,
                            _fmt(mDur),
                            yearColor,
                          ),
                      ],
                    ),
                  ),
                  const SizedBox(width: 8),
                  AnimatedRotation(
                    turns: open ? 0.5 : 0,
                    duration: const Duration(milliseconds: 200),
                    child: Icon(
                      Icons.keyboard_arrow_down_rounded,
                      size: 18,
                      color: Colors.white.withOpacity(0.3),
                    ),
                  ),
                ],
              ),
            ),
          ),

          AnimatedCrossFade(
            firstChild: const SizedBox.shrink(),
            secondChild: Padding(
              padding: const EdgeInsets.only(top: 4, left: 16),
              child: Column(
                children: weeks
                    .map(
                      (w) => _buildWeek(year, month, w, weekMap[w]!, yearColor),
                    )
                    .toList(),
              ),
            ),
            crossFadeState: open
                ? CrossFadeState.showSecond
                : CrossFadeState.showFirst,
            duration: const Duration(milliseconds: 180),
          ),
        ],
      ),
    );
  }

  // ── Week block ────────────────────────────────────────────────────────
  Widget _buildWeek(
    int year,
    int month,
    int weekNum,
    Map<DateTime, _WlDayData> dayMap,
    Color yearColor,
  ) {
    final wKey = '$year-$month-$weekNum';
    final open = _isExpanded(wKey);

    Duration wDur = Duration.zero;
    final Set<String> wTasks = {};
    for (final d in dayMap.values) {
      for (final s in d.sessions) {
        wTasks.add(s.taskId);
        wDur += s.duration;
      }
    }

    final days = dayMap.keys.toList()..sort((a, b) => b.compareTo(a));

    // ── Compute the actual Mon–Sun dates for this ISO week ──────────────
    // ISO week 1 = week containing Jan 4
    final jan4 = DateTime(year, 1, 4);
    final startOfWeek1 = jan4.subtract(Duration(days: jan4.weekday - 1));
    final weekMonday = startOfWeek1.add(Duration(days: (weekNum - 1) * 7));
    final weekDates = List.generate(
      7,
      (i) => weekMonday.add(Duration(days: i)),
    );

    final today = DateTime.now();
    final todayKey = DateTime(today.year, today.month, today.day);

    return Padding(
      padding: const EdgeInsets.only(bottom: 4),
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.stretch,
        children: [
          // ── Week header ──
          GestureDetector(
            onTap: () => _toggle(wKey),
            child: Container(
              padding: const EdgeInsets.fromLTRB(12, 9, 12, 9),
              decoration: BoxDecoration(
                color: Colors.white.withOpacity(0.02),
                borderRadius: BorderRadius.circular(8),
                border: Border.all(color: Colors.white.withOpacity(0.05)),
              ),
              child: Row(
                children: [
                  // Week badge
                  Container(
                    padding: const EdgeInsets.symmetric(
                      horizontal: 7,
                      vertical: 3,
                    ),
                    decoration: BoxDecoration(
                      color: yearColor.withOpacity(0.1),
                      borderRadius: BorderRadius.circular(5),
                      border: Border.all(color: yearColor.withOpacity(0.25)),
                    ),
                    child: Text(
                      'W$weekNum',
                      style: TextStyle(
                        color: yearColor.withOpacity(0.8),
                        fontSize: 10,
                        fontWeight: FontWeight.w700,
                        letterSpacing: 0.5,
                      ),
                    ),
                  ),
                  const SizedBox(width: 10),

                  // ── 7-day strip ──────────────────────────────────────
                  ...weekDates.map((wd) {
                    final wdk = DateTime(wd.year, wd.month, wd.day);
                    final hasData = dayMap.containsKey(wdk);
                    final isToday = wdk == todayKey;
                    final isWeekend =
                        wd.weekday == DateTime.saturday ||
                        wd.weekday == DateTime.sunday;

                    Color dotColor;
                    Color labelColor;
                    Color bgColor;
                    if (hasData) {
                      dotColor = yearColor;
                      labelColor = isToday
                          ? yearColor
                          : Colors.white.withOpacity(0.75);
                      bgColor = yearColor.withOpacity(0.12);
                    } else {
                      dotColor = Colors.transparent;
                      labelColor = isWeekend
                          ? Colors.white.withOpacity(0.24)
                          : Colors.white.withOpacity(0.22);
                      bgColor = Colors.transparent;
                    }

                    // Time bar height (proportional to day duration vs week max)
                    Duration dayDur = Duration.zero;
                    if (hasData) {
                      for (final s in dayMap[wdk]!.sessions) {
                        dayDur += s.duration;
                      }
                    }
                    final maxSecs = dayMap.values.fold<int>(0, (mx, d) {
                      final ds = d.sessions.fold<int>(
                        0,
                        (sum, s) => sum + s.duration.inSeconds,
                      );
                      return ds > mx ? ds : mx;
                    });
                    final barFill = (maxSecs > 0 && dayDur.inSeconds > 0)
                        ? (dayDur.inSeconds / maxSecs).clamp(0.0, 1.0)
                        : 0.0;

                    return Padding(
                      padding: const EdgeInsets.only(right: 4),
                      child: Column(
                        mainAxisSize: MainAxisSize.min,
                        children: [
                          // Day letter
                          Text(
                            _dayShort[wd.weekday - 1][0], // 'M','T','W'…
                            style: TextStyle(
                              color: labelColor,
                              fontSize: 9,
                              fontWeight: hasData
                                  ? FontWeight.w700
                                  : FontWeight.normal,
                            ),
                          ),
                          const SizedBox(height: 3),
                          // Day number circle / filled dot
                          Container(
                            width: 22,
                            height: 22,
                            decoration: BoxDecoration(
                              color: bgColor,
                              shape: BoxShape.circle,
                              border: isToday
                                  ? Border.all(
                                      color: yearColor.withOpacity(0.7),
                                      width: 1.5,
                                    )
                                  : null,
                            ),
                            child: Center(
                              child: Text(
                                '${wd.day}',
                                style: TextStyle(
                                  color: labelColor,
                                  fontSize: 10,
                                  fontWeight: hasData
                                      ? FontWeight.w700
                                      : FontWeight.normal,
                                ),
                              ),
                            ),
                          ),
                          const SizedBox(height: 3),
                          // Mini activity bar
                          Container(
                            width: 22,
                            height: 3,
                            decoration: BoxDecoration(
                              borderRadius: BorderRadius.circular(2),
                              color: Colors.white.withOpacity(0.06),
                            ),
                            child: Align(
                              alignment: Alignment.centerLeft,
                              child: FractionallySizedBox(
                                widthFactor: barFill,
                                child: Container(
                                  decoration: BoxDecoration(
                                    borderRadius: BorderRadius.circular(2),
                                    color: hasData
                                        ? yearColor.withOpacity(0.75)
                                        : Colors.transparent,
                                  ),
                                ),
                              ),
                            ),
                          ),
                        ],
                      ),
                    );
                  }),

                  const Spacer(),

                  // Stats
                  if (wTasks.isNotEmpty) ...[
                    Text(
                      '${wTasks.length} tasks',
                      style: TextStyle(
                        color: Colors.white.withOpacity(0.35),
                        fontSize: 10,
                      ),
                    ),
                    const SizedBox(width: 6),
                    Container(
                      width: 1,
                      height: 10,
                      color: Colors.white.withOpacity(0.1),
                    ),
                    const SizedBox(width: 6),
                  ],
                  if (wDur.inSeconds > 0)
                    Text(
                      _fmt(wDur),
                      style: TextStyle(
                        color: Colors.white.withOpacity(0.55),
                        fontSize: 10,
                        fontWeight: FontWeight.w600,
                      ),
                    ),
                  const SizedBox(width: 8),
                  AnimatedRotation(
                    turns: open ? 0.5 : 0,
                    duration: const Duration(milliseconds: 200),
                    child: Icon(
                      Icons.keyboard_arrow_down_rounded,
                      size: 16,
                      color: Colors.white.withOpacity(0.25),
                    ),
                  ),
                ],
              ),
            ),
          ),

          AnimatedCrossFade(
            firstChild: const SizedBox.shrink(),
            secondChild: Padding(
              padding: const EdgeInsets.only(top: 3, left: 14),
              child: Column(
                children: days
                    .map((d) => _buildDay(d, dayMap[d]!, yearColor))
                    .toList(),
              ),
            ),
            crossFadeState: open
                ? CrossFadeState.showSecond
                : CrossFadeState.showFirst,
            duration: const Duration(milliseconds: 160),
          ),
        ],
      ),
    );
  }

  // ── Day block ─────────────────────────────────────────────────────────
  Widget _buildDay(DateTime day, _WlDayData data, Color yearColor) {
    // Aggregate tasks (merge duplicate taskIds)
    final Map<String, ({String title, Duration dur})> byTask = {};
    for (final s in data.sessions) {
      byTask.update(
        s.taskId,
        (v) => (title: v.title, dur: v.dur + s.duration),
        ifAbsent: () => (title: s.taskTitle, dur: s.duration),
      );
    }

    Duration dayDur = Duration.zero;
    for (final t in byTask.values) dayDur += t.dur;

    final isToday = () {
      final now = DateTime.now();
      return day.year == now.year &&
          day.month == now.month &&
          day.day == now.day;
    }();

    return Padding(
      padding: const EdgeInsets.only(bottom: 3),
      child: Container(
        decoration: BoxDecoration(
          color: isToday
              ? yearColor.withOpacity(0.06)
              : Colors.white.withOpacity(0.02),
          borderRadius: BorderRadius.circular(7),
          border: Border.all(
            color: isToday
                ? yearColor.withOpacity(0.2)
                : Colors.white.withOpacity(0.04),
          ),
        ),
        child: Column(
          crossAxisAlignment: CrossAxisAlignment.stretch,
          children: [
            // Day header
            Padding(
              padding: const EdgeInsets.fromLTRB(11, 8, 11, 6),
              child: Row(
                children: [
                  // Day name + number
                  Row(
                    children: [
                      Text(
                        _dayShort[day.weekday - 1],
                        style: TextStyle(
                          color: isToday
                              ? yearColor
                              : Colors.white.withOpacity(0.5),
                          fontSize: 11,
                          fontWeight: FontWeight.w700,
                          letterSpacing: 0.5,
                        ),
                      ),
                      const SizedBox(width: 4),
                      Container(
                        width: 22,
                        height: 22,
                        decoration: BoxDecoration(
                          color: isToday
                              ? yearColor.withOpacity(0.2)
                              : Colors.transparent,
                          shape: BoxShape.circle,
                        ),
                        child: Center(
                          child: Text(
                            '${day.day}',
                            style: TextStyle(
                              color: isToday
                                  ? yearColor
                                  : Colors.white.withOpacity(0.55),
                              fontSize: 11,
                              fontWeight: FontWeight.w600,
                            ),
                          ),
                        ),
                      ),
                    ],
                  ),
                  const SizedBox(width: 8),
                  if (isToday)
                    Container(
                      padding: const EdgeInsets.symmetric(
                        horizontal: 5,
                        vertical: 1,
                      ),
                      decoration: BoxDecoration(
                        color: yearColor.withOpacity(0.15),
                        borderRadius: BorderRadius.circular(3),
                      ),
                      child: Text(
                        'TODAY',
                        style: TextStyle(
                          color: yearColor,
                          fontSize: 8,
                          fontWeight: FontWeight.w800,
                          letterSpacing: 0.8,
                        ),
                      ),
                    ),
                  const Spacer(),
                  // Task count + time
                  Text(
                    '${byTask.length} task${byTask.length == 1 ? '' : 's'}',
                    style: TextStyle(
                      color: Colors.white.withOpacity(0.3),
                      fontSize: 10,
                    ),
                  ),
                  const SizedBox(width: 6),
                  Container(
                    width: 1,
                    height: 10,
                    color: Colors.white.withOpacity(0.1),
                  ),
                  const SizedBox(width: 6),
                  Text(
                    dayDur.inSeconds > 0 ? _fmt(dayDur) : '—',
                    style: TextStyle(
                      color: yearColor.withOpacity(0.8),
                      fontSize: 10,
                      fontWeight: FontWeight.w700,
                    ),
                  ),
                ],
              ),
            ),

            // Task list
            if (byTask.isNotEmpty) ...[
              Container(
                height: 1,
                color: Colors.white.withOpacity(0.04),
                margin: const EdgeInsets.symmetric(horizontal: 11),
              ),
              Padding(
                padding: const EdgeInsets.fromLTRB(11, 6, 11, 8),
                child: Column(
                  crossAxisAlignment: CrossAxisAlignment.start,
                  children: byTask.entries.map((e) {
                    return Padding(
                      padding: const EdgeInsets.only(bottom: 4),
                      child: Row(
                        children: [
                          Container(
                            width: 4,
                            height: 4,
                            decoration: BoxDecoration(
                              color: yearColor.withOpacity(0.5),
                              shape: BoxShape.circle,
                            ),
                          ),
                          const SizedBox(width: 8),
                          Expanded(
                            child: Text(
                              e.value.title,
                              style: TextStyle(
                                color: Colors.white.withOpacity(0.65),
                                fontSize: 11,
                              ),
                              maxLines: 1,
                              overflow: TextOverflow.ellipsis,
                            ),
                          ),
                          const SizedBox(width: 8),
                          Text(
                            e.value.dur.inSeconds > 0 ? _fmt(e.value.dur) : '—',
                            style: TextStyle(
                              color: Colors.white.withOpacity(0.3),
                              fontSize: 10,
                              fontFamily: 'monospace',
                            ),
                          ),
                        ],
                      ),
                    );
                  }).toList(),
                ),
              ),
            ],
          ],
        ),
      ),
    );
  }

  // ── Small helpers ─────────────────────────────────────────────────────
  Widget _statPill(String label, Color color) => Container(
    padding: const EdgeInsets.symmetric(horizontal: 8, vertical: 3),
    decoration: BoxDecoration(
      color: color.withOpacity(0.1),
      borderRadius: BorderRadius.circular(20),
      border: Border.all(color: color.withOpacity(0.2)),
    ),
    child: Text(
      label,
      style: TextStyle(
        color: color.withOpacity(0.85),
        fontSize: 10,
        fontWeight: FontWeight.w600,
      ),
    ),
  );

  Widget _inlineStat(IconData icon, String value, Color color) => Row(
    mainAxisSize: MainAxisSize.min,
    children: [
      Icon(icon, size: 10, color: color.withOpacity(0.5)),
      const SizedBox(width: 3),
      Text(
        value,
        style: TextStyle(
          color: Colors.white.withOpacity(0.45),
          fontSize: 10,
          fontWeight: FontWeight.w500,
        ),
      ),
    ],
  );
}

// ── Worklog data models ───────────────────────────────────────────────────────
class _WlSession {
  final String taskId;
  final String taskTitle;
  final Duration duration;
  _WlSession({
    required this.taskId,
    required this.taskTitle,
    required this.duration,
  });
}

class _WlDayData {
  final List<_WlSession> sessions;
  _WlDayData({required this.sessions});
}

// ─────────────────────────────────────────────────────────────────────────────
// _ScheduleCanvas  –  zoomable/pannable week calendar canvas
// ─────────────────────────────────────────────────────────────────────────────

class _ScheduleCanvas extends StatefulWidget {
  final List<Task> allTasks;
  final DateTime weekStart;
  final DateTime? rangeEnd;
  final Map<String, Project> projects;
  final void Function(Task) onTaskUpdated;
  final void Function(DateTime slot, int suggestedDuration) onCreateRequest;
  final void Function(
    DateTime visibleStart,
    DateTime visibleEnd, {
    required bool shiftPanning,
  })?
  onVisibleRangeChanged;
  final Map<String, List<_ExecutionSession>> taskSessions;
  final _ExecutionViewMode execViewMode;
  final Map<String, Color> projectColors;
  // Feature 8: right-click opens the standard task context menu
  final void Function(Task task, Offset globalPos)? onContextMenu;

  const _ScheduleCanvas({
    Key? key,
    required this.allTasks,
    required this.weekStart,
    this.rangeEnd,
    required this.projects,
    this.projectColors = const {},
    this.taskSessions = const {},
    this.execViewMode = _ExecutionViewMode.planning,
    required this.onTaskUpdated,
    required this.onCreateRequest,
    this.onVisibleRangeChanged,
    this.onContextMenu,
  }) : super(key: key);

  @override
  State<_ScheduleCanvas> createState() => _ScheduleCanvasState();
}

class _ScheduleCanvasState extends State<_ScheduleCanvas> {
  // ── Constants ──────────────────────────────────────────────────────────────
  static const double _bHH = 64.0; // base hour height at scale 1.0
  static const double _tCW = 56.0; // time column width (fixed)
  static const double _hdrH = 40.0; // day-header row height
  static const double _padT = 28.0; // top padding above 12 AM
  static const double _padB = 36.0; // bottom padding below 11:55 PM

  // ── State ──────────────────────────────────────────────────────────────────
  // _scale: VERTICAL zoom (hour height = _bHH * _scale).
  // _hScale: HORIZONTAL zoom (visibleDays = ceil(7 / _hScale)).
  // They start equal and can diverge via axis-specific zoom.
  double _scale = 1.0;
  double _hScale = 1.0;

  // _ox: sub-column horizontal offset in screen pixels, kept in (-cw, 0].
  // _dayShift: how many days from widget.weekStart the first visible column is.
  //   0 = Mon of current week; negative = past; positive = future.
  double _ox = 0.0;
  int _dayShift = 0;

  // _oy: vertical scroll in screen pixels (starts at -7h so 7 AM is visible).
  double _oy = 0.0;

  double _canvasW = 0, _canvasH = 0, _scrollH = 0;
  int _visibleDays = 7; // updated every build

  // Pan gesture bookkeeping
  Offset _panPtrStart = Offset.zero;
  double _panOrigOX = 0, _panOrigOY = 0;
  int _panOrigDayShift = 0;

  // Task drag
  String? _dragId;
  int _dragOrigCol = 0, _dragCurCol = 0;
  double _dragOrigWY = 0, _dragCurWY = 0;
  Offset _dragPtrOrigin = Offset.zero;

  // Task resize
  String? _resizeId;
  double _resizeOrigH = 0, _resizeCurH = 0;
  Offset _resizePtrOrigin = Offset.zero;

  // Hover ghost
  int? _hoverCol;
  double? _hoverWY;

  // All-day strip collapsed/expanded
  bool _allDayExpanded = false;

  // Pill color mode: false = status color (default), true = project color
  bool _pillColorByProject = false;

  // Task Creation Mode: when true, hovering shows the hint and clicking creates
  // a task — same as holding Shift. Toggled from the bottom bar switcher.
  bool _taskCreationMode = false;

  /// True when the user can create a new task by clicking on the canvas.
  /// Active when Shift is held OR the bottom-bar Task Creation Mode toggle is on.
  bool get _isCreationActive => _shiftDown || _taskCreationMode;

  // When true, the next didUpdateWidget weekStart change will NOT compensate
  // _dayShift — used by deliberate top-bar navigation (Back / Forward / Today).
  bool _skipNextCompensation = false;

  Timer? _clockTimer;

  // ── Lifecycle ──────────────────────────────────────────────────────────────
  @override
  void initState() {
    super.initState();
    // Store the desired 7-AM offset unconditionally. _clampOY cannot do its
    // job here because _canvasH/_scrollH are 0 before the first layout pass.
    // A post-frame callback re-clamps _oy once real dimensions are available,
    // which prevents the first build from clamping everything to 0 and hiding
    // all task cards.
    _oy = -(7 * _bHH + _padT); // scroll to 7 AM on open
    WidgetsBinding.instance.addPostFrameCallback((_) {
      if (mounted) {
        setState(() {
          _oy = _clampOY(_oy, _scale);
        });
      }
    });
    _clockTimer = Timer.periodic(const Duration(minutes: 1), (_) {
      if (mounted) setState(() {});
    });
    HardwareKeyboard.instance.addHandler(_handleKeyEvent);
  }

  @override
  void didUpdateWidget(_ScheduleCanvas oldWidget) {
    super.didUpdateWidget(oldWidget);
    // When the parent sets a new weekStart (from Shift-drag feedback), compensate
    // _dayShift so the visual position stays the same.
    // When a deliberate top-bar navigation triggered this update, skip the
    // compensation so the canvas actually jumps to the new date range.
    if (oldWidget.weekStart != widget.weekStart) {
      if (_skipNextCompensation) {
        _skipNextCompensation = false;
        // No compensation — canvas already jumped to the new start.
      } else {
        final diff = widget.weekStart.difference(oldWidget.weekStart).inDays;
        _dayShift -= diff;
      }
    }
  }

  @override
  void dispose() {
    HardwareKeyboard.instance.removeHandler(_handleKeyEvent);
    _clockTimer?.cancel();
    super.dispose();
  }

  /// Called whenever a key is pressed/released. When Shift is released we
  /// snap the horizontal position back inside the rangeEnd boundary so the
  /// view never "parks" in an illegal position.
  /// We also rebuild on Shift down/up so the creation hint appears / disappears
  /// immediately without requiring the mouse to move first.
  bool _handleKeyEvent(KeyEvent event) {
    final isShiftKey =
        event.logicalKey == LogicalKeyboardKey.shiftLeft ||
        event.logicalKey == LogicalKeyboardKey.shiftRight;
    if (event is KeyUpEvent && isShiftKey) {
      // Shift just went up — snap rightward overshoot back into range.
      _snapToBoundary();
      if (mounted) setState(() {}); // hide creation hint
    } else if (event is KeyDownEvent && isShiftKey) {
      if (mounted) setState(() {}); // show creation hint
    }
    return false; // never consume
  }

  /// Snap to right boundary when Shift is released or after zoom.
  /// [visibleDays] can be passed explicitly when called right after a zoom
  /// mutation before the next build updates _visibleDays.
  void _snapToBoundary({int? visibleDays}) {
    final vd = visibleDays ?? _visibleDays;
    final cw = _colW(vd);
    if (cw <= 0) return;
    // _applyHorizBounds won't run when _shiftDown, but we just released Shift
    // so call it directly (Shift is already up by the time this runs).
    final mx = _maxDayShift(vd);
    if (mx == null) return;
    if (_dayShift > mx || (_dayShift == mx && _ox < 0)) {
      setState(() {
        _dayShift = mx;
        _ox = 0.0;
      });
    }
  }

  void resetView() {
    setState(() {
      _scale = 1.0.clamp(_absMinScale, 6.0);
      _hScale = 1.0;
      _ox = 0.0;
      _dayShift = 0;
      _oy = _clampOY(-(7 * _bHH * _scale + _padT), _scale);
    });
  }

  /// Called by top-bar navigation buttons (Back / Forward / Today).
  /// Resets the canvas horizontal position to the new [newWeekStart] and
  /// marks that the upcoming didUpdateWidget should NOT compensate _dayShift.
  void navigateTo(DateTime newWeekStart) {
    _skipNextCompensation = true;
    setState(() {
      _dayShift = 0;
      _ox = 0.0;
    });
  }

  /// Called by the Week / Month toggle in the top bar.
  /// 'week'  → show 7 days  (_hScale = 1.0)
  /// 'month' → show 30 days (_hScale = 7/30) from the current weekStart
  void setViewMode(String mode) {
    _skipNextCompensation = true;
    setState(() {
      _dayShift = 0;
      _ox = 0.0;
      if (mode == 'month') {
        _hScale = 7.0 / 30.0; // 30 columns visible
      } else if (mode == '14d') {
        _hScale = 7.0 / 14.0; // 14 columns visible
      } else {
        _hScale = 1.0; // 7 columns visible (week)
      }
    });
  }

  /// Set an arbitrary number of visible days from the Custom dialog.
  void setViewDays(int days) {
    _skipNextCompensation = true;
    setState(() {
      _dayShift = 0;
      _ox = 0.0;
      _hScale = 7.0 / days.clamp(1, 365);
    });
  }

  void zoomIn() {
    setState(() {
      final newScale = (_scale * 1.3).clamp(_absMinScale, 6.0);
      final midY = (_scrollH > 0 ? _scrollH : _canvasH) / 2;
      final origWY = (midY - _oy) / _vScale;
      _scale = newScale;
      _hScale = (_hScale * 1.3).clamp(_absMinScale, 6.0);
      _ox = 0.0;
      _oy = _clampOY(midY - origWY * newScale, newScale);
    });
    final newVD = (7.0 / _hScale).ceil().clamp(7, 365);
    _snapToBoundary(visibleDays: newVD);
  }

  void zoomOut() {
    setState(() {
      final newScale = (_scale / 1.3).clamp(_absMinScale, 6.0);
      final midY = (_scrollH > 0 ? _scrollH : _canvasH) / 2;
      final origWY = (midY - _oy) / _vScale;
      _scale = newScale;
      _hScale = (_hScale / 1.3).clamp(_absMinScale, 6.0);
      _ox = 0.0;
      _oy = _clampOY(midY - origWY * newScale, newScale);
    });
    final newVD = (7.0 / _hScale).ceil().clamp(7, 365);
    _snapToBoundary(visibleDays: newVD);
  }

  // ── Derived geometry ───────────────────────────────────────────────────────
  // Column width in screen pixels: always fills available width exactly.
  double _colW(int visibleDays) =>
      _canvasW > 0 ? (_canvasW - _tCW) / visibleDays : 120.0;

  // Minimum scale: hard floor so day content never becomes invisible.
  static const double _absMinScale = 0.05;

  // Scale at which 24h + pads exactly fills the scroll area.
  double get _fitScale =>
      _scrollH > 0 ? (_scrollH - _padT - _padB) / (24 * _bHH) : _absMinScale;

  // Effective VERTICAL scale: never compress below fit (24h always fills view).
  // Horizontal zoom (_visibleDays) keeps using raw _scale so more days appear.
  double get _vScale => _scale < _fitScale ? _fitScale : _scale;

  // Clamp _oy so content never leaves empty space — but if content is
  // shorter than the canvas (fully zoomed out), pin to top (oy = 0).
  double _clampOY(double oy, double scale) {
    final vs = scale < _fitScale ? _fitScale : scale;
    final totalH = 24 * _bHH * vs + _padT + _padB;
    final h = _scrollH > 0 ? _scrollH : _canvasH;
    if (totalH <= h) return 0.0;
    return oy.clamp(h - totalH, 0.0);
  }

  bool get _busy => _dragId != null || _resizeId != null;

  // ── Coordinate helpers ─────────────────────────────────────────────────────
  // Screen X of the left edge of column [col].  No _scale in horizontal.
  double _sx(int col, double cw) => col * cw + _ox + _tCW;

  // Screen Y of a world-Y position (hours x _bHH).
  double _sy(double wy) => wy * _vScale + _oy + _padT;

  // Column index from screen X.
  int _colFromSX(double sx, double cw) => ((sx - _ox - _tCW) / cw).floor();

  // World-Y from screen Y.
  double _wy(double sy) => (sy - _oy - _padT) / _vScale;

  // ── Snap helpers ───────────────────────────────────────────────────────────
  double _snapWY(double wy) {
    final min5 = ((wy / _bHH * 60) / 5).round() * 5;
    return (min5 / 60.0 * _bHH).clamp(0.0, (23 * 60 + 55) / 60.0 * _bHH);
  }

  double _snapWH(double wh) {
    final slots = ((wh / _bHH * 60) / 5).round().clamp(1, 24 * 12);
    return slots * 5 / 60.0 * _bHH;
  }

  // ── Date helpers ───────────────────────────────────────────────────────────
  DateTime _slotFromWorld(int col, double wy) {
    final day = widget.weekStart.add(Duration(days: col + _dayShift));
    final totalMin = ((wy / _bHH) * 60).round().clamp(0, 23 * 60 + 55);
    return DateTime(
      day.year,
      day.month,
      day.day,
      totalMin ~/ 60,
      totalMin % 60,
    );
  }

  String _fmt12h(int h, int m) {
    final p = h < 12 ? 'AM' : 'PM';
    final hh = h == 0 ? 12 : (h > 12 ? h - 12 : h);
    return '$hh:${m.toString().padLeft(2, '0')} $p';
  }

  // ── Input handlers ─────────────────────────────────────────────────────────

  bool get _altDown => HardwareKeyboard.instance.isAltPressed;
  bool get _shiftDown => HardwareKeyboard.instance.isShiftPressed;

  // Max _dayShift allowed when not Shift-panning: keeps right edge within rangeEnd.
  // We clamp so that dayShift + visibleDays - 1 <= rangeSpan,
  // i.e. the rightmost visible column never exceeds rangeEnd.
  int? _maxDayShift(int visibleDays) {
    if (_shiftDown) return null; // unlocked when Shift is pressed

    // If we are showing 7 days (default), max shift is 0 (panning is locked).
    // If we are zoomed in to show 3 days, max shift is 4 (can pan within the 7 days).
    // If we are zoomed out (>7 days), max shift is 0.
    // This perfectly prevents revealing new columns without Shift.
    return (7 - visibleDays).clamp(0, 365);
  }

  // Absorb full column-widths from _ox into _dayShift so _ox stays in (-cw, 0].
  // allowPast: if false, clamp _dayShift >= 0 (Monday = hard left border).
  void _normalizeOX(double cw, {bool allowPast = false}) {
    if (cw <= 0) return;
    if (_ox <= -cw) {
      final cols = (-_ox / cw).floor();
      _dayShift += cols;
      _ox += cols * cw;
    } else if (_ox > 0) {
      final cols = (_ox / cw).ceil();
      _dayShift -= cols;
      _ox -= cols * cw; // _ox lands in (-cw, 0]
    }
    if (!allowPast && _dayShift < 0) {
      _ox = 0.0;
      _dayShift = 0;
    }
  }

  /// Hard boundary clamp, applied after every horizontal-position mutation.
  /// [vd] is the current visible-day count (pass fresh value from the closure,
  /// not the possibly-stale _visibleDays field).
  void _applyHorizBounds(double cw, int vd) {
    if (_shiftDown) return; // Shift = intentionally unlocked
    // Past (left) boundary — never before weekStart
    if (_dayShift < 0) {
      _dayShift = 0;
      _ox = 0.0;
      return;
    }
    // Future (right) boundary — never past rangeEnd
    final mx = _maxDayShift(vd);
    if (mx == null) return; // no rangeEnd set yet, nothing to clamp
    if (_dayShift > mx) {
      _dayShift = mx;
      _ox = 0.0;
    } else if (_dayShift == mx && _ox < 0) {
      // Sub-column overshoot at the boundary — park flush.
      _ox = 0.0;
    }
  }

  // Zoom horizontal axis around a screen-X position.
  void _zoomH(double screenX, double factor, double cw) {
    final newHScale = (_hScale * factor).clamp(_absMinScale, 6.0);
    final worldCol = (screenX - _ox - _tCW) / cw;
    final newVD = (7.0 / newHScale).ceil().clamp(7, 365);
    final newCw = _canvasW > 0 ? (_canvasW - _tCW) / newVD : cw;
    _hScale = newHScale;
    _ox = screenX - _tCW - worldCol * newCw;
    _normalizeOX(newCw, allowPast: true); // absorb full columns first
    _applyHorizBounds(newCw, newVD); // then enforce boundary
  }

  // Zoom vertical axis around a screen-Y position.
  void _zoomV(double screenY, double factor) {
    final newScale = (_scale * factor).clamp(_absMinScale, 6.0);
    final origWY = _wy(screenY);
    _scale = newScale;
    final newVS = newScale < _fitScale ? _fitScale : newScale;
    _oy = _clampOY(screenY - _padT - origWY * newVS, newScale);
  }

  // Canvas area scroll (Alt = zoom both, plain = pan).
  void _handleScrollCanvas(PointerScrollEvent e, double cw) {
    final vd = _visibleDays;
    setState(() {
      if (_altDown) {
        final factor = 1 + (-e.scrollDelta.dy) * 0.0015;
        _zoomV(e.localPosition.dy, factor);
        // _zoomH computes its own fresh vd from newHScale
        _zoomH(e.localPosition.dx, factor, cw);
      } else if (e.scrollDelta.dx.abs() > e.scrollDelta.dy.abs()) {
        _ox -= e.scrollDelta.dx;
        _normalizeOX(cw, allowPast: _shiftDown);
        _applyHorizBounds(cw, vd);
      } else {
        _oy = _clampOY(_oy - e.scrollDelta.dy, _scale);
      }
    });
  }

  // Day-header row scroll (Alt = zoom H, plain = pan H).
  void _handleScrollDayHeader(PointerScrollEvent e, double cw) {
    final vd = _visibleDays;
    setState(() {
      final dy = e.scrollDelta.dy;
      final dx = e.scrollDelta.dx;
      final dominant = dy.abs() > dx.abs() ? dy : dx;
      if (_altDown) {
        _zoomH(e.localPosition.dx - _tCW, 1 + (-dominant) * 0.0015, cw);
      } else {
        _ox -= dominant;
        _normalizeOX(cw, allowPast: _shiftDown);
        _applyHorizBounds(cw, vd);
      }
    });
  }

  // Time-column scroll (Alt = zoom V, plain = pan V).
  void _handleScrollTimeCol(PointerScrollEvent e) {
    setState(() {
      final dy = e.scrollDelta.dy;
      final dx = e.scrollDelta.dx;
      final dominant = dy.abs() > dx.abs() ? dy : dx;
      if (_altDown) {
        _zoomV(e.localPosition.dy, 1 + (-dominant) * 0.0015);
      } else {
        _oy = _clampOY(_oy - dominant, _scale);
      }
    });
  }

  // ── Build ──────────────────────────────────────────────────────────────────
  @override
  Widget build(BuildContext context) {
    return LayoutBuilder(
      builder: (ctx, box) {
        _canvasW = box.maxWidth;
        _canvasH = box.maxHeight;

        final now = DateTime.now();
        final today = DateTime(now.year, now.month, now.day);

        // visibleDays: zoom out (_scale < 1) -> more days; zoom in -> fewer.
        // Minimum 7 so a full week is always shown at default zoom.
        final int visibleDays = (7.0 / _hScale).ceil().clamp(7, 365);
        _visibleDays = visibleDays;
        final cw = _colW(visibleDays);
        final days = List.generate(
          visibleDays,
          (i) => widget.weekStart.add(Duration(days: i + _dayShift)),
        );

        // Tell parent which date range is visible (post-frame to avoid
        // setState-during-build).
        WidgetsBinding.instance.addPostFrameCallback((_) {
          widget.onVisibleRangeChanged?.call(
            days.first,
            days.last,
            shiftPanning: _shiftDown,
          );
        });

        // Separate date-only (all-day) from datetime (timed) tasks.
        // Uses scheduledDateTime (plannedAt > dueDay+time) for placement.
        final Map<String, int> taskCol = {};
        final Map<String, int> allDayCol = {};

        for (int c = 0; c < visibleDays; c++) {
          final d = days[c];
          for (final t in widget.allTasks) {
            final date = t.scheduledDate;
            if (date == null) continue;
            if (date.year == d.year &&
                date.month == d.month &&
                date.day == d.day) {
              if (t.scheduledDateTime != null) {
                taskCol[t.id] = c;
              } else {
                allDayCol[t.id] = c;
              }
            }
          }
        }

        final allDayTasks = widget.allTasks
            .where((t) => allDayCol.containsKey(t.id))
            .toList();

        final todayCol = days.indexWhere((d) => d == today);

        return Column(
          children: [
            Listener(
              onPointerSignal: (e) {
                if (e is PointerScrollEvent) _handleScrollDayHeader(e, cw);
              },
              child: _buildHeader(days, today, visibleDays, cw),
            ),
            _buildAllDayStrip(allDayTasks, allDayCol, days, visibleDays, cw),
            Expanded(
              child: LayoutBuilder(
                builder: (_, scrollBox) {
                  _scrollH = scrollBox.maxHeight;
                  // Re-clamp immediately with the fresh _scrollH so _oy is
                  // always valid relative to the actual visible area.
                  _scale = _scale.clamp(_absMinScale, 6.0);
                  _oy = _clampOY(_oy, _scale);
                  return Listener(
                    onPointerSignal: (e) {
                      if (e is PointerScrollEvent) _handleScrollCanvas(e, cw);
                    },
                    child: MouseRegion(
                      cursor: _isCreationActive
                          ? SystemMouseCursors.precise
                          : SystemMouseCursors.basic,
                      onHover: _busy
                          ? null
                          : (e) {
                              final sx = e.localPosition.dx;
                              final sy = e.localPosition.dy;
                              final col = _colFromSX(sx, cw);
                              final wy = _wy(sy);
                              if (col >= 0 &&
                                  col < visibleDays &&
                                  wy >= 0 &&
                                  wy < 24 * _bHH) {
                                setState(() {
                                  _hoverCol = col;
                                  _hoverWY = _snapWY(wy);
                                });
                              } else {
                                setState(() {
                                  _hoverCol = null;
                                  _hoverWY = null;
                                });
                              }
                            },
                      onExit: (_) => setState(() {
                        _hoverCol = null;
                        _hoverWY = null;
                      }),
                      child: GestureDetector(
                        behavior: HitTestBehavior.opaque,
                        onScaleStart: _busy
                            ? null
                            : (d) {
                                _panPtrStart = d.localFocalPoint;
                                _panOrigOX = _ox;
                                _panOrigOY = _oy;
                                _panOrigDayShift = _dayShift;
                              },
                        onScaleUpdate: _busy
                            ? null
                            : (d) {
                                if (d.pointerCount >= 2) {
                                  final newScale = (_scale * d.scale).clamp(
                                    _absMinScale,
                                    6.0,
                                  );
                                  final focal = d.localFocalPoint;
                                  final origWY = _wy(focal.dy);
                                  final newVS = newScale < _fitScale
                                      ? _fitScale
                                      : newScale;
                                  setState(() {
                                    _scale = newScale;
                                    _oy = _clampOY(
                                      focal.dy - origWY * newVS,
                                      newScale,
                                    );
                                  });
                                } else {
                                  final delta =
                                      d.localFocalPoint - _panPtrStart;
                                  final vd = _visibleDays;
                                  setState(() {
                                    _ox = _panOrigOX + delta.dx;
                                    _dayShift = _panOrigDayShift;
                                    _normalizeOX(cw, allowPast: _shiftDown);
                                    _applyHorizBounds(cw, vd);
                                    _oy = _clampOY(
                                      _panOrigOY + delta.dy,
                                      _scale,
                                    );
                                  });
                                }
                              },
                        onTapUp: (d) {
                          // Only create a task when Shift is held or the
                          // Task Creation Mode toggle is active.
                          if (!_isCreationActive) return;
                          if (_hoverCol == null || _hoverWY == null) return;
                          final hourH = _bHH * _vScale;
                          final int slotMin = hourH >= 80
                              ? 5
                              : hourH >= 40
                              ? 15
                              : 30;
                          widget.onCreateRequest(
                            _slotFromWorld(_hoverCol!, _hoverWY!),
                            slotMin,
                          );
                        },
                        child: ClipRect(
                          child: Stack(
                            children: [
                              Positioned.fill(
                                child: CustomPaint(
                                  painter: _ScheduleGridPainter(
                                    scale: _vScale,
                                    ox: _ox,
                                    oy: _oy,
                                    colW: cw,
                                    bHH: _bHH,
                                    tCW: _tCW,
                                    padT: _padT,
                                    padB: _padB,
                                    todayCol: todayCol,
                                    visibleDays: visibleDays,
                                  ),
                                ),
                              ),
                              // Time-column overlay: plain scroll = pan V, Alt = zoom V
                              Positioned(
                                left: 0,
                                top: 0,
                                width: _tCW,
                                bottom: 0,
                                child: Listener(
                                  behavior: HitTestBehavior.opaque,
                                  onPointerSignal: (e) {
                                    if (e is PointerScrollEvent)
                                      _handleScrollTimeCol(e);
                                  },
                                  child: const SizedBox.expand(),
                                ),
                              ),
                              if (!_busy &&
                                  _isCreationActive &&
                                  _hoverCol != null &&
                                  _hoverWY != null)
                                _buildHint(_hoverCol!, _hoverWY!, cw),
                              if (todayCol >= 0)
                                ..._buildNowLine(now, todayCol),
                              ...widget.allTasks
                                  .where((t) => taskCol.containsKey(t.id))
                                  .map((t) {
                                    return _buildCard(
                                      t,
                                      taskCol[t.id]!,
                                      cw,
                                      opacity:
                                          widget.execViewMode !=
                                              _ExecutionViewMode.planning
                                          ? 0.22
                                          : 1.0,
                                    );
                                  }),
                              // ── Execution session blocks ────────────────────
                              if (widget.execViewMode !=
                                  _ExecutionViewMode.planning)
                                ...widget.taskSessions.entries.expand((entry) {
                                  return (entry.value).map((session) {
                                    final sStart = session.startTime;
                                    final sDay = DateTime(
                                      sStart.year,
                                      sStart.month,
                                      sStart.day,
                                    );
                                    final colIdx = days.indexWhere(
                                      (d) =>
                                          d.year == sDay.year &&
                                          d.month == sDay.month &&
                                          d.day == sDay.day,
                                    );
                                    if (colIdx < 0)
                                      return const Positioned(
                                        top: 0,
                                        left: 0,
                                        child: SizedBox.shrink(),
                                      );

                                    final task = widget.allTasks.firstWhere(
                                      (t) => t.id == entry.key,
                                      orElse: () => Task(
                                        id: '',
                                        title: '?',
                                        isDone: false,
                                        projectId: '',
                                        subTaskIds: [],
                                        timeSpent: 0,
                                        attachments: [],
                                        tagIds: [],
                                      ),
                                    );
                                    if (task.id.isEmpty)
                                      return const Positioned(
                                        top: 0,
                                        left: 0,
                                        child: SizedBox.shrink(),
                                      );

                                    final colorIdx = widget.projects.keys
                                        .toList()
                                        .indexOf(task.projectId);
                                    final color = _projectColor(
                                      task.projectId,
                                      colorIdx < 0 ? 0 : colorIdx,
                                    );

                                    final worldY =
                                        (sStart.hour +
                                            sStart.minute / 60.0 +
                                            sStart.second / 3600.0) *
                                        _bHH;
                                    final durH =
                                        session.duration.inSeconds / 3600.0;
                                    final worldH = durH * _bHH;

                                    final gutter = cw >= 12
                                        ? 3.0
                                        : (cw * 0.25).floorToDouble();
                                    final sx = _sx(colIdx, cw) + gutter;
                                    final sy = _sy(worldY) + 2;
                                    final sw = (cw - gutter * 2).clamp(
                                      1.0,
                                      double.infinity,
                                    );
                                    final sh = (worldH * _vScale - 4).clamp(
                                      6.0,
                                      double.infinity,
                                    );

                                    if (sx + sw < _tCW ||
                                        sx > _canvasW ||
                                        sy + sh < 0 ||
                                        sy > _scrollH) {
                                      return const Positioned(
                                        top: 0,
                                        left: 0,
                                        child: SizedBox.shrink(),
                                      );
                                    }

                                    final segs =
                                        widget.execViewMode ==
                                            _ExecutionViewMode.executionDetail
                                        ? _buildSessionSegs(session, color)
                                        : <_SegBlock>[];

                                    final isInterrupted =
                                        session.status ==
                                        _SessionStatus.interrupted;
                                    final isCompleted =
                                        session.status ==
                                        _SessionStatus.completed;
                                    final borderColor = isInterrupted
                                        ? const Color(
                                            0xFFFFB74D,
                                          ).withOpacity(0.7)
                                        : isCompleted
                                        ? const Color(
                                            0xFF81C784,
                                          ).withOpacity(0.7)
                                        : color.withOpacity(0.6);
                                    final bgColor = isInterrupted
                                        ? const Color(
                                            0xFFFFB74D,
                                          ).withOpacity(0.15)
                                        : isCompleted
                                        ? const Color(
                                            0xFF81C784,
                                          ).withOpacity(0.18)
                                        : color.withOpacity(0.22);

                                    return Positioned(
                                      left: sx,
                                      top: sy,
                                      width: sw,
                                      height: sh,
                                      child: Tooltip(
                                        message:
                                            '${task.title}\n'
                                            '${sStart.hour.toString().padLeft(2, '0')}:${sStart.minute.toString().padLeft(2, '0')}'
                                            ' – ${session.endTime != null ? '${session.endTime!.hour.toString().padLeft(2, '0')}:${session.endTime!.minute.toString().padLeft(2, '0')}' : 'now'}'
                                            '${isInterrupted
                                                ? '  · interrupted'
                                                : isCompleted
                                                ? '  · completed'
                                                : ''}',
                                        child: Container(
                                          decoration: BoxDecoration(
                                            color: bgColor,
                                            borderRadius: BorderRadius.circular(
                                              4,
                                            ),
                                            border: Border.all(
                                              color: borderColor,
                                              width: 1.5,
                                            ),
                                          ),
                                          clipBehavior: Clip.hardEdge,
                                          child: segs.isEmpty
                                              ? (sw > 30
                                                    ? Align(
                                                        alignment: Alignment
                                                            .centerLeft,
                                                        child: Padding(
                                                          padding:
                                                              const EdgeInsets.symmetric(
                                                                horizontal: 4,
                                                              ),
                                                          child: Text(
                                                            task.title,
                                                            style: TextStyle(
                                                              fontSize: 9,
                                                              color: color
                                                                  .withOpacity(
                                                                    0.9,
                                                                  ),
                                                              fontWeight:
                                                                  FontWeight
                                                                      .w500,
                                                            ),
                                                            overflow:
                                                                TextOverflow
                                                                    .ellipsis,
                                                          ),
                                                        ),
                                                      )
                                                    : null)
                                              // ── Execution-Detail card ──
                                              : Container(
                                                  // Thicker unified border enclosing title + W/R bands
                                                  decoration: BoxDecoration(
                                                    borderRadius:
                                                        BorderRadius.circular(
                                                          4,
                                                        ),
                                                    border: Border.all(
                                                      color: borderColor,
                                                      width: 2.0,
                                                    ),
                                                  ),
                                                  clipBehavior: Clip.hardEdge,
                                                  child: Column(
                                                    crossAxisAlignment:
                                                        CrossAxisAlignment
                                                            .stretch,
                                                    children: [
                                                      // ── Title header ──
                                                      if (sw > 32 && sh > 14)
                                                        Container(
                                                          height: 18,
                                                          color: bgColor,
                                                          padding:
                                                              const EdgeInsets.symmetric(
                                                                horizontal: 5,
                                                              ),
                                                          child: Row(
                                                            crossAxisAlignment:
                                                                CrossAxisAlignment
                                                                    .center,
                                                            children: [
                                                              Icon(
                                                                task
                                                                    .status
                                                                    .icon,
                                                                size: 9,
                                                                color: color,
                                                              ),
                                                              const SizedBox(
                                                                width: 3,
                                                              ),
                                                              Expanded(
                                                                child: Text(
                                                                  task.title,
                                                                  style: TextStyle(
                                                                    fontSize: 9,
                                                                    fontWeight:
                                                                        FontWeight
                                                                            .w600,
                                                                    color: Colors
                                                                        .white
                                                                        .withOpacity(
                                                                          0.9,
                                                                        ),
                                                                    letterSpacing:
                                                                        0.1,
                                                                  ),
                                                                  overflow:
                                                                      TextOverflow
                                                                          .ellipsis,
                                                                  maxLines: 1,
                                                                ),
                                                              ),
                                                            ],
                                                          ),
                                                        ),

                                                      // ── Thin separator ──
                                                      if (sw > 32 && sh > 14)
                                                        Container(
                                                          height: 1,
                                                          color: borderColor
                                                              .withOpacity(0.6),
                                                        ),

                                                      // ── W/R bands ──
                                                      Expanded(
                                                        child: Stack(
                                                          children: [
                                                            Positioned.fill(
                                                              child: Column(
                                                                children: segs.map((
                                                                  s,
                                                                ) {
                                                                  final titleH =
                                                                      sw > 32 &&
                                                                          sh >
                                                                              14
                                                                      ? 19.0
                                                                      : 0.0;
                                                                  final bandH =
                                                                      s.frac *
                                                                      (sh -
                                                                          titleH);
                                                                  final isWork =
                                                                      s.label ==
                                                                      'W';
                                                                  final badgeColor =
                                                                      isWork
                                                                      ? const Color(
                                                                          0xFF4FC3F7,
                                                                        )
                                                                      : const Color(
                                                                          0xFF81C784,
                                                                        );
                                                                  return Expanded(
                                                                    flex:
                                                                        (s.frac *
                                                                                1000)
                                                                            .round()
                                                                            .clamp(
                                                                              1,
                                                                              999,
                                                                            ),
                                                                    child: Container(
                                                                      color: s
                                                                          .color,
                                                                      padding:
                                                                          bandH >
                                                                              14
                                                                          ? const EdgeInsets.only(
                                                                              left: 4,
                                                                              top: 3,
                                                                            )
                                                                          : EdgeInsets.zero,
                                                                      alignment:
                                                                          Alignment
                                                                              .topLeft,
                                                                      // ── W / R badge card ──
                                                                      child:
                                                                          bandH >
                                                                              14
                                                                          ? Container(
                                                                              padding: const EdgeInsets.symmetric(
                                                                                horizontal: 4,
                                                                                vertical: 1,
                                                                              ),
                                                                              decoration: BoxDecoration(
                                                                                color: badgeColor.withOpacity(
                                                                                  0.18,
                                                                                ),
                                                                                borderRadius: BorderRadius.circular(
                                                                                  3,
                                                                                ),
                                                                                border: Border.all(
                                                                                  color: badgeColor.withOpacity(
                                                                                    0.55,
                                                                                  ),
                                                                                  width: 0.8,
                                                                                ),
                                                                              ),
                                                                              child: Text(
                                                                                s.label,
                                                                                style: TextStyle(
                                                                                  fontSize: 7,
                                                                                  fontWeight: FontWeight.w800,
                                                                                  color: badgeColor,
                                                                                  letterSpacing: 0.4,
                                                                                ),
                                                                              ),
