                                                                          : null,
                                                                    ),
                                                                  );
                                                                }).toList(),
                                                              ),
                                                            ),
                                                            // ── Resize handle ──
                                                            if (sh > 18)
                                                              Positioned(
                                                                bottom: 0,
                                                                left: 0,
                                                                right: 0,
                                                                height: 12,
                                                                child: Container(
                                                                  decoration: BoxDecoration(
                                                                    borderRadius:
                                                                        const BorderRadius.vertical(
                                                                          bottom:
                                                                              Radius.circular(
                                                                                4,
                                                                              ),
                                                                        ),
                                                                    gradient: LinearGradient(
                                                                      begin: Alignment
                                                                          .topCenter,
                                                                      end: Alignment
                                                                          .bottomCenter,
                                                                      colors: [
                                                                        Colors
                                                                            .transparent,
                                                                        Colors
                                                                            .black
                                                                            .withOpacity(
                                                                              0.3,
                                                                            ),
                                                                      ],
                                                                    ),
                                                                  ),
                                                                  child: Center(
                                                                    child: Container(
                                                                      width: 20,
                                                                      height: 2,
                                                                      decoration: BoxDecoration(
                                                                        color: Colors
                                                                            .white
                                                                            .withOpacity(
                                                                              0.3,
                                                                            ),
                                                                        borderRadius:
                                                                            BorderRadius.circular(
                                                                              1,
                                                                            ),
                                                                      ),
                                                                    ),
                                                                  ),
                                                                ),
                                                              ),
                                                          ],
                                                        ),
                                                      ),
                                                    ],
                                                  ),
                                                ),
                                        ),
                                      ),
                                    );
                                  });
                                }),
                            ],
                          ),
                        ),
                      ),
                    ),
                  );
                },
              ),
            ),
            _buildBottomBar(),
          ],
        );
      },
    );
  }

  // ── Bottom status bar ──────────────────────────────────────────────────────
  Widget _buildBottomBar() {
    // The hover-slot info is only relevant when creation is active.
    final hasHover =
        !_busy && _isCreationActive && _hoverCol != null && _hoverWY != null;

    // Build the left-side content based on mode and hover state.
    Widget leftContent;

    if (hasHover) {
      // ── Derive slot duration from current zoom (same logic as _buildHint) ──
      final hourH = _bHH * _vScale;
      final int slotMin;
      if (hourH >= 80) {
        slotMin = 5;
      } else if (hourH >= 40) {
        slotMin = 15;
      } else {
        slotMin = 30;
      }

      final int startMin = ((_hoverWY! / _bHH) * 60).round().clamp(
        0,
        23 * 60 + 55,
      );
      final int endMin = (startMin + slotMin).clamp(0, 24 * 60);

      final String startLabel = _fmt12h(startMin ~/ 60, startMin % 60);
      final String endLabel = _fmt12h(endMin ~/ 60, endMin % 60);
      final int pct = (_scale * 100).round();
      final String spanLabel = slotMin >= 60
          ? '${slotMin ~/ 60}h'
          : '$slotMin min';

      leftContent = Row(
        mainAxisSize: MainAxisSize.min,
        children: [
          const Icon(Icons.schedule, size: 11, color: Color(0xFF4FC3F7)),
          const SizedBox(width: 6),
          Text(
            'Span at Current Zoom ($pct%): $spanLabel',
            style: const TextStyle(fontSize: 10, color: Color(0xFF6B7080)),
          ),
          const SizedBox(width: 8),
          const Text(
            '────▶',
            style: TextStyle(fontSize: 9, color: Color(0xFF3A4050)),
          ),
          const SizedBox(width: 8),
          Text(
            'Block: $startLabel – $endLabel',
            style: const TextStyle(
              fontSize: 10,
              color: Color(0xFF4FC3F7),
              fontWeight: FontWeight.w600,
            ),
          ),
        ],
      );
    } else if (_taskCreationMode) {
      // Creation mode is on via toggle but mouse isn't hovering a valid slot.
      leftContent = const Row(
        mainAxisSize: MainAxisSize.min,
        children: [
          Icon(Icons.add_circle_outline, size: 11, color: Color(0xFF4FC3F7)),
          SizedBox(width: 6),
          Text(
            'Task Creation Mode — click on the canvas to place a task',
            style: TextStyle(fontSize: 10, color: Color(0xFF4A6070)),
          ),
        ],
      );
    } else {
      // Default idle state: no creation mode, show a concise hint.
      leftContent = const Row(
        mainAxisSize: MainAxisSize.min,
        children: [
          Icon(Icons.drag_indicator, size: 11, color: Color(0xFF4A4F58)),
          SizedBox(width: 6),
          Text(
            'Drag or resize tasks · Right-click a task for details · Hold Shift or enable Task Creation Mode to add',
            style: TextStyle(fontSize: 10, color: Color(0xFF4A4F58)),
          ),
        ],
      );
    }

    return Container(
      height: 28,
      decoration: const BoxDecoration(
        color: Color(0xFF151718),
        border: Border(top: BorderSide(color: Color(0xFF2C2F32), width: 0.5)),
      ),
      padding: const EdgeInsets.symmetric(horizontal: 10),
      child: Row(
        children: [
          leftContent,
          const Spacer(),
          // ── Task Creation Mode toggle ──────────────────────────────────────
          _buildCreationModeToggle(),
          const SizedBox(width: 10),
          _buildPillColorToggle(),
        ],
      ),
    );
  }

  // ── Task Creation Mode toggle ──────────────────────────────────────────────
  Widget _buildCreationModeToggle() {
    final isOn = _taskCreationMode;
    const accent = Color(0xFF4FC3F7);
    const offTrack = Color(0xFF2A2D32);
    const offBorder = Color(0xFF3A4050);

    return GestureDetector(
      onTap: () => setState(() => _taskCreationMode = !_taskCreationMode),
      child: Tooltip(
        message: isOn
            ? 'Task Creation Mode ON — click to disable'
            : 'Task Creation Mode OFF — click to enable (or hold Shift)',
        child: Row(
          mainAxisSize: MainAxisSize.min,
          children: [
            Icon(
              Icons.add_task_rounded,
              size: 11,
              color: isOn ? accent : const Color(0xFF4A4F58),
            ),
            const SizedBox(width: 4),
            Text(
              'Task Creation',
              style: TextStyle(
                fontSize: 9,
                fontWeight: FontWeight.w600,
                color: isOn ? accent : const Color(0xFF4A4F58),
                letterSpacing: 0.3,
              ),
            ),
            const SizedBox(width: 5),
            AnimatedContainer(
              duration: const Duration(milliseconds: 180),
              width: 28,
              height: 14,
              decoration: BoxDecoration(
                borderRadius: BorderRadius.circular(7),
                color: isOn ? const Color(0xFF1A3A4A) : offTrack,
                border: Border.all(
                  color: isOn ? accent.withOpacity(0.5) : offBorder,
                  width: 1,
                ),
              ),
              child: AnimatedAlign(
                duration: const Duration(milliseconds: 180),
                alignment: isOn ? Alignment.centerRight : Alignment.centerLeft,
                child: Padding(
                  padding: const EdgeInsets.symmetric(horizontal: 2),
                  child: Container(
                    width: 10,
                    height: 10,
                    decoration: BoxDecoration(
                      shape: BoxShape.circle,
                      color: isOn ? accent : const Color(0xFF4A4F58),
                    ),
                  ),
                ),
              ),
            ),
          ],
        ),
      ),
    );
  }

