            Icon(
              isProject ? Icons.folder_outlined : Icons.flag_outlined,
              size: 11,
              color: isProject
                  ? const Color(0xFF4FC3F7)
                  : const Color(0xFF9E9E9E),
            ),
            const SizedBox(width: 4),
            Text(
              isProject ? 'Project' : 'Status',
              style: TextStyle(
                fontSize: 9,
                fontWeight: FontWeight.w600,
                color: isProject
                    ? const Color(0xFF4FC3F7)
                    : const Color(0xFF6B7080),
                letterSpacing: 0.3,
              ),
            ),
            const SizedBox(width: 5),
            AnimatedContainer(
              duration: const Duration(milliseconds: 180),
              width: 28,
              height: 14,
              decoration: BoxDecoration(
                borderRadius: BorderRadius.circular(7),
                color: isProject
                    ? const Color(0xFF1A3A4A)
                    : const Color(0xFF2A2D32),
                border: Border.all(
                  color: isProject
                      ? const Color(0xFF4FC3F7).withOpacity(0.5)
                      : const Color(0xFF3A4050),
                  width: 1,
                ),
              ),
              child: AnimatedAlign(
                duration: const Duration(milliseconds: 180),
