  // ── All-day strip ──────────────────────────────────────────────────────────
  Widget _buildAllDayStrip(
    List<Task> tasks,
    Map<String, int> colMap,
    List<DateTime> days,
    int visibleDays,
    double cw,
  ) {
    final Map<int, List<Task>> byCol = {};
    for (final t in tasks) {
      final c = colMap[t.id]!;
      (byCol[c] ??= []).add(t);
    }

    final int totalTasks = tasks.length;
    final int maxRows = byCol.values
        .fold(0, (m, l) => l.length > m ? l.length : m)
        .clamp(1, 4);
    final double expandedH = maxRows * 22.0 + 8.0;

    // Collapsed bar height: always 22px, shows count badge + chevron.
    const double collapsedH = 22.0;

    final bool hasEvents = totalTasks > 0;

    return AnimatedContainer(
      duration: const Duration(milliseconds: 180),
      curve: Curves.easeInOut,
      height: (_allDayExpanded && hasEvents) ? expandedH : collapsedH,
      decoration: const BoxDecoration(
        color: Color(0xFF181A1C),
        border: Border(
          bottom: BorderSide(color: Color(0xFF2C2F32), width: 0.5),
        ),
      ),
      child: Row(
        crossAxisAlignment: CrossAxisAlignment.start,
        children: [
          // Time-column side: toggle button
          GestureDetector(
            onTap: hasEvents
                ? () => setState(() => _allDayExpanded = !_allDayExpanded)
                : null,
            child: Container(
              width: _tCW,
              height: collapsedH,
              alignment: Alignment.center,
              padding: const EdgeInsets.only(right: 4),
              child: Row(
                mainAxisAlignment: MainAxisAlignment.end,
                children: [
                  if (hasEvents && !_allDayExpanded)
                    Container(
                      padding: const EdgeInsets.symmetric(
                        horizontal: 4,
                        vertical: 1,
                      ),
                      decoration: BoxDecoration(
                        color: const Color(0xFF4FC3F7).withOpacity(0.18),
                        borderRadius: BorderRadius.circular(8),
                      ),
                      child: Text(
                        '$totalTasks',
                        style: const TextStyle(
                          fontSize: 8,
                          color: Color(0xFF4FC3F7),
                          fontWeight: FontWeight.w600,
                        ),
                      ),
                    ),
                  const SizedBox(width: 2),
                  AnimatedRotation(
                    turns: (_allDayExpanded && hasEvents) ? 0.25 : 0.0,
                    duration: const Duration(milliseconds: 180),
                    child: Icon(
                      Icons.chevron_right,
                      size: 14,
                      color: hasEvents
                          ? const Color(0xFF6B7080)
                          : const Color(0xFF3A3F48),
                    ),
                  ),
                ],
              ),
            ),
          ),
          // Content area: tasks (only visible when expanded)
          Expanded(
            child: ClipRect(
              child: _allDayExpanded && hasEvents
                  ? Transform.translate(
                      offset: Offset(_ox, 0),
                      child: Row(
                        mainAxisSize: MainAxisSize.min,
                        crossAxisAlignment: CrossAxisAlignment.start,
                        children: List.generate(visibleDays, (c) {
                          final colTasks = byCol[c] ?? [];
                          return SizedBox(
                            width: cw,
                            child: Padding(
                              padding: const EdgeInsets.fromLTRB(2, 3, 2, 3),
                              child: Column(
                                crossAxisAlignment: CrossAxisAlignment.start,
                                mainAxisSize: MainAxisSize.min,
                                children: colTasks.take(4).map((t) {
                                  return Container(
                                    height: 18,
                                    margin: const EdgeInsets.only(bottom: 2),
                                    padding: const EdgeInsets.symmetric(
                                      horizontal: 5,
                                    ),
                                    decoration: BoxDecoration(
                                      color: const Color(
                                        0xFF4FC3F7,
                                      ).withOpacity(0.15),
                                      borderRadius: BorderRadius.circular(3),
                                      border: Border.all(
                                        color: const Color(
                                          0xFF4FC3F7,
                                        ).withOpacity(0.35),
                                        width: 0.5,
                                      ),
                                    ),
                                    child: Align(
                                      alignment: Alignment.centerLeft,
                                      child: Text(
                                        t.title,
                                        style: const TextStyle(
                                          fontSize: 10,
                                          color: Colors.white70,
                                        ),
                                        overflow: TextOverflow.ellipsis,
                                        maxLines: 1,
                                      ),
                                    ),
                                  );
                                }).toList(),
                              ),
                            ),
                          );
                        }),
                      ),
                    )
                  : const SizedBox.shrink(),
            ),
          ),
        ],
      ),
    );
  }

  // ── Header ─────────────────────────────────────────────────────────────────
  Widget _buildHeader(
    List<DateTime> days,
    DateTime today,
    int visibleDays,
    double cw,
  ) {
    const names = ['Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat', 'Sun'];
    const monthNames = [
      '',
      'Jan',
      'Feb',
      'Mar',
      'Apr',
      'May',
      'Jun',
      'Jul',
      'Aug',
      'Sep',
      'Oct',
      'Nov',
      'Dec',
    ];
    final bool showDayName = cw > 44;
    final bool showDay = cw > 14;
    final bool showDot = cw > 30;
    final double fontSize = (cw * 0.38).clamp(6.0, 13.0);
    final double nameFontSize = (cw * 0.30).clamp(5.0, 11.0);

    // Two-row mode: range spans two months AND horizontal zoom <= 25 %
    final bool twoRow =
        _hScale <= 0.25 &&
        days.isNotEmpty &&
        days.first.month != days.last.month;
    const double monthRowH = 16.0;
    const double dayRowH = _hdrH - monthRowH;

    return Container(
      height: _hdrH,
      decoration: const BoxDecoration(
        color: Color(0xFF1A1C1E),
        border: Border(
          bottom: BorderSide(color: Color(0xFF2C2F32), width: 0.5),
        ),
      ),
      child: Row(
        children: [
          SizedBox(width: _tCW),
          Expanded(
            child: ClipRect(
              child: Transform.translate(
                offset: Offset(_ox, 0),
                child: twoRow
                    // ── Two-row layout ─────────────────────────────────
                    ? Column(
                        mainAxisSize: MainAxisSize.min,
                        crossAxisAlignment: CrossAxisAlignment.start,
                        children: [
                          // Top row: month label at start of each new month
                          SizedBox(
                            height: monthRowH,
                            child: Row(
                              mainAxisSize: MainAxisSize.min,
                              children: List.generate(visibleDays, (i) {
                                final d = days[i];
                                final showMonth = i == 0 || d.day == 1;
                                final monthLabel = cw < 14
                                    ? '${d.month}'
                                    : monthNames[d.month];
                                return SizedBox(
                                  width: cw,
                                  child: showMonth
                                      ? Padding(
                                          padding: const EdgeInsets.only(
                                            left: 4,
                                          ),
                                          child: Text(
                                            monthLabel,
                                            overflow: TextOverflow.clip,
                                            style: TextStyle(
                                              fontSize: (cw * 0.32).clamp(
                                                6.0,
                                                11.0,
                                              ),
                                              fontWeight: FontWeight.w600,
                                              color:
                                                  d.month ==
                                                      DateTime.now().month
                                                  ? const Color(0xFF4FC3F7)
                                                  : Colors.white54,
                                            ),
                                          ),
                                        )
                                      : const SizedBox.shrink(),
                                );
                              }),
                            ),
                          ),
                          // Bottom row: day numbers
                          Expanded(
                            child: Row(
                              mainAxisSize: MainAxisSize.min,
                              children: List.generate(visibleDays, (i) {
                                final d = days[i];
                                final isToday = d == today;
                                return SizedBox(
                                  width: cw,
                                  child: Container(
                                    decoration: BoxDecoration(
                                      color: isToday
                                          ? const Color(
                                              0xFF4FC3F7,
                                            ).withOpacity(0.05)
                                          : Colors.transparent,
                                      border: const Border(
                                        left: BorderSide(
                                          color: Color(0xFF2A2D30),
                                          width: 0.5,
                                        ),
                                      ),
                                    ),
                                    child: Center(
                                      child: cw < 6
                                          ? const SizedBox.shrink()
                                          : Row(
                                              mainAxisSize: MainAxisSize.min,
                                              children: [
                                                if (isToday && showDot)
                                                  Container(
                                                    width: (cw * 0.12).clamp(
                                                      3.0,
                                                      5.0,
                                                    ),
                                                    height: (cw * 0.12).clamp(
                                                      3.0,
                                                      5.0,
                                                    ),
                                                    margin:
                                                        const EdgeInsets.only(
                                                          right: 3,
                                                        ),
                                                    decoration:
                                                        const BoxDecoration(
                                                          color: Color(
                                                            0xFF4FC3F7,
                                                          ),
                                                          shape:
                                                              BoxShape.circle,
                                                        ),
                                                  ),
                                                if (showDay)
                                                  Text(
                                                    '${d.day}',
                                                    overflow: TextOverflow.clip,
                                                    style: TextStyle(
                                                      fontSize: (cw * 0.38)
                                                          .clamp(5.0, 11.0),
                                                      fontWeight:
                                                          FontWeight.w700,
                                                      color: isToday
                                                          ? const Color(
                                                              0xFF4FC3F7,
                                                            )
                                                          : Colors.white70,
                                                    ),
                                                  ),
                                              ],
                                            ),
                                    ),
                                  ),
                                );
                              }),
                            ),
                          ),
                        ],
                      )
                    // ── Single-row layout (default) ─────────────────────
                    : Row(
                        mainAxisSize: MainAxisSize.min,
                        children: List.generate(visibleDays, (i) {
                          final d = days[i];
                          final isToday = d == today;
                          final name = names[d.weekday - 1];
                          return SizedBox(
                            width: cw,
                            child: Container(
                              decoration: BoxDecoration(
                                color: isToday
                                    ? const Color(0xFF4FC3F7).withOpacity(0.05)
                                    : Colors.transparent,
                                border: const Border(
                                  left: BorderSide(
                                    color: Color(0xFF2A2D30),
                                    width: 0.5,
                                  ),
                                ),
                              ),
                              child: Center(
                                child: cw < 6
                                    ? const SizedBox.shrink()
                                    : Row(
                                        mainAxisSize: MainAxisSize.min,
                                        children: [
                                          if (isToday && showDot)
                                            Container(
                                              width: (cw * 0.12).clamp(
                                                3.0,
                                                6.0,
                                              ),
                                              height: (cw * 0.12).clamp(
                                                3.0,
                                                6.0,
                                              ),
                                              margin: EdgeInsets.only(
                                                right: showDayName ? 5.0 : 3.0,
                                              ),
                                              decoration: const BoxDecoration(
                                                color: Color(0xFF4FC3F7),
                                                shape: BoxShape.circle,
                                              ),
                                            ),
                                          if (showDay)
                                            RichText(
                                              overflow: TextOverflow.clip,
                                              text: TextSpan(
                                                children: [
                                                  TextSpan(
                                                    text: showDayName
                                                        ? '${d.day} '
                                                        : '${d.day}',
                                                    style: TextStyle(
                                                      fontSize: fontSize,
                                                      fontWeight:
                                                          FontWeight.w700,
                                                      color: isToday
                                                          ? const Color(
                                                              0xFF4FC3F7,
                                                            )
                                                          : Colors.white70,
                                                    ),
                                                  ),
                                                  if (showDayName)
                                                    TextSpan(
                                                      text: name,
                                                      style: TextStyle(
                                                        fontSize: nameFontSize,
                                                        color: isToday
                                                            ? const Color(
                                                                0xFF4FC3F7,
                                                              ).withOpacity(0.8)
                                                            : Colors.white38,
                                                      ),
                                                    ),
                                                ],
                                              ),
                                            ),
                                        ],
                                      ),
                              ),
                            ),
                          );
                        }),
                      ),
              ),
            ),
          ),
        ],
      ),
    );
  }

  // ── Hover hint ─────────────────────────────────────────────────────────────
  Widget _buildHint(int col, double wY, double cw) {
    final hourH = _bHH * _vScale;

    // Match the height to exactly one grid subdivision at the current zoom
    final double slotH;
    if (hourH >= 80) {
      slotH = hourH / 12; // 5-min slot
    } else if (hourH >= 40) {
      slotH = hourH / 4; // 15-min slot
    } else {
      slotH = hourH / 2; // 30-min slot
    }

    final sx = _sx(col, cw) + 3;
    final sy = _sy(wY);
    final w = (cw - 6).clamp(20.0, double.infinity);
    final totalMin = ((wY / _bHH) * 60).round().clamp(0, 23 * 60 + 55);
    final h = totalMin ~/ 60;
    final m = totalMin % 60;

    return Positioned(
      left: sx,
      top: sy,
      width: w,
      height: slotH,
      child: IgnorePointer(
        child: Container(
          decoration: BoxDecoration(
            color: const Color(0xFF4FC3F7).withOpacity(0.10),
            borderRadius: BorderRadius.circular(3),
            border: Border.all(
              color: const Color(0xFF4FC3F7).withOpacity(0.40),
              width: 0.8,
            ),
          ),
          child: slotH >= 14
              ? Padding(
                  padding: const EdgeInsets.symmetric(horizontal: 5),
                  child: Row(
                    children: [
                      if (slotH >= 16)
                        Expanded(
                          child: Text(
                            _fmt12h(h, m),
                            style: const TextStyle(
                              fontSize: 9,
                              color: Color(0xFF4FC3F7),
                              fontWeight: FontWeight.w600,
                            ),
                            overflow: TextOverflow.clip,
                            softWrap: false,
                          ),
                        ),
                      const Icon(Icons.add, size: 11, color: Color(0xFF4FC3F7)),
                    ],
                  ),
                )
              : const SizedBox.shrink(),
        ),
      ),
    );
  }

  // ── Now line ───────────────────────────────────────────────────────────────
  List<Widget> _buildNowLine(DateTime now, int todayCol) {
    final nowWY = (now.hour + now.minute / 60.0) * _bHH;
    final sy = _sy(nowWY);
    if (sy < 0 || sy > _scrollH) return [];
    return [
      Positioned(
        top: sy,
        left: _tCW - 5,
        right: 0,
        child: Row(
          children: [
            Container(
              width: 10,
              height: 10,
              decoration: const BoxDecoration(
                color: Color(0xFFEF5350),
                shape: BoxShape.circle,
              ),
            ),
            Expanded(
              child: Container(height: 1.5, color: const Color(0xFFEF5350)),
            ),
          ],
        ),
      ),
    ];
  }

  // ── Task card ──────────────────────────────────────────────────────────────
  Widget _buildCard(Task t, int origCol, double cw, {double opacity = 1.0}) {
    final due = t.scheduledDateTime;
    if (due == null)
      return const Positioned(top: 0, left: 0, child: SizedBox.shrink());
    final isDragging = _dragId == t.id;
    final isResizing = _resizeId == t.id;

    final int curCol = isDragging ? _dragCurCol : origCol;
    final double worldY = isDragging
        ? _dragCurWY
        : (due.hour + due.minute / 60.0) * _bHH;
    final double worldH = isResizing
        ? _resizeCurH
        : (t.durationMinutes.clamp(5, 24 * 60) / 60.0) * _bHH;

    // Horizontal: cw (no _scale). Vertical: _vScale applied.
    final double gutter = cw >= 12 ? 3.0 : (cw * 0.25).floorToDouble();
    final sx = _sx(curCol, cw) + gutter;
    final sy = _sy(worldY) + 2;
    final sw = (cw - gutter * 2).clamp(1.0, double.infinity);
    final sh = (worldH * _vScale - 4).clamp(6.0, double.infinity);

    // ── Bug fix: viewport height for culling ────────────────────────────────
    // _scrollH is populated by the inner LayoutBuilder and is 0 on the very
    // first build frame (before the layout pass completes). Using 0 makes
    // "sy > _scrollH" true for every card with a positive screen-Y, silently
    // culling all scheduled task cards on load.
    // Fix: fall back to _canvasH (set by the outer LayoutBuilder, which runs
    // before the inner one) when _scrollH has not yet been measured.
    final double viewH = _scrollH > 0
        ? _scrollH
        : (_canvasH > 0 ? _canvasH : double.infinity);

    // Cull only cards that are entirely outside the viewport.
    // "sy + sh < 0"   → card is above the top edge (scrolled past).
    // "sy > viewH"    → card TOP is below the bottom edge (not yet scrolled to).
    // Using sy > viewH (not sy + sh > viewH) means a card that starts inside
    // the viewport but extends past midnight is never wrongly culled.
    if (kDebugPlanner) {
      // ignore: avoid_print
      print(
        '[Planner] id=${t.id} plannedAt=${t.plannedAt} '
        'scheduledDateTime=$due worldY=$worldY sy=$sy sh=$sh '
        'durationMinutes=${t.durationMinutes} viewH=$viewH '
        '_scrollH=$_scrollH _canvasH=$_canvasH',
      );
    }

    if (sx + sw < _tCW || sx > _canvasW || sy + sh < 0 || sy > viewH) {
      return const Positioned(top: 0, left: 0, child: SizedBox.shrink());
    }

    return Positioned(
      left: sx,
      top: sy,
      width: sw,
      height: sh,
      child: GestureDetector(
        // Feature 8: right-click opens the standard task context menu
        onSecondaryTapDown: (d) =>
            widget.onContextMenu?.call(t, d.globalPosition),
        child: Listener(
          behavior: HitTestBehavior.opaque,
          onPointerDown: (e) {
            if (e.localPosition.dy > sh - 12) {
              setState(() {
                _resizeId = t.id;
                _resizeOrigH = worldH;
                _resizeCurH = worldH;
                _resizePtrOrigin = e.position;
              });
            } else {
              setState(() {
                _dragId = t.id;
                _dragOrigCol = origCol;
                _dragCurCol = origCol;
                _dragOrigWY = worldY;
                _dragCurWY = worldY;
                _dragPtrOrigin = e.position;
              });
            }
          },
          onPointerMove: (e) {
            if (_dragId == t.id) {
              final gd = e.position - _dragPtrOrigin;
              final rawWY = _dragOrigWY + gd.dy / _vScale;
              // Horizontal delta maps directly (cw is in screen px, no _scale)
              final rawSX = _sx(_dragOrigCol, cw) + gd.dx;
              final newCol = _colFromSX(
                rawSX - cw * 0.5,
                cw,
              ).clamp(0, _visibleDays - 1);
              setState(() {
                _dragCurWY = _snapWY(rawWY);
                _dragCurCol = newCol;
              });
            } else if (_resizeId == t.id) {
              final gd = e.position - _resizePtrOrigin;
              setState(() {
                _resizeCurH = _snapWH(_resizeOrigH + gd.dy / _vScale);
              });
            }
          },
          onPointerUp: (e) {
            if (_dragId == t.id) {
              final slot = _slotFromWorld(_dragCurCol, _dragCurWY);
              t.dueDay = slot.toIso8601String().split('T').first;
              t.plannedAt = slot.millisecondsSinceEpoch;
              widget.onTaskUpdated(t);
              setState(() {
                _dragId = null;
              });
            } else if (_resizeId == t.id) {
              t.durationMinutes = (_resizeCurH / _bHH * 60).round().clamp(
                5,
                24 * 60,
              );
              widget.onTaskUpdated(t);
              setState(() {
                _resizeId = null;
              });
            }
          },
          onPointerCancel: (_) => setState(() {
            _dragId = null;
            _resizeId = null;
          }),
          child: Builder(
            builder: (_) {
              final pillColor = _pillColorByProject
                  ? (widget.projectColors[t.projectId] ?? t.status.color)
                  : t.status.color;
              final projName = widget.projects[t.projectId]?.title;
              return opacity < 1.0
                  ? Opacity(
                      opacity: opacity,
                      child: _ScheduleCardContent(
                        task: t,
                        screenH: sh,
                        scale: _vScale,
                        isActive: isDragging || isResizing,
                        pillColor: pillColor,
                        projectName: projName,
                      ),
                    )
                  : _ScheduleCardContent(
                      task: t,
                      screenH: sh,
                      scale: _vScale,
                      isActive: isDragging || isResizing,
                      pillColor: pillColor,
                      projectName: projName,
                    );
            },
          ),
        ), // closes Listener
      ), // closes GestureDetector (Feature 8 right-click)
    );
  }

  // ── Project colour helpers ────────────────────────────────────────────────
  static const List<Color> _palette = [
    Color(0xFF7986CB),
    Color(0xFF4DD0E1),
    Color(0xFFAED581),
    Color(0xFFFFD54F),
    Color(0xFFFF8A65),
    Color(0xFFF06292),
    Color(0xFF4DB6AC),
    Color(0xFF90CAF9),
    Color(0xFFF48FB1),
  ];

  Color _projectColor(String projectId, int idx) =>
      _palette[idx % _palette.length];

  // ── Build work/rest segment bars for a session block (Execution–Detail) ──
  List<_SegBlock> _buildSessionSegs(
    _ExecutionSession session,
    Color taskColor,
  ) {
    final blocks = session.blocksSnapshot;
    if (blocks.isEmpty) return [];
    final totalMs = blocks.fold<int>(0, (s, b) => s + b.minutes) * 60000;
    if (totalMs == 0) return [];
    final durMs = session.duration.inMilliseconds;
    final segs = <_SegBlock>[];
    int remaining = durMs;
    for (final b in blocks) {
      if (remaining <= 0) break;
      final blockMs = b.minutes * 60000;
      final covered = remaining >= blockMs ? blockMs : remaining;
      segs.add(
        _SegBlock(
          frac: covered / durMs,
          color: b.type == _StagingType.work
              ? const Color(0xFF4FC3F7).withOpacity(0.65)
              : const Color(0xFF81C784).withOpacity(0.5),
          label: b.type == _StagingType.work ? 'W' : 'R',
        ),
      );
      remaining -= covered;
    }
    return segs;
  }
}

// ─────────────────────────────────────────────────────────────────────────────
// _ScheduleGridPainter
// ─────────────────────────────────────────────────────────────────────────────

class _ScheduleGridPainter extends CustomPainter {
  final double scale, ox, oy, colW, bHH, tCW, padT, padB;
  final int todayCol;
  final int visibleDays;

  const _ScheduleGridPainter({
    required this.scale,
    required this.ox,
    required this.oy,
    required this.colW,
    required this.bHH,
    required this.tCW,
    required this.padT,
    required this.padB,
    required this.todayCol,
    required this.visibleDays,
  });

  @override
  void paint(Canvas canvas, Size size) {
    final hourH = bHH * scale; // scaled pixel height of one hour
    final dayH = 24 * hourH; // total height of the 24-hour block

    // Origin of hour-0 in screen coords
    final originY = oy + padT;

    // ── Paints ────────────────────────────────────────────────────────────────
    final hourPaint = Paint()
      ..color = const Color(0xFF2E3135)
      ..strokeWidth = 0.6;
    final halfPaint = Paint()
      ..color = const Color(0xFF262A2D)
      ..strokeWidth = 0.5;
    final qtrPaint = Paint()
      ..color = const Color(0xFF222528)
      ..strokeWidth = 0.4;
    final minPaint = Paint()
      ..color = const Color(0xFF1E2124)
      ..strokeWidth = 0.3;
    final colPaint = Paint()
      ..color = const Color(0xFF2A2D30)
      ..strokeWidth = 0.5;
    final padPaint = Paint()..color = const Color(0xFF0E0F10);

    // ── Top pad zone (above 12 AM) ────────────────────────────────────────────
    final topPadBottom = originY.clamp(0.0, size.height);
    if (topPadBottom > 0) {
      canvas.drawRect(
        Rect.fromLTWH(tCW, 0, size.width - tCW, topPadBottom),
        padPaint,
      );
    }

    // ── Bottom pad zone (below 11:55 PM) ──────────────────────────────────────
    final bottomPadTop = (originY + dayH).clamp(0.0, size.height);
    if (bottomPadTop < size.height) {
      canvas.drawRect(
        Rect.fromLTWH(
          tCW,
          bottomPadTop,
          size.width - tCW,
          size.height - bottomPadTop,
        ),
        padPaint,
      );
    }

    // ── Time column background ────────────────────────────────────────────────
    canvas.drawRect(
      Rect.fromLTWH(0, 0, tCW, size.height),
      Paint()..color = const Color(0xFF151718),
    );

    // ── Today column tint ─────────────────────────────────────────────────────
    if (todayCol >= 0) {
      final x = todayCol * colW + ox + tCW;
      canvas.drawRect(
        Rect.fromLTWH(
          x.clamp(tCW, size.width),
          0,
          colW.clamp(0, size.width - tCW),
          size.height,
        ),
        Paint()..color = const Color(0xFF4FC3F7).withOpacity(0.03),
      );
    }

    // ── Sub-hour lines ────────────────────────────────────────────────────────
    final bool show15 = hourH >= 40;
    final bool show5 = hourH >= 80;

    if (show5 || show15) {
      final int steps = show5 ? 12 : 4;
      for (int h = 0; h < 24; h++) {
        for (int s = 1; s < steps; s++) {
          final y = (h + s / steps) * hourH + originY;
          if (y < 0 || y > size.height) continue;
          final bool isHalf = s == steps ~/ 2;
          final Paint p = isHalf ? halfPaint : (show5 ? minPaint : qtrPaint);
          final double indent = isHalf ? tCW + 8 : tCW + 16;
          canvas.drawLine(Offset(indent, y), Offset(size.width, y), p);
        }
      }
    } else {
      for (int h = 0; h < 24; h++) {
        final y2 = (h + 0.5) * hourH + originY;
        if (y2 >= 0 && y2 <= size.height) {
          canvas.drawLine(
            Offset(tCW + 8, y2),
            Offset(size.width, y2),
            halfPaint,
          );
        }
      }
    }

    // ── Hour lines + labels ───────────────────────────────────────────────────
    final labelStyle = TextStyle(
      fontSize: (8 + scale * 1.5).clamp(9.0, 13.0),
      color: const Color(0xFF8A9099),
      fontWeight: FontWeight.w500,
    );

    for (int h = 0; h <= 24; h++) {
      final y = h * hourH + originY;
      if (y < -20 || y > size.height + 1) continue;

      if (y >= 0) {
        canvas.drawLine(Offset(tCW, y), Offset(size.width, y), hourPaint);
      }

      if (h < 24) {
        final label = h == 0 ? '12 AM' : _labelFor(h);
        final tp = TextPainter(
          text: TextSpan(text: label, style: labelStyle),
          textDirection: TextDirection.ltr,
        )..layout(maxWidth: tCW - 6);
        final labelY = y - tp.height * 0.5;
        if (labelY + tp.height >= 0 && labelY <= size.height) {
          tp.paint(canvas, Offset(tCW - tp.width - 5, labelY));
        }
      }
    }

    // ── Column dividers ───────────────────────────────────────────────────────
    for (int c = 0; c <= visibleDays; c++) {
      final x = c * colW + ox + tCW;
      if (x < tCW - 1 || x > size.width + 1) continue;
      canvas.drawLine(Offset(x, 0), Offset(x, size.height), colPaint);
    }

    // ── Time column right border ──────────────────────────────────────────────
    canvas.drawLine(
      Offset(tCW, 0),
      Offset(tCW, size.height),
      Paint()
        ..color = const Color(0xFF2C2F32)
        ..strokeWidth = 0.5,
    );
  }

  String _labelFor(int h) {
    if (h == 12) return '12 PM';
    final period = h < 12 ? 'AM' : 'PM';
    final hh = h > 12 ? h - 12 : h;
    return '$hh $period';
  }

  @override
  bool shouldRepaint(_ScheduleGridPainter o) =>
      o.scale != scale ||
      o.ox != ox ||
      o.oy != oy ||
      o.colW != colW ||
      o.bHH != bHH ||
      o.padT != padT ||
      o.padB != padB ||
      o.todayCol != todayCol ||
      o.visibleDays != visibleDays ||
      o.tCW != tCW;
}

// ─────────────────────────────────────────────────────────────────────────────
// _ScheduleCardContent
// ─────────────────────────────────────────────────────────────────────────────

class _ScheduleCardContent extends StatelessWidget {
  final Task task;
  final double screenH;
  final double scale;
  final bool isActive;
  final Color? pillColor;
  final String? projectName;

  const _ScheduleCardContent({
    Key? key,
    required this.task,
    required this.screenH,
    required this.scale,
    required this.isActive,
    this.pillColor,
    this.projectName,
  }) : super(key: key);

  @override
  Widget build(BuildContext context) {
    final color = pillColor ?? task.status.color;
    final isLight = AppTheme.of(context).isLight;
    final minFontSize = 8.0;

    // Features 4 & 5: override border when fill luminance is too dark/light
    final contrastBorder = adaptiveBorder(color, isLight);

    return MouseRegion(
      cursor: SystemMouseCursors.grab,
      child: Container(
        decoration: BoxDecoration(
          color: color.withOpacity(isActive ? 0.32 : 0.18),
          borderRadius: BorderRadius.circular(5),
          border:
              contrastBorder ??
              Border.all(
                color: color.withOpacity(isActive ? 0.85 : 0.5),
                width: isActive ? 1.5 : 1,
              ),
          boxShadow: isActive
              ? [
                  BoxShadow(
                    color: Colors.black.withOpacity(0.35),
                    blurRadius: 10,
                    offset: const Offset(2, 5),
                  ),
                ]
              : null,
        ),
        clipBehavior: Clip.hardEdge,
        child: Stack(
          children: [
            // Content
            Padding(
              padding: EdgeInsets.fromLTRB(5, 3, 4, screenH > 18 ? 14 : 3),
              child: LayoutBuilder(
                builder: (context, constraints) {
                  final availW = constraints.maxWidth;
                  final double iconSize = (10 * scale).clamp(minFontSize, 14);
                  // Only show icon if it fits (icon + 4px gap)
                  final showIcon = screenH > 8 && availW >= iconSize + 4;
                  final showText =
                      screenH > 16 && availW > (showIcon ? iconSize + 4 : 0);
                  final showProject =
                      screenH > 28 && projectName != null && projectName!.isNotEmpty;
                  if (!showIcon && !showText) return const SizedBox.shrink();
                  return Column(
                    crossAxisAlignment: CrossAxisAlignment.start,
                    mainAxisSize: MainAxisSize.max,
                    children: [
                      // ── Project name ──────────────────────────────────
                      if (showProject) ...[
                        Text(
                          projectName!,
                          style: TextStyle(
                            fontSize: (9 * scale).clamp(7.0, 10.0),
                            color: color.withOpacity(0.75),
                            fontWeight: FontWeight.w600,
                            letterSpacing: 0.2,
                          ),
                          overflow: TextOverflow.ellipsis,
                          maxLines: 1,
                        ),
                        const SizedBox(height: 1),
                      ],
                      // ── Status icon + title ───────────────────────────
                      Expanded(
                        child: Row(
                          crossAxisAlignment: CrossAxisAlignment.center,
                          children: [
                            if (showIcon) ...[
                              Icon(
                                task.status.icon,
                                size: iconSize,
                                color: color,
                              ),
                              const SizedBox(width: 4),
                            ],
                            if (showText)
                              Expanded(
                                child: Text(
                                  task.title,
                                  style: TextStyle(
                                    fontSize: (11 * scale).clamp(minFontSize, 13),
                                    color: Colors.white.withOpacity(0.88),
                                    fontWeight: FontWeight.w500,
                                  ),
                                  overflow: TextOverflow.ellipsis,
                                  maxLines: (screenH / 14).floor().clamp(1, 20),
                                ),
                              ),
                          ],
                        ),
                      ),
                    ],
                  );
                },
              ),
            ),
            // Resize handle
            if (screenH > 18)
              Positioned(
                bottom: 0,
                left: 0,
                right: 0,
                height: 12,
                child: MouseRegion(
                  cursor: SystemMouseCursors.resizeRow,
                  child: Container(
                    decoration: BoxDecoration(
                      borderRadius: const BorderRadius.vertical(
                        bottom: Radius.circular(5),
                      ),
                      gradient: LinearGradient(
                        begin: Alignment.topCenter,
                        end: Alignment.bottomCenter,
                        colors: [Colors.transparent, color.withOpacity(0.35)],
                      ),
                    ),
                    child: Center(
                      child: Container(
                        width: 20,
                        height: 2,
                        decoration: BoxDecoration(
                          color: color.withOpacity(0.6),
                          borderRadius: BorderRadius.circular(1),
                        ),
                      ),
                    ),
                  ),
                ),
              ),
          ],
        ),
      ),
    );
  }
}

// ─────────────────────────────────────────────────────────────────────────────
// _TaskRow  –  individual task list card with hover-revealed action buttons
// ─────────────────────────────────────────────────────────────────────────────

class _TaskRow extends StatefulWidget {
  final Task task;
  final DateTime today;
  final Set<String> allSubtaskIds;

  /// Overrides task.timeSpent — use when subtasks aggregate to parent.
  final int? effectiveTimeSpentMs;

  /// Overrides task.durationMinutes — use when subtasks aggregate to parent.
  final int? effectiveDurationMinutes;
  final Map<String, Project> projects;
  final Map<String, String> projectIcons;
  final List<Task> allTasks;
  final String? activeTimerTaskId;
  final String? activeStagingTaskId;
  final VoidCallback? onStopStaging;
  final String? activeFlowtimeTaskId;
  final VoidCallback? onFlowtimeToggle;
  final Map<String, bool> taskDetailExpanded;
  final String Function() formatElapsed;
  final VoidCallback onStatusToggle;
  final void Function(TaskStatus) onStatusSelect;
  final VoidCallback onTimerToggle;
  final VoidCallback? onStagingToggle;
  final bool stagingWasInterrupted;
  final VoidCallback onDetailToggle;
  final VoidCallback? onSubtasksToggle;
  final bool subtasksExpanded;
  final VoidCallback? onRepeatInstancesToggle;
  final bool repeatInstancesExpanded;
  final int repeatInstanceCount;
  final void Function(Offset globalPos)? onContextMenu;
  final void Function(String newTitle)? onRename;

  /// If provided, replaces the default drag-indicator icon with this widget
  /// (typically a [ReorderableDragStartListener]-wrapped icon).
  final Widget? dragHandle;

  /// Horizontal margin on each side between the card and the list edge (distance_d).
  final double horizPadding;

  /// Called when the user picks a new date from the date chip.
  final void Function(String isoDay, int? plannedAt)? onDateChanged;

  const _TaskRow({
    Key? key,
    required this.task,
    required this.today,
    required this.allSubtaskIds,
    required this.projects,
    required this.projectIcons,
    required this.allTasks,
    required this.activeTimerTaskId,
    this.activeStagingTaskId,
    this.onStopStaging,
    this.activeFlowtimeTaskId,
    this.onFlowtimeToggle,
    required this.taskDetailExpanded,
    required this.formatElapsed,
    required this.onStatusToggle,
    required this.onStatusSelect,
    required this.onTimerToggle,
    this.onStagingToggle,
    this.stagingWasInterrupted = false,
    required this.onDetailToggle,
    this.onSubtasksToggle,
    this.subtasksExpanded = false,
    this.onRepeatInstancesToggle,
    this.repeatInstancesExpanded = false,
    this.repeatInstanceCount = 0,
    this.onContextMenu,
    this.onRename,
    this.dragHandle,
    this.onDateChanged,
    this.effectiveTimeSpentMs,
    this.effectiveDurationMinutes,
    this.horizPadding = 12.0,
  }) : super(key: key);

  @override
  State<_TaskRow> createState() => _TaskRowState();
}

class _TaskRowState extends State<_TaskRow> {
  bool _hovered = false;
  // Prevents the card-level right-click menu from also firing when the
  // status icon is right-clicked.
  bool _suppressNextContextMenu = false;
  bool _editing = false;
  late TextEditingController _titleCtrl;
  final FocusNode _titleFocus = FocusNode();
  final GlobalKey _dateChipKey = GlobalKey();

  @override
  void initState() {
    super.initState();
    _titleCtrl = TextEditingController(text: widget.task.title);
    _titleFocus.addListener(() {
      if (!_titleFocus.hasFocus && _editing) _commitEdit();
    });
  }

  @override
  void didUpdateWidget(_TaskRow old) {
    super.didUpdateWidget(old);
    if (!_editing && old.task.title != widget.task.title) {
      _titleCtrl.text = widget.task.title;
    }
  }

  @override
  void dispose() {
    _titleCtrl.dispose();
    _titleFocus.dispose();
    super.dispose();
  }

  void _startEdit() {
    setState(() {
      _editing = true;
      _titleCtrl.text = widget.task.title;
      _titleCtrl.selection = TextSelection(
        baseOffset: 0,
        extentOffset: _titleCtrl.text.length,
      );
    });
    WidgetsBinding.instance.addPostFrameCallback(
      (_) => FocusScope.of(context).requestFocus(_titleFocus),
    );
  }

  void _commitEdit() {
    final newTitle = _titleCtrl.text.trim();
    setState(() => _editing = false);
    if (newTitle.isNotEmpty && newTitle != widget.task.title) {
      widget.onRename?.call(newTitle);
    } else {
      _titleCtrl.text = widget.task.title; // revert if empty or unchanged
    }
  }

  @override
  Widget build(BuildContext context) {
    final task = widget.task;
    final bool isSubtask = widget.allSubtaskIds.contains(task.id);
    final bool isDone =
        task.status == TaskStatus.done || task.status == TaskStatus.cancelled;
    final bool timerActive = widget.activeTimerTaskId == task.id;
    final bool detailActive = widget.taskDetailExpanded[task.id] ?? false;

    DateTime? dueDate;
    bool isOverdue = false;
    String? dateLabel;
    String? timeLabel; // time-of-day portion extracted from dueDay
    if (task.dueDay != null) {
      dueDate = DateTime.tryParse(task.dueDay!);
      if (dueDate != null) {
        final d = DateTime(dueDate.year, dueDate.month, dueDate.day);
        isOverdue = d.isBefore(widget.today) && !isDone;
        final todayD = DateTime(
          widget.today.year,
          widget.today.month,
          widget.today.day,
        );
        // Use the centralised chip formatter (shows year for non-current-year dates)
        dateLabel = _fmtDateChip(dueDate);
        // Extract time from plannedAt (set by Task Details > Planning > Time).
        // Show even if 00:00 — only omit when no time has been set at all.
        if (task.plannedAt != null && task.plannedAt! > 0) {
          final scheduledDt = task.scheduledDateTime;
          if (scheduledDt != null) {
            timeLabel =
                '${scheduledDt.hour.toString().padLeft(2, '0')}:${scheduledDt.minute.toString().padLeft(2, '0')}';
          }
        }
      }
    }

    final subtasks = widget.allTasks
        .where((t) => task.subTaskIds.any((id) => id.toString() == t.id))
        .toList();
    final doneSubtasks = subtasks
        .where((t) => t.status == TaskStatus.done)
        .length;

    const surface = Color(0xFF212426);
    const subtaskSurface = Color(
      0xFF262B2F,
    ); // slightly lighter so it's visible
    const border = Color(0xFF2C2F32);

    return GestureDetector(
      onSecondaryTapDown: (d) {
        if (_suppressNextContextMenu) {
          _suppressNextContextMenu = false;
          return;
        }
        widget.onContextMenu?.call(d.globalPosition);
      },
      child: MouseRegion(
        onEnter: (_) => setState(() => _hovered = true),
        onExit: (_) => setState(() => _hovered = false),
        child: Padding(
          padding: EdgeInsets.zero,
          child: Container(
            // When rendered as a subtask inside the subtask container, suppress
            // the horizontal margin so the card fills the container properly.
            margin: isSubtask
                ? const EdgeInsets.symmetric(vertical: 2)
                : EdgeInsets.only(
                    left: widget.horizPadding,
                    right: widget.horizPadding,
                    top: 3,
                    bottom: (!isSubtask && widget.subtasksExpanded) ? 0 : 3,
                  ),
            decoration: BoxDecoration(
              color: isSubtask
                  ? (_hovered
                        ? subtaskSurface.withBlue(subtaskSurface.blue + 8)
                        : subtaskSurface)
                  : (_hovered ? surface.withBlue(surface.blue + 8) : surface),
              borderRadius: (!isSubtask && widget.subtasksExpanded)
                  ? const BorderRadius.only(
                      topLeft: Radius.circular(8),
                      topRight: Radius.circular(8),
                    )
                  : BorderRadius.circular(isSubtask ? 4 : 8),
              border: Border.all(
                color: isOverdue
                    ? const Color(0xFFEF5350).withOpacity(0.3)
                    : _hovered
                    ? Colors.white24
                    : border,
              ),
              boxShadow: (!isSubtask && widget.subtasksExpanded)
                  ? [
                      BoxShadow(
                        color: Colors.black.withOpacity(0.45),
                        blurRadius: 6,
                        offset: const Offset(0, 4),
                        spreadRadius: 0,
                      ),
                    ]
                  : null,
            ),
            child: IntrinsicHeight(
              child: Row(
                children: [
                  // Drag handle — replaced by ReorderableDragStartListener
                  // when the list supports reordering.
                  widget.dragHandle ??
                      Padding(
                        padding: const EdgeInsets.symmetric(horizontal: 8),
                        child: Icon(
                          Icons.drag_indicator,
                          size: 14,
                          color: Colors.white12,
                        ),
                      ),
                  // Status icon — right-click opens status picker only;
                  // flag prevents the card-level Delete menu from also firing.
                  GestureDetector(
                    onTap: widget.onStatusToggle,
                    onSecondaryTapDown: (details) {
                      _suppressNextContextMenu = true;
                      showMenu<TaskStatus>(
                        context: context,
                        position: RelativeRect.fromLTRB(
                          details.globalPosition.dx,
                          details.globalPosition.dy,
                          details.globalPosition.dx + 1,
                          details.globalPosition.dy + 1,
                        ),
                        color: const Color(0xFF252829),
                        shape: RoundedRectangleBorder(
                          borderRadius: BorderRadius.circular(8),
                          side: const BorderSide(color: Colors.white12),
                        ),
                        items: TaskStatus.values.map((s) {
                          final selected = widget.task.status == s;
                          return PopupMenuItem<TaskStatus>(
                            value: s,
                            padding: const EdgeInsets.symmetric(
                              horizontal: 12,
                              vertical: 4,
                            ),
                            child: Row(
                              children: [
                                Icon(
                                  s.icon,
                                  size: 14,
                                  color: selected
                                      ? s.color
                                      : s.color.withOpacity(0.6),
                                ),
                                const SizedBox(width: 10),
                                Text(
                                  s.label,
                                  style: TextStyle(
                                    fontSize: 12,
                                    color: selected
                                        ? Colors.white
                                        : Colors.white70,
                                    fontWeight: selected
                                        ? FontWeight.w600
                                        : FontWeight.normal,
                                  ),
                                ),
                                if (selected) ...[
                                  const Spacer(),
                                  const Icon(
                                    Icons.check,
                                    size: 12,
                                    color: Colors.white54,
                                  ),
                                ],
                              ],
                            ),
                          );
                        }).toList(),
                      ).then((picked) {
                        if (picked != null) widget.onStatusSelect(picked);
                      });
                    },
                    child: Padding(
                      padding: const EdgeInsets.only(right: 10),
                      child: Icon(
                        task.status.icon,
                        size: 16,
                        color: isDone ? Colors.white24 : task.status.color,
                      ),
                    ),
                  ),
                  // Title + project
                  Expanded(
                    child: Padding(
                      padding: const EdgeInsets.symmetric(vertical: 11),
                      child: Column(
                        crossAxisAlignment: CrossAxisAlignment.start,
                        mainAxisSize: MainAxisSize.min,
                        children: [
                          _editing
                              ? TextField(
                                  controller: _titleCtrl,
                                  focusNode: _titleFocus,
                                  maxLines: 1,
                                  strutStyle: const StrutStyle(
                                    forceStrutHeight: true,
                                    fontSize: 13,
                                    height: 1.0,
                                    leading: 0.0,
                                  ),
                                  style: TextStyle(
                                    fontSize: 13,
                                    color: Colors.white.withOpacity(0.88),
                                  ),
                                  decoration: InputDecoration(
                                    isDense: true,
                                    contentPadding: const EdgeInsets.symmetric(
                                      horizontal: 4,
                                      vertical: 4,
                                    ),
                                    filled: true,
                                    fillColor: Colors.white.withOpacity(0.06),
                                    border: OutlineInputBorder(
                                      borderRadius: BorderRadius.circular(4),
                                      borderSide: const BorderSide(
                                        color: Color(0xFF4FC3F7),
                                        width: 0.8,
                                      ),
                                    ),
                                    enabledBorder: OutlineInputBorder(
                                      borderRadius: BorderRadius.circular(4),
                                      borderSide: const BorderSide(
                                        color: Color(0xFF4FC3F7),
                                        width: 0.8,
                                      ),
                                    ),
                                    focusedBorder: OutlineInputBorder(
                                      borderRadius: BorderRadius.circular(4),
                                      borderSide: const BorderSide(
                                        color: Color(0xFF4FC3F7),
                                        width: 1.2,
                                      ),
                                    ),
                                  ),
                                  onSubmitted: (_) => _commitEdit(),
                                )
                              : GestureDetector(
                                  onDoubleTap: widget.onRename != null
                                      ? _startEdit
                                      : null,
                                  child: Row(
                                    mainAxisSize: MainAxisSize.min,
                                    children: [
                                      // Repeat badge: ↻ for parent, ↩ for instance
                                      if (task.repeatConfig != null)
                                        Tooltip(
                                          message:
                                              'Repeating task – ${task.repeatConfig!.label}',
                                          child: Padding(
                                            padding: const EdgeInsets.only(
                                              right: 5,
                                            ),
                                            child: Icon(
                                              Icons.repeat_rounded,
                                              size: 11,
                                              color: const Color(
                                                0xFF4FC3F7,
                                              ).withOpacity(0.6),
                                            ),
                                          ),
                                        )
                                      else if (task.repeatParentId != null)
                                        Tooltip(
                                          message: 'Repeat instance',
                                          child: Padding(
                                            padding: const EdgeInsets.only(
                                              right: 5,
                                            ),
                                            child: Icon(
                                              Icons.repeat_one_rounded,
                                              size: 11,
                                              color: Colors.white.withOpacity(
                                                0.25,
                                              ),
                                            ),
                                          ),
                                        ),
                                      Flexible(
                                        child: Text(
                                          task.title,
                                          style: TextStyle(
                                            fontSize: 13,
                                            color: isDone
                                                ? Colors.white24
                                                : Colors.white.withOpacity(
                                                    0.88,
                                                  ),
                                            decoration: isDone
                                                ? TextDecoration.lineThrough
                                                : null,
                                            decorationColor: Colors.white38,
                                          ),
                                          overflow: TextOverflow.ellipsis,
                                        ),
                                      ),
                                    ],
                                  ),
                                ),
                          if (task.projectId == 'INBOX_PROJECT' ||
                              widget.projects[task.projectId] != null) ...[
                            const SizedBox(height: 2),
                            Row(
                              mainAxisSize: MainAxisSize.min,
                              children: [
                                () {
                                  final icon = task.projectId == 'INBOX_PROJECT'
                                      ? ''
                                      : (widget.projectIcons[task.projectId] ??
                                            '');
                                  if (icon.isNotEmpty) {
                                    return Padding(
                                      padding: const EdgeInsets.only(right: 3),
                                      child: Text(
                                        icon,
                                        style: const TextStyle(
                                          fontSize: 9,
                                          fontFamilyFallback: [
                                            'NotoColorEmoji',
                                            'Apple Color Emoji',
                                            'Segoe UI Emoji',
                                          ],
                                        ),
                                      ),
                                    );
                                  }
                                  return Padding(
                                    padding: const EdgeInsets.only(right: 3),
                                    child: Icon(
                                      task.projectId == 'INBOX_PROJECT'
                                          ? Icons.inbox_outlined
                                          : Icons.folder_outlined,
                                      size: 9,
                                      color: Colors.white24,
                                    ),
                                  );
                                }(),
                                Flexible(
                                  child: Text(
                                    task.projectId == 'INBOX_PROJECT'
                                        ? 'Inbox'
                                        : widget
                                              .projects[task.projectId]!
                                              .title,
                                    style: const TextStyle(
                                      fontSize: 10,
                                      color: Colors.white30,
                                    ),
                                    overflow: TextOverflow.ellipsis,
                                  ),
                                ),
                              ],
                            ),
                          ],
                          if (subtasks.isNotEmpty) ...[
                            const SizedBox(height: 4),
                            GestureDetector(
                              onTap: widget.onSubtasksToggle,
                              child: Row(
                                mainAxisSize: MainAxisSize.min,
                                children: [
                                  Icon(
                                    widget.subtasksExpanded
                                        ? Icons.keyboard_arrow_down
                                        : Icons.keyboard_arrow_right,
                                    size: 11,
                                    color: Colors.white38,
                                  ),
                                  const SizedBox(width: 2),
                                  Icon(
                                    Icons.account_tree_outlined,
                                    size: 10,
                                    color: Colors.white24,
                                  ),
                                  const SizedBox(width: 4),
                                  Text(
                                    '$doneSubtasks/${subtasks.length}',
                                    style: const TextStyle(
                                      fontSize: 10,
                                      color: Colors.white38,
                                    ),
                                  ),
                                ],
                              ),
                            ),
                          ],
                          if (widget.repeatInstanceCount > 0) ...[
                            const SizedBox(height: 4),
                            GestureDetector(
                              onTap: widget.onRepeatInstancesToggle,
                              child: Row(
                                mainAxisSize: MainAxisSize.min,
                                children: [
                                  Icon(
                                    widget.repeatInstancesExpanded
                                        ? Icons.keyboard_arrow_down
                                        : Icons.keyboard_arrow_right,
                                    size: 11,
                                    color: Colors.white38,
                                  ),
                                  const SizedBox(width: 2),
                                  Icon(
                                    Icons.repeat_rounded,
                                    size: 10,
                                    color: Colors.white24,
                                  ),
                                  const SizedBox(width: 4),
                                  Text(
                                    '${widget.repeatInstanceCount} upcoming',
                                    style: const TextStyle(
                                      fontSize: 10,
                                      color: Colors.white38,
                                    ),
                                  ),
                                ],
                              ),
                            ),
                          ],
                        ],
                      ),
                    ),
                  ),
                  // Date badge
                  if (dateLabel != null)
                    Padding(
                      padding: const EdgeInsets.only(right: 6),
                      child: GestureDetector(
                        key: _dateChipKey,
                        onTap: widget.onDateChanged == null
                            ? null
                            : () {
                                final box =
                                    _dateChipKey.currentContext
                                            ?.findRenderObject()
                                        as RenderBox?;
                                final pos =
                                    box?.localToGlobal(Offset.zero) ??
                                    Offset.zero;
                                final size = box?.size ?? Size.zero;
                                _showDueDatePopup(
                                  context: context,
                                  anchorRect: Rect.fromLTWH(
                                    pos.dx,
                                    pos.dy,
                                    size.width,
                                    size.height,
                                  ),
                                  selectedDueDay: task.dueDay,
                                  plannedAt: task.plannedAt,
                                  onConfirm: (isoDay, newPlannedAt) {
                                    widget.onDateChanged?.call(
                                      isoDay,
                                      newPlannedAt,
                                    );
                                  },
                                );
                              },
                        child: MouseRegion(
                          cursor: widget.onDateChanged != null
                              ? SystemMouseCursors.click
                              : MouseCursor.defer,
                          child: Container(
                            padding: const EdgeInsets.symmetric(
                              horizontal: 7,
                              vertical: 3,
                            ),
                            decoration: BoxDecoration(
                              color: isOverdue
                                  ? const Color(0xFFEF5350).withOpacity(0.12)
                                  : Colors.white.withOpacity(0.05),
                              borderRadius: BorderRadius.circular(5),
                              border: Border.all(
                                color: isOverdue
                                    ? const Color(0xFFEF5350).withOpacity(0.4)
                                    : Colors.white12,
                              ),
                            ),
                            child: Row(
                              mainAxisSize: MainAxisSize.min,
                              children: [
                                Icon(
                                  Icons.calendar_today_outlined,
                                  size: 9,
                                  color: isOverdue
                                      ? const Color(0xFFEF5350)
                                      : Colors.white38,
                                ),
                                const SizedBox(width: 4),
                                Text(
                                  dateLabel!,
                                  style: TextStyle(
                                    fontSize: 10,
                                    fontWeight: FontWeight.w500,
                                    color: isOverdue
                                        ? const Color(0xFFEF5350)
                                        : Colors.white38,
                                  ),
                                ),
                                if (timeLabel != null) ...[
                                  const SizedBox(width: 5),
                                  Container(
                                    width: 1,
                                    height: 9,
                                    color: isOverdue
                                        ? const Color(
                                            0xFFEF5350,
                                          ).withOpacity(0.4)
                                        : Colors.white12,
                                  ),
                                  const SizedBox(width: 5),
                                  Icon(
                                    Icons.access_time_rounded,
                                    size: 9,
                                    color: isOverdue
                                        ? const Color(0xFFEF5350)
                                        : Colors.white38,
                                  ),
                                  const SizedBox(width: 3),
                                  Text(
                                    timeLabel!,
                                    style: TextStyle(
                                      fontSize: 10,
                                      fontWeight: FontWeight.w500,
                                      color: isOverdue
                                          ? const Color(0xFFEF5350)
                                          : Colors.white38,
                                    ),
                                  ),
                                ],
                              ],
                            ),
                          ),
                        ),
                      ),
                    ),
                  // ── Right-end area: time stats at rest, buttons on hover ──
                  SizedBox(
                    width: 112,
                    child: Stack(
                      alignment: Alignment.centerRight,
                      children: [
                        // Time stats — visible when not hovered
                        AnimatedOpacity(
                          opacity: (_hovered || timerActive || detailActive)
                              ? 0.0
                              : 1.0,
                          duration: const Duration(milliseconds: 150),
                          child: IgnorePointer(
                            child: Padding(
                              padding: const EdgeInsets.only(right: 8),
                              child: Column(
                                mainAxisSize: MainAxisSize.min,
                                crossAxisAlignment: CrossAxisAlignment.end,
                                children: [
                                  Builder(
                                    builder: (_) {
                                      final ms =
                                          widget.effectiveTimeSpentMs ??
                                          task.timeSpent;
                                      if (ms <= 0)
                                        return const SizedBox.shrink();
                                      final h = ms ~/ 3600000;
                                      final m = (ms % 3600000) ~/ 60000;
                                      return Text(
                                        h > 0 ? '${h}h ${m}m' : '${m}m',
                                        style: const TextStyle(
                                          fontSize: 10,
                                          color: Color(0xFF4A5060),
                                        ),
                                      );
                                    },
                                  ),
                                  Builder(
                                    builder: (_) {
                                      final mins =
                                          widget.effectiveDurationMinutes ??
                                          task.durationMinutes;
                                      final h = mins ~/ 60;
                                      final rm = mins % 60;
                                      return Text(
                                        h > 0
                                            ? (rm > 0
                                                  ? '${h}h ${rm}m'
                                                  : '${h}h')
                                            : '${mins}m',
                                        style: const TextStyle(
                                          fontSize: 10,
                                          color: Color(0xFF3A4050),
                                        ),
                                      );
                                    },
                                  ),
                                ],
                              ),
                            ),
                          ),
                        ),
                        // Action buttons — visible on hover / active
                        AnimatedOpacity(
                          opacity: (_hovered || timerActive || detailActive)
                              ? 1.0
                              : 0.0,
                          duration: const Duration(milliseconds: 150),
                          child: Row(
                            mainAxisSize: MainAxisSize.min,
                            children: [
                              // ── Countdown / Stop button ──────────────────────
                              _TaskRowBtn(
                                tooltip: timerActive
                                    ? 'Stop (${widget.formatElapsed()})'
                                    : (widget.activeStagingTaskId == task.id)
                                    ? 'Stop Pomodoro & Start Countdown'
                                    : 'Start Countdown',
                                icon: timerActive
                                    ? Icons.stop_rounded
                                    : Icons.play_arrow_rounded,
                                active: timerActive,
                                activeColor: const Color(0xFF4CAF50),
                                onTap: widget.onTimerToggle,
                              ),
                              // ── Start With Staging / Stop Staging button ─
                              if (widget.onStagingToggle != null)
                                _TaskRowBtn(
                                  tooltip: widget.activeStagingTaskId == task.id
                                      ? 'Stop Pomodoro'
                                      : widget.stagingWasInterrupted
                                      ? 'Continue Pomodoro'
                                      : 'Start Pomodoro',
                                  icon: widget.activeStagingTaskId == task.id
                                      ? Icons.stop_circle_outlined
                                      : Icons.timer_outlined,
                                  active: widget.activeStagingTaskId == task.id,
                                  activeColor: const Color(0xFFFFB74D),
                                  onTap: widget.activeStagingTaskId == task.id
                                      ? widget.onStopStaging ??
                                            widget.onStagingToggle!
                                      : widget.onStagingToggle!,
                                ),
                              // ── Flowtime button ──────────────────────────
                              if (widget.onFlowtimeToggle != null)
                                _TaskRowBtn(
                                  tooltip:
                                      widget.activeFlowtimeTaskId == task.id
                                      ? 'Stop Flowtime'
                                      : 'Start Flowtime',
                                  icon: widget.activeFlowtimeTaskId == task.id
                                      ? Icons.stop_rounded
                                      : Icons.trending_up_rounded,
                                  active:
                                      widget.activeFlowtimeTaskId == task.id,
                                  activeColor: const Color(0xFFA78BFA),
                                  onTap: widget.onFlowtimeToggle!,
                                ),
                              _TaskRowBtn(
                                tooltip: detailActive
                                    ? 'Collapse'
                                    : 'Show details',
                                icon: detailActive
                                    ? Icons.view_headline
                                    : Icons.table_rows_outlined,
                                active: detailActive,
                                activeColor: const Color(0xFF4FC3F7),
                                onTap: widget.onDetailToggle,
                              ),
                            ],
                          ),
                        ),
                      ],
                    ),
                  ),
                  const SizedBox(width: 8),
                ],
              ),
            ),
          ),
        ),
      ), // GestureDetector
    );
  }
}

// ─────────────────────────────────────────────────────────────────────────────
// _AnnexedMenuItem  –  popup menu item that shows an annexed submenu to its right
// ─────────────────────────────────────────────────────────────────────────────

// ─────────────────────────────────────────────────────────────────────────────
// _HoverColorSwatch — 24×24 swatch with ★ hover overlay for fav toggling
// ─────────────────────────────────────────────────────────────────────────────

class _HoverColorSwatch extends StatefulWidget {
  final Color color;
  final bool isActive;
  final bool isFavorite;
  final VoidCallback onTap;
  final VoidCallback onFavToggle;
  final VoidCallback? onRemove;

  const _HoverColorSwatch({
    required this.color,
    required this.isActive,
    required this.isFavorite,
    required this.onTap,
    required this.onFavToggle,
    this.onRemove,
  });

  @override
  State<_HoverColorSwatch> createState() => _HoverColorSwatchState();
}

class _HoverColorSwatchState extends State<_HoverColorSwatch> {
  bool _hovered = false;

  @override
  Widget build(BuildContext context) {
    final lum = widget.color.computeLuminance();
    final iconColor = lum > 0.5 ? Colors.black54 : Colors.white70;

    return MouseRegion(
      cursor: SystemMouseCursors.click,
      onEnter: (_) => setState(() => _hovered = true),
      onExit: (_) => setState(() => _hovered = false),
      child: GestureDetector(
        onTap: widget.onTap,
        child: Tooltip(
          message: widget.isFavorite
              ? 'Remove from favorites'
              : 'Add to favorites',
          child: AnimatedContainer(
            duration: const Duration(milliseconds: 120),
            width: 24,
            height: 24,
            decoration: BoxDecoration(
              color: widget.color,
              borderRadius: BorderRadius.circular(5),
              border: Border.all(
                color: widget.isActive
                    ? Colors.white
                    : Colors.white.withOpacity(0.15),
                width: widget.isActive ? 2 : 1,
              ),
              boxShadow: widget.isActive
                  ? [
                      BoxShadow(
                        color: widget.color.withOpacity(0.6),
                        blurRadius: 6,
                      ),
                    ]
                  : null,
            ),
            child: _hovered
                ? GestureDetector(
                    onTap: widget.onFavToggle,
                    child: Icon(
                      widget.isFavorite
                          ? Icons.star_rounded
                          : Icons.star_outline_rounded,
                      size: 14,
                      color: iconColor,
                    ),
                  )
                : widget.isFavorite
                ? Icon(
                    Icons.star_rounded,
                    size: 10,
                    color: iconColor.withOpacity(0.6),
                  )
                : null,
          ),
        ),
      ),
    );
  }
}

class _AnnexedItem {
  final String value;
  final String label;
  final IconData icon;
  final Color iconColor;
  final bool active;

  const _AnnexedItem({
    required this.value,
    required this.label,
    required this.icon,
    this.iconColor = const Color(0xFF9AA3B0),
    this.active = false,
  });
}

class _AnnexedMenuItem extends StatefulWidget {
  final IconData icon;
  final String label;
  final int? badge;
  final List<_AnnexedItem> items;
  final void Function(String value) onSelect;

  const _AnnexedMenuItem({
    Key? key,
    required this.icon,
    required this.label,
    required this.items,
    required this.onSelect,
    this.badge,
  }) : super(key: key);

  @override
  State<_AnnexedMenuItem> createState() => _AnnexedMenuItemState();
}

class _AnnexedMenuItemState extends State<_AnnexedMenuItem> {
  final _key = GlobalKey();
  bool _hovered = false;

  void _showSubmenu() async {
    final box = _key.currentContext?.findRenderObject() as RenderBox?;
    if (box == null) return;
    final topLeft = box.localToGlobal(Offset.zero);
    final size = box.size;

    const menuColor = Color(0xFF1E2124);
    const menuBorder = Color(0xFF2C2F35);

    final result = await showMenu<String>(
      context: context,
      color: menuColor,
      elevation: 12,
      shape: RoundedRectangleBorder(
        borderRadius: BorderRadius.circular(10),
        side: const BorderSide(color: menuBorder, width: 0.8),
      ),
      position: RelativeRect.fromLTRB(
        topLeft.dx + size.width + 2, // annexed: just to the right
        topLeft.dy - 8,
        topLeft.dx + size.width + 2,
        topLeft.dy - 8,
      ),
      items: widget.items.map((item) {
        return PopupMenuItem<String>(
          value: item.value,
          height: 34,
          child: Row(
            children: [
              Icon(item.icon, size: 14, color: item.iconColor),
              const SizedBox(width: 10),
              Text(
                item.label,
                style: TextStyle(
                  fontSize: 12.5,
                  color: item.active ? Colors.white : Colors.white70,
                ),
              ),
              if (item.active) ...[
                const Spacer(),
                const Icon(Icons.check, size: 12, color: Color(0xFF4FC3F7)),
              ],
            ],
          ),
        );
      }).toList(),
    );

    if (result != null) {
      widget.onSelect(result);
    }
  }

  @override
  Widget build(BuildContext context) {
    return MouseRegion(
      onEnter: (_) => setState(() => _hovered = true),
      onExit: (_) => setState(() => _hovered = false),
      child: GestureDetector(
        onTap: _showSubmenu,
        child: Container(
          key: _key,
          height: 36,
          color: _hovered ? Colors.white.withOpacity(0.05) : Colors.transparent,
          child: Row(
            children: [
              Icon(widget.icon, size: 15, color: const Color(0xFF9AA3B0)),
              const SizedBox(width: 12),
              Expanded(
                child: Text(
                  widget.label,
                  style: const TextStyle(
                    fontSize: 12.5,
                    color: Color(0xFFD0D4DC),
                  ),
                ),
              ),
              if (widget.badge != null) ...[
                Container(
                  padding: const EdgeInsets.symmetric(
                    horizontal: 5,
                    vertical: 1,
                  ),
                  decoration: BoxDecoration(
                    color: const Color(0xFF2C3040),
                    borderRadius: BorderRadius.circular(10),
                  ),
                  child: Text(
                    '${widget.badge}',
                    style: const TextStyle(fontSize: 10, color: Colors.white38),
                  ),
                ),
                const SizedBox(width: 4),
              ],
              const Icon(Icons.chevron_right, size: 14, color: Colors.white24),
            ],
          ),
        ),
      ),
    );
  }
}

// ─────────────────────────────────────────────────────────────────────────────
// _ScheduleIconRow  –  row of 5 schedule quick-action buttons in context menu
// ─────────────────────────────────────────────────────────────────────────────

class _ScheduleIconRow extends StatelessWidget {
  final Task task;
  final void Function(String value) onSchedule;

  const _ScheduleIconRow({
    Key? key,
    required this.task,
    required this.onSchedule,
  }) : super(key: key);

  @override
  Widget build(BuildContext context) {
    final now = DateTime.now();
    final today = DateTime(now.year, now.month, now.day);
    final hasDate = task.dueDay != null;
    final dueDate = hasDate ? DateTime.tryParse(task.dueDay!) : null;
    final isToday =
        dueDate != null &&
        DateTime(dueDate.year, dueDate.month, dueDate.day) == today;
    final isTomorrow =
        dueDate != null &&
        DateTime(dueDate.year, dueDate.month, dueDate.day) ==
            today.add(const Duration(days: 1));

    Widget btn(
      IconData icon,
      String tooltip,
      String value, {
      bool active = false,
      Color? activeColor,
    }) {
      return Tooltip(
        message: tooltip,
        preferBelow: true,
        child: InkWell(
          borderRadius: BorderRadius.circular(6),
          onTap: () => onSchedule(value),
          child: Container(
            width: 36,
            height: 36,
            decoration: BoxDecoration(
              color: active
                  ? (activeColor ?? const Color(0xFF4FC3F7)).withOpacity(0.15)
                  : Colors.transparent,
              borderRadius: BorderRadius.circular(6),
              border: active
                  ? Border.all(
                      color: (activeColor ?? const Color(0xFF4FC3F7))
                          .withOpacity(0.4),
                      width: 0.8,
                    )
                  : null,
            ),
            child: Icon(
              icon,
              size: 16,
              color: active
                  ? (activeColor ?? const Color(0xFF4FC3F7))
                  : const Color(0xFF9AA3B0),
            ),
          ),
        ),
      );
    }

    return Row(
      mainAxisAlignment: MainAxisAlignment.spaceEvenly,
      children: [
        btn(Icons.today_outlined, 'Schedule Today', 'sched_today'),
        btn(Icons.wb_sunny_outlined, 'Schedule Tomorrow', 'sched_tomorrow'),
        btn(Icons.date_range_outlined, 'Schedule Next Week', 'sched_nextweek'),
        btn(Icons.edit_calendar_outlined, 'Reschedule', 'sched_reschedule'),
        btn(Icons.event_busy_outlined, 'Unschedule', 'sched_unschedule'),
      ],
    );
  }
}

