// ─────────────────────────────────────────────────────────────────────────────
// _AddTaskOverlay
//
// A floating quick-entry panel (like the screenshot) that appears below the
// + button in the Tasks action bar. Supports inline #tag / @time parsing,
// project picker, due-date picker, and tag picker chips.
// ─────────────────────────────────────────────────────────────────────────────

class _AddTaskOverlay extends StatefulWidget {
  final double top, left, width;
  final TextEditingController controller;
  final Map<String, Project> projects;
  final List<String> projectOrder;
  final String? selectedProjectId;
  final String? selectedDueDay;
  final List<String> selectedTags;
  final List<String> allTags;
  final void Function(String? id) onProjectChanged;
  final void Function(String? day) onDueDayChanged;
  final void Function(String tag) onTagToggled;
  final VoidCallback onCommit;
  final VoidCallback onDismiss;

  const _AddTaskOverlay({
    Key? key,
    required this.top,
    required this.left,
    required this.width,
    required this.controller,
    required this.projects,
    required this.projectOrder,
    required this.selectedProjectId,
    required this.selectedDueDay,
    required this.selectedTags,
    required this.allTags,
    required this.onProjectChanged,
    required this.onDueDayChanged,
    required this.onTagToggled,
    required this.onCommit,
    required this.onDismiss,
  }) : super(key: key);

  @override
  State<_AddTaskOverlay> createState() => _AddTaskOverlayState();
}

class _AddTaskOverlayState extends State<_AddTaskOverlay> {
  // Which secondary panel is open: null | 'project' | 'due' | 'tags' | 'estimate'
  String? _openPanel;
  final FocusNode _focusNode = FocusNode();
  final _duePillKey = GlobalKey();

  void _showDuePopup() {
    final box = _duePillKey.currentContext?.findRenderObject() as RenderBox?;
    if (box == null) return;
    final pos = box.localToGlobal(Offset.zero);
    final size = box.size;
    _showDueDatePopup(
      context: context,
      anchorRect: Rect.fromLTWH(pos.dx, pos.dy, size.width, size.height),
      selectedDueDay: widget.selectedDueDay,
      onConfirm: (day, _) {
        widget.onDueDayChanged(day);
        setState(() {});
      },
    );
  }

  @override
  void initState() {
    super.initState();
    WidgetsBinding.instance.addPostFrameCallback(
      (_) => _focusNode.requestFocus(),
    );
  }

  @override
  void dispose() {
    _focusNode.dispose();
    super.dispose();
  }

  @override
  Widget build(BuildContext context) {
    return Stack(
      children: [
        // Dismiss tap-outside
        Positioned.fill(
          child: GestureDetector(
            behavior: HitTestBehavior.translucent,
            onTap: widget.onDismiss,
          ),
        ),
        Positioned(
          top: widget.top,
          left: widget.left,
          width: widget.width,
          child: Material(
            color: Colors.transparent,
            child: Container(
              decoration: BoxDecoration(
                color: const Color(0xFF1E2022),
                borderRadius: BorderRadius.circular(10),
                border: Border.all(color: Colors.white12),
                boxShadow: [
                  BoxShadow(
                    color: Colors.black.withOpacity(0.55),
                    blurRadius: 24,
                    offset: const Offset(0, 8),
                  ),
                ],
              ),
              child: Column(
                mainAxisSize: MainAxisSize.min,
                crossAxisAlignment: CrossAxisAlignment.stretch,
                children: [
                  // ── Text input row ─────────────────────────────────────
                  Padding(
                    padding: const EdgeInsets.fromLTRB(14, 10, 10, 6),
                    child: Row(
                      children: [
                        Expanded(
                          child: TextField(
                            controller: widget.controller,
                            focusNode: _focusNode,
                            // Spec §1: block reserved filesystem chars in titles.
                            inputFormatters: [
                              FilteringTextInputFormatter.deny(
                                RegExp(r'[/\\:]'),
                              ),
                            ],
                            style: const TextStyle(
                              color: Colors.white,
                              fontSize: 13,
                            ),
                            decoration: const InputDecoration(
                              hintText: 'A task title  #tag  @16:00',
                              hintStyle: TextStyle(
                                color: Colors.white24,
                                fontSize: 13,
                              ),
                              border: InputBorder.none,
                              isDense: true,
                              contentPadding: EdgeInsets.zero,
                            ),
                            onSubmitted: (_) => widget.onCommit(),
                          ),
                        ),
                        const SizedBox(width: 8),
                        _iconBtn(Icons.upload_outlined, 'Import', () {}),
                        const SizedBox(width: 4),
                        _iconBtn(Icons.search, 'Search', () {}),
                      ],
                    ),
                  ),
                  // Thin divider
                  Container(height: 0.5, color: Colors.white12),
                  // ── Pill row ───────────────────────────────────────────
                  SingleChildScrollView(
                    scrollDirection: Axis.horizontal,
                    padding: const EdgeInsets.symmetric(
                      horizontal: 10,
                      vertical: 8,
                    ),
                    child: Row(
                      children: [
                        _pill(
                          icon: Icons.inbox_outlined,
                          label: widget.selectedProjectId != null
                              ? (widget
                                        .projects[widget.selectedProjectId]
                                        ?.title ??
                                    'Project')
                              : 'Inbox',
                          active: _openPanel == 'project',
                          onTap: () => setState(
                            () => _openPanel = _openPanel == 'project'
                                ? null
                                : 'project',
                          ),
                        ),
                        const SizedBox(width: 6),
                        KeyedSubtree(
                          key: _duePillKey,
                          child: _pill(
                            icon: Icons.calendar_today_outlined,
                            label: widget.selectedDueDay != null
                                ? _formatDueLabel(widget.selectedDueDay!)
                                : 'Due',
                            active: widget.selectedDueDay != null,
                            onTap: _showDuePopup,
                          ),
                        ),
                        const SizedBox(width: 6),
                        _pill(
                          icon: Icons.label_outline,
                          label: widget.selectedTags.isEmpty
                              ? 'Tags'
                              : widget.selectedTags.join(', '),
                          active:
                              _openPanel == 'tags' ||
                              widget.selectedTags.isNotEmpty,
                          onTap: () => setState(
                            () => _openPanel = _openPanel == 'tags'
                                ? null
                                : 'tags',
                          ),
                        ),
                        const SizedBox(width: 6),
                        _pill(
                          icon: Icons.timer_outlined,
                          label: 'Estimate',
                          active: _openPanel == 'estimate',
                          onTap: () => setState(
                            () => _openPanel = _openPanel == 'estimate'
                                ? null
                                : 'estimate',
                          ),
                        ),
                      ],
                    ),
                  ),
                  // ── Secondary panels ───────────────────────────────────
                  if (_openPanel == 'project') _buildProjectPanel(),
                  if (_openPanel == 'tags') _buildTagsPanel(),
                ],
              ),
            ),
          ),
        ),
      ],
    );
  }

  Widget _iconBtn(IconData icon, String tooltip, VoidCallback onTap) => Tooltip(
    message: tooltip,
    child: InkWell(
      onTap: onTap,
      borderRadius: BorderRadius.circular(5),
      child: Padding(
        padding: const EdgeInsets.all(5),
        child: Icon(icon, size: 15, color: Colors.white38),
      ),
    ),
  );

  Widget _pill({
    required IconData icon,
    required String label,
    required bool active,
    required VoidCallback onTap,
  }) {
    return GestureDetector(
      onTap: onTap,
      child: AnimatedContainer(
        duration: const Duration(milliseconds: 120),
        padding: const EdgeInsets.symmetric(horizontal: 9, vertical: 5),
        decoration: BoxDecoration(
          color: active
              ? const Color(0xFF4FC3F7).withOpacity(0.12)
              : Colors.white.withOpacity(0.05),
          borderRadius: BorderRadius.circular(6),
          border: Border.all(
            color: active
                ? const Color(0xFF4FC3F7).withOpacity(0.4)
                : Colors.white12,
          ),
        ),
        child: Row(
          mainAxisSize: MainAxisSize.min,
          children: [
            Icon(
              icon,
              size: 12,
              color: active ? const Color(0xFF4FC3F7) : Colors.white38,
            ),
            const SizedBox(width: 5),
            Text(
              label,
              style: TextStyle(
                fontSize: 11,
                color: active ? const Color(0xFF4FC3F7) : Colors.white38,
                fontWeight: active ? FontWeight.w600 : FontWeight.normal,
              ),
            ),
          ],
        ),
      ),
    );
  }

  Widget _buildProjectPanel() {
    return Container(
      constraints: const BoxConstraints(maxHeight: 180),
      margin: const EdgeInsets.fromLTRB(10, 0, 10, 8),
      decoration: BoxDecoration(
        color: const Color(0xFF252829),
        borderRadius: BorderRadius.circular(7),
        border: Border.all(color: Colors.white10),
      ),
      child: ListView(
        padding: const EdgeInsets.symmetric(vertical: 4),
        shrinkWrap: true,
        children: [
          _panelItem(
            icon: Icons.inbox_outlined,
            label: 'Inbox',
            selected: widget.selectedProjectId == null,
            onTap: () {
              widget.onProjectChanged(null);
              setState(() => _openPanel = null);
            },
          ),
          ...widget.projectOrder.map((pid) {
            final proj = widget.projects[pid];
            if (proj == null) return const SizedBox.shrink();
            return _panelItem(
              icon: Icons.folder_outlined,
              label: proj.title,
              selected: widget.selectedProjectId == pid,
              onTap: () {
                widget.onProjectChanged(pid);
                setState(() => _openPanel = null);
              },
            );
          }),
        ],
      ),
    );
  }

  Widget _buildDuePanel() {
    return Container(
      margin: const EdgeInsets.fromLTRB(10, 0, 10, 8),
      child: _DueDatePickerPanel(
        selectedDueDay: widget.selectedDueDay,
        onConfirm: (isoDay, _) {
          widget.onDueDayChanged(isoDay);
          setState(() => _openPanel = null);
        },
        onCancel: () => setState(() => _openPanel = null),
      ),
    );
  }

  // ── Tags panel ────────────────────────────────────────────────────────

  Widget _buildTagsPanel() {
    if (widget.allTags.isEmpty) {
      return Padding(
        padding: const EdgeInsets.fromLTRB(14, 6, 14, 10),
        child: const Text(
          'No tags yet — type #tagname in the title',
          style: TextStyle(color: Colors.white30, fontSize: 11),
        ),
      );
    }
    return Container(
      constraints: const BoxConstraints(maxHeight: 160),
      margin: const EdgeInsets.fromLTRB(10, 0, 10, 8),
      decoration: BoxDecoration(
        color: const Color(0xFF252829),
        borderRadius: BorderRadius.circular(7),
        border: Border.all(color: Colors.white10),
      ),
      child: ListView(
        padding: const EdgeInsets.symmetric(vertical: 4),
        shrinkWrap: true,
        children: widget.allTags.map((tag) {
          final selected = widget.selectedTags.contains(tag);
          return _panelItem(
            icon: selected ? Icons.label : Icons.label_outline,
            label: '#$tag',
            selected: selected,
            onTap: () => widget.onTagToggled(tag),
          );
        }).toList(),
      ),
    );
  }

  Widget _panelItem({
    required IconData icon,
    required String label,
    required bool selected,
    required VoidCallback onTap,
  }) {
    return InkWell(
      onTap: onTap,
      child: Padding(
        padding: const EdgeInsets.symmetric(horizontal: 12, vertical: 8),
        child: Row(
          children: [
            Icon(
              icon,
              size: 14,
              color: selected ? const Color(0xFF4FC3F7) : Colors.white38,
            ),
            const SizedBox(width: 10),
            Expanded(
              child: Text(
                label,
                style: TextStyle(
                  fontSize: 12,
                  color: selected ? const Color(0xFF4FC3F7) : Colors.white70,
                  fontWeight: selected ? FontWeight.w600 : FontWeight.normal,
                ),
              ),
            ),
            if (selected)
              const Icon(Icons.check, size: 13, color: Color(0xFF4FC3F7)),
          ],
        ),
      ),
    );
  }

  String _formatDueLabel(String isoDay) {
    final d = DateTime.tryParse(isoDay);
    if (d == null) return isoDay;
    return _fmtDateChip(d);
  }
}

// ─────────────────────────────────────────────────────────────────────────────
// _DueDatePickerPanel
//
// A full calendar date/time picker that matches the screenshot:
// quick-pick top bar, month grid, time input, Cancel/Schedule footer.
// ─────────────────────────────────────────────────────────────────────────────

/// Shows the [_DueDatePickerPanel] as a floating popup anchored to [anchorRect].
/// Dismisses on tap-outside (barrier). Calls [onConfirm] with the chosen ISO date.
void _showDueDatePopup({
  required BuildContext context,
  required Rect anchorRect,
  required String? selectedDueDay,
  required void Function(String isoDay, int? plannedAt) onConfirm,
  int? plannedAt,
}) {
  // Panel dimensions
  const double panelW = 268;
  const double panelH = 390; // generous upper bound
  const double margin = 8.0;

  // Safe area / screen bounds
  final media = MediaQuery.of(context);
  final screen = media.size;
  final safeTop = media.padding.top + margin;
  final safeBottom = screen.height - media.padding.bottom - margin;
  final safeLeft = media.padding.left + margin;
  final safeRight = screen.width - media.padding.right - margin;

  // Horizontal: prefer left-aligned with anchor, clamp within safe bounds
  double left = anchorRect.left;
  if (left + panelW > safeRight) left = safeRight - panelW;
  if (left < safeLeft) left = safeLeft;

  // Vertical: prefer below the chip; fall back to above; clamp in either case
  double top;
  final spaceBelow = safeBottom - anchorRect.bottom;
  final spaceAbove = anchorRect.top - safeTop;

  if (spaceBelow >= panelH || spaceBelow >= spaceAbove) {
    // Anchor below — use all available space if panel is taller than room
    top = anchorRect.bottom + 4;
  } else {
    // Anchor above
    top = anchorRect.top - panelH - 4;
  }
  // Final clamp so no pixel ever leaves safe area
  if (top + panelH > safeBottom) top = safeBottom - panelH;
  if (top < safeTop) top = safeTop;

  showGeneralDialog(
    context: context,
    barrierDismissible: true,
    barrierLabel: 'DuePicker',
    barrierColor: Colors.transparent,
    transitionDuration: const Duration(milliseconds: 120),
    transitionBuilder: (ctx, anim, _, child) => FadeTransition(
      opacity: CurvedAnimation(parent: anim, curve: Curves.easeOut),
      child: child,
    ),
    pageBuilder: (ctx, _, __) {
      return Stack(
        children: [
          Positioned(
            left: left,
            top: top,
            width: panelW,
            child: Material(
              color: Colors.transparent,
              child: _DueDatePickerPanel(
                selectedDueDay: selectedDueDay,
                plannedAt: plannedAt,
                onConfirm: (isoDay, newPlannedAt) {
                  Navigator.of(ctx).pop();
                  onConfirm(isoDay, newPlannedAt);
                },
                onCancel: () => Navigator.of(ctx).pop(),
              ),
            ),
          ),
        ],
      );
    },
  );
}

class _DueDatePickerPanel extends StatefulWidget {
  final String? selectedDueDay;
  final int? plannedAt;
  final void Function(String isoDay, int? plannedAt) onConfirm;
  final VoidCallback onCancel;

  const _DueDatePickerPanel({
    Key? key,
    required this.selectedDueDay,
    this.plannedAt,
    required this.onConfirm,
    required this.onCancel,
  }) : super(key: key);

  @override
  State<_DueDatePickerPanel> createState() => _DueDatePickerPanelState();
}

class _DueDatePickerPanelState extends State<_DueDatePickerPanel> {
  late DateTime _viewMonth; // first day of the displayed month
  DateTime? _selected;
  final TextEditingController _timeCtrl = TextEditingController();

  static const _weekDays = ['M', 'T', 'W', 'T', 'F', 'S', 'S'];
  static const _monthNames = [
    'JAN',
    'FEB',
    'MAR',
    'APR',
    'MAY',
    'JUN',
    'JUL',
    'AUG',
    'SEP',
    'OCT',
    'NOV',
    'DEC',
  ];

  @override
  void initState() {
    super.initState();
    final now = DateTime.now();
    _viewMonth = DateTime(now.year, now.month, 1);
    if (widget.selectedDueDay != null) {
      final d = DateTime.tryParse(widget.selectedDueDay!);
      if (d != null) {
        _selected = DateTime(d.year, d.month, d.day);
        _viewMonth = DateTime(d.year, d.month, 1);
      }
    }
    // Pre-fill time field from plannedAt if a time has been set
    if (widget.plannedAt != null && widget.plannedAt! > 0) {
      final dt = DateTime.fromMillisecondsSinceEpoch(
        widget.plannedAt!,
      ).toLocal();
      _timeCtrl.text =
          '${dt.hour.toString().padLeft(2, '0')}:${dt.minute.toString().padLeft(2, '0')}';
    }
  }

  @override
  void dispose() {
    _timeCtrl.dispose();
    super.dispose();
  }

  DateTime get _today {
    final n = DateTime.now();
    return DateTime(n.year, n.month, n.day);
  }

  void _quickPick(DateTime day) => setState(() {
    _selected = day;
    _viewMonth = DateTime(day.year, day.month, 1);
  });

  void _confirm() {
    if (_selected == null) return;
    final timeText = _timeCtrl.text.trim();
    int? newPlannedAt;
    if (timeText.isNotEmpty) {
      // Parse 24h hh:mm
      final parts = timeText.split(':');
      if (parts.length == 2) {
        final h = int.tryParse(parts[0].trim());
        final m = int.tryParse(parts[1].trim());
        if (h != null && m != null && h >= 0 && h <= 23 && m >= 0 && m <= 59) {
          final withTime = DateTime(
            _selected!.year,
            _selected!.month,
            _selected!.day,
            h,
            m,
          );
          newPlannedAt = withTime.millisecondsSinceEpoch;
        }
      }
    }
    final isoDay = _selected!.toIso8601String().split('T').first;
    widget.onConfirm(isoDay, newPlannedAt);
  }

  /// Build the 6×7 calendar grid for the current _viewMonth.
  List<DateTime?> _calendarDays() {
    final first = _viewMonth;
    // weekday: 1=Mon … 7=Sun → offset so Mon is col 0
    final startOffset = (first.weekday - 1) % 7;
    final daysInMonth = DateTime(_viewMonth.year, _viewMonth.month + 1, 0).day;
    final cells = <DateTime?>[];
    for (int i = 0; i < startOffset; i++) cells.add(null);
    for (int d = 1; d <= daysInMonth; d++) {
      cells.add(DateTime(_viewMonth.year, _viewMonth.month, d));
    }
    // Pad to complete last row
    while (cells.length % 7 != 0) cells.add(null);
    return cells;
  }

  @override
  Widget build(BuildContext context) {
    final today = _today;
    final cells = _calendarDays();
    const bg = Color(0xFF1E2022);
    const surface = Color(0xFF252829);
    const accent = Color(0xFF4FC3F7);
    const dimText = Color(0xFF9E9E9E);

    Widget quickBtn(
      IconData icon,
      String tip,
      VoidCallback onTap, {
      bool active = false,
    }) => Tooltip(
      message: tip,
      child: InkWell(
        onTap: onTap,
        borderRadius: BorderRadius.circular(8),
        child: Container(
          width: 44,
          height: 40,
          decoration: BoxDecoration(
            color: active ? accent.withOpacity(0.15) : Colors.transparent,
            borderRadius: BorderRadius.circular(8),
            border: Border.all(
              color: active ? accent.withOpacity(0.5) : Colors.transparent,
            ),
          ),
          child: Icon(icon, size: 18, color: active ? accent : Colors.white54),
        ),
      ),
    );

    return ConstrainedBox(
      constraints: const BoxConstraints(maxWidth: 268),
      child: Container(
        decoration: BoxDecoration(
          color: bg,
          borderRadius: BorderRadius.circular(10),
          border: Border.all(color: Colors.white12),
          boxShadow: [
            BoxShadow(
              color: Colors.black.withOpacity(0.4),
              blurRadius: 16,
              offset: const Offset(0, 6),
            ),
          ],
        ),
        child: Column(
          mainAxisSize: MainAxisSize.min,
          children: [
            // ── Quick-pick top bar ─────────────────────────────────────────
            Container(
              padding: const EdgeInsets.symmetric(vertical: 6),
              decoration: const BoxDecoration(
                border: Border(bottom: BorderSide(color: Colors.white10)),
              ),
              child: Row(
                mainAxisAlignment: MainAxisAlignment.spaceEvenly,
                children: [
                  quickBtn(
                    Icons.wb_sunny_outlined,
                    'Today',
                    () => _quickPick(today),
                    active: _selected == today,
                  ),
                  quickBtn(
                    Icons.wb_twilight_outlined,
                    'Tomorrow',
                    () => _quickPick(today.add(const Duration(days: 1))),
                    active: _selected == today.add(const Duration(days: 1)),
                  ),
                  quickBtn(
                    Icons.calendar_today_outlined,
                    'Next week (+7)',
                    () => _quickPick(today.add(const Duration(days: 7))),
                    active: _selected == today.add(const Duration(days: 7)),
                  ),
                  quickBtn(
                    Icons.nightlight_round,
                    'Tonight',
                    () => _quickPick(today),
                    active: false,
                  ),
                ],
              ),
            ),

            // ── Month navigation ───────────────────────────────────────────
            Padding(
              padding: const EdgeInsets.symmetric(horizontal: 12, vertical: 8),
              child: Row(
                children: [
                  GestureDetector(
                    onTap: () => setState(() {
                      _viewMonth = DateTime(
                        _viewMonth.year,
                        _viewMonth.month - 1,
                        1,
                      );
                    }),
                    child: const Icon(
                      Icons.chevron_left,
                      size: 18,
                      color: Colors.white54,
                    ),
                  ),
                  const Spacer(),
                  Text(
                    '${_monthNames[_viewMonth.month - 1]} ${_viewMonth.year}  ▾',
                    style: const TextStyle(
                      fontSize: 12,
                      fontWeight: FontWeight.w600,
                      color: Colors.white,
                      letterSpacing: 0.5,
                    ),
                  ),
                  const Spacer(),
                  GestureDetector(
                    onTap: () => setState(() {
                      _viewMonth = DateTime(
                        _viewMonth.year,
                        _viewMonth.month + 1,
                        1,
                      );
                    }),
                    child: const Icon(
                      Icons.chevron_right,
                      size: 18,
                      color: Colors.white54,
                    ),
                  ),
                ],
              ),
            ),

            // ── Weekday headers ────────────────────────────────────────────
            Padding(
              padding: const EdgeInsets.symmetric(horizontal: 10),
              child: Row(
                children: _weekDays.map((d) {
                  return Expanded(
                    child: Center(
                      child: Text(
                        d,
                        style: const TextStyle(
                          fontSize: 10,
                          fontWeight: FontWeight.w600,
                          color: dimText,
                          letterSpacing: 0.5,
                        ),
                      ),
                    ),
                  );
                }).toList(),
              ),
            ),
            const SizedBox(height: 4),

            // ── Calendar grid ──────────────────────────────────────────────
            Padding(
              padding: const EdgeInsets.symmetric(horizontal: 10),
              child: GridView.count(
                crossAxisCount: 7,
                shrinkWrap: true,
                physics: const NeverScrollableScrollPhysics(),
                childAspectRatio: 1.1,
                children: cells.map((day) {
                  if (day == null) return const SizedBox.shrink();
                  final isToday = day == today;
                  final isSelected = day == _selected;
                  final isSat = day.weekday == 6;
                  final isSun = day.weekday == 7;
                  final Color textColor = isSelected
                      ? Colors.white
                      : isToday
                      ? accent
                      : (isSat || isSun)
                      ? Colors.white38
                      : Colors.white70;

                  return GestureDetector(
                    onTap: () => setState(() => _selected = day),
                    child: Center(
                      child: AnimatedContainer(
                        duration: const Duration(milliseconds: 100),
                        width: 30,
                        height: 30,
                        decoration: BoxDecoration(
                          shape: BoxShape.circle,
                          color: isSelected
                              ? accent.withOpacity(0.25)
                              : Colors.transparent,
                          border: isToday
                              ? Border.all(color: accent, width: 1.5)
                              : isSelected
                              ? Border.all(color: accent, width: 1.5)
                              : null,
                        ),
                        child: Center(
                          child: Text(
                            '${day.day}',
                            style: TextStyle(
                              fontSize: 12,
                              color: textColor,
                              fontWeight: isToday || isSelected
                                  ? FontWeight.w600
                                  : FontWeight.normal,
                            ),
                          ),
                        ),
                      ),
                    ),
                  );
                }).toList(),
              ),
            ),
            const SizedBox(height: 4),

            // ── Time input ─────────────────────────────────────────────────
            Container(
              margin: const EdgeInsets.symmetric(horizontal: 10),
              padding: const EdgeInsets.symmetric(horizontal: 10, vertical: 8),
              decoration: BoxDecoration(
                color: surface,
                borderRadius: BorderRadius.circular(7),
                border: Border.all(color: Colors.white10),
              ),
              child: Row(
                children: [
                  // Clock icon — tapping opens the system time picker
                  GestureDetector(
                    onTap: () async {
                      final currentText = _timeCtrl.text.trim();
                      TimeOfDay initial = TimeOfDay.now();
                      if (currentText.isNotEmpty) {
                        final parts = currentText.split(':');
                        if (parts.length == 2) {
                          final h = int.tryParse(parts[0].trim());
                          final m = int.tryParse(parts[1].trim());
                          if (h != null && m != null) {
                            initial = TimeOfDay(hour: h, minute: m);
                          }
                        }
                      }
                      final picked = await showTimePicker(
                        context: context,
                        initialTime: initial,
                        builder: (ctx, child) => Theme(
                          data: Theme.of(ctx).copyWith(
                            colorScheme: const ColorScheme.dark(
                              primary: Color(0xFF4FC3F7),
                              surface: Color(0xFF1E2124),
                            ),
                            timePickerTheme: const TimePickerThemeData(
                              backgroundColor: Color(0xFF1E2124),
                            ),
                          ),
                          child: child!,
                        ),
                      );
                      if (picked != null) {
                        setState(() {
                          _timeCtrl.text =
                              '${picked.hour.toString().padLeft(2, '0')}:${picked.minute.toString().padLeft(2, '0')}';
                        });
                      }
                    },
                    child: MouseRegion(
                      cursor: SystemMouseCursors.click,
                      child: Tooltip(
                        message: 'Pick time',
                        child: Icon(
                          Icons.access_time_outlined,
                          size: 14,
                          color: _timeCtrl.text.isNotEmpty
                              ? accent
                              : Colors.white38,
                        ),
                      ),
                    ),
                  ),
                  const SizedBox(width: 10),
                  Expanded(
                    child: Column(
                      crossAxisAlignment: CrossAxisAlignment.start,
                      mainAxisSize: MainAxisSize.min,
                      children: [
                        const Text(
                          'Time',
                          style: TextStyle(
                            fontSize: 10,
                            color: Colors.white38,
                            fontWeight: FontWeight.w500,
                          ),
                        ),
                        TextField(
                          controller: _timeCtrl,
                          onChanged: (_) => setState(() {}),
                          style: const TextStyle(
                            color: Colors.white70,
                            fontSize: 12,
                          ),
                          decoration: const InputDecoration(
                            hintText: 'hh:mm',
                            hintStyle: TextStyle(
                              color: Colors.white24,
                              fontSize: 12,
                            ),
                            border: InputBorder.none,
                            isDense: true,
                            contentPadding: EdgeInsets.zero,
                          ),
                        ),
                      ],
                    ),
                  ),
                  // Clear button — only shown when a time is entered
                  if (_timeCtrl.text.isNotEmpty)
                    GestureDetector(
                      onTap: () => setState(() => _timeCtrl.clear()),
                      child: const Icon(
                        Icons.close,
                        size: 13,
                        color: Colors.white24,
                      ),
                    ),
                ],
              ),
            ),
            const SizedBox(height: 8),

            // ── Footer: Cancel / Schedule ──────────────────────────────────
            Container(
              padding: const EdgeInsets.fromLTRB(12, 8, 12, 10),
              decoration: const BoxDecoration(
                border: Border(top: BorderSide(color: Colors.white10)),
              ),
              child: Row(
                mainAxisAlignment: MainAxisAlignment.end,
                children: [
                  TextButton(
                    onPressed: widget.onCancel,
                    style: TextButton.styleFrom(
                      foregroundColor: Colors.white54,
                      padding: const EdgeInsets.symmetric(
                        horizontal: 14,
                        vertical: 7,
                      ),
                      minimumSize: Size.zero,
                      tapTargetSize: MaterialTapTargetSize.shrinkWrap,
                    ),
                    child: const Text('Cancel', style: TextStyle(fontSize: 12)),
                  ),
                  const SizedBox(width: 8),
                  ElevatedButton.icon(
                    onPressed: _selected != null ? _confirm : null,
                    icon: const Icon(Icons.calendar_month_outlined, size: 13),
                    label: const Text(
                      'Schedule',
                      style: TextStyle(
                        fontSize: 12,
                        fontWeight: FontWeight.w600,
                      ),
                    ),
                    style: ElevatedButton.styleFrom(
                      backgroundColor: _selected != null
                          ? const Color(0xFF2E7D32)
                          : Colors.white10,
                      foregroundColor: _selected != null
                          ? Colors.white
                          : Colors.white38,
                      elevation: 0,
                      padding: const EdgeInsets.symmetric(
                        horizontal: 14,
                        vertical: 7,
                      ),
                      minimumSize: Size.zero,
                      tapTargetSize: MaterialTapTargetSize.shrinkWrap,
                    ),
                  ),
                ],
              ),
            ),
          ],
        ),
      ), // ConstrainedBox
    );
  }
}

// ─────────────────────────────────────────────────────────────────────────────
// _VerticalDragListener
//
// Like _ResizeHandle but only tracks vertical delta.  Uses a raw Listener so
// it bypasses the gesture arena entirely and never gets cancelled by a parent
// ScrollView or SingleChildScrollView.
// ─────────────────────────────────────────────────────────────────────────────

class _VerticalDragListener extends StatefulWidget {
  final void Function(double dy) onDelta;
  final Widget child;

  const _VerticalDragListener({
    Key? key,
    required this.onDelta,
    required this.child,
  }) : super(key: key);

  @override
  State<_VerticalDragListener> createState() => _VerticalDragListenerState();
}

class _VerticalDragListenerState extends State<_VerticalDragListener> {
  int? _activePointer;
  double _lastY = 0;

  @override
  Widget build(BuildContext context) {
    return Listener(
      behavior: HitTestBehavior.opaque,
      onPointerDown: (e) {
        if (_activePointer != null) return;
        _activePointer = e.pointer;
        _lastY = e.position.dy;
      },
      onPointerMove: (e) {
        if (e.pointer != _activePointer) return;
        final dy = e.position.dy - _lastY;
        _lastY = e.position.dy;
        widget.onDelta(dy);
      },
      onPointerUp: (e) {
        if (e.pointer == _activePointer) _activePointer = null;
      },
      onPointerCancel: (e) {
        if (e.pointer == _activePointer) _activePointer = null;
      },
      child: widget.child,
    );
  }
}

//
// A transparent hit-area widget that uses a raw Listener (not GestureDetector)
// to track pointer deltas.  Because it bypasses the gesture arena entirely,
// it never competes with the Draggable or canvas pan detector that would
// otherwise fire when Shift is held.
// ─────────────────────────────────────────────────────────────────────────────

class _ResizeHandle extends StatefulWidget {
  final double? width;
  final double? height;
  final void Function(double dx, double dy) onDelta;
  final void Function(bool active) onActiveChanged;

  const _ResizeHandle({
    Key? key,
    this.width,
    this.height,
    required this.onDelta,
    required this.onActiveChanged,
  }) : super(key: key);

  @override
  State<_ResizeHandle> createState() => _ResizeHandleState();
}

class _ResizeHandleState extends State<_ResizeHandle> {
  int? _activePointer;
  Offset _last = Offset.zero;

  @override
  Widget build(BuildContext context) {
    return Listener(
      behavior: HitTestBehavior.opaque,
      onPointerDown: (e) {
        if (_activePointer != null) return; // ignore extra fingers
        _activePointer = e.pointer;
        _last = e.position;
        widget.onActiveChanged(true);
      },
      onPointerMove: (e) {
        if (e.pointer != _activePointer) return;
        final delta = e.position - _last;
        _last = e.position;
        widget.onDelta(delta.dx, delta.dy);
      },
      onPointerUp: (e) {
        if (e.pointer != _activePointer) return;
        _activePointer = null;
        widget.onActiveChanged(false);
      },
      onPointerCancel: (e) {
        if (e.pointer != _activePointer) return;
        _activePointer = null;
        widget.onActiveChanged(false);
      },
      child: Container(
        width: widget.width,
        height: widget.height,
        color: Colors.transparent,
      ),
    );
  }
}

// ─────────────────────────────────────────────────────────────────────────────
// _SubCanvasWidget
//
// An embedded mini-canvas that displays a task's subtasks. Subtasks can be:
//   • Panned (drag on empty space or scroll wheel)
//   • Moved within the canvas (drag the card)
//   • Promoted to the main canvas by dragging outside the container border
// The "Open Full Canvas" button navigates to _SubtaskFullCanvasScreen.
// ─────────────────────────────────────────────────────────────────────────────

class _SubCanvasWidget extends StatefulWidget {
  final double height;
  final Task parentTask;
  final List<Task> subtasks;
  final Map<String, Offset> taskPositions;
  final void Function(String id, Offset worldPos) onPositionChanged;
  final void Function(Task task, Offset globalPos) onPromote;
  final Widget Function(Task task) cardBuilder;

  const _SubCanvasWidget({
    Key? key,
    required this.height,
    required this.parentTask,
    required this.subtasks,
    required this.taskPositions,
    required this.onPositionChanged,
    required this.onPromote,
    required this.cardBuilder,
  }) : super(key: key);

  @override
  State<_SubCanvasWidget> createState() => _SubCanvasWidgetState();
}

class _SubCanvasWidgetState extends State<_SubCanvasWidget> {
  // ── Viewport pan ──
  Offset _pan = Offset.zero;
  Offset _panPointerStart = Offset.zero;
  Offset _panAtStart = Offset.zero;

  // ── Subtask drag ──
  String? _activeId;
  Offset _dragPointerStart = Offset.zero;
  Offset _taskWorldStart = Offset.zero;

  final GlobalKey _containerKey = GlobalKey();

  // ── Mini-card logical size for hit-testing ──
  static const double _cardW = 120;
  static const double _cardH = 50;

  bool _isPointerInsideContainer(Offset globalPos) {
    final box = _containerKey.currentContext?.findRenderObject() as RenderBox?;
    if (box == null) return false;
    final local = box.globalToLocal(globalPos);
    return local.dx >= 0 &&
        local.dy >= 0 &&
        local.dx <= box.size.width &&
        local.dy <= box.size.height;
  }

  String? _hitTestSubtask(Offset localPos) {
    for (final st in widget.subtasks) {
      final worldPos = widget.taskPositions[st.id] ?? const Offset(20, 20);
      final screenPos = worldPos + _pan;
      final rect = Rect.fromLTWH(screenPos.dx, screenPos.dy, _cardW, _cardH);
      if (rect.contains(localPos)) return st.id;
    }
    return null;
  }

  @override
  Widget build(BuildContext context) {
    return Column(
      mainAxisSize: MainAxisSize.min,
      crossAxisAlignment: CrossAxisAlignment.stretch,
      children: [
        // ── Subcanvas viewport ──────────────────────────────────────────────
        Container(
          key: _containerKey,
          height: widget.height,
          decoration: BoxDecoration(
            color: Colors.black.withOpacity(0.25),
            border: Border.all(color: Colors.white10),
            borderRadius: BorderRadius.circular(6),
          ),
          child: ClipRRect(
            borderRadius: BorderRadius.circular(6),
            child: Listener(
              behavior: HitTestBehavior.opaque,
              // ── Scroll-wheel panning ──
              onPointerSignal: (e) {
                if (e is PointerScrollEvent) {
                  setState(
                    () => _pan -= Offset(e.scrollDelta.dx, e.scrollDelta.dy),
                  );
                }
              },
              // ── Pointer down: hit-test to decide pan vs. task-drag ──
              onPointerDown: (e) {
                final hit = _hitTestSubtask(e.localPosition);
                if (hit != null) {
                  setState(() {
                    _activeId = hit;
                    _dragPointerStart = e.position;
                    _taskWorldStart =
                        widget.taskPositions[hit] ?? const Offset(20, 20);
                  });
                } else {
                  _panPointerStart = e.position;
                  _panAtStart = _pan;
                }
              },
              // ── Pointer move: move task or pan ──
              onPointerMove: (e) {
                if (_activeId != null) {
                  // Check if pointer has left the container → promote
                  if (!_isPointerInsideContainer(e.position)) {
                    final task = widget.subtasks.firstWhere(
                      (t) => t.id == _activeId,
                    );
                    widget.onPromote(task, e.position);
                    setState(() => _activeId = null);
                  } else {
                    final delta = e.position - _dragPointerStart;
                    final newWorld = _taskWorldStart + delta;
                    widget.onPositionChanged(_activeId!, newWorld);
                  }
                } else if (_panPointerStart != Offset.zero) {
                  setState(
                    () => _pan = _panAtStart + (e.position - _panPointerStart),
                  );
                }
              },
              // ── Pointer up: clear drag state ──
              onPointerUp: (_) {
                setState(() {
                  _activeId = null;
                  _panPointerStart = Offset.zero;
                });
              },
              onPointerCancel: (_) {
                setState(() {
                  _activeId = null;
                  _panPointerStart = Offset.zero;
                });
              },
              child: Stack(
                clipBehavior: Clip.none,
                children: [
                  // Dot-grid background
                  Positioned.fill(
                    child: CustomPaint(
                      painter: GridPainter(
                        offset: _pan,
                        scale: 1.0,
                        thickness: 0.5,
                        color: Colors.white12,
                      ),
                    ),
                  ),
                  // Subtask cards
                  ...widget.subtasks.map((st) {
                    final worldPos =
                        widget.taskPositions[st.id] ?? const Offset(20, 20);
                    final screenPos = worldPos + _pan;
                    final isDragging = st.id == _activeId;
                    return Positioned(
                      left: screenPos.dx,
                      top: screenPos.dy,
                      child: Opacity(
                        opacity: isDragging ? 0.55 : 1.0,
                        child: widget.cardBuilder(st),
                      ),
                    );
                  }),
                  // "Drag out to promote" hint
                  const Positioned(
                    bottom: 5,
                    right: 8,
                    child: Text(
                      'DRAG OUT TO PROMOTE',
                      style: TextStyle(
                        color: Colors.white12,
                        fontSize: 8,
                        letterSpacing: 0.5,
                      ),
                    ),
                  ),
                ],
              ),
            ),
          ),
        ),
      ],
    );
  }
}

// ─────────────────────────────────────────────────────────────────────────────
// _CropImageDialog
//
// A self-contained square/circle crop dialog for desktop Flutter.
// The user pans and pinch-zooms the image behind a circular mask, then hits
// "Crop & Save" to write the result to a temp PNG and return its path.
// ─────────────────────────────────────────────────────────────────────────────

class _CropImageDialog extends StatefulWidget {
  final String imagePath;
  const _CropImageDialog({required this.imagePath});

  @override
  State<_CropImageDialog> createState() => _CropImageDialogState();
}

class _CropImageDialogState extends State<_CropImageDialog> {
  ui.Image? _image;
  Offset _offset = Offset.zero;
  double _scale = 1.0;
  Offset _lastFocalPoint = Offset.zero;
  double _lastScale = 1.0;
  bool _saving = false;

  static const double _cropSize = 300.0;

  @override
  void initState() {
    super.initState();
    _loadImage();
  }

  Future<void> _loadImage() async {
    final bytes = await File(widget.imagePath).readAsBytes();
    final codec = await ui.instantiateImageCodec(bytes);
    final frame = await codec.getNextFrame();
    if (mounted) setState(() => _image = frame.image);
  }

  // Clamp so image always covers the circle
  Offset _clampOffset(Offset o, Size imgDisplaySize) {
    final halfCrop = _cropSize / 2;
    final halfW = imgDisplaySize.width / 2;
    final halfH = imgDisplaySize.height / 2;
    return Offset(
      o.dx.clamp(halfCrop - halfW, halfW - halfCrop),
      o.dy.clamp(halfCrop - halfH, halfH - halfCrop),
    );
  }

  Future<void> _save() async {
    if (_image == null) return;
    setState(() => _saving = true);

    final recorder = ui.PictureRecorder();
    final canvas = Canvas(recorder);

    // Compute how the image is drawn inside the preview so we can replicate it
    final iw = _image!.width.toDouble();
    final ih = _image!.height.toDouble();
    final fitScale = _cropSize / (iw < ih ? iw : ih); // cover base
    final drawW = iw * fitScale * _scale;
    final drawH = ih * fitScale * _scale;

    final src = Rect.fromLTWH(0, 0, iw, ih);
    final dst = Rect.fromCenter(
      center: Offset(_cropSize / 2, _cropSize / 2) + _offset,
      width: drawW,
      height: drawH,
    );

    // Clip to circle
    canvas.clipPath(Path()..addOval(Rect.fromLTWH(0, 0, _cropSize, _cropSize)));
    canvas.drawImageRect(
      _image!,
      src,
      dst,
      Paint()..filterQuality = FilterQuality.high,
    );

    final picture = recorder.endRecording();
    final img = await picture.toImage(_cropSize.toInt(), _cropSize.toInt());
    final pngBytes = await img.toByteData(format: ui.ImageByteFormat.png);

    final tmp =
        '${Directory.systemTemp.path}/ws_avatar_${DateTime.now().millisecondsSinceEpoch}.png';
    await File(tmp).writeAsBytes(pngBytes!.buffer.asUint8List());

    if (mounted) Navigator.pop(context, tmp);
  }

  @override
  Widget build(BuildContext context) {
    return Dialog(
      backgroundColor: const Color(0xFF1A1A1A),
      shape: RoundedRectangleBorder(borderRadius: BorderRadius.circular(12)),
      child: Padding(
        padding: const EdgeInsets.all(24),
        child: Column(
          mainAxisSize: MainAxisSize.min,
          children: [
            // ── Header ──────────────────────────────────────────────────────
            Row(
              children: [
                const Icon(
                  Icons.crop_rotate,
                  color: Colors.blueAccent,
                  size: 18,
                ),
                const SizedBox(width: 10),
                const Text(
                  'CROP IMAGE',
                  style: TextStyle(
                    color: Colors.white70,
                    fontSize: 12,
                    fontWeight: FontWeight.bold,
                    letterSpacing: 1.2,
                  ),
                ),
                const Spacer(),
                const Text(
                  'Pan & scroll to position',
                  style: TextStyle(color: Colors.white24, fontSize: 11),
                ),
              ],
            ),

            const SizedBox(height: 20),

            // ── Crop viewport ────────────────────────────────────────────────
            SizedBox(
              width: _cropSize,
              height: _cropSize,
              child: _image == null
                  ? const Center(
                      child: CircularProgressIndicator(
                        color: Colors.blueAccent,
                      ),
                    )
                  : GestureDetector(
                      onScaleStart: (d) {
                        _lastFocalPoint = d.localFocalPoint;
                        _lastScale = _scale;
                      },
                      onScaleUpdate: (d) {
                        setState(() {
                          _scale = (_lastScale * d.scale).clamp(0.5, 8.0);
                          final delta = d.localFocalPoint - _lastFocalPoint;
                          _lastFocalPoint = d.localFocalPoint;
                          final iw = _image!.width.toDouble();
                          final ih = _image!.height.toDouble();
                          final fitScale = _cropSize / (iw < ih ? iw : ih);
                          final dispSize = Size(
                            iw * fitScale * _scale,
                            ih * fitScale * _scale,
                          );
                          _offset = _clampOffset(_offset + delta, dispSize);
                        });
                      },
                      child: Listener(
                        onPointerSignal: (e) {
                          if (e is PointerScrollEvent) {
                            setState(() {
                              final dir = e.scrollDelta.dy < 0 ? 1.05 : 0.95;
                              _scale = (_scale * dir).clamp(0.5, 8.0);
                              final iw = _image!.width.toDouble();
                              final ih = _image!.height.toDouble();
                              final fitScale = _cropSize / (iw < ih ? iw : ih);
                              final dispSize = Size(
                                iw * fitScale * _scale,
                                ih * fitScale * _scale,
                              );
                              _offset = _clampOffset(_offset, dispSize);
                            });
                          }
                        },
                        child: ClipOval(
                          child: CustomPaint(
                            size: const Size(_cropSize, _cropSize),
                            painter: _ImagePainter(
                              image: _image!,
                              offset: _offset,
                              scale: _scale,
                              cropSize: _cropSize,
                            ),
                          ),
                        ),
                      ),
                    ),
            ),

            // ── Ring border around the viewport ──────────────────────────────
            const SizedBox(height: 4),
            Container(
              width: _cropSize + 4,
              height: 2,
              decoration: BoxDecoration(
                borderRadius: BorderRadius.circular(1),
                color: Colors.blueAccent.withOpacity(0.4),
              ),
            ),

            const SizedBox(height: 20),

            // ── Actions ──────────────────────────────────────────────────────
            Row(
              mainAxisAlignment: MainAxisAlignment.end,
              children: [
                TextButton(
                  onPressed: () => Navigator.pop(context),
                  child: const Text(
                    'Cancel',
                    style: TextStyle(color: Colors.white38),
                  ),
                ),
                const SizedBox(width: 8),
                TextButton(
                  onPressed: _saving ? null : _save,
                  child: _saving
                      ? const SizedBox(
                          width: 14,
                          height: 14,
                          child: CircularProgressIndicator(
                            strokeWidth: 2,
                            color: Colors.blueAccent,
                          ),
                        )
                      : const Text(
                          'Apply',
                          style: TextStyle(
                            color: Colors.blueAccent,
                            fontWeight: FontWeight.bold,
                          ),
                        ),
                ),
              ],
            ),
          ],
        ),
      ),
    );
  }
}

class _ImagePainter extends CustomPainter {
  final ui.Image image;
  final Offset offset;
  final double scale;
  final double cropSize;

  const _ImagePainter({
    required this.image,
    required this.offset,
    required this.scale,
    required this.cropSize,
  });

  @override
  void paint(Canvas canvas, Size size) {
    final iw = image.width.toDouble();
    final ih = image.height.toDouble();
    final fitScale = cropSize / (iw < ih ? iw : ih);
    final drawW = iw * fitScale * scale;
    final drawH = ih * fitScale * scale;

    final src = Rect.fromLTWH(0, 0, iw, ih);
    final dst = Rect.fromCenter(
      center: Offset(cropSize / 2, cropSize / 2) + offset,
      width: drawW,
      height: drawH,
    );
    canvas.drawImageRect(
      image,
      src,
      dst,
      Paint()..filterQuality = FilterQuality.high,
    );
  }

  @override
  bool shouldRepaint(_ImagePainter old) =>
      old.offset != offset || old.scale != scale || old.image != image;
}

