// _NotesPageButton — small icon button used in the Notes header of the Task
// Details panel. Matches the magnifying-glass style used by PROJECT / TAGS
// headers. Disabled (greyed) when onTap is null.
// ─────────────────────────────────────────────────────────────────────────────

class _NotesPageButton extends StatefulWidget {
  final VoidCallback? onTap;
  const _NotesPageButton({this.onTap});

  @override
  State<_NotesPageButton> createState() => _NotesPageButtonState();
}

class _NotesPageButtonState extends State<_NotesPageButton> {
  bool _hovered = false;

  @override
  Widget build(BuildContext context) {
    const accent = Color(0xFF4FC3F7);
    final enabled = widget.onTap != null;
    final active = enabled && _hovered;

    return MouseRegion(
      cursor: enabled ? SystemMouseCursors.click : SystemMouseCursors.basic,
      onEnter: (_) => setState(() => _hovered = true),
      onExit: (_) => setState(() => _hovered = false),
      child: Tooltip(
        message: enabled ? 'Open notes page' : 'No notes page',
        waitDuration: const Duration(milliseconds: 400),
        child: GestureDetector(
          onTap: widget.onTap,
          child: AnimatedContainer(
            duration: const Duration(milliseconds: 120),
            width: 20,
            height: 20,
            decoration: BoxDecoration(
              color: active ? accent.withOpacity(0.12) : Colors.transparent,
              borderRadius: BorderRadius.circular(4),
            ),
            child: Icon(
              Icons.open_in_new_rounded,
              size: 13,
              color: active
                  ? accent
                  : (enabled ? Colors.white24 : Colors.white12),
            ),
          ),
        ),
      ),
    );
  }
}

