  final VoidCallback? onCancelGeneral;
  final VoidCallback? onFocusOverlayGeneral;
  final VoidCallback? onStartStaging;
  final VoidCallback? onStartFlowtime;
  final void Function(Task)? onRepeatChanged;
  final void Function(Task, _RepeatPropagateScope, Set<String>)?
  onPropagateScoped;
  final void Function(Task instance, RepeatConfig newCfg)? onApplyForward;
  final void Function(
    Task parent,
    RepeatConfig cfg,
    _RepeatPropagateScope scope,
  )?
  onApplyScoped;

  /// Called when the user taps the "open notes page" button in the Notes
  /// header. The parent should navigate to the Notes view and open the
