    this.stagingBlocks = const [],
    this.activeStagingTaskId,
    this.stagingPhaseIndex = 0,
    this.stagingPhaseStarted,
    this.executionSessions = const [],
    this.allTags = const [],
    this.allTasks = const [],
    required this.onSubTaskCreated,
    this.activeGeneralTaskId,
    this.generalTimerStartedAt,
    this.onStartGeneral,
    this.onCancelGeneral,
    this.onFocusOverlayGeneral,
    this.onStartStaging,
    this.onStartFlowtime,
    this.onRepeatChanged,
    this.onPropagateScoped,
    this.onApplyForward,
    this.onApplyScoped,
    this.onOpenTaskNote,
  });

  @override
  State<_TaskDetailsPanel> createState() => _TaskDetailsPanelState();
}

class _TaskDetailsPanelState extends State<_TaskDetailsPanel> {
  late final TextEditingController _titleCtrl;
  late final TextEditingController _notesCtrl;
  late final TextEditingController _timeSpentCtrl;
  late final TextEditingController _estimateCtrl;
  late final TextEditingController _tagAddCtrl;
  late final TextEditingController _subTaskAddCtrl;
  bool _tagAddOpen = false;
  bool _subTaskAddOpen = false;
  bool _subTasksExpanded = true;

  // ── Filter state for PROJECT and TAGS sections ───────────────────────────
  bool _projectFilterOpen = false;
  String _projectFilterQuery = '';
  late final TextEditingController _projectFilterCtrl;
  bool _tagsFilterOpen = false;
  String _tagsFilterQuery = '';
  late final TextEditingController _tagsFilterCtrl;
  bool _timeExpanded = true;
  bool _dueSchedulingExpanded = true;

  /// Propagation scope for repeat instances
  _RepeatPropagateScope _propagateScope = _RepeatPropagateScope.current;

  /// Which fields will be copied to siblings when Propagate is tapped.
  final Set<String> _propagateFields = {};

  // ── Propagation helpers ─────────────────────────────────────────────────────

  /// A small checkbox on the left of each field row, visible only when
  /// [_repeatExpanded] is true. [key] maps to [_propagateFields].
  Widget _buildPropagateCheckbox(String key) {
    if (!_repeatExpanded) return const SizedBox.shrink();
    final checked = _propagateFields.contains(key);
    return GestureDetector(
      onTap: () => setState(() {
        if (checked) {
          _propagateFields.remove(key);
        } else {
          _propagateFields.add(key);
        }
      }),
      child: AnimatedContainer(
        duration: const Duration(milliseconds: 120),
        width: 14,
        height: 14,
        decoration: BoxDecoration(
          color: checked
              ? const Color(0xFF4FC3F7).withOpacity(0.18)
              : Colors.transparent,
          borderRadius: BorderRadius.circular(3),
          border: Border.all(
            color: checked
                ? const Color(0xFF4FC3F7)
                : Colors.white.withOpacity(0.2),
            width: 1.5,
          ),
        ),
        child: checked
            ? const Icon(Icons.check_rounded, size: 9, color: Color(0xFF4FC3F7))
            : null,
      ),
    );
  }

  /// Renders a section with an optional propagate checkbox aligned with
  /// the label. When [_repeatExpanded] is false the checkbox is hidden and
  /// the layout is identical to the collapsed state.
  ///
  /// [labelText] – the section label string (e.g. 'TITLE'). Pass null for
  /// sections that have no label (e.g. Sub-tasks).
  /// [field] – the input widget(s) below the label.
  /// [labelSpacing] – gap between label and field (default 6).
  /// [bottomSpacing] – gap below the field (default 18).
  Widget _fieldRow(
    String key,
    String? labelText,
    Widget field, {
    double labelSpacing = 6,
    double bottomSpacing = 18,
  }) {
    final label = labelText != null ? _sectionLabel(labelText) : null;

    if (!_repeatExpanded) {
      // Collapsed: plain label + field, no checkbox
      return Column(
        crossAxisAlignment: CrossAxisAlignment.stretch,
        children: [
          if (label != null) ...[label, SizedBox(height: labelSpacing)],
          field,
          SizedBox(height: bottomSpacing),
        ],
      );
    }

    // Expanded: checkbox shares a Row with the label, field sits below
    final checkbox = _buildPropagateCheckbox(key);
    return Column(
      crossAxisAlignment: CrossAxisAlignment.stretch,
      children: [
        Row(
          crossAxisAlignment: CrossAxisAlignment.center,
          children: [
            checkbox,
            const SizedBox(width: 6),
            if (label != null) label,
          ],
        ),
        SizedBox(height: labelSpacing),
        field,
        SizedBox(height: bottomSpacing),
      ],
    );
  }

  /// Whether the Repeat + Apply Changes To section is expanded in the panel.
  bool _repeatExpanded = false;

  /// Converts milliseconds → "Xh Ym" or "Xm" or "0m"
  static String _msToLabel(int ms) {
    final h = ms ~/ 3600000;
    final m = (ms % 3600000) ~/ 60000;
    if (h > 0 && m > 0) return '${h}h ${m}m';
    if (h > 0) return '${h}h';
    return '${m}m';
  }

  /// Parses "Xh Ym", "Xh", "Ym", bare minutes, or "X:YY" → milliseconds. Returns null on failure.
  static int? _parseTimeInput(String raw) {
    final s = raw.trim();
    if (s.isEmpty) return null;
    // "1h 30m" or "1h30m"
    final hm = RegExp(
      r'^(\d+)h\s*(\d*)m?$',
      caseSensitive: false,
    ).firstMatch(s);
    if (hm != null) {
      final h = int.parse(hm.group(1)!);
      final m = hm.group(2)!.isEmpty ? 0 : int.parse(hm.group(2)!);
      return (h * 60 + m) * 60000;
    }
    // "30m"
    final mOnly = RegExp(r'^(\d+)m$', caseSensitive: false).firstMatch(s);
    if (mOnly != null) return int.parse(mOnly.group(1)!) * 60000;
    // "1:30"
    final colon = RegExp(r'^(\d+):(\d{2})$').firstMatch(s);
    if (colon != null) {
      final h = int.parse(colon.group(1)!);
      final m = int.parse(colon.group(2)!);
      return (h * 60 + m) * 60000;
    }
    // bare integer → minutes
    final bare = int.tryParse(s);
    if (bare != null) return bare * 60000;
    return null;
  }

  @override
  void initState() {
    super.initState();
    _titleCtrl = TextEditingController(text: widget.task.title);
    _notesCtrl = TextEditingController(text: widget.task.notes ?? '');
    _timeSpentCtrl = TextEditingController(
      text: _msToLabel(widget.task.timeSpent),
    );
    _estimateCtrl = TextEditingController(
      text: _msToLabel(widget.task.durationMinutes * 60000),
    );
    _tagAddCtrl = TextEditingController();
    _subTaskAddCtrl = TextEditingController();
    _projectFilterCtrl = TextEditingController();
    _tagsFilterCtrl = TextEditingController();
  }

  @override
  void dispose() {
    _titleCtrl.dispose();
    _notesCtrl.dispose();
    _timeSpentCtrl.dispose();
    _estimateCtrl.dispose();
    _tagAddCtrl.dispose();
    _subTaskAddCtrl.dispose();
    _projectFilterCtrl.dispose();
    _tagsFilterCtrl.dispose();
    super.dispose();
  }

  void _save(VoidCallback mutate) {
    mutate();
    setState(() {});
    unawaited(widget.onSave(widget.task));
    // Propagation is triggered explicitly by the "Apply Changes To" button,
    // not automatically on every save.
  }

  Future<void> _pickDate() async {
    final task = widget.task;
    final now = DateTime.now();
    final initial = task.dueDay != null
        ? (DateTime.tryParse(task.dueDay!) ?? now)
        : now;
    final picked = await showDatePicker(
      context: context,
      initialDate: initial,
      firstDate: DateTime(2020),
      lastDate: DateTime(2030),
      builder: (ctx, child) => Theme(
        data: Theme.of(ctx).copyWith(
          colorScheme: const ColorScheme.dark(
            primary: Color(0xFF4FC3F7),
            surface: Color(0xFF1E2124),
          ),
        ),
        child: child!,
      ),
    );
    if (picked != null) {
      _save(() => task.dueDay = picked.toIso8601String().split('T').first);
    }
  }

  Widget _buildPropagationScopeDropdown(Task task) {
