                        Text(
                          'Propagate',
                          style: TextStyle(
                            fontSize: 10,
                            fontWeight: FontWeight.w600,
                            color:
                                _propagateScope != _RepeatPropagateScope.current
                                ? const Color(0xFF4FC3F7)
