  @override
  Widget build(BuildContext context) {
    final task = widget.task;
    final color = const Color(0xFF1A1C1F);
    final borderColor = Colors.white.withOpacity(0.07);

    // Format due date nicely
    String? dueFmt;
    if (task.dueDay != null) {
      final d = DateTime.tryParse(task.dueDay!);
      if (d != null) {
        final months = [
          'Jan',
          'Feb',
          'Mar',
          'Apr',
          'May',
          'Jun',
          'Jul',
          'Aug',
          'Sep',
          'Oct',
          'Nov',
          'Dec',
        ];
        dueFmt = '${months[d.month - 1]} ${d.day}, ${d.year}';
      }
    }

    // Duration display
    final int durH = task.durationMinutes ~/ 60;
    final int durM = task.durationMinutes % 60;
    final String durLabel = durH > 0
        ? (durM > 0 ? '${durH}h ${durM}m' : '${durH}h')
        : '${durM}m';

    return Container(
      width: 300,
      decoration: BoxDecoration(
        color: color,
        border: Border(left: BorderSide(color: borderColor, width: 1)),
      ),
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.stretch,
        children: [
          // ── Header ────────────────────────────────────────────
          Container(
            padding: const EdgeInsets.fromLTRB(16, 14, 8, 14),
            decoration: BoxDecoration(
              border: Border(bottom: BorderSide(color: borderColor)),
            ),
            child: Row(
              children: [
                Icon(task.status.icon, size: 16, color: task.status.color),
                const SizedBox(width: 10),
                const Expanded(
                  child: Text(
                    'Task Details',
                    style: TextStyle(
                      color: Colors.white70,
                      fontSize: 12,
                      fontWeight: FontWeight.w600,
                      letterSpacing: 0.3,
                    ),
                  ),
                ),
                // Repeat toggle button
                Builder(
                  builder: (context) {
                    final hasRepeat =
                        task.repeatConfig != null ||
                        task.repeatParentId != null;
                    final isActive = _repeatExpanded;
                    return Tooltip(
                      message: isActive
                          ? 'Hide Repeat & Propagation'
                          : 'Show Repeat & Propagation',
                      child: GestureDetector(
                        onTap: () =>
                            setState(() => _repeatExpanded = !_repeatExpanded),
                        child: AnimatedContainer(
                          duration: const Duration(milliseconds: 150),
                          padding: const EdgeInsets.symmetric(
                            horizontal: 7,
                            vertical: 4,
                          ),
                          decoration: BoxDecoration(
                            color: isActive
                                ? const Color(0xFF4FC3F7).withOpacity(0.12)
                                : hasRepeat
                                ? const Color(0xFF4FC3F7).withOpacity(0.06)
                                : Colors.transparent,
                            borderRadius: BorderRadius.circular(5),
                            border: Border.all(
                              color: isActive
                                  ? const Color(0xFF4FC3F7).withOpacity(0.4)
                                  : hasRepeat
                                  ? const Color(0xFF4FC3F7).withOpacity(0.2)
                                  : Colors.transparent,
                            ),
                          ),
                          child: Row(
                            mainAxisSize: MainAxisSize.min,
                            children: [
                              Icon(
                                Icons.repeat_rounded,
                                size: 12,
                                color: isActive
                                    ? const Color(0xFF4FC3F7)
                                    : hasRepeat
                                    ? const Color(0xFF4FC3F7).withOpacity(0.6)
                                    : Colors.white30,
                              ),
                              if (hasRepeat && !isActive) ...[
                                const SizedBox(width: 3),
                                Container(
                                  width: 5,
                                  height: 5,
                                  decoration: const BoxDecoration(
                                    shape: BoxShape.circle,
                                    color: Color(0xFF4FC3F7),
                                  ),
                                ),
                              ],
                              const SizedBox(width: 4),
                              Icon(
                                isActive
                                    ? Icons.expand_less_rounded
                                    : Icons.expand_more_rounded,
                                size: 12,
                                color: isActive
                                    ? const Color(0xFF4FC3F7)
                                    : Colors.white30,
                              ),
                            ],
                          ),
                        ),
                      ),
                    );
                  },
                ),
                const SizedBox(width: 2),
                IconButton(
                  icon: const Icon(
                    Icons.close,
                    color: Colors.white24,
                    size: 16,
                  ),
                  padding: EdgeInsets.zero,
                  constraints: const BoxConstraints(
                    minWidth: 28,
                    minHeight: 28,
                  ),
                  onPressed: widget.onClose,
                ),
              ],
            ),
          ),

          // ── Scrollable fields ──────────────────────────────────
          Expanded(
            child: ListView(
              padding: const EdgeInsets.fromLTRB(14, 16, 14, 32),
              children: [
                // ── Repeat + Apply Changes To (collapsible) ─────────
                AnimatedSize(
                  duration: const Duration(milliseconds: 200),
                  curve: Curves.easeInOut,
                  child: _repeatExpanded
                      ? Column(
                          crossAxisAlignment: CrossAxisAlignment.stretch,
                          children: [
                            // Propagation scope (instances only)
                            if (task.repeatParentId != null) ...[
                              _buildPropagationScopeDropdown(task),
                              const SizedBox(height: 12),
                            ],

                            // Repeat config row
                            _sectionLabel('REPEAT'),
                            const SizedBox(height: 6),
                            GestureDetector(
                              onTap: () async {
                                Future<void> openDialog(Task target) async {
                                  final result = await showDialog<RepeatConfig>(
                                    context: context,
                                    builder: (_) => _RepeatConfigDialog(
                                      task: target,
                                      initial: target.repeatParentId != null
                                          ? widget.allTasks
                                                .firstWhere(
                                                  (t) =>
                                                      t.id ==
                                                      target.repeatParentId,
                                                  orElse: () => target,
                                                )
                                                .repeatConfig
                                          : target.repeatConfig,
                                      allTasks: widget.allTasks,
                                      onRefresh: target.repeatConfig != null
                                          ? () => widget.onRepeatChanged?.call(
                                              target,
                                            )
                                          : null,
                                      onRefreshFromInstance:
                                          target.repeatParentId != null
                                          ? () => widget.onRepeatChanged?.call(
                                              target,
                                            )
                                          : null,
                                      onApplyForward:
                                          target.repeatParentId != null
                                          ? (cfg) => widget.onApplyForward
                                                ?.call(target, cfg)
                                          : null,
                                      onApplyScoped:
                                          target.repeatParentId == null
                                          ? (cfg, scope) => widget.onApplyScoped
                                                ?.call(target, cfg, scope)
                                          : null,
                                      onOpenParentConfig:
                                          target.repeatParentId != null
                                          ? () {
                                              final parent = widget.allTasks
                                                  .firstWhere(
                                                    (t) =>
                                                        t.id ==
                                                        target.repeatParentId,
                                                    orElse: () => target,
                                                  );
                                              openDialog(parent);
                                            }
                                          : null,
                                    ),
                                  );
                                  if (result != null &&
                                      target.repeatParentId == null) {
                                    _save(() {
                                      target.repeatConfig = result.cleared
                                          ? null
                                          : result;
                                      final anchor = result.anchorDate;
                                      if (!result.cleared && anchor != null) {
                                        target.dueDay = anchor
                                            .toIso8601String()
                                            .split('T')
                                            .first;
                                        if (target.plannedAt != null) {
                                          final old =
                                              DateTime.fromMillisecondsSinceEpoch(
                                                target.plannedAt!,
                                              );
                                          target.plannedAt = DateTime(
                                            anchor.year,
                                            anchor.month,
                                            anchor.day,
                                            old.hour,
                                            old.minute,
                                          ).millisecondsSinceEpoch;
                                        }
                                      }
                                    });
                                    widget.onRepeatChanged?.call(target);
                                  }
                                }

                                await openDialog(task);
                              },
                              child: Container(
                                padding: const EdgeInsets.symmetric(
                                  horizontal: 10,
                                  vertical: 7,
                                ),
                                decoration: BoxDecoration(
                                  color: Colors.white.withOpacity(0.04),
                                  borderRadius: BorderRadius.circular(5),
                                  border: Border.all(
                                    color: Colors.white.withOpacity(0.1),
                                  ),
                                ),
                                child: Row(
                                  children: [
                                    Icon(
                                      Icons.repeat_rounded,
                                      size: 13,
                                      color:
                                          (task.repeatConfig != null ||
                                              task.repeatParentId != null)
                                          ? const Color(0xFF4FC3F7)
                                          : Colors.white38,
                                    ),
                                    const SizedBox(width: 8),
                                    Expanded(
                                      child: () {
                                        String label;
                                        if (task.repeatParentId != null) {
                                          final parent = widget.allTasks
                                              .firstWhere(
                                                (t) =>
                                                    t.id == task.repeatParentId,
                                                orElse: () => task,
                                              );
                                          label =
                                              parent.repeatConfig?.label ??
                                              'Repeat instance';
                                        } else {
                                          label =
                                              task.repeatConfig?.label ??
                                              'No repeat';
                                        }
                                        return Text(
                                          label,
                                          style: TextStyle(
                                            fontSize: 11,
                                            color:
                                                (task.repeatConfig != null ||
                                                    task.repeatParentId != null)
                                                ? Colors.white70
                                                : Colors.white38,
                                          ),
                                        );
                                      }(),
                                    ),
                                    const Icon(
                                      Icons.chevron_right_rounded,
                                      size: 14,
                                      color: Colors.white24,
                                    ),
                                  ],
                                ),
                              ),
                            ),
                            const SizedBox(height: 12),
                          ],
                        )
                      : const SizedBox.shrink(),
                ),

                // ── Divider + propagation selection controls ────────────
                if (_repeatExpanded) ...[
                  const SizedBox(height: 8),
                  Row(
                    children: [
                      const Expanded(
                        child: Divider(
                          color: Color(0xFF2A2D30),
                          thickness: 1,
                          height: 1,
                        ),
                      ),
                      const SizedBox(width: 10),
                      GestureDetector(
                        onTap: () => setState(
                          () => _propagateFields
                            ..addAll([
                              'title',
                              'status',
                              'time',
                              'duration',
                              'notes',
                              'tags',
                              'subtasks',
                            ]),
                        ),
                        child: Text(
                          'Select all',
                          style: TextStyle(
                            fontSize: 10,
                            color: Colors.white.withOpacity(0.35),
                          ),
                        ),
                      ),
                      const SizedBox(width: 8),
                      Text(
                        '·',
                        style: TextStyle(
                          fontSize: 10,
                          color: Colors.white.withOpacity(0.2),
                        ),
                      ),
                      const SizedBox(width: 8),
                      GestureDetector(
                        onTap: () => setState(() => _propagateFields.clear()),
                        child: Text(
                          'Deselect all',
                          style: TextStyle(
                            fontSize: 10,
                            color: Colors.white.withOpacity(0.35),
                          ),
                        ),
                      ),
                      const SizedBox(width: 10),
                      const Expanded(
                        child: Divider(
                          color: Color(0xFF2A2D30),
                          thickness: 1,
                          height: 1,
                        ),
                      ),
                    ],
                  ),
                  const SizedBox(height: 12),
                ] else
                  const SizedBox(height: 8),

                // Title
                _fieldRow(
                  'title',
                  'TITLE',
                  TextField(
                    controller: _titleCtrl,
                    maxLines: 2,
                    // Spec §1: block reserved filesystem chars in titles.
                    inputFormatters: [
                      FilteringTextInputFormatter.deny(RegExp(r'[/\\:]')),
                    ],
                    onChanged: (v) {
                      // Spec §1: also strip defensively on every change.
                      final safe = v.replaceAll(RegExp(r'[/\\:]'), '');
                      if (safe != v) {
                        _titleCtrl.value = TextEditingValue(
                          text: safe,
                          selection: TextSelection.collapsed(
                            offset: safe.length,
                          ),
                        );
                      }
                      _save(
                        () => task.title = safe.trim().isEmpty
                            ? task.title
                            : safe,
                      );
                    },
                    style: const TextStyle(color: Colors.white, fontSize: 13),
                    decoration: _inputDecoration('Task title…'),
                  ),
                ),

                // Status
                _fieldRow(
                  'status',
                  'STATUS',
                  Wrap(
                    spacing: 6,
                    runSpacing: 6,
                    children: TaskStatus.values.map((s) {
                      final active = task.status == s;
                      return GestureDetector(
                        onTap: () => _save(() {
                          task.status = s;
                          task.isDone = s == TaskStatus.done;
                        }),
                        child: Container(
                          padding: const EdgeInsets.symmetric(
                            horizontal: 8,
                            vertical: 5,
                          ),
                          decoration: BoxDecoration(
                            color: active
                                ? s.color.withOpacity(0.18)
                                : const Color(0xFF252729),
                            borderRadius: BorderRadius.circular(5),
                            border: Border.all(
                              color: active
                                  ? s.color.withOpacity(0.6)
                                  : Colors.white10,
                            ),
                          ),
                          child: Row(
                            mainAxisSize: MainAxisSize.min,
                            children: [
                              Icon(
                                s.icon,
                                size: 11,
                                color: active ? s.color : Colors.white24,
                              ),
                              const SizedBox(width: 5),
                              Text(
                                s.label,
                                style: TextStyle(
                                  fontSize: 11,
                                  color: active ? s.color : Colors.white38,
                                  fontWeight: active
                                      ? FontWeight.w600
                                      : FontWeight.normal,
                                ),
                              ),
                            ],
                          ),
                        ),
                      );
                    }).toList(),
                  ),
                  labelSpacing: 8,
                ),

                // Planning (Date — not propagated, anchor per instance)
                _collapsibleLabel(
                  'PLANNING',
                  _dueSchedulingExpanded,
                  () => setState(
                    () => _dueSchedulingExpanded = !_dueSchedulingExpanded,
                  ),
                ),
                if (_dueSchedulingExpanded) ...[
                  const SizedBox(height: 6),
                  Container(
                    padding: const EdgeInsets.fromLTRB(10, 12, 10, 12),
                    decoration: BoxDecoration(
                      color: const Color(0xFF1C1F21),
                      borderRadius: BorderRadius.circular(6),
                      border: Border.all(color: Colors.white.withOpacity(0.08)),
                    ),
                    child: Column(
                      crossAxisAlignment: CrossAxisAlignment.stretch,
                      children: [
                        // DATE (no checkbox — each instance has its own date)
                        _sectionLabel('DATE'),
                        const SizedBox(height: 6),
                        GestureDetector(
                          onTap: _pickDate,
                          child: Container(
                            padding: const EdgeInsets.symmetric(
                              horizontal: 10,
                              vertical: 10,
                            ),
                            decoration: BoxDecoration(
                              color: const Color(0xFF252729),
                              borderRadius: BorderRadius.circular(6),
                              border: Border.all(color: Colors.white10),
                            ),
                            child: Row(
                              children: [
                                Icon(
                                  Icons.calendar_today_outlined,
                                  size: 13,
                                  color: dueFmt != null
                                      ? const Color(0xFF4FC3F7)
                                      : Colors.white24,
                                ),
                                const SizedBox(width: 8),
                                Expanded(
                                  child: Text(
                                    dueFmt ?? 'No date set',
                                    style: TextStyle(
                                      fontSize: 12,
                                      color: dueFmt != null
                                          ? Colors.white70
                                          : Colors.white24,
                                    ),
                                  ),
                                ),
                                if (dueFmt != null)
                                  GestureDetector(
                                    onTap: () =>
                                        _save(() => task.dueDay = null),
                                    child: const Icon(
                                      Icons.close,
                                      size: 13,
                                      color: Colors.white24,
                                    ),
                                  ),
                              ],
                            ),
                          ),
                        ),
                        const SizedBox(height: 12),

                        // TIME — has propagate checkbox
                        _fieldRow(
                          'time',
                          'TIME',
                          GestureDetector(
                            onTap: () async {
                              final now = TimeOfDay.now();
                              final picked = await showTimePicker(
                                context: context,
                                initialTime: now,
                                builder: (ctx, child) => Theme(
                                  data: Theme.of(ctx).copyWith(
                                    colorScheme: const ColorScheme.dark(
                                      primary: Color(0xFF4FC3F7),
                                      surface: Color(0xFF1E2124),
                                    ),
                                    timePickerTheme: const TimePickerThemeData(
                                      backgroundColor: Color(0xFF1E2124),
                                    ),
                                  ),
                                  child: child!,
                                ),
                              );
                              if (picked != null) {
                                final base = task.dueDay != null
                                    ? (DateTime.tryParse(task.dueDay!) ??
                                          DateTime.now())
                                    : DateTime.now();
                                final withTime = DateTime(
                                  base.year,
                                  base.month,
                                  base.day,
                                  picked.hour,
                                  picked.minute,
                                );
                                _save(() {
                                  task.dueDay = withTime
                                      .toIso8601String()
                                      .split('T')
                                      .first;
                                  task.plannedAt =
                                      withTime.millisecondsSinceEpoch;
                                });
                              }
                            },
                            child: Container(
                              padding: const EdgeInsets.symmetric(
                                horizontal: 10,
                                vertical: 10,
                              ),
                              decoration: BoxDecoration(
                                color: const Color(0xFF252729),
                                borderRadius: BorderRadius.circular(6),
                                border: Border.all(color: Colors.white10),
                              ),
                              child: Row(
                                children: [
                                  Icon(
                                    Icons.access_time_outlined,
                                    size: 13,
                                    color: _dueTimeLabel(task) != null
                                        ? const Color(0xFF4FC3F7)
                                        : Colors.white24,
                                  ),
                                  const SizedBox(width: 8),
                                  Expanded(
                                    child: Text(
                                      _dueTimeLabel(task) ?? 'No time set',
                                      style: TextStyle(
                                        fontSize: 12,
                                        color: _dueTimeLabel(task) != null
                                            ? Colors.white70
                                            : Colors.white24,
                                      ),
                                    ),
                                  ),
                                  if (_dueTimeLabel(task) != null)
                                    GestureDetector(
                                      onTap: () {
                                        if (task.dueDay != null) {
                                          _save(() {
                                            task.dueDay = task.dueDay!
                                                .split('T')
                                                .first;
                                            task.plannedAt = null;
                                          });
                                        }
                                      },
                                      child: const Icon(
                                        Icons.close,
                                        size: 13,
                                        color: Colors.white24,
                                      ),
                                    ),
                                ],
                              ),
                            ),
                          ),
                          bottomSpacing: 12,
                        ),

                        // DURATION — has propagate checkbox
                        _fieldRow(
                          'duration',
                          'DURATION',
                          TextField(
                            controller: _estimateCtrl,
                            style: const TextStyle(
                              color: Colors.white70,
                              fontSize: 12,
                            ),
                            decoration: _inputDecoration('e.g. 45m'),
                            onSubmitted: (v) {
                              final ms = _parseTimeInput(v);
                              if (ms != null) {
                                final mins = (ms ~/ 60000).clamp(1, 24 * 60);
                                _save(() => task.durationMinutes = mins);
                                _estimateCtrl.text = _msToLabel(mins * 60000);
                              } else {
                                _estimateCtrl.text = _msToLabel(
                                  task.durationMinutes * 60000,
                                );
                              }
                            },
                          ),
                          bottomSpacing: 0,
                        ),
                      ],
                    ),
                  ),
                ],
                const SizedBox(height: 18),

                // Execution
                _collapsibleLabel(
                  'EXECUTION',
                  _timeExpanded,
                  () => setState(() => _timeExpanded = !_timeExpanded),
                ),
                if (_timeExpanded) ...[
                  const SizedBox(height: 8),
                  _ExecutionTimelines(
                    task: task,
                    stagingBlocks: widget.stagingBlocks,
                    isActiveStagingTask: widget.activeStagingTaskId == task.id,
                    stagingPhaseIndex: widget.stagingPhaseIndex,
                    stagingPhaseStarted: widget.stagingPhaseStarted,
                    sessions: widget.executionSessions,
                    isActiveGeneralTask: widget.activeGeneralTaskId == task.id,
                    generalTimerStartedAt: widget.generalTimerStartedAt,
                    onStartGeneral: widget.onStartGeneral != null
                        ? () => widget.onStartGeneral!(task.id)
                        : null,
                    onCancelGeneral: widget.onCancelGeneral,
                    onFocusOverlayGeneral: widget.onFocusOverlayGeneral,
                    onStartStaging: widget.onStartStaging,
                    onStartFlowtime: widget.onStartFlowtime,
                  ),
                ],
                const SizedBox(height: 18),

                // Notes — header row with "open notes page" button
                _fieldRow(
                  'notes',
                  null, // We supply our own header row below
                  Column(
                    crossAxisAlignment: CrossAxisAlignment.stretch,
                    children: [
                      // Header row: label + navigate-to-notes button
                      Row(
                        crossAxisAlignment: CrossAxisAlignment.center,
                        children: [
                          if (_repeatExpanded) ...[
                            _buildPropagateCheckbox('notes'),
                            const SizedBox(width: 6),
                          ],
                          _sectionLabel('NOTES'),
                          const Spacer(),
                          // Open-notes-page button (matches magnifying-glass style)
                          _NotesPageButton(
                            onTap: widget.onOpenTaskNote != null
                                ? () =>
                                      widget.onOpenTaskNote!('task:${task.id}')
                                : null,
                          ),
                        ],
                      ),
                      const SizedBox(height: 6),
                      TextField(
                        controller: _notesCtrl,
                        maxLines: 5,
                        onChanged: (v) =>
                            _save(() => task.notes = v.isEmpty ? null : v),
                        style: const TextStyle(
                          color: Colors.white70,
                          fontSize: 12,
                        ),
                        decoration: _inputDecoration('Add notes…'),
                      ),
                    ],
                  ),
                ),

                // Project — Feature 10
                _buildFilterableSection(
                  key: 'project',
                  labelText: 'PROJECT',
                  filterOpen: _projectFilterOpen,
                  filterCtrl: _projectFilterCtrl,
                  onToggleFilter: () => setState(() {
                    _projectFilterOpen = !_projectFilterOpen;
                    if (!_projectFilterOpen) {
                      _projectFilterQuery = '';
                      _projectFilterCtrl.clear();
                    }
                  }),
                  onFilterChanged: (v) =>
                      setState(() => _projectFilterQuery = v.toLowerCase()),
                  child: _buildProjectSelector(task, _projectFilterQuery),
                ),

                // Tags
                _buildFilterableSection(
                  key: 'tags',
                  labelText: 'TAGS',
                  filterOpen: _tagsFilterOpen,
                  filterCtrl: _tagsFilterCtrl,
                  onToggleFilter: () => setState(() {
                    _tagsFilterOpen = !_tagsFilterOpen;
                    if (!_tagsFilterOpen) {
                      _tagsFilterQuery = '';
                      _tagsFilterCtrl.clear();
                    }
                  }),
                  onFilterChanged: (v) =>
                      setState(() => _tagsFilterQuery = v.toLowerCase()),
                  child: _buildTagEditor(task, _tagsFilterQuery),
                ),

                // Sub-tasks
                _fieldRow(
                  'subtasks',
                  null,
                  _buildSubtaskEditor(task),
                  bottomSpacing: 24,
                ),

                // ID (debug / copy)
                SelectableText(
                  'ID: ${task.id}',
                  style: TextStyle(
                    color: Colors.white.withOpacity(0.15),
                    fontSize: 9,
                    fontFamily: 'monospace',
                  ),
                ),
              ],
            ),
          ),
        ],
      ),
    );
  }

  Widget _buildSubtaskEditor(Task task) {
    final subtasks = widget.allTasks
        .where((t) => task.subTaskIds.any((id) => id.toString() == t.id))
        .toList();
    final count = subtasks.length;
    final doneCount = subtasks
        .where((t) => t.status == TaskStatus.done || t.isDone)
        .length;

    const accent = Color(0xFF66BB6A); // green — distinct from repeat blue
    const cardBg = Color(0xFF1A1D1F);
    const border = Color(0xFF252A2E);

    return Column(
      crossAxisAlignment: CrossAxisAlignment.stretch,
      children: [
        // ── Header row ──────────────────────────────────────────────────
        GestureDetector(
          onTap: () => setState(() => _subTasksExpanded = !_subTasksExpanded),
          child: Row(
            children: [
              const Icon(Icons.checklist_rounded, size: 11, color: accent),
              const SizedBox(width: 5),
              Text(
                'SUB TASKS',
                style: const TextStyle(
                  fontSize: 10,
                  fontWeight: FontWeight.w600,
                  color: accent,
                  letterSpacing: 0.8,
                ),
              ),
              if (count > 0) ...[
                const SizedBox(width: 6),
                Container(
                  padding: const EdgeInsets.symmetric(
                    horizontal: 6,
                    vertical: 1,
                  ),
                  decoration: BoxDecoration(
                    color: accent.withOpacity(0.12),
                    borderRadius: BorderRadius.circular(8),
                  ),
                  child: Text(
                    '$doneCount/$count',
                    style: const TextStyle(
                      fontSize: 9,
                      fontWeight: FontWeight.w700,
                      color: accent,
                    ),
                  ),
                ),
              ],
              const Spacer(),
              Icon(
                _subTasksExpanded
                    ? Icons.keyboard_arrow_up
                    : Icons.keyboard_arrow_down,
                size: 14,
                color: Colors.white24,
              ),
            ],
          ),
        ),

        if (_subTasksExpanded) ...[
          const SizedBox(height: 6),

          // ── Contained card ──────────────────────────────────────────────
          Container(
            decoration: BoxDecoration(
              color: cardBg,
              borderRadius: BorderRadius.circular(8),
              border: Border.all(color: border),
              // Left accent bar distinguishes from repeat groups (which use
              // a blue top/full border, no left-only bar)
            ),
            child: Column(
              crossAxisAlignment: CrossAxisAlignment.stretch,
              children: [
                // Left-accent wrapper
                IntrinsicHeight(
                  child: Row(
                    crossAxisAlignment: CrossAxisAlignment.stretch,
                    children: [
                      Container(
                        width: 3,
                        decoration: BoxDecoration(
                          color: accent.withOpacity(0.5),
                          borderRadius: const BorderRadius.only(
                            topLeft: Radius.circular(8),
                            bottomLeft: Radius.circular(8),
                          ),
                        ),
                      ),
                      Expanded(
                        child: Column(
                          crossAxisAlignment: CrossAxisAlignment.stretch,
                          children: [
                            // ── Subtask rows (no empty state; double-click to rename) ──
                            ...subtasks.asMap().entries.map((entry) {
                              final i = entry.key;
                              final sub = entry.value;
                              final isDone =
                                  sub.status == TaskStatus.done || sub.isDone;
                              final isLast = i == subtasks.length - 1;
                              bool editing = false;
                              final editCtrl = TextEditingController(
                                text: sub.title,
                              );
                              return StatefulBuilder(
                                builder: (_, setRow) {
                                  return Container(
                                    decoration: BoxDecoration(
                                      border: isLast
                                          ? null
                                          : Border(
                                              bottom: BorderSide(
                                                color: Colors.white.withOpacity(
                                                  0.05,
                                                ),
                                              ),
                                            ),
                                    ),
                                    padding: EdgeInsets.symmetric(
                                      horizontal: 10,
                                      vertical: editing ? 10 : 7,
                                    ),
                                    child: Row(
                                      children: [
                                        // Checkbox
                                        GestureDetector(
                                          onTap: () => _save(() {
                                            if (isDone) {
                                              sub.status = TaskStatus.none;
                                              sub.isDone = false;
                                            } else {
                                              sub.status = TaskStatus.done;
                                              sub.isDone = true;
                                            }
                                            unawaited(widget.onSave(sub));
                                          }),
                                          child: Icon(
                                            isDone
                                                ? Icons.check_circle_rounded
                                                : Icons.radio_button_unchecked,
                                            size: 15,
                                            color: isDone
                                                ? accent
                                                : Colors.white24,
                                          ),
                                        ),
                                        const SizedBox(width: 8),
                                        // Title — double-click to edit inline
                                        Expanded(
                                          child: editing
                                              ? TextField(
                                                  controller: editCtrl,
                                                  autofocus: true,
                                                  maxLines: 1,
                                                  strutStyle: const StrutStyle(
                                                    forceStrutHeight: true,
                                                    height: 1.0,
                                                    leading: 0,
                                                  ),
                                                  style: const TextStyle(
                                                    fontSize: 12,
                                                    color: Colors.white70,
                                                  ),
                                                  decoration:
                                                      const InputDecoration(
                                                        border:
                                                            InputBorder.none,
                                                        isDense: true,
                                                        contentPadding:
                                                            EdgeInsets.symmetric(
                                                              vertical: 0,
                                                            ),
                                                      ),
                                                  onSubmitted: (val) {
                                                    final t = val.trim();
                                                    if (t.isNotEmpty) {
                                                      _save(
                                                        () => sub.title = t,
                                                      );
                                                      unawaited(
                                                        widget.onSave(sub),
                                                      );
                                                    }
                                                    setRow(
                                                      () => editing = false,
                                                    );
                                                  },
                                                  onTapOutside: (_) {
                                                    final t = editCtrl.text
                                                        .trim();
                                                    if (t.isNotEmpty) {
                                                      _save(
                                                        () => sub.title = t,
                                                      );
                                                      unawaited(
                                                        widget.onSave(sub),
                                                      );
                                                    }
                                                    setRow(
                                                      () => editing = false,
                                                    );
                                                  },
                                                )
                                              : GestureDetector(
                                                  onDoubleTap: () => setRow(
                                                    () => editing = true,
                                                  ),
                                                  child: Text(
                                                    sub.title,
                                                    overflow:
                                                        TextOverflow.ellipsis,
                                                    maxLines: 1,
                                                    style: TextStyle(
                                                      fontSize: 12,
                                                      color: isDone
                                                          ? Colors.white24
                                                          : Colors.white70,
                                                      decoration: isDone
                                                          ? TextDecoration
                                                                .lineThrough
                                                          : null,
                                                      decorationColor:
                                                          Colors.white24,
                                                    ),
                                                  ),
                                                ),
                                        ),
                                        // Remove
                                        GestureDetector(
                                          onTap: () => _save(() {
                                            task.subTaskIds.remove(sub.id);
                                          }),
                                          child: Icon(
                                            Icons.close_rounded,
                                            size: 12,
                                            color: Colors.white.withOpacity(
                                              0.18,
                                            ),
                                          ),
                                        ),
                                      ],
                                    ),
                                  );
                                },
                              );
                            }),

                            // ── Divider before add row ──────────────────
                            if (subtasks.isNotEmpty)
                              Container(
                                height: 0.5,
                                color: Colors.white.withOpacity(0.06),
                              ),

                            // ── Add subtask row / input ──────────────────
                            if (!_subTaskAddOpen)
                              GestureDetector(
                                onTap: () => setState(() {
                                  _subTaskAddOpen = true;
                                  _subTaskAddCtrl.clear();
                                }),
                                child: Padding(
                                  padding: const EdgeInsets.symmetric(
                                    horizontal: 10,
                                    vertical: 8,
                                  ),
                                  child: Row(
                                    children: [
                                      Icon(
                                        Icons.add_rounded,
                                        size: 13,
                                        color: accent.withOpacity(0.5),
                                      ),
                                      const SizedBox(width: 6),
                                      Text(
                                        'Add sub task',
                                        style: TextStyle(
                                          fontSize: 11,
                                          color: accent.withOpacity(0.5),
                                        ),
                                      ),
                                    ],
                                  ),
                                ),
                              )
                            else
                              Padding(
                                padding: const EdgeInsets.fromLTRB(
                                  10,
                                  6,
                                  10,
                                  6,
                                ),
                                child: Row(
                                  children: [
                                    Expanded(
                                      child: TextField(
                                        controller: _subTaskAddCtrl,
                                        autofocus: true,
                                        maxLines: 1,
                                        textInputAction: TextInputAction.done,
                                        style: const TextStyle(
                                          fontSize: 12,
                                          color: Colors.white70,
                                        ),
                                        decoration: InputDecoration(
                                          hintText: 'Sub task title…',
                                          hintStyle: TextStyle(
                                            fontSize: 12,
                                            color: Colors.white.withOpacity(
                                              0.22,
                                            ),
                                          ),
                                          isDense: true,
                                          contentPadding:
                                              const EdgeInsets.symmetric(
                                                horizontal: 0,
                                                vertical: 4,
                                              ),
                                          border: InputBorder.none,
                                        ),
                                        onSubmitted: (val) =>
                                            _commitSubTask(task, val),
                                      ),
                                    ),
                                    const SizedBox(width: 6),
                                    GestureDetector(
                                      onTap: () => _commitSubTask(
                                        task,
                                        _subTaskAddCtrl.text,
                                      ),
                                      child: Container(
                                        width: 24,
                                        height: 24,
                                        decoration: BoxDecoration(
                                          color: accent.withOpacity(0.15),
                                          borderRadius: BorderRadius.circular(
                                            5,
                                          ),
                                        ),
                                        child: Icon(
                                          Icons.check_rounded,
                                          size: 13,
                                          color: accent,
                                        ),
                                      ),
                                    ),
                                    const SizedBox(width: 4),
                                    GestureDetector(
                                      onTap: () => setState(
                                        () => _subTaskAddOpen = false,
                                      ),
                                      child: Container(
                                        width: 24,
                                        height: 24,
                                        decoration: BoxDecoration(
                                          color: Colors.white.withOpacity(0.04),
                                          borderRadius: BorderRadius.circular(
                                            5,
                                          ),
                                        ),
                                        child: const Icon(
                                          Icons.close_rounded,
                                          size: 13,
                                          color: Colors.white38,
                                        ),
                                      ),
                                    ),
                                  ],
                                ),
                              ),
                          ],
                        ),
                      ),
                    ],
                  ),
                ),
              ],
            ),
          ),
        ],
      ],
    );
  }

  void _commitSubTask(Task task, String val) {
    FocusManager.instance.primaryFocus?.unfocus();
    final title = val.trim();
    if (title.isNotEmpty) {
      final sub = Task(
        id: DateTime.now().millisecondsSinceEpoch.toString(),
        title: title,
        isDone: false,
        status: TaskStatus.none,
        projectId: task.projectId,
        subTaskIds: [],
        timeSpent: 0,
        attachments: [],
        tagIds: [],
      );
      _save(() => task.subTaskIds.add(sub.id));
      widget.onSubTaskCreated(sub);
    }
    setState(() => _subTaskAddOpen = false);
  }

  /// Feature 10 — Project selector shown in the details panel above tags.
  /// Displays every project as a tappable chip; the active one is highlighted.
  /// Inbox is always listed first, using the sentinel 'INBOX_PROJECT' id.
  // ── Filterable section wrapper (PROJECT / TAGS) ──────────────────────────
  // Renders a section label row with a magnifying-glass toggle on the right.
  // When filterOpen is true an inline search field appears below the header.
  Widget _buildFilterableSection({
    required String key,
    required String labelText,
    required bool filterOpen,
    required TextEditingController filterCtrl,
    required VoidCallback onToggleFilter,
    required void Function(String) onFilterChanged,
    required Widget child,
  }) {
    const accent = Color(0xFF4FC3F7);
    final hasQuery = filterCtrl.text.isNotEmpty;
    final active = filterOpen || hasQuery;

    return Column(
      crossAxisAlignment: CrossAxisAlignment.stretch,
      children: [
        // ── Header row ───────────────────────────────────────────────────
        Row(
          crossAxisAlignment: CrossAxisAlignment.center,
          children: [
            if (_repeatExpanded) ...[
              _buildPropagateCheckbox(key),
              const SizedBox(width: 6),
            ],
            _sectionLabel(labelText),
            const Spacer(),
            // Magnifying-glass button
            GestureDetector(
              onTap: onToggleFilter,
              child: AnimatedContainer(
                duration: const Duration(milliseconds: 120),
                width: 20,
                height: 20,
                decoration: BoxDecoration(
                  color: active ? accent.withOpacity(0.12) : Colors.transparent,
                  borderRadius: BorderRadius.circular(4),
                ),
                child: Icon(
                  Icons.search_rounded,
                  size: 13,
                  color: active ? accent : Colors.white24,
                ),
              ),
            ),
          ],
        ),
        // ── Inline filter field ──────────────────────────────────────────
        if (filterOpen) ...[
          const SizedBox(height: 4),
          TextField(
            controller: filterCtrl,
            autofocus: true,
            onChanged: onFilterChanged,
            style: const TextStyle(fontSize: 11, color: Colors.white70),
            decoration: InputDecoration(
              hintText: 'Filter…',
              hintStyle: const TextStyle(fontSize: 11, color: Colors.white24),
              isDense: true,
              contentPadding: const EdgeInsets.symmetric(
                horizontal: 8,
                vertical: 5,
              ),
              filled: true,
              fillColor: const Color(0xFF1E2022),
              border: OutlineInputBorder(
                borderRadius: BorderRadius.circular(5),
                borderSide: const BorderSide(color: Colors.white12),
              ),
              enabledBorder: OutlineInputBorder(
                borderRadius: BorderRadius.circular(5),
                borderSide: const BorderSide(color: Colors.white12),
              ),
              focusedBorder: OutlineInputBorder(
                borderRadius: BorderRadius.circular(5),
                borderSide: BorderSide(color: accent.withOpacity(0.5)),
              ),
              prefixIcon: const Padding(
                padding: EdgeInsets.only(left: 7, right: 4),
                child: Icon(
                  Icons.search_rounded,
                  size: 11,
                  color: Colors.white38,
                ),
              ),
              prefixIconConstraints: const BoxConstraints(
                minWidth: 0,
                minHeight: 0,
              ),
              suffixIcon: hasQuery
                  ? GestureDetector(
                      onTap: () {
                        filterCtrl.clear();
                        onFilterChanged('');
                      },
                      child: const Icon(
                        Icons.close,
                        size: 12,
                        color: Colors.white38,
                      ),
                    )
                  : null,
            ),
          ),
        ],
        const SizedBox(height: 6),
        child,
        const SizedBox(height: 18),
      ],
    );
  }

  Widget _buildProjectSelector(Task task, [String filterQuery = '']) {
    final isLight = AppTheme.of(context).isLight;
    final accent = const Color(0xFF4FC3F7);

    // Build the ordered list: Inbox first, then the rest alphabetically.
    final entries = <MapEntry<String, String>>[
      const MapEntry('INBOX_PROJECT', 'Inbox'),
      ...widget.projects.entries
          .where((e) => e.key != 'INBOX_PROJECT')
          .map((e) => MapEntry(e.key, e.value.title))
          .toList()
        ..sort((a, b) => a.value.compareTo(b.value)),
    ];

    // Apply filter
    final filtered = filterQuery.isEmpty
        ? entries
        : entries
              .where((e) => e.value.toLowerCase().contains(filterQuery))
              .toList();

    if (filtered.isEmpty) {
      return Padding(
        padding: const EdgeInsets.symmetric(vertical: 4),
        child: Text(
          'No projects match',
          style: const TextStyle(fontSize: 11, color: Colors.white24),
        ),
      );
    }

    return ConstrainedBox(
      constraints: const BoxConstraints(maxHeight: 200),
      child: SingleChildScrollView(
        child: Wrap(
          spacing: 6,
          runSpacing: 6,
          children: filtered.map((entry) {
            final id = entry.key;
            final name = entry.value;
            final active = task.projectId == id;
            final chipColor = id == 'INBOX_PROJECT'
                ? Colors.white38
                : (widget.projectColors[id] ?? accent);

            return GestureDetector(
              onTap: () => _save(() => task.projectId = id),
              // ConstrainedBox caps chip width so long names wrap inside
              child: ConstrainedBox(
                constraints: const BoxConstraints(maxWidth: 190),
                child: AnimatedContainer(
                  duration: const Duration(milliseconds: 120),
                  padding: const EdgeInsets.symmetric(
                    horizontal: 9,
                    vertical: 5,
                  ),
                  decoration: BoxDecoration(
                    color: active
                        ? chipColor.withOpacity(isLight ? 0.15 : 0.18)
                        : (isLight
                              ? const Color(0xFFF0F1F4)
                              : Colors.white.withOpacity(0.05)),
                    borderRadius: BorderRadius.circular(6),
                    border: Border.all(
                      color: active
                          ? chipColor.withOpacity(0.7)
                          : (isLight
                                ? const Color(0xFFD0D4DA)
                                : Colors.white.withOpacity(0.12)),
                      width: active ? 1.5 : 1,
                    ),
                  ),
                  child: Row(
                    mainAxisSize: MainAxisSize.min,
                    children: [
                      Container(
                        width: 7,
                        height: 7,
                        decoration: BoxDecoration(
                          color: chipColor,
                          shape: BoxShape.circle,
                          border: adaptiveBorder(chipColor, isLight) != null
                              ? Border.all(
                                  color: isLight ? Colors.black : Colors.white,
                                  width: 1,
                                )
                              : null,
                        ),
                      ),
                      const SizedBox(width: 5),
                      // Flexible lets text wrap inside the capped chip width
                      Flexible(
                        child: Text(
                          name,
                          softWrap: true,
                          style: TextStyle(
                            fontSize: 11,
                            fontWeight: active
                                ? FontWeight.w600
                                : FontWeight.normal,
                            color: active
                                ? (isLight
                                      ? chipColor.withOpacity(0.9)
                                      : chipColor)
                                : (isLight
                                      ? const Color(0xFF555D6B)
                                      : Colors.white60),
                          ),
                        ),
                      ),
                    ],
                  ),
                ),
              ),
            );
          }).toList(),
        ),
      ),
    );
  }

  Widget _buildTagEditor(Task task, [String filterQuery = '']) {
    final currentTags = task.tagIds.map((e) => e.toString()).toList();
    final filteredTags = filterQuery.isEmpty
        ? currentTags
        : currentTags
              .where((t) => t.toLowerCase().contains(filterQuery))
              .toList();
    final suggestions = widget.allTags
        .where((t) => !currentTags.contains(t))
        .toList();

    return Column(
      crossAxisAlignment: CrossAxisAlignment.start,
      children: [
        // ── Existing tags — in a scrollable area ──────────────────────────
        if (currentTags.isNotEmpty) ...[
          ConstrainedBox(
            constraints: const BoxConstraints(maxHeight: 160),
            child: SingleChildScrollView(
              child: filteredTags.isNotEmpty
                  ? Wrap(
                      spacing: 5,
                      runSpacing: 5,
                      children: filteredTags.map((tag) {
                        return ConstrainedBox(
                          constraints: const BoxConstraints(maxWidth: 190),
                          child: Container(
                            padding: const EdgeInsets.symmetric(
                              horizontal: 7,
                              vertical: 3,
                            ),
                            decoration: BoxDecoration(
                              color: const Color(0xFF252729),
                              borderRadius: BorderRadius.circular(4),
                              border: Border.all(color: Colors.white12),
                            ),
                            child: Row(
                              mainAxisSize: MainAxisSize.min,
                              children: [
                                // Flexible lets long tag names wrap
                                Flexible(
                                  child: Text(
                                    tag,
                                    softWrap: true,
                                    style: const TextStyle(
                                      fontSize: 11,
                                      color: Colors.white60,
                                    ),
                                  ),
                                ),
                                const SizedBox(width: 5),
                                GestureDetector(
                                  onTap: () => _save(() {
                                    task.tagIds.remove(tag);
                                  }),
                                  child: Icon(
                                    Icons.close,
                                    size: 10,
                                    color: Colors.white38,
                                  ),
                                ),
                              ],
                            ),
                          ),
                        );
                      }).toList(),
                    )
                  : Padding(
                      padding: const EdgeInsets.symmetric(vertical: 4),
                      child: Text(
                        'No tags match',
                        style: const TextStyle(
                          fontSize: 11,
                          color: Colors.white24,
                        ),
                      ),
                    ),
            ),
          ),
          const SizedBox(height: 6),
        ],

        // ── + Add Tag button / inline input ──────────────────────────────
        if (!_tagAddOpen)
          GestureDetector(
            onTap: () => setState(() {
              _tagAddOpen = true;
              _tagAddCtrl.clear();
            }),
            child: Container(
              padding: const EdgeInsets.symmetric(horizontal: 8, vertical: 5),
              decoration: BoxDecoration(
                color: Colors.white.withOpacity(0.04),
                borderRadius: BorderRadius.circular(5),
                border: Border.all(
                  color: Colors.white12,
                  style: BorderStyle.solid,
                ),
              ),
              child: Row(
                mainAxisSize: MainAxisSize.min,
                children: const [
                  Icon(
                    Icons.local_offer_outlined,
                    size: 11,
                    color: Colors.white38,
                  ),
                  SizedBox(width: 5),
                  Text(
                    '+ Add Tag',
                    style: TextStyle(fontSize: 11, color: Colors.white38),
                  ),
                ],
              ),
            ),
          )
        else
          Column(
            crossAxisAlignment: CrossAxisAlignment.start,
            children: [
              // Text input
              Row(
                children: [
                  Expanded(
                    child: TextField(
                      controller: _tagAddCtrl,
                      autofocus: true,
                      style: const TextStyle(
                        fontSize: 11,
                        color: Colors.white70,
                      ),
                      decoration: InputDecoration(
                        hintText: 'Tag name…',
                        hintStyle: const TextStyle(
                          fontSize: 11,
                          color: Colors.white24,
                        ),
                        isDense: true,
                        contentPadding: const EdgeInsets.symmetric(
                          horizontal: 8,
                          vertical: 6,
                        ),
                        filled: true,
                        fillColor: const Color(0xFF1E2022),
                        border: OutlineInputBorder(
                          borderRadius: BorderRadius.circular(5),
                          borderSide: const BorderSide(color: Colors.white12),
                        ),
                        enabledBorder: OutlineInputBorder(
                          borderRadius: BorderRadius.circular(5),
                          borderSide: const BorderSide(color: Colors.white12),
                        ),
                        focusedBorder: OutlineInputBorder(
                          borderRadius: BorderRadius.circular(5),
                          borderSide: BorderSide(
                            color: const Color(0xFF4FC3F7).withOpacity(0.5),
                          ),
                        ),
                        prefixIcon: const Padding(
                          padding: EdgeInsets.only(left: 7, right: 4),
                          child: Icon(
                            Icons.local_offer_outlined,
                            size: 11,
                            color: Colors.white38,
                          ),
                        ),
                        prefixIconConstraints: const BoxConstraints(
                          minWidth: 0,
                          minHeight: 0,
                        ),
                      ),
                      onSubmitted: (val) {
                        final tag = val.trim();
                        if (tag.isNotEmpty && !currentTags.contains(tag)) {
                          _save(() => task.tagIds.add(tag));
                        }
                        setState(() => _tagAddOpen = false);
                      },
                    ),
                  ),
                  const SizedBox(width: 6),
                  GestureDetector(
                    onTap: () {
                      final tag = _tagAddCtrl.text.trim();
                      if (tag.isNotEmpty && !currentTags.contains(tag)) {
                        _save(() => task.tagIds.add(tag));
                      }
                      setState(() => _tagAddOpen = false);
                    },
                    child: Container(
                      width: 28,
                      height: 28,
                      decoration: BoxDecoration(
                        color: const Color(0xFF4FC3F7).withOpacity(0.12),
                        borderRadius: BorderRadius.circular(5),
                        border: Border.all(
                          color: const Color(0xFF4FC3F7).withOpacity(0.3),
                        ),
                      ),
                      child: const Icon(
                        Icons.check,
                        size: 13,
                        color: Color(0xFF4FC3F7),
                      ),
                    ),
                  ),
                  const SizedBox(width: 4),
                  GestureDetector(
                    onTap: () => setState(() => _tagAddOpen = false),
                    child: Container(
                      width: 28,
                      height: 28,
                      decoration: BoxDecoration(
                        color: Colors.white.withOpacity(0.04),
                        borderRadius: BorderRadius.circular(5),
                        border: Border.all(color: Colors.white10),
                      ),
                      child: const Icon(
                        Icons.close,
                        size: 13,
                        color: Colors.white38,
                      ),
                    ),
                  ),
                ],
              ),

              // Suggestions from other tasks
              if (suggestions.isNotEmpty) ...[
                const SizedBox(height: 6),
                Wrap(
                  spacing: 4,
                  runSpacing: 4,
                  children: suggestions.take(8).map((tag) {
                    return GestureDetector(
                      onTap: () {
                        if (!currentTags.contains(tag)) {
                          _save(() => task.tagIds.add(tag));
                        }
                        setState(() => _tagAddOpen = false);
                      },
                      child: Container(
                        padding: const EdgeInsets.symmetric(
                          horizontal: 7,
                          vertical: 3,
                        ),
                        decoration: BoxDecoration(
                          color: const Color(0xFF1E2022),
                          borderRadius: BorderRadius.circular(4),
                          border: Border.all(
                            color: const Color(0xFF4FC3F7).withOpacity(0.2),
                          ),
                        ),
                        child: Row(
                          mainAxisSize: MainAxisSize.min,
                          children: [
                            Icon(
                              Icons.add,
                              size: 9,
                              color: const Color(0xFF4FC3F7).withOpacity(0.7),
                            ),
                            const SizedBox(width: 3),
                            Text(
                              tag,
                              style: TextStyle(
                                fontSize: 10,
                                color: const Color(0xFF4FC3F7).withOpacity(0.8),
                              ),
                            ),
                          ],
                        ),
                      ),
                    );
                  }).toList(),
                ),
              ],
            ],
          ),
      ],
    );
  }

