  /// Returns formatted time string from plannedAt (or dueDay time component),
  /// null if no time is scheduled.
  String? _dueTimeLabel(Task task) {
    final dt = task.scheduledDateTime;
    if (dt == null) return null;
    final h = dt.hour.toString().padLeft(2, '0');
    final m = dt.minute.toString().padLeft(2, '0');
    return '$h:$m';
  }

  Widget _emptyLabel(String text) =>
      Text(text, style: const TextStyle(fontSize: 12, color: Colors.white24));

  Widget _infoRow(IconData icon, String value) => Row(
    children: [
      Icon(icon, size: 13, color: Colors.white24),
      const SizedBox(width: 8),
      Text(value, style: const TextStyle(fontSize: 12, color: Colors.white54)),
    ],
  );

