    onTap: onTap,
    child: Container(
      width: 30,
      height: 36,
      decoration: BoxDecoration(
        color: const Color(0xFF252729),
        borderRadius: BorderRadius.circular(6),
        border: Border.all(color: Colors.white10),
      ),
      child: Icon(icon, size: 14, color: Colors.white38),
