    ),
    enabledBorder: OutlineInputBorder(
      borderRadius: BorderRadius.circular(6),
      borderSide: const BorderSide(color: Colors.white10),
    ),
    focusedBorder: OutlineInputBorder(
      borderRadius: BorderRadius.circular(6),
      borderSide: const BorderSide(color: Color(0xFF4FC3F7), width: 0.8),
    ),
  );
}

// ─────────────────────────────────────────────────────────────────────────────
// _InlineAddTaskCard
//
// Inline version of the + button overlay. Idle: shows "Add task…" placeholder.
// Active: renders the same card (text field + pill row + sub-panels) as
// _AddTaskOverlay, but as a normal widget inside the task list scroll view.
// ─────────────────────────────────────────────────────────────────────────────

class _InlineAddTaskCard extends StatefulWidget {
  final bool active;
  final TextEditingController controller;
  final Map<String, Project> projects;
  final List<String> projectOrder;
  final String? selectedProjectId;
  final String? selectedDueDay;
  final List<String> selectedTags;
  final List<String> allTags;
  final VoidCallback onActivate;
  final void Function(String? id) onProjectChanged;
  final void Function(String? day) onDueDayChanged;
  final void Function(String tag) onTagToggled;
  final VoidCallback onCommit;
  final VoidCallback onDismiss;

  const _InlineAddTaskCard({
    Key? key,
    required this.active,
    required this.controller,
    required this.projects,
    required this.projectOrder,
    required this.selectedProjectId,
    required this.selectedDueDay,
    required this.selectedTags,
    required this.allTags,
    required this.onActivate,
    required this.onProjectChanged,
    required this.onDueDayChanged,
    required this.onTagToggled,
    required this.onCommit,
    required this.onDismiss,
  }) : super(key: key);

  @override
  State<_InlineAddTaskCard> createState() => _InlineAddTaskCardState();
}

class _InlineAddTaskCardState extends State<_InlineAddTaskCard> {
  String? _openPanel;
  final FocusNode _focusNode = FocusNode();
  final _duePillKey = GlobalKey();

  // ── % project autocomplete ─────────────────────────────────────────────
  List<MapEntry<String, Project>> _projectSuggestions = [];
  int _projectSuggestIndex = 0;
  int? _projectTokenStart; // char index of the '%' in the text field

  @override
  void initState() {
    super.initState();
    widget.controller.addListener(_onTextChanged);
    _focusNode.onKeyEvent = _handleKeyEvent;
  }

  @override
  void didUpdateWidget(_InlineAddTaskCard old) {
    super.didUpdateWidget(old);
    if (widget.active && !old.active) {
      WidgetsBinding.instance.addPostFrameCallback(
        (_) => _focusNode.requestFocus(),
      );
    }
  }

  @override
  void dispose() {
    widget.controller.removeListener(_onTextChanged);
    _focusNode.dispose();
    super.dispose();
  }

  // ── % autocomplete logic ───────────────────────────────────────────────

  void _onTextChanged() {
    final text = widget.controller.text;
    final cursor = widget.controller.selection.baseOffset;
    if (cursor <= 0) {
      _clearSuggestions();
      return;
    }

    // Find a % token immediately before the cursor (no spaces after %)
    final sub = text.substring(0, cursor);
    final match = RegExp(r'%(\w*)$').firstMatch(sub);
    if (match == null) {
      _clearSuggestions();
      return;
    }

    final query = match.group(1)!.toLowerCase();
    final tokenStart = match.start;

    final matches = widget.projects.entries
        .where((e) => e.value.title.toLowerCase().startsWith(query))
        .toList();

    if (matches.isEmpty) {
      _clearSuggestions();
      return;
    }

    setState(() {
      _projectSuggestions = matches;
      _projectSuggestIndex = 0;
      _projectTokenStart = tokenStart;
    });
  }

  void _clearSuggestions() {
    if (_projectSuggestions.isNotEmpty || _projectTokenStart != null) {
      setState(() {
        _projectSuggestions = [];
        _projectTokenStart = null;
      });
    }
  }

  KeyEventResult _handleKeyEvent(FocusNode node, KeyEvent event) {
    if (_projectSuggestions.isEmpty) return KeyEventResult.ignored;
    if (event is! KeyDownEvent) return KeyEventResult.ignored;

    final key = event.logicalKey;
    if (key == LogicalKeyboardKey.arrowDown) {
      setState(
        () => _projectSuggestIndex =
            (_projectSuggestIndex + 1) % _projectSuggestions.length,
      );
      return KeyEventResult.handled;
    }
    if (key == LogicalKeyboardKey.arrowUp) {
      setState(
        () => _projectSuggestIndex =
            (_projectSuggestIndex - 1 + _projectSuggestions.length) %
            _projectSuggestions.length,
      );
      return KeyEventResult.handled;
    }
    if (key == LogicalKeyboardKey.enter ||
        key == LogicalKeyboardKey.numpadEnter) {
      _selectSuggestion(_projectSuggestions[_projectSuggestIndex]);
      return KeyEventResult.handled;
    }
    if (key == LogicalKeyboardKey.escape) {
      _clearSuggestions();
      return KeyEventResult.handled;
    }
    return KeyEventResult.ignored;
  }

  /// Completes the %query token: strips it from the text field and sets the
  /// project via [onProjectChanged]. The project pill updates automatically.
  void _selectSuggestion(MapEntry<String, Project> entry) {
    final text = widget.controller.text;
    final cursor = widget.controller.selection.baseOffset;
    final tokenStart = _projectTokenStart;
    if (tokenStart == null) return;

    // Remove the %query token (from tokenStart up to cursor)
    final newText =
        text.substring(0, tokenStart) + text.substring(cursor < 0 ? 0 : cursor);
    widget.controller.value = TextEditingValue(
      text: newText,
      selection: TextSelection.collapsed(offset: tokenStart),
    );
    widget.onProjectChanged(entry.key);
    setState(() {
      _projectSuggestions = [];
      _projectTokenStart = null;
    });
  }

  // ── Due popup ─────────────────────────────────────────────────────────

  void _showDuePopup() {
    final box = _duePillKey.currentContext?.findRenderObject() as RenderBox?;
    if (box == null) return;
    final pos = box.localToGlobal(Offset.zero);
    final size = box.size;
    _showDueDatePopup(
      context: context,
      anchorRect: Rect.fromLTWH(pos.dx, pos.dy, size.width, size.height),
      selectedDueDay: widget.selectedDueDay,
      onConfirm: (day, _) {
        widget.onDueDayChanged(day);
        setState(() {});
      },
    );
  }

  // ── Build ─────────────────────────────────────────────────────────────

  @override
  Widget build(BuildContext context) {
    if (!widget.active) {
      return GestureDetector(
        onTap: widget.onActivate,
        child: Container(
          height: 36,
          decoration: BoxDecoration(
            color: const Color(0xFF1E2022),
            borderRadius: BorderRadius.circular(8),
            border: Border.all(color: Colors.white10),
          ),
          child: Row(
            children: const [
              SizedBox(width: 10),
              Icon(Icons.add, size: 15, color: Colors.white24),
              SizedBox(width: 8),
              Text(
                'Add task…',
                style: TextStyle(color: Colors.white24, fontSize: 13),
              ),
            ],
          ),
        ),
      );
    }

    return Material(
      color: Colors.transparent,
      child: Container(
        decoration: BoxDecoration(
          color: const Color(0xFF1E2022),
          borderRadius: BorderRadius.circular(10),
          border: Border.all(color: Colors.white12),
          boxShadow: [
            BoxShadow(
              color: Colors.black.withOpacity(0.35),
              blurRadius: 14,
              offset: const Offset(0, 4),
            ),
          ],
        ),
        child: Column(
          mainAxisSize: MainAxisSize.min,
          crossAxisAlignment: CrossAxisAlignment.stretch,
          children: [
            // ── Text input row ──────────────────────────────────────────
            Padding(
              padding: const EdgeInsets.fromLTRB(14, 10, 10, 6),
              child: Row(
                children: [
                  Expanded(
                    child: TextField(
                      controller: widget.controller,
                      focusNode: _focusNode,
                      maxLines: 1,
                      textInputAction: TextInputAction.done,
                      // Spec §1: block reserved filesystem chars in titles.
                      inputFormatters: [
                        FilteringTextInputFormatter.deny(RegExp(r'[/\\:]')),
                      ],
                      style: const TextStyle(color: Colors.white, fontSize: 13),
                      decoration: const InputDecoration(
                        hintText: 'A task title  #tag  @16:00  %Project',
                        hintStyle: TextStyle(
                          color: Colors.white24,
                          fontSize: 13,
                        ),
                        border: InputBorder.none,
                        isDense: true,
                        contentPadding: EdgeInsets.zero,
                      ),
                      onSubmitted: (_) {
                        if (_projectSuggestions.isNotEmpty) {
                          _selectSuggestion(
                            _projectSuggestions[_projectSuggestIndex],
                          );
                        } else {
                          widget.onCommit();
                        }
                      },
                    ),
                  ),
                  const SizedBox(width: 8),
                  _iconBtn(Icons.upload_outlined, 'Import', () {}),
                  const SizedBox(width: 4),
                  _iconBtn(Icons.search, 'Search', () {}),
                ],
              ),
            ),
            // ── % project autocomplete dropdown ─────────────────────────
            if (_projectSuggestions.isNotEmpty)
              _buildProjectSuggestionsDropdown(),
            // Thin divider
            Container(height: 0.5, color: Colors.white12),
            // ── Pill row ────────────────────────────────────────────────
            SingleChildScrollView(
              scrollDirection: Axis.horizontal,
              padding: const EdgeInsets.symmetric(horizontal: 10, vertical: 8),
              child: Row(
                children: [
                  _pill(
                    icon: Icons.inbox_outlined,
                    label: widget.selectedProjectId != null
                        ? (widget.projects[widget.selectedProjectId]?.title ??
                              'Project')
                        : 'Inbox',
                    active: _openPanel == 'project',
                    onTap: () => setState(
                      () => _openPanel = _openPanel == 'project'
                          ? null
                          : 'project',
                    ),
                  ),
                  const SizedBox(width: 6),
                  KeyedSubtree(
                    key: _duePillKey,
                    child: _pill(
                      icon: Icons.calendar_today_outlined,
                      label: widget.selectedDueDay != null
                          ? _formatDueLabel(widget.selectedDueDay!)
                          : 'Due',
                      active: widget.selectedDueDay != null,
                      onTap: _showDuePopup,
                    ),
                  ),
                  const SizedBox(width: 6),
                  _pill(
                    icon: Icons.label_outline,
                    label: widget.selectedTags.isEmpty
                        ? 'Tags'
                        : widget.selectedTags.join(', '),
                    active:
                        _openPanel == 'tags' || widget.selectedTags.isNotEmpty,
                    onTap: () => setState(
                      () => _openPanel = _openPanel == 'tags' ? null : 'tags',
                    ),
                  ),
                  const SizedBox(width: 6),
                  _pill(
                    icon: Icons.timer_outlined,
                    label: 'Estimate',
                    active: _openPanel == 'estimate',
                    onTap: () => setState(
                      () => _openPanel = _openPanel == 'estimate'
                          ? null
                          : 'estimate',
                    ),
                  ),
                ],
              ),
            ),
            // ── Secondary panels ─────────────────────────────────────────
            if (_openPanel == 'project') _buildProjectPanel(),
            if (_openPanel == 'tags') _buildTagsPanel(),
          ],
        ),
      ),
    );
  }

  // ── % autocomplete dropdown ───────────────────────────────────────────

  Widget _buildProjectSuggestionsDropdown() {
    return Container(
      constraints: const BoxConstraints(maxHeight: 180),
      margin: const EdgeInsets.fromLTRB(10, 0, 10, 4),
