      ),
      child: ListView.builder(
        padding: const EdgeInsets.symmetric(vertical: 4),
        shrinkWrap: true,
        itemCount: _projectSuggestions.length,
        itemBuilder: (context, i) {
          final entry = _projectSuggestions[i];
          final selected = i == _projectSuggestIndex;
          return GestureDetector(
            onTap: () => _selectSuggestion(entry),
            child: AnimatedContainer(
              duration: const Duration(milliseconds: 80),
              color: selected
                  ? const Color(0xFF4FC3F7).withOpacity(0.10)
                  : Colors.transparent,
              padding: const EdgeInsets.symmetric(horizontal: 12, vertical: 8),
              child: Row(
                children: [
                  Icon(
                    Icons.folder_outlined,
                    size: 13,
                    color: selected ? const Color(0xFF4FC3F7) : Colors.white38,
                  ),
                  const SizedBox(width: 10),
                  Expanded(
                    child: Text(
                      entry.value.title,
                      style: TextStyle(
                        fontSize: 12,
                        color: selected
                            ? const Color(0xFF4FC3F7)
                            : Colors.white70,
                        fontWeight: selected
                            ? FontWeight.w600
                            : FontWeight.normal,
                      ),
                    ),
                  ),
                  if (selected)
                    const Text(
                      '↵',
                      style: TextStyle(fontSize: 10, color: Color(0xFF4FC3F7)),
                    ),
                ],
              ),
            ),
          );
        },
      ),
    );
  }

  // ── Icon button ───────────────────────────────────────────────────────

  Widget _iconBtn(IconData icon, String tooltip, VoidCallback onTap) => Tooltip(
    message: tooltip,
    child: InkWell(
      onTap: onTap,
      borderRadius: BorderRadius.circular(5),
      child: Padding(
        padding: const EdgeInsets.all(5),
        child: Icon(icon, size: 15, color: Colors.white38),
      ),
    ),
  );

  // ── Pill ──────────────────────────────────────────────────────────────

  Widget _pill({
    required IconData icon,
    required String label,
    required bool active,
    required VoidCallback onTap,
  }) {
    return GestureDetector(
      onTap: onTap,
      child: AnimatedContainer(
        duration: const Duration(milliseconds: 120),
        padding: const EdgeInsets.symmetric(horizontal: 9, vertical: 5),
        decoration: BoxDecoration(
          color: active
              ? const Color(0xFF4FC3F7).withOpacity(0.12)
              : Colors.white.withOpacity(0.05),
          borderRadius: BorderRadius.circular(6),
          border: Border.all(
            color: active
                ? const Color(0xFF4FC3F7).withOpacity(0.4)
                : Colors.white12,
          ),
        ),
        child: Row(
          mainAxisSize: MainAxisSize.min,
          children: [
            Icon(
              icon,
              size: 12,
              color: active ? const Color(0xFF4FC3F7) : Colors.white38,
            ),
            const SizedBox(width: 5),
            Text(
              label,
              style: TextStyle(
                fontSize: 11,
                color: active ? const Color(0xFF4FC3F7) : Colors.white38,
                fontWeight: active ? FontWeight.w600 : FontWeight.normal,
              ),
            ),
          ],
        ),
      ),
    );
  }

  // ── Project panel ─────────────────────────────────────────────────────

  Widget _buildProjectPanel() {
    return Container(
      constraints: const BoxConstraints(maxHeight: 180),
      margin: const EdgeInsets.fromLTRB(10, 0, 10, 8),
      decoration: BoxDecoration(
        color: const Color(0xFF252829),
        borderRadius: BorderRadius.circular(7),
        border: Border.all(color: Colors.white10),
      ),
      child: ListView(
        padding: const EdgeInsets.symmetric(vertical: 4),
        shrinkWrap: true,
        children: [
          _panelItem(
            icon: Icons.inbox_outlined,
            label: 'Inbox',
            selected: widget.selectedProjectId == null,
            onTap: () {
              widget.onProjectChanged(null);
              setState(() => _openPanel = null);
            },
          ),
          ...widget.projectOrder.map((pid) {
            final proj = widget.projects[pid];
            if (proj == null) return const SizedBox.shrink();
            return _panelItem(
              icon: Icons.folder_outlined,
              label: proj.title,
              selected: widget.selectedProjectId == pid,
              onTap: () {
                widget.onProjectChanged(pid);
                setState(() => _openPanel = null);
              },
            );
          }),
        ],
      ),
    );
  }

  // ── Due panel ─────────────────────────────────────────────────────────

  Widget _buildDuePanel() {
    return Container(
      margin: const EdgeInsets.fromLTRB(10, 0, 10, 8),
      child: _DueDatePickerPanel(
        selectedDueDay: widget.selectedDueDay,
        onConfirm: (isoDay, _) {
          widget.onDueDayChanged(isoDay);
          setState(() => _openPanel = null);
        },
        onCancel: () => setState(() => _openPanel = null),
      ),
    );
  }

  // ── Tags panel ────────────────────────────────────────────────────────

  Widget _buildTagsPanel() {
    if (widget.allTags.isEmpty) {
      return const Padding(
        padding: EdgeInsets.fromLTRB(14, 6, 14, 10),
        child: Text(
          'No tags yet — type #tagname in the title',
          style: TextStyle(color: Colors.white30, fontSize: 11),
        ),
      );
    }
    return Container(
      constraints: const BoxConstraints(maxHeight: 160),
      margin: const EdgeInsets.fromLTRB(10, 0, 10, 8),
      decoration: BoxDecoration(
        color: const Color(0xFF252829),
        borderRadius: BorderRadius.circular(7),
        border: Border.all(color: Colors.white10),
      ),
      child: ListView(
        padding: const EdgeInsets.symmetric(vertical: 4),
        shrinkWrap: true,
        children: widget.allTags.map((tag) {
          final selected = widget.selectedTags.contains(tag);
          return _panelItem(
            icon: selected ? Icons.label : Icons.label_outline,
            label: '#$tag',
            selected: selected,
            onTap: () => widget.onTagToggled(tag),
          );
        }).toList(),
      ),
    );
  }

  // ── Panel item ────────────────────────────────────────────────────────

  Widget _panelItem({
    required IconData icon,
    required String label,
    required bool selected,
    required VoidCallback onTap,
  }) {
    return InkWell(
      onTap: onTap,
      child: Padding(
        padding: const EdgeInsets.symmetric(horizontal: 12, vertical: 8),
        child: Row(
          children: [
            Icon(
              icon,
              size: 14,
              color: selected ? const Color(0xFF4FC3F7) : Colors.white38,
            ),
            const SizedBox(width: 10),
            Expanded(
              child: Text(
                label,
                style: TextStyle(
                  fontSize: 12,
                  color: selected ? const Color(0xFF4FC3F7) : Colors.white70,
                  fontWeight: selected ? FontWeight.w600 : FontWeight.normal,
                ),
              ),
            ),
            if (selected)
              const Icon(Icons.check, size: 13, color: Color(0xFF4FC3F7)),
          ],
        ),
      ),
    );
  }

  // ── Due label formatter ───────────────────────────────────────────────

  String _formatDueLabel(String isoDay) {
    final d = DateTime.tryParse(isoDay);
    if (d == null) return isoDay;
    return _fmtDateChip(d);
  }
}

// ─────────────────────────────────────────────────────────────────────────────
// _SidebarResizeHandle
//
// An 8px-wide hit area that shows a subtle 1px line. On hover the line
// brightens and a resize cursor appears. Dragging left past the threshold
// hides the sidebar; double-tap toggles visibility.
// ─────────────────────────────────────────────────────────────────────────────

// ─────────────────────────────────────────────────────────────────────────────
// Nord palette constants (Notes-scoped)
// ─────────────────────────────────────────────────────────────────────────────
// Background layers
const _nordBase = Color(0xFF2E3440); // scaffold bg
const _kBase = 16.0; // Notes base font size
const _nordBase1 = Color(0xFF3B4252); // slightly lighter
const _nordBase2 = Color(0xFF434C5E); // selection / hover
const _nordSidebar = Color(0xFF242933); // sidebar / header bg
// Text / frost
const _nordFrost = Color(0xFFD8DEE9); // primary text
const _nordFrost2 = Color(0xFFECEFF4); // brightest text
const _nordSnow = Color(0xFF8896AC); // muted text
// Divider
const _nordDivider = Color(0xFF3B4252);
// Heading colours
const _nordRed = Color(0xFFBF616A);
const _nordOrange = Color(0xFFD08770);
const _nordYellow = Color(0xFFEBCB8B);
const _nordGreen = Color(0xFFA3BE8C);
const _nordPurple = Color(0xFFB48EAD);
const _nordBlue = Color(0xFF81A1C1);
const _nordCyan = Color(0xFF88C0D0);

// ─────────────────────────────────────────────────────────────────────────────
// Notes block model — Affine-inspired block-based architecture
//
// The note body is no longer a single TextField blob. Instead the markdown
// string is parsed into a typed List<NoteBlock> where every heading/paragraph/
// list item is its own block. Heading blocks carry a `collapsed` flag; when
// set, _collapsedSiblings() returns the range of blocks that belong to its
// scope and those blocks are simply not rendered — matching Affine's
// calculateCollapsedSiblings + display:none approach exactly.
// ─────────────────────────────────────────────────────────────────────────────

// ── Block type ───────────────────────────────────────────────────────────────

enum NoteBlockType {
  text,
  h1,
  h2,
  h3,
  h4,
  h5,
  h6,
  quote,
  bullet,
  numbered,
  check,
  code,
  divider,
}

// ── Block data ───────────────────────────────────────────────────────────────

class NoteBlock {
  String id;
  NoteBlockType type;
  String
  content; // raw text — heading blocks include their "# " prefix (Obsidian live-preview)
  bool collapsed; // heading only: scope is folded
  bool checked; // check item only
  int indent; // bullet / numbered / check: nesting depth (0-based)
  int lineOffset; // NEW: backing-text byte offset of this block's first line

  NoteBlock({
    required this.id,
    required this.type,
    required this.content,
    this.collapsed = false,
    this.checked = false,
    this.indent = 0,
    this.lineOffset = 0, // NEW (default keeps every existing call-site intact)
  });

  bool get isHeading =>
      type.index >= NoteBlockType.h1.index &&
      type.index <= NoteBlockType.h6.index;

  int get headingLevel =>
      isHeading ? (type.index - NoteBlockType.h1.index + 1) : 0;
}

// ── ID generator ─────────────────────────────────────────────────────────────

int _nbSeq = 0;
String _nbId() => 'nb${++_nbSeq}';

// ── Markdown → blocks ─────────────────────────────────────────────────────────

List<NoteBlock> _parseBlocks(String md) {
  if (md.isEmpty)
    return [
      NoteBlock(
        id: _nbId(),
        type: NoteBlockType.text,
        content: '',
        lineOffset: 0,
      ),
    ];
  final lines = md.split('\n');
  final blocks = <NoteBlock>[];
  int i = 0;
  int offset = 0; // NEW: cumulative backing offset

  while (i < lines.length) {
    final line = lines[i];
    final currentOffset = offset; // NEW: offset at start of this line

    // Code fence
    if (line.trimLeft().startsWith('```')) {
      final sb = StringBuffer();
      offset += line.length + 1; // NEW: advance past the opening fence line
      i++;
      while (i < lines.length && !lines[i].trimLeft().startsWith('```')) {
        if (sb.isNotEmpty) sb.write('\n');
        sb.write(lines[i]);
        offset += lines[i].length + 1; // NEW
        i++;
      }
      if (i < lines.length) {
        offset += lines[i].length + 1; // NEW: advance past closing fence
        i++;
      }
      blocks.add(
        NoteBlock(
          id: _nbId(),
          type: NoteBlockType.code,
          content: sb.toString(),
          lineOffset: currentOffset, // NEW
        ),
      );
      continue;
    }

    // Divider  ---  ***  ___
    if (RegExp(r'^[-*_]{3,}\s*$').hasMatch(line)) {
      blocks.add(
        NoteBlock(
          id: _nbId(),
          type: NoteBlockType.divider,
          content: '',
          lineOffset: currentOffset,
        ),
      );
      offset += line.length + 1; // NEW
      i++;
      continue;
    }

    // Headings
    final hm = RegExp(r'^(#{1,6}) (.*)').firstMatch(line);
    if (hm != null) {
      const ht = [
        NoteBlockType.h1,
        NoteBlockType.h2,
        NoteBlockType.h3,
        NoteBlockType.h4,
        NoteBlockType.h5,
        NoteBlockType.h6,
      ];
      blocks.add(
        NoteBlock(
          id: _nbId(),
          type: ht[hm.group(1)!.length - 1],
          content: line,
          lineOffset: currentOffset, // NEW
        ),
      );
      offset += line.length + 1; // NEW
      i++;
      continue;
    }

    // Blockquote
    if (line.startsWith('> ')) {
      blocks.add(
        NoteBlock(
          id: _nbId(),
          type: NoteBlockType.quote,
          content: line.substring(2),
          lineOffset: currentOffset, // NEW
        ),
      );
      offset += line.length + 1; // NEW
      i++;
      continue;
    }

    // Checkbox  - [ ]  /  - [x]
    final cm = RegExp(r'^(\s*)- \[([ xX])\] (.*)').firstMatch(line);
    if (cm != null) {
      blocks.add(
        NoteBlock(
          id: _nbId(),
          type: NoteBlockType.check,
          content: cm.group(3)!,
          checked: cm.group(2)!.toLowerCase() == 'x',
          indent: cm.group(1)!.length ~/ 2,
          lineOffset: currentOffset, // NEW
        ),
      );
      offset += line.length + 1; // NEW
      i++;
      continue;
    }

    // Bullet  -  *  +
    final bm = RegExp(r'^(\s*)[-*+] (.*)').firstMatch(line);
    if (bm != null) {
      blocks.add(
        NoteBlock(
          id: _nbId(),
          type: NoteBlockType.bullet,
          content: bm.group(2)!,
          indent: bm.group(1)!.length ~/ 2,
          lineOffset: currentOffset, // NEW
        ),
      );
      offset += line.length + 1; // NEW
      i++;
      continue;
    }

    // Numbered list  1.  1)
    final nm = RegExp(r'^(\s*)\d+[.)]\s+(.*)').firstMatch(line);
    if (nm != null) {
      blocks.add(
        NoteBlock(
          id: _nbId(),
          type: NoteBlockType.numbered,
          content: nm.group(2)!,
          indent: nm.group(1)!.length ~/ 2,
          lineOffset: currentOffset, // NEW
        ),
      );
      offset += line.length + 1; // NEW
      i++;
      continue;
    }

    // Plain text / blank line
    blocks.add(
      NoteBlock(
        id: _nbId(),
        type: NoteBlockType.text,
        content: line,
        lineOffset: currentOffset,
      ),
    );
    offset += line.length + 1; // NEW
    i++;
  }

  return blocks.isEmpty
      ? [
          NoteBlock(
            id: _nbId(),
            type: NoteBlockType.text,
            content: '',
            lineOffset: 0,
          ),
        ]
      : blocks;
}
// ── Blocks → markdown ─────────────────────────────────────────────────────────

String _serializeBlocks(List<NoteBlock> blocks) {
  return blocks
      .map((b) {
        final pad = '  ' * b.indent;
        switch (b.type) {
          case NoteBlockType.h1:
          case NoteBlockType.h2:
          case NoteBlockType.h3:
          case NoteBlockType.h4:
          case NoteBlockType.h5:
          case NoteBlockType.h6:
            // content already holds the full heading line, e.g. "# My Title".
            // Legacy guard: if an old in-memory block somehow lacks the prefix,
            // re-synthesise it so the file always contains valid markdown.
            {
              final lvl = b.headingLevel;
              final pfx = '${'#' * lvl} ';
              return b.content.startsWith(pfx) ? b.content : '$pfx${b.content}';
            }
          case NoteBlockType.quote:
            return '> ${b.content}';
          case NoteBlockType.bullet:
            return '${pad}- ${b.content}';
          case NoteBlockType.numbered:
            return '${pad}1. ${b.content}';
          case NoteBlockType.check:
            return '$pad- [${b.checked ? 'x' : ' '}] ${b.content}';
          case NoteBlockType.code:
            return '```\n${b.content}\n```';
          case NoteBlockType.divider:
            return '---';
          case NoteBlockType.text:
            return b.content;
        }
      })
      .join('\n');
}

// ── Heading style helpers (shared by editor and any reading widgets) ──────────

Color _nbHeadingColor(int level) {
  switch (level) {
    case 1:
      return _nordRed;
    case 2:
      return _nordOrange;
    case 3:
      return _nordYellow;
    case 4:
      return _nordGreen;
    case 5:
      return _nordPurple;
    case 6:
      return _nordOrange;
    default:
      return _nordFrost;
  }
}

double _nbHeadingSize(int level) {
  switch (level) {
    case 1:
      return _kBase * 2.25;
    case 2:
      return _kBase * 1.9;
    case 3:
      return _kBase * 1.6;
    case 4:
      return _kBase * 1.4;
    case 5:
      return _kBase * 1.25;
    case 6:
      return _kBase * 1.1;
    default:
      return _kBase;
  }
}

FontWeight _nbHeadingWeight(int level) =>
    level <= 1 ? FontWeight.w700 : FontWeight.w600;

// ── Inline markdown span builder ─────────────────────────────────────────────
//
// Renders **bold**, *italic*, `code`, [link](url) within a single line of
// text. Block-structure (heading markers, bullets, etc.) is determined at the
// NoteBlock level and never processed here.

TextSpan _buildInlineSpan(String text, TextStyle base) {
  if (text.isEmpty) return TextSpan(text: '', style: base);
  final spans = <InlineSpan>[];
  int pos = 0;
  final re = RegExp(
    r'(\*\*|__)(.*?)\1' // bold       groups 1, 2
    r'|(~~)(.*?)\3' // strikethrough groups 3, 4
    r'|(\*|_)(.*?)\5' // italic      groups 5, 6
    r'|(`)(.*?)\7' // code         groups 7, 8
    r'|\[([^\]]+)\]\(([^)]+)\)', // link  groups 9, 10
  );
  for (final m in re.allMatches(text)) {
    if (m.start > pos) {
      spans.add(TextSpan(text: text.substring(pos, m.start), style: base));
    }
    if (m.group(1) != null) {
      // Bold
      spans.add(
        TextSpan(
          text: m.group(2),
          style: base.copyWith(fontWeight: FontWeight.bold, color: _nordFrost2),
        ),
      );
    } else if (m.group(3) != null) {
      // Strikethrough
      spans.add(
        TextSpan(
          text: m.group(4),
          style: base.copyWith(
            decoration: TextDecoration.lineThrough,
            decorationColor: base.color,
          ),
        ),
      );
    } else if (m.group(5) != null) {
      // Italic
      spans.add(
        TextSpan(
          text: m.group(6),
          style: base.copyWith(fontStyle: FontStyle.italic),
        ),
      );
    } else if (m.group(7) != null) {
      // Inline code
      spans.add(
        TextSpan(
          text: m.group(8),
          style: base.copyWith(
            fontFamily: 'monospace',
            color: _nordCyan,
            background: Paint()..color = _nordBase1,
          ),
        ),
      );
    } else if (m.group(9) != null) {
      // Link
      spans.add(
        TextSpan(
          text: m.group(9),
          style: base.copyWith(
            color: _nordBlue,
            decoration: TextDecoration.underline,
          ),
        ),
      );
    }
    pos = m.end;
  }
  if (pos < text.length) {
    spans.add(TextSpan(text: text.substring(pos), style: base));
  }
  return TextSpan(
    children: spans.isEmpty ? [TextSpan(text: text, style: base)] : spans,
    style: base,
  );
}

// ─────────────────────────────────────────────────────────────────────────────
// _Fold — one collapsed heading section.
//
//   start = index of first HIDDEN char in _backingText
//           (= index of the char immediately after the heading's '\n')
//   end   = index of last hidden char (inclusive)
//   level = heading level 1–6 that owns this fold
//
// The '\n' that terminates the heading line lives at (start − 1) and is always
// VISIBLE — it is the line-break displayed between the heading and whatever
// comes after the fold in _displayText.
// ─────────────────────────────────────────────────────────────────────────────

class _Fold {
  int start;
  int end;
  int level;

  _Fold({required this.start, required this.end, required this.level});

  bool contains(int pos) => pos >= start && pos <= end;

  @override
  String toString() => '_Fold(start=$start, end=$end, level=$level)';
}

// ─────────────────────────────────────────────────────────────────────────────
// _SpLiveMarkdownController  —  single-document Obsidian-style live-preview
//
// The entire note is stored as one flat string in this controller.
// buildTextSpan processes every line on every cursor change, emitting
// cursor-aware decorations without any block list, per-block controller, or
// focus transfer:
//
//   • Cursor ON a line  → markers rendered dimmed (~40% opacity)
//   • Cursor OFF a line → markers rendered as faint ghosts (~18% opacity)
//                         and block-level structure is fully styled
//
// This mirrors the CM6 ViewPlugin decoration model from the Obsidian docs,
// within the constraints of Flutter's single-TextField model.
// ─────────────────────────────────────────────────────────────────────────────

const TextStyle _kDocBase = TextStyle(
  fontFamily: 'Inter',
  fontSize: _kBase,
  color: _nordFrost,
  height: 1.75,
);

// ─────────────────────────────────────────────────────────────────────────────
// _SpLiveMarkdownController
//
// Layer 1 — _backingText is the single source of truth.
// Layer 2 — _displayText + _fwdMap + _revMap are recomputed whenever
//   _backingText or _folds changes. Folds are physically absent from
//   _displayText; no zero-height tricks.
// Layer 3 — Overrides get/set value so the framework always sees _displayText
//   while all edits are transparently mapped to/from _backingText.
// ─────────────────────────────────────────────────────────────────────────────

class _SpLiveMarkdownController extends TextEditingController {
  // ── Layer 1 ────────────────────────────────────────────────────────────────
  String _backingText = '';
  final List<_Fold> _folds = [];

  // ── Layer 2 ────────────────────────────────────────────────────────────────
  String _displayText = '';
  Uint32List _fwdMap = Uint32List(1);
  Uint32List _revMap = Uint32List(1);

  // ── Selection (always in display space) ───────────────────────────────────
  TextSelection _sel = const TextSelection.collapsed(offset: 0);

  // ── Public accessors ───────────────────────────────────────────────────────

  String get backingText => _backingText;
  List<_Fold> get folds => List.unmodifiable(_folds);

  bool isFoldedAt(int headingLineStart) {
    final nl = _backingText.indexOf('\n', headingLineStart);
    if (nl < 0) return false;
    final bodyStart = nl + 1;
    return _folds.any((f) => f.start == bodyStart);
  }

  // ── Content reset ──────────────────────────────────────────────────────────

  void resetContent(String content) {
    _backingText = content;
    _folds.clear();
    _recomputeDisplay();
    _sel = const TextSelection.collapsed(offset: 0);
    notifyListeners();
  }

  // ── Fold toggle ────────────────────────────────────────────────────────────

  /// Returns the full heading line text for every heading that is currently
  /// folded (e.g. ["## Introduction", "### Details"]).  Used for persistence.
  List<String> getFoldedHeadings() {
    final result = <String>[];
    final back = _backingText;
    for (final fold in _folds) {
      // fold.start is the first char of the body (one char after the '\n').
      // The heading line ends at fold.start - 1, which is the '\n'.
      final headingEnd = fold.start - 1;
      if (headingEnd <= 0) continue;
      final headingStart = back.lastIndexOf('\n', headingEnd - 1);
      final lineStart = headingStart < 0 ? 0 : headingStart + 1;
      final line = back.substring(lineStart, headingEnd);
      if (line.startsWith('#')) result.add(line);
    }
    return result;
  }

  /// Scans [_backingText] for each heading in [headings] and folds it.
  /// Called once after [resetContent] to restore persisted fold state.
  void restoreFolds(List<String> headings) {
    if (headings.isEmpty) return;
    final back = _backingText;
    final lines = back.split('\n');
    int offset = 0;
    for (final line in lines) {
      if (headings.contains(line) && RegExp(r'^#{1,6} ').hasMatch(line)) {
        toggleFold(offset);
      }
      offset += line.length + 1; // +1 for the '\n'
    }
  }

  void toggleFold(int headingLineStart) {
    final back = _backingText;
    final M = back.length;

    final nl = back.indexOf('\n', headingLineStart);
    if (nl < 0) return;

    final headingLine = back.substring(headingLineStart, nl);
    final hm = RegExp(r'^(#{1,6}) ').firstMatch(headingLine);
    if (hm == null) return;
    final level = hm.group(1)!.length;

    final bodyStart = nl + 1;
    if (bodyStart >= M) return;

    int pos = bodyStart;
    int bodyEnd = M - 1;
    while (pos < M) {
      final nextNl = back.indexOf('\n', pos);
      final lineEnd = nextNl < 0 ? M : nextNl;
      final nextLine = back.substring(pos, lineEnd);
      final nhm = RegExp(r'^(#{1,6}) ').firstMatch(nextLine);
      if (nhm != null && nhm.group(1)!.length <= level) {
        bodyEnd = pos - 1;
        break;
      }
      pos = (nextNl < 0) ? M : nextNl + 1;
    }
    if (bodyEnd < bodyStart) return;

    final oldDi = _sel.baseOffset.clamp(0, _displayText.length);
    final oldBi = _fwdMap[oldDi];

    final existingIdx = _folds.indexWhere((f) => f.start == bodyStart);
    if (existingIdx >= 0) {
      _folds.removeAt(existingIdx);
    } else {
      _folds.removeWhere((f) => f.start >= bodyStart && f.end <= bodyEnd);
      _folds.add(_Fold(start: bodyStart, end: bodyEnd, level: level));
      _folds.sort((a, b) => a.start.compareTo(b.start));
    }

    _recomputeDisplay();
    final newDi = _revMap[oldBi.clamp(0, _backingText.length)];
    _sel = TextSelection.collapsed(offset: newDi);

    notifyListeners();
  }

  // ── Recompute display + maps ───────────────────────────────────────────────

  void _recomputeDisplay() {
    final back = _backingText;
    final M = back.length;

    _folds.sort((a, b) => a.start.compareTo(b.start));

    final units = Uint16List(M);
    final fwdBuf = Uint32List(M + 1);
    final revBuf = Uint32List(M + 1);

    int di = 0;
    int bi = 0;
    int fi = 0;

    while (bi < M) {
      while (fi < _folds.length && _folds[fi].end < bi) fi++;

      if (fi < _folds.length && bi == _folds[fi].start) {
        final fEnd = _folds[fi].end.clamp(0, M - 1);
        final snapDi = di > 0 ? di - 1 : 0;
        for (int k = bi; k <= fEnd; k++) revBuf[k] = snapDi;
        bi = fEnd + 1;
        fi++;
        continue;
      }

      units[di] = back.codeUnitAt(bi);
      fwdBuf[di] = bi;
      revBuf[bi] = di;
      di++;
      bi++;
    }

    fwdBuf[di] = M;
    revBuf[M] = di;

    _displayText = String.fromCharCodes(units, 0, di);
    _fwdMap = fwdBuf.sublist(0, di + 1);
    _revMap = revBuf;
  }

  // ── TextEditingController overrides ───────────────────────────────────────

  @override
  TextEditingValue get value =>
      TextEditingValue(text: _displayText, selection: _sel);

  @override
  set value(TextEditingValue newVal) {
    final newText = newVal.text;

    if (newText == _displayText) {
      // Preserve non-collapsed selections (e.g. Ctrl+A select-all).
      // Only collapse when the incoming selection is already collapsed.
      final TextSelection snapped;
      if (newVal.selection.isCollapsed) {
        snapped = TextSelection.collapsed(
          offset: newVal.selection.baseOffset.clamp(0, _displayText.length),
        );
      } else {
        snapped = TextSelection(
          baseOffset: newVal.selection.baseOffset.clamp(0, _displayText.length),
          extentOffset: newVal.selection.extentOffset.clamp(
            0,
            _displayText.length,
          ),
        );
      }
      if (snapped != _sel) {
        _sel = snapped;
        notifyListeners();
      }
      return;
    }

    final diff = _diffStrings(_displayText, newText);

    final bStart = _fwdMap[diff.pos.clamp(0, _fwdMap.length - 1)];
    final bEnd =
        _fwdMap[(diff.pos + diff.deletedLen).clamp(0, _fwdMap.length - 1)];

    _backingText = _backingText.replaceRange(bStart, bEnd, diff.inserted);

    _adjustFoldsAfterEdit(bStart, bEnd - bStart, diff.inserted.length);

    _recomputeDisplay();

    // Use the cursor position supplied by the caller (IME / our own handlers)
    // rather than recomputing from the diff position. The diff-based cursor is
    // wrong whenever the inserted character equals the adjacent character (e.g.
    // inserting '\n' before an existing '\n'): _diffStrings slides the change
    // forward by one, so newBackingCursor ends up one past the empty line and
    // lands on the next non-empty line. The incoming selection is always in new
    // display-text space, which matches _displayText after _recomputeDisplay().
    final incomingBase = newVal.selection.baseOffset.clamp(
      0,
      _displayText.length,
    );
    final incomingExtent = newVal.selection.extentOffset.clamp(
      0,
      _displayText.length,
    );
    _sel = incomingBase == incomingExtent
        ? TextSelection.collapsed(offset: incomingBase)
        : TextSelection(baseOffset: incomingBase, extentOffset: incomingExtent);

    notifyListeners();
  }

  // ── Edit helpers ───────────────────────────────────────────────────────────

  ({int pos, int deletedLen, String inserted}) _diffStrings(
    String old,
    String neo,
  ) {
    int start = 0;
    final minLen = min(old.length, neo.length);
    while (start < minLen && old[start] == neo[start]) start++;

    int oldEnd = old.length;
    int newEnd = neo.length;
    while (oldEnd > start &&
        newEnd > start &&
        old[oldEnd - 1] == neo[newEnd - 1]) {
      oldEnd--;
      newEnd--;
    }
    return (
      pos: start,
      deletedLen: oldEnd - start,
      inserted: neo.substring(start, newEnd),
    );
  }

  void _adjustFoldsAfterEdit(
    int editStart,
    int deletedCount,
    int insertedCount,
  ) {
    final editEnd = editStart + deletedCount;
    final delta = insertedCount - deletedCount;
    final toRemove = <int>[];

    for (int i = 0; i < _folds.length; i++) {
      final f = _folds[i];

      if (f.end < editStart) {
        continue;
      }

      if (f.start >= editEnd) {
        _folds[i] = _Fold(
          start: f.start + delta,
          end: f.end + delta,
          level: f.level,
        );
        continue;
      }

      if (f.start >= editStart) {
        if (editEnd > f.end) {
          toRemove.add(i);
        } else {
          _folds[i] = _Fold(
            start: editStart + insertedCount,
            end: f.end + delta,
            level: f.level,
          );
        }
      } else {
        if (editEnd > f.end) {
          _folds[i] = _Fold(start: f.start, end: editStart - 1, level: f.level);
        } else {
          _folds[i] = _Fold(start: f.start, end: f.end + delta, level: f.level);
        }
      }
    }

    for (final i in toRemove.reversed) _folds.removeAt(i);
    _folds.removeWhere((f) => f.start > f.end || f.start < 0);
    _removeOrphanedFolds();
  }

  void _removeOrphanedFolds() {
    _folds.removeWhere((f) {
      if (f.start == 0) return true;
      if (f.start - 1 >= _backingText.length) return true;
      if (_backingText[f.start - 1] != '\n') return true;
      final headingNl = f.start - 1;
      final prevNl = headingNl > 0
          ? _backingText.lastIndexOf('\n', headingNl - 1)
          : -1;
      final lineStart = prevNl + 1;
      final headingLine = _backingText.substring(lineStart, headingNl);
      return !RegExp('^#{${f.level}} ').hasMatch(headingLine);
    });
  }

  @override
  TextSpan buildTextSpan({
    required BuildContext context,
    TextStyle? style,
    required bool withComposing,
  }) {
    final cur = _sel.isValid ? _sel.baseOffset : -1;
    return _buildDocumentSpan(_displayText, cur, style ?? _kDocBase);
  }
}
// ── Document span builder ─────────────────────────────────────────────────────
//
// Single pass over every line. The cursor position (one integer, CM6-style)
// drives all decoration decisions — no block list, no widget rebuild per line.
//
// Supported line prefixes:
//   #…######   Headings
//   > text     Blockquote
//   - / * / +  Bullet
//   1. / 1)    Numbered
//   - [ ] / - [x]  Checkbox
//   ```        Code fence toggle
//   ---/***/___ Divider

TextSpan _buildDocumentSpan(String text, int cursorPos, TextStyle base) {
  if (text.isEmpty) return TextSpan(text: '', style: base);

  final children = <InlineSpan>[];
  final lines = text.split('\n');
  int offset = 0;
  bool inFence = false;
  // NOTE: No collapsedLevel / collapse state machine here.
  //       _displayText has fold bodies physically removed — nothing to skip.

  for (int li = 0; li < lines.length; li++) {
    final line = lines[li];
    final lineStart = offset;
    final lineEnd = offset + line.length;
    final onLine = cursorPos >= lineStart && cursorPos <= lineEnd;

    if (li > 0) children.add(TextSpan(text: '\n', style: base));

    // ── Code fence toggle ──────────────────────────────────────────────────
    if (line.trimLeft().startsWith('```')) {
      inFence = !inFence;
      children.add(
        TextSpan(
          text: line,
          style: base.copyWith(
            fontFamily: 'monospace',
            fontSize: _kBase * 0.88,
            color: _nordDivider,
          ),
        ),
      );
      offset = lineEnd + 1;
      continue;
    }

    // ── Inside code fence ─────────────────────────────────────────────────
    if (inFence) {
      children.add(
        TextSpan(
          text: line,
          style: base.copyWith(
            fontFamily: 'monospace',
            fontSize: _kBase * 0.88,
            color: _nordCyan,
          ),
        ),
      );
      offset = lineEnd + 1;
      continue;
    }

    // ── Divider: ---  ***  ___ ────────────────────────────────────────────
    if (RegExp(r'^[-*_]{3,}\s*$').hasMatch(line)) {
      children.add(
        TextSpan(
          text: line,
          style: base.copyWith(
            color: _nordDivider,
            fontWeight: FontWeight.w300,
          ),
        ),
      );
      offset = lineEnd + 1;
      continue;
    }

    // ── Heading: #…###### text ────────────────────────────────────────────
    final hm = RegExp(r'^(#{1,6}) (.*)$').firstMatch(line);
    if (hm != null) {
      final hashes = hm.group(1)!;
      final prefix = '$hashes '; // e.g. "## "
      final content = hm.group(2)!;
      final level = hashes.length;
      final hStyle = base.copyWith(
        fontSize: _nbHeadingSize(level),
        fontWeight: _nbHeadingWeight(level),
        color: _nbHeadingColor(level),
        height: 1.75,
        decoration: TextDecoration.none,
      );
      // When the cursor is on the line: show #s dimmed at 40% opacity.
      // When the cursor is elsewhere:   hide them (transparent + near-zero size
      //   so they occupy no space, matching Obsidian-style clean heading display).
      children.add(
        TextSpan(
          text: prefix,
          style: onLine
              ? hStyle.copyWith(
                  color: _nbHeadingColor(level).withOpacity(0.40),
                  fontWeight: FontWeight.normal,
                )
              : hStyle.copyWith(
                  color: Colors.transparent,
                  fontSize: 0.001,
                  height: 0.001,
                ),
        ),
      );
      final inlineCursor = onLine
          ? (cursorPos - lineStart - prefix.length).clamp(-1, content.length)
          : -1;
      children.add(_buildLineInlineSpan(content, hStyle, inlineCursor));
      offset = lineEnd + 1;
      continue;
    }

    // ── Blockquote: > text ────────────────────────────────────────────────
    if (line.startsWith('> ')) {
      const prefix = '> ';
      final content = line.substring(2);
      final qStyle = base.copyWith(
        color: _nordFrost.withOpacity(0.72),
        fontStyle: FontStyle.italic,
      );
      children.add(
        TextSpan(
          text: prefix,
          style: base.copyWith(
            color: _nordBlue.withOpacity(onLine ? 0.60 : 0.28),
          ),
        ),
      );
      final inlineCursor = onLine
          ? (cursorPos - lineStart - prefix.length).clamp(-1, content.length)
          : -1;
      children.add(_buildLineInlineSpan(content, qStyle, inlineCursor));
      offset = lineEnd + 1;
      continue;
    }

    // ── Checkbox: [indent]- [ ] / - [x] ──────────────────────────────────
    final cm = RegExp(r'^(\s*- \[)([ xX])(\] )(.*)$').firstMatch(line);
    if (cm != null) {
      final prefixOpen = cm.group(1)!; // "- ["
      final mark = cm.group(2)!; // " " or "x"
      final prefixClose = cm.group(3)!; // "] "
      final content = cm.group(4)!;
      final checked = mark.toLowerCase() == 'x';
      final prefixLen = prefixOpen.length + mark.length + prefixClose.length;
      final dimOpacity = onLine ? 0.55 : 0.25;
      children.add(
        TextSpan(
          text: '$prefixOpen$mark$prefixClose',
          style: base.copyWith(
            color: (checked ? _nordGreen : _nordSnow).withOpacity(dimOpacity),
            fontFamily: 'monospace',
          ),
        ),
      );
      final contentStyle = base.copyWith(
        color: checked ? _nordFrost.withOpacity(0.38) : _nordFrost,
        decoration: checked ? TextDecoration.lineThrough : TextDecoration.none,
        decorationColor: _nordFrost.withOpacity(0.38),
      );
      final inlineCursor = onLine
          ? (cursorPos - lineStart - prefixLen).clamp(-1, content.length)
          : -1;
      children.add(_buildLineInlineSpan(content, contentStyle, inlineCursor));
      offset = lineEnd + 1;
      continue;
    }

    // ── Bullet: [indent]- / * / + ─────────────────────────────────────────
    final bm = RegExp(r'^(\s*)([-*+] )(.*)$').firstMatch(line);
    if (bm != null) {
      final indent = bm.group(1)!;
      final bullet = bm.group(2)!;
      final content = bm.group(3)!;
      final prefixLen = indent.length + bullet.length;
      children.add(
        TextSpan(
          text: '$indent$bullet',
          style: base.copyWith(
            color: _nordBlue.withOpacity(onLine ? 0.72 : 0.32),
          ),
        ),
      );
      final inlineCursor = onLine
          ? (cursorPos - lineStart - prefixLen).clamp(-1, content.length)
          : -1;
      children.add(_buildLineInlineSpan(content, base, inlineCursor));
      offset = lineEnd + 1;
      continue;
    }

    // ── Numbered list: [indent]1. / 1) ───────────────────────────────────
    final nm = RegExp(r'^(\s*\d+[.)]\s+)(.*)$').firstMatch(line);
    if (nm != null) {
      final numPrefix = nm.group(1)!;
      final content = nm.group(2)!;
      children.add(
        TextSpan(
          text: numPrefix,
          style: base.copyWith(
            color: _nordFrost.withOpacity(onLine ? 0.60 : 0.28),
          ),
        ),
      );
      final inlineCursor = onLine
          ? (cursorPos - lineStart - numPrefix.length).clamp(-1, content.length)
          : -1;
      children.add(_buildLineInlineSpan(content, base, inlineCursor));
      offset = lineEnd + 1;
      continue;
    }

    // ── Plain text with inline markdown ───────────────────────────────────
    final inlineCursor = onLine ? (cursorPos - lineStart) : -1;
    children.add(_buildLineInlineSpan(line, base, inlineCursor));
    offset = lineEnd + 1;
  }

  return TextSpan(children: children, style: base);
}

// ── Per-line inline span builder ─────────────────────────────────────────────
//
// Handles: **bold**, *italic*, `code`, ~~strike~~, [link](url).
// [cursorPos] is relative to [text] (after any line prefix is stripped).
// Pass -1 to suppress cursor-reveal (cursor is on a different line).

TextSpan _buildLineInlineSpan(String text, TextStyle base, int cursorPos) {
  if (text.isEmpty) return TextSpan(text: '', style: base);

  final dimMarker = base.copyWith(
    color: (base.color ?? _nordFrost).withOpacity(0.30),
    fontWeight: FontWeight.normal,
    fontStyle: FontStyle.normal,
    decoration: TextDecoration.none,
  );

  final spans = <InlineSpan>[];
  int pos = 0;

  final re = RegExp(
    r'(\*\*|__)(.*?)\1' // bold           groups 1,2
    r'|(~~)(.*?)\3' // strikethrough  groups 3,4
    r'|(\*|_)(.*?)\5' // italic         groups 5,6
    r'|(`)(.*?)\7' // inline code    groups 7,8
    r'|\[([^\]]+)\]\(([^)]+)\)', // link           groups 9,10
    dotAll: false,
  );

  for (final m in re.allMatches(text)) {
    if (m.start > pos) {
      spans.add(TextSpan(text: text.substring(pos, m.start), style: base));
    }
    final inside = cursorPos >= m.start && cursorPos <= m.end;

    if (m.group(1) != null) {
      final marker = m.group(1)!;
      final content = m.group(2)!;
      final styled = base.copyWith(
        fontWeight: FontWeight.bold,
        color: _nordFrost2,
      );
      if (inside) {
        spans.addAll([
          TextSpan(text: marker, style: dimMarker),
          TextSpan(text: content, style: styled),
          TextSpan(text: marker, style: dimMarker),
        ]);
      } else {
        spans.add(TextSpan(text: content, style: styled));
      }
    } else if (m.group(3) != null) {
      final marker = m.group(3)!;
      final content = m.group(4)!;
      final styled = base.copyWith(
        decoration: TextDecoration.lineThrough,
        decorationColor: base.color,
      );
      if (inside) {
        spans.addAll([
          TextSpan(text: marker, style: dimMarker),
          TextSpan(text: content, style: styled),
          TextSpan(text: marker, style: dimMarker),
        ]);
      } else {
        spans.add(TextSpan(text: content, style: styled));
      }
    } else if (m.group(5) != null) {
      final marker = m.group(5)!;
      final content = m.group(6)!;
      final styled = base.copyWith(fontStyle: FontStyle.italic);
      if (inside) {
        spans.addAll([
          TextSpan(text: marker, style: dimMarker),
          TextSpan(text: content, style: styled),
          TextSpan(text: marker, style: dimMarker),
        ]);
      } else {
        spans.add(TextSpan(text: content, style: styled));
      }
    } else if (m.group(7) != null) {
      final marker = m.group(7)!;
      final content = m.group(8)!;
      final styled = base.copyWith(
        fontFamily: 'monospace',
        color: _nordCyan,
        background: Paint()..color = _nordBase1,
      );
      if (inside) {
        spans.addAll([
          TextSpan(text: marker, style: dimMarker),
          TextSpan(text: content, style: styled),
          TextSpan(text: marker, style: dimMarker),
        ]);
      } else {
        spans.add(TextSpan(text: content, style: styled));
      }
    } else if (m.group(9) != null) {
      // Links: always rendered; no cursor-reveal needed.
      spans.add(
        TextSpan(
          text: m.group(9),
          style: base.copyWith(
            color: _nordBlue,
            decoration: TextDecoration.underline,
            decorationColor: _nordBlue,
          ),
        ),
      );
    }
    pos = m.end;
  }

  if (pos < text.length) {
    spans.add(TextSpan(text: text.substring(pos), style: base));
  }

  return TextSpan(
    children: spans.isEmpty ? [TextSpan(text: text, style: base)] : spans,
    style: base,
  );
}

// ─────────────────────────────────────────────────────────────────────────────
// _NotesSidebar  —  Nord-themed explorer panel
// ─────────────────────────────────────────────────────────────────────────────

class _NotesSidebar extends StatefulWidget {
  final List<Note> taskNotes;
  final List<Note> projectNotes;
  final List<Note> commonNotes;
  final String? activeNoteId;
  final void Function(String id) onSelectNote;
  final VoidCallback onNewNote;
  final List<Task> allTasks;
  final Map<String, NoteFolder> noteFolders;
  final void Function(String name) onCreateFolder;
  final void Function(String noteId, String? folderId) onAssignFolder;
  final void Function(String folderId, String newName) onRenameFolder;
  final void Function(String folderId) onDeleteFolder;
  final void Function(String scope) onFilterGroupSort;
  // 9f: callback to delete a note from right-click context menu
  final void Function(String noteId)? onDeleteNote;

  // Task context menu actions from Notes sidebar (schedule, details, duplicate, etc.)
  final Future<void> Function(String action, Task task, BuildContext context)?
  onNoteTaskAction;
  // Tag colors for the tag annexed submenu
  final Map<String, Color> tagColors;

  // 9e: callback fired when the user drags notes to reorder them
  final void Function(List<String> orderedIds)? onReorderNotes;
  // Parity: reorder callbacks for task/project note sections
  final void Function(List<String> orderedIds)? onReorderProjectNotes;
  final void Function(List<String> orderedIds)? onReorderTaskNotes;
  // Parity: visibility toggles
  final void Function(String linkedId)? onToggleProjectVisibility;
  final void Function(String linkedId)? onToggleTaskVisibility;
  // Parity: pre-computed hidden sets passed from parent
  final Set<String> hiddenNoteProjects;
  final Set<String> hiddenNoteTasks;
  // Parity: settings gear callbacks
  final VoidCallback? onProjectSettings;
  final VoidCallback? onTaskSettings;
  // Notes header: Settings button
  final VoidCallback? onNotesSettings;
  // Projects header: Add button
  final VoidCallback? onAddProject;
  // Parity: manual order lists (passed from parent state)
  final List<String> noteProjectOrder;
  final List<String> noteTaskOrder;
  // ── Notes-section folder order (independent from projectFolderOrder) ───────
  final List<String> noteFolderOrder;
  final void Function(List<String> orderedIds)? onReorderNoteFolders;
  // ── Project-folder parity props (mirrors Tasks sidebar) ──────────────────
  // Passed by reference so folder mutations in Tasks sidebar are reflected here.
  final Map<String, Set<String>> projectFolders;
  final List<String> projectFolderOrder;
  final Map<String, Project> projects;
  final Map<String, bool> projectHiddenFromMenu;

  /// Called when the user right-clicks a project-note item in the Projects
  /// section. Provides (TapDownDetails, projectId) so the parent can show the
  /// same context-menu panel as the Tasks sidebar projects.
  final void Function(TapDownDetails details, String projectId)?
  onNoteProjectContextMenu;

  // ── Project-level F/S rules (from the Tasks tab F/G/S panel) ─────────────
  // Passed so the Tasks collapsible mirrors the same filter/sort as Tasks>.
  final List<FilterRule> filterRules;
  final List<SortCriterion> sortCriteria;

  const _NotesSidebar({
    required this.taskNotes,
    required this.projectNotes,
    required this.commonNotes,
    required this.activeNoteId,
    required this.onSelectNote,
    required this.onNewNote,
    this.allTasks = const [],
    this.noteFolders = const {},
    required this.onCreateFolder,
    required this.onAssignFolder,
    required this.onRenameFolder,
    required this.onDeleteFolder,
    required this.onFilterGroupSort,
    this.onDeleteNote,
    this.onNoteTaskAction,
    this.tagColors = const {},
    this.onReorderNotes,
    this.onReorderProjectNotes,
    this.onReorderTaskNotes,
    this.onToggleProjectVisibility,
    this.onToggleTaskVisibility,
    this.hiddenNoteProjects = const {},
    this.hiddenNoteTasks = const {},
    this.onProjectSettings,
    this.onTaskSettings,
    this.onNotesSettings,
    this.onAddProject,
    this.noteProjectOrder = const [],
    this.noteTaskOrder = const [],
    this.noteFolderOrder = const [],
    this.onReorderNoteFolders,
    this.projectFolders = const {},
    this.projectFolderOrder = const [],
    this.projects = const {},
    this.projectHiddenFromMenu = const {},
    this.onNoteProjectContextMenu,
    this.filterRules = const [],
    this.sortCriteria = const [],
  });

  @override
  State<_NotesSidebar> createState() => _NotesSidebarState();
}

class _NotesSidebarState extends State<_NotesSidebar> {
  bool _taskExpanded = true;
  bool _projectExpanded = true;
  bool _commonExpanded = true;
  final Map<String, bool> _folderExpanded = {};
  // Tracks which project-folder groups are collapsed in the Notes sidebar.
  final Set<String> _collapsedNoteProjectFolders = {};
  // Tracks which project-folder groups are collapsed in the Tasks note section.
  final Set<String> _collapsedNoteTaskFolders = {};
  String _search = '';
  final _searchCtrl = TextEditingController();
  // 9e: persists drag-reorder within the common notes list.
  List<String> _noteOrder = [];
  // Parity: local order mirrors for task/project note sections
  List<String> _localProjectNoteOrder = [];
  List<String> _localTaskNoteOrder = [];
  // Local mirror of noteFolderOrder — drives ReorderableListView for folders
  List<String> _localNoteFolderOrder = [];
  // Merged order of named folders + '__standard__' sentinel — drives the
  // single unified ReorderableListView in the Notes section.
  static const _kStandard = '__standard__';
  List<String> _notesEffectiveOrder = [];
  // Projects section sort state (mirrors _OrgSettingsViewState pattern)
  String _noteProjectSortField = 'name'; // 'name' | 'taskCount'
  bool _noteProjectSortAsc = true;
  // Notes section sort state (mirrors Projects section pattern)
  String _noteCommonSortField = 'name'; // 'name' | 'updated'
  bool _noteCommonSortAsc = true;
  // Standard folder collapse state for the Notes section
  bool _notesStandardExpanded = true;

  @override
  void initState() {
    super.initState();
    _noteOrder = widget.commonNotes.map((n) => n.id).toList();
    _localProjectNoteOrder = widget.noteProjectOrder.isNotEmpty
        ? List<String>.from(widget.noteProjectOrder)
        : widget.projectNotes.map((n) => n.id).toList();
    _localTaskNoteOrder = widget.noteTaskOrder.isNotEmpty
        ? List<String>.from(widget.noteTaskOrder)
        : widget.taskNotes.map((n) => n.id).toList();
    _localNoteFolderOrder = widget.noteFolderOrder.isNotEmpty
        ? List<String>.from(widget.noteFolderOrder)
        : widget.noteFolders.keys.toList();
    _notesEffectiveOrder = [..._localNoteFolderOrder, _kStandard];
  }

  @override
  void didUpdateWidget(_NotesSidebar old) {
    super.didUpdateWidget(old);
    // Sync common notes order list
    final incoming = widget.commonNotes.map((n) => n.id).toSet();
    _noteOrder.removeWhere((id) => !incoming.contains(id));
    for (final id in widget.commonNotes.map((n) => n.id)) {
      if (!_noteOrder.contains(id)) _noteOrder.add(id);
    }
    // Sync project notes order
    final incomingProj = widget.projectNotes.map((n) => n.id).toSet();
    _localProjectNoteOrder.removeWhere((id) => !incomingProj.contains(id));
    for (final id in widget.projectNotes.map((n) => n.id)) {
      if (!_localProjectNoteOrder.contains(id)) _localProjectNoteOrder.add(id);
    }
    // Sync task notes order
    final incomingTask = widget.taskNotes.map((n) => n.id).toSet();
    _localTaskNoteOrder.removeWhere((id) => !incomingTask.contains(id));
    for (final id in widget.taskNotes.map((n) => n.id)) {
      if (!_localTaskNoteOrder.contains(id)) _localTaskNoteOrder.add(id);
    }
    // Sync note-folder order — reconcile against current folder keys
    final incomingFolders = widget.noteFolders.keys.toSet();
    _localNoteFolderOrder.removeWhere((id) => !incomingFolders.contains(id));
    // Respect incoming order from parent (persisted state)
    for (final id in widget.noteFolderOrder) {
      if (!_localNoteFolderOrder.contains(id) && incomingFolders.contains(id)) {
        _localNoteFolderOrder.add(id);
      }
    }
    // Any folder not yet in the list goes to the end
    for (final id in incomingFolders) {
      if (!_localNoteFolderOrder.contains(id)) _localNoteFolderOrder.add(id);
    }
    // Reconcile _notesEffectiveOrder: drop deleted real folders, add new ones,
    // keep '__standard__' wherever the user last placed it.
    _notesEffectiveOrder.removeWhere(
      (id) => id != _kStandard && !incomingFolders.contains(id),
    );
    for (final id in _localNoteFolderOrder) {
      if (!_notesEffectiveOrder.contains(id)) _notesEffectiveOrder.add(id);
    }
    if (!_notesEffectiveOrder.contains(_kStandard)) {
      _notesEffectiveOrder.add(_kStandard);
    }
  }

  // ── Full task + Notes-specific right-click menu (Notes > Tasks section) ────
  Future<void> _showNotesTaskContextMenu(
    BuildContext context,
    Note note,
    Task? linkedTask,
    Offset globalPos,
  ) async {
    Widget menuItem(
      IconData icon,
      String label, {
      Color iconColor = const Color(0xFF9AA3B0),
      Color labelColor = const Color(0xFFD0D4DC),
      Widget? trailing,
      String? shortcut,
    }) {
      return Row(
        children: [
          Icon(icon, size: 15, color: iconColor),
          const SizedBox(width: 12),
          Expanded(
            child: Text(
              label,
              style: TextStyle(fontSize: 12.5, color: labelColor),
            ),
          ),
          if (trailing != null) trailing,
          if (shortcut != null) ...[
            const SizedBox(width: 8),
            Container(
              padding: const EdgeInsets.symmetric(horizontal: 5, vertical: 2),
              decoration: BoxDecoration(
                color: const Color(0xFF2C2F35),
                borderRadius: BorderRadius.circular(4),
                border: Border.all(color: Colors.white12),
              ),
              child: Text(
                shortcut,
                style: const TextStyle(fontSize: 10, color: Colors.white38),
              ),
            ),
          ],
        ],
      );
    }

    Widget badge(int n) => Container(
      padding: const EdgeInsets.symmetric(horizontal: 5, vertical: 1),
      decoration: BoxDecoration(
        color: const Color(0xFF2C3040),
        borderRadius: BorderRadius.circular(10),
      ),
      child: Text(
        '$n',
        style: const TextStyle(fontSize: 10, color: Colors.white38),
      ),
    );

    const menuBg = Color(0xFF1E2124);
    const menuBorder = Color(0xFF2C2F35);
    final pos = RelativeRect.fromLTRB(
      globalPos.dx,
      globalPos.dy,
      globalPos.dx + 1,
      globalPos.dy + 1,
    );

    // ── "Add to Folder" annexed items ───────────────────────────────────────
    final folderAnnexedItems = <_AnnexedItem>[
      _AnnexedItem(
        value: '__no_folder__',
        label: 'No Folder',
        icon: Icons.folder_off_outlined,
        iconColor: const Color(0xFF9AA3B0),
        active: note.folderId == null,
      ),
      ...widget.noteFolders.values.map(
        (f) => _AnnexedItem(
          value: f.id,
          label: f.name,
          icon: Icons.folder_outlined,
          iconColor: const Color(0xFFEBCB8B),
          active: note.folderId == f.id,
        ),
      ),
    ];

    final items = <PopupMenuEntry<String>>[
      // ── Task-specific items (only when linked task exists) ─────────────
      if (linkedTask != null) ...[
        // Schedule quick-action row
        PopupMenuItem(
          value: '__schedule_row__',
          enabled: false,
          height: 48,
          padding: const EdgeInsets.symmetric(horizontal: 8),
          child: _ScheduleIconRow(
            task: linkedTask,
            onSchedule: (val) => Navigator.of(context).pop(val),
          ),
        ),
        PopupMenuItem(
          value: 'start_focus',
          height: 36,
          child: menuItem(
            Icons.center_focus_strong_outlined,
            'Start Focus',
            iconColor: const Color(0xFFFFB74D),
            labelColor: const Color(0xFFFFB74D),
          ),
        ),
        PopupMenuItem(
          value: 'details',
          height: 36,
          child: menuItem(
            Icons.info_outline_rounded,
            'Details',
            iconColor: const Color(0xFF4FC3F7),
            labelColor: const Color(0xFF4FC3F7),
          ),
        ),
        PopupMenuItem(
          value: 'duplicate',
          height: 36,
          child: menuItem(Icons.content_copy_outlined, 'Duplicate'),
        ),
        PopupMenuItem(
          value: 'subtask',
          height: 36,
          child: menuItem(
            Icons.add_task_outlined,
            'Add sub task',
            trailing: linkedTask.subTaskIds.isNotEmpty
                ? badge(linkedTask.subTaskIds.length)
                : null,
          ),
        ),
        // Tags — annexed submenu
        PopupMenuItem(
          value: '__tags__',
          height: 36,
          child: _AnnexedMenuItem(
            icon: Icons.label_outline,
            label: 'Add Tags',
            badge: linkedTask.tagIds.isNotEmpty
                ? linkedTask.tagIds.length
                : null,
            items: () {
              final allKnownTags = {
                ...widget.tagColors.keys,
                ...widget.allTasks.expand(
                  (t) => t.tagIds.map((id) => id.toString()),
                ),
              }.toList()..sort();
              return allKnownTags.map((tagId) {
                final has = linkedTask.tagIds.contains(tagId);
                final tagColor =
                    widget.tagColors[tagId] ?? const Color(0xFF9AA3B0);
                return _AnnexedItem(
                  value: tagId,
                  label: tagId,
                  icon: has ? Icons.label : Icons.label_outline,
                  iconColor: tagColor,
                  active: has,
                );
              }).toList();
            }(),
            onSelect: (tagId) {
              widget.onNoteTaskAction?.call(
                'tag_toggle:$tagId',
                linkedTask,
                context,
              );
            },
          ),
        ),
        // Move to Project — annexed submenu
        PopupMenuItem(
          value: '__move__',
          height: 36,
          child: _AnnexedMenuItem(
            icon: Icons.drive_file_move_outline,
            label: 'Move to Project',
            badge: widget.projects.isNotEmpty ? widget.projects.length : null,
            items: [
              _AnnexedItem(
                value: 'INBOX_PROJECT',
                label: 'Inbox',
                icon: Icons.inbox_outlined,
                active: linkedTask.projectId == 'INBOX_PROJECT',
              ),
              ...widget.projects.entries.map(
                (e) => _AnnexedItem(
                  value: e.key,
                  label: e.value.title,
                  icon: Icons.folder_outlined,
                  active: linkedTask.projectId == e.key,
                ),
              ),
            ],
            onSelect: (projId) {
              widget.onNoteTaskAction?.call(
                'move:$projId',
                linkedTask,
                context,
              );
            },
          ),
        ),
        // Convert to Parent (conditional)
        if (widget.allTasks.any(
          (t) => t.subTaskIds.any((id) => id.toString() == linkedTask.id),
        ))
          PopupMenuItem(
            value: 'convert_to_parent',
            height: 36,
            child: menuItem(Icons.upgrade_outlined, 'Convert to Parent Task'),
          ),
        const PopupMenuDivider(height: 4),
      ],

      // ── Notes-specific items ───────────────────────────────────────────
      PopupMenuItem(
        value: '__folder__',
        height: 36,
        child: _AnnexedMenuItem(
          icon: Icons.create_new_folder_outlined,
          label: 'Add to Folder',
          badge: note.folderId != null ? 1 : null,
          items: folderAnnexedItems,
          onSelect: (folderId) {
            widget.onAssignFolder(
              note.id,
              folderId == '__no_folder__' ? null : folderId,
            );
          },
        ),
      ),

      const PopupMenuDivider(height: 4),

      // Delete Note
      PopupMenuItem(
        value: 'delete_note',
        height: 36,
        child: menuItem(
          Icons.note_alt_outlined,
          'Delete Note',
          iconColor: const Color(0xFFEF5350),
          labelColor: const Color(0xFFEF5350),
        ),
      ),
      // Delete Task (only when linked task exists)
      if (linkedTask != null)
        PopupMenuItem(
          value: 'delete',
          height: 36,
          child: menuItem(
            Icons.delete_outline,
            'Delete Task',
            iconColor: const Color(0xFFEF5350),
            labelColor: const Color(0xFFEF5350),
            shortcut: 'Backspace',
          ),
        ),
    ];

    final choice = await showMenu<String>(
      context: context,
      position: pos,
      color: menuBg,
      elevation: 12,
      shape: RoundedRectangleBorder(
        borderRadius: BorderRadius.circular(10),
        side: const BorderSide(color: menuBorder, width: 0.8),
      ),
      items: items,
    );

    if (choice == null || !mounted) return;

    switch (choice) {
      case 'sched_today':
      case 'sched_tomorrow':
      case 'sched_nextweek':
      case 'sched_reschedule':
      case 'sched_unschedule':
      case 'start_focus':
      case 'details':
      case 'duplicate':
      case 'subtask':
      case 'convert_to_parent':
      case 'delete':
        if (linkedTask != null) {
          widget.onNoteTaskAction?.call(choice, linkedTask, context);
        }
        break;

      case 'delete_note':
        final confirmed = await showDialog<bool>(
          context: context,
          builder: (ctx) => AlertDialog(
            backgroundColor: const Color(0xFF2E3440),
            title: const Text(
              'Delete note?',
              style: TextStyle(color: Colors.white, fontSize: 14),
            ),
            content: const Text(
              'This cannot be undone.',
              style: TextStyle(color: Colors.white70, fontSize: 12),
            ),
            actions: [
              TextButton(
                onPressed: () => Navigator.of(ctx).pop(false),
                child: const Text(
                  'Cancel',
                  style: TextStyle(color: Colors.white54),
                ),
              ),
              TextButton(
                onPressed: () => Navigator.of(ctx).pop(true),
                child: const Text(
                  'Delete',
                  style: TextStyle(color: Colors.redAccent),
                ),
              ),
            ],
          ),
        );
        if (confirmed == true) widget.onDeleteNote?.call(note.id);
        break;
    }
  }

  @override
  void dispose() {
    _searchCtrl.dispose();
    super.dispose();
  }

  List<Note> _filter(List<Note> notes) {
    if (_search.isEmpty) return notes;
    final q = _search.toLowerCase();
    return notes
        .where(
          (n) =>
              n.title.toLowerCase().contains(q) ||
              n.content.toLowerCase().contains(q),
        )
        .toList();
  }

  @override
  Widget build(BuildContext context) {
    Widget noteItem(
      Note note, {
      Future<void> Function(TapDownDetails)? onContextMenuOverride,
    }) {
      final active = note.id == widget.activeNoteId;
      IconData icon;
      switch (note.type) {
        case NoteType.task:
          icon = Icons.check_box_outline_blank_rounded;
          break;
        case NoteType.project:
          icon = Icons.folder_open_outlined;
          break;
        case NoteType.common:
          icon = Icons.article_outlined;
          break;
      }

      // For task notes, look up the linked task's scheduled date and time
      String? taskDateLabel;
      String? taskTimeLabel;
      if (note.type == NoteType.task && note.linkedTaskId != null) {
        try {
          final task = widget.allTasks.firstWhere(
            (t) => t.id == note.linkedTaskId,
          );
          final dt = task.scheduledDate;
          if (dt != null) {
            taskDateLabel = _fmtDateChip(dt);
          }
          // Time: plannedAt first, then T-component of dueDay, then space suffix
          if (task.plannedAt != null && task.plannedAt! > 0) {
            final tdt = DateTime.fromMillisecondsSinceEpoch(
              task.plannedAt!,
            ).toLocal();
            taskTimeLabel =
                "${tdt.hour.toString().padLeft(2, '0')}:${tdt.minute.toString().padLeft(2, '0')}";
          } else if (task.dueDay != null && task.dueDay!.contains('T')) {
            final tdt = DateTime.tryParse(task.dueDay!);
            if (tdt != null) {
              taskTimeLabel =
                  "${tdt.hour.toString().padLeft(2, '0')}:${tdt.minute.toString().padLeft(2, '0')}";
            }
          } else if (task.dueDay != null && task.dueDay!.contains(' ')) {
            taskTimeLabel = task.dueDay!.split(' ').skip(1).join(' ');
          }
        } catch (_) {}
      }

      return MouseRegion(
        cursor: SystemMouseCursors.click,
        child: GestureDetector(
          onTap: () => widget.onSelectNote(note.id),
          // 9f: right-click context menu with Delete option
          onSecondaryTapDown:
              onContextMenuOverride ??
              (widget.onDeleteNote == null
                  ? null
                  : (d) async {
                      final action = await showMenu<String>(
                        context: context,
                        position: RelativeRect.fromLTRB(
                          d.globalPosition.dx,
                          d.globalPosition.dy,
                          d.globalPosition.dx + 1,
                          d.globalPosition.dy + 1,
                        ),
                        items: const [
                          PopupMenuItem(
                            value: 'delete',
                            child: Row(
                              children: [
                                Icon(
                                  Icons.delete_outline_rounded,
                                  size: 14,
                                  color: Colors.redAccent,
                                ),
                                SizedBox(width: 8),
                                Text(
                                  'Delete',
                                  style: TextStyle(color: Colors.redAccent),
                                ),
                              ],
                            ),
                          ),
                        ],
                      );
                      if (action != 'delete') return;
                      // Confirmation dialog
                      final confirmed = await showDialog<bool>(
                        context: context,
                        builder: (ctx) => AlertDialog(
                          backgroundColor: const Color(0xFF2E3440),
                          title: const Text(
                            'Delete note?',
                            style: TextStyle(color: Colors.white, fontSize: 14),
                          ),
                          content: const Text(
                            'This cannot be undone.',
                            style: TextStyle(
                              color: Colors.white70,
                              fontSize: 12,
                            ),
                          ),
                          actions: [
                            TextButton(
                              onPressed: () => Navigator.of(ctx).pop(false),
                              child: const Text(
                                'Cancel',
                                style: TextStyle(color: Colors.white54),
                              ),
                            ),
                            TextButton(
                              onPressed: () => Navigator.of(ctx).pop(true),
                              child: const Text(
                                'Delete',
                                style: TextStyle(color: Colors.redAccent),
                              ),
                            ),
                          ],
                        ),
                      );
                      if (confirmed == true) widget.onDeleteNote!(note.id);
                    }),
          child: AnimatedContainer(
            duration: const Duration(milliseconds: 100),
            margin: const EdgeInsets.symmetric(horizontal: 6, vertical: 1),
            padding: const EdgeInsets.symmetric(horizontal: 8, vertical: 5),
            decoration: BoxDecoration(
              color: active ? _nordBase2 : Colors.transparent,
              borderRadius: BorderRadius.circular(4),
            ),
            child: Row(
              children: [
                Icon(icon, size: 13, color: active ? _nordCyan : _nordSnow),
                const SizedBox(width: 8),
                Expanded(
                  child: Column(
                    crossAxisAlignment: CrossAxisAlignment.start,
                    mainAxisSize: MainAxisSize.min,
                    children: [
                      Text(
                        note.title,
                        maxLines: 1,
                        overflow: TextOverflow.ellipsis,
                        style: TextStyle(
                          fontSize: 12,
                          color: active ? _nordFrost2 : _nordFrost,
                          fontWeight: active
                              ? FontWeight.w500
                              : FontWeight.normal,
                        ),
                      ),
                      if (taskDateLabel != null)
                        Padding(
                          padding: const EdgeInsets.only(top: 2),
                          child: Row(
                            children: [
                              Text(
                                taskDateLabel,
                                style: const TextStyle(
                                  fontSize: 9,
                                  color: _nordSnow,
                                  letterSpacing: 0.2,
                                ),
                              ),
                              if (taskTimeLabel != null) ...[
                                const Text(
                                  '  |  ',
                                  style: TextStyle(
                                    fontSize: 9,
                                    color: Color(
                                      0xFF4C566A,
                                    ), // _nordSnow at ~50%
                                  ),
                                ),
                                Text(
                                  taskTimeLabel,
                                  style: const TextStyle(
                                    fontSize: 9,
                                    color: _nordSnow,
                                    letterSpacing: 0.2,
                                  ),
                                ),
                              ],
                            ],
                          ),
                        ),
                    ],
                  ),
                ),
              ],
            ),
          ),
        ),
      );
    }

    // ── Task notes: apply text search, then project-level F/S rules ─────────
    // Build a task lookup so we can check each note's linked task.
    final _taskMap = <String, Task>{for (final t in widget.allTasks) t.id: t};

    // 1. Text search (existing behaviour)
    List<Note> taskFiltered = _filter(widget.taskNotes);

    // 2. Apply active Filter rules from the Tasks tab F/G/S panel.
    final _activeNoteTaskFilters = widget.filterRules
        .where((r) => r.isConfigured)
        .toList();
    if (_activeNoteTaskFilters.isNotEmpty) {
      taskFiltered = taskFiltered.where((note) {
        if (note.linkedTaskId == null)
          return true; // unlinked notes: always show
        final task = _taskMap[note.linkedTaskId!];
        if (task == null) return true; // dangling link: show rather than hide
        return _activeNoteTaskFilters.every(
          (r) => r.matches(task, widget.projects),
        );
      }).toList();
    }

    // 3. Apply Sort criteria — reorder notes to match the Tasks tab order.
    if (widget.sortCriteria.isNotEmpty && taskFiltered.isNotEmpty) {
      final linked = taskFiltered
          .where(
            (n) =>
                n.linkedTaskId != null && _taskMap.containsKey(n.linkedTaskId),
          )
          .toList();
      final orphans = taskFiltered
          .where(
            (n) =>
                n.linkedTaskId == null || !_taskMap.containsKey(n.linkedTaskId),
          )
          .toList();
      final sortedTasks = _applySortCriteria(
        linked.map((n) => _taskMap[n.linkedTaskId!]!).toList(),
        widget.sortCriteria,
      );
      final taskIdOrder = {
        for (var i = 0; i < sortedTasks.length; i++) sortedTasks[i].id: i,
      };
      linked.sort((a, b) {
        final ia = taskIdOrder[a.linkedTaskId] ?? 999999;
        final ib = taskIdOrder[b.linkedTaskId] ?? 999999;
        return ia.compareTo(ib);
      });
      taskFiltered = [...linked, ...orphans];
    }

    final projectFiltered = _filter(widget.projectNotes);
    final commonFiltered = _filter(widget.commonNotes);

    return Container(
      color: _nordSidebar,
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.stretch,
        children: [
          // ── Search + new note ──────────────────────────────────────────
          Padding(
            padding: const EdgeInsets.fromLTRB(8, 10, 8, 6),
            child: Row(
              children: [
                Expanded(
                  child: Container(
                    height: 27,
                    decoration: BoxDecoration(
                      color: _nordBase1,
                      borderRadius: BorderRadius.circular(5),
                      border: Border.all(color: _nordDivider),
                    ),
                    child: Row(
                      children: [
                        const SizedBox(width: 7),
                        const Icon(
                          Icons.search_rounded,
                          size: 13,
                          color: _nordSnow,
                        ),
                        const SizedBox(width: 5),
                        Expanded(
                          child: TextField(
                            controller: _searchCtrl,
                            style: const TextStyle(
                              fontSize: 11,
                              color: _nordFrost,
                            ),
                            decoration: const InputDecoration(
                              hintText: 'Search…',
                              hintStyle: TextStyle(
                                fontSize: 11,
                                color: _nordSnow,
                              ),
                              border: InputBorder.none,
                              isDense: true,
                              contentPadding: EdgeInsets.zero,
                            ),
                            onChanged: (v) => setState(() => _search = v),
                          ),
                        ),
                      ],
                    ),
                  ),
                ),
              ],
            ),
          ),
          const Divider(color: _nordDivider, height: 1, thickness: 1),
          Expanded(
            child: ListView(
              padding: const EdgeInsets.only(top: 4, bottom: 16),
              children: [
                // ── Tasks header — matches Projects header style ──
                InkWell(
                  onTap: () => setState(() => _taskExpanded = !_taskExpanded),
                  hoverColor: Colors.white.withOpacity(0.03),
                  child: Container(
                    height: 40,
                    decoration: BoxDecoration(
                      color: Colors.white.withOpacity(0.05),
                      border: Border(
                        bottom: BorderSide(
                          color: const Color(0xFF2C2F32),
                          width: 0.5,
                        ),
                      ),
                    ),
                    padding: const EdgeInsets.fromLTRB(14, 0, 6, 0),
                    child: Row(
                      children: [
                        AnimatedRotation(
                          turns: _taskExpanded ? 0.25 : 0.0,
                          duration: const Duration(milliseconds: 150),
                          child: const Icon(
                            Icons.chevron_right_rounded,
                            size: 14,
                            color: Color(0xFF6B7280),
                          ),
                        ),
                        const SizedBox(width: 6),
                        Expanded(
                          child: Text(
                            'TASKS',
                            style: const TextStyle(
                              fontSize: 10,
                              fontWeight: FontWeight.w700,
                              color: Color(0xFF9CA3AF),
                              letterSpacing: 1.4,
                            ),
                          ),
                        ),
                        // Count badge
                        if (taskFiltered.isNotEmpty)
                          Padding(
                            padding: const EdgeInsets.only(right: 4),
                            child: Text(
                              '${taskFiltered.length}',
                              style: const TextStyle(
                                fontSize: 9,
                                color: Color(0xFF6B7280),
                              ),
                            ),
                          ),
                        // ── Settings button ───────────────────────────────
                        if (widget.onTaskSettings != null)
                          Tooltip(
                            message: 'Task Settings',
                            waitDuration: const Duration(milliseconds: 500),
                            child: InkWell(
                              onTap: widget.onTaskSettings,
                              borderRadius: BorderRadius.circular(5),
                              hoverColor: Colors.white.withOpacity(0.07),
                              child: const Padding(
                                padding: EdgeInsets.all(5),
                                child: Icon(
                                  Icons.settings_outlined,
                                  size: 13,
                                  color: Color(0xFF6B7280),
                                ),
                              ),
                            ),
                          ),
                        const SizedBox(width: 2),
                      ],
                    ),
                  ),
                ),
                if (_taskExpanded) ...[
                  // ── Same folder-grouped structure as Projects section ───────
                  // Task notes are grouped by the project of their linked task:
                  //   note.linkedTaskId → task.projectId → _projectFolders bucket
                  () {
                    const accent = Color(0xFF4FC3F7);
                    const folderYellow = Color(0xFFEBCB8B);
                    const standardKey = '__standard__';

                    // Build taskId → projectId lookup from allTasks.
                    final taskIdToProjectId = <String, String>{
                      for (final t in widget.allTasks) t.id: t.projectId,
                    };

                    // Build projectId → folderName lookup from projectFolders.
                    final pidToFolder = <String, String>{};
                    for (final entry in widget.projectFolders.entries) {
                      for (final pid in entry.value) {
                        pidToFolder[pid] = entry.key;
                      }
                    }

                    // Group task notes by folder (Standard = no folder).
                    final Map<String, List<Note>> grouped = {};
                    final List<Note> standardNotes = [];
                    for (final note in taskFiltered) {
                      final tid = note.linkedTaskId;
                      final pid = tid != null ? taskIdToProjectId[tid] : null;
                      final fn = pid != null ? pidToFolder[pid] : null;
                      if (fn != null) {
                        grouped.putIfAbsent(fn, () => []).add(note);
                      } else {
                        standardNotes.add(note);
                      }
                    }

                    // Effective folder order — same _projectFolderOrder list.
                    final allFolderKeys = <String>[
                      ...widget.projectFolders.keys,
                      if (standardNotes.isNotEmpty) standardKey,
                    ];
                    final reconciled = <String>[
                      ...widget.projectFolderOrder.where(
                        allFolderKeys.contains,
                      ),
                      ...allFolderKeys.where(
                        (k) => !widget.projectFolderOrder.contains(k),
                      ),
                    ];
                    final effectiveOrder = reconciled;

                    // ── Single task-note row ───────────────────────────────
                    Widget noteRow(Note note) {
                      final linkedId = note.linkedTaskId ?? '';
                      final isHidden = widget.hiddenNoteTasks.contains(
                        linkedId,
                      );
                      if (isHidden) return const SizedBox.shrink();
                      return Stack(
                        key: ValueKey('tnote_folder_${note.id}'),
                        children: [
                          noteItem(
                            note,
                            onContextMenuOverride: (d) async {
                              final linked = note.linkedTaskId != null
                                  ? widget.allTasks.cast<Task?>().firstWhere(
                                      (t) => t?.id == note.linkedTaskId,
                                      orElse: () => null,
                                    )
                                  : null;
                              await _showNotesTaskContextMenu(
                                context,
                                note,
                                linked,
                                d.globalPosition,
                              );
                            },
                          ),
                          Positioned(
                            right: 4,
                            top: 0,
                            bottom: 0,
                            child: Tooltip(
                              message: 'Hide from sidebar',
                              child: InkWell(
                                onTap: () => widget.onToggleTaskVisibility
                                    ?.call(linkedId),
                                child: Padding(
                                  padding: const EdgeInsets.symmetric(
                                    horizontal: 3,
                                  ),
                                  child: Icon(
                                    Icons.visibility_off_outlined,
                                    size: 11,
                                    color: Colors.white.withOpacity(0.2),
                                  ),
                                ),
                              ),
                            ),
                          ),
                        ],
                      );
                    }

                    // ── Folder block (identical chrome to Projects section) ─
                    Widget buildFolderBlock({
                      required String folderKey,
                      required String displayName,
                      required List<Note> notes,
                      bool isStandard = false,
                      int listIdx = 0,
                    }) {
                      final isCollapsed = _collapsedNoteTaskFolders.contains(
                        folderKey,
                      );
                      return AnimatedContainer(
                        duration: const Duration(milliseconds: 120),
                        margin: const EdgeInsets.only(top: 1),
                        child: Column(
                          crossAxisAlignment: CrossAxisAlignment.stretch,
                          children: [
                            InkWell(
                              onTap: () => setState(() {
                                if (isCollapsed) {
                                  _collapsedNoteTaskFolders.remove(folderKey);
                                } else {
                                  _collapsedNoteTaskFolders.add(folderKey);
                                }
                              }),
                              hoverColor: Colors.white.withOpacity(0.04),
                              borderRadius: BorderRadius.circular(5),
                              child: Padding(
                                padding: const EdgeInsets.fromLTRB(
                                  12,
                                  6,
                                  10,
                                  6,
                                ),
                                child: Row(
                                  children: [
                                    ReorderableDragStartListener(
                                      index: listIdx,
                                      child: MouseRegion(
                                        cursor: SystemMouseCursors.grab,
                                        child: Padding(
                                          padding: const EdgeInsets.only(
                                            right: 5,
                                          ),
                                          child: Icon(
                                            Icons.drag_indicator_rounded,
                                            size: 13,
                                            color: Colors.white.withOpacity(
                                              0.18,
                                            ),
                                          ),
                                        ),
                                      ),
                                    ),
                                    Icon(
                                      isCollapsed
                                          ? Icons.folder_outlined
                                          : Icons.folder_open_outlined,
                                      size: 13,
                                      color: isStandard
                                          ? Colors.white24
                                          : folderYellow,
                                    ),
                                    const SizedBox(width: 7),
                                    Expanded(
                                      child: Text(
                                        displayName,
                                        overflow: TextOverflow.ellipsis,
                                        style: TextStyle(
                                          fontSize: 11,
                                          fontWeight: FontWeight.w600,
                                          letterSpacing: isStandard ? 0.6 : 0.0,
                                          color: isStandard
                                              ? Colors.white38
                                              : Colors.white70,
                                        ),
                                      ),
                                    ),
                                    if (notes.isNotEmpty)
                                      Text(
                                        '${notes.length}',
                                        style: const TextStyle(
                                          fontSize: 9,
                                          color: Color(0xFF6B7280),
                                        ),
                                      ),
                                    const SizedBox(width: 1),
                                    AnimatedRotation(
                                      turns: isCollapsed ? 0.0 : 0.25,
                                      duration: const Duration(
                                        milliseconds: 150,
                                      ),
                                      child: const Icon(
                                        Icons.chevron_right_rounded,
                                        size: 13,
                                        color: Color(0xFF4B5563),
                                      ),
                                    ),
                                  ],
                                ),
                              ),
                            ),
                            if (!isCollapsed)
                              Padding(
                                padding: const EdgeInsets.only(left: 14),
                                child: Column(
                                  crossAxisAlignment:
                                      CrossAxisAlignment.stretch,
                                  children: notes.map(noteRow).toList(),
                                ),
                              ),
                          ],
                        ),
                      );
                    }

                    // ── ReorderableListView — same pattern as Projects ──────
                    return ReorderableListView.builder(
                      shrinkWrap: true,
                      physics: const NeverScrollableScrollPhysics(),
                      buildDefaultDragHandles: false,
                      itemCount: effectiveOrder.length,
                      itemBuilder: (ctx, i) {
                        final key = effectiveOrder[i];
                        final child = key == standardKey
                            ? buildFolderBlock(
                                folderKey: standardKey,
                                displayName: 'Standard',
                                notes: standardNotes,
                                isStandard: true,
                                listIdx: i,
                              )
                            : buildFolderBlock(
                                folderKey: key,
                                displayName: key,
                                notes: grouped[key] ?? [],
                                listIdx: i,
                              );
                        return KeyedSubtree(
                          key: ValueKey('notes_task_folder_$key'),
                          child: child,
                        );
                      },
                      onReorder: (oldIdx, newIdx) {
                        if (newIdx > oldIdx) newIdx--;
                        // Signal parent with '__taskFolderOrder__' prefix so
                        // it updates _projectFolderOrder (same list used by
                        // both Projects and Tasks note sections).
                        widget.onReorderTaskNotes?.call([
                          '__taskFolderOrder__',
                          ...effectiveOrder,
                        ]);
                        setState(() {});
                      },
                    );
                  }(),
                ],
                const SizedBox(height: 6),
                // ── Projects header — matches _sidebarCategoryHeader style ──
                InkWell(
                  onTap: () =>
                      setState(() => _projectExpanded = !_projectExpanded),
                  hoverColor: Colors.white.withOpacity(0.03),
                  child: Container(
                    height: 40,
                    decoration: BoxDecoration(
                      color: Colors.white.withOpacity(0.05),
                      border: Border(
                        bottom: BorderSide(
                          color: const Color(0xFF2C2F32),
                          width: 0.5,
                        ),
                      ),
                    ),
                    padding: const EdgeInsets.fromLTRB(14, 0, 6, 0),
                    child: Row(
                      children: [
                        AnimatedRotation(
                          turns: _projectExpanded ? 0.25 : 0.0,
                          duration: const Duration(milliseconds: 150),
                          child: const Icon(
                            Icons.chevron_right_rounded,
                            size: 14,
                            color: Color(0xFF6B7280),
                          ),
                        ),
                        const SizedBox(width: 6),
                        Expanded(
                          child: Text(
                            'PROJECTS',
                            style: const TextStyle(
                              fontSize: 10,
                              fontWeight: FontWeight.w700,
                              color: Color(0xFF9CA3AF),
                              letterSpacing: 1.4,
                            ),
                          ),
                        ),
                        // Count badge
                        if (projectFiltered.isNotEmpty)
                          Padding(
                            padding: const EdgeInsets.only(right: 4),
                            child: Text(
                              '${projectFiltered.length}',
                              style: const TextStyle(
                                fontSize: 9,
                                color: Color(0xFF6B7280),
                              ),
                            ),
                          ),
                        // ── Add button ────────────────────────────────────
                        if (widget.onAddProject != null)
                          Tooltip(
                            message: 'New Project',
                            waitDuration: const Duration(milliseconds: 500),
                            child: InkWell(
                              onTap: widget.onAddProject,
                              borderRadius: BorderRadius.circular(5),
                              hoverColor: Colors.white.withOpacity(0.07),
                              child: const Padding(
                                padding: EdgeInsets.all(5),
                                child: Icon(
                                  Icons.add_rounded,
                                  size: 13,
                                  color: Color(0xFF6B7280),
                                ),
                              ),
                            ),
                          ),
                        // ── Sort button ───────────────────────────────────
                        Tooltip(
                          message: 'Sort projects',
                          waitDuration: const Duration(milliseconds: 500),
                          child: InkWell(
                            onTap: () async {
                              final box =
                                  context.findRenderObject() as RenderBox?;
                              if (box == null) return;
                              final pos = box.localToGlobal(Offset.zero);
                              const fields = [
                                ('name', 'Name'),
                                ('taskCount', 'Task Count'),
                              ];
                              final picked = await showMenu<String>(
                                context: context,
                                color: const Color(0xFF1E2124),
                                shape: RoundedRectangleBorder(
                                  borderRadius: BorderRadius.circular(8),
                                  side: const BorderSide(
                                    color: Color(0xFF2C2F35),
                                  ),
                                ),
                                position: RelativeRect.fromLTRB(
                                  pos.dx + box.size.width - 180,
                                  pos.dy + 48,
                                  pos.dx + box.size.width,
                                  pos.dy + 48,
                                ),
                                items: [
                                  ...fields.map(
                                    (f) => PopupMenuItem<String>(
                                      value: 'field:${f.$1}',
                                      height: 34,
                                      child: Row(
                                        children: [
                                          Icon(
                                            _noteProjectSortField == f.$1
                                                ? Icons.radio_button_checked
                                                : Icons.radio_button_unchecked,
                                            size: 13,
                                            color: _noteProjectSortField == f.$1
                                                ? const Color(0xFF4FC3F7)
                                                : Colors.white38,
                                          ),
                                          const SizedBox(width: 8),
                                          Text(
                                            f.$2,
                                            style: TextStyle(
                                              fontSize: 12,
                                              color:
                                                  _noteProjectSortField == f.$1
                                                  ? Colors.white
                                                  : Colors.white70,
                                            ),
                                          ),
                                        ],
                                      ),
                                    ),
                                  ),
                                  const PopupMenuDivider(height: 8),
                                  PopupMenuItem<String>(
                                    value: 'dir:asc',
                                    height: 34,
                                    child: Row(
                                      children: [
                                        Icon(
                                          _noteProjectSortAsc
                                              ? Icons.radio_button_checked
                                              : Icons.radio_button_unchecked,
                                          size: 13,
                                          color: _noteProjectSortAsc
                                              ? const Color(0xFF4FC3F7)
                                              : Colors.white38,
                                        ),
                                        const SizedBox(width: 8),
                                        Text(
                                          'Ascending',
                                          style: TextStyle(
                                            fontSize: 12,
                                            color: _noteProjectSortAsc
                                                ? Colors.white
                                                : Colors.white70,
                                          ),
                                        ),
                                      ],
                                    ),
                                  ),
                                  PopupMenuItem<String>(
                                    value: 'dir:desc',
                                    height: 34,
                                    child: Row(
                                      children: [
                                        Icon(
                                          !_noteProjectSortAsc
                                              ? Icons.radio_button_checked
                                              : Icons.radio_button_unchecked,
                                          size: 13,
                                          color: !_noteProjectSortAsc
                                              ? const Color(0xFF4FC3F7)
                                              : Colors.white38,
                                        ),
                                        const SizedBox(width: 8),
                                        Text(
                                          'Descending',
                                          style: TextStyle(
                                            fontSize: 12,
                                            color: !_noteProjectSortAsc
                                                ? Colors.white
                                                : Colors.white70,
                                          ),
                                        ),
                                      ],
                                    ),
                                  ),
                                ],
                              );
                              if (picked == null) return;
                              setState(() {
                                if (picked.startsWith('field:')) {
                                  _noteProjectSortField = picked.substring(6);
                                } else if (picked == 'dir:asc') {
                                  _noteProjectSortAsc = true;
                                } else if (picked == 'dir:desc') {
                                  _noteProjectSortAsc = false;
                                }
                              });
                            },
                            borderRadius: BorderRadius.circular(5),
                            hoverColor: Colors.white.withOpacity(0.07),
                            child: Padding(
                              padding: const EdgeInsets.all(5),
                              child: Icon(
                                Icons.sort_rounded,
                                size: 13,
                                color:
                                    (_noteProjectSortField != 'name' ||
                                        !_noteProjectSortAsc)
                                    ? const Color(0xFF4FC3F7)
                                    : const Color(0xFF6B7280),
                              ),
                            ),
                          ),
                        ),
                        // ── Settings button ───────────────────────────────
                        if (widget.onProjectSettings != null)
                          Tooltip(
                            message: 'Projects Settings',
                            waitDuration: const Duration(milliseconds: 500),
                            child: InkWell(
                              onTap: widget.onProjectSettings,
                              borderRadius: BorderRadius.circular(5),
                              hoverColor: Colors.white.withOpacity(0.07),
                              child: const Padding(
                                padding: EdgeInsets.all(5),
                                child: Icon(
                                  Icons.settings_outlined,
                                  size: 13,
                                  color: Color(0xFF6B7280),
                                ),
                              ),
                            ),
                          ),
                        const SizedBox(width: 2),
                      ],
                    ),
                  ),
                ),
                if (_projectExpanded) ...[
                  // ── Mirror Tasks sidebar folder logic ──────────────────────
                  // Notes are grouped by their linkedProjectId's folder membership.
                  // The folder order, collapse state, and drag-handle reordering
                  // all match the Tasks sidebar Projects section exactly.
                  () {
                    const accent = Color(0xFF4FC3F7);
                    const folderYellow = Color(0xFFEBCB8B);
                    const standardKey = '__standard__';

                    // Apply sort to projectFiltered before grouping.
                    projectFiltered.sort((a, b) {
                      int cmp;
                      if (_noteProjectSortField == 'taskCount') {
                        final ca = widget.allTasks
                            .where((t) => t.projectId == a.linkedProjectId)
                            .length;
                        final cb = widget.allTasks
                            .where((t) => t.projectId == b.linkedProjectId)
                            .length;
                        cmp = ca.compareTo(cb);
                      } else {
                        cmp = a.title.toLowerCase().compareTo(
                          b.title.toLowerCase(),
                        );
                      }
                      return _noteProjectSortAsc ? cmp : -cmp;
                    });

                    // Build lookup: projectId → folder name
                    final pidToFolder = <String, String>{};
                    for (final entry in widget.projectFolders.entries) {
                      for (final pid in entry.value) {
                        pidToFolder[pid] = entry.key;
                      }
                    }

                    // Group notes: folderName → [Note]  (null key = Standard)
                    final Map<String, List<Note>> grouped = {};
                    final List<Note> standardNotes = [];
                    for (final note in projectFiltered) {
                      final pid = note.linkedProjectId;
                      if (pid != null && pidToFolder.containsKey(pid)) {
                        final fn = pidToFolder[pid]!;
                        grouped.putIfAbsent(fn, () => []).add(note);
                      } else {
                        standardNotes.add(note);
                      }
                    }

                    // Determine the effective folder order.
                    final allFolderKeys = <String>[
                      ...widget.projectFolders.keys,
                      if (standardNotes.isNotEmpty) standardKey,
                    ];
                    final reconciled = <String>[
                      ...widget.projectFolderOrder.where(
                        allFolderKeys.contains,
                      ),
                      ...allFolderKeys.where(
                        (k) => !widget.projectFolderOrder.contains(k),
                      ),
                    ];
                    final effectiveOrder = reconciled;

                    // ── Helper: render a single note row (no Draggable needed,
                    // folder membership is driven from Tasks sidebar) ──────────
                    Widget noteRow(Note note) {
                      final linkedId = note.linkedProjectId ?? '';
                      final isHidden = widget.hiddenNoteProjects.contains(
                        linkedId,
                      );
                      if (isHidden) return const SizedBox.shrink();
                      return Stack(
                        key: ValueKey('pnote_folder_${note.id}'),
                        children: [
                          noteItem(
                            note,
                            onContextMenuOverride:
                                (linkedId.isNotEmpty &&
                                    widget.onNoteProjectContextMenu != null)
                                ? (d) async => widget.onNoteProjectContextMenu!(
                                    d,
                                    linkedId,
                                  )
                                : null,
                          ),
                          Positioned(
                            right: 4,
                            top: 0,
                            bottom: 0,
                            child: Tooltip(
                              message: 'Hide from sidebar',
                              child: InkWell(
                                onTap: () => widget.onToggleProjectVisibility
                                    ?.call(linkedId),
                                child: Padding(
                                  padding: const EdgeInsets.symmetric(
                                    horizontal: 3,
                                  ),
                                  child: Icon(
                                    Icons.visibility_off_outlined,
                                    size: 11,
                                    color: Colors.white.withOpacity(0.2),
                                  ),
                                ),
                              ),
                            ),
                          ),
                        ],
                      );
                    }

                    // ── Shared folder header + children widget ─────────────
                    Widget buildFolderBlock({
                      required String folderKey,
                      required String displayName,
                      required List<Note> notes,
                      bool isStandard = false,
                      int listIdx = 0,
                    }) {
                      final isCollapsed = _collapsedNoteProjectFolders.contains(
                        folderKey,
                      );
                      // Show project name in folder header if only one project.
                      final projectIds = notes
                          .map((n) => n.linkedProjectId)
                          .whereType<String>()
                          .toSet();

                      return AnimatedContainer(
                        duration: const Duration(milliseconds: 120),
                        margin: const EdgeInsets.only(top: 1),
                        child: Column(
                          crossAxisAlignment: CrossAxisAlignment.stretch,
                          children: [
                            // ── Header row ──────────────────────────────────
                            InkWell(
                              onTap: () => setState(() {
                                if (isCollapsed) {
                                  _collapsedNoteProjectFolders.remove(
                                    folderKey,
                                  );
                                } else {
                                  _collapsedNoteProjectFolders.add(folderKey);
                                }
                              }),
                              hoverColor: Colors.white.withOpacity(0.04),
                              borderRadius: BorderRadius.circular(5),
                              child: Padding(
                                padding: const EdgeInsets.fromLTRB(
                                  12,
                                  6,
                                  10,
                                  6,
                                ),
                                child: Row(
                                  children: [
                                    // Reorder handle (for ReorderableListView)
                                    ReorderableDragStartListener(
                                      index: listIdx,
                                      child: MouseRegion(
                                        cursor: SystemMouseCursors.grab,
                                        child: Padding(
                                          padding: const EdgeInsets.only(
                                            right: 5,
                                          ),
                                          child: Icon(
                                            Icons.drag_indicator_rounded,
                                            size: 13,
                                            color: Colors.white.withOpacity(
                                              0.18,
                                            ),
                                          ),
                                        ),
                                      ),
                                    ),
                                    Icon(
                                      isCollapsed
                                          ? Icons.folder_outlined
                                          : Icons.folder_open_outlined,
                                      size: 13,
                                      color: isStandard
                                          ? Colors.white24
                                          : folderYellow,
                                    ),
                                    const SizedBox(width: 7),
                                    Expanded(
                                      child: Text(
                                        displayName,
                                        overflow: TextOverflow.ellipsis,
                                        style: TextStyle(
                                          fontSize: 11,
                                          fontWeight: FontWeight.w600,
                                          letterSpacing: isStandard ? 0.6 : 0.0,
                                          color: isStandard
                                              ? Colors.white38
                                              : Colors.white70,
                                        ),
                                      ),
                                    ),
                                    // Count badge
                                    if (notes.isNotEmpty)
                                      Text(
                                        '${notes.length}',
                                        style: const TextStyle(
                                          fontSize: 9,
                                          color: Color(0xFF6B7280),
                                        ),
                                      ),
                                    const SizedBox(width: 4),
                                    AnimatedRotation(
                                      turns: isCollapsed ? 0.0 : 0.25,
                                      duration: const Duration(
                                        milliseconds: 150,
                                      ),
                                      child: const Icon(
                                        Icons.chevron_right_rounded,
                                        size: 13,
                                        color: Color(0xFF4B5563),
                                      ),
                                    ),
                                  ],
                                ),
                              ),
                            ),
                            // ── Children (16 px left indent, matches Tasks) ──
                            if (!isCollapsed)
                              Padding(
                                padding: const EdgeInsets.only(left: 14),
                                child: Column(
                                  crossAxisAlignment:
                                      CrossAxisAlignment.stretch,
                                  children: notes.map(noteRow).toList(),
                                ),
                              ),
                          ],
                        ),
                      );
                    }

                    // ── ReorderableListView mirroring Tasks sidebar ─────────
                    return ReorderableListView.builder(
                      shrinkWrap: true,
                      physics: const NeverScrollableScrollPhysics(),
                      buildDefaultDragHandles: false,
                      itemCount: effectiveOrder.length,
                      itemBuilder: (ctx, i) {
                        final key = effectiveOrder[i];
                        final child = key == standardKey
                            ? buildFolderBlock(
                                folderKey: standardKey,
                                displayName: 'Standard',
                                notes: standardNotes,
                                isStandard: true,
                                listIdx: i,
                              )
                            : buildFolderBlock(
                                folderKey: key,
                                displayName: key,
                                notes: grouped[key] ?? [],
                                listIdx: i,
                              );
                        return KeyedSubtree(
                          key: ValueKey('notes_proj_folder_$key'),
                          child: child,
                        );
                      },
                      // Folder reordering in Notes is visual-only: the actual
                      // _projectFolderOrder is owned by the Tasks sidebar state.
                      // We notify the parent so it can persist the change.
                      onReorder: (oldIdx, newIdx) {
                        if (newIdx > oldIdx) newIdx--;
                        widget.onReorderProjectNotes?.call(
                          // Encode the new folder order as a special signal
                          // prefixed with '__folderOrder__' so the parent can
                          // distinguish it from a note-ID list.
                          // The parent (_buildNotesNavContent onReorderProjectNotes)
                          // already calls _saveWorkspace, so no extra call needed.
                          ['__folderOrder__', ...effectiveOrder],
                        );
                        setState(() {});
                      },
                    );
                  }(),
                ],
                const SizedBox(height: 6),
                // ── Notes header — matches Projects header style ──────────
                InkWell(
                  onTap: () =>
                      setState(() => _commonExpanded = !_commonExpanded),
                  hoverColor: Colors.white.withOpacity(0.03),
                  child: Container(
                    height: 40,
                    decoration: BoxDecoration(
                      color: Colors.white.withOpacity(0.05),
                      border: Border(
                        bottom: BorderSide(
                          color: const Color(0xFF2C2F32),
                          width: 0.5,
                        ),
                      ),
                    ),
                    padding: const EdgeInsets.fromLTRB(14, 0, 6, 0),
                    child: Row(
                      children: [
                        AnimatedRotation(
                          turns: _commonExpanded ? 0.25 : 0.0,
                          duration: const Duration(milliseconds: 150),
                          child: const Icon(
                            Icons.chevron_right_rounded,
                            size: 14,
                            color: Color(0xFF6B7280),
                          ),
                        ),
                        const SizedBox(width: 6),
                        Expanded(
                          child: Text(
                            'NOTES',
                            style: const TextStyle(
                              fontSize: 10,
                              fontWeight: FontWeight.w700,
                              color: Color(0xFF9CA3AF),
                              letterSpacing: 1.4,
                            ),
                          ),
                        ),
                        // Count badge
                        if (commonFiltered.isNotEmpty)
                          Padding(
                            padding: const EdgeInsets.only(right: 4),
                            child: Text(
                              '${commonFiltered.length}',
                              style: const TextStyle(
                                fontSize: 9,
                                color: Color(0xFF6B7280),
                              ),
                            ),
                          ),
                        // ── Add button ──────────────────────────────────
                        Tooltip(
                          message: 'New Note',
                          waitDuration: const Duration(milliseconds: 500),
                          child: InkWell(
                            onTap: widget.onNewNote,
                            borderRadius: BorderRadius.circular(5),
                            hoverColor: Colors.white.withOpacity(0.07),
                            child: const Padding(
                              padding: EdgeInsets.all(5),
                              child: Icon(
                                Icons.add_rounded,
                                size: 13,
                                color: Color(0xFF6B7280),
                              ),
                            ),
                          ),
                        ),
                        // ── Sort button ─────────────────────────────────
                        Tooltip(
                          message: 'Sort notes',
                          waitDuration: const Duration(milliseconds: 500),
                          child: InkWell(
                            onTap: () async {
                              final box =
                                  context.findRenderObject() as RenderBox?;
                              if (box == null) return;
                              final pos = box.localToGlobal(Offset.zero);
                              const fields = [
                                ('name', 'Name'),
                                ('updated', 'Last Updated'),
                              ];
                              final picked = await showMenu<String>(
                                context: context,
                                color: const Color(0xFF1E2124),
                                shape: RoundedRectangleBorder(
                                  borderRadius: BorderRadius.circular(8),
                                  side: const BorderSide(
                                    color: Color(0xFF2C2F35),
                                  ),
                                ),
                                position: RelativeRect.fromLTRB(
                                  pos.dx + box.size.width - 180,
                                  pos.dy + 48,
                                  pos.dx + box.size.width,
                                  pos.dy + 48,
                                ),
                                items: [
                                  ...fields.map(
                                    (f) => PopupMenuItem<String>(
                                      value: 'field:${f.$1}',
                                      height: 34,
                                      child: Row(
                                        children: [
                                          Icon(
                                            _noteCommonSortField == f.$1
                                                ? Icons.radio_button_checked
                                                : Icons.radio_button_unchecked,
                                            size: 13,
                                            color: _noteCommonSortField == f.$1
                                                ? const Color(0xFF4FC3F7)
                                                : Colors.white38,
                                          ),
                                          const SizedBox(width: 8),
                                          Text(
                                            f.$2,
                                            style: TextStyle(
                                              fontSize: 12,
                                              color:
                                                  _noteCommonSortField == f.$1
                                                  ? Colors.white
                                                  : Colors.white70,
                                            ),
                                          ),
                                        ],
                                      ),
                                    ),
                                  ),
                                  const PopupMenuDivider(height: 8),
                                  PopupMenuItem<String>(
                                    value: 'dir:asc',
                                    height: 34,
                                    child: Row(
                                      children: [
                                        Icon(
                                          _noteCommonSortAsc
                                              ? Icons.radio_button_checked
                                              : Icons.radio_button_unchecked,
                                          size: 13,
                                          color: _noteCommonSortAsc
                                              ? const Color(0xFF4FC3F7)
                                              : Colors.white38,
                                        ),
                                        const SizedBox(width: 8),
                                        Text(
                                          'Ascending',
                                          style: TextStyle(
                                            fontSize: 12,
                                            color: _noteCommonSortAsc
                                                ? Colors.white
                                                : Colors.white70,
                                          ),
                                        ),
                                      ],
                                    ),
                                  ),
                                  PopupMenuItem<String>(
                                    value: 'dir:desc',
                                    height: 34,
                                    child: Row(
                                      children: [
                                        Icon(
                                          !_noteCommonSortAsc
                                              ? Icons.radio_button_checked
                                              : Icons.radio_button_unchecked,
                                          size: 13,
                                          color: !_noteCommonSortAsc
                                              ? const Color(0xFF4FC3F7)
                                              : Colors.white38,
                                        ),
                                        const SizedBox(width: 8),
                                        Text(
                                          'Descending',
                                          style: TextStyle(
                                            fontSize: 12,
                                            color: !_noteCommonSortAsc
                                                ? Colors.white
                                                : Colors.white70,
                                          ),
                                        ),
                                      ],
                                    ),
                                  ),
                                ],
                              );
                              if (picked == null) return;
                              setState(() {
                                if (picked.startsWith('field:')) {
                                  _noteCommonSortField = picked.substring(6);
                                } else if (picked == 'dir:asc') {
                                  _noteCommonSortAsc = true;
                                } else if (picked == 'dir:desc') {
                                  _noteCommonSortAsc = false;
                                }
                              });
                            },
                            borderRadius: BorderRadius.circular(5),
                            hoverColor: Colors.white.withOpacity(0.07),
                            child: Padding(
                              padding: const EdgeInsets.all(5),
                              child: Icon(
                                Icons.sort_rounded,
                                size: 13,
                                color:
                                    (_noteCommonSortField != 'name' ||
                                        !_noteCommonSortAsc)
                                    ? const Color(0xFF4FC3F7)
                                    : const Color(0xFF6B7280),
                              ),
                            ),
                          ),
                        ),
                        // ── Settings button ─────────────────────────────
                        if (widget.onNotesSettings != null)
                          Tooltip(
                            message: 'Notes Settings',
                            waitDuration: const Duration(milliseconds: 500),
                            child: InkWell(
                              onTap: widget.onNotesSettings,
                              borderRadius: BorderRadius.circular(5),
                              hoverColor: Colors.white.withOpacity(0.07),
                              child: const Padding(
                                padding: EdgeInsets.all(5),
                                child: Icon(
                                  Icons.settings_outlined,
                                  size: 13,
                                  color: Color(0xFF6B7280),
                                ),
                              ),
                            ),
                          ),
                        const SizedBox(width: 2),
                      ],
                    ),
                  ),
                ),
                if (_commonExpanded) ...[
                  // ── Folders + Standard — single unified reorderable list ──
                  ReorderableListView.builder(
                    shrinkWrap: true,
                    physics: const NeverScrollableScrollPhysics(),
                    buildDefaultDragHandles: false,
                    itemCount: _notesEffectiveOrder.length,
                    itemBuilder: (ctx, listIdx) {
                      final fid = _notesEffectiveOrder[listIdx];

                      // ── Standard folder slot ───────────────────────────────
                      if (fid == _kStandard) {
                        final unfoldered = _noteOrder
                            .map(
                              (id) => widget.commonNotes.firstWhere(
                                (n) => n.id == id,
                                orElse: () => Note(
                                  id: id,
                                  type: NoteType.common,
                                  title: '',
                                  content: '',
                                ),
                              ),
                            )
                            .where(
                              (n) =>
                                  n.folderId == null &&
                                  (_search.isEmpty ||
                                      n.title.toLowerCase().contains(
                                        _search.toLowerCase(),
                                      ) ||
                                      n.content.toLowerCase().contains(
                                        _search.toLowerCase(),
                                      )),
                            )
                            .where((n) => n.title.isNotEmpty)
                            .toList();
                        unfoldered.sort((a, b) {
                          int cmp;
                          if (_noteCommonSortField == 'updated') {
                            cmp = a.title.toLowerCase().compareTo(
                              b.title.toLowerCase(),
                            );
                          } else {
                            cmp = a.title.toLowerCase().compareTo(
                              b.title.toLowerCase(),
                            );
                          }
                          return _noteCommonSortAsc ? cmp : -cmp;
                        });
                        return KeyedSubtree(
                          key: const ValueKey('note_folder___standard__'),
                          child: AnimatedContainer(
                            duration: const Duration(milliseconds: 120),
                            margin: const EdgeInsets.only(top: 1),
                            child: Column(
                              crossAxisAlignment: CrossAxisAlignment.stretch,
                              children: [
                                InkWell(
                                  onTap: () => setState(
                                    () => _notesStandardExpanded =
                                        !_notesStandardExpanded,
                                  ),
                                  hoverColor: Colors.white.withOpacity(0.04),
                                  borderRadius: BorderRadius.circular(5),
                                  child: Padding(
                                    padding: const EdgeInsets.fromLTRB(
                                      12,
                                      6,
                                      10,
                                      6,
                                    ),
                                    child: Row(
                                      children: [
                                        ReorderableDragStartListener(
                                          index: listIdx,
                                          child: MouseRegion(
                                            cursor: SystemMouseCursors.grab,
                                            child: Padding(
                                              padding: const EdgeInsets.only(
                                                right: 5,
                                              ),
                                              child: Icon(
                                                Icons.drag_indicator_rounded,
                                                size: 13,
                                                color: Colors.white.withOpacity(
                                                  0.18,
                                                ),
                                              ),
                                            ),
                                          ),
                                        ),
                                        Icon(
                                          _notesStandardExpanded
                                              ? Icons.folder_open_outlined
                                              : Icons.folder_outlined,
                                          size: 13,
                                          color: Colors.white24,
                                        ),
                                        const SizedBox(width: 7),
                                        Expanded(
                                          child: Text(
                                            'Standard',
                                            overflow: TextOverflow.ellipsis,
                                            style: const TextStyle(
                                              fontSize: 11,
                                              fontWeight: FontWeight.w600,
                                              letterSpacing: 0.6,
                                              color: Colors.white38,
                                            ),
                                          ),
                                        ),
                                        if (unfoldered.isNotEmpty)
                                          Text(
                                            '${unfoldered.length}',
                                            style: const TextStyle(
                                              fontSize: 9,
                                              color: Color(0xFF6B7280),
                                            ),
                                          ),
                                        const SizedBox(width: 4),
                                        AnimatedRotation(
                                          turns: _notesStandardExpanded
                                              ? 0.25
                                              : 0.0,
                                          duration: const Duration(
                                            milliseconds: 150,
                                          ),
                                          child: const Icon(
                                            Icons.chevron_right_rounded,
                                            size: 13,
                                            color: Color(0xFF4B5563),
                                          ),
                                        ),
                                      ],
                                    ),
                                  ),
                                ),
                                if (_notesStandardExpanded &&
                                    unfoldered.isNotEmpty)
                                  Padding(
                                    padding: const EdgeInsets.only(left: 14),
                                    child: SizedBox(
                                      height: unfoldered.length * 32.0,
                                      child: ReorderableListView.builder(
                                        shrinkWrap: true,
                                        physics:
                                            const NeverScrollableScrollPhysics(),
                                        buildDefaultDragHandles: false,
                                        itemCount: unfoldered.length,
                                        onReorder: (oldIdx, newIdx) {
                                          setState(() {
                                            if (newIdx > oldIdx) newIdx--;
                                            final movedId =
                                                unfoldered[oldIdx].id;
                                            final globalOld = _noteOrder
                                                .indexOf(movedId);
                                            if (globalOld < 0) return;
                                            _noteOrder.removeAt(globalOld);
                                            if (newIdx >= unfoldered.length) {
                                              _noteOrder.add(movedId);
                                            } else {
                                              final anchorId =
                                                  unfoldered[newIdx].id;
                                              final globalNew = _noteOrder
                                                  .indexOf(anchorId);
                                              _noteOrder.insert(
                                                globalNew < 0
                                                    ? _noteOrder.length
                                                    : globalNew,
                                                movedId,
                                              );
                                            }
                                          });
                                          widget.onReorderNotes?.call(
                                            List.unmodifiable(_noteOrder),
                                          );
                                        },
                                        itemBuilder: (_, i) {
                                          final n = unfoldered[i];
                                          return ReorderableDragStartListener(
                                            key: ValueKey(n.id),
                                            index: i,
                                            child: _noteItemWithContext(
                                              n,
                                              noteItem,
                                              widget.noteFolders,
                                              widget.onAssignFolder,
                                            ),
                                          );
                                        },
                                      ),
                                    ),
                                  ),
                              ],
                            ),
                          ),
                        );
                      }

                      // ── Named folder slot ──────────────────────────────────
                      final folder = widget.noteFolders[fid];
                      if (folder == null) {
                        return SizedBox.shrink(
                          key: ValueKey('note_folder_missing_$fid'),
                        );
                      }
                      final folderNotes = commonFiltered
                          .where((n) => n.folderId == folder.id)
                          .toList();
                      final expanded = _folderExpanded[folder.id] ?? true;
                      return KeyedSubtree(
                        key: ValueKey('note_folder_$fid'),
                        child: DragTarget<Note>(
                          onWillAcceptWithDetails: (d) =>
                              d.data.folderId != folder.id,
                          onAcceptWithDetails: (d) =>
                              widget.onAssignFolder(d.data.id, folder.id),
                          builder: (ctx, candidateData, _) {
                            final isOver = candidateData.isNotEmpty;
                            return AnimatedContainer(
                              duration: const Duration(milliseconds: 100),
                              decoration: isOver
                                  ? BoxDecoration(
                                      color: const Color(
                                        0xFF4FC3F7,
                                      ).withOpacity(0.08),
                                      borderRadius: BorderRadius.circular(6),
                                      border: Border.all(
                                        color: const Color(
                                          0xFF4FC3F7,
                                        ).withOpacity(0.35),
                                        width: 1,
                                      ),
                                    )
                                  : const BoxDecoration(),
                              child: Column(
                                crossAxisAlignment: CrossAxisAlignment.stretch,
                                children: [
                                  GestureDetector(
                                    onSecondaryTapDown: (d) async {
                                      final action = await showMenu<String>(
                                        context: context,
                                        position: RelativeRect.fromLTRB(
                                          d.globalPosition.dx,
                                          d.globalPosition.dy,
                                          d.globalPosition.dx + 1,
                                          d.globalPosition.dy + 1,
                                        ),
                                        items: [
                                          const PopupMenuItem(
                                            value: 'filter_group_sort',
                                            child: Row(
                                              children: [
                                                Icon(
                                                  Icons.filter_list,
                                                  size: 14,
                                                  color: Color(0xFF4FC3F7),
                                                ),
                                                SizedBox(width: 8),
                                                Text(
                                                  'Filter / Group / Sort',
                                                  style: TextStyle(
                                                    color: Color(0xFF4FC3F7),
                                                  ),
                                                ),
                                              ],
                                            ),
                                          ),
                                          const PopupMenuItem(
                                            value: 'rename',
                                            child: Text('Rename folder'),
                                          ),
                                          const PopupMenuItem(
                                            value: 'delete',
                                            child: Text('Delete folder'),
                                          ),
                                        ],
                                      );
                                      if (action == 'filter_group_sort') {
                                        widget.onFilterGroupSort(
                                          'Folder: ${folder.name}',
                                        );
                                      } else if (action == 'rename') {
                                        final ctrl = TextEditingController(
                                          text: folder.name,
                                        );
                                        final name = await showDialog<String>(
                                          context: context,
                                          builder: (ctx) => AlertDialog(
                                            backgroundColor: const Color(
                                              0xFF2E3440,
                                            ),
                                            title: const Text(
                                              'Rename Folder',
                                              style: TextStyle(
                                                color: Colors.white,
                                                fontSize: 14,
                                              ),
                                            ),
                                            content: TextField(
                                              controller: ctrl,
                                              autofocus: true,
                                              style: const TextStyle(
                                                color: Colors.white,
                                              ),
                                              onSubmitted: (v) => Navigator.of(
                                                ctx,
                                              ).pop(v.trim()),
                                              decoration: const InputDecoration(
                                                enabledBorder:
                                                    UnderlineInputBorder(
                                                      borderSide: BorderSide(
                                                        color: Colors.white24,
                                                      ),
                                                    ),
                                              ),
                                            ),
                                            actions: [
                                              TextButton(
                                                onPressed: () =>
                                                    Navigator.of(ctx).pop(),
                                                child: const Text(
                                                  'Cancel',
                                                  style: TextStyle(
                                                    color: Colors.white54,
                                                  ),
                                                ),
                                              ),
                                              TextButton(
                                                onPressed: () => Navigator.of(
                                                  ctx,
                                                ).pop(ctrl.text.trim()),
                                                child: const Text(
                                                  'Rename',
                                                  style: TextStyle(
                                                    color: Color(0xFF88C0D0),
                                                  ),
                                                ),
                                              ),
                                            ],
                                          ),
                                        );
                                        if (name != null && name.isNotEmpty) {
                                          widget.onRenameFolder(
                                            folder.id,
                                            name,
                                          );
                                        }
                                      } else if (action == 'delete') {
                                        widget.onDeleteFolder(folder.id);
                                      }
                                    },
                                    child: InkWell(
                                      onTap: () => setState(
                                        () => _folderExpanded[folder.id] =
                                            !expanded,
                                      ),
                                      hoverColor: Colors.white.withOpacity(
                                        0.04,
                                      ),
                                      borderRadius: BorderRadius.circular(5),
                                      child: Padding(
                                        padding: const EdgeInsets.fromLTRB(
                                          12,
                                          6,
                                          10,
                                          6,
                                        ),
                                        child: Row(
                                          children: [
                                            // Drag handle
                                            ReorderableDragStartListener(
                                              index: listIdx,
                                              child: MouseRegion(
                                                cursor: SystemMouseCursors.grab,
                                                child: Padding(
                                                  padding:
                                                      const EdgeInsets.only(
                                                        right: 5,
                                                      ),
                                                  child: Icon(
                                                    Icons
                                                        .drag_indicator_rounded,
                                                    size: 13,
                                                    color: Colors.white
                                                        .withOpacity(0.18),
                                                  ),
                                                ),
                                              ),
                                            ),
                                            Icon(
                                              expanded
                                                  ? Icons.folder_open_outlined
                                                  : Icons.folder_outlined,
                                              size: 13,
                                              color: isOver
                                                  ? const Color(0xFF4FC3F7)
                                                  : _nordYellow,
                                            ),
                                            const SizedBox(width: 7),
                                            Expanded(
                                              child: Text(
                                                folder.name,
                                                overflow: TextOverflow.ellipsis,
                                                style: TextStyle(
                                                  fontSize: 11,
                                                  fontWeight: FontWeight.w600,
                                                  color: isOver
                                                      ? const Color(0xFF4FC3F7)
                                                      : Colors.white70,
                                                ),
                                              ),
                                            ),
                                            if (folderNotes.isNotEmpty)
                                              Text(
                                                '${folderNotes.length}',
                                                style: const TextStyle(
                                                  fontSize: 9,
                                                  color: Color(0xFF6B7280),
                                                ),
                                              ),
                                            const SizedBox(width: 4),
                                            AnimatedRotation(
                                              turns: expanded ? 0.25 : 0.0,
                                              duration: const Duration(
                                                milliseconds: 150,
                                              ),
                                              child: const Icon(
                                                Icons.chevron_right_rounded,
                                                size: 13,
                                                color: Color(0xFF4B5563),
                                              ),
                                            ),
                                          ],
                                        ),
                                      ),
                                    ),
                                  ),
                                  // Note items inside folder, each Draggable
                                  // 14 px left indent matches Projects section style
                                  if (expanded)
                                    Padding(
                                      padding: const EdgeInsets.only(left: 14),
                                      child: Column(
                                        crossAxisAlignment:
                                            CrossAxisAlignment.stretch,
                                        children: folderNotes.map((n) {
                                          final item = _noteItemWithContext(
                                            n,
                                            noteItem,
                                            widget.noteFolders,
                                            widget.onAssignFolder,
                                          );
                                          return Draggable<Note>(
                                            data: n,
                                            feedback: Material(
                                              color: Colors.transparent,
                                              child: Container(
                                                padding:
                                                    const EdgeInsets.symmetric(
                                                      horizontal: 10,
                                                      vertical: 5,
                                                    ),
                                                decoration: BoxDecoration(
                                                  color: const Color(
                                                    0xFF2E3440,
                                                  ),
                                                  borderRadius:
                                                      BorderRadius.circular(6),
                                                  border: Border.all(
                                                    color: const Color(
                                                      0xFF4FC3F7,
                                                    ).withOpacity(0.5),
                                                  ),
                                                ),
                                                child: Row(
                                                  mainAxisSize:
                                                      MainAxisSize.min,
                                                  children: [
                                                    const Icon(
                                                      Icons.article_outlined,
                                                      size: 12,
                                                      color: Color(0xFF88C0D0),
                                                    ),
                                                    const SizedBox(width: 6),
                                                    Text(
                                                      n.title.isNotEmpty
                                                          ? n.title
                                                          : 'Untitled',
                                                      style: const TextStyle(
                                                        fontSize: 12,
                                                        color: Color(
                                                          0xFFD8DEE9,
                                                        ),
                                                      ),
                                                    ),
                                                  ],
                                                ),
                                              ),
                                            ),
                                            childWhenDragging: Opacity(
                                              opacity: 0.3,
                                              child: item,
                                            ),
                                            child: item,
                                          );
                                        }).toList(),
                                      ),
                                    ),
                                ],
                              ),
                            );
                          },
                        ),
                      );
                    },
                    onReorder: (oldIdx, newIdx) {
                      setState(() {
                        if (newIdx > oldIdx) newIdx--;
                        final moved = _notesEffectiveOrder.removeAt(oldIdx);
                        _notesEffectiveOrder.insert(newIdx, moved);
                        // Keep _localNoteFolderOrder in sync (named folders only)
                        _localNoteFolderOrder = _notesEffectiveOrder
                            .where((id) => id != _kStandard)
                            .toList();
                      });
                      widget.onReorderNoteFolders?.call(
                        List<String>.from(_localNoteFolderOrder),
                      );
                    },
                  ),
                ],
              ],
            ),
          ),
        ],
      ),
    );
  }
}

// ─────────────────────────────────────────────────────────────────────────────
// Helper: wraps a note item with a right-click context menu for folder assignment
class _NoteItemWithContext extends StatelessWidget {
  final Note note;
  final Widget Function(Note) noteItem;
  final Map<String, NoteFolder> folders;
  final void Function(String noteId, String? folderId) onAssign;

  const _NoteItemWithContext({
    required this.note,
    required this.noteItem,
    required this.folders,
    required this.onAssign,
  });

  @override
  Widget build(BuildContext context) {
    if (note.type != NoteType.common || folders.isEmpty) return noteItem(note);
    return GestureDetector(
      onSecondaryTapDown: (d) async {
        final items = <PopupMenuEntry<String>>[
          const PopupMenuItem(
            value: '__none__',
            child: Text('Remove from folder'),
          ),
          const PopupMenuDivider(),
          ...folders.values.map(
            (f) =>
                PopupMenuItem(value: f.id, child: Text('Move to: ${f.name}')),
          ),
        ];
        final chosen = await showMenu<String>(
          context: context,
          position: RelativeRect.fromLTRB(
            d.globalPosition.dx,
            d.globalPosition.dy,
            d.globalPosition.dx + 1,
            d.globalPosition.dy + 1,
          ),
          items: items,
        );
        if (chosen == null) return;
        onAssign(note.id, chosen == '__none__' ? null : chosen);
      },
      child: noteItem(note),
    );
  }
}

Widget _noteItemWithContext(
  Note note,
  Widget Function(Note) noteItem,
  Map<String, NoteFolder> folders,
  void Function(String noteId, String? folderId) onAssign,
) {
  return _NoteItemWithContext(
    note: note,
    noteItem: noteItem,
    folders: folders,
    onAssign: onAssign,
  );
}

// _NotesEditor  —  Nord editor with live highlighting, reading mode, folding
// ─────────────────────────────────────────────────────────────────────────────

class _NotesEditor extends StatefulWidget {
  final Note? note;
  final Map<String, Project> projects;
  final Map<String, String> projectIcons;
  final List<Task> allTasks;
  final void Function(Note note) onNoteChanged;
  final VoidCallback? onDeleteNote;

  /// Called when the user collapses or expands a heading.  Receives the note
  /// id and the updated list of folded heading texts.  The parent uses this
  /// to persist fold state without rewriting the .md file.
  final void Function(String noteId, List<String> headings)? onFoldsChanged;

  /// Returns true when [newTitle] is already used by another common note.
  /// [currentId] is the note being renamed and must be excluded from the check.
  final bool Function(String newTitle, String currentId)? isTitleTaken;

  const _NotesEditor({
    Key? key,
    required this.note,
    required this.projects,
    required this.projectIcons,
    required this.allTasks,
    required this.onNoteChanged,
    this.onDeleteNote,
    this.isTitleTaken,
    this.onFoldsChanged,
  }) : super(key: key);

  @override
  State<_NotesEditor> createState() => _NotesEditorState();
}

// ─────────────────────────────────────────────────────────────────────────────
// _NotesEditorState — Obsidian-style single-document live-preview editor.
//
// Architecture (CM6-inspired):
//   ONE _SpLiveMarkdownController  → holds the full markdown as a flat string.
//   ONE FocusNode                  → no per-block focus transfers.
//   ONE TextField(maxLines:null)   → no block list, no widget-per-paragraph.
//
// All decoration logic lives in _SpLiveMarkdownController.buildTextSpan which
// runs on every cursor move, toggling marker visibility based on the single
// integer cursor offset — exactly the CM6 ViewPlugin update() loop.
// ─────────────────────────────────────────────────────────────────────────────

class _NotesEditorState extends State<_NotesEditor> {
  // ── Title ─────────────────────────────────────────────────────────────────
  late final TextEditingController _titleCtrl;
  final FocusNode _titleFocusNode = FocusNode();
  bool _titleLocked = true;

  /// Non-null when the last save attempt was blocked by a duplicate title.
  String? _titleError;

  // ── Document — single controller, single focus node ───────────────────────
  final _SpLiveMarkdownController _ctrl = _SpLiveMarkdownController();
  final FocusNode _focus = FocusNode();

  // ── Mode ──────────────────────────────────────────────────────────────────
  bool _readingMode = false;

  // ── Gutter hover — mouse Y within the body Row, null when outside ──────────
  double? _gutterHoverY;

  // ── Reading mode hover — lineOffset of the hovered heading, null when none ──
  int? _readingHoveredLineOffset;

  // ── Save debounce ─────────────────────────────────────────────────────────
  Timer? _saveDebounce;

  @override
  void initState() {
    super.initState();
    final note = widget.note;
    _titleCtrl = TextEditingController(text: note?.title ?? '');
    _titleLocked =
        note != null &&
        (note.type == NoteType.task || note.type == NoteType.project);
    _ctrl.resetContent(note?.content ?? '');
    if (note != null && note.collapsedHeadings.isNotEmpty) {
      _ctrl.restoreFolds(note.collapsedHeadings);
    }
    _ctrl.addListener(_onDocChanged);
    _titleCtrl.addListener(_onTitleTextChanged);
    _titleFocusNode.addListener(() {
      if (!_titleFocusNode.hasFocus) _save();
    });
  }

  void _onTitleTextChanged() {
    if (_titleError != null) setState(() => _titleError = null);
  }

  @override
  void didUpdateWidget(_NotesEditor old) {
    super.didUpdateWidget(old);
    if (old.note?.id != widget.note?.id) {
      _titleCtrl.text = widget.note?.title ?? '';
      _titleLocked =
          widget.note != null &&
          (widget.note!.type == NoteType.task ||
              widget.note!.type == NoteType.project);
      _titleError = null;
      // Swap content without triggering a spurious save.
      _ctrl.removeListener(_onDocChanged);
      _ctrl.resetContent(widget.note?.content ?? '');
      // Restore persisted heading folds for the new note.
      final newNote = widget.note;
      if (newNote != null && newNote.collapsedHeadings.isNotEmpty) {
        _ctrl.restoreFolds(newNote.collapsedHeadings);
      }
      _ctrl.addListener(_onDocChanged);
      // Fold state is already cleared by resetContent().
    }
  }

  @override
  void dispose() {
    _saveDebounce?.cancel();
    _titleCtrl.removeListener(_onTitleTextChanged);
    _titleCtrl.dispose();
    _titleFocusNode.dispose();
    _ctrl.removeListener(_onDocChanged);
    _ctrl.dispose();
    _focus.dispose();
    super.dispose();
  }

  // ── Save ──────────────────────────────────────────────────────────────────

  void _onDocChanged() {
    // setState rebuilds the gutter widget, which reads the backing text.
    if (mounted) setState(() {});
    _saveDebounce?.cancel();
    _saveDebounce = Timer(const Duration(milliseconds: 350), _save);
  }

  void _save() {
    _saveDebounce?.cancel();
    final note = widget.note;
    if (note == null) return;
    // ── Duplicate-name guard (common notes only) ───────────────────────────
    if (!_titleLocked && note.type == NoteType.common) {
      final candidate = _titleCtrl.text.trim();
      if (candidate.isNotEmpty &&
          candidate != note.title &&
          (widget.isTitleTaken?.call(candidate, note.id) ?? false)) {
        // Revert the title field to the last saved name and surface an error.
        setState(() {
          _titleCtrl.text = note.title;
          _titleCtrl.selection = TextSelection.collapsed(
            offset: note.title.length,
          );
          _titleError = 'A note named "$candidate" already exists.';
        });
        return;
      }
    }
    note.title = _titleLocked ? note.title : _titleCtrl.text;
    note.content = _ctrl.backingText; // always persist the full document
    note.updatedAt = DateTime.now();
    widget.onNoteChanged(note);
  }

  // ── Text mutation helpers ─────────────────────────────────────────────────

  /// Inserts [text] at the current cursor, replacing any selection.
  void _insertAtCursor(String text) {
    final sel = _ctrl.selection;
    if (!sel.isValid) return;
    final t = _ctrl.text;
    final newText = t.replaceRange(sel.start, sel.end, text);
    _ctrl.value = TextEditingValue(
      text: newText,
      selection: TextSelection.collapsed(offset: sel.start + text.length),
    );
  }

  /// Replaces [start..end] with [replacement], placing the cursor at
  /// [cursorAfter] (absolute offset in the new string).
  void _replaceRange(int start, int end, String replacement, int cursorAfter) {
    final newText = _ctrl.text.replaceRange(start, end, replacement);
    _ctrl.value = TextEditingValue(
      text: newText,
      selection: TextSelection.collapsed(
        offset: cursorAfter.clamp(0, newText.length),
      ),
    );
  }

  /// Wraps the current selection (or inserts an empty pair) with [marker].
  void _wrapSelection(String marker) {
    final sel = _ctrl.selection;
    if (!sel.isValid) return;
    final t = _ctrl.text;
    if (sel.isCollapsed) {
      final newText = t.replaceRange(sel.start, sel.start, '$marker$marker');
      _ctrl.value = TextEditingValue(
        text: newText,
        selection: TextSelection.collapsed(offset: sel.start + marker.length),
      );
    } else {
      final s = sel.textInside(t);
      final newText = t.replaceRange(sel.start, sel.end, '$marker$s$marker');
      _ctrl.value = TextEditingValue(
        text: newText,
        selection: TextSelection.collapsed(
          offset: sel.start + marker.length + s.length + marker.length,
        ),
      );
    }
    _save();
  }

  /// Returns info about the line the cursor is currently on.
  ({String line, int lineStart, int lineEnd}) _curLineInfo() {
    final t = _ctrl.text;
    final cursor = _ctrl.selection.baseOffset.clamp(0, t.length);
    final raw = cursor > 0 ? t.lastIndexOf('\n', cursor - 1) : -1;
    final start = raw < 0 ? 0 : raw + 1;
    final rawEnd = t.indexOf('\n', cursor);
    final end = rawEnd < 0 ? t.length : rawEnd;
    return (line: t.substring(start, end), lineStart: start, lineEnd: end);
  }

  // ── Keyboard event handler ────────────────────────────────────────────────
  //
  // Intercepted by the Focus wrapper around the single TextField, so it fires
  // before the TextField's own key handler.
  //
  // Handled:
  //   Enter      → list auto-continuation / escape empty list item
  //   Backspace  → strip block prefix when cursor is at start of content
  //   Tab        → indent list item   (Shift+Tab → dedent)
  //   Ctrl+B/I   → bold / italic wrap
  //   Ctrl+`     → inline-code wrap

  KeyEventResult _onKeyEvent(FocusNode _, KeyEvent event) {
    if (event is! KeyDownEvent && event is! KeyRepeatEvent) {
      return KeyEventResult.ignored;
    }

    final key = event.logicalKey;
    final ctrlHeld = HardwareKeyboard.instance.isControlPressed;
    final shiftHeld = HardwareKeyboard.instance.isShiftPressed;

    // ── Ctrl shortcuts ───────────────────────────────────────────────────
    if (ctrlHeld) {
      if (key == LogicalKeyboardKey.keyB) {
        _wrapSelection('**');
        return KeyEventResult.handled;
      }
      if (key == LogicalKeyboardKey.keyI) {
        _wrapSelection('*');
        return KeyEventResult.handled;
      }
      if (key == LogicalKeyboardKey.backquote) {
        _wrapSelection('`');
        return KeyEventResult.handled;
      }
      if (key == LogicalKeyboardKey.keyA) {
        // Select all display text. The controller's set value now preserves
        // non-collapsed selections so this will actually stick.
        final len = _ctrl.text.length;
        _ctrl.value = TextEditingValue(
          text: _ctrl.text,
          selection: TextSelection(baseOffset: 0, extentOffset: len),
        );
        return KeyEventResult.handled;
      }
      return KeyEventResult.ignored;
    }

    if (key == LogicalKeyboardKey.enter) return _handleEnter();
    if (key == LogicalKeyboardKey.backspace) return _handleBackspace();
    if (key == LogicalKeyboardKey.tab) return _handleTab(shiftHeld);

    return KeyEventResult.ignored;
  }

  KeyEventResult _handleEnter() {
    final sel = _ctrl.selection;
    if (!sel.isCollapsed) return KeyEventResult.ignored;

    final (:line, :lineStart, :lineEnd) = _curLineInfo();
    final cursor = sel.baseOffset;

    // ── Heading ──────────────────────────────────────────────────────────
    // When Enter is pressed anywhere on a heading line, insert a plain
    // newline at the cursor position (splitting the heading text if mid-line).
    // Without this, the default TextField handler can jump across folded
    // content and land on the next heading instead of the line after this one.
    final hm = RegExp(r'^#{1,6} ').hasMatch(line);
    if (hm) {
      // Insert \n at the cursor, splitting the heading at that point.
      // End-of-line: inserts empty line below. Mid-line: moves right-hand
      // text to a new plain line below.
      final t = _ctrl.text;
      final newText = t.replaceRange(cursor, cursor, '\n');
      _ctrl.value = TextEditingValue(
        text: newText,
        selection: TextSelection.collapsed(offset: cursor + 1),
      );
      _save();
      return KeyEventResult.handled;
    }

    // ── Checkbox ────────────────────────────────────────────────────────
    final cm = RegExp(r'^(\s*)(- \[[ xX]\] )').firstMatch(line);
    if (cm != null) {
      final indent = cm.group(1)!;
      final pfxLen = cm.group(1)!.length + cm.group(2)!.length;
      final content = line.substring(pfxLen);
      if (content.isEmpty && cursor >= lineStart + pfxLen) {
        // Empty item → escape: remove prefix, leave bare line.
        _replaceRange(
          lineStart,
          lineStart + pfxLen,
          indent,
          lineStart + indent.length,
        );
        return KeyEventResult.handled;
      }
      _insertAtCursor('\n${indent}- [ ] ');
      return KeyEventResult.handled;
    }

    // ── Bullet ──────────────────────────────────────────────────────────
    final bm = RegExp(r'^(\s*)([-*+] )').firstMatch(line);
    if (bm != null) {
      final indent = bm.group(1)!;
      final bullet = bm.group(2)!;
      final pfxLen = indent.length + bullet.length;
      final content = line.substring(pfxLen);
      if (content.isEmpty && cursor >= lineStart + pfxLen) {
        _replaceRange(
          lineStart,
          lineStart + pfxLen,
          indent,
          lineStart + indent.length,
        );
        return KeyEventResult.handled;
      }
      _insertAtCursor('\n$indent$bullet');
      return KeyEventResult.handled;
    }

    // ── Numbered list ────────────────────────────────────────────────────
    final nm = RegExp(r'^(\s*)(\d+)([.)]) ').firstMatch(line);
    if (nm != null) {
      final indent = nm.group(1)!;
      final num = int.parse(nm.group(2)!);
      final sep = nm.group(3)!;
      final pfxLen = nm.end;
      final content = line.substring(pfxLen);
      if (content.isEmpty && cursor >= lineStart + pfxLen) {
        _replaceRange(
          lineStart,
          lineStart + pfxLen,
          indent,
          lineStart + indent.length,
        );
        return KeyEventResult.handled;
      }
      _insertAtCursor('\n$indent${num + 1}$sep ');
      return KeyEventResult.handled;
    }

    // Default: let TextField insert the newline.
    return KeyEventResult.ignored;
  }

  KeyEventResult _handleBackspace() {
    final sel = _ctrl.selection;
    if (!sel.isCollapsed) return KeyEventResult.ignored;

    final (:line, :lineStart, :lineEnd) = _curLineInfo();
    final cursor = sel.baseOffset;

    // Heading: Backspace right after the "# " prefix strips it to plain text.
    final hm = RegExp(r'^(#{1,6} )').firstMatch(line);
    if (hm != null && cursor == lineStart + hm.end) {
      _replaceRange(lineStart, lineStart + hm.end, '', lineStart);
      return KeyEventResult.handled;
    }

    // List prefix: Backspace at start of content strips the prefix.
    final lm = RegExp(
      r'^(\s*(?:- \[[ xX]\] |[-*+] |\d+[.)]\s+))',
    ).firstMatch(line);
    if (lm != null && cursor == lineStart + lm.end) {
      _replaceRange(lineStart, lineStart + lm.end, '', lineStart);
      return KeyEventResult.handled;
    }

    return KeyEventResult.ignored;
  }

  KeyEventResult _handleTab(bool shift) {
    final (:line, :lineStart, :lineEnd) = _curLineInfo();

    final isList =
        RegExp(r'^\s*(?:[-*+]|\d+[.)]) ').hasMatch(line) ||
        RegExp(r'^\s*- \[[ xX]\] ').hasMatch(line);
    if (!isList) return KeyEventResult.ignored;

    final cursor = _ctrl.selection.baseOffset;
    if (shift) {
      if (line.startsWith('  ')) {
        _replaceRange(
          lineStart,
          lineEnd,
          line.substring(2),
          (cursor - 2).clamp(lineStart, lineStart + line.length - 2),
        );
        return KeyEventResult.handled;
      }
    } else {
      _replaceRange(lineStart, lineEnd, '  $line', cursor + 2);
      return KeyEventResult.handled;
    }
    return KeyEventResult.ignored;
  }

  // ── Toolbar helpers ───────────────────────────────────────────────────────

  /// Appends a new line with [prefix] after the current line,
  /// placing the cursor ready to type.
  void _insertLineSyntax(String prefix) {
    final sel = _ctrl.selection;
    if (!sel.isValid) return;
    final t = _ctrl.text;
    final rawEnd = t.indexOf('\n', sel.start);
    final insertAt = rawEnd < 0 ? t.length : rawEnd;
    // For code block, place cursor inside the fence.
    final isCodeBlock = prefix.startsWith('```');
    final insert = '\n$prefix';
    final newText = t.replaceRange(insertAt, insertAt, insert);
    final newCursor = isCodeBlock
        ? insertAt +
              5 // after "```\n" → inside the fence
        : insertAt + insert.length;
    _ctrl.value = TextEditingValue(
      text: newText,
      selection: TextSelection.collapsed(
        offset: newCursor.clamp(0, newText.length),
      ),
    );
    _save();
    _focus.requestFocus();
  }

  // ── Widget helpers ────────────────────────────────────────────────────────

  String _fmtDate(DateTime dt) {
    final now = DateTime.now();
    final diff = now.difference(dt);
    if (diff.inSeconds < 60) return 'just now';
    if (diff.inMinutes < 60) return '${diff.inMinutes}m ago';
    if (diff.inHours < 24) return '${diff.inHours}h ago';
    return '${dt.day}/${dt.month}/${dt.year}';
  }

  Widget _toolBtn(
    IconData icon,
    String tooltip,
    VoidCallback onTap, {
    Color? color,
    bool active = false,
  }) {
    return Tooltip(
      message: tooltip,
      waitDuration: const Duration(milliseconds: 400),
      child: InkWell(
        onTap: onTap,
        borderRadius: BorderRadius.circular(4),
        hoverColor: _nordBase2.withOpacity(0.5),
        child: Container(
          padding: const EdgeInsets.symmetric(horizontal: 5, vertical: 4),
          decoration: active
              ? BoxDecoration(
                  color: _nordBase2,
                  borderRadius: BorderRadius.circular(4),
                )
              : null,
          child: Icon(
            icon,
            size: 14,
            color: active ? _nordCyan : (color ?? _nordSnow),
          ),
        ),
      ),
    );
  }

  // ── Build ─────────────────────────────────────────────────────────────────

  @override
  Widget build(BuildContext context) {
    if (widget.note == null) {
      return Container(
        color: _nordBase,
        child: Center(
          child: Column(
            mainAxisSize: MainAxisSize.min,
            children: [
              Icon(
                Icons.article_outlined,
                size: 52,
                color: _nordSnow.withOpacity(0.2),
              ),
              const SizedBox(height: 14),
              const Text(
                'Select a note or create a new one',
                style: TextStyle(color: _nordSnow, fontSize: 13),
              ),
            ],
          ),
        ),
      );
    }

    final note = widget.note!;
    String typeLabel;
    IconData typeIcon;
    Color typeColor;
    switch (note.type) {
      case NoteType.task:
        typeLabel = 'Task';
        typeIcon = Icons.check_box_outline_blank_rounded;
        typeColor = _nordGreen;
        break;
      case NoteType.project:
        typeLabel = 'Project';
        typeIcon = Icons.folder_open_outlined;
        typeColor = _nordYellow;
        break;
      case NoteType.common:
      default:
        typeLabel = 'Note';
        typeIcon = Icons.article_outlined;
        typeColor = _nordCyan;
        break;
    }

    return Container(
      color: _nordBase,
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.stretch,
        children: [
          // ── Toolbar ────────────────────────────────────────────────────
          Container(
            height: 36,
            padding: const EdgeInsets.symmetric(horizontal: 16),
            decoration: const BoxDecoration(
              color: _nordSidebar,
              border: Border(bottom: BorderSide(color: _nordDivider, width: 1)),
            ),
            child: Row(
              children: [
                Icon(typeIcon, size: 12, color: typeColor),
                const SizedBox(width: 5),
                Text(
                  typeLabel,
                  style: TextStyle(
                    fontSize: 10,
                    color: typeColor,
                    fontWeight: FontWeight.w600,
                    letterSpacing: 0.4,
                  ),
                ),
                const SizedBox(width: 10),
                Container(width: 1, height: 12, color: _nordDivider),
                const SizedBox(width: 10),
                Text(
                  _fmtDate(note.updatedAt),
                  style: const TextStyle(fontSize: 10, color: _nordSnow),
                ),
                const Spacer(),
                _toolBtn(
                  _readingMode ? Icons.edit_outlined : Icons.menu_book_outlined,
                  _readingMode ? 'Edit' : 'Reading mode',
                  () => setState(() => _readingMode = !_readingMode),
                  active: _readingMode,
                ),
                const SizedBox(width: 4),
                Container(width: 1, height: 12, color: _nordDivider),
                const SizedBox(width: 4),
                if (!_readingMode) ...[
                  _toolBtn(
                    Icons.format_bold_rounded,
                    'Bold  (Ctrl+B)',
                    () => _wrapSelection('**'),
                  ),
                  _toolBtn(
                    Icons.format_italic_rounded,
                    'Italic  (Ctrl+I)',
                    () => _wrapSelection('*'),
                  ),
                  _toolBtn(
                    Icons.format_strikethrough_rounded,
                    'Strikethrough',
                    () => _wrapSelection('~~'),
                  ),
                  const SizedBox(width: 4),
                  Container(width: 1, height: 12, color: _nordDivider),
                  const SizedBox(width: 4),
                  _toolBtn(
                    Icons.code_rounded,
                    'Inline code  (Ctrl+`)',
                    () => _wrapSelection('`'),
                  ),
                  _toolBtn(
                    Icons.data_object_rounded,
                    'Code block',
                    () => _insertLineSyntax('```\n\n```'),
                  ),
                  const SizedBox(width: 4),
                  Container(width: 1, height: 12, color: _nordDivider),
                  const SizedBox(width: 4),
                  _toolBtn(
                    Icons.format_list_bulleted_rounded,
                    'Bullet list',
                    () => _insertLineSyntax('- '),
                  ),
                  _toolBtn(
                    Icons.format_list_numbered_rounded,
                    'Numbered list',
                    () => _insertLineSyntax('1. '),
                  ),
                  _toolBtn(
                    Icons.check_box_outlined,
                    'Task item',
                    () => _insertLineSyntax('- [ ] '),
                  ),
                  const SizedBox(width: 4),
                  Container(width: 1, height: 12, color: _nordDivider),
                  const SizedBox(width: 4),
                  _toolBtn(
                    Icons.horizontal_rule_rounded,
                    'Divider',
                    () => _insertLineSyntax('---'),
                  ),
                  const SizedBox(width: 4),
                  Container(width: 1, height: 12, color: _nordDivider),
                  const SizedBox(width: 4),
                ],
                if (widget.onDeleteNote != null)
                  _toolBtn(
                    Icons.delete_outline_rounded,
                    'Delete note',
                    widget.onDeleteNote!,
                    color: _nordRed.withOpacity(0.8),
                  ),
              ],
            ),
          ),

          // ── Content ────────────────────────────────────────────────────
          Expanded(
            child: AnimatedSwitcher(
              duration: const Duration(milliseconds: 200),
              layoutBuilder: (current, previous) => Stack(
                alignment: Alignment.topLeft,
                children: [...previous, if (current != null) current],
              ),
              child: _readingMode ? _buildReadingView() : _buildEditingView(),
            ),
          ),
        ],
      ),
    );
  }

  // ── Heading collapse helpers ──────────────────────────────────────────────

  void _toggleCollapse(int headingLineStart) {
    // headingLineStart is a backing-text offset (from gutter or reading view).
    setState(() => _ctrl.toggleFold(headingLineStart));
    // Persist the updated fold state via the lightweight fold callback so the
    // parent can update notes_meta.json without rewriting the .md file.
    final noteId = widget.note?.id;
    if (noteId != null) {
      widget.onFoldsChanged?.call(noteId, _ctrl.getFoldedHeadings());
    }
  }

  /// Computes (y, level, rawLine) for every heading line in [_ctrl.text],
  // ── Editing view ──────────────────────────────────────────────────────────

  Widget _buildEditingView() {
    return Focus(
      // This Focus intercepts key events before the TextField processes them.
      // canRequestFocus: false keeps it invisible to Tab-order traversal.
      canRequestFocus: false,
      skipTraversal: true,
      onKeyEvent: _onKeyEvent,
      child: SingleChildScrollView(
        // Left padding reduced from 56→8 so the 28px gutter + 8px gap
        // keeps text at the same ~36px horizontal position.
        padding: const EdgeInsets.fromLTRB(8, 24, 56, 60),
        child: Column(
          crossAxisAlignment: CrossAxisAlignment.start,
          children: [
            // Title — indented to match the text body (28 gutter + 8 gap)
            Padding(
              padding: const EdgeInsets.only(left: 36),
              child: _titleLocked
                  ? Text(
                      widget.note!.title,
                      style: const TextStyle(
                        fontFamily: 'Inter',
                        fontSize: 32,
                        fontWeight: FontWeight.w700,
                        color: _nordFrost2,
                        height: 1.0,
                        letterSpacing: -0.4,
                      ),
                    )
                  : TextField(
                      controller: _titleCtrl,
                      focusNode: _titleFocusNode,
                      // Spec §1: block reserved filesystem chars in note titles.
                      inputFormatters: [
                        FilteringTextInputFormatter.deny(RegExp(r'[/\\:]')),
                      ],
                      style: const TextStyle(
                        fontFamily: 'Inter',
                        fontSize: 32,
                        fontWeight: FontWeight.w700,
                        color: _nordFrost2,
                        height: 1.0,
                        letterSpacing: -0.4,
                      ),
                      cursorColor: _nordCyan,
                      decoration: const InputDecoration(
                        hintText: 'Note title…',
                        hintStyle: TextStyle(
                          fontSize: 30,
                          fontWeight: FontWeight.w700,
                          color: Color(0x40D8DEE9),
                        ),
                        border: InputBorder.none,
                        isDense: true,
                        contentPadding: EdgeInsets.zero,
                      ),
                      onSubmitted: (_) => _save(),
                    ),
            ),
            // ── Duplicate-title error ─────────────────────────────────
            if (_titleError != null)
              Padding(
                padding: const EdgeInsets.only(top: 4),
                child: Row(
                  children: [
                    const Icon(
                      Icons.error_outline_rounded,
                      size: 13,
                      color: Color(0xFFBF616A),
                    ),
                    const SizedBox(width: 6),
                    Expanded(
                      child: Text(
                        _titleError!,
                        style: const TextStyle(
                          fontSize: 11,
                          color: Color(0xFFBF616A),
                        ),
                      ),
                    ),
                  ],
                ),
              ),
            const SizedBox(height: 6),
            Padding(
              padding: const EdgeInsets.only(left: 36),
              child: Container(height: 1, width: 36, color: _nordDivider),
            ),
            const SizedBox(height: 24),

            // ── Body: gutter (28px) + gap (8px) + TextField ──────────
            MouseRegion(
              onHover: (e) =>
                  setState(() => _gutterHoverY = e.localPosition.dy),
              onExit: (_) => setState(() => _gutterHoverY = null),
              child: LayoutBuilder(
                builder: (context, constraints) => Row(
                  crossAxisAlignment: CrossAxisAlignment.start,
                  children: [
                    // Collapse gutter — one item per visible text line
                    _buildEditGutter(context, constraints.maxWidth),
                    const SizedBox(width: 8),
                    // Single flat-document TextField (the entire note body)
                    Expanded(
                      child: TextField(
                        controller: _ctrl,
                        focusNode: _focus,
                        maxLines: null,
                        cursorColor: _nordCyan,
                        cursorWidth: 1.5,
                        style: _kDocBase,
                        strutStyle: const StrutStyle(
                          height: 0,
                          leading: 0,
                          forceStrutHeight: false,
                        ),
                        decoration: const InputDecoration(
                          hintText:
                              'Start writing…  (# heading, - bullet, - [ ] task)',
                          hintStyle: TextStyle(
                            fontSize: _kBase,
                            color: Color(0x28D8DEE9),
                          ),
                          border: InputBorder.none,
                          isDense: true,
                          contentPadding: EdgeInsets.zero,
                        ),
                      ),
                    ),
                  ],
                ),
              ),
            ),

            // Tap-below area: click anywhere below the text to focus ──
            GestureDetector(
              behavior: HitTestBehavior.opaque,
              onTap: () => _focus.requestFocus(),
              child: const SizedBox(height: 80, width: double.infinity),
            ),
          ],
        ),
      ),
    );
  }

  /// Returns true when the heading whose first line starts at [headingLineStart]
  /// has at least one non-empty content line before the next same-or-higher-level
  /// heading. Used by both edit and reading modes.
  bool _headingHasBody(int headingLineStart, String headingLine) {
    final back = _ctrl.backingText;
    final level =
        RegExp(r'^(#{1,6}) ').firstMatch(headingLine)?.group(1)?.length ?? 0;
    int pos = headingLineStart + headingLine.length + 1;
    while (pos < back.length) {
      final nl = back.indexOf('\n', pos);
      final end = nl < 0 ? back.length : nl;
      final l = back.substring(pos, end);
      final hm2 = RegExp(r'^(#{1,6}) ').firstMatch(l);
      if (hm2 != null && hm2.group(1)!.length <= level) break;
      if (l.trim().isNotEmpty) return true;
      pos = end + 1;
    }
    return false;
  }

  /// Builds the 28 px-wide gutter that shows collapse chevrons next to
  /// heading lines in the editing view.
  ///
  /// [availableWidth] is the full width of the Row (gutter + gap + text field).
  /// We derive the text field width from it and pass it to a [TextPainter] so
  /// that the measured line heights match Flutter's actual text layout — no
  /// hardcoded multipliers that can drift when headings collapse or expand.
  Widget _buildEditGutter(BuildContext context, double availableWidth) {
    const double gutterW = 28;
    const double gap = 8;
    final double textW = (availableWidth - gutterW - gap).clamp(
      1.0,
      double.infinity,
    );

    // Build the same TextSpan the TextField renders (uses _displayText with
    // fold bodies already removed).
    final span = _ctrl.buildTextSpan(
      context: context,
      style: _kDocBase,
      withComposing: false,
    );

    // Lay it out at the real width with the same StrutStyle as the TextField.
    final painter = TextPainter(
      text: span,
      textDirection: TextDirection.ltr,
      strutStyle: const StrutStyle(
        height: 0,
        leading: 0,
        forceStrutHeight: false,
      ),
    )..layout(maxWidth: textW);

    // computeLineMetrics() returns one entry per *visual* line.
    // hardBreak == true marks the last visual line of each logical line
    // (i.e. every line that ended with '\n', plus the very last line).
    // We accumulate visual-line heights until hardBreak, giving us the
    // exact pixel height that the TextField allocates to each logical line.
    final metrics = painter.computeLineMetrics();
    final List<double> logicalHeights = [];
    double acc = 0;
    for (final m in metrics) {
      acc += m.height;
      if (m.hardBreak) {
        logicalHeights.add(acc);
        acc = 0;
      }
    }
    if (acc > 0) logicalHeights.add(acc); // safety: trailing visual line

    // Walk the backing text (which includes folded content) and emit one
    // SizedBox per visible logical line, indexed into logicalHeights.
    final back = _ctrl.backingText;
    final folds = _ctrl.folds;
    final children = <Widget>[];
    int offset = 0;
    int logIdx = 0;

    // Pre-split lines for the hasBody helper below.
    final allLines = back.split('\n');

    bool headingHasBody(int headingLineStart, String headingLine) =>
        _headingHasBody(headingLineStart, headingLine);

    // Determine which heading line (by backing-text offset) the mouse is
    // currently over, using the accumulated line heights computed above.
    // We rebuild this each frame — no extra state needed.
    int? hoveredLineStart;
    if (_gutterHoverY != null) {
      double cumY = 0;
      int scanOffset = 0;
      int scanLogIdx = 0;
      for (final line in allLines) {
        final lineStart = scanOffset;
        scanOffset += line.length + 1;
        final isHidden = folds.any(
          (f) => lineStart >= f.start && lineStart <= f.end,
        );
        if (isHidden) continue;
        final double h = scanLogIdx < logicalHeights.length
            ? logicalHeights[scanLogIdx]
            : _kBase * 1.75;
        scanLogIdx++;
        if (_gutterHoverY! >= cumY && _gutterHoverY! < cumY + h) {
          if (RegExp(r'^#{1,6} ').hasMatch(line)) hoveredLineStart = lineStart;
          break;
        }
        cumY += h;
      }
    }

    int lineOffset = 0;
    for (final line in allLines) {
      final lineStart = lineOffset;
      lineOffset += line.length + 1; // +1 for '\n'

      // Lines hidden inside an active fold occupy zero height.
      final isHidden = folds.any(
        (f) => lineStart >= f.start && lineStart <= f.end,
      );
      if (isHidden) {
        children.add(const SizedBox(width: 28, height: 0));
        continue;
      }

      final double rawH = logIdx < logicalHeights.length
          ? logicalHeights[logIdx]
          : _kBase * 1.75;
      logIdx++;

      final hm = RegExp(r'^(#{1,6}) (.*)$').firstMatch(line);
      if (hm != null) {
        final isFolded = _ctrl.isFoldedAt(lineStart);
        final hasBody = isFolded || headingHasBody(lineStart, line);

        // Show button: always when folded, on hover (full-row) when expanded.
        final showBtn = hasBody && (isFolded || hoveredLineStart == lineStart);

        children.add(
          SizedBox(
            width: 28,
            height: rawH,
            child: Align(
              alignment: Alignment.centerLeft,
              child: showBtn
                  ? _collapseArrow(
                      isFolded,
                      () => _toggleCollapse(lineStart),
                      orangeExpand: isFolded,
                    )
                  : const SizedBox(width: 16, height: 16),
            ),
          ),
        );
      } else {
        children.add(SizedBox(width: 28, height: rawH));
      }
    }

    return SizedBox(
      width: 28,
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.start,
        mainAxisSize: MainAxisSize.min,
        children: children,
      ),
    );
  }

  /// Small clickable chevron icon used in both edit and reading modes.
  /// [orangeExpand] — when true (heading is collapsed) the icon is rendered in
  /// an amber/orange tint so it is always discoverable at a glance.
  Widget _collapseArrow(
    bool collapsed,
    VoidCallback onTap, {
    bool orangeExpand = false,
  }) {
    final Color iconColor = orangeExpand
        ? const Color(0xFFFFB74D) // warm amber-orange
        : _nordSnow.withOpacity(0.55);
    return MouseRegion(
      cursor: SystemMouseCursors.click,
      child: GestureDetector(
        onTap: onTap,
        child: AnimatedRotation(
          turns: collapsed ? -0.25 : 0,
          duration: const Duration(milliseconds: 150),
          child: Icon(Icons.expand_more_rounded, size: 16, color: iconColor),
        ),
      ),
    );
  }

  // ── Reading view ──────────────────────────────────────────────────────────
  // Parses the document into blocks on-demand and renders without edit handles.

  Widget _buildReadingView() {
    final blocks = _parseBlocks(_ctrl.backingText); // use backing, not display

    // Honor fold state from the controller.
    final visible = <NoteBlock>[];
    int? collapsedLevel;
    for (final b in blocks) {
      if (b.isHeading) {
        if (collapsedLevel != null && b.headingLevel <= collapsedLevel!) {
          collapsedLevel = null;
        }
        if (collapsedLevel != null) continue;
        visible.add(b);
        if (_ctrl.isFoldedAt(b.lineOffset)) collapsedLevel = b.headingLevel;
      } else {
        if (collapsedLevel != null) continue;
        visible.add(b);
      }
    }

    return SingleChildScrollView(
      // Left padding mirrors the editing view (8px outer + 28px gutter + 8px gap = 44px)
      padding: const EdgeInsets.fromLTRB(8, 24, 56, 60),
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.start,
        children: [
          // Title — indented to match the text body (28 gutter + 8 gap = 36)
          Padding(
            padding: const EdgeInsets.only(left: 36),
            child: Text(
              widget.note!.title,
              style: const TextStyle(
                fontFamily: 'Inter',
                fontSize: 32,
                fontWeight: FontWeight.w700,
                color: _nordFrost2,
                height: 1.0,
                letterSpacing: -0.4,
              ),
            ),
          ),
          const SizedBox(height: 6),
          Padding(
            padding: const EdgeInsets.only(left: 36),
            child: Container(height: 1, width: 36, color: _nordDivider),
          ),
          const SizedBox(height: 32),
          for (int i = 0; i < visible.length; i++)
            _buildReadingBlock(visible, i),
        ],
      ),
    );
  }

  Widget _buildReadingBlock(List<NoteBlock> blocks, int idx) {
    final b = blocks[idx];

    // ── Helper: wrap any non-heading content in the same gutter offset ────────
    // Headings own the gutter column (collapse button); everything else gets a
    // 36px (28 gutter + 8 gap) transparent spacer so all content aligns.
    Widget gutterOffset(Widget child) => Row(
      crossAxisAlignment: CrossAxisAlignment.start,
      children: [
        const SizedBox(width: 36),
        Expanded(child: child),
      ],
    );

    if (b.type == NoteBlockType.divider) {
      return gutterOffset(
        Padding(
          padding: const EdgeInsets.symmetric(vertical: 16),
          child: Container(height: 1, color: _nordDivider),
        ),
      );
    }

    if (b.type == NoteBlockType.code) {
      return gutterOffset(
        Padding(
          padding: const EdgeInsets.only(bottom: 12),
          child: Container(
            decoration: BoxDecoration(
              color: _nordBase1,
              borderRadius: BorderRadius.circular(6),
              border: Border.all(color: _nordDivider),
            ),
            padding: const EdgeInsets.all(12),
            child: SelectableText(
              b.content,
              style: TextStyle(
                fontFamily: 'monospace',
                fontSize: _kBase * 0.88,
                color: _nordCyan,
                height: 1.6,
              ),
            ),
          ),
        ),
      );
    }

    if (b.isHeading) {
      final lvl = b.headingLevel;
      final color = _nbHeadingColor(lvl);
      final size = _nbHeadingSize(lvl);
      final weight = _nbHeadingWeight(lvl);
      // Strip the "# " prefix for display.
      final prefix = '${'#' * lvl} ';
      final displayText = b.content.startsWith(prefix)
          ? b.content.substring(prefix.length)
          : b.content;
      final isCollapsed = _ctrl.isFoldedAt(b.lineOffset);

      // Show the arrow only when the heading has body content AND
      // (it is already collapsed OR the row is hovered).
      // Key on lineOffset — stable across rebuilds unlike block id.
      final hasBody = _headingHasBody(b.lineOffset, b.content);
      final isHovered = _readingHoveredLineOffset == b.lineOffset;
      final showArrow = hasBody && (isCollapsed || isHovered);

      return MouseRegion(
        onEnter: (_) =>
            setState(() => _readingHoveredLineOffset = b.lineOffset),
        onExit: (_) => setState(() {
          if (_readingHoveredLineOffset == b.lineOffset)
            _readingHoveredLineOffset = null;
        }),
        child: Padding(
          padding: EdgeInsets.only(
            top: lvl <= 2 ? 40 : 28,
            bottom: isCollapsed ? 20 : 8,
          ),
          // IntrinsicHeight forces the gutter SizedBox to be stretched to the
          // exact pixel height that RichText actually renders — identical to
          // the edit gutter's TextPainter-measured approach — so that
          // Align(centerLeft) places the icon at the true vertical midpoint of
          // the heading text regardless of font-metric subtleties.
          child: IntrinsicHeight(
            child: Row(
              crossAxisAlignment: CrossAxisAlignment.stretch,
              children: [
                SizedBox(
                  width: 28,
                  child: Align(
                    alignment: Alignment.centerLeft,
                    child: showArrow
                        ? _collapseArrow(
                            isCollapsed,
                            () => _toggleCollapse(b.lineOffset),
                            orangeExpand: isCollapsed,
                          )
                        : const SizedBox(width: 16, height: 16),
                  ),
                ),
                const SizedBox(width: 8),
                Expanded(
                  child: RichText(
                    text: _buildInlineSpan(
                      displayText,
                      TextStyle(
                        fontFamily: 'Inter',
                        fontSize: size,
                        fontWeight: weight,
                        color: color,
                        height: 1.75,
                      ),
                    ),
                  ),
                ),
              ],
            ),
          ),
        ),
      );
    }

    if (b.type == NoteBlockType.quote) {
      return gutterOffset(
        Padding(
          padding: const EdgeInsets.only(bottom: 8),
          child: IntrinsicHeight(
            child: Row(
              crossAxisAlignment: CrossAxisAlignment.stretch,
              children: [
                Container(
                  width: 3,
                  decoration: BoxDecoration(
                    color: _nordBlue.withOpacity(0.6),
                    borderRadius: BorderRadius.circular(2),
                  ),
                ),
                const SizedBox(width: 12),
                Expanded(
                  child: RichText(
                    text: _buildInlineSpan(
                      b.content,
                      TextStyle(
                        fontFamily: 'Inter',
                        fontSize: _kBase,
                        color: _nordFrost.withOpacity(0.75),
                        height: 1.75,
                        fontStyle: FontStyle.italic,
                      ),
                    ),
                  ),
                ),
              ],
            ),
          ),
        ),
      );
    }

    if (b.type == NoteBlockType.bullet) {
      return gutterOffset(
        Padding(
          padding: EdgeInsets.only(left: b.indent * 20.0, bottom: 3),
          child: Row(
            crossAxisAlignment: CrossAxisAlignment.start,
            children: [
              Padding(
                padding: const EdgeInsets.only(right: 8, top: 8),
                child: Container(
                  width: 5,
                  height: 5,
                  decoration: const BoxDecoration(
                    shape: BoxShape.circle,
                    color: _nordBlue,
                  ),
                ),
              ),
              Expanded(
                child: RichText(
                  text: _buildInlineSpan(
                    b.content,
                    const TextStyle(
                      fontFamily: 'Inter',
                      fontSize: _kBase,
                      color: _nordFrost,
                      height: 1.75,
                    ),
                  ),
                ),
              ),
            ],
          ),
        ),
      );
    }

    if (b.type == NoteBlockType.numbered) {
      int num = 1;
      for (int i = idx - 1; i >= 0; i--) {
        if (blocks[i].type == NoteBlockType.numbered &&
            blocks[i].indent == b.indent)
          num++;
        else
          break;
      }
      return gutterOffset(
        Padding(
          padding: EdgeInsets.only(left: b.indent * 20.0, bottom: 3),
          child: Row(
            crossAxisAlignment: CrossAxisAlignment.start,
            children: [
              Text(
                '$num.  ',
                style: TextStyle(
                  fontFamily: 'Inter',
                  fontSize: _kBase,
                  color: _nordFrost.withOpacity(0.6),
                  height: 1.75,
                ),
              ),
              Expanded(
                child: RichText(
                  text: _buildInlineSpan(
                    b.content,
                    const TextStyle(
                      fontFamily: 'Inter',
                      fontSize: _kBase,
                      color: _nordFrost,
                      height: 1.75,
                    ),
                  ),
                ),
              ),
            ],
          ),
        ),
      );
    }

    if (b.type == NoteBlockType.check) {
      return gutterOffset(
        Padding(
          padding: EdgeInsets.only(left: b.indent * 20.0, bottom: 3),
          child: Row(
            crossAxisAlignment: CrossAxisAlignment.start,
            children: [
              Padding(
                padding: const EdgeInsets.only(right: 6, top: 2),
                child: Icon(
                  b.checked
                      ? Icons.check_box_rounded
                      : Icons.check_box_outline_blank_rounded,
                  size: 16,
                  color: b.checked ? _nordGreen : _nordSnow.withOpacity(0.5),
                ),
              ),
              Expanded(
                child: RichText(
                  text: _buildInlineSpan(
                    b.content,
                    TextStyle(
                      fontFamily: 'Inter',
                      fontSize: _kBase,
                      color: b.checked
                          ? _nordFrost.withOpacity(0.4)
                          : _nordFrost,
                      height: 1.75,
                      decoration: b.checked
                          ? TextDecoration.lineThrough
                          : TextDecoration.none,
                    ),
                  ),
                ),
              ),
            ],
          ),
        ),
      );
    }

    // Plain text / blank line
    if (b.content.isEmpty) return const SizedBox(height: 8);
    return gutterOffset(
      Padding(
        padding: const EdgeInsets.only(bottom: 4),
        child: RichText(
          text: _buildInlineSpan(
            b.content,
            const TextStyle(
              fontFamily: 'Inter',
              fontSize: _kBase,
              color: _nordFrost,
              height: 1.75,
            ),
          ),
        ),
      ),
    );
  }
}

class _OrgSettingsView extends StatefulWidget {
  final bool isProjects;
  // shared mutable state passed by reference — mutations are reflected live
  final Map<String, Project> projects;
  final List<String> projectOrder;
  final Map<String, Set<String>> projectFolders;
  final Map<String, Set<String>> tagFolders;
  final Set<String> hiddenTags;
  final Map<String, bool> projectHiddenFromMenu;
  final List<Task> allTasks;
  final Set<String> customTags;
  final List<Map<String, dynamic>> savedBoards;
  final VoidCallback onChanged; // call after any mutation to persist + repaint
  /// Called when a new project is created, passing (id, color) so the parent
  /// can register the color in _projectColors.
  final void Function(String id, Color color)? onProjectCreated;

  /// Feature 4: callback to open the app-level unified color picker.
  final void Function({
    required String title,
    required Color initialColor,
    required void Function(Color) onApply,
    String? colorContext,
  })?
  onShowColorPicker;

  /// When non-null, a Close button is shown in the toolbar (used when rendered
  /// inside a dialog so the user can dismiss it without tapping the barrier).
  final VoidCallback? onBack;

  const _OrgSettingsView({
    Key? key,
    required this.isProjects,
    required this.projects,
    required this.projectOrder,
    required this.projectFolders,
    required this.tagFolders,
    required this.hiddenTags,
    required this.projectHiddenFromMenu,
    required this.allTasks,
    required this.customTags,
    required this.savedBoards,
    required this.onChanged,
    this.onProjectCreated,
    this.onShowColorPicker,
    this.onBack,
  }) : super(key: key);

  @override
  State<_OrgSettingsView> createState() => _OrgSettingsViewState();
}

class _OrgSettingsViewState extends State<_OrgSettingsView> {
  static const _bg = Color(0xFF181A1B);
  static const _surface = Color(0xFF212426);
  static const _border = Color(0xFF2C2F32);
  static const _accent = Color(0xFF4FC3F7);

  final Set<String> _collapsed = {}; // folderKey → collapsed
  String _searchQuery = '';
  final _searchCtrl = TextEditingController();
  bool _searchActive = false;
  bool _addingFolder = false;
  final _newFolderCtrl = TextEditingController();
  String? _renamingFolder;
  final _renameFolderCtrl = TextEditingController();
  bool _addingTag = false;
  final _newTagCtrl = TextEditingController();
  String? _newTagProjectId; // null = no project
  bool _addingProject = false;
  final _newProjectCtrl = TextEditingController();
  Color _newProjectColor = Colors.blueAccent;

  // Feature 5: sort state for the org panel
  // sortField values: 'name' | 'taskCount' | 'usageCount'
  String _sortField = 'name';
  bool _sortAsc = true;

  @override
  void dispose() {
    _searchCtrl.dispose();
    _newFolderCtrl.dispose();
    _renameFolderCtrl.dispose();
    _newTagCtrl.dispose();
    _newProjectCtrl.dispose();
    super.dispose();
  }

  // ── Data helpers ──────────────────────────────────────────────────────────

  Map<String, Set<String>> get _folders =>
      widget.isProjects ? widget.projectFolders : widget.tagFolders;

  List<String> get _allItemKeys {
    if (widget.isProjects) return widget.projectOrder;
    final all = <String>{
      for (final t in widget.allTasks) ...t.tagIds.map((e) => e.toString()),
      ...widget.customTags,
    };
    return all.toList()..sort();
  }

  Set<String> get _placedKeys => {for (final s in _folders.values) ...s};

  List<String> get _standardItems =>
      _allItemKeys.where((k) => !_placedKeys.contains(k)).toList();

  bool _matchesSearch(String key) {
    if (_searchQuery.isEmpty) return true;
    final q = _searchQuery.toLowerCase();
    return _label(key).toLowerCase().contains(q);
  }

  List<String> _filteredItems(List<String> items) =>
      _searchQuery.isEmpty ? items : items.where(_matchesSearch).toList();

  /// Returns filtered items sorted by the active sort field.
  List<String> _sortedFilteredItems(List<String> items) {
    final filtered = _filteredItems(items);
    final sorted = List<String>.from(filtered);
    sorted.sort((a, b) {
      int cmp;
      if (_sortField == 'taskCount') {
        final ca = widget.allTasks
            .where(
              (t) =>
                  widget.isProjects ? t.projectId == a : t.tagIds.contains(a),
            )
            .length;
        final cb = widget.allTasks
            .where(
              (t) =>
                  widget.isProjects ? t.projectId == b : t.tagIds.contains(b),
            )
            .length;
        cmp = ca.compareTo(cb);
      } else {
        // 'name' or 'usageCount' (same as taskCount for tags) — default to name
        cmp = a.toLowerCase().compareTo(b.toLowerCase());
      }
      return _sortAsc ? cmp : -cmp;
    });
    return sorted;
  }

  bool _isHidden(String key) => widget.isProjects
      ? (widget.projectHiddenFromMenu[key] ?? false)
      : widget.hiddenTags.contains(key);

  void _setHidden(String key, bool hidden) {
    if (widget.isProjects) {
      widget.projectHiddenFromMenu[key] = hidden;
    } else {
      if (hidden)
        widget.hiddenTags.add(key);
      else
        widget.hiddenTags.remove(key);
    }
    setState(() {});
    widget.onChanged();
  }

  bool _isProtected(String folderKey) {
    if (!widget.isProjects &&
        widget.savedBoards.any(
          (b) => (b['title'] as String? ?? '') == folderKey,
        ))
      return true;
    return false;
  }

  bool _isTrello(String folderKey) =>
      !widget.isProjects &&
      widget.savedBoards.any((b) => (b['title'] as String? ?? '') == folderKey);

  String _label(String key) =>
      widget.isProjects ? (widget.projects[key]?.title ?? key) : key;

  void _moveToFolder(String key, String? folderKey) {
    for (final s in _folders.values) s.remove(key);
    if (folderKey != null) _folders.putIfAbsent(folderKey, () => {}).add(key);
    setState(() {});
    widget.onChanged();
  }

  void _createProject(String name) {
    // Spec §1: strip reserved filesystem characters before any other check.
    final n = name.replaceAll(RegExp(r'[/\\:]'), '').trim();
    if (n.isEmpty) return;

    // Spec §2: global project name uniqueness.
    final duplicate = widget.projects.values.any(
      (p) => p.title.toLowerCase() == n.toLowerCase(),
    );
    if (duplicate) {
      ScaffoldMessenger.of(context).showSnackBar(
        SnackBar(
          content: Text('A project named "$n" already exists.'),
          backgroundColor: const Color(0xFFB71C1C),
          duration: const Duration(seconds: 3),
        ),
      );
      return;
    }

    final id = 'proj_${DateTime.now().millisecondsSinceEpoch}';
    widget.projects[id] = Project(id: id, title: n);
    widget.projectOrder.add(id);
    if (widget.onProjectCreated != null) {
      widget.onProjectCreated!(id, _newProjectColor);
    }
    _newProjectCtrl.clear();
    setState(() {
      _addingProject = false;
      _newProjectColor = Colors.blueAccent;
    });
    widget.onChanged();
  }

  void _createTag(String name) {
    final n = name.trim();
    if (n.isEmpty) return;
    widget.customTags.add(n);
    // If a project was selected, auto-assign all tasks of that project the tag
    if (_newTagProjectId != null) {
      for (final t in widget.allTasks) {
        if (t.projectId == _newTagProjectId && !t.tagIds.contains(n)) {
          t.tagIds.add(n);
        }
      }
    }
    _newTagCtrl.clear();
    setState(() {
      _addingTag = false;
      _newTagProjectId = null;
    });
    widget.onChanged();
  }

  void _createFolder(String name) {
    final n = name.trim();
    if (n.isEmpty) return;
    _folders.putIfAbsent(n, () => {});
    _newFolderCtrl.clear();
    setState(() => _addingFolder = false);
    widget.onChanged();
  }

  void _renameFolder(String oldKey, String newKey) {
    final n = newKey.trim();
    if (n.isEmpty || n == oldKey) {
      setState(() => _renamingFolder = null);
      return;
    }
    final items = _folders.remove(oldKey) ?? {};
    _folders[n] = items;
    if (_collapsed.remove(oldKey)) _collapsed.add(n);
    setState(() => _renamingFolder = null);
    widget.onChanged();
  }

  void _deleteFolder(String key) {
    _folders.remove(key); // items fall back to Standard automatically
    _collapsed.remove(key);
    setState(() {});
    widget.onChanged();
  }

  // ── Item row ─────────────────────────────────────────────────────────────
  // Wrapped in Draggable (immediate click-and-drag) — mirrors sidebar gesture.

  Widget _itemRow(String key, {String? currentFolder}) {
    final hidden = _isHidden(key);
    final label = _label(key);

    final rowContent = Container(
      margin: const EdgeInsets.symmetric(horizontal: 12, vertical: 2),
      padding: const EdgeInsets.fromLTRB(10, 7, 8, 7),
      decoration: BoxDecoration(
        color: _surface,
        borderRadius: BorderRadius.circular(6),
        border: Border.all(color: _border),
      ),
      child: Row(
        children: [
          Icon(
            widget.isProjects ? Icons.folder_outlined : Icons.label_outline,
            size: 13,
            color: hidden ? Colors.white12 : Colors.white38,
          ),
          const SizedBox(width: 9),
          Expanded(
            child: Text(
              label,
              style: TextStyle(
                fontSize: 12,
                color: hidden ? Colors.white24 : Colors.white70,
                fontStyle: hidden ? FontStyle.italic : FontStyle.normal,
              ),
            ),
          ),
          // Folder picker
          PopupMenuButton<String?>(
            tooltip: 'Move to folder',
            color: const Color(0xFF1E2124),
            padding: EdgeInsets.zero,
            icon: Icon(
              Icons.drive_file_move_outline,
              size: 13,
              color: currentFolder != null
                  ? _accent.withOpacity(0.7)
                  : Colors.white24,
            ),
            itemBuilder: (_) => [
              PopupMenuItem<String?>(
                value: null,
                child: Text(
                  'Standard',
                  style: TextStyle(
                    fontSize: 12,
                    color: currentFolder == null ? _accent : Colors.white70,
                  ),
                ),
              ),
              ..._folders.keys.map(
                (f) => PopupMenuItem<String?>(
                  value: f,
                  child: Text(
                    f,
                    style: TextStyle(
                      fontSize: 12,
                      color: currentFolder == f ? _accent : Colors.white70,
                    ),
                  ),
                ),
              ),
            ],
            onSelected: (f) => _moveToFolder(key, f),
          ),
          // Eye toggle
          Tooltip(
            message: hidden ? 'Show in sidebar' : 'Hide from sidebar',
            child: InkWell(
              onTap: () => _setHidden(key, !hidden),
              borderRadius: BorderRadius.circular(4),
              child: Padding(
                padding: const EdgeInsets.all(4),
                child: Icon(
                  hidden
                      ? Icons.visibility_off_outlined
                      : Icons.visibility_outlined,
                  size: 14,
                  color: hidden ? Colors.white24 : Colors.white38,
                ),
              ),
            ),
          ),
        ],
      ),
    );

    // Unified click-and-drag (no delay) — mirrors sidebar Draggable pattern.
    return Draggable<String>(
      data: key,
      feedback: Material(
        color: Colors.transparent,
        child: Container(
          padding: const EdgeInsets.symmetric(horizontal: 12, vertical: 7),
          decoration: BoxDecoration(
            color: const Color(0xFF1C1F23),
            borderRadius: BorderRadius.circular(8),
            border: Border.all(color: _accent.withOpacity(0.55)),
            boxShadow: [
              BoxShadow(
                color: Colors.black.withOpacity(0.50),
                blurRadius: 14,
                offset: const Offset(0, 5),
              ),
              BoxShadow(
                color: _accent.withOpacity(0.08),
                blurRadius: 10,
                spreadRadius: 1,
              ),
            ],
          ),
          child: Row(
            mainAxisSize: MainAxisSize.min,
            children: [
              Icon(Icons.drag_indicator_rounded, size: 12, color: _accent),
              const SizedBox(width: 6),
              Text(label, style: const TextStyle(fontSize: 12, color: _accent)),
            ],
          ),
        ),
      ),
      childWhenDragging: Opacity(opacity: 0.3, child: rowContent),
      child: rowContent,
    );
  }

  // ── Folder block ──────────────────────────────────────────────────────────

  Widget _folderBlock({
    required String folderKey,
    required List<String> items,
    bool isStandard = false,
  }) {
    final isProtected = isStandard || _isProtected(folderKey);
    final isTrello = _isTrello(folderKey);
    final isCollapsed = _collapsed.contains(folderKey);
    final isRenaming = _renamingFolder == folderKey;
    final allHidden = items.isNotEmpty && items.every(_isHidden);

    // Folder colour / badge
    Color folderColor = _accent.withOpacity(0.6);
    Widget? badge;
    if (isTrello) {
      folderColor = const Color(0xFF0052CC).withOpacity(0.8);
      badge = Tooltip(
        message: 'Auto-created from Trello board',
        child: Padding(
          padding: const EdgeInsets.only(right: 4),
          child: Icon(
            Icons.dashboard_outlined,
            size: 11,
            color: const Color(0xFF0052CC).withOpacity(0.6),
          ),
        ),
      );
    } else if (isStandard) {
      badge = Tooltip(
        message: 'Tags not assigned to any folder',
        child: Padding(
          padding: const EdgeInsets.only(right: 4),
          child: Icon(Icons.inbox_outlined, size: 11, color: Colors.white24),
        ),
      );
    }

    final displayKey = isStandard ? 'Standard Folder' : folderKey;

    // The folder itself is a DragTarget — mirror sidebar drop logic
    return DragTarget<String>(
      onWillAcceptWithDetails: (d) => !items.contains(d.data),
      onAcceptWithDetails: (d) =>
          _moveToFolder(d.data, isStandard ? null : folderKey),
      builder: (ctx, candidates, _) {
        final isOver = candidates.isNotEmpty;
        return AnimatedContainer(
          duration: const Duration(milliseconds: 100),
          margin: const EdgeInsets.fromLTRB(12, 6, 12, 0),
          decoration: BoxDecoration(
            color: isOver
                ? _accent.withOpacity(0.04)
                : _surface.withOpacity(0.5),
            borderRadius: BorderRadius.circular(8),
            border: Border.all(
              color: isOver ? _accent.withOpacity(0.3) : _border,
            ),
          ),
          child: Column(
            crossAxisAlignment: CrossAxisAlignment.stretch,
            children: [
              // Header row — tappable to collapse
              InkWell(
                onTap: () => setState(() {
                  if (isCollapsed)
                    _collapsed.remove(folderKey);
                  else
                    _collapsed.add(folderKey);
                }),
                borderRadius: const BorderRadius.vertical(
                  top: Radius.circular(8),
                ),
                child: Padding(
                  padding: const EdgeInsets.fromLTRB(10, 8, 8, 8),
                  child: Row(
                    children: [
                      AnimatedRotation(
                        turns: isCollapsed ? -0.25 : 0,
                        duration: const Duration(milliseconds: 150),
                        child: const Icon(
                          Icons.expand_more_rounded,
                          size: 13,
                          color: Colors.white30,
                        ),
                      ),
                      const SizedBox(width: 5),
                      Icon(Icons.folder_rounded, size: 13, color: folderColor),
                      const SizedBox(width: 7),
                      Expanded(
                        child: isRenaming
                            ? TextField(
                                controller: _renameFolderCtrl,
                                autofocus: true,
                                style: const TextStyle(
                                  fontSize: 12,
                                  color: Colors.white,
                                ),
                                decoration: const InputDecoration(
                                  isDense: true,
                                  contentPadding: EdgeInsets.zero,
                                  border: InputBorder.none,
                                ),
                                onSubmitted: (v) => _renameFolder(folderKey, v),
                              )
                            : Text(
                                displayKey,
                                style: TextStyle(
                                  fontSize: 12,
                                  fontWeight: FontWeight.w600,
                                  color: isTrello ? _accent : Colors.white70,
                                ),
                              ),
                      ),
                      if (badge != null) badge,
                      // Item count
                      Container(
                        padding: const EdgeInsets.symmetric(
                          horizontal: 5,
                          vertical: 1,
                        ),
                        decoration: BoxDecoration(
                          color: Colors.white.withOpacity(0.06),
                          borderRadius: BorderRadius.circular(8),
                        ),
                        child: Text(
                          '${items.length}',
                          style: const TextStyle(
                            fontSize: 9,
                            fontWeight: FontWeight.bold,
                            color: Colors.white30,
                          ),
                        ),
                      ),
                      const SizedBox(width: 4),
                      // Drop hint
                      if (isOver)
                        Icon(
                          Icons.add_rounded,
                          size: 12,
                          color: _accent.withOpacity(0.7),
                        ),
                      // Eye (whole folder)
                      Tooltip(
                        message: allHidden
                            ? 'Show all in sidebar'
                            : 'Hide all from sidebar',
                        child: InkWell(
                          onTap: () {
                            for (final k in items) _setHidden(k, !allHidden);
                          },
                          borderRadius: BorderRadius.circular(4),
                          child: Padding(
                            padding: const EdgeInsets.all(4),
                            child: Icon(
                              allHidden
                                  ? Icons.visibility_off_outlined
                                  : Icons.visibility_outlined,
                              size: 13,
                              color: allHidden
                                  ? Colors.white24
                                  : Colors.white30,
                            ),
                          ),
                        ),
                      ),
                      // Rename
                      if (!isProtected)
                        Tooltip(
                          message: 'Rename folder',
                          child: InkWell(
                            onTap: () {
                              _renameFolderCtrl.text = folderKey;
                              setState(() => _renamingFolder = folderKey);
                            },
                            borderRadius: BorderRadius.circular(4),
                            child: Padding(
                              padding: const EdgeInsets.all(4),
                              child: Icon(
                                Icons.edit_outlined,
                                size: 12,
                                color: Colors.white24,
                              ),
                            ),
                          ),
                        ),
                      // Delete
                      if (!isProtected)
                        Tooltip(
                          message: 'Delete folder (items move to Standard)',
                          child: InkWell(
                            onTap: () => _deleteFolder(folderKey),
                            borderRadius: BorderRadius.circular(4),
                            child: Padding(
                              padding: const EdgeInsets.all(4),
                              child: Icon(
                                Icons.delete_outline,
                                size: 12,
                                color: Colors.redAccent.withOpacity(0.55),
                              ),
                            ),
                          ),
                        ),
                    ],
                  ),
                ),
              ),
              // Items — animate in/out on collapse
              AnimatedSize(
                duration: const Duration(milliseconds: 180),
                curve: Curves.easeInOut,
                alignment: Alignment.topCenter,
                child: isCollapsed
                    ? const SizedBox.shrink()
                    : Column(
                        crossAxisAlignment: CrossAxisAlignment.stretch,
                        children: [
                          if (items.isNotEmpty)
                            const Divider(color: _border, height: 1),
                          ...items.map(
                            (k) => _itemRow(
                              k,
                              currentFolder: isStandard ? null : folderKey,
                            ),
                          ),
                          if (items.isEmpty)
                            Padding(
                              padding: const EdgeInsets.fromLTRB(14, 8, 14, 10),
                              child: Text(
                                'Long-press a tag and drag it here',
                                style: TextStyle(
                                  fontSize: 11,
                                  color: isOver
                                      ? _accent.withOpacity(0.5)
                                      : Colors.white.withOpacity(0.24),
                                  fontStyle: FontStyle.italic,
                                ),
                              ),
                            ),
                        ],
                      ),
              ),
            ],
          ),
        );
      },
    );
  }

  // ── Build ─────────────────────────────────────────────────────────────────

