    final standardItems = _standardItems;

    // Ordered folder keys: user folders first, then Trello board folders
    final trelloKeys = widget.isProjects
        ? <String>[]
        : widget.savedBoards
              .map((b) => b['title'] as String? ?? '')
              .where((n) => n.isNotEmpty && folders.containsKey(n))
              .toList();
    final userFolders =
        folders.keys.where((k) => !trelloKeys.contains(k)).toList()..sort();

    return Container(
      color: _bg,
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.stretch,
        children: [
          // ── Toolbar ──────────────────────────────────────────────────────
          Container(
            padding: const EdgeInsets.fromLTRB(16, 10, 16, 10),
            decoration: const BoxDecoration(
              color: Color(0xFF212426),
              border: Border(bottom: BorderSide(color: _border)),
            ),
            child: Row(
              children: [
                // ── Search field (expands when active) ──────────────────
                AnimatedContainer(
                  duration: const Duration(milliseconds: 180),
