                              const SizedBox(width: 5),
                              Expanded(
                                child: TextField(
                                  controller: _searchCtrl,
                                  autofocus: true,
                                  style: const TextStyle(
                                    fontSize: 11,
                                    color: Colors.white,
                                  ),
                                  decoration: const InputDecoration(
                                    hintText: 'Search…',
                                    hintStyle: TextStyle(
                                      fontSize: 11,
                                      color: Colors.white30,
