                            ],
                            style: const TextStyle(
                              fontSize: 12,
                              color: Colors.white,
                            ),
                            decoration: const InputDecoration(
                              hintText: 'Project name…',
                              hintStyle: TextStyle(
                                fontSize: 12,
                                color: Colors.white30,
                              ),
                              isDense: true,
                              contentPadding: EdgeInsets.zero,
                              border: InputBorder.none,
                            ),
                            onSubmitted: _createProject,
                          ),
                        ),
                        const SizedBox(width: 12),
                        TextButton(
                          onPressed: () => _createProject(_newProjectCtrl.text),
                          child: const Text(
                            'Create',
                            style: TextStyle(fontSize: 11, color: _accent),
                          ),
                        ),
                        TextButton(
                          onPressed: () => setState(() {
                            _addingProject = false;
                            _newProjectCtrl.clear();
                            _newProjectColor = Colors.blueAccent;
                          }),
                          child: const Text(
                            'Cancel',
                            style: TextStyle(
                              fontSize: 11,
                              color: Colors.white38,
                            ),
                          ),
                        ),
                      ],
                    ),
                    const SizedBox(height: 8),
                    // Feature 4: full color picker instead of preset grid
                    Row(
                      children: [
                        // Live preview chip
                        GestureDetector(
                          onTap: () {
                            widget.onShowColorPicker?.call(
                              title: 'Project Color',
                              initialColor: _newProjectColor,
                              onApply: (c) =>
                                  setState(() => _newProjectColor = c),
                              colorContext: 'projectColor',
                            );
                          },
                          child: AnimatedContainer(
                            duration: const Duration(milliseconds: 150),
                            width: 28,
                            height: 28,
                            decoration: BoxDecoration(
                              color: _newProjectColor,
                              borderRadius: BorderRadius.circular(6),
                              border: Border.all(
                                color: Colors.white.withOpacity(0.25),
                                width: 1.5,
                              ),
                            ),
                          ),
                        ),
                        const SizedBox(width: 10),
                        // Preview chip with project name
                        Expanded(
                          child: Container(
                            padding: const EdgeInsets.symmetric(
                              horizontal: 10,
                              vertical: 6,
                            ),
                            decoration: BoxDecoration(
                              color: _newProjectColor.withOpacity(0.12),
                              borderRadius: BorderRadius.circular(6),
                              border: Border.all(
                                color: _newProjectColor.withOpacity(0.4),
                              ),
                            ),
                            child: Row(
                              children: [
                                Container(
                                  width: 8,
                                  height: 8,
                                  decoration: BoxDecoration(
                                    color: _newProjectColor,
                                    shape: BoxShape.circle,
                                  ),
                                ),
                                const SizedBox(width: 6),
                                Expanded(
                                  child: Text(
                                    _newProjectCtrl.text.isEmpty
                                        ? 'Project name…'
                                        : _newProjectCtrl.text,
                                    style: TextStyle(
                                      fontSize: 11,
                                      color: _newProjectCtrl.text.isEmpty
                                          ? Colors.white30
                                          : Colors.white.withOpacity(0.85),
                                    ),
                                    overflow: TextOverflow.ellipsis,
                                  ),
                                ),
                              ],
                            ),
                          ),
                        ),
                        const SizedBox(width: 8),
                        Tooltip(
                          message: 'Pick color',
                          child: GestureDetector(
                            onTap: () {
                              widget.onShowColorPicker?.call(
                                title: 'Project Color',
                                initialColor: _newProjectColor,
                                onApply: (c) =>
                                    setState(() => _newProjectColor = c),
                                colorContext: 'projectColor',
                              );
                            },
                            child: Container(
                              padding: const EdgeInsets.symmetric(
                                horizontal: 10,
                                vertical: 6,
                              ),
                              decoration: BoxDecoration(
                                color: Colors.white.withOpacity(0.06),
                                borderRadius: BorderRadius.circular(5),
                                border: Border.all(color: Colors.white12),
                              ),
                              child: Row(
                                mainAxisSize: MainAxisSize.min,
                                children: const [
                                  Icon(
                                    Icons.color_lens_outlined,
                                    size: 13,
                                    color: Colors.white54,
                                  ),
                                  SizedBox(width: 4),
                                  Text(
                                    'Color',
                                    style: TextStyle(
                                      fontSize: 10,
                                      color: Colors.white54,
                                    ),
                                  ),
                                ],
                              ),
                            ),
                          ),
                        ),
                      ],
                    ),
                  ],
                ),
              ),
            ),
          // ── New tag input ────────────────────────────────────────────
          if (_addingTag)
            Container(
              color: _surface,
              padding: const EdgeInsets.fromLTRB(14, 8, 14, 8),
              child: Row(
                children: [
                  const Icon(Icons.label_outlined, size: 14, color: _accent),
                  const SizedBox(width: 8),
                  Expanded(
                    child: TextField(
                      controller: _newTagCtrl,
                      autofocus: true,
                      style: const TextStyle(fontSize: 12, color: Colors.white),
                      decoration: const InputDecoration(
                        hintText: 'Tag name…',
                        hintStyle: TextStyle(
                          fontSize: 12,
                          color: Colors.white30,
                        ),
                        isDense: true,
                        contentPadding: EdgeInsets.zero,
                        border: InputBorder.none,
                      ),
                      onSubmitted: _createTag,
                    ),
                  ),
                  const SizedBox(width: 10),
                  // Optional project picker
                  PopupMenuButton<String?>(
                    tooltip: 'Link to project (optional)',
                    color: const Color(0xFF1E2124),
                    child: Container(
                      padding: const EdgeInsets.symmetric(
                        horizontal: 8,
                        vertical: 4,
                      ),
                      decoration: BoxDecoration(
                        color: _newTagProjectId != null
                            ? _accent.withOpacity(0.12)
                            : Colors.white.withOpacity(0.06),
                        borderRadius: BorderRadius.circular(5),
                        border: Border.all(
                          color: _newTagProjectId != null
                              ? _accent.withOpacity(0.3)
                              : Colors.white12,
                        ),
                      ),
                      child: Row(
                        mainAxisSize: MainAxisSize.min,
                        children: [
                          Icon(
                            Icons.folder_outlined,
                            size: 12,
                            color: _newTagProjectId != null
                                ? _accent
                                : Colors.white38,
                          ),
                          const SizedBox(width: 5),
                          Text(
                            _newTagProjectId != null
                                ? (widget.projects[_newTagProjectId]?.title ??
                                      'Project')
                                : 'No project',
                            style: TextStyle(
                              fontSize: 11,
                              color: _newTagProjectId != null
                                  ? _accent
                                  : Colors.white38,
                            ),
                          ),
                        ],
                      ),
                    ),
                    itemBuilder: (_) => [
                      PopupMenuItem<String?>(
                        value: null,
                        child: Text(
                          'No project',
                          style: TextStyle(
                            fontSize: 12,
                            color: _newTagProjectId == null
                                ? _accent
                                : Colors.white70,
                          ),
                        ),
                      ),
                      ...widget.projectOrder.map((pid) {
                        final title = widget.projects[pid]?.title ?? pid;
                        return PopupMenuItem<String?>(
                          value: pid,
                          child: Text(
                            title,
                            style: TextStyle(
                              fontSize: 12,
                              color: _newTagProjectId == pid
                                  ? _accent
                                  : Colors.white70,
                            ),
                          ),
                        );
                      }),
                    ],
                    onSelected: (pid) => setState(() => _newTagProjectId = pid),
                  ),
                  const SizedBox(width: 4),
                  TextButton(
                    onPressed: () => _createTag(_newTagCtrl.text),
                    child: const Text(
                      'Add',
                      style: TextStyle(fontSize: 11, color: _accent),
                    ),
                  ),
                  TextButton(
                    onPressed: () => setState(() {
                      _addingTag = false;
                      _newTagCtrl.clear();
                      _newTagProjectId = null;
                    }),
                    child: const Text(
                      'Cancel',
                      style: TextStyle(fontSize: 11, color: Colors.white38),
                    ),
                  ),
                ],
              ),
            ),
          // ── New folder input ──────────────────────────────────────────
          if (_addingFolder)
            Container(
              color: _surface,
              padding: const EdgeInsets.fromLTRB(14, 8, 14, 8),
              child: Row(
                children: [
                  const Icon(Icons.folder_outlined, size: 14, color: _accent),
                  const SizedBox(width: 8),
                  Expanded(
                    child: TextField(
                      controller: _newFolderCtrl,
                      autofocus: true,
                      style: const TextStyle(fontSize: 12, color: Colors.white),
                      decoration: const InputDecoration(
                        hintText: 'Folder name…',
                        hintStyle: TextStyle(
                          fontSize: 12,
                          color: Colors.white30,
                        ),
                        isDense: true,
                        contentPadding: EdgeInsets.zero,
                        border: InputBorder.none,
                      ),
                      onSubmitted: _createFolder,
                    ),
                  ),
                  TextButton(
                    onPressed: () => _createFolder(_newFolderCtrl.text),
                    child: const Text(
                      'Create',
                      style: TextStyle(fontSize: 11, color: _accent),
                    ),
                  ),
                  TextButton(
                    onPressed: () => setState(() {
                      _addingFolder = false;
                      _newFolderCtrl.clear();
                    }),
                    child: const Text(
                      'Cancel',
                      style: TextStyle(fontSize: 11, color: Colors.white38),
                    ),
                  ),
                ],
              ),
            ),
          // ── Content ───────────────────────────────────────────────────
          Expanded(
            child: ListView(
              padding: const EdgeInsets.only(top: 6, bottom: 24),
              children: [
                // 1. Standard folder (always first)
                _folderBlock(
                  folderKey: '__standard__',
                  items: _sortedFilteredItems(standardItems),
                  isStandard: true,
                ),
                // 2. User-created folders
                ...userFolders.map(
                  (k) => _folderBlock(
                    folderKey: k,
                    items: _sortedFilteredItems(
                      (folders[k] ?? {}).toList()..sort(),
                    ),
                  ),
                ),
                // 4. Trello board folders
                ...trelloKeys.map(
                  (k) => _folderBlock(
                    folderKey: k,
                    items: _sortedFilteredItems(
                      (folders[k] ?? {}).toList()..sort(),
                    ),
                  ),
                ),
                if (_searchQuery.isNotEmpty &&
                    _allItemKeys.where(_matchesSearch).isEmpty)
                  Padding(
                    padding: const EdgeInsets.only(top: 40),
                    child: Center(
                      child: Text(
                        'No results for "$_searchQuery"',
                        style: const TextStyle(
                          color: Colors.white24,
                          fontSize: 13,
                        ),
                      ),
                    ),
                  )
                else if (_allItemKeys.isEmpty)
                  Padding(
                    padding: const EdgeInsets.only(top: 60),
                    child: Center(
                      child: Text(
                        widget.isProjects ? 'No projects yet' : 'No tags yet',
                        style: const TextStyle(
                          color: Colors.white24,
                          fontSize: 13,
                        ),
                      ),
                    ),
                  ),
              ],
            ),
          ),
        ],
      ),
    );
  }
}

// ─────────────────────────────────────────────────────────────────────────────
// _TagSettingsView  —  individual tag settings: name, color, icon, visibility
// ─────────────────────────────────────────────────────────────────────────────

class _TagSettingsView extends StatefulWidget {
  final String tagName;
  final Color? initialColor;
  final String initialIcon;
  final bool isHidden;
  final Map<String, Set<String>> tagFolders;
  final void Function({
    required String newName,
    required Color? color,
    required String icon,
    required bool hidden,
  })
  onChanged;

  const _TagSettingsView({
    Key? key,
    required this.tagName,
    required this.initialColor,
    required this.initialIcon,
    required this.isHidden,
    required this.tagFolders,
    required this.onChanged,
  }) : super(key: key);

  @override
  State<_TagSettingsView> createState() => _TagSettingsViewState();
}

class _TagSettingsViewState extends State<_TagSettingsView> {
  static const _bg = Color(0xFF181A1B);
  static const _surface = Color(0xFF212426);
  static const _border = Color(0xFF2C2F32);
  static const _accent = Color(0xFF4FC3F7);
  static const _FB = <String>[
    'NotoColorEmoji',
    'Apple Color Emoji',
    'Segoe UI Emoji',
  ];

  late final TextEditingController _nameCtrl;
  late final TextEditingController _iconCtrl;
  late Color? _color;
  late bool _hidden;

  // Emoji picker overlay
  final LayerLink _layerLink = LayerLink();
  OverlayEntry? _emojiOverlay;
  bool _emojiOpen = false;

  @override
  void initState() {
    super.initState();
    _nameCtrl = TextEditingController(text: widget.tagName);
    _iconCtrl = TextEditingController(text: widget.initialIcon);
    _color = widget.initialColor;
    _hidden = widget.isHidden;
    _iconCtrl.addListener(() => setState(() {}));
  }

  @override
  void dispose() {
    _closeEmoji();
    _nameCtrl.dispose();
    _iconCtrl.dispose();
    super.dispose();
  }

  void _save() {
    widget.onChanged(
      newName: _nameCtrl.text.trim().isEmpty
          ? widget.tagName
          : _nameCtrl.text.trim(),
      color: _color,
      icon: _iconCtrl.text.trim(),
      hidden: _hidden,
    );
  }

  void _openEmoji() {
    final overlay = Overlay.of(context);
    _emojiOverlay = OverlayEntry(
      builder: (_) => _EmojiPickerOverlay(
        layerLink: _layerLink,
        accentColor: _color ?? _accent,
        onSelect: (e) {
          _iconCtrl.text = e;
          _iconCtrl.selection = TextSelection.collapsed(offset: e.length);
          _closeEmoji();
          _save();
        },
        onClose: _closeEmoji,
      ),
    );
    overlay.insert(_emojiOverlay!);
    setState(() => _emojiOpen = true);
  }

  void _closeEmoji() {
    _emojiOverlay?.remove();
    _emojiOverlay = null;
    if (mounted) setState(() => _emojiOpen = false);
  }

  // ── Colour palette (mirrors project settings) ─────────────────────────────
  static const _palette = <Color>[
    Color(0xFF4FC3F7), // cyan
    Colors.blueAccent,
    Color(0xFF4CAF50), // green
    Color(0xFFE91E63), // pink
    Color(0xFFFF9800), // orange
    Color(0xFF9C27B0), // purple
    Color(0xFFFFD600), // yellow
    Color(0xFF00BCD4), // teal
    Color(0xFFF44336), // red
    Color(0xFF8BC34A), // light green
    Color(0xFFFF5722), // deep orange
    Color(0xFF607D8B), // blue grey
  ];

  Widget _section(String label, Widget child) => Column(
    crossAxisAlignment: CrossAxisAlignment.start,
    children: [
      Padding(
        padding: const EdgeInsets.fromLTRB(16, 20, 16, 8),
        child: Text(
          label.toUpperCase(),
          style: const TextStyle(
            fontSize: 9,
            fontWeight: FontWeight.bold,
            color: Colors.white24,
            letterSpacing: 1.2,
          ),
        ),
      ),
      child,
      const Divider(color: _border, height: 1),
    ],
  );

  @override
  Widget build(BuildContext context) {
    final icon = _iconCtrl.text.trim();
    final effectiveColor = _color ?? _accent;

    return Container(
      color: _bg,
      child: ListView(
        padding: const EdgeInsets.only(bottom: 40),
        children: [
          // ── Tag identity header ────────────────────────────────────────
          Container(
            padding: const EdgeInsets.fromLTRB(16, 20, 16, 16),
            decoration: const BoxDecoration(
              color: _surface,
              border: Border(bottom: BorderSide(color: _border)),
            ),
            child: Row(
              children: [
                // Color dot / icon preview
                Container(
                  width: 44,
                  height: 44,
                  decoration: BoxDecoration(
                    color: effectiveColor.withOpacity(0.15),
                    borderRadius: BorderRadius.circular(10),
                    border: Border.all(color: effectiveColor.withOpacity(0.4)),
                  ),
                  child: Center(
                    child: icon.isNotEmpty
                        ? Text(
                            icon,
                            style: TextStyle(
                              fontSize: 22,
                              fontFamilyFallback: _FB,
                            ),
                          )
                        : Icon(
                            Icons.label_rounded,
                            size: 22,
                            color: effectiveColor,
                          ),
                  ),
                ),
                const SizedBox(width: 14),
                Expanded(
                  child: TextField(
                    controller: _nameCtrl,
                    style: const TextStyle(
                      color: Colors.white,
                      fontSize: 16,
                      fontWeight: FontWeight.w600,
                    ),
                    decoration: const InputDecoration(
                      hintText: 'Tag name',
                      hintStyle: TextStyle(color: Colors.white30),
                      border: InputBorder.none,
                      isDense: true,
                      contentPadding: EdgeInsets.zero,
                    ),
                    onSubmitted: (_) => _save(),
                    onEditingComplete: _save,
                  ),
                ),
              ],
            ),
          ),

          // ── Icon ──────────────────────────────────────────────────────
          _section(
            'Icon',
            Container(
              color: _surface,
              padding: const EdgeInsets.fromLTRB(16, 8, 16, 12),
              child: Row(
                children: [
                  Expanded(
                    child: TextField(
                      controller: _iconCtrl,
                      style: TextStyle(
                        color: Colors.white,
                        fontSize: 16,
                        fontFamilyFallback: _FB,
                      ),
                      decoration: const InputDecoration(
                        hintText: 'Paste any emoji…',
                        hintStyle: TextStyle(
                          fontSize: 13,
                          color: Colors.white30,
                        ),
                        border: InputBorder.none,
                        isDense: true,
                        contentPadding: EdgeInsets.zero,
                      ),
                      onChanged: (v) {
                        final t = v.characters.isEmpty
                            ? ''
                            : v.characters.first;
                        if (t != v) {
                          _iconCtrl.value = TextEditingValue(
                            text: t,
                            selection: TextSelection.collapsed(
                              offset: t.length,
                            ),
                          );
                        }
                        setState(() {});
                        _save();
                      },
                    ),
                  ),
                  const SizedBox(width: 8),
                  // Emoji picker button
                  CompositedTransformTarget(
                    link: _layerLink,
                    child: GestureDetector(
                      onTap: _emojiOpen ? _closeEmoji : _openEmoji,
                      child: AnimatedContainer(
                        duration: const Duration(milliseconds: 150),
                        width: 36,
                        height: 36,
                        decoration: BoxDecoration(
                          color: _emojiOpen
                              ? effectiveColor.withOpacity(0.22)
                              : effectiveColor.withOpacity(0.08),
                          borderRadius: BorderRadius.circular(8),
                          border: Border.all(
                            color: _emojiOpen
                                ? effectiveColor.withOpacity(0.75)
                                : effectiveColor.withOpacity(0.28),
                          ),
                        ),
                        child: Center(
                          child: icon.isNotEmpty
                              ? Text(
                                  icon,
                                  style: TextStyle(
                                    fontSize: 18,
                                    fontFamilyFallback: _FB,
                                  ),
                                )
                              : Icon(
                                  Icons.emoji_emotions_outlined,
                                  size: 16,
                                  color: effectiveColor,
                                ),
                        ),
                      ),
                    ),
                  ),
                  if (icon.isNotEmpty) ...[
                    const SizedBox(width: 6),
                    Tooltip(
                      message: 'Clear icon',
                      child: InkWell(
                        onTap: () {
                          _iconCtrl.clear();
                          setState(() {});
                          _save();
                        },
                        borderRadius: BorderRadius.circular(4),
                        child: const Padding(
                          padding: EdgeInsets.all(5),
                          child: Icon(
                            Icons.clear_rounded,
                            size: 14,
                            color: Colors.white38,
                          ),
                        ),
                      ),
                    ),
                  ],
                ],
              ),
            ),
          ),

          // ── Color ─────────────────────────────────────────────────────
          _section(
            'Color',
            Container(
              color: _surface,
              padding: const EdgeInsets.fromLTRB(16, 10, 16, 14),
              child: Column(
                crossAxisAlignment: CrossAxisAlignment.start,
                children: [
                  Wrap(
                    spacing: 10,
                    runSpacing: 10,
                    children: [
                      // No color
                      Tooltip(
                        message: 'Default (no color)',
                        child: GestureDetector(
                          onTap: () => setState(() {
                            _color = null;
                            _save();
                          }),
                          child: Container(
                            width: 26,
                            height: 26,
                            decoration: BoxDecoration(
                              color: Colors.transparent,
                              shape: BoxShape.circle,
                              border: Border.all(
                                color: _color == null
                                    ? Colors.white
                                    : Colors.white24,
                                width: _color == null ? 2 : 1,
                              ),
                            ),
                            child: _color == null
                                ? const Icon(
                                    Icons.close_rounded,
                                    size: 13,
                                    color: Colors.white54,
                                  )
                                : null,
                          ),
                        ),
                      ),
                      ..._palette.map((c) {
                        final sel = _color == c;
                        return GestureDetector(
                          onTap: () => setState(() {
                            _color = c;
                            _save();
                          }),
                          child: Container(
                            width: 26,
                            height: 26,
                            decoration: BoxDecoration(
                              color: c,
                              shape: BoxShape.circle,
                              border: Border.all(
                                color: sel ? Colors.white : Colors.transparent,
                                width: 2,
                              ),
                            ),
                          ),
                        );
                      }),
                    ],
                  ),
                ],
              ),
            ),
          ),

          // ── Visibility ────────────────────────────────────────────────
          _section(
            'Sidebar',
            Container(
              color: _surface,
              child: SwitchListTile(
                title: const Text(
                  'Show in sidebar',
                  style: TextStyle(color: Colors.white70, fontSize: 13),
                ),
                subtitle: Text(
                  _hidden
                      ? 'This tag is hidden from the sidebar'
                      : 'This tag appears in the sidebar',
                  style: TextStyle(color: Colors.white38, fontSize: 11),
                ),
                value: !_hidden,
                activeColor: _accent,
                onChanged: (v) {
                  setState(() => _hidden = !v);
                  _save();
                },
              ),
            ),
          ),

          // ── Folder ────────────────────────────────────────────────────
          _section(
            'Folder',
            Container(
              color: _surface,
              padding: const EdgeInsets.fromLTRB(16, 8, 16, 12),
              child: Builder(
                builder: (ctx) {
                  final currentFolder = widget.tagFolders.entries
                      .where((e) => e.value.contains(widget.tagName))
                      .map((e) => e.key)
                      .firstOrNull;
                  final folders = widget.tagFolders.keys.toList()..sort();

                  return PopupMenuButton<String?>(
                    tooltip: 'Assign to folder',
                    color: const Color(0xFF1E2124),
                    child: Container(
                      padding: const EdgeInsets.symmetric(
                        horizontal: 12,
                        vertical: 8,
                      ),
                      decoration: BoxDecoration(
                        color: _bg,
                        borderRadius: BorderRadius.circular(6),
                        border: Border.all(color: _border),
                      ),
                      child: Row(
                        mainAxisSize: MainAxisSize.min,
                        children: [
                          Icon(
                            Icons.folder_outlined,
                            size: 14,
                            color: currentFolder != null
                                ? _accent
                                : Colors.white38,
                          ),
                          const SizedBox(width: 8),
                          Text(
                            currentFolder ?? 'Standard Folder',
                            style: TextStyle(
                              fontSize: 12,
                              color: currentFolder != null
                                  ? _accent
                                  : Colors.white54,
                            ),
                          ),
                          const SizedBox(width: 6),
                          const Icon(
                            Icons.arrow_drop_down_rounded,
                            size: 16,
                            color: Colors.white38,
                          ),
                        ],
                      ),
                    ),
                    itemBuilder: (_) => [
                      PopupMenuItem<String?>(
                        value: null,
                        child: Text(
                          'Standard Folder',
                          style: TextStyle(
                            fontSize: 12,
                            color: currentFolder == null
                                ? _accent
                                : Colors.white70,
                          ),
                        ),
                      ),
                      ...folders.map(
                        (f) => PopupMenuItem<String?>(
                          value: f,
                          child: Text(
                            f,
                            style: TextStyle(
                              fontSize: 12,
                              color: currentFolder == f
                                  ? _accent
                                  : Colors.white70,
                            ),
                          ),
                        ),
                      ),
                    ],
                    onSelected: (f) {
                      // Move tag to chosen folder
                      for (final s in widget.tagFolders.values) {
                        s.remove(widget.tagName);
                      }
                      if (f != null) {
                        widget.tagFolders
                            .putIfAbsent(f, () => {})
                            .add(widget.tagName);
                      }
                      _save();
                    },
                  );
                },
              ),
            ),
          ),
        ],
      ),
    );
  }
}

class _SidebarResizeHandle extends StatefulWidget {
  final void Function(double dx) onDrag;
  final VoidCallback onDoubleTap;

  const _SidebarResizeHandle({
    Key? key,
    required this.onDrag,
    required this.onDoubleTap,
  }) : super(key: key);

  @override
  State<_SidebarResizeHandle> createState() => _SidebarResizeHandleState();
}

class _SidebarResizeHandleState extends State<_SidebarResizeHandle> {
  bool _hovered = false;
  bool _dragging = false;

  @override
  Widget build(BuildContext context) {
    final active = _hovered || _dragging;
    return MouseRegion(
      cursor: SystemMouseCursors.resizeColumn,
      onEnter: (_) => setState(() => _hovered = true),
      onExit: (_) => setState(() => _hovered = false),
      child: GestureDetector(
        behavior: HitTestBehavior.opaque,
        onHorizontalDragStart: (_) => setState(() => _dragging = true),
        onHorizontalDragUpdate: (d) => widget.onDrag(d.delta.dx),
        onHorizontalDragEnd: (_) => setState(() => _dragging = false),
        onDoubleTap: widget.onDoubleTap,
        child: SizedBox(
          width: 8,
          child: Center(
            child: AnimatedContainer(
              duration: const Duration(milliseconds: 120),
              width: active ? 2 : 1,
              color: active
                  ? const Color(0xFF4FC3F7).withOpacity(0.6)
                  : Colors.white.withOpacity(0.07),
            ),
          ),
        ),
      ),
    );
  }
}

// ─────────────────────────────────────────────────────────────────────────────
// _TimeTrackingPanel  –  floating day timeline popup
// ─────────────────────────────────────────────────────────────────────────────

class _TimeTrackingPanel extends StatefulWidget {
  final List<Task> allTasks;
  final String? activeTimerTaskId;
  final DateTime? timerStartedAt;
  final Map<String, Project> projects;
  final _ExecutionViewMode execViewMode;
  final Map<String, List<_ExecutionSession>> taskSessions;

  const _TimeTrackingPanel({
    Key? key,
    required this.allTasks,
    required this.activeTimerTaskId,
    required this.timerStartedAt,
    required this.projects,
    this.execViewMode = _ExecutionViewMode.planning,
    this.taskSessions = const {},
  }) : super(key: key);

  @override
  State<_TimeTrackingPanel> createState() => _TimeTrackingPanelState();
}

class _TimeTrackingPanelState extends State<_TimeTrackingPanel>
    with SingleTickerProviderStateMixin {
  late final AnimationController _pulse;

  // Timeline spans 6 AM – midnight (18 hours)
  static const int _startHour = 0;
  static const int _endHour = 24;
  static const int _spanHours = _endHour - _startHour;

  @override
  void initState() {
    super.initState();
    _pulse = AnimationController(
      vsync: this,
      duration: const Duration(milliseconds: 1200),
    )..repeat(reverse: true);
  }

  @override
  void dispose() {
    _pulse.dispose();
    super.dispose();
  }

  // Project index → color (cycles through palette)
  static const List<Color> _palette = [
    Color(0xFF4FC3F7),
    Color(0xFF81C784),
    Color(0xFFFFB74D),
    Color(0xFFBA68C8),
    Color(0xFF4DB6AC),
    Color(0xFFFF8A65),
    Color(0xFF90CAF9),
    Color(0xFFF48FB1),
  ];

  Color _projectColor(String projectId, int idx) =>
      _palette[idx % _palette.length];

  double _hourToFraction(double hour) =>
      ((hour - _startHour) / _spanHours).clamp(0.0, 1.0);

  @override
  Widget build(BuildContext context) {
    final now = DateTime.now();
    final today = DateTime(now.year, now.month, now.day);

    // Build ordered project color map
    final projectIds = widget.projects.keys.toList();

    // ── Build PLANNING blocks (planned schedule) ──────────────────────────
    final planningBlocks = <_TrackBlock>[];
    // ── Build EXECUTION blocks (actual tracked sessions) ───────────────────
    final executionBlocks = <_TrackBlock>[];

    for (final t in widget.allTasks) {
      final isActive = t.id == widget.activeTimerTaskId;
      final dt = t.scheduledDateTime;
      final colorIdx = projectIds.indexOf(t.projectId);
      final color = _projectColor(t.projectId, colorIdx < 0 ? 0 : colorIdx);

      // Planning lane: tasks with a scheduled time today
      if (dt != null) {
        final dayOf = DateTime(dt.year, dt.month, dt.day);
        if (dayOf == today) {
          final durH = t.durationMinutes / 60.0;
          if (durH > 0) {
            final startHour = dt.hour + dt.minute / 60.0;
            planningBlocks.add(
              _TrackBlock(
                task: t,
                startHour: startHour,
                durationH: durH.clamp(0.01, 24.0),
                color: color,
                isActive: isActive,
                segments: [],
              ),
            );
          }
        }
      }

      // Execution lane: actual recorded sessions for any task (today)
      final sessions = widget.taskSessions[t.id] ?? [];
      for (final session in sessions) {
        final sStart = session.startTime;
        final sDay = DateTime(sStart.year, sStart.month, sStart.day);
        if (sDay != today) continue;
        final startHour =
            sStart.hour + sStart.minute / 60.0 + sStart.second / 3600.0;
        final durH = session.duration.inSeconds / 3600.0;
        if (durH <= 0.001) continue;
        final segs = _buildSessionSegs(session, color);
        executionBlocks.add(
          _TrackBlock(
            task: t,
            startHour: startHour,
            durationH: durH.clamp(0.01, 24.0),
            color: color,
            isActive: session.status == _SessionStatus.running,
            segments: segs,
            sessionStatus: session.status,
          ),
        );
      }
      // Active running timer not yet logged
      if (isActive && widget.timerStartedAt != null && sessions.isEmpty) {
        final sStart = widget.timerStartedAt!;
        final sDay = DateTime(sStart.year, sStart.month, sStart.day);
        if (sDay == today) {
          final startHour =
              sStart.hour + sStart.minute / 60.0 + sStart.second / 3600.0;
          final durH = DateTime.now().difference(sStart).inSeconds / 3600.0;
          if (durH > 0.001) {
            executionBlocks.add(
              _TrackBlock(
                task: t,
                startHour: startHour,
                durationH: durH.clamp(0.01, 24.0),
                color: color,
                isActive: true,
                segments: [],
              ),
            );
          }
        }
      }
    }
    // Keep legacy `blocks` alias pointing to planning for legend + stats
    final blocks = planningBlocks;

    // Total time stats
    final totalSpentMs = widget.allTasks.fold<int>(
      0,
      (s, t) => s + t.timeSpent,
    );
    final totalEstMs = widget.allTasks
        .where(
          (t) =>
              t.status != TaskStatus.done && t.status != TaskStatus.cancelled,
        )
        .fold<int>(0, (s, t) => s + t.durationMinutes * 60000);

    String fmtMs(int ms) {
      final h = ms ~/ 3600000;
      final m = (ms % 3600000) ~/ 60000;
      if (ms <= 0) return '0m';
      if (h > 0 && m > 0) return '${h}h ${m}m';
      if (h > 0) return '${h}h';
      return '${m}m';
    }

    final nowFraction = _hourToFraction(now.hour + now.minute / 60.0);

    return Container(
      decoration: BoxDecoration(
        color: const Color(0xFF1A1C1F),
        borderRadius: BorderRadius.circular(12),
        border: Border.all(color: Colors.white.withOpacity(0.1)),
        boxShadow: [
          BoxShadow(
            color: Colors.black.withOpacity(0.5),
            blurRadius: 24,
            offset: const Offset(0, 8),
          ),
        ],
      ),
      child: Column(
        mainAxisSize: MainAxisSize.min,
        crossAxisAlignment: CrossAxisAlignment.stretch,
        children: [
          // ── Header ────────────────────────────────────────────────────────
          Padding(
            padding: const EdgeInsets.fromLTRB(16, 12, 16, 8),
            child: Row(
              children: [
                const Icon(
                  Icons.timeline_outlined,
                  size: 14,
                  color: Color(0xFF4FC3F7),
                ),
                const SizedBox(width: 8),
                const Text(
                  'TIME TRACKING',
                  style: TextStyle(
                    fontSize: 10,
                    fontWeight: FontWeight.w700,
                    letterSpacing: 1.2,
                    color: Color(0xFF4FC3F7),
                  ),
                ),
                const Spacer(),
                _statPill(
                  'Tracked',
                  fmtMs(totalSpentMs),
                  const Color(0xFF81C784),
                ),
                const SizedBox(width: 10),
                _statPill(
                  'Remaining',
                  fmtMs(totalEstMs),
                  const Color(0xFF4FC3F7),
                ),
              ],
            ),
          ),

          // ── Dual Timeline (Planning + Execution) ───────────────────────
          Padding(
            padding: const EdgeInsets.fromLTRB(16, 0, 16, 4),
            child: LayoutBuilder(
              builder: (_, constraints) {
                final w = constraints.maxWidth;

                Widget timelineLane(
                  List<_TrackBlock> laneBlocks,
                  String label,
                  Color labelColor,
                ) {
                  return Column(
                    crossAxisAlignment: CrossAxisAlignment.start,
                    children: [
                      // Lane label
                      Padding(
                        padding: const EdgeInsets.only(bottom: 2),
                        child: Text(
                          label,
                          style: TextStyle(
                            fontSize: 8,
                            fontWeight: FontWeight.w600,
                            letterSpacing: 0.8,
                            color: labelColor,
                          ),
                        ),
                      ),
                      SizedBox(
                        height: 38,
                        child: Stack(
                          clipBehavior: Clip.none,
                          children: [
                            // Tick marks
                            ...List.generate(25, (i) {
                              final frac = _hourToFraction(i.toDouble());
                              final x = frac * w;
                              return Positioned(
                                left: x - 0.5,
                                top: 0,
                                child: Container(
                                  width: 1,
                                  height: i % 6 == 0
                                      ? 10
                                      : (i % 3 == 0 ? 5 : 2),
                                  color: Colors.white.withOpacity(
                                    i % 6 == 0
                                        ? 0.15
                                        : (i % 3 == 0 ? 0.06 : 0.02),
                                  ),
                                ),
                              );
                            }),
                            // Lane background
                            Positioned(
                              left: 0,
                              right: 0,
                              top: 12,
                              child: Container(
                                height: 22,
                                decoration: BoxDecoration(
                                  color: Colors.white.withOpacity(0.03),
                                  borderRadius: BorderRadius.circular(4),
                                  border: Border.all(
                                    color: Colors.white.withOpacity(0.05),
                                  ),
                                ),
                              ),
                            ),
                            // Blocks
                            ...laneBlocks.map((b) {
                              final x = _hourToFraction(b.startHour) * w;
                              final bw = (b.durationH / _spanHours * w).clamp(
                                4.0,
                                w - x,
                              );
                              if (b.isActive) {
                                return AnimatedBuilder(
                                  animation: _pulse,
                                  builder: (_, __) => Positioned(
                                    left: x,
                                    top: 13,
                                    width: bw,
                                    height: 20,
                                    child: _taskBlock(b, bw, _pulse.value),
                                  ),
                                );
                              }
                              return Positioned(
                                left: x,
                                top: 13,
                                width: bw,
                                height: 20,
                                child: _taskBlock(b, bw, 0),
                              );
                            }),
                            // Now line
                            if (nowFraction >= 0 && nowFraction <= 1)
                              Positioned(
                                left: nowFraction * w - 0.75,
                                top: 0,
                                bottom: 0,
                                child: Container(
                                  width: 1.5,
                                  decoration: BoxDecoration(
                                    color: const Color(0xFFEF5350),
                                    borderRadius: BorderRadius.circular(1),
                                  ),
                                ),
                              ),
                          ],
                        ),
                      ),
                    ],
                  );
                }

                return Column(
                  mainAxisSize: MainAxisSize.min,
                  children: [
                    timelineLane(
                      planningBlocks,
                      'PLANNING',
                      const Color(0xFF4FC3F7),
                    ),
                    const SizedBox(height: 6),
                    timelineLane(
                      executionBlocks,
                      'EXECUTION',
                      const Color(0xFF81C784),
                    ),
                  ],
                );
              },
            ),
          ),

          // ── Hour labels row ───────────────────────────────────────────────
          Padding(
            padding: const EdgeInsets.fromLTRB(16, 0, 16, 4),
            child: Row(
              mainAxisAlignment: MainAxisAlignment.spaceBetween,
              children: [
                for (int h = 0; h <= 24; h += 6)
                  Text(
                    h == 0 || h == 24
                        ? '12AM'
                        : h == 12
                        ? '12PM'
                        : h < 12
                        ? '${h}AM'
                        : '${h - 12}PM',
                    style: const TextStyle(
                      fontSize: 9,
                      color: Color(0xFF454A55),
                    ),
                  ),
              ],
            ),
          ),

          // ── Task legend ───────────────────────────────────────────────────
          if (blocks.isNotEmpty)
            Padding(
              padding: const EdgeInsets.fromLTRB(16, 4, 16, 12),
              child: Wrap(
                spacing: 10,
                runSpacing: 4,
                children: blocks.map((b) {
                  final h = b.durationH;
                  final hh = h.floor();
                  final mm = ((h - hh) * 60).round();
                  final dur = hh > 0
                      ? (mm > 0 ? '${hh}h ${mm}m' : '${hh}h')
                      : '${mm}m';
                  return Row(
                    mainAxisSize: MainAxisSize.min,
                    children: [
                      Container(
                        width: 8,
                        height: 8,
                        decoration: BoxDecoration(
                          color: b.color.withOpacity(0.8),
                          borderRadius: BorderRadius.circular(2),
                        ),
                      ),
                      const SizedBox(width: 5),
                      Text(
                        '${b.task.title}  $dur',
                        style: const TextStyle(
                          fontSize: 10,
                          color: Color(0xFF5A6070),
                        ),
                        overflow: TextOverflow.ellipsis,
                      ),
                      if (b.isActive) ...[
                        const SizedBox(width: 4),
                        const Icon(
                          Icons.circle,
                          size: 5,
                          color: Color(0xFF4CAF50),
                        ),
                      ],
                    ],
                  );
                }).toList(),
              ),
            )
          else
            Padding(
              padding: const EdgeInsets.fromLTRB(16, 4, 16, 14),
              child: Text(
                'No time tracked today. Start a timer on a scheduled task to see it here.',
                style: const TextStyle(fontSize: 10, color: Color(0xFF3A4050)),
              ),
            ),
        ],
      ),
    );
  }

  /// Build work/rest segment bars for a session block (Execution–Detail mode)
  List<_SegBlock> _buildSessionSegs(
    _ExecutionSession session,
    Color taskColor,
  ) {
    final blocks = session.blocksSnapshot;
    if (blocks.isEmpty) return [];
    final totalMs = blocks.fold<int>(0, (s, b) => s + b.minutes) * 60000;
    if (totalMs == 0) return [];
    final durMs = session.duration.inMilliseconds;
    final segs = <_SegBlock>[];
    int remaining = durMs;
    for (final b in blocks) {
      if (remaining <= 0) break;
      final blockMs = b.minutes * 60000;
      final covered = remaining >= blockMs ? blockMs : remaining;
      segs.add(
        _SegBlock(
          frac: covered / durMs,
          color: b.type == _StagingType.work
              ? const Color(0xFF4FC3F7).withOpacity(0.65)
              : const Color(0xFF81C784).withOpacity(0.5),
          label: b.type == _StagingType.work ? 'W' : 'R',
        ),
      );
      remaining -= covered;
    }
    return segs;
  }

  Widget _taskBlock(_TrackBlock b, double bw, double pulse) {
    final isInterrupted = b.sessionStatus == _SessionStatus.interrupted;
    final isCompleted = b.sessionStatus == _SessionStatus.completed;
    final borderColor = isInterrupted
        ? const Color(0xFFFFB74D).withOpacity(0.6 + pulse * 0.2)
        : isCompleted
        ? const Color(0xFF81C784).withOpacity(0.6)
        : b.color.withOpacity(b.isActive ? 0.7 + pulse * 0.3 : 0.4);
    final bgColor = isInterrupted
        ? const Color(0xFFFFB74D).withOpacity(0.12 + pulse * 0.06)
        : isCompleted
        ? const Color(0xFF81C784).withOpacity(0.15)
        : b.color.withOpacity(b.isActive ? 0.25 + pulse * 0.15 : 0.2);

    Widget content;
    if (b.segments.isNotEmpty && bw > 20) {
      // Detail mode: segmented bar
      content = Row(
        children: b.segments
            .map(
              (s) => Expanded(
                flex: (s.frac * 1000).round().clamp(1, 999),
                child: Container(
                  color: s.color,
                  child: bw * s.frac > 16
                      ? Center(
                          child: Text(
                            s.label,
                            style: const TextStyle(
                              fontSize: 7,
                              color: Colors.white54,
                              fontWeight: FontWeight.w700,
                            ),
                          ),
                        )
                      : null,
                ),
              ),
            )
            .toList(),
      );
    } else if (bw > 30) {
      content = Align(
        alignment: Alignment.centerLeft,
        child: Padding(
          padding: const EdgeInsets.symmetric(horizontal: 4),
          child: Text(
            b.task.title,
            style: TextStyle(
              fontSize: 9,
              color: b.color.withOpacity(0.9),
              fontWeight: FontWeight.w500,
            ),
            overflow: TextOverflow.ellipsis,
          ),
        ),
      );
    } else {
      content = const SizedBox.shrink();
    }

    final String durLabel = b.durationH >= 1
        ? '${b.durationH.floor()}h ${((b.durationH % 1) * 60).round()}m'
        : '${((b.durationH) * 60).round()}m';
    final statusSuffix = isInterrupted
        ? ' · interrupted'
        : isCompleted
        ? ' · completed'
        : '';

    return Tooltip(
      message:
          '${b.task.title}\n'
          '${b.startHour.floor()}:${((b.startHour % 1) * 60).round().toString().padLeft(2, '0')}'
          '  ·  $durLabel$statusSuffix',
      child: Container(
        margin: const EdgeInsets.symmetric(horizontal: 1),
        decoration: BoxDecoration(
          color: bgColor,
          borderRadius: BorderRadius.circular(3),
          border: Border.all(color: borderColor, width: b.isActive ? 1.5 : 1),
        ),
        child: ClipRRect(
          borderRadius: BorderRadius.circular(2),
          child: content,
        ),
      ),
    );
  }

  Widget _statPill(String label, String value, Color color) => Row(
    mainAxisSize: MainAxisSize.min,
    children: [
      Text(
        '$label  ',
        style: const TextStyle(fontSize: 10, color: Color(0xFF454A55)),
      ),
      Text(
        value,
        style: TextStyle(
          fontSize: 10,
          fontWeight: FontWeight.w600,
          color: color.withOpacity(0.8),
        ),
      ),
    ],
  );
}

class _SegBlock {
  final double frac; // fraction of the block width
  final Color color;
  final String label;
  const _SegBlock({required this.frac, required this.color, this.label = ''});
}

class _TrackBlock {
  final Task task;
  final double startHour;
  final double durationH;
  final Color color;
  final bool isActive;
  final List<_SegBlock> segments; // non-empty only for Execution–Detail
  final _SessionStatus? sessionStatus;

  const _TrackBlock({
    required this.task,
    required this.startHour,
    required this.durationH,
    required this.color,
    required this.isActive,
    this.segments = const [],
    this.sessionStatus,
  });
}

// ─────────────────────────────────────────────────────────────────────────────
// Task Staging — data + editor widget
// ─────────────────────────────────────────────────────────────────────────────

// ── Execution view modes for the schedule canvas ──────────────────────────
enum _ExecutionViewMode {
  /// Default: shows planned duration blocks only.
  planning,

  /// Shows actual execution session blocks (no segment breakdown).
  execution,

  /// Shows execution session blocks with internal work/rest segment detail.
  executionDetail,
}

/// Compact dropdown for switching [_ExecutionViewMode] in the schedule toolbar.
class _ExecViewDropdown extends StatelessWidget {
  final _ExecutionViewMode value;
  final ValueChanged<_ExecutionViewMode> onChanged;

  const _ExecViewDropdown({
    Key? key,
    required this.value,
    required this.onChanged,
  }) : super(key: key);

  static const _items = [
    (label: 'Planning', value: _ExecutionViewMode.planning),
    (label: 'Execution', value: _ExecutionViewMode.execution),
    (label: 'Exec. Detail', value: _ExecutionViewMode.executionDetail),
  ];

  @override
  Widget build(BuildContext context) {
    return Container(
      height: 28,
      padding: const EdgeInsets.symmetric(horizontal: 8),
      decoration: BoxDecoration(
        color: Colors.white.withOpacity(0.04),
        borderRadius: BorderRadius.circular(4),
        border: Border.all(color: Colors.white10),
      ),
      child: DropdownButton<_ExecutionViewMode>(
        value: value,
        onChanged: (v) {
          if (v != null) onChanged(v);
        },
        underline: const SizedBox.shrink(),
        dropdownColor: const Color(0xFF1E1E2E),
        isDense: true,
        style: const TextStyle(color: Colors.white70, fontSize: 12),
        items: _items
            .map((e) => DropdownMenuItem(value: e.value, child: Text(e.label)))
            .toList(),
      ),
    );
  }
}

enum _StagingType { work, rest }

enum _SessionStatus { running, interrupted, completed }

enum _SessionType { countdown, pomodoro, flowtime }

class _ExecutionSession {
  final String id;
  final DateTime startTime;
  DateTime? endTime;
  _SessionStatus status;
  final List<_StagingBlock> blocksSnapshot;
  final _SessionType sessionType;

  _ExecutionSession({
    required this.id,
    required this.startTime,
    required this.blocksSnapshot,
    this.status = _SessionStatus.running,
    this.endTime,
    _SessionType? sessionType,
  }) : sessionType =
           sessionType ??
           (blocksSnapshot.isEmpty
               ? _SessionType.countdown
               : _SessionType.pomodoro);

  Duration get duration => (endTime ?? DateTime.now()).difference(startTime);

  /// Total work ms spent in this session based on blocks ratio
  int get workMs {
    final total = blocksSnapshot.fold<int>(0, (s, b) => s + b.minutes);
    if (total == 0) return duration.inMilliseconds;
    final workMins = blocksSnapshot
        .where((b) => b.type == _StagingType.work)
        .fold<int>(0, (s, b) => s + b.minutes);
    return (duration.inMilliseconds * workMins / total).round();
  }

  /// Total rest ms spent in this session based on blocks ratio
  int get restMs {
    final total = blocksSnapshot.fold<int>(0, (s, b) => s + b.minutes);
    if (total == 0) return 0;
    final restMins = blocksSnapshot
        .where((b) => b.type == _StagingType.rest)
        .fold<int>(0, (s, b) => s + b.minutes);
    return (duration.inMilliseconds * restMins / total).round();
  }
}

class _StagingBlock {
  _StagingType type;
  int minutes;
  _StagingBlock({required this.type, required this.minutes});
  _StagingBlock copy() => _StagingBlock(type: type, minutes: minutes);
}

class _StagingTimelineEditor extends StatefulWidget {
  final List<_StagingBlock> blocks;
  final ValueChanged<List<_StagingBlock>> onChanged;

  const _StagingTimelineEditor({
    Key? key,
    required this.blocks,
    required this.onChanged,
  }) : super(key: key);

  @override
  State<_StagingTimelineEditor> createState() => _StagingTimelineEditorState();
}

class _StagingTimelineEditorState extends State<_StagingTimelineEditor> {
  // Which block is being edited (minute input focused)
  int? _editingIndex;
  int?
  _hoveredIndex; // tracks which row the cursor is over for the delete button
  late List<_StagingBlock> _blocks;
  final Map<int, TextEditingController> _ctrls = {};

  static const Color _workColor = Color(0xFF4FC3F7);
  static const Color _restColor = Color(0xFF81C784);
  static const Color _workBg = Color(0xFF1A2A35);
  static const Color _restBg = Color(0xFF1A2A1A);

  @override
  void initState() {
    super.initState();
    _blocks = widget.blocks.map((b) => b.copy()).toList();
    _initControllers();
  }

  @override
  void didUpdateWidget(_StagingTimelineEditor old) {
    super.didUpdateWidget(old);
    if (old.blocks != widget.blocks) {
      _blocks = widget.blocks.map((b) => b.copy()).toList();
      _disposeControllers();
      _initControllers();
    }
  }

  void _initControllers() {
    for (int i = 0; i < _blocks.length; i++) {
      _ctrls[i] = TextEditingController(text: '${_blocks[i].minutes}');
    }
  }

  void _disposeControllers() {
    for (final c in _ctrls.values) c.dispose();
    _ctrls.clear();
  }

  @override
  void dispose() {
    _disposeControllers();
    super.dispose();
  }

  void _notify() => widget.onChanged(List.from(_blocks));

  void _addBlock(_StagingType type) {
    setState(() {
      _blocks.add(_StagingBlock(type: type, minutes: 1));
      final i = _blocks.length - 1;
      _ctrls[i] = TextEditingController(text: '1');
    });
    _notify();
  }

  void _removeBlock(int index) {
    setState(() {
      _blocks.removeAt(index);
      _ctrls.remove(index);
      // Re-key controllers
      final newCtrls = <int, TextEditingController>{};
      for (int i = 0; i < _blocks.length; i++) {
        newCtrls[i] =
            _ctrls[i > index ? i + 1 : i] ??
            TextEditingController(text: '${_blocks[i].minutes}');
      }
      _ctrls.clear();
      _ctrls.addAll(newCtrls);
    });
    _notify();
  }

  void _reorder(int oldIndex, int newIndex) {
    setState(() {
      if (newIndex > oldIndex) newIndex--;
      final b = _blocks.removeAt(oldIndex);
      _blocks.insert(newIndex, b);
      // Rebuild controllers preserving values
      final vals = _blocks.map((b) => b.minutes).toList();
      _disposeControllers();
      for (int i = 0; i < _blocks.length; i++) {
        _ctrls[i] = TextEditingController(text: '${vals[i]}');
      }
    });
    _notify();
  }

  void _updateMinutes(int index, String val) {
    final m = int.tryParse(val);
    if (m != null && m > 0) {
      _blocks[index].minutes = m;
      // _notify() is intentionally NOT called here — calling it on every
      // keystroke triggers didUpdateWidget which re-initialises all controllers,
      // limiting input to one character. Notify only when editing is finished.
    }
  }

  int get _totalMinutes => _blocks.fold(0, (s, b) => s + b.minutes);

  @override
  Widget build(BuildContext context) {
    final total = _totalMinutes;

    return Column(
      crossAxisAlignment: CrossAxisAlignment.stretch,
      children: [
        // ── Chips row (add blocks) ──────────────────────────────────────────
        Row(
          children: [
            _addChip('+ Work', _workColor, () => _addBlock(_StagingType.work)),
            const SizedBox(width: 8),
            _addChip('+ Rest', _restColor, () => _addBlock(_StagingType.rest)),
            const Spacer(),
            if (total > 0)
              Text(
                'Total: ${total >= 60 ? '${total ~/ 60}h ${total % 60}m' : '${total}m'}',
                style: const TextStyle(fontSize: 10, color: Color(0xFF454A55)),
              ),
          ],
        ),
        const SizedBox(height: 12),

        // ── Reorderable block list ──────────────────────────────────────────
        if (_blocks.isEmpty)
          const Padding(
            padding: EdgeInsets.symmetric(vertical: 16),
            child: Text(
              'Add work and rest blocks above.',
              style: TextStyle(fontSize: 11, color: Color(0xFF454A55)),
              textAlign: TextAlign.center,
            ),
          )
        else ...[
          // Palette row (non-interactive preview of order)
          _buildTimelinePalette(total),
          const SizedBox(height: 10),

          // Reorderable list
          ReorderableListView(
            shrinkWrap: true,
            physics: const NeverScrollableScrollPhysics(),
            buildDefaultDragHandles: false, // we supply our own at the left
            onReorder: _reorder,
            proxyDecorator: (child, index, anim) =>
                Material(color: Colors.transparent, child: child),
            children: [
              for (int i = 0; i < _blocks.length; i++) _buildBlockRow(i, total),
            ],
          ),
        ],
      ],
    );
  }

  Widget _buildTimelinePalette(int total) {
    if (total == 0) return const SizedBox.shrink();
    return ClipRRect(
      borderRadius: BorderRadius.circular(6),
      child: SizedBox(
        height: 10,
        child: Row(
          children: _blocks.map((b) {
            final frac = b.minutes / total;
            final color = b.type == _StagingType.work ? _workColor : _restColor;
            return Expanded(
              flex: (frac * 1000).round(),
              child: Container(color: color.withOpacity(0.55)),
            );
          }).toList(),
        ),
      ),
    );
  }

  Widget _buildBlockRow(int i, int total) {
    final b = _blocks[i];
    final isWork = b.type == _StagingType.work;
    final accent = isWork ? _workColor : _restColor;
    final bg = isWork ? _workBg : _restBg;
    final ctrl = _ctrls[i] ?? TextEditingController(text: '${b.minutes}');
    final frac = total > 0 ? b.minutes / total : 0.0;
    final pct = (frac * 100).round();
    final isHovered = _hoveredIndex == i;

    return KeyedSubtree(
      key: ValueKey('staging_block_$i'),
      // Right-click to delete via context menu
      child: GestureDetector(
        onSecondaryTap: () async {
          final choice = await showMenu<String>(
            context: context,
            position: RelativeRect.fromLTRB(0, 0, 0, 0),
            color: const Color(0xFF1E2124),
            shape: RoundedRectangleBorder(
              borderRadius: BorderRadius.circular(6),
            ),
            items: [
              PopupMenuItem<String>(
                value: 'delete',
                child: Row(
                  children: [
                    Icon(
                      Icons.delete_outline,
                      size: 14,
                      color: Colors.redAccent,
                    ),
                    const SizedBox(width: 8),
                    Text(
                      'Delete',
                      style: TextStyle(fontSize: 12, color: Colors.redAccent),
                    ),
                  ],
                ),
              ),
            ],
          );
          if (choice == 'delete') _removeBlock(i);
        },
        child: MouseRegion(
          onEnter: (_) => setState(() => _hoveredIndex = i),
          onExit: (_) => setState(() => _hoveredIndex = null),
          child: Container(
            margin: const EdgeInsets.only(bottom: 6),
            decoration: BoxDecoration(
              color: bg,
              borderRadius: BorderRadius.circular(8),
              border: Border.all(color: accent.withOpacity(0.22)),
            ),
            child: Row(
              children: [
                // ── Drag handle (far left, non-overlapping) ────────────────
                ReorderableDragStartListener(
                  index: i,
                  child: Padding(
                    padding: const EdgeInsets.symmetric(
                      horizontal: 8,
                      vertical: 10,
                    ),
                    child: Icon(
                      Icons.drag_indicator,
                      size: 14,
                      color: Colors.white12,
                    ),
                  ),
                ),
                // Type badge
                Container(
                  padding: const EdgeInsets.symmetric(
                    horizontal: 8,
                    vertical: 4,
                  ),
                  decoration: BoxDecoration(
                    color: accent.withOpacity(0.12),
                    borderRadius: BorderRadius.circular(4),
                  ),
                  child: Text(
                    isWork ? 'WORK' : 'REST',
                    style: TextStyle(
                      fontSize: 9,
                      fontWeight: FontWeight.w700,
                      letterSpacing: 0.8,
                      color: accent.withOpacity(0.85),
                    ),
                  ),
                ),
                const SizedBox(width: 10),
                // Mini bar fill
                Expanded(
                  child: ClipRRect(
                    borderRadius: BorderRadius.circular(3),
                    child: LinearProgressIndicator(
                      value: frac.clamp(0.0, 1.0),
                      backgroundColor: Colors.white.withOpacity(0.04),
                      color: accent.withOpacity(0.25),
                      minHeight: 6,
                    ),
                  ),
                ),
                const SizedBox(width: 10),
                // Pct
                SizedBox(
                  width: 32,
                  child: Text(
                    '$pct%',
                    style: const TextStyle(
                      fontSize: 9,
                      color: Color(0xFF3A4050),
                    ),
                  ),
                ),
                // Minute input
                SizedBox(
                  width: 42,
                  height: 28,
                  child: TextField(
                    controller: ctrl,
                    textAlign: TextAlign.center,
                    keyboardType: TextInputType.number,
                    style: TextStyle(
                      fontSize: 12,
                      fontWeight: FontWeight.w600,
                      color: accent,
                    ),
                    decoration: InputDecoration(
                      isDense: true,
                      contentPadding: EdgeInsets.zero,
                      filled: true,
                      fillColor: accent.withOpacity(0.08),
                      border: OutlineInputBorder(
                        borderRadius: BorderRadius.circular(5),
                        borderSide: BorderSide(color: accent.withOpacity(0.2)),
                      ),
                      enabledBorder: OutlineInputBorder(
                        borderRadius: BorderRadius.circular(5),
                        borderSide: BorderSide(color: accent.withOpacity(0.2)),
                      ),
                      focusedBorder: OutlineInputBorder(
                        borderRadius: BorderRadius.circular(5),
                        borderSide: BorderSide(
                          color: accent.withOpacity(0.6),
                          width: 1.2,
                        ),
                      ),
                      suffixText: 'm',
                      suffixStyle: TextStyle(
                        fontSize: 9,
                        color: accent.withOpacity(0.5),
                      ),
                    ),
                    // Update local state on each keystroke so the palette
                    // refreshes live, but do NOT call _notify() here — that
                    // would trigger didUpdateWidget and reset the controller.
                    onChanged: (v) {
                      final m = int.tryParse(v);
                      if (m != null && m > 0) {
                        setState(() => _blocks[i].minutes = m);
                      }
                    },
                    // Notify the parent (and persist) only when editing ends.
                    onSubmitted: (_) => _notify(),
                    onEditingComplete: () {
                      _notify();
                      FocusScope.of(context).unfocus();
                    },
                  ),
                ),
                // ── Increased gap then hover-reveal delete button ──────────
                const SizedBox(width: 16),
                AnimatedOpacity(
                  duration: const Duration(milliseconds: 120),
                  opacity: isHovered ? 1.0 : 0.0,
                  child: Tooltip(
                    message: 'Delete block (or right-click)',
                    child: GestureDetector(
                      onTap: isHovered ? () => _removeBlock(i) : null,
                      child: Padding(
                        padding: const EdgeInsets.symmetric(
                          horizontal: 8,
                          vertical: 10,
                        ),
                        child: Icon(
                          Icons.close,
                          size: 13,
                          color: Colors.redAccent.withOpacity(0.75),
                        ),
                      ),
                    ),
                  ),
                ),
              ],
            ),
          ),
        ),
      ),
    );
  }

  Widget _addChip(String label, Color color, VoidCallback onTap) => InkWell(
    onTap: onTap,
    borderRadius: BorderRadius.circular(20),
    child: Container(
      padding: const EdgeInsets.symmetric(horizontal: 12, vertical: 5),
      decoration: BoxDecoration(
        color: color.withOpacity(0.08),
        borderRadius: BorderRadius.circular(20),
        border: Border.all(color: color.withOpacity(0.25)),
      ),
      child: Text(
        label,
        style: TextStyle(fontSize: 11, color: color.withOpacity(0.85)),
      ),
    ),
  );
}

// ─────────────────────────────────────────────────────────────────────────────
// _ExecutionTimelines  –  three stacked timelines in the Execution section
//   Row 1: work + rest alternation — live playhead when staging is active
//   Row 2: work-only segments, same proportions
//   Row 3: rest-only segments, same proportions
// ─────────────────────────────────────────────────────────────────────────────

class _ExecutionTimelines extends StatefulWidget {
  final Task task;
  final List<_StagingBlock> stagingBlocks;
  final bool isActiveStagingTask;
  final int stagingPhaseIndex;
  final DateTime? stagingPhaseStarted;
  final List<_ExecutionSession> sessions;
  final bool isActiveGeneralTask;
  final DateTime? generalTimerStartedAt;
  final VoidCallback? onStartGeneral;
  final VoidCallback? onCancelGeneral;
  final VoidCallback? onFocusOverlayGeneral;
  final VoidCallback? onStartStaging;
  final VoidCallback? onStartFlowtime;

  /// Elapsed ms in the CURRENT cycle (wraps each cycle)
  double get _cycleProgressFrac {
    if (!isActiveStagingTask || stagingPhaseStarted == null) return 0.0;
    final blocks = stagingBlocks.isEmpty
        ? [
            _StagingBlock(type: _StagingType.work, minutes: 25),
            _StagingBlock(type: _StagingType.rest, minutes: 5),
          ]
        : stagingBlocks;
    final totalMs = blocks.fold<int>(0, (s, b) => s + b.minutes) * 60000;
    if (totalMs == 0) return 0.0;
    int completedMs = 0;
    for (int i = 0; i < stagingPhaseIndex % blocks.length; i++) {
      completedMs += blocks[i].minutes * 60000;
    }
    final elapsedInPhase = DateTime.now()
        .difference(stagingPhaseStarted!)
        .inMilliseconds;
    return ((completedMs + elapsedInPhase) % totalMs) / totalMs;
  }

  static const Color workColor = Color(0xFF4FC3F7);
  static const Color restColor = Color(0xFF81C784);

  const _ExecutionTimelines({
    Key? key,
    required this.task,
    required this.stagingBlocks,
    this.isActiveStagingTask = false,
    this.stagingPhaseIndex = 0,
    this.stagingPhaseStarted,
    this.sessions = const [],
    this.isActiveGeneralTask = false,
    this.generalTimerStartedAt,
    this.onStartGeneral,
    this.onCancelGeneral,
    this.onFocusOverlayGeneral,
    this.onStartStaging,
    this.onStartFlowtime,
  }) : super(key: key);

  @override
  State<_ExecutionTimelines> createState() => _ExecutionTimelinesState();
}

class _ExecutionTimelinesState extends State<_ExecutionTimelines> {
  Timer? _ticker;

  @override
  void initState() {
    super.initState();
    if (widget.isActiveStagingTask || widget.isActiveGeneralTask)
      _startTicker();
  }

  @override
  void didUpdateWidget(_ExecutionTimelines old) {
    super.didUpdateWidget(old);
    final wasActive = old.isActiveStagingTask || old.isActiveGeneralTask;
    final isActive = widget.isActiveStagingTask || widget.isActiveGeneralTask;
    if (isActive && !wasActive) {
      _startTicker();
    } else if (!isActive && wasActive) {
      _ticker?.cancel();
      _ticker = null;
    }
  }

  void _startTicker() {
    _ticker?.cancel();
    _ticker = Timer.periodic(const Duration(milliseconds: 500), (_) {
      if (mounted) setState(() {});
    });
  }

  @override
  void dispose() {
    _ticker?.cancel();
    super.dispose();
  }

  List<_StagingBlock> get _blocks {
    if (widget.stagingBlocks.isEmpty) {
      return [
        _StagingBlock(type: _StagingType.work, minutes: 25),
        _StagingBlock(type: _StagingType.rest, minutes: 5),
      ];
    }
    return widget.stagingBlocks;
  }

  /// Returns progress [0..1] of the playhead across the full staging cycle,
  /// wrapping if time exceeds one full cycle.
  double _playheadFraction() {
    if (!widget.isActiveStagingTask || widget.stagingPhaseStarted == null)
      return -1;
    final blocks = _blocks;
    final totalMins = blocks.fold<int>(0, (s, b) => s + b.minutes);
    if (totalMins == 0) return -1;
    final totalMs = totalMins * 60000;

    // Compute total elapsed since staging started for this task.
    // We know: current phase index + elapsed in current phase.
    final elapsedInPhaseMs = DateTime.now()
        .difference(widget.stagingPhaseStarted!)
        .inMilliseconds;
    // Sum time of completed phases (wrapping cycle)
    int completedMs = 0;
    for (int i = 0; i < widget.stagingPhaseIndex % blocks.length; i++) {
      completedMs += blocks[i].minutes * 60000;
    }
    final totalElapsed = completedMs + elapsedInPhaseMs;
    return (totalElapsed % totalMs) / totalMs;
  }

  // ── Aggregate helpers ────────────────────────────────────────────────────

  /// Sum of ALL session durations (general + staging). Running sessions use
  /// DateTime.now() via _ExecutionSession.duration, so this is always live.
  int get _aggregateTotalMs =>
      widget.sessions.fold<int>(0, (s, e) => s + e.duration.inMilliseconds);

  /// Sum of work ms from staging sessions only.
  int get _aggregateWorkMs => widget.sessions
      .where((s) => s.blocksSnapshot.isNotEmpty)
      .fold<int>(0, (s, e) => s + e.workMs);

  /// Sum of rest ms from staging sessions only.
  int get _aggregateRestMs => widget.sessions
      .where((s) => s.blocksSnapshot.isNotEmpty)
      .fold<int>(0, (s, e) => s + e.restMs);

  // ── build ────────────────────────────────────────────────────────────────

  @override
  Widget build(BuildContext context) {
    final blocks = _blocks;
    final totalMins = blocks.fold<int>(0, (s, b) => s + b.minutes);
    final isAnyActive =
        widget.isActiveGeneralTask || widget.isActiveStagingTask;

    if (!isAnyActive && widget.sessions.isEmpty) return const SizedBox.shrink();

    String fmtMs(int ms) {
      if (ms <= 0) return '0m';
      final h = ms ~/ 3600000;
      final m = (ms % 3600000) ~/ 60000;
      final s = (ms % 60000) ~/ 1000;
      if (h > 0 && m > 0) return '${h}h ${m}m';
      if (h > 0) return '${h}h';
      if (m > 0) return '${m}m';
      return '${s}s';
    }

    // Decide whether to show the staging rows in the aggregate.
    final hasStagingData =
        widget.isActiveStagingTask ||
        widget.sessions.any((s) => s.blocksSnapshot.isNotEmpty);

    return Column(
      crossAxisAlignment: CrossAxisAlignment.stretch,
      children: [
        // ── AGGREGATE CARD ─────────────────────────────────────────────────
        _buildAggregateCard(fmtMs, blocks, totalMins, hasStagingData),

        // ── PER-SESSION SUBCARDS ───────────────────────────────────────────
        ...widget.sessions.asMap().entries.map((entry) {
          return Padding(
            padding: const EdgeInsets.only(top: 8),
            child: _buildSessionCard(
              entry.key,
              entry.value,
              widget.sessions.length,
              fmtMs,
            ),
          );
        }),
      ],
    );
  }

  // ── Aggregate card ───────────────────────────────────────────────────────

  Widget _buildAggregateCard(
    String Function(int) fmtMs,
    List<_StagingBlock> blocks,
    int totalMins,
    bool hasStagingData,
  ) {
    final isAnyActive =
        widget.isActiveGeneralTask || widget.isActiveStagingTask;

    // GENERAL aggregate
    final totalElapsedMs = _aggregateTotalMs;
    final durationMs = widget.task.durationMinutes * 60000;
    final generalProgress = durationMs > 0
        ? (totalElapsedMs / durationMs).clamp(0.0, 1.2)
        : 0.0;
    final generalOverrun = generalProgress > 1.0;
    final generalColor = generalOverrun
        ? const Color(0xFFEF5350)
        : isAnyActive
        ? const Color(0xFF4FC3F7)
        : Colors.white24;
    final plannedLabel = widget.task.durationMinutes > 0
        ? fmtMs(durationMs)
        : '—';

    // STAGING aggregate
    final totalWorkMs = _aggregateWorkMs;
    final totalRestMs = _aggregateRestMs;
    final totalStagingMs = totalWorkMs + totalRestMs;
    final playhead = _playheadFraction();

    return Container(
      padding: const EdgeInsets.fromLTRB(10, 12, 10, 12),
      decoration: BoxDecoration(
        color: const Color(0xFF1C1F21),
        borderRadius: BorderRadius.circular(6),
        border: Border.all(color: Colors.white.withOpacity(0.08)),
      ),
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.stretch,
        children: [
          // ── Start buttons (shown only when neither timer is active) ─────
          if (!isAnyActive) ...[
            // Start Countdown button (green)
            GestureDetector(
              onTap: widget.onStartGeneral,
              child: Container(
                padding: const EdgeInsets.symmetric(vertical: 7),
                decoration: BoxDecoration(
                  color: const Color(0xFF4CAF50).withOpacity(0.1),
                  borderRadius: BorderRadius.circular(5),
                  border: Border.all(
                    color: const Color(0xFF4CAF50).withOpacity(0.35),
                  ),
                ),
                child: Row(
                  mainAxisAlignment: MainAxisAlignment.center,
                  children: const [
                    Icon(
                      Icons.play_arrow_rounded,
                      size: 13,
                      color: Color(0xFF4CAF50),
                    ),
                    SizedBox(width: 5),
                    Text(
                      'Start Countdown',
                      style: TextStyle(
                        fontSize: 11,
                        fontWeight: FontWeight.w700,
                        color: Color(0xFF4CAF50),
                        letterSpacing: 0.3,
                      ),
                    ),
                  ],
                ),
              ),
            ),
            const SizedBox(height: 6),
            // Start Pomodoro button (orange)
            GestureDetector(
              onTap: widget.onStartStaging,
              child: Container(
                padding: const EdgeInsets.symmetric(vertical: 7),
                decoration: BoxDecoration(
                  color: const Color(0xFFFFB74D).withOpacity(0.08),
                  borderRadius: BorderRadius.circular(5),
                  border: Border.all(
                    color: const Color(0xFFFFB74D).withOpacity(0.25),
                  ),
                ),
                child: Row(
                  mainAxisAlignment: MainAxisAlignment.center,
                  children: const [
                    Icon(
                      Icons.timer_outlined,
                      size: 13,
                      color: Color(0xFFFFB74D),
                    ),
                    SizedBox(width: 5),
                    Text(
                      'Start Pomodoro',
                      style: TextStyle(
                        fontSize: 11,
                        fontWeight: FontWeight.w700,
                        color: Color(0xFFFFB74D),
                        letterSpacing: 0.3,
                      ),
                    ),
                  ],
                ),
              ),
            ),
            const SizedBox(height: 6),
            // Start Flowtime button (purple)
            GestureDetector(
              onTap: widget.onStartFlowtime,
              child: Container(
                padding: const EdgeInsets.symmetric(vertical: 7),
                decoration: BoxDecoration(
                  color: const Color(0xFFA78BFA).withOpacity(0.08),
                  borderRadius: BorderRadius.circular(5),
                  border: Border.all(
                    color: const Color(0xFFA78BFA).withOpacity(0.25),
                  ),
                ),
                child: Row(
                  mainAxisAlignment: MainAxisAlignment.center,
                  children: const [
                    Icon(
                      Icons.trending_up_rounded,
                      size: 13,
                      color: Color(0xFFA78BFA),
                    ),
                    SizedBox(width: 5),
                    Text(
                      'Start Flowtime',
                      style: TextStyle(
                        fontSize: 11,
                        fontWeight: FontWeight.w700,
                        color: Color(0xFFA78BFA),
                        letterSpacing: 0.3,
                      ),
                    ),
                  ],
                ),
              ),
            ),
            const SizedBox(height: 10),
          ],

          // ── GENERAL row ─────────────────────────────────────────────────
          Row(
            children: [
              Text(
                'COUNTDOWN',
                style: TextStyle(
                  fontSize: 9,
                  fontWeight: FontWeight.w700,
                  letterSpacing: 0.8,
                  color: isAnyActive ? const Color(0xFF4FC3F7) : Colors.white38,
                ),
              ),
              const Spacer(),
              // Live elapsed / planned label
              if (isAnyActive || totalElapsedMs > 0)
                Text(
                  '${fmtMs(totalElapsedMs)} / $plannedLabel',
                  style: TextStyle(
                    fontSize: 9,
                    color: generalOverrun
                        ? const Color(0xFFEF5350)
                        : isAnyActive
                        ? const Color(0xFF4FC3F7)
                        : Colors.white38,
                    fontWeight: isAnyActive
                        ? FontWeight.w600
                        : FontWeight.normal,
                    fontFeatures: const [FontFeature.tabularFigures()],
                  ),
                ),
            ],
          ),
          const SizedBox(height: 4),
          // GENERAL progress bar
          ClipRRect(
            borderRadius: BorderRadius.circular(3),
            child: SizedBox(
              height: 6,
              child: Stack(
                children: [
                  Container(color: Colors.white.withOpacity(0.06)),
                  FractionallySizedBox(
                    widthFactor: generalProgress.clamp(0.0, 1.0),
                    child: Container(
                      decoration: BoxDecoration(
                        color: generalColor.withOpacity(0.7),
                        borderRadius: BorderRadius.circular(3),
                      ),
                    ),
                  ),
                  if (isAnyActive)
                    Positioned.fill(
                      child: FractionallySizedBox(
                        widthFactor: generalProgress.clamp(0.0, 1.0),
                        alignment: Alignment.centerLeft,
                        child: Container(
                          decoration: BoxDecoration(
                            gradient: LinearGradient(
                              colors: [
                                Colors.transparent,
                                generalColor.withOpacity(0.3),
                              ],
                            ),
                          ),
                        ),
                      ),
                    ),
                ],
              ),
            ),
          ),
          // Cancel / Focus Overlay controls (general timer only)
          if (widget.isActiveGeneralTask) ...[
            const SizedBox(height: 6),
            Row(
              children: [
                if (widget.onCancelGeneral != null)
                  GestureDetector(
                    onTap: widget.onCancelGeneral,
                    child: const Text(
                      'Cancel',
                      style: TextStyle(fontSize: 10, color: Color(0xFF5A6070)),
                    ),
                  ),
                const SizedBox(width: 14),
                if (widget.onFocusOverlayGeneral != null)
                  GestureDetector(
                    onTap: widget.onFocusOverlayGeneral,
                    child: const Text(
                      'Focus Overlay',
                      style: TextStyle(
                        fontSize: 10,
                        color: Color(0xFF4FC3F7),
                        fontWeight: FontWeight.w500,
                      ),
                    ),
                  ),
              ],
            ),
          ],

          // ── RHYTHM / WORK / REST rows (only when staging data exists) ────
          if (hasStagingData && totalMins > 0) ...[
            const SizedBox(height: 10),
            _timelineRowWithPlayhead(
              label: 'RHYTHM',
              color: _ExecutionTimelines.workColor,
              segments: blocks
                  .map(
                    (b) => _Seg(
                      frac: b.minutes / totalMins,
                      color: b.type == _StagingType.work
                          ? _ExecutionTimelines.workColor.withOpacity(
                              widget.isActiveStagingTask ? 0.18 : 0.10,
                            )
                          : _ExecutionTimelines.restColor.withOpacity(
                              widget.isActiveStagingTask ? 0.14 : 0.08,
                            ),
                      isGap: false,
                      tooltip:
                          '${b.minutes}m ${b.type == _StagingType.work ? 'work' : 'rest'}',
                      inlineLabel: b.type == _StagingType.work
                          ? '${b.minutes}m'
                          : '',
                      minutes: b.minutes,
                    ),
                  )
                  .toList(),
              trailing: widget.isActiveStagingTask
                  ? '${totalMins}m cycle'
                  : fmtMs(totalStagingMs),
              playheadFrac: playhead,
            ),
            const SizedBox(height: 10),
            _timelineRow(
              label: 'WORK',
              color: _ExecutionTimelines.workColor,
              segments: _typedSegs(blocks, totalMins, _StagingType.work),
              progressFrac: widget.isActiveStagingTask
                  ? widget._cycleProgressFrac
                  : null,
              trailing: fmtMs(totalWorkMs),
            ),
            const SizedBox(height: 10),
            _timelineRow(
              label: 'REST',
              color: _ExecutionTimelines.restColor,
              segments: _typedSegs(blocks, totalMins, _StagingType.rest),
              progressFrac: widget.isActiveStagingTask
                  ? widget._cycleProgressFrac
                  : null,
              trailing: fmtMs(totalRestMs),
            ),
          ],
        ],
      ),
    );
  }

  // ── Per-session subcard ──────────────────────────────────────────────────

  Widget _buildSessionCard(
    int index,
    _ExecutionSession session,
    int totalSessions,
    String Function(int) fmtMs,
  ) {
    final isGeneral = session.sessionType == _SessionType.countdown;
    final isFlowtime = session.sessionType == _SessionType.flowtime;
    final isRunning = session.status == _SessionStatus.running;

    final statusColors = {
      _SessionStatus.running: const Color(0xFF4FC3F7),
      _SessionStatus.interrupted: const Color(0xFFFFB74D),
      _SessionStatus.completed: const Color(0xFF81C784),
    };
    final statusLabels = {
      _SessionStatus.running: 'R',
      _SessionStatus.interrupted: 'S',
      _SessionStatus.completed: 'D',
    };
    final statusTooltips = {
      _SessionStatus.running: 'Running',
      _SessionStatus.interrupted: 'Stopped',
      _SessionStatus.completed: 'Done',
    };

    final sc = statusColors[session.status] ?? const Color(0xFF4FC3F7);
    final sl = statusLabels[session.status] ?? '';
    final st = statusTooltips[session.status] ?? '';
    final durMs = session.duration.inMilliseconds;
    final startFmt = _fmtDateTime(session.startTime);
    final endFmt = session.endTime != null
        ? _fmtDateTime(session.endTime!)
        : 'now';

    // For staging sessions: compute executed segments for mini bars
    final execSegs = (isGeneral || isFlowtime)
        ? <_Seg>[]
        : _executedSegs(session);
    final hasWork = execSegs.any(
      (seg) => !seg.isGap && seg.tooltip.startsWith('work'),
    );
    final hasRest = execSegs.any(
      (seg) => !seg.isGap && seg.tooltip.startsWith('rest'),
    );

    // For general sessions: simple elapsed bar
    final sessionDurationMs = widget.task.durationMinutes * 60000;
    final generalBarFrac = sessionDurationMs > 0
        ? (durMs / sessionDurationMs).clamp(0.0, 1.0)
        : (durMs > 0 ? 1.0 : 0.0);

    return Container(
      padding: const EdgeInsets.fromLTRB(10, 8, 10, 8),
      decoration: BoxDecoration(
        color: sc.withOpacity(0.03),
        borderRadius: BorderRadius.circular(5),
        border: Border.all(color: sc.withOpacity(0.12)),
      ),
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.stretch,
        children: [
          // ── Header row ─────────────────────────────────────────────────
          Row(
            children: [
              Text(
                '#${index + 1}',
                style: TextStyle(
                  fontSize: 9,
                  fontWeight: FontWeight.w700,
                  color: sc.withOpacity(0.55),
                  letterSpacing: 0.5,
                ),
              ),
              const SizedBox(width: 6),
              // Session type pill
              Container(
                padding: const EdgeInsets.symmetric(horizontal: 5, vertical: 1),
                decoration: BoxDecoration(
                  color: Colors.white.withOpacity(0.04),
                  borderRadius: BorderRadius.circular(3),
                  border: Border.all(color: Colors.white.withOpacity(0.08)),
                ),
                child: Text(
                  isFlowtime
                      ? 'FLOWTIME'
                      : isGeneral
                      ? 'COUNTDOWN'
                      : 'POMODORO',
                  style: const TextStyle(
                    fontSize: 7,
                    fontWeight: FontWeight.w700,
                    letterSpacing: 0.5,
                    color: Colors.white24,
                  ),
                ),
              ),
              const SizedBox(width: 6),
              // Time range — expands to fill space, pushes duration+pill right
              Expanded(
                child: Text(
                  '$startFmt → $endFmt',
                  style: const TextStyle(fontSize: 9, color: Color(0xFF5A6070)),
                  overflow: TextOverflow.ellipsis,
                ),
              ),
              const SizedBox(width: 8),
              Text(
                fmtMs(durMs),
                style: TextStyle(
                  fontSize: 9,
                  color: sc.withOpacity(0.6),
                  fontWeight: FontWeight.w600,
                ),
              ),
              const SizedBox(width: 6),
              // Status pill
              Tooltip(
                message: st,
                child: Container(
                  padding: const EdgeInsets.symmetric(
                    horizontal: 5,
                    vertical: 1,
                  ),
                  decoration: BoxDecoration(
                    color: sc.withOpacity(0.1),
                    borderRadius: BorderRadius.circular(8),
                    border: Border.all(color: sc.withOpacity(0.2)),
                  ),
                  child: Text(
                    sl,
                    style: TextStyle(
                      fontSize: 8,
                      fontWeight: FontWeight.w700,
                      letterSpacing: 0.6,
                      color: sc.withOpacity(0.7),
                    ),
                  ),
                ),
              ),
            ],
          ),
          const SizedBox(height: 6),

          // ── Timelines ──────────────────────────────────────────────────
          if (isFlowtime) ...[
            // Flowtime: simple elapsed bar in violet
            _sessionMiniRow('GENERAL', const Color(0xFFA78BFA), [
              _Seg(
                frac: generalBarFrac,
                color: const Color(
                  0xFFA78BFA,
                ).withOpacity(isRunning ? 0.55 : 0.35),
                isGap: false,
                tooltip: fmtMs(durMs),
                inlineLabel: fmtMs(durMs),
                minutes: durMs ~/ 60000,
              ),
              if (generalBarFrac < 1.0)
                _Seg(
                  frac: 1.0 - generalBarFrac,
                  color: Colors.white.withOpacity(0.04),
                  isGap: true,
                  tooltip: '',
                  minutes: 0,
                ),
            ]),
          ] else if (isGeneral) ...[
            // Countdown: simple elapsed bar
            _sessionMiniRow('GENERAL', sc, [
              _Seg(
                frac: generalBarFrac,
                color: sc.withOpacity(isRunning ? 0.55 : 0.35),
                isGap: false,
                tooltip: fmtMs(durMs),
                inlineLabel: fmtMs(durMs),
                minutes: durMs ~/ 60000,
              ),
              if (generalBarFrac < 1.0)
                _Seg(
                  frac: 1.0 - generalBarFrac,
                  color: Colors.white.withOpacity(0.04),
                  isGap: true,
                  tooltip: '',
                  minutes: 0,
                ),
            ]),
          ] else ...[
            // RHYTHM bar
            _sessionMiniRow(
              'RHYTHM',
              sc,
              execSegs
                  .map(
                    (seg) => _Seg(
                      frac: seg.frac,
                      color: seg.isGap
                          ? const Color(0xFF151719)
                          : (seg.tooltip.startsWith('work')
                                ? const Color(0xFF4FC3F7).withOpacity(0.7)
                                : const Color(0xFF81C784).withOpacity(0.6)),
                      isGap: seg.isGap,
                      tooltip: seg.tooltip,
                      inlineLabel: seg.inlineLabel,
                      minutes: seg.minutes,
                    ),
                  )
                  .toList(),
            ),
            if (hasWork) ...[
              const SizedBox(height: 4),
              _sessionMiniRow(
                'WORK',
                const Color(0xFF4FC3F7),
                execSegs
                    .map(
                      (seg) => _Seg(
                        frac: seg.frac,
                        color: (!seg.isGap && seg.tooltip.startsWith('work'))
                            ? const Color(0xFF4FC3F7).withOpacity(0.6)
                            : const Color(0xFF151719),
                        isGap: seg.isGap || seg.tooltip.startsWith('rest'),
                        tooltip: seg.tooltip,
                        inlineLabel: seg.tooltip.startsWith('work')
                            ? seg.inlineLabel
                            : '',
                        minutes: seg.minutes,
                      ),
                    )
                    .toList(),
              ),
            ],
            if (hasRest) ...[
              const SizedBox(height: 4),
              _sessionMiniRow(
                'REST',
                const Color(0xFF81C784),
                execSegs
                    .map(
                      (seg) => _Seg(
                        frac: seg.frac,
                        color: (!seg.isGap && seg.tooltip.startsWith('rest'))
                            ? const Color(0xFF81C784).withOpacity(0.55)
                            : const Color(0xFF151719),
                        isGap: seg.isGap || seg.tooltip.startsWith('work'),
                        tooltip: seg.tooltip,
                        inlineLabel: '',
                        minutes: seg.minutes,
                      ),
                    )
                    .toList(),
              ),
            ],
          ],
        ],
      ),
    );
  }

  static String _fmtDateTime(DateTime dt) {
    final h = dt.hour.toString().padLeft(2, '0');
    final m = dt.minute.toString().padLeft(2, '0');
    return '${dt.month}/${dt.day} $h:$m';
  }

  /// Compute which _Segs were actually executed in a session.
  /// Returns partial segments proportional to the ENTIRE session duration.
  List<_Seg> _executedSegs(_ExecutionSession session) {
    final blocks = session.blocksSnapshot;
    if (blocks.isEmpty)
      return [_Seg(frac: 1.0, color: const Color(0xFF151719), isGap: true)];
    final totalBlockMs = blocks.fold<int>(0, (s, b) => s + b.minutes) * 60000;
    final execMs = session.duration.inMilliseconds.clamp(
      0,
      totalBlockMs * 9999,
    );
    final segs = <_Seg>[];
    int remainingMs = execMs;
    for (final b in blocks) {
      if (remainingMs <= 0) break;
      final blockMs = b.minutes * 60000;
      final coveredMs = remainingMs >= blockMs ? blockMs : remainingMs;
      final frac = coveredMs / totalBlockMs;
      final typeLabel = b.type == _StagingType.work ? 'work' : 'rest';
      final coveredMin =
          coveredMs ~/ 60000; // floor — avoids showing 1m from first second
      final coveredMinDisplay = coveredMin > 0 ? '${coveredMin}m' : '';
      segs.add(
        _Seg(
          frac: frac,
          color: Colors.transparent, // callers override
          isGap: false,
          tooltip: coveredMin > 0 ? '$typeLabel ${coveredMin}m' : typeLabel,
          inlineLabel: b.type == _StagingType.work ? coveredMinDisplay : '',
          minutes: coveredMin,
        ),
      );
      remainingMs -= coveredMs;
    }
    return segs;
  }

  Widget _sessionMiniRow(String label, Color color, List<_Seg> segs) {
    return _TimelineRowWidget(
      label: label,
      labelColor: color.withOpacity(0.35),
      segments: segs,
      trailing: '',
      trailingColor: Colors.transparent,
      progressFrac: null,
      playheadFrac: -1,
      barHeight: 7,
      labelWidth: 40,
      fontSize: 7,
    );
  }

  List<_Seg> _typedSegs(
    List<_StagingBlock> blocks,
    int total,
    _StagingType type,
  ) {
    final color = type == _StagingType.work
        ? _ExecutionTimelines.workColor.withOpacity(0.18)
        : _ExecutionTimelines.restColor.withOpacity(0.14);
    return blocks.map((b) {
      final frac = b.minutes / total;
      final tip = b.type == type
          ? '${b.minutes}m ${type == _StagingType.work ? 'work' : 'rest'}'
          : '';
      if (b.type == type) {
        return _Seg(
          frac: frac,
          color: color,
          isGap: false,
          tooltip: tip,
          inlineLabel: type == _StagingType.work ? '${b.minutes}m' : '',
          minutes: b.minutes,
        );
      } else {
        return _Seg(
          frac: frac,
          color: const Color(0xFF151719),
          isGap: true,
          tooltip:
              '${b.minutes}m ${b.type == _StagingType.work ? 'work' : 'rest'} (gap)',
          minutes: b.minutes,
        );
      }
    }).toList();
  }

  Widget _timelineRowWithPlayhead({
    required String label,
    required Color color,
    required List<_Seg> segments,
    required String trailing,
    required double playheadFrac,
  }) {
    return _TimelineRowWidget(
      label: label,
      labelColor: color.withOpacity(0.45),
      segments: segments,
      trailing: trailing,
      trailingColor: color.withOpacity(0.4),
      progressFrac: null,
      playheadFrac: playheadFrac,
      trailingWidth: 56,
    );
  }

  Widget _timelineRow({
    required String label,
    required Color color,
    required List<_Seg> segments,
    required String trailing,
    double? progressFrac,
  }) {
    return _TimelineRowWidget(
      label: label,
      labelColor: color.withOpacity(0.45),
      segments: segments,
      trailing: trailing,
      trailingColor: color.withOpacity(0.4),
      progressFrac: progressFrac,
      playheadFrac: -1,
      trailingWidth: 56,
    );
  }
}

// ─────────────────────────────────────────────────────────────────────────────
// _TimelineRowWidget  –  a single timeline bar row with hover tooltips,
//   inline time labels, progress fill, and optional live playhead.
// ─────────────────────────────────────────────────────────────────────────────

class _TimelineRowWidget extends StatefulWidget {
  final String label;
  final Color labelColor;
  final List<_Seg> segments;
  final String trailing;
  final Color trailingColor;
  final double? progressFrac; // 0..1 bright-fill cutoff (null = no fill)
  final double playheadFrac; // ≥0 draws playhead line (−1 = none)
  final double barHeight;
  final double labelWidth;
  final double fontSize;
  final double?
  trailingWidth; // fixed width for trailing — ensures bar widths match

  const _TimelineRowWidget({
    Key? key,
    required this.label,
    required this.labelColor,
    required this.segments,
    required this.trailing,
    required this.trailingColor,
    this.progressFrac,
    required this.playheadFrac,
    this.barHeight = 12,
    this.labelWidth = 40,
    this.fontSize = 8,
    this.trailingWidth,
  }) : super(key: key);

  @override
  State<_TimelineRowWidget> createState() => _TimelineRowWidgetState();
}

class _TimelineRowWidgetState extends State<_TimelineRowWidget> {
  int? _hoveredIndex;

  @override
  Widget build(BuildContext context) {
    return Row(
      children: [
        SizedBox(
          width: widget.labelWidth,
          child: Text(
            widget.label,
            style: TextStyle(
              fontSize: widget.fontSize,
              fontWeight: FontWeight.w700,
              letterSpacing: 0.6,
              color: widget.labelColor,
            ),
          ),
        ),
        Expanded(
          child: LayoutBuilder(
            builder: (_, constraints) {
              final w = constraints.maxWidth;
              return ClipRRect(
                borderRadius: BorderRadius.circular(3),
                child: SizedBox(
                  height: widget.barHeight,
                  child: Stack(
                    children: [
                      // Base bar with hover-sensitive segments
                      Row(
                        children: widget.segments.asMap().entries.map((entry) {
                          final i = entry.key;
                          final s = entry.value;
                          final baseColor = s.isGap
                              ? const Color(0xFF151719)
                              : s.color;
                          final isHovered = _hoveredIndex == i;
                          final displayColor = isHovered && !s.isGap
                              ? Color.lerp(baseColor, Colors.white, 0.2)!
                              : baseColor;
                          final seg = MouseRegion(
                            onEnter: (_) => setState(() => _hoveredIndex = i),
                            onExit: (_) => setState(() => _hoveredIndex = null),
                            child: Tooltip(
                              message: s.tooltip,
                              waitDuration: Duration.zero,
                              preferBelow: true,
                              decoration: BoxDecoration(
                                color: const Color(0xFF1E2228),
                                borderRadius: BorderRadius.circular(4),
                                border: Border.all(color: Colors.white12),
                              ),
                              textStyle: const TextStyle(
                                fontSize: 10,
                                color: Colors.white70,
                              ),
                              child: Stack(
                                children: [
                                  Container(color: displayColor),
                                  // Inline time label inside work segments
                                  if (!s.isGap && s.inlineLabel.isNotEmpty)
                                    Center(
                                      child: Text(
                                        s.inlineLabel,
                                        style: TextStyle(
                                          fontSize: widget.barHeight >= 10
                                              ? 7
                                              : 6,
                                          fontWeight: FontWeight.w600,
                                          color: Colors.white.withOpacity(0.55),
                                          height: 1,
                                        ),
                                        overflow: TextOverflow.clip,
                                      ),
                                    ),
                                ],
                              ),
                            ),
                          );
                          return Expanded(
                            flex: (s.frac * 1000).round().clamp(1, 999),
                            child: seg,
                          );
                        }).toList(),
                      ),
                      // Bright fill overlay up to progressFrac
                      if (widget.progressFrac != null &&
                          widget.progressFrac! > 0)
                        Positioned(
                          left: 0,
                          top: 0,
                          bottom: 0,
                          width: (widget.progressFrac! * w).clamp(0, w),
                          child: Container(
                            color: Colors.white.withOpacity(0.08),
                          ),
                        ),
                      // Progress line
                      if (widget.progressFrac != null)
                        Positioned(
                          left: (widget.progressFrac! * w - 1).clamp(0, w - 2),
                          top: 0,
                          bottom: 0,
                          child: Container(
                            width: 2,
                            color: Colors.white.withOpacity(0.5),
                          ),
                        ),
                      // Live playhead
                      if (widget.playheadFrac >= 0)
                        Positioned(
                          left: (widget.playheadFrac * w - 1).clamp(0, w - 2),
                          top: 0,
                          bottom: 0,
                          child: Container(
                            width: 2,
                            decoration: BoxDecoration(
                              color: Colors.white.withOpacity(0.9),
                              boxShadow: [
                                BoxShadow(
                                  color: Colors.white.withOpacity(0.6),
                                  blurRadius: 4,
                                ),
                              ],
                            ),
                          ),
                        ),
                    ],
                  ),
                ),
              );
            },
          ),
        ),
        if (widget.trailing.isNotEmpty || widget.trailingWidth != null) ...[
          const SizedBox(width: 8),
          widget.trailingWidth != null
              ? SizedBox(
                  width: widget.trailingWidth,
                  child: Text(
                    widget.trailing,
                    style: TextStyle(fontSize: 9, color: widget.trailingColor),
                    overflow: TextOverflow.ellipsis,
                  ),
                )
              : Text(
                  widget.trailing,
                  style: TextStyle(fontSize: 9, color: widget.trailingColor),
                ),
        ],
      ],
    );
  }
}

class _Seg {
  final double frac;
  final Color color;
  final bool isGap;
  final String tooltip; // shown on hover
  final String inlineLabel; // shown inside the bar (work segments)
  final int minutes;
  const _Seg({
    required this.frac,
    required this.color,
    required this.isGap,
    this.tooltip = '',
    this.inlineLabel = '',
    this.minutes = 0,
  });
}

// ─────────────────────────────────────────────────────────────────────────────
// _GeneralOverlay  –  fullscreen focus panel for simple (non-segmented) timing
// ─────────────────────────────────────────────────────────────────────────────

class _GeneralOverlay extends StatefulWidget {
  final Task task;
  final DateTime? startedAt;
  final VoidCallback onStop;
  final VoidCallback onComplete;
  final VoidCallback onDismiss;

  const _GeneralOverlay({
    Key? key,
    required this.task,
    required this.startedAt,
    required this.onStop,
    required this.onComplete,
    required this.onDismiss,
  }) : super(key: key);

  @override
  State<_GeneralOverlay> createState() => _GeneralOverlayState();
}

class _GeneralOverlayState extends State<_GeneralOverlay>
    with SingleTickerProviderStateMixin {
  late AnimationController _pulse;

  static const Color _color = Color(
    0xFF4CAF50,
  ); // matches "Start Countdown" button

  @override
  void initState() {
    super.initState();
    _pulse = AnimationController(
      vsync: this,
      duration: const Duration(milliseconds: 1800),
    )..repeat(reverse: true);
  }

  @override
  void dispose() {
    _pulse.dispose();
    super.dispose();
  }

  int get _elapsedSeconds {
    if (widget.startedAt == null) return 0;
    return DateTime.now().difference(widget.startedAt!).inSeconds;
  }

  double get _progress {
    final durationMs = widget.task.durationMinutes * 60000;
    if (durationMs <= 0 || widget.startedAt == null) return 0.0;
    final elapsed = DateTime.now().difference(widget.startedAt!).inMilliseconds;
    return (elapsed / durationMs).clamp(0.0, 1.0);
  }

  @override
  Widget build(BuildContext context) {
    final durationMins = widget.task.durationMinutes;
    final planMs = durationMins * 60000;
    final hasPlan = planMs > 0;
    final spentMs = widget.task.timeSpent;
    final overrun = hasPlan && spentMs > planMs;
    final displayMs = hasPlan ? (planMs - spentMs).abs() : spentMs;

    final totalSecs = displayMs ~/ 1000;
    final h = totalSecs ~/ 3600;
    final m = (totalSecs % 3600) ~/ 60;
    final s = totalSecs % 60;
    final prefix = overrun ? '+' : '';
    final timeStr = h > 0
        ? '$prefix${h.toString().padLeft(2, '0')}:${m.toString().padLeft(2, '0')}:${s.toString().padLeft(2, '0')}'
        : '$prefix${m.toString().padLeft(2, '0')}:${s.toString().padLeft(2, '0')}';

    final progress = hasPlan ? (spentMs / planMs).clamp(0.0, 1.0) : 0.0;
    final barColor = overrun ? const Color(0xFFEF5350) : _color;

    return Material(
      color: Colors.transparent,
      child: Container(
        color: const Color(0xFF0D0F11),
        child: Stack(
          children: [
            // Close button — dismisses overlay but keeps timer running
            Positioned(
              top: 16,
              right: 16,
              child: GestureDetector(
                onTap: widget.onDismiss,
                child: Container(
                  width: 32,
                  height: 32,
                  decoration: BoxDecoration(
                    color: Colors.white.withOpacity(0.04),
                    borderRadius: BorderRadius.circular(6),
                    border: Border.all(color: Colors.white12),
                  ),
                  child: const Icon(
                    Icons.close,
                    size: 16,
                    color: Colors.white38,
                  ),
                ),
              ),
            ),

            // Center content
            Center(
              child: Column(
                mainAxisSize: MainAxisSize.min,
                children: [
                  // Badge
                  AnimatedBuilder(
                    animation: _pulse,
                    builder: (_, __) => Container(
                      padding: const EdgeInsets.symmetric(
                        horizontal: 14,
                        vertical: 5,
                      ),
                      decoration: BoxDecoration(
                        color: _color.withOpacity(0.07 + _pulse.value * 0.06),
                        borderRadius: BorderRadius.circular(20),
                        border: Border.all(
                          color: _color.withOpacity(0.2 + _pulse.value * 0.15),
                        ),
                      ),
                      child: const Text(
                        'COUNTDOWN',
                        style: const TextStyle(
                          fontSize: 10,
                          fontWeight: FontWeight.w700,
                          letterSpacing: 1.4,
                          color: _color,
                        ),
                      ),
                    ),
                  ),
                  const SizedBox(height: 20),

                  // Task title
                  Text(
                    widget.task.title,
                    style: const TextStyle(
                      fontSize: 20,
                      fontWeight: FontWeight.w300,
                      color: Colors.white70,
                      letterSpacing: 0.3,
                    ),
                    textAlign: TextAlign.center,
                  ),
                  const SizedBox(height: 32),

                  // Remaining / elapsed time circle
                  SizedBox(
                    width: 180,
