// ─────────────────────────────────────────────────────────────────────────────
// _FlowtimeOverlay  –  fullscreen focus panel for Flowtime (elapsed-up timer)
// ─────────────────────────────────────────────────────────────────────────────

class _FlowtimeOverlay extends StatefulWidget {
  final Task task;
  final VoidCallback onStop;
  final VoidCallback onComplete;
  final VoidCallback onDismiss;

  const _FlowtimeOverlay({
    Key? key,
    required this.task,
    required this.onStop,
    required this.onComplete,
    required this.onDismiss,
  }) : super(key: key);

  @override
  State<_FlowtimeOverlay> createState() => _FlowtimeOverlayState();
}

class _FlowtimeOverlayState extends State<_FlowtimeOverlay>
    with SingleTickerProviderStateMixin {
  late AnimationController _pulse;
  bool _showElapsed = true;
  bool _showTaskRemaining = false;

  static const Color _color = Color(0xFFA78BFA); // violet

  @override
  void initState() {
    super.initState();
    _pulse = AnimationController(
      vsync: this,
      duration: const Duration(milliseconds: 1800),
    )..repeat(reverse: true);
  }

  @override
  void dispose() {
    _pulse.dispose();
    super.dispose();
  }

  String _fmt(int ms, {bool withSign = false, bool forceElapsed = false}) {
    final totalSecs = ms.abs() ~/ 1000;
    final h = totalSecs ~/ 3600;
    final m = (totalSecs % 3600) ~/ 60;
    final s = totalSecs % 60;
    final sign = withSign && ms < 0 ? '+' : '';
    return h > 0
        ? '$sign${h.toString().padLeft(2, '0')}:${m.toString().padLeft(2, '0')}:${s.toString().padLeft(2, '0')}'
        : '$sign${m.toString().padLeft(2, '0')}:${s.toString().padLeft(2, '0')}';
  }

  @override
  Widget build(BuildContext context) {
    final spentMs = widget.task.timeSpent; // goes up every second
    final planMs = widget.task.durationMinutes * 60000;
    final hasPlan = planMs > 0;
    final remainingMs = hasPlan ? planMs - spentMs : 0;
    final taskOverrun = hasPlan && remainingMs < 0;
    final taskColor = taskOverrun
        ? const Color(0xFFEF5350)
        : const Color(0xFFA5D6A7);

    // Arc shows elapsed / plan progress (no overrun flip)
    final progress = hasPlan ? (spentMs / planMs).clamp(0.0, 1.0) : 0.0;

    // Effective selections — at least one always on
    final showE = _showElapsed || !_showTaskRemaining;
    final showT = _showTaskRemaining;

    final elapsedStr = _fmt(spentMs);
    final taskStr = _fmt(remainingMs, withSign: true);

    return Material(
      color: Colors.transparent,
      child: Container(
        color: const Color(0xFF0D0F11),
        child: Stack(
          children: [
            // ── Top-right controls ──────────────────────────────────────────
            Positioned(
              top: 16,
              right: 16,
              child: Row(
                mainAxisSize: MainAxisSize.min,
                children: [
                  _FlowtimeCounterDropdown(
                    showElapsed: _showElapsed,
                    showTaskRemaining: _showTaskRemaining,
                    onChanged: (e, t) => setState(() {
                      if (!e && !t) return;
                      _showElapsed = e;
                      _showTaskRemaining = t;
                    }),
                  ),
                  const SizedBox(width: 8),
                  GestureDetector(
                    onTap: widget.onDismiss,
                    child: Container(
                      width: 32,
                      height: 32,
                      decoration: BoxDecoration(
                        color: Colors.white.withOpacity(0.04),
                        borderRadius: BorderRadius.circular(6),
                        border: Border.all(color: Colors.white12),
                      ),
                      child: const Icon(
                        Icons.close,
                        size: 16,
                        color: Colors.white38,
                      ),
                    ),
                  ),
                ],
              ),
            ),

            // ── Center content ──────────────────────────────────────────────
            Center(
              child: Column(
                mainAxisSize: MainAxisSize.min,
                children: [
                  // Badge
                  AnimatedBuilder(
                    animation: _pulse,
                    builder: (_, __) => Container(
                      padding: const EdgeInsets.symmetric(
                        horizontal: 14,
                        vertical: 5,
                      ),
                      decoration: BoxDecoration(
                        color: _color.withOpacity(0.07 + _pulse.value * 0.06),
                        borderRadius: BorderRadius.circular(20),
                        border: Border.all(
                          color: _color.withOpacity(0.2 + _pulse.value * 0.15),
                        ),
                      ),
                      child: const Text(
                        'FLOWTIME',
                        style: TextStyle(
                          fontSize: 10,
                          fontWeight: FontWeight.w700,
                          letterSpacing: 1.4,
                          color: _color,
                        ),
                      ),
                    ),
                  ),
                  const SizedBox(height: 20),

                  // Task title
                  Text(
                    widget.task.title,
                    style: const TextStyle(
                      fontSize: 20,
                      fontWeight: FontWeight.w300,
                      color: Colors.white70,
                      letterSpacing: 0.3,
                    ),
                    textAlign: TextAlign.center,
                  ),
                  const SizedBox(height: 32),

                  // Circle timer
                  SizedBox(
                    width: 180,
                    height: 180,
                    child: AnimatedBuilder(
                      animation: _pulse,
                      builder: (_, __) => CustomPaint(
                        painter: _CircleTimerPainter(
                          progress: progress,
                          color: showE ? _color : taskColor,
                          pulseValue: _pulse.value,
                        ),
                        child: Center(
                          child: Column(
                            mainAxisSize: MainAxisSize.min,
                            children: [
                              // Elapsed counter
                              if (showE) ...[
                                Text(
                                  elapsedStr,
                                  style: TextStyle(
                                    fontSize: showT ? 30 : 38,
                                    fontWeight: FontWeight.w200,
                                    color: _color,
                                    letterSpacing: 2,
                                    fontFeatures: const [
                                      FontFeature.tabularFigures(),
                                    ],
                                  ),
                                ),
                                Text(
                                  'elapsed',
                                  style: TextStyle(
                                    fontSize: 9,
                                    color: _color.withOpacity(0.45),
                                    fontWeight: FontWeight.w300,
                                    letterSpacing: 0.5,
                                  ),
                                ),
                              ],
                              // Divider when both shown
                              if (showE && showT)
                                Padding(
                                  padding: const EdgeInsets.symmetric(
                                    vertical: 4,
                                  ),
                                  child: Container(
                                    width: 24,
                                    height: 1,
                                    color: Colors.white12,
                                  ),
                                ),
                              // Task remaining counter
                              if (showT) ...[
                                Text(
                                  hasPlan ? taskStr : elapsedStr,
                                  style: TextStyle(
                                    fontSize: showE ? 22 : 38,
                                    fontWeight: FontWeight.w200,
                                    color: taskOverrun
                                        ? const Color(0xFFEF5350)
                                        : Colors.white70,
                                    letterSpacing: 2,
                                    fontFeatures: const [
                                      FontFeature.tabularFigures(),
                                    ],
                                  ),
                                ),
                                Text(
                                  hasPlan
                                      ? (taskOverrun
                                            ? 'over plan'
                                            : 'task left')
                                      : 'elapsed',
                                  style: TextStyle(
                                    fontSize: 9,
                                    color: taskColor.withOpacity(0.5),
                                    fontWeight: FontWeight.w300,
                                    letterSpacing: 0.5,
                                  ),
                                ),
                              ],
                            ],
                          ),
                        ),
                      ),
                    ),
                  ),
                  const SizedBox(height: 40),

                  // Action buttons
                  Row(
                    mainAxisSize: MainAxisSize.min,
                    children: [
                      _flowtimeBtn(
                        icon: Icons.check,
                        tooltip: 'Mark complete & stop',
                        color: const Color(0xFF81C784),
                        onTap: widget.onComplete,
                      ),
                      const SizedBox(width: 20),
                      _flowtimeBtn(
                        icon: Icons.stop_rounded,
                        tooltip: 'Stop timer',
                        color: const Color(0xFFEF5350),
                        onTap: widget.onStop,
                      ),
                    ],
                  ),
                ],
              ),
            ),
          ],
        ),
      ),
    );
  }

  Widget _flowtimeBtn({
    required IconData icon,
    required String tooltip,
    required Color color,
    required VoidCallback onTap,
  }) => Tooltip(
    message: tooltip,
    child: GestureDetector(
      onTap: onTap,
      child: Container(
        width: 52,
        height: 52,
        decoration: BoxDecoration(
          color: color.withOpacity(0.08),
          shape: BoxShape.circle,
          border: Border.all(color: color.withOpacity(0.25)),
        ),
        child: Icon(icon, size: 22, color: color.withOpacity(0.8)),
      ),
    ),
  );
}

// ─────────────────────────────────────────────────────────────────────────────
// _FlowtimeCounterDropdown  –  "Elapsed" / "Task Remaining" multi-select
// ─────────────────────────────────────────────────────────────────────────────

class _FlowtimeCounterDropdown extends StatefulWidget {
  final bool showElapsed;
  final bool showTaskRemaining;
  final void Function(bool elapsed, bool taskRemaining) onChanged;

  const _FlowtimeCounterDropdown({
    Key? key,
    required this.showElapsed,
    required this.showTaskRemaining,
    required this.onChanged,
  }) : super(key: key);

  @override
  State<_FlowtimeCounterDropdown> createState() =>
      _FlowtimeCounterDropdownState();
}

class _FlowtimeCounterDropdownState extends State<_FlowtimeCounterDropdown> {
  OverlayEntry? _entry;
  final _btnKey = GlobalKey();

  static const Color _color = Color(0xFFA78BFA);

  void _open() {
    if (_entry != null) {
      _close();
      return;
    }
    final box = _btnKey.currentContext?.findRenderObject() as RenderBox?;
    if (box == null) return;
    final pos = box.localToGlobal(Offset.zero);
    final size = box.size;

    _entry = OverlayEntry(
      builder: (ctx) => GestureDetector(
        behavior: HitTestBehavior.translucent,
        onTap: _close,
        child: Stack(
          children: [
            Positioned(
              left: pos.dx - 140 + size.width,
              top: pos.dy + size.height + 6,
              child: GestureDetector(
                onTap: () {},
                child: _FlowtimeCounterPanel(
                  showElapsed: widget.showElapsed,
                  showTaskRemaining: widget.showTaskRemaining,
                  onChanged: (e, t) {
                    widget.onChanged(e, t);
                    _close();
                  },
                ),
              ),
            ),
          ],
        ),
      ),
    );
    Overlay.of(context).insert(_entry!);
    setState(() {});
  }

  void _close() {
    _entry?.remove();
    _entry = null;
    if (mounted) setState(() {});
  }

  @override
  void dispose() {
    _entry?.remove();
    super.dispose();
  }

  @override
  Widget build(BuildContext context) {
    final isOpen = _entry != null;
    return GestureDetector(
      key: _btnKey,
      onTap: _open,
      child: Container(
        height: 32,
        padding: const EdgeInsets.symmetric(horizontal: 10),
        decoration: BoxDecoration(
          color: isOpen
              ? Colors.white.withOpacity(0.08)
              : Colors.white.withOpacity(0.04),
          borderRadius: BorderRadius.circular(6),
          border: Border.all(color: isOpen ? Colors.white24 : Colors.white12),
        ),
        child: Row(
          mainAxisSize: MainAxisSize.min,
          children: [
            Icon(
              Icons.timer_outlined,
              size: 13,
              color: _color.withOpacity(0.6),
            ),
            const SizedBox(width: 5),
            Text(
              'Counters',
              style: TextStyle(
                fontSize: 11,
                color: _color.withOpacity(0.6),
                fontWeight: FontWeight.w500,
              ),
            ),
            const SizedBox(width: 4),
            Icon(
              isOpen ? Icons.expand_less : Icons.expand_more,
              size: 14,
              color: Colors.white24,
            ),
          ],
        ),
      ),
    );
  }
}

class _FlowtimeCounterPanel extends StatefulWidget {
  final bool showElapsed;
  final bool showTaskRemaining;
  final void Function(bool elapsed, bool taskRemaining) onChanged;

  const _FlowtimeCounterPanel({
    Key? key,
    required this.showElapsed,
    required this.showTaskRemaining,
    required this.onChanged,
  }) : super(key: key);

  @override
  State<_FlowtimeCounterPanel> createState() => _FlowtimeCounterPanelState();
}

class _FlowtimeCounterPanelState extends State<_FlowtimeCounterPanel> {
  late bool _elapsed;
  late bool _task;

  @override
  void initState() {
    super.initState();
    _elapsed = widget.showElapsed;
    _task = widget.showTaskRemaining;
  }

  void _toggle(bool isElapsed) {
    final newE = isElapsed ? !_elapsed : _elapsed;
    final newT = !isElapsed ? !_task : _task;
    if (!newE && !newT) return; // at least one must stay on
    setState(() {
      _elapsed = newE;
      _task = newT;
    });
    widget.onChanged(_elapsed, _task);
  }

  Widget _row(String label, bool value, bool isElapsed) {
    return GestureDetector(
      onTap: () => _toggle(isElapsed),
      child: Container(
        padding: const EdgeInsets.symmetric(horizontal: 12, vertical: 8),
        child: Row(
          children: [
            Container(
              width: 15,
              height: 15,
              decoration: BoxDecoration(
                color: value
                    ? Colors.white.withOpacity(0.15)
                    : Colors.transparent,
                borderRadius: BorderRadius.circular(3),
                border: Border.all(
                  color: value ? Colors.white38 : Colors.white24,
                ),
              ),
              child: value
                  ? const Icon(Icons.check, size: 10, color: Colors.white70)
                  : null,
            ),
            const SizedBox(width: 10),
            Text(
              label,
              style: TextStyle(
                fontSize: 12,
                color: value ? Colors.white70 : Colors.white38,
                fontWeight: value ? FontWeight.w500 : FontWeight.normal,
              ),
            ),
          ],
        ),
      ),
    );
  }

  @override
  Widget build(BuildContext context) {
    return Material(
      color: Colors.transparent,
      child: Container(
        width: 160,
        decoration: BoxDecoration(
          color: const Color(0xFF1C1F24),
          borderRadius: BorderRadius.circular(8),
          border: Border.all(color: Colors.white.withOpacity(0.1)),
          boxShadow: [
            BoxShadow(
              color: Colors.black.withOpacity(0.4),
              blurRadius: 16,
              offset: const Offset(0, 6),
            ),
          ],
        ),
        child: Column(
          mainAxisSize: MainAxisSize.min,
          crossAxisAlignment: CrossAxisAlignment.stretch,
          children: [
            const Padding(
              padding: EdgeInsets.fromLTRB(12, 8, 12, 4),
              child: Text(
                'SHOW COUNTERS',
                style: TextStyle(
                  fontSize: 9,
                  fontWeight: FontWeight.w700,
                  letterSpacing: 0.8,
                  color: Colors.white24,
                ),
              ),
            ),
            _row('Elapsed', _elapsed, true),
            _row('Task Remaining', _task, false),
            const SizedBox(height: 4),
          ],
        ),
      ),
    );
  }
}

// ─────────────────────────────────────────────────────────────────────────────
// _StagingOverlay  –  fullscreen focus panel shown during Task Staging
// ─────────────────────────────────────────────────────────────────────────────

class _StagingOverlay extends StatefulWidget {
  final Task task;
  final List<_StagingBlock> stagingBlocks;
  final int phaseIndex;
  final DateTime? phaseStarted;
  final VoidCallback onStop;
  final VoidCallback onInterrupt;
  final VoidCallback onComplete;

  const _StagingOverlay({
    Key? key,
    required this.task,
    required this.stagingBlocks,
    required this.phaseIndex,
    required this.phaseStarted,
    required this.onStop,
    required this.onInterrupt,
    required this.onComplete,
  }) : super(key: key);

  @override
  State<_StagingOverlay> createState() => _StagingOverlayState();
}

class _StagingOverlayState extends State<_StagingOverlay>
    with SingleTickerProviderStateMixin {
  late AnimationController _pulse;
  bool _showPhase = true;
  bool _showTaskRemaining = false;

  static const Color _workColor = Color(0xFF4FC3F7);
  static const Color _restColor = Color(0xFF81C784);

  @override
  void initState() {
    super.initState();
    _pulse = AnimationController(
      vsync: this,
      duration: const Duration(milliseconds: 1500),
    )..repeat(reverse: true);
  }

  @override
  void dispose() {
    _pulse.dispose();
    super.dispose();
  }

  List<_StagingBlock> get _blocks {
    if (widget.stagingBlocks.isEmpty) {
      return [
        _StagingBlock(type: _StagingType.work, minutes: 25),
        _StagingBlock(type: _StagingType.rest, minutes: 5),
      ];
    }
    return widget.stagingBlocks;
  }

  _StagingBlock get _currentBlock {
    final blocks = _blocks;
    return blocks[widget.phaseIndex % blocks.length];
  }

  /// Seconds remaining in the current phase
  int get _secondsRemaining {
    if (widget.phaseStarted == null) return _currentBlock.minutes * 60;
    final elapsed = DateTime.now().difference(widget.phaseStarted!).inSeconds;
    return (_currentBlock.minutes * 60 - elapsed).clamp(
      0,
      _currentBlock.minutes * 60,
    );
  }

  /// Progress [0..1] of current phase (0 = start, 1 = done)
  double get _phaseProgress {
    if (widget.phaseStarted == null) return 0.0;
    final total = _currentBlock.minutes * 60;
    final elapsed = DateTime.now().difference(widget.phaseStarted!).inSeconds;
    return (elapsed / total).clamp(0.0, 1.0);
  }

  bool get _isWork => _currentBlock.type == _StagingType.work;

  @override
  Widget build(BuildContext context) {
    final secs = _secondsRemaining;
    final mm = (secs ~/ 60).toString().padLeft(2, '0');
    final ss = (secs % 60).toString().padLeft(2, '0');
    final phaseColor = _isWork ? _workColor : _restColor;
    final phaseLabel = _isWork ? 'WORK' : 'REST';

    // ── Task-remaining values ──────────────────────────────────────────────
    final planMs = widget.task.durationMinutes * 60000;
    final hasPlan = planMs > 0;
    final spentMs = widget.task.timeSpent;
    final remainingMs = hasPlan ? planMs - spentMs : 0;
    final taskOverrun = hasPlan && remainingMs < 0;
    final taskDisplayMs = remainingMs.abs();
    final taskTotalSecs = taskDisplayMs ~/ 1000;
    final th = taskTotalSecs ~/ 3600;
    final tm = (taskTotalSecs % 3600) ~/ 60;
    final ts = taskTotalSecs % 60;
    final taskTimeStr = th > 0
        ? '${th.toString().padLeft(2, '0')}:${tm.toString().padLeft(2, '0')}:${ts.toString().padLeft(2, '0')}'
        : '${taskOverrun ? '+' : ''}${tm.toString().padLeft(2, '0')}:${ts.toString().padLeft(2, '0')}';
    final taskColor = taskOverrun
        ? const Color(0xFFEF5350)
        : const Color(0xFFA5D6A7);

    // Decide what the circle arc represents (phase takes priority)
    final circleProgress = _showPhase
        ? _phaseProgress
        : hasPlan
        ? (spentMs / planMs).clamp(0.0, 1.0)
        : 0.0;
    final circleColor = _showPhase ? phaseColor : taskColor;

    // Both or neither selected → show at least something sensible
    final effectiveShowPhase = _showPhase || !_showTaskRemaining;
    final effectiveShowTask = _showTaskRemaining;

    return Material(
      color: Colors.transparent,
      child: Container(
        color: const Color(0xFF0D0F11),
        child: Stack(
          children: [
            // ── Top-right controls ─────────────────────────────────────────
            Positioned(
              top: 16,
              right: 16,
              child: Row(
                mainAxisSize: MainAxisSize.min,
                children: [
                  // Counter selector dropdown
                  _CounterDropdown(
                    showPhase: _showPhase,
                    showTaskRemaining: _showTaskRemaining,
                    phaseColor: phaseColor,
                    onChanged: (phase, task) => setState(() {
                      // At least one must stay on
                      if (!phase && !task) return;
                      _showPhase = phase;
                      _showTaskRemaining = task;
                    }),
                  ),
                  const SizedBox(width: 8),
                  // Close button
                  GestureDetector(
                    onTap: widget.onStop,
                    child: Container(
                      width: 32,
                      height: 32,
                      decoration: BoxDecoration(
                        color: Colors.white.withOpacity(0.04),
                        borderRadius: BorderRadius.circular(6),
                        border: Border.all(color: Colors.white12),
                      ),
                      child: const Icon(
                        Icons.close,
                        size: 16,
                        color: Colors.white38,
                      ),
                    ),
                  ),
                ],
              ),
            ),

            // ── Center content ─────────────────────────────────────────────
            Center(
              child: Column(
                mainAxisSize: MainAxisSize.min,
                children: [
                  // Phase badge
                  AnimatedBuilder(
                    animation: _pulse,
                    builder: (_, __) => Container(
                      padding: const EdgeInsets.symmetric(
                        horizontal: 14,
                        vertical: 5,
                      ),
                      decoration: BoxDecoration(
                        color: phaseColor.withOpacity(
                          0.08 + _pulse.value * 0.06,
                        ),
                        borderRadius: BorderRadius.circular(20),
                        border: Border.all(
                          color: phaseColor.withOpacity(
                            0.25 + _pulse.value * 0.15,
                          ),
                        ),
                      ),
                      child: Text(
                        phaseLabel,
                        style: TextStyle(
                          fontSize: 10,
                          fontWeight: FontWeight.w700,
                          letterSpacing: 1.4,
                          color: phaseColor.withOpacity(0.7),
                        ),
                      ),
                    ),
                  ),
