// _CounterDropdown  –  multi-select dropdown for choosing which counters to
//   show inside the staging overlay timer circle.
// ─────────────────────────────────────────────────────────────────────────────

class _CounterDropdown extends StatefulWidget {
  final bool showPhase;
  final bool showTaskRemaining;
  final Color phaseColor;
  final void Function(bool phase, bool taskRemaining) onChanged;

  const _CounterDropdown({
    Key? key,
    required this.showPhase,
    required this.showTaskRemaining,
    required this.phaseColor,
    required this.onChanged,
  }) : super(key: key);

  @override
  State<_CounterDropdown> createState() => _CounterDropdownState();
}

class _CounterDropdownState extends State<_CounterDropdown> {
  OverlayEntry? _entry;
  final _btnKey = GlobalKey();

  void _open() {
    if (_entry != null) {
      _close();
      return;
    }
    final box = _btnKey.currentContext?.findRenderObject() as RenderBox?;
    if (box == null) return;
    final pos = box.localToGlobal(Offset.zero);
    final size = box.size;

    _entry = OverlayEntry(
      builder: (ctx) => GestureDetector(
        behavior: HitTestBehavior.translucent,
        onTap: _close,
        child: Stack(
          children: [
            Positioned(
              left: pos.dx - 140 + size.width,
              top: pos.dy + size.height + 6,
              child: GestureDetector(
                onTap: () {}, // absorb taps inside panel
                child: _CounterPanel(
                  showPhase: widget.showPhase,
                  showTaskRemaining: widget.showTaskRemaining,
                  onChanged: (phase, task) {
                    widget.onChanged(phase, task);
                    _close();
                  },
                ),
              ),
            ),
          ],
        ),
      ),
    );
    Overlay.of(context).insert(_entry!);
    setState(() {});
  }

  void _close() {
    _entry?.remove();
    _entry = null;
    if (mounted) setState(() {});
  }

  @override
  void dispose() {
    _entry?.remove();
    super.dispose();
  }

  @override
  Widget build(BuildContext context) {
    final isOpen = _entry != null;
    final activeCount =
        (widget.showPhase ? 1 : 0) + (widget.showTaskRemaining ? 1 : 0);

    return GestureDetector(
      key: _btnKey,
      onTap: _open,
      child: Container(
        height: 32,
        padding: const EdgeInsets.symmetric(horizontal: 10),
        decoration: BoxDecoration(
          color: isOpen
              ? Colors.white.withOpacity(0.08)
              : Colors.white.withOpacity(0.04),
          borderRadius: BorderRadius.circular(6),
          border: Border.all(color: isOpen ? Colors.white24 : Colors.white12),
        ),
        child: Row(
          mainAxisSize: MainAxisSize.min,
          children: [
            const Icon(Icons.timer_outlined, size: 13, color: Colors.white38),
            const SizedBox(width: 5),
            Text(
              'Counters',
              style: const TextStyle(
                fontSize: 11,
                color: Colors.white38,
                fontWeight: FontWeight.w500,
              ),
            ),
            const SizedBox(width: 4),
            Icon(
              isOpen ? Icons.expand_less : Icons.expand_more,
              size: 14,
              color: Colors.white24,
            ),
          ],
        ),
      ),
    );
  }
}

// Inline panel shown by the dropdown
class _CounterPanel extends StatefulWidget {
  final bool showPhase;
  final bool showTaskRemaining;
  final void Function(bool phase, bool taskRemaining) onChanged;

  const _CounterPanel({
    Key? key,
    required this.showPhase,
    required this.showTaskRemaining,
    required this.onChanged,
  }) : super(key: key);

  @override
  State<_CounterPanel> createState() => _CounterPanelState();
}

class _CounterPanelState extends State<_CounterPanel> {
  late bool _phase;
  late bool _task;

  @override
  void initState() {
    super.initState();
    _phase = widget.showPhase;
    _task = widget.showTaskRemaining;
  }

  void _toggle(bool isPhase) {
    final newPhase = isPhase ? !_phase : _phase;
    final newTask = !isPhase ? !_task : _task;
    // At least one must remain on
    if (!newPhase && !newTask) return;
    setState(() {
      _phase = newPhase;
      _task = newTask;
    });
    widget.onChanged(_phase, _task);
  }

  Widget _row(String label, bool value, bool isPhase) {
    return GestureDetector(
      onTap: () => _toggle(isPhase),
      child: Container(
        padding: const EdgeInsets.symmetric(horizontal: 12, vertical: 8),
        child: Row(
          children: [
            Container(
              width: 15,
              height: 15,
              decoration: BoxDecoration(
                color: value
                    ? Colors.white.withOpacity(0.15)
                    : Colors.transparent,
                borderRadius: BorderRadius.circular(3),
                border: Border.all(
                  color: value ? Colors.white38 : Colors.white24,
                ),
              ),
              child: value
                  ? const Icon(Icons.check, size: 10, color: Colors.white70)
                  : null,
            ),
            const SizedBox(width: 10),
            Text(
              label,
              style: TextStyle(
                fontSize: 12,
                color: value ? Colors.white70 : Colors.white38,
                fontWeight: value ? FontWeight.w500 : FontWeight.normal,
              ),
            ),
          ],
        ),
      ),
    );
  }

  @override
  Widget build(BuildContext context) {
    return Material(
      color: Colors.transparent,
      child: Container(
        width: 160,
        decoration: BoxDecoration(
          color: const Color(0xFF1C1F24),
          borderRadius: BorderRadius.circular(8),
          border: Border.all(color: Colors.white.withOpacity(0.1)),
          boxShadow: [
            BoxShadow(
              color: Colors.black.withOpacity(0.4),
              blurRadius: 16,
              offset: const Offset(0, 6),
            ),
          ],
        ),
        child: Column(
          mainAxisSize: MainAxisSize.min,
          crossAxisAlignment: CrossAxisAlignment.stretch,
          children: [
            Padding(
              padding: const EdgeInsets.fromLTRB(12, 8, 12, 4),
              child: Text(
                'SHOW COUNTERS',
                style: const TextStyle(
                  fontSize: 9,
                  fontWeight: FontWeight.w700,
                  letterSpacing: 0.8,
                  color: Colors.white24,
                ),
              ),
            ),
            _row('Phase', _phase, true),
            _row('Task Remaining', _task, false),
            const SizedBox(height: 4),
          ],
        ),
      ),
    );
  }
}

class _CircleTimerPainter extends CustomPainter {
  final double progress;
  final Color color;
  final double pulseValue;

  const _CircleTimerPainter({
    required this.progress,
    required this.color,
    required this.pulseValue,
  });

  @override
  void paint(Canvas canvas, Size size) {
    final center = Offset(size.width / 2, size.height / 2);
    final radius = size.width / 2 - 10;
    const startAngle = -pi / 2;
    const fullAngle = 2 * pi;

    // Track
    final trackPaint = Paint()
      ..color = Colors.white.withOpacity(0.06)
      ..strokeWidth = 6
      ..style = PaintingStyle.stroke
      ..strokeCap = StrokeCap.round;
    canvas.drawCircle(center, radius, trackPaint);

    // Progress arc
    final arcPaint = Paint()
      ..color = color.withOpacity(0.55 + pulseValue * 0.2)
      ..strokeWidth = 6
      ..style = PaintingStyle.stroke
      ..strokeCap = StrokeCap.round;
    canvas.drawArc(
      Rect.fromCircle(center: center, radius: radius),
      startAngle,
      fullAngle * progress,
      false,
      arcPaint,
    );
  }

  @override
  bool shouldRepaint(_CircleTimerPainter old) =>
      old.progress != progress || old.pulseValue != pulseValue;
}

class _MiniRhythmBar extends StatelessWidget {
  final List<_StagingBlock> blocks;
  final int phaseIndex;
  final double phaseProgress;

  static const Color _workColor = Color(0xFF4FC3F7);
  static const Color _restColor = Color(0xFF81C784);

  const _MiniRhythmBar({
    Key? key,
    required this.blocks,
    required this.phaseIndex,
    required this.phaseProgress,
  }) : super(key: key);

  @override
  Widget build(BuildContext context) {
    final total = blocks.fold<int>(0, (s, b) => s + b.minutes);
    if (total == 0) return const SizedBox.shrink();
    final currentIdx = phaseIndex % blocks.length;

    return LayoutBuilder(
      builder: (_, constraints) {
        final w = constraints.maxWidth;

        // Compute playhead position
        double completedFrac = 0;
        for (int i = 0; i < currentIdx; i++) {
          completedFrac += blocks[i].minutes / total;
        }
        final currentBlockFrac = blocks[currentIdx].minutes / total;
        final playheadFrac = completedFrac + currentBlockFrac * phaseProgress;

        return ClipRRect(
          borderRadius: BorderRadius.circular(4),
          child: SizedBox(
            height: 8,
            child: Stack(
              children: [
                Row(
                  children: blocks.asMap().entries.map((e) {
                    final i = e.key;
                    final b = e.value;
                    final color = b.type == _StagingType.work
                        ? _workColor.withOpacity(i == currentIdx ? 0.7 : 0.35)
                        : _restColor.withOpacity(i == currentIdx ? 0.6 : 0.25);
                    return Expanded(
                      flex: (b.minutes / total * 1000).round().clamp(1, 999),
                      child: Container(color: color),
                    );
                  }).toList(),
                ),
                // Playhead
                Positioned(
                  left: (playheadFrac * w - 1).clamp(0, w - 2),
                  top: 0,
                  bottom: 0,
                  child: Container(
                    width: 2,
                    color: Colors.white.withOpacity(0.9),
                  ),
                ),
              ],
            ),
          ),
        );
      },
    );
  }
}

// ── Repeat Config Dialog ───────────────────────────────────────────────────

class _RepeatConfigDialog extends StatefulWidget {
  final Task task;
  final RepeatConfig? initial;
  final VoidCallback? onRefresh;
  final VoidCallback? onRefreshFromInstance; // for repeat instances
  final List<Task> allTasks;

  /// Called when an instance user applies a new repeat config going forward.
  /// The dialog pops itself; caller handles propagation.
  final void Function(RepeatConfig)? onApplyForward;

  /// Called when the user taps "CONFIG (inherited from parent)".
  /// The dialog pops itself first; caller then shows the parent config dialog.
  final VoidCallback? onOpenParentConfig;

  /// Called when the parent taps "Apply Changes To" with a scope selection.
  /// Propagates the new config to instances matching [scope].
  final void Function(RepeatConfig cfg, _RepeatPropagateScope scope)?
  onApplyScoped;

  const _RepeatConfigDialog({
    required this.task,
    this.initial,
    this.onRefresh,
    this.onRefreshFromInstance,
    this.allTasks = const [],
    this.onApplyForward,
    this.onOpenParentConfig,
    this.onApplyScoped,
  });

  @override
  State<_RepeatConfigDialog> createState() => _RepeatConfigDialogState();
}

class _RepeatConfigDialogState extends State<_RepeatConfigDialog> {
  late RepeatPreset _preset;
  late int _customEvery;
  late RepeatCycle _customCycle;
  late DateTime _customStartDate;
  late Set<int> _customWeekDays;

  /// Anchor / start date for this repeat series (drives plannedAt/dueDay on parent).
  /// In forward-edit mode on an instance, this is locked to the instance's own date.
  DateTime? _anchorDate;

  /// Generation horizon controls
  DateTime? _endDate; // null = no fixed end
  int? _propagationDays; // null = empty (no days cap, defer to endDate)

  // Text controllers
  late TextEditingController _everyCtrl;
  late TextEditingController _daysAheadCtrl;

  // Timeline scroll controller – used to centre the current instance on open
  final ScrollController _timelineCtrl = ScrollController();
  bool _timelineScrolled = false; // ensures we only auto-scroll once

  /// When true (instances only), the full preset editor is shown so the user
  /// can change the repeat schedule going forward.
  bool _editingForward = false;

  /// Scope used by the "Apply Changes To" button in parent mode.
  _RepeatPropagateScope _applyScope = _RepeatPropagateScope.forward;

  @override
  void initState() {
    super.initState();
    final cfg = widget.initial;
    _preset = cfg?.preset ?? RepeatPreset.everyday;
    _customEvery = cfg?.customEvery ?? 1;
    _customCycle = cfg?.customCycle ?? RepeatCycle.day;
    _customStartDate = cfg?.customStartDate ?? DateTime.now();
    _customWeekDays = cfg?.customWeekDays.toSet() ?? {DateTime.now().weekday};
    _endDate = cfg?.endDate;
    _propagationDays = cfg?.propagationDays; // null → field starts empty
    // anchorDate: use explicit value from config, else fall back to the
    // task's own scheduled date (for instances) or today (new parent).
    _anchorDate =
        cfg?.anchorDate ??
        widget.task.scheduledDate ??
        (widget.task.repeatParentId == null ? DateTime.now() : null);
    _everyCtrl = TextEditingController(text: _customEvery.toString());
    _daysAheadCtrl = TextEditingController(
      text: _propagationDays != null ? _propagationDays.toString() : '',
    );
  }

  @override
  void dispose() {
    _everyCtrl.dispose();
    _daysAheadCtrl.dispose();
    _timelineCtrl.dispose();
    super.dispose();
  }

  RepeatConfig _build() => RepeatConfig(
    preset: _preset,
    customEvery: _customEvery,
    customCycle: _customCycle,
    customStartDate: _customStartDate,
    customWeekDays: _customWeekDays.toSet(),
    anchorDate: _anchorDate,
    endDate: _endDate,
    propagationDays: _propagationDays, // null = no days cap
  );

  String _weekDayName(int d) =>
      ['Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat', 'Sun'][d - 1];

  String _fmtDate(DateTime d) =>
      '${d.day.toString().padLeft(2, '0')}/${d.month.toString().padLeft(2, '0')}/${d.year}';

  Future<void> _pickStartDate() async {
    final picked = await showDatePicker(
      context: context,
      initialDate: _customStartDate,
      firstDate: DateTime(2020),
      lastDate: DateTime(2035),
      builder: (ctx, child) => Theme(
        data: Theme.of(ctx).copyWith(
          colorScheme: const ColorScheme.dark(
            primary: Color(0xFF4FC3F7),
            surface: Color(0xFF1E2124),
          ),
        ),
        child: child!,
      ),
    );
    if (picked != null) setState(() => _customStartDate = picked);
  }

  Future<void> _pickEndDate() async {
    final picked = await showDatePicker(
      context: context,
      initialDate: _endDate ?? DateTime.now().add(const Duration(days: 30)),
      firstDate: DateTime.now(),
      lastDate: DateTime(2040),
      builder: (ctx, child) => Theme(
        data: Theme.of(ctx).copyWith(
          colorScheme: const ColorScheme.dark(
            primary: Color(0xFF4FC3F7),
            surface: Color(0xFF1E2124),
          ),
        ),
        child: child!,
      ),
    );
    if (picked != null) setState(() => _endDate = picked);
  }

  Future<void> _pickAnchorDate() async {
    final initial = _anchorDate ?? DateTime.now();
    final picked = await showDatePicker(
      context: context,
      initialDate: initial,
      firstDate: DateTime(2020),
      lastDate: DateTime(2040),
      builder: (ctx, child) => Theme(
        data: Theme.of(ctx).copyWith(
          colorScheme: const ColorScheme.dark(
            primary: Color(0xFF4FC3F7),
            surface: Color(0xFF1E2124),
          ),
        ),
        child: child!,
      ),
    );
    if (picked != null) setState(() => _anchorDate = picked);
  }

  @override
  Widget build(BuildContext context) {
    final now = DateTime.now();
    final weekDayNames = ['Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat', 'Sun'];
    final monthDay = now.day;
    final monthSuffix = monthDay == 1 || monthDay == 21 || monthDay == 31
        ? 'st'
        : monthDay == 2 || monthDay == 22
        ? 'nd'
        : monthDay == 3 || monthDay == 23
        ? 'rd'
        : 'th';

    final presets = <RepeatPreset, String>{
      RepeatPreset.everyday: 'Every day',
