      RepeatPreset.everyMonth: 'Every month on the $monthDay$monthSuffix',
      RepeatPreset.everyYear:
          'Every year on ${now.day.toString().padLeft(2, '0')}/${now.month.toString().padLeft(2, '0')}',
      RepeatPreset.custom: 'Custom repeat',
