                      style: const TextStyle(
                        fontSize: 11,
                        fontWeight: FontWeight.w700,
                        letterSpacing: 1,
                        color: Colors.white70,
                      ),
                    ),
                    const Spacer(),
                    GestureDetector(
                      onTap: () => Navigator.of(context).pop(),
                      child: const Icon(
                        Icons.close_rounded,
                        size: 16,
                        color: Colors.white38,
                      ),
                    ),
                  ],
                ),
                const SizedBox(height: 16),

                // ── Instance timeline (only for repeat instances) ────────────
                if (widget.task.repeatParentId != null) ...[
