  /// Timeline strip showing all instances in the series with the current one
  /// highlighted. Scrollable horizontally.
  Widget _buildInstanceTimeline() {
    final parentId = widget.task.repeatParentId!;
    // Collect parent + all instances sorted by scheduled date
    final series =
        widget.allTasks
            .where((t) => t.id == parentId || t.repeatParentId == parentId)
            .toList()
          ..sort((a, b) {
            final da = a.scheduledDate ?? DateTime(2099);
            final db = b.scheduledDate ?? DateTime(2099);
            return da.compareTo(db);
          });

    final currentDate = widget.task.scheduledDate;
    final int currentIdx = series.indexWhere((t) => t.id == widget.task.id);
    final int total = series.length;

    String _shortDate(DateTime? d) {
      if (d == null) return '?';
      const months = [
        'Jan',
        'Feb',
        'Mar',
        'Apr',
        'May',
        'Jun',
        'Jul',
        'Aug',
        'Sep',
        'Oct',
        'Nov',
        'Dec',
      ];
      return '${months[d.month - 1]} ${d.day}';
    }

    // ── Auto-centre on the current instance (runs once after first layout) ──
    if (!_timelineScrolled && currentIdx >= 0) {
      WidgetsBinding.instance.addPostFrameCallback((_) {
        if (_timelineCtrl.hasClients && !_timelineScrolled) {
          _timelineScrolled = true;
          // Accumulate the pixel offset to the leading edge of the current dot.
          // Each item occupies: dotWidth + connectorWidth (20 px).
          //   parent dot  = 10 px
          //   regular dot = 8 px
          //   current dot = 14 px  (only at currentIdx, so not in this loop)
          double pixelOffset = 0;
          for (int i = 0; i < currentIdx; i++) {
            final isParent = series[i].id == parentId;
            pixelOffset += (isParent ? 10.0 : 8.0) + 20.0;
          }
          pixelOffset += 7.0; // half of the current dot (14 px / 2)

          final viewportWidth = _timelineCtrl.position.viewportDimension;
          final target = (pixelOffset - viewportWidth / 2).clamp(
            0.0,
            _timelineCtrl.position.maxScrollExtent,
          );
          _timelineCtrl.animateTo(
            target,
            duration: const Duration(milliseconds: 350),
            curve: Curves.easeOut,
          );
        }
      });
    }

    return Column(
      crossAxisAlignment: CrossAxisAlignment.start,
      children: [
        // Position badge
        Row(
          children: [
            Container(
              padding: const EdgeInsets.symmetric(horizontal: 8, vertical: 3),
              decoration: BoxDecoration(
                color: const Color(0xFF4FC3F7).withOpacity(0.12),
                borderRadius: BorderRadius.circular(20),
                border: Border.all(
                  color: const Color(0xFF4FC3F7).withOpacity(0.35),
                ),
              ),
              child: Text(
                currentIdx >= 0
                    ? 'Instance ${currentIdx + 1} of $total'
                    : '$total instances',
                style: const TextStyle(
                  fontSize: 10,
                  color: Color(0xFF4FC3F7),
                  fontWeight: FontWeight.w600,
                ),
              ),
            ),
            const SizedBox(width: 8),
            if (currentDate != null)
              Text(
                _shortDate(currentDate),
                style: TextStyle(
                  fontSize: 10,
                  color: Colors.white.withOpacity(0.4),
                ),
              ),
          ],
        ),
        const SizedBox(height: 10),

        // Horizontal scrollable timeline – current instance centred on open
        SizedBox(
          height: 64,
          child: SingleChildScrollView(
            controller: _timelineCtrl,
            scrollDirection: Axis.horizontal,
            child: Row(
              crossAxisAlignment: CrossAxisAlignment.center,
              children: [
                for (int i = 0; i < series.length; i++) ...[
                  _buildTimelineDot(
                    task: series[i],
                    isCurrent: series[i].id == widget.task.id,
                    isParent: series[i].id == parentId,
                    shortDate: _shortDate(series[i].scheduledDate),
                  ),
                  if (i < series.length - 1)
                    Container(
                      width: 20,
                      height: 1.5,
                      color: Colors.white.withOpacity(0.12),
                    ),
                ],
              ],
            ),
          ),
        ),
      ],
    );
  }

  Widget _buildTimelineDot({
    required Task task,
    required bool isCurrent,
    required bool isParent,
    required String shortDate,
  }) {
    final today = DateTime.now();
    final taskDate = task.scheduledDate;
    final isPast =
        taskDate != null &&
        taskDate.isBefore(DateTime(today.year, today.month, today.day));

    Color dotColor;
    if (isCurrent) {
      dotColor = const Color(0xFF4FC3F7);
    } else if (task.isDone || task.status == TaskStatus.done) {
      dotColor = const Color(0xFF4CAF50);
    } else if (isPast) {
      dotColor = Colors.white24;
    } else {
      dotColor = Colors.white38;
    }

    return Column(
      mainAxisAlignment: MainAxisAlignment.center,
      children: [
        // Date label
        Text(
          shortDate,
          style: TextStyle(
            fontSize: 8,
            color: isCurrent
                ? const Color(0xFF4FC3F7)
                : Colors.white.withOpacity(0.3),
            fontWeight: isCurrent ? FontWeight.w700 : FontWeight.normal,
          ),
        ),
        const SizedBox(height: 4),
        // Dot
        Container(
          width: isCurrent ? 14 : (isParent ? 10 : 8),
          height: isCurrent ? 14 : (isParent ? 10 : 8),
          decoration: BoxDecoration(
            shape: BoxShape.circle,
            color: isCurrent ? dotColor.withOpacity(0.2) : Colors.transparent,
            border: Border.all(color: dotColor, width: isCurrent ? 2 : 1.5),
          ),
          child: isCurrent
              ? Center(
                  child: Container(
                    width: 5,
                    height: 5,
                    decoration: const BoxDecoration(
                      shape: BoxShape.circle,
                      color: Color(0xFF4FC3F7),
                    ),
                  ),
                )
              : null,
        ),
        const SizedBox(height: 4),
        // Status dot
        if (task.isDone || task.status == TaskStatus.done)
          const Icon(Icons.check_rounded, size: 8, color: Color(0xFF4CAF50))
        else
          const SizedBox(height: 8),
      ],
    );
  }

