                    ],
                  ),
                ),
              ),
            ],
          ),
        ),
      ],
    );
  }

  /// Reusable End Date picker row — used in both parent Generation Range
  /// and instance forward-edit blocks.
  Widget _buildEndDateRow() {
    return Row(
      children: [
        const Text(
          'End date',
          style: TextStyle(fontSize: 11, color: Colors.white54),
        ),
        const Spacer(),
        GestureDetector(
          onTap: _pickEndDate,
          child: Container(
            padding: const EdgeInsets.symmetric(horizontal: 10, vertical: 5),
            decoration: BoxDecoration(
              color: _endDate != null
                  ? const Color(0xFF4FC3F7).withOpacity(0.1)
                  : Colors.white.withOpacity(0.05),
              borderRadius: BorderRadius.circular(4),
              border: Border.all(
                color: _endDate != null
                    ? const Color(0xFF4FC3F7).withOpacity(0.4)
                    : Colors.white.withOpacity(0.12),
              ),
            ),
            child: Row(
              mainAxisSize: MainAxisSize.min,
              children: [
                Icon(
                  Icons.calendar_today_outlined,
                  size: 11,
                  color: _endDate != null
                      ? const Color(0xFF4FC3F7)
                      : Colors.white38,
                ),
                const SizedBox(width: 6),
                Text(
                  _endDate != null ? _fmtDate(_endDate!) : 'No end date',
                  style: TextStyle(
                    fontSize: 11,
                    color: _endDate != null
                        ? const Color(0xFF4FC3F7)
                        : Colors.white38,
                  ),
                ),
              ],
            ),
          ),
        ),
        if (_endDate != null) ...[
          const SizedBox(width: 6),
          GestureDetector(
            onTap: () => setState(() => _endDate = null),
            child: const Icon(
              Icons.close_rounded,
              size: 13,
              color: Colors.white30,
            ),
          ),
        ],
      ],
    );
  }

  /// Reusable Days Ahead field — used in both parent Generation Range
  /// and instance forward-edit blocks.
  Widget _buildDaysAheadSlider() {
    final hasValue = _propagationDays != null;
    return Column(
      crossAxisAlignment: CrossAxisAlignment.stretch,
      children: [
        Row(
          children: [
            const Text(
              'Days ahead',
              style: TextStyle(fontSize: 11, color: Colors.white54),
            ),
            const Spacer(),
            // ── Text field ────────────────────────────────────────────
            SizedBox(
              width: 72,
              height: 30,
              child: TextField(
                controller: _daysAheadCtrl,
                keyboardType: TextInputType.number,
                inputFormatters: [FilteringTextInputFormatter.digitsOnly],
                textAlign: TextAlign.center,
                style: TextStyle(
                  fontSize: 12,
                  fontWeight: FontWeight.w600,
                  color: hasValue
                      ? const Color(0xFF4FC3F7)
                      : Colors.white38,
                ),
                decoration: InputDecoration(
                  isDense: true,
                  hintText: '—',
                  hintStyle: const TextStyle(
                    fontSize: 12,
                    color: Colors.white24,
                  ),
                  contentPadding: const EdgeInsets.symmetric(
                    horizontal: 8,
                    vertical: 6,
                  ),
                  suffixText: hasValue ? 'd' : null,
                  suffixStyle: const TextStyle(
                    fontSize: 11,
                    color: Color(0xFF4FC3F7),
                  ),
                  filled: true,
                  fillColor: hasValue
                      ? const Color(0xFF4FC3F7).withOpacity(0.08)
                      : Colors.white.withOpacity(0.04),
                  enabledBorder: OutlineInputBorder(
                    borderRadius: BorderRadius.circular(6),
                    borderSide: BorderSide(
                      color: hasValue
                          ? const Color(0xFF4FC3F7).withOpacity(0.3)
                          : Colors.white.withOpacity(0.12),
                    ),
                  ),
                  focusedBorder: OutlineInputBorder(
                    borderRadius: BorderRadius.circular(6),
                    borderSide: BorderSide(
                      color: hasValue
                          ? const Color(0xFF4FC3F7)
                          : Colors.white38,
                    ),
                  ),
                ),
                onChanged: (v) {
                  final parsed = int.tryParse(v);
                  setState(() {
                    _propagationDays = (parsed != null && parsed >= 1)
                        ? parsed
                        : null;
                  });
                },
                onEditingComplete: () {
                  final parsed = int.tryParse(_daysAheadCtrl.text);
                  if (parsed != null && parsed >= 1) {
                    setState(() {
                      _propagationDays = parsed;
                      _daysAheadCtrl.text = parsed.toString();
                    });
                  } else {
                    setState(() {
                      _propagationDays = null;
                      _daysAheadCtrl.clear();
                    });
                  }
                  FocusScope.of(context).unfocus();
                },
              ),
            ),
            // ── X clear button ────────────────────────────────────────
            if (hasValue) ...[
              const SizedBox(width: 4),
              GestureDetector(
                onTap: () => setState(() {
                  _propagationDays = null;
                  _daysAheadCtrl.clear();
                }),
                child: const Icon(
                  Icons.close_rounded,
                  size: 13,
                  color: Colors.white30,
                ),
              ),
            ],
          ],
        ),
        const SizedBox(height: 8),
        Text(
          _propagationDays != null && _endDate != null
              ? 'Instances generated up to ${_fmtDate(_endDate!)} or $_propagationDays days from the start date, whichever comes first.'
              : _propagationDays != null
              ? 'Instances generated for $_propagationDays days from the start date.'
              : _endDate != null
              ? 'Instances generated up to ${_fmtDate(_endDate!)}.'
              : 'Instances generated indefinitely (set a days limit or end date to cap generation).',
          style: TextStyle(
            fontSize: 10,
            color: Colors.white.withOpacity(0.35),
            fontStyle: FontStyle.italic,
          ),
        ),
      ],
    );
  }

  /// Read-only summary of the repeat config, inherited from the parent task.
  /// Tapping fires [onOpenParentConfig] which closes this dialog and reopens
  /// the parent's full repeat config dialog.
  Widget _buildReadOnlyConfig() {
    final parentId = widget.task.repeatParentId!;
    final parent = widget.allTasks.firstWhere(
      (t) => t.id == parentId,
      orElse: () => widget.task,
    );
    final cfg = parent.repeatConfig ?? widget.initial;
    final canOpen = widget.onOpenParentConfig != null;

    return _HoverContainer(
      onTap: canOpen
          ? () {
              Navigator.of(context).pop();
              widget.onOpenParentConfig!();
            }
          : null,
      borderDefault: Colors.white.withOpacity(0.07),
      borderHover: const Color(0xFF4FC3F7).withOpacity(0.4),
      child: Padding(
        padding: const EdgeInsets.all(12),
        child: Column(
          crossAxisAlignment: CrossAxisAlignment.start,
          children: [
            Row(
              children: [
                Icon(
                  Icons.link_rounded,
                  size: 11,
                  color: Colors.white.withOpacity(0.35),
                ),
                const SizedBox(width: 5),
                Text(
                  'CONFIG (inherited from parent)',
                  style: TextStyle(
                    fontSize: 9,
                    fontWeight: FontWeight.w700,
                    letterSpacing: 0.7,
                    color: Colors.white.withOpacity(0.35),
                  ),
                ),
                const Spacer(),
                if (canOpen)
                  Icon(
                    Icons.open_in_new_rounded,
                    size: 11,
                    color: Colors.white.withOpacity(0.25),
                  ),
              ],
            ),
            const SizedBox(height: 8),
            Text(
              cfg?.label ?? 'No repeat',
              style: const TextStyle(
                fontSize: 12,
                color: Colors.white70,
                fontWeight: FontWeight.w500,
              ),
            ),
            if (cfg?.endDate != null) ...[
              const SizedBox(height: 4),
              Text(
                'Ends ${_fmtDate(cfg!.endDate!)}',
                style: const TextStyle(fontSize: 10, color: Colors.white38),
              ),
            ],
          ],
        ),
      ),
    );
  }

  /// Button shown below the read-only config card for instances.
  /// Switches the dialog into forward-edit mode.
  Widget _buildEditFromHereButton() {
    return GestureDetector(
      onTap: () => setState(() => _editingForward = true),
      child: Container(
        width: double.infinity,
        padding: const EdgeInsets.symmetric(vertical: 8),
        decoration: BoxDecoration(
          color: Colors.white.withOpacity(0.03),
          borderRadius: BorderRadius.circular(6),
          border: Border.all(color: Colors.white.withOpacity(0.1)),
        ),
        child: Row(
          mainAxisAlignment: MainAxisAlignment.center,
          children: [
            Icon(
              Icons.edit_calendar_outlined,
              size: 12,
              color: Colors.white.withOpacity(0.45),
            ),
            const SizedBox(width: 7),
            Text(
              'Change repeat from this instance…',
              style: TextStyle(
                fontSize: 11,
                color: Colors.white.withOpacity(0.5),
              ),
            ),
          ],
        ),
      ),
    );
  }
}

// ─────────────────────────────────────────────────────────────────────────────
// _HoverContainer – a Container that reacts to mouse hover with a border tint.
// Used by _buildReadOnlyConfig to hint that the card is tappable.
// ─────────────────────────────────────────────────────────────────────────────

class _HoverContainer extends StatefulWidget {
  final Widget child;
  final VoidCallback? onTap;
  final Color borderDefault;
  final Color borderHover;

  const _HoverContainer({
    required this.child,
    required this.borderDefault,
    required this.borderHover,
    this.onTap,
  });

  @override
  State<_HoverContainer> createState() => _HoverContainerState();
}

class _HoverContainerState extends State<_HoverContainer> {
  bool _hovered = false;

  @override
  Widget build(BuildContext context) {
    return MouseRegion(
      cursor: widget.onTap != null
          ? SystemMouseCursors.click
          : MouseCursor.defer,
      onEnter: (_) => setState(() => _hovered = true),
      onExit: (_) => setState(() => _hovered = false),
      child: GestureDetector(
        onTap: widget.onTap,
        child: AnimatedContainer(
          duration: const Duration(milliseconds: 120),
          decoration: BoxDecoration(
            color: _hovered && widget.onTap != null
                ? Colors.white.withOpacity(0.04)
                : Colors.white.withOpacity(0.03),
            borderRadius: BorderRadius.circular(7),
            border: Border.all(
              color: _hovered && widget.onTap != null
                  ? widget.borderHover
                  : widget.borderDefault,
            ),
          ),
          child: widget.child,
        ),
      ),
    );
  }
}

// ─────────────────────────────────────────────────────────────────────────────
// _EmojiPickerButton – tappable preview that opens a floating EmojiSelector
// ─────────────────────────────────────────────────────────────────────────────

class _EmojiPickerButton extends StatefulWidget {
  final TextEditingController controller;
  final Color accentColor;

  const _EmojiPickerButton({
    required this.controller,
    required this.accentColor,
  });

  @override
  State<_EmojiPickerButton> createState() => _EmojiPickerButtonState();
}

class _EmojiPickerButtonState extends State<_EmojiPickerButton> {
  final LayerLink _layerLink = LayerLink();
  OverlayEntry? _overlayEntry;
  bool _isOpen = false;

  void _toggle() => _isOpen ? _close() : _open();

  void _open() {
    final overlay = Overlay.of(context);
    _overlayEntry = OverlayEntry(
      builder: (_) => _EmojiPickerOverlay(
        layerLink: _layerLink,
        accentColor: widget.accentColor,
        onSelect: (emoji) {
          widget.controller.text = emoji;
          widget.controller.selection = TextSelection.fromPosition(
            TextPosition(offset: emoji.length),
          );
          _close();
        },
        onClose: _close,
      ),
    );
    overlay.insert(_overlayEntry!);
    setState(() => _isOpen = true);
  }

  void _close() {
    _overlayEntry?.remove();
    _overlayEntry = null;
    if (mounted) setState(() => _isOpen = false);
  }

  @override
  void dispose() {
    _close();
    super.dispose();
  }

  @override
  Widget build(BuildContext context) {
    final icon = widget.controller.text.trim();
    final accent = widget.accentColor;
    return CompositedTransformTarget(
      link: _layerLink,
      child: GestureDetector(
        onTap: _toggle,
        child: AnimatedContainer(
          duration: const Duration(milliseconds: 150),
          width: 36,
          height: 36,
          decoration: BoxDecoration(
            color: _isOpen
                ? accent.withOpacity(0.22)
                : accent.withOpacity(0.08),
            borderRadius: BorderRadius.circular(8),
            border: Border.all(
              color: _isOpen
                  ? accent.withOpacity(0.75)
                  : accent.withOpacity(0.28),
            ),
          ),
          child: icon.isNotEmpty
              ? Center(
                  child: Text(
                    icon,
                    style: const TextStyle(
                      fontSize: 18,
                      fontFamilyFallback: [
                        'NotoColorEmoji',
                        'Apple Color Emoji',
                        'Segoe UI Emoji',
                      ],
                    ),
                  ),
                )
              : Icon(Icons.folder_outlined, color: accent, size: 18),
        ),
      ),
    );
  }
}

