class _EmojiPickerOverlay extends StatefulWidget {
  final LayerLink layerLink;
  final Color accentColor;
  final void Function(String emoji) onSelect;
  final VoidCallback onClose;

  const _EmojiPickerOverlay({
    required this.layerLink,
    required this.accentColor,
    required this.onSelect,
    required this.onClose,
  });

  @override
  State<_EmojiPickerOverlay> createState() => _EmojiPickerOverlayState();
}

class _EmojiPickerOverlayState extends State<_EmojiPickerOverlay> {
  static const _bg = Color(0xFF1A1C1E);
  static const _border = Color(0xFF2A2D30);
  static const _surface = Color(0xFF22252A);

  final _searchCtrl = TextEditingController();
  final _scrollCtrl = ScrollController();
  String _query = '';
  String _activeCategory = _kEmojiCategories.keys.first;

  @override
  void dispose() {
    _searchCtrl.dispose();
    _scrollCtrl.dispose();
    super.dispose();
  }

  List<List<String>> get _displayEmojis {
    if (_query.isNotEmpty) {
      final q = _query.toLowerCase();
      return _kEmojiCategories.values
          .expand((list) => list)
          .where((e) => e[1].contains(q) || e[0].contains(q))
          .toList();
    }
    return _kEmojiCategories[_activeCategory] ?? [];
  }

  @override
  Widget build(BuildContext context) {
    final categories = _kEmojiCategories.keys.toList();
    final emojis = _displayEmojis;
    final accent = widget.accentColor;

    return Stack(
      children: [
        Positioned.fill(
          child: GestureDetector(
            onTap: widget.onClose,
            behavior: HitTestBehavior.translucent,
          ),
        ),
        CompositedTransformFollower(
          link: widget.layerLink,
          showWhenUnlinked: false,
          targetAnchor: Alignment.bottomRight,
          followerAnchor: Alignment.topRight,
          offset: const Offset(0, 6),
          child: Material(
            color: Colors.transparent,
            child: Container(
              width: 380,
              height: 460,
              decoration: BoxDecoration(
                color: _bg,
                borderRadius: BorderRadius.circular(12),
                border: Border.all(color: _border),
                boxShadow: [
                  BoxShadow(
                    color: Colors.black.withOpacity(0.55),
                    blurRadius: 24,
                    offset: const Offset(0, 8),
                  ),
                ],
              ),
              child: Column(
                children: [
                  // ── Search bar ───────────────────────────────────────
                  Container(
                    padding: const EdgeInsets.fromLTRB(10, 10, 10, 6),
                    decoration: const BoxDecoration(
                      border: Border(bottom: BorderSide(color: _border)),
                    ),
                    child: Container(
                      height: 32,
                      decoration: BoxDecoration(
                        color: _surface,
                        borderRadius: BorderRadius.circular(7),
                        border: Border.all(color: _border),
                      ),
                      child: Row(
                        children: [
                          const SizedBox(width: 8),
                          Icon(
                            Icons.search_rounded,
                            size: 14,
                            color: Colors.white38,
                          ),
                          const SizedBox(width: 6),
                          Expanded(
                            child: TextField(
                              controller: _searchCtrl,
                              autofocus: false,
                              style: const TextStyle(
                                fontSize: 12,
                                color: Colors.white,
                              ),
                              decoration: const InputDecoration(
                                hintText: 'Search emoji…',
                                hintStyle: TextStyle(
                                  fontSize: 12,
                                  color: Colors.white30,
                                ),
                                isDense: true,
                                contentPadding: EdgeInsets.zero,
                                border: InputBorder.none,
                              ),
                              onChanged: (v) =>
                                  setState(() => _query = v.toLowerCase()),
                            ),
                          ),
                          if (_query.isNotEmpty)
                            GestureDetector(
                              onTap: () => setState(() {
                                _query = '';
                                _searchCtrl.clear();
                              }),
                              child: const Padding(
                                padding: EdgeInsets.symmetric(horizontal: 6),
                                child: Icon(
                                  Icons.close_rounded,
                                  size: 13,
                                  color: Colors.white38,
                                ),
                              ),
                            ),
                        ],
                      ),
                    ),
                  ),
                  // ── Category tabs (hidden during search) ─────────────
                  if (_query.isEmpty)
                    Container(
                      height: 34,
                      decoration: const BoxDecoration(
                        border: Border(bottom: BorderSide(color: _border)),
                      ),
                      child: ListView.builder(
                        scrollDirection: Axis.horizontal,
                        padding: const EdgeInsets.symmetric(
                          horizontal: 6,
                          vertical: 4,
                        ),
                        itemCount: categories.length,
                        itemBuilder: (_, i) {
                          final cat = categories[i];
                          final isActive = cat == _activeCategory;
                          return GestureDetector(
                            onTap: () {
                              setState(() => _activeCategory = cat);
                              _scrollCtrl.jumpTo(0);
                            },
                            child: AnimatedContainer(
                              duration: const Duration(milliseconds: 120),
                              margin: const EdgeInsets.symmetric(horizontal: 2),
                              padding: const EdgeInsets.symmetric(
                                horizontal: 10,
                                vertical: 3,
                              ),
                              decoration: BoxDecoration(
                                color: isActive
                                    ? accent.withOpacity(0.15)
                                    : Colors.transparent,
                                borderRadius: BorderRadius.circular(5),
                                border: Border.all(
                                  color: isActive
                                      ? accent.withOpacity(0.4)
                                      : Colors.transparent,
                                ),
                              ),
                              child: Text(
                                cat,
                                style: TextStyle(
                                  fontSize: 10,
                                  fontWeight: isActive
                                      ? FontWeight.w600
                                      : FontWeight.normal,
                                  color: isActive ? accent : Colors.white54,
                                ),
                              ),
                            ),
                          );
                        },
                      ),
                    ),
                  // ── Emoji grid ───────────────────────────────────────
                  Expanded(
                    child: emojis.isEmpty
                        ? Center(
                            child: Text(
                              'No emoji found',
                              style: TextStyle(
                                color: Colors.white38,
                                fontSize: 12,
                              ),
                            ),
                          )
                        : GridView.builder(
                            controller: _scrollCtrl,
                            padding: const EdgeInsets.all(8),
                            gridDelegate:
                                const SliverGridDelegateWithFixedCrossAxisCount(
                                  crossAxisCount: 8,
                                  mainAxisSpacing: 2,
                                  crossAxisSpacing: 2,
                                ),
                            itemCount: emojis.length,
                            itemBuilder: (_, i) {
                              final emoji = emojis[i][0];
                              return Tooltip(
                                message: emojis[i][1],
                                waitDuration: const Duration(milliseconds: 500),
                                child: InkWell(
                                  onTap: () => widget.onSelect(emoji),
                                  borderRadius: BorderRadius.circular(6),
                                  child: Center(
                                    child: Text(
                                      emoji,
                                      style: const TextStyle(
                                        fontSize: 20,
                                        fontFamilyFallback: [
                                          'NotoColorEmoji',
                                          'Apple Color Emoji',
                                          'Segoe UI Emoji',
                                        ],
                                      ),
                                    ),
                                  ),
                                ),
                              );
                            },
                          ),
                  ),
                ],
              ),
            ),
          ),
        ),
      ],
    );
  }
}

// ─────────────────────────────────────────────────────────────────────────────
// _FocusModePopup – centralized popup to choose Countdown / Pomodoro / Flowtime
// ─────────────────────────────────────────────────────────────────────────────

class _FocusModePopup extends StatelessWidget {
  final Task? task;
  final VoidCallback? onCountdown;
  final VoidCallback? onPomodoro;
  final VoidCallback? onFlowtime;

  static const _bg = Color(0xFF1A1C1E);
  static const _card = Color(0xFF1E2124);
  static const _border = Color(0xFF2A2D30);

  const _FocusModePopup({
    required this.task,
    this.onCountdown,
    this.onPomodoro,
    this.onFlowtime,
  });

  @override
  Widget build(BuildContext context) {
    final hasTask = task != null;

    return Container(
      width: 340,
      decoration: BoxDecoration(
        color: _bg,
        borderRadius: BorderRadius.circular(14),
        border: Border.all(color: _border),
        boxShadow: [
          BoxShadow(
            color: Colors.black.withOpacity(0.6),
            blurRadius: 32,
            offset: const Offset(0, 12),
          ),
        ],
      ),
      child: Column(
        mainAxisSize: MainAxisSize.min,
        crossAxisAlignment: CrossAxisAlignment.stretch,
        children: [
          // ── Header ─────────────────────────────────────────────────────
          Container(
            padding: const EdgeInsets.fromLTRB(18, 16, 18, 14),
            decoration: BoxDecoration(
              border: Border(bottom: BorderSide(color: _border)),
            ),
            child: Column(
              crossAxisAlignment: CrossAxisAlignment.start,
              children: [
                Row(
                  children: [
                    const Icon(
                      Icons.center_focus_strong_outlined,
                      size: 15,
                      color: Colors.white54,
                    ),
                    const SizedBox(width: 8),
                    const Text(
                      'START FOCUS',
                      style: TextStyle(
                        color: Colors.white,
                        fontSize: 13,
                        fontWeight: FontWeight.w700,
                        letterSpacing: 1.2,
                      ),
                    ),
                  ],
                ),
                if (hasTask) ...[
                  const SizedBox(height: 8),
                  Text(
                    task!.title,
                    maxLines: 2,
                    overflow: TextOverflow.ellipsis,
                    style: TextStyle(
                      fontSize: 12,
                      color: Colors.white.withOpacity(0.45),
                    ),
                  ),
                ] else ...[
                  const SizedBox(height: 6),
                  Text(
                    'No tasks available in the current view.',
                    style: TextStyle(
                      fontSize: 11,
                      color: Colors.white.withOpacity(0.3),
                    ),
                  ),
                ],
              ],
            ),
          ),

          // ── Mode buttons ────────────────────────────────────────────────
          Padding(
            padding: const EdgeInsets.all(14),
            child: Column(
              crossAxisAlignment: CrossAxisAlignment.stretch,
              children: [
                _ModeButton(
                  icon: Icons.play_arrow_rounded,
                  label: 'Countdown',
                  sublabel: 'Work until the task duration runs out',
                  color: const Color(0xFF4CAF50),
                  enabled: hasTask,
                  onTap: onCountdown,
                ),
                const SizedBox(height: 8),
                _ModeButton(
                  icon: Icons.timer_outlined,
                  label: 'Pomodoro',
                  sublabel: 'Focused sprints with scheduled breaks',
                  color: const Color(0xFFFFB74D),
                  enabled: hasTask,
                  onTap: onPomodoro,
                ),
                const SizedBox(height: 8),
                _ModeButton(
                  icon: Icons.waves_rounded,
                  label: 'Flowtime',
                  sublabel: 'Work freely, break when you feel it',
                  color: const Color(0xFF9575CD),
                  enabled: hasTask,
                  onTap: onFlowtime,
                ),
              ],
            ),
          ),
        ],
      ),
    );
  }
}

class _ModeButton extends StatefulWidget {
  final IconData icon;
  final String label;
  final String sublabel;
  final Color color;
  final bool enabled;
  final VoidCallback? onTap;

  const _ModeButton({
    required this.icon,
    required this.label,
    required this.sublabel,
    required this.color,
    required this.enabled,
    this.onTap,
  });

  @override
  State<_ModeButton> createState() => _ModeButtonState();
}

class _ModeButtonState extends State<_ModeButton> {
  bool _hovered = false;

  @override
  Widget build(BuildContext context) {
    final c = widget.enabled ? widget.color : Colors.white24;

    return MouseRegion(
      onEnter: (_) => setState(() => _hovered = true),
      onExit: (_) => setState(() => _hovered = false),
      child: GestureDetector(
        onTap: widget.enabled ? widget.onTap : null,
        child: AnimatedContainer(
          duration: const Duration(milliseconds: 120),
          padding: const EdgeInsets.symmetric(horizontal: 14, vertical: 12),
          decoration: BoxDecoration(
            color: _hovered && widget.enabled
                ? c.withOpacity(0.13)
                : c.withOpacity(0.07),
            borderRadius: BorderRadius.circular(9),
            border: Border.all(
              color: _hovered && widget.enabled
                  ? c.withOpacity(0.55)
                  : c.withOpacity(0.22),
            ),
          ),
          child: Row(
            children: [
              Container(
                width: 32,
                height: 32,
                decoration: BoxDecoration(
                  color: c.withOpacity(0.15),
                  borderRadius: BorderRadius.circular(7),
                ),
                child: Icon(widget.icon, size: 17, color: c),
              ),
              const SizedBox(width: 12),
              Expanded(
                child: Column(
                  crossAxisAlignment: CrossAxisAlignment.start,
                  children: [
                    Text(
                      widget.label,
                      style: TextStyle(
                        fontSize: 13,
                        fontWeight: FontWeight.w600,
                        color: widget.enabled ? Colors.white : Colors.white38,
                      ),
                    ),
                    const SizedBox(height: 2),
                    Text(
                      widget.sublabel,
                      style: TextStyle(
                        fontSize: 10,
                        color: widget.enabled
                            ? Colors.white.withOpacity(0.35)
                            : Colors.white12,
                      ),
                    ),
                  ],
                ),
              ),
              Icon(
                Icons.chevron_right_rounded,
                size: 16,
                color: c.withOpacity(widget.enabled ? 0.6 : 0.2),
              ),
            ],
          ),
        ),
      ),
    );
  }
}

// ─────────────────────────────────────────────────────────────────────────────
// _HoverLabelBtn – icon button that expands to show a label on hover.
// Used for the Filter / Group / Sort button in the task-list topbar.
// ─────────────────────────────────────────────────────────────────────────────

// ─────────────────────────────────────────────────────────────────────────────
// _OverflowTopBar — responsive button row that collapses into a ⋮ menu
//
// Usage: supply [pinned] buttons that always show, and [collapsible] buttons
// that hide when horizontal space is insufficient. Each collapsible button
// provides an [icon], [label], and [onTap] for the overflow menu entry.
// ─────────────────────────────────────────────────────────────────────────────

class _OverflowItem {
  final Widget button; // the full widget shown in the bar when space allows
  final IconData icon; // icon shown in the overflow menu
  final String label; // label shown in the overflow menu
  final VoidCallback onTap;

  const _OverflowItem({
    required this.button,
    required this.icon,
    required this.label,
    required this.onTap,
  });
}

class _OverflowTopBar extends StatelessWidget {
  /// Widgets that never collapse (leftmost — usually the title).
  final List<Widget> leading;

  /// Buttons that collapse into the ⋮ menu when space is tight.
  final List<_OverflowItem> collapsible;

  /// Widgets that never collapse (rightmost — e.g. close button).
  final List<Widget> trailing;

  /// Estimated width of each collapsible button (icon btn = 36, etc.)
  final double buttonWidth;

  /// Gap between buttons.
  final double gap;

  const _OverflowTopBar({
    Key? key,
    required this.leading,
    required this.collapsible,
    this.trailing = const [],
    this.buttonWidth = 36.0,
    this.gap = 4.0,
  }) : super(key: key);

  @override
  Widget build(BuildContext context) {
    return LayoutBuilder(
      builder: (context, constraints) {
        final available = constraints.maxWidth;

        // Estimate leading width (intrinsic would be ideal but costly;
        // we use a generous heuristic of 200px for the title area).
        const leadingEst = 200.0;
        // Trailing: 32px × count + gaps
        final trailingEst = trailing.length * 36.0 + (trailing.length * gap);
        // Overflow button itself: 32px
        const overflowBtnW = 32.0;

        // Space available for collapsible buttons
        final spaceForButtons = available - leadingEst - trailingEst - gap * 2;

        // How many collapsible buttons fit?
        final eachW = buttonWidth + gap;
        final maxFit = spaceForButtons > 0
            ? (spaceForButtons / eachW).floor().clamp(0, collapsible.length)
            : 0;

        // If all fit, no overflow button needed. If none fit, still try at
        // least showing the overflow button itself.
        final shown = collapsible.take(maxFit).toList();
        final hidden = collapsible.skip(maxFit).toList();
        final needsOverflow = hidden.isNotEmpty;

        return Row(
          children: [
            // ── Leading (title etc.) ──────────────────────────────────────
            ...leading,
            const Spacer(),
            // ── Visible collapsible buttons ───────────────────────────────
            ...shown.expand((item) => [item.button, SizedBox(width: gap)]),
            // ── Overflow ⋮ button ─────────────────────────────────────────
            if (needsOverflow)
              PopupMenuButton<int>(
                icon: const Icon(
                  Icons.more_vert_rounded,
                  size: 16,
                  color: Colors.white54,
                ),
                tooltip: 'More options',
                color: const Color(0xFF1E2124),
                shape: RoundedRectangleBorder(
                  borderRadius: BorderRadius.circular(8),
                  side: BorderSide(color: Colors.white.withOpacity(0.08)),
                ),
                padding: EdgeInsets.zero,
                constraints: const BoxConstraints(minWidth: 32, minHeight: 32),
                onSelected: (idx) => hidden[idx].onTap(),
                itemBuilder: (_) => hidden.asMap().entries.map((entry) {
                  final i = entry.key;
                  final item = entry.value;
                  return PopupMenuItem<int>(
                    value: i,
                    height: 38,
                    child: Row(
                      children: [
                        Icon(item.icon, size: 14, color: Colors.white54),
                        const SizedBox(width: 10),
                        Text(
                          item.label,
                          style: const TextStyle(
                            fontSize: 12,
                            color: Colors.white70,
                          ),
                        ),
                      ],
                    ),
                  );
                }).toList(),
              ),
            if (needsOverflow) SizedBox(width: gap),
            // ── Trailing (always visible) ─────────────────────────────────
            ...trailing.expand((w) => [w, SizedBox(width: gap)]),
          ],
        );
      },
    );
  }
}

class _HoverLabelBtn extends StatefulWidget {
  final IconData icon;
  final String hoverLabel;
  final bool isActive;
  final VoidCallback onTap;

  const _HoverLabelBtn({
    super.key,
    required this.icon,
    required this.hoverLabel,
    required this.isActive,
    required this.onTap,
  });

  @override
  State<_HoverLabelBtn> createState() => _HoverLabelBtnState();
}

class _HoverLabelBtnState extends State<_HoverLabelBtn> {
  bool _hovered = false;

  @override
  Widget build(BuildContext context) {
    const accent = Color(0xFF4FC3F7);
    final active = widget.isActive || _hovered;

    return MouseRegion(
      cursor: SystemMouseCursors.click,
      onEnter: (_) => setState(() => _hovered = true),
      onExit: (_) => setState(() => _hovered = false),
      child: GestureDetector(
        onTap: widget.onTap,
        child: AnimatedContainer(
          duration: const Duration(milliseconds: 150),
          height: 32,
          padding: const EdgeInsets.symmetric(horizontal: 8),
          decoration: BoxDecoration(
            color: active
                ? accent.withOpacity(0.10)
                : Colors.white.withOpacity(0.04),
            borderRadius: BorderRadius.circular(6),
            border: Border.all(
              color: active ? accent.withOpacity(0.35) : Colors.white12,
            ),
          ),
          child: Icon(
            widget.icon,
            size: 15,
            color: active ? accent : Colors.white54,
          ),
        ),
      ),
    );
  }
}

// ─────────────────────────────────────────────────────────────────────────────
// _DropdownDialog – lightweight overlay used by the filter sidebar dropdowns.
// ─────────────────────────────────────────────────────────────────────────────

class _DropdownDialog<T> extends StatelessWidget {
  final T current;
  final List<T> items;
  final String Function(T) itemLabel;
  final void Function(T) onSelected;

  const _DropdownDialog({
    required this.current,
    required this.items,
    required this.itemLabel,
    required this.onSelected,
  });

  @override
  Widget build(BuildContext context) {
    return GestureDetector(
      onTap: () => Navigator.of(context).pop(),
      child: Material(
        color: Colors.transparent,
        child: Stack(
          children: [
            Positioned.fill(child: Container(color: Colors.transparent)),
            Center(
              child: Container(
                width: 220,
                constraints: const BoxConstraints(maxHeight: 320),
                decoration: BoxDecoration(
                  color: const Color(0xFF1E2124),
                  borderRadius: BorderRadius.circular(8),
                  border: Border.all(color: Colors.white.withOpacity(0.1)),
                  boxShadow: [
                    BoxShadow(
                      color: Colors.black.withOpacity(0.5),
                      blurRadius: 20,
                      offset: const Offset(0, 8),
                    ),
                  ],
                ),
                child: ClipRRect(
                  borderRadius: BorderRadius.circular(8),
                  child: ListView(
                    padding: const EdgeInsets.symmetric(vertical: 6),
                    shrinkWrap: true,
                    children: items.map((item) {
                      final selected = item == current;
                      return GestureDetector(
                        onTap: () => onSelected(item),
                        child: Container(
                          padding: const EdgeInsets.symmetric(
                            horizontal: 14,
                            vertical: 9,
                          ),
                          color: selected
                              ? const Color(0xFF4FC3F7).withOpacity(0.10)
                              : Colors.transparent,
                          child: Row(
                            children: [
                              Expanded(
                                child: Text(
                                  itemLabel(item),
                                  style: TextStyle(
                                    fontSize: 12,
                                    color: selected
                                        ? const Color(0xFF4FC3F7)
                                        : Colors.white70,
                                    fontWeight: selected
                                        ? FontWeight.w600
                                        : FontWeight.normal,
                                  ),
                                ),
                              ),
                              if (selected)
                                const Icon(
                                  Icons.check_rounded,
                                  size: 13,
                                  color: Color(0xFF4FC3F7),
                                ),
                            ],
                          ),
                        ),
                      );
                    }).toList(),
                  ),
                ),
              ),
            ),
          ],
        ),
      ),
    );
  }
}

