// ─────────────────────────────────────────────────────────────────────────────
// _PlannerView  –  Kanban-style horizontal day planner (2 weeks + overdue)
// ─────────────────────────────────────────────────────────────────────────────

class _PlannerView extends StatefulWidget {
  final List<Task> allTasks;
  final Map<String, Project> projects;
  final Map<String, Color> projectColors;
  final void Function(String dueDay, Task task) onAddTask;
  final void Function(Task) onTaskTap;
  final void Function(Task) onStatusToggle;
  final void Function(Task, TaskStatus) onStatusSelect;
  final void Function(Task, String? newDueDay, int? newPlannedAt) onReschedule;
  final void Function(Task) onDelete;
  final void Function(Task, String tag) onToggleTag;
  final void Function(Task, String projectId) onMoveToProject;
  final void Function(Task) onStartFocus;
  final void Function(Task, Offset) onContextMenu;

  const _PlannerView({
    required this.allTasks,
    required this.projects,
    required this.projectColors,
    required this.onAddTask,
    required this.onTaskTap,
    required this.onStatusToggle,
    required this.onStatusSelect,
    required this.onReschedule,
    required this.onDelete,
    required this.onToggleTag,
    required this.onMoveToProject,
    required this.onStartFocus,
    required this.onContextMenu,
  });

  @override
  State<_PlannerView> createState() => _PlannerViewState();
}

class _PlannerViewState extends State<_PlannerView> {
  final ScrollController _hScroll = ScrollController();
  final ScrollController _overdueScroll = ScrollController();
  final ScrollController _nodateScroll = ScrollController();
  static const double _colWidth = 230.0;
  static const double _headerHeight = 56.0;

  @override
  void dispose() {
    _hScroll.dispose();
    _overdueScroll.dispose();
    _nodateScroll.dispose();
    super.dispose();
  }

  String _isoDay(DateTime d) =>
      '${d.year}-${d.month.toString().padLeft(2, '0')}-${d.day.toString().padLeft(2, '0')}';

  String _shortMonth(int m) => const [
    '',
    'Jan',
    'Feb',
    'Mar',
    'Apr',
    'May',
    'Jun',
    'Jul',
    'Aug',
    'Sep',
    'Oct',
    'Nov',
    'Dec',
  ][m];

  String _weekday(int wd) =>
      const ['', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat', 'Sun'][wd];

  // ── Drag state ──────────────────────────────────────────────────────────────
  Task? _draggingTask;
  String? _dragOverCol; // iso day key or 'overdue'

  void _onDrop(Task task, String? targetDueDay, bool inScheduledZone) async {
    // Feature 6: dropping onto the Overdue or No-Date column (targetDueDay == null)
    // must ask for a new date rather than silently clearing / keeping a past date.
    if (targetDueDay == null) {
      await _promptNewDateForTask(task, inScheduledZone);
      setState(() {
        _draggingTask = null;
        _dragOverCol = null;
      });
      return;
    }

    if (inScheduledZone) {
      // Show time-picker pre-filled with the column's date
      final date = DateTime.tryParse(targetDueDay);
      if (date == null) return;
      final picked = await showTimePicker(
        context: context,
        initialTime: TimeOfDay.now(),
        builder: (ctx, child) => Theme(
          data: Theme.of(ctx).copyWith(
            colorScheme: const ColorScheme.dark(
              primary: Color(0xFF4FC3F7),
              surface: Color(0xFF1E2124),
            ),
            timePickerTheme: const TimePickerThemeData(
              backgroundColor: Color(0xFF1E2124),
            ),
          ),
          child: child!,
        ),
      );
      if (picked == null) return;
      final withTime = DateTime(
        date.year,
        date.month,
        date.day,
        picked.hour,
        picked.minute,
      );
      widget.onReschedule(task, targetDueDay, withTime.millisecondsSinceEpoch);
    } else {
      widget.onReschedule(task, targetDueDay, null);
    }
    setState(() {
      _draggingTask = null;
      _dragOverCol = null;
    });
  }

  /// Shows a date picker (+ optional time picker for scheduled tasks) when a
  /// task is dropped onto the Overdue or No-Date column. On confirmation the
  /// task gets its new date; on cancellation nothing changes.
  Future<void> _promptNewDateForTask(Task task, bool inScheduledZone) async {
    final now = DateTime.now();
    final yesterday = DateTime(now.year, now.month, now.day - 1);

    // Determine whether this task originally had a time component.
    final hadTime = task.plannedAt != null && task.plannedAt! > 0;
    final originalTime = hadTime
        ? TimeOfDay.fromDateTime(
            DateTime.fromMillisecondsSinceEpoch(task.plannedAt!),
          )
        : null;

    final pickedDate = await showDatePicker(
      context: context,
      initialDate: yesterday,
      firstDate: DateTime(2020),
      lastDate: DateTime(2099),
      builder: (ctx, child) => Theme(
        data: Theme.of(ctx).copyWith(
          colorScheme: const ColorScheme.dark(
            primary: Color(0xFF4FC3F7),
            surface: Color(0xFF1E2124),
            onSurface: Colors.white,
          ),
          dialogBackgroundColor: const Color(0xFF1E2124),
        ),
        child: child!,
      ),
    );
    if (pickedDate == null) return; // cancelled — leave task untouched

    final isoDate =
        '${pickedDate.year}-${pickedDate.month.toString().padLeft(2, '0')}-${pickedDate.day.toString().padLeft(2, '0')}';

    if (hadTime || inScheduledZone) {
      // Also pick a time
      final pickedTime = await showTimePicker(
        context: context,
        initialTime: originalTime ?? TimeOfDay.now(),
        builder: (ctx, child) => Theme(
          data: Theme.of(ctx).copyWith(
            colorScheme: const ColorScheme.dark(
              primary: Color(0xFF4FC3F7),
              surface: Color(0xFF1E2124),
            ),
            timePickerTheme: const TimePickerThemeData(
              backgroundColor: Color(0xFF1E2124),
            ),
          ),
          child: child!,
        ),
      );
      if (pickedTime == null) return; // cancelled
      final withTime = DateTime(
        pickedDate.year,
        pickedDate.month,
        pickedDate.day,
        pickedTime.hour,
        pickedTime.minute,
      );
      widget.onReschedule(task, isoDate, withTime.millisecondsSinceEpoch);
    } else {
      widget.onReschedule(task, isoDate, null);
    }
  }

  @override
  Widget build(BuildContext context) {
    final now = DateTime.now();
    final today = DateTime(now.year, now.month, now.day);
    final days = List.generate(14, (i) => today.add(Duration(days: i)));

    final allSubtaskIds = widget.allTasks
        .expand((t) => t.subTaskIds.map((id) => id.toString()))
        .toSet();

    List<Task> overdueTasks = [];
    List<Task> noDateTasks = []; // Feature 3: tasks with no date at all
    final Map<String, List<Task>> dayUnscheduled = {};
    final Map<String, List<Task>> dayScheduled = {};
    for (final day in days) {
      final iso = _isoDay(day);
      dayUnscheduled[iso] = [];
      dayScheduled[iso] = [];
    }

    // ── Feature 11: effective project ids for repeat instances ──────────────
    // Build taskId → effective projectId so repeat instances can display
    // their parent task's project even though projectId is final on Task.
    final Map<String, String> effectiveProjectIds = {};
    for (final t in widget.allTasks) {
      if (t.repeatParentId != null && t.projectId == 'INBOX_PROJECT') {
        try {
          final parent = widget.allTasks.firstWhere(
            (p) => p.id == t.repeatParentId,
          );
          if (parent.projectId != 'INBOX_PROJECT') {
            effectiveProjectIds[t.id] = parent.projectId;
          }
        } catch (_) {}
      }
    }

    for (final t in widget.allTasks) {
      if (allSubtaskIds.contains(t.id)) continue;
      // done/cancelled tasks stay in the planner (shown with strikethrough)

      // ── Feature 10: Support tasks with plannedAt but no/null dueDay ───────
      // scheduledDate reads plannedAt first, then falls back to dueDay.
      final schedDate = t.scheduledDate;
      final dueDay = t.dueDay;
      // Determine the canonical day for bucketing
      DateTime? dayOnly;
      if (schedDate != null) {
        dayOnly = schedDate;
      } else if (dueDay != null) {
        final d = DateTime.tryParse(dueDay);
        if (d != null) dayOnly = DateTime(d.year, d.month, d.day);
      }
      if (dayOnly == null) {
        noDateTasks.add(t); // Feature 3: no date → "No Date" column
        continue;
      }

      if (dayOnly.isBefore(today)) {
        overdueTasks.add(t);
        continue;
      }
      final iso = _isoDay(dayOnly);
      if (!dayUnscheduled.containsKey(iso)) continue;
      // A task is "scheduled" (shows in timed zone) when plannedAt is set
      // AND durationMinutes > 0 — matching scheduledDateTime getter logic.
      if (t.plannedAt != null && t.plannedAt! > 0 && t.durationMinutes > 0) {
        dayScheduled[iso]!.add(t);
      } else {
        dayUnscheduled[iso]!.add(t);
      }
    }
    for (final list in dayScheduled.values) {
      list.sort((a, b) => (a.plannedAt ?? 0).compareTo(b.plannedAt ?? 0));
    }

    final allTags = {
      for (final t in widget.allTasks) ...t.tagIds.map((id) => id.toString()),
    }.toList()..sort();

    _PlannerColumnWidget buildCol({
      required bool isOverdue,
      bool isToday = false,
      required String headerLabel,
      String? headerCount,
      required String? colDueDay,
      required List<Task> unscheduled,
      required List<Task> scheduled,
    }) {
      return _PlannerColumnWidget(
        isOverdue: isOverdue,
        isToday: isToday,
        headerLabel: headerLabel,
        headerCount: headerCount,
        headerHeight: _headerHeight,
        colDueDay: colDueDay,
        colKey: colDueDay ?? 'overdue',
        unscheduledTasks: unscheduled,
        scheduledTasks: scheduled,
        projects: widget.projects,
        projectColors: widget.projectColors,
        effectiveProjectIds: effectiveProjectIds,
        allTags: allTags,
        draggingTask: _draggingTask,
        dragOverCol: _dragOverCol,
        onDragStart: (t) => setState(() => _draggingTask = t),
        onDragEnd: () => setState(() {
          _draggingTask = null;
          _dragOverCol = null;
        }),
        onDragEnter: (col) => setState(() => _dragOverCol = col),
        onDrop: _onDrop,
        onAddTask: isOverdue
            ? null
            : (task) => widget.onAddTask(colDueDay!, task),
        onTaskTap: widget.onTaskTap,
        onStatusToggle: widget.onStatusToggle,
        onStatusSelect: widget.onStatusSelect,
        onContextMenu: (task, offset) => widget.onContextMenu(task, offset),
      );
    }

    // dayCols: one _PlannerColumnWidget per day in the scrolling area
    final dayCols = days.map((day) {
      final iso = _isoDay(day);
      final isToday = day == today;
      final wd = _weekday(day.weekday);
      final label = isToday
          ? '☀ $wd ${_shortMonth(day.month)}/${day.day}'
          : '$wd ${_shortMonth(day.month)}/${day.day}';
      return buildCol(
        isOverdue: false,
        isToday: isToday,
        headerLabel: label,
        headerCount: null,
        colDueDay: iso,
        unscheduled: dayUnscheduled[iso] ?? [],
        scheduled: dayScheduled[iso] ?? [],
      );
    }).toList();

    return Container(
      color: AppTheme.of(context).colors.canvasBg,
      child: Row(
        crossAxisAlignment: CrossAxisAlignment.stretch,
        children: [
          // ── Combined split column: Overdue (top) | No Date (bottom) ─
          SizedBox(
            width: _colWidth,
            child: _buildSplitColumn(
              context: context,
              overdueTasks: overdueTasks,
              noDateTasks: noDateTasks,
              effectiveProjectIds: effectiveProjectIds,
              allTags: allTags,
            ),
          ),
          Container(width: 1, color: Colors.white.withOpacity(0.06)),
          Expanded(
            child: Scrollbar(
              controller: _hScroll,
              thumbVisibility: true,
              trackVisibility: true,
              child: SingleChildScrollView(
                controller: _hScroll,
                scrollDirection: Axis.horizontal,
                child: SizedBox(
                  // Fix: give a concrete height so columns stretch properly
                  height: MediaQuery.of(context).size.height,
                  child: Row(
                    crossAxisAlignment: CrossAxisAlignment.stretch,
                    children: dayCols
                        .map(
                          (col) => Row(
                            crossAxisAlignment: CrossAxisAlignment.stretch,
                            children: [
                              SizedBox(width: _colWidth, child: col),
                              Container(
                                width: 1,
                                color: Colors.white.withOpacity(0.06),
                              ),
                            ],
                          ),
                        )
                        .toList(),
                  ),
                ),
              ),
            ),
          ),
        ],
      ),
    );
  }

  // ── Split column: Overdue (top half) / No Date (bottom half) ─────────────
  //
  // Each half has its own independent ScrollController and Scrollbar.
  // DragTargets wrap the full scrollable area of each half so drops are
  // accepted anywhere in the section, not just on the empty-state placeholder.
  //
  // Drop routing:
  //   • Overdue  half  → targetDueDay = null, inScheduledZone = hadTime
  //                       → triggers _promptNewDateForTask (date picker)
  //   • No Date  half  → targetDueDay = null, inScheduledZone = false
  //                       → _onDrop clears dueDay + plannedAt
  //
  // The distinction is made via a separate _onDropNoDate helper that always
  // clears the date, bypassing the date-prompt path in _onDrop.
  Widget _buildSplitColumn({
    required BuildContext context,
    required List<Task> overdueTasks,
    required List<Task> noDateTasks,
    required Map<String, String> effectiveProjectIds,
    required List<String> allTags,
  }) {
    final isLight = AppTheme.of(context).isLight;
    final colors = AppTheme.of(context).colors;
    final overdueAccent = const Color(0xFFEF5350);
    final nodateAccent = Colors.white54;

    final isOverdueDropTarget =
        _dragOverCol == 'overdue' && _draggingTask != null;
    final isNodateDropTarget =
        _dragOverCol == 'nodate' && _draggingTask != null;

    // ── Shared card-list builder ────────────────────────────────────────────
    List<Widget> buildCards(List<Task> tasks) => tasks.map((t) {
      final proj = widget.projects[t.projectId];
      final effPid = effectiveProjectIds[t.id] ?? t.projectId;
      final projColor = widget.projectColors[effPid] ?? Colors.white24;
      final isDone = t.status == TaskStatus.done;

      return Draggable<Task>(
        data: t,
        feedback: Material(
          color: Colors.transparent,
          child: Opacity(
            opacity: 0.85,
            child: SizedBox(
              width: _colWidth - 24,
              child: Container(
                margin: const EdgeInsets.fromLTRB(12, 4, 12, 0),
                padding: const EdgeInsets.fromLTRB(10, 8, 10, 8),
                decoration: BoxDecoration(
                  color: const Color(0xFF252830),
                  borderRadius: BorderRadius.circular(7),
                  border: Border.all(
                    color: const Color(0xFF4FC3F7).withOpacity(0.5),
                  ),
                  boxShadow: [
                    BoxShadow(
                      color: Colors.black.withOpacity(0.4),
                      blurRadius: 12,
                    ),
                  ],
                ),
                child: Text(
                  t.title,
                  style: const TextStyle(fontSize: 12, color: Colors.white),
                  maxLines: 1,
                  overflow: TextOverflow.ellipsis,
                ),
              ),
            ),
          ),
        ),
        childWhenDragging: Opacity(
          opacity: 0.25,
          child: _splitCard(context, t, proj, projColor, isDone, isLight),
        ),
        onDragStarted: () => setState(() => _draggingTask = t),
        onDragEnd: (_) => setState(() {
          _draggingTask = null;
          _dragOverCol = null;
        }),
        child: GestureDetector(
          onTap: () => widget.onTaskTap(t),
          onSecondaryTapDown: (d) => widget.onContextMenu(t, d.globalPosition),
          child: _splitCard(context, t, proj, projColor, isDone, isLight),
        ),
      );
    }).toList();

    // ── Header builder ──────────────────────────────────────────────────────
    Widget buildHeader(
      String label,
      int count,
      Color accent,
      bool isDropTarget,
    ) {
      return SizedBox(
        height: _headerHeight,
        child: Container(
          padding: const EdgeInsets.fromLTRB(12, 0, 12, 0),
          alignment: Alignment.centerLeft,
          decoration: BoxDecoration(
            color: isDropTarget ? accent.withOpacity(0.05) : Colors.transparent,
            border: Border(bottom: BorderSide(color: colors.borderSubtle)),
          ),
          child: Row(
            children: [
              Expanded(
                child: Text(
                  label,
                  style: TextStyle(
                    fontSize: 13,
                    fontWeight: FontWeight.w700,
                    color: accent,
                    letterSpacing: 0.2,
                  ),
                ),
              ),
              Container(
                padding: const EdgeInsets.symmetric(horizontal: 6, vertical: 1),
                decoration: BoxDecoration(
                  color: accent.withOpacity(0.12),
                  borderRadius: BorderRadius.circular(8),
                ),
                child: Text(
                  '$count',
                  style: TextStyle(
                    fontSize: 10,
                    fontWeight: FontWeight.w700,
                    color: accent.withOpacity(0.8),
                  ),
                ),
              ),
            ],
          ),
        ),
      );
    }

    // ── Half builder ────────────────────────────────────────────────────────
    Widget buildHalf({
      required List<Task> tasks,
      required List<Widget> cards,
      required String colKey,
      required ScrollController scrollCtrl,
      required Color accent,
      required bool isDropTarget,
      required void Function(Task, bool) onDrop,
      required String emptyLabel,
    }) {
      return Expanded(
        child: AnimatedContainer(
          duration: const Duration(milliseconds: 120),
          decoration: BoxDecoration(
            color: isDropTarget ? accent.withOpacity(0.04) : Colors.transparent,
            border: isDropTarget
                ? Border.all(color: accent.withOpacity(0.25))
                : null,
          ),
          child: DragTarget<Task>(
            onWillAcceptWithDetails: (_) {
              setState(() => _dragOverCol = colKey);
              return true;
            },
            onLeave: (_) {
              if (_dragOverCol == colKey) setState(() => _dragOverCol = null);
            },
            onAcceptWithDetails: (details) => onDrop(
              details.data,
              details.data.plannedAt != null && details.data.plannedAt! > 0,
            ),
            builder: (ctx, candidates, _) {
              final hovering = candidates.isNotEmpty;
              return Scrollbar(
                controller: scrollCtrl,
                thumbVisibility: true,
                trackVisibility: true,
                child: SingleChildScrollView(
                  controller: scrollCtrl,
                  child: Column(
                    crossAxisAlignment: CrossAxisAlignment.stretch,
                    children: [
                      if (tasks.isEmpty)
                        Padding(
                          padding: const EdgeInsets.fromLTRB(12, 12, 12, 8),
                          child: Text(
                            hovering ? 'Drop here…' : emptyLabel,
                            style: TextStyle(
                              fontSize: 11,
                              fontStyle: FontStyle.italic,
                              color: hovering
                                  ? accent.withOpacity(0.6)
                                  : (isLight
                                        ? const Color(0xFFB0B8C4)
                                        : Colors.white.withOpacity(0.24)),
                            ),
                          ),
                        )
                      else
                        ...cards,
                      const SizedBox(height: 16),
                    ],
                  ),
                ),
              );
            },
          ),
        ),
      );
    }

    return Column(
      crossAxisAlignment: CrossAxisAlignment.stretch,
      children: [
        // ── TOP HALF — OVERDUE ─────────────────────────────────────────
        buildHeader(
          'Overdue',
          overdueTasks.length,
          overdueAccent,
          isOverdueDropTarget,
        ),
        buildHalf(
          tasks: overdueTasks,
          cards: buildCards(overdueTasks),
          colKey: 'overdue',
          scrollCtrl: _overdueScroll,
          accent: overdueAccent,
          isDropTarget: isOverdueDropTarget,
          // Overdue drops trigger the date prompt (_onDrop with null targetDueDay)
          onDrop: (task, hadTime) => _onDrop(task, null, hadTime),
          emptyLabel: 'No overdue tasks',
        ),

        // ── DIVIDER ────────────────────────────────────────────────────
        Divider(
          thickness: 1,
          height: 1,
          color: isLight ? const Color(0xFFD0D4DA) : const Color(0xFF2C2F35),
        ),

        // ── BOTTOM HALF — NO DATE ──────────────────────────────────────
        buildHeader(
          'No Date',
          noDateTasks.length,
          nodateAccent,
          isNodateDropTarget,
        ),
        buildHalf(
          tasks: noDateTasks,
          cards: buildCards(noDateTasks),
          colKey: 'nodate',
          scrollCtrl: _nodateScroll,
          accent: nodateAccent,
          isDropTarget: isNodateDropTarget,
          // No Date drops clear both dates (onReschedule with null, null)
          onDrop: (task, _) {
            widget.onReschedule(task, null, null);
            setState(() {
              _draggingTask = null;
              _dragOverCol = null;
            });
          },
          emptyLabel: 'No undated tasks',
        ),
      ],
    );
  }

  // ── Shared card widget used inside the split column ───────────────────────
  Widget _splitCard(
    BuildContext context,
    Task t,
    Project? proj,
    Color projColor,
    bool isDone,
    bool isLight,
  ) {
    final statusColor = t.status.color;
    final statusBorder = adaptiveBorder(statusColor, isLight);
    return Container(
      margin: const EdgeInsets.fromLTRB(12, 4, 12, 0),
      padding: const EdgeInsets.fromLTRB(10, 8, 10, 8),
      decoration: BoxDecoration(
        color: isLight ? Colors.white : const Color(0xFF1C1F24),
        borderRadius: BorderRadius.circular(7),
        border: Border.all(
          color: isLight
              ? const Color(0xFFD0D4DA)
              : Colors.white.withOpacity(0.07),
        ),
      ),
      child: Row(
        crossAxisAlignment: CrossAxisAlignment.start,
        children: [
          GestureDetector(
            onTap: () => widget.onStatusToggle(t),
            child: Padding(
              padding: const EdgeInsets.only(top: 1, right: 8),
              child: Container(
                width: 18,
                height: 18,
                decoration: BoxDecoration(
                  shape: BoxShape.circle,
                  border: statusBorder,
                ),
                child: Icon(
                  t.status.icon,
                  size: 14,
                  color: (isDone || t.status == TaskStatus.cancelled)
                      ? Colors.white24
                      : statusColor,
                ),
              ),
            ),
          ),
          Expanded(
            child: Column(
              crossAxisAlignment: CrossAxisAlignment.start,
              children: [
                Text(
                  t.title,
                  style: TextStyle(
                    fontSize: 12,
                    color: (isDone || t.status == TaskStatus.cancelled)
                        ? (isLight ? Colors.black26 : Colors.white30)
                        : (isLight
                              ? const Color(0xFF1A1C22)
                              : Colors.white.withOpacity(0.85)),
                    decoration: (isDone || t.status == TaskStatus.cancelled)
                        ? TextDecoration.lineThrough
                        : null,
                    decorationColor: isLight ? Colors.black26 : Colors.white24,
                  ),
                  maxLines: 2,
                  overflow: TextOverflow.ellipsis,
                ),
                if (proj != null) ...[
                  const SizedBox(height: 3),
                  Row(
                    children: [
                      Icon(
                        Icons.folder_outlined,
                        size: 10,
                        color: projColor.withOpacity(0.7),
                      ),
                      const SizedBox(width: 3),
                      Flexible(
                        child: Text(
                          proj.title,
                          style: TextStyle(
                            fontSize: 9,
                            color: projColor.withOpacity(0.7),
                          ),
                          overflow: TextOverflow.ellipsis,
                        ),
                      ),
                    ],
                  ),
                ],
                if (t.tagIds.isNotEmpty) ...[
                  const SizedBox(height: 3),
                  Wrap(
                    spacing: 4,
                    children: t.tagIds
                        .take(3)
                        .map(
                          (tag) => Container(
                            padding: const EdgeInsets.symmetric(
                              horizontal: 5,
                              vertical: 1,
                            ),
                            decoration: BoxDecoration(
                              color: isLight
                                  ? const Color(0xFFEEF0F3)
                                  : Colors.white.withOpacity(0.06),
                              borderRadius: BorderRadius.circular(3),
                            ),
                            child: Text(
                              tag.toString(),
                              style: TextStyle(
                                fontSize: 8,
                                color: isLight
                                    ? const Color(0xFF555D6B)
                                    : Colors.white38,
                              ),
                            ),
                          ),
                        )
                        .toList(),
                  ),
                ],
              ],
            ),
          ),
          // Details button
          GestureDetector(
            onTap: () => widget.onTaskTap(t),
            child: Tooltip(
              message: 'Open details',
              child: Padding(
                padding: const EdgeInsets.only(left: 4, top: 1),
                child: Icon(
                  Icons.open_in_new_rounded,
                  size: 12,
                  color: isLight
                      ? const Color(0xFF9EA7B3)
                      : Colors.white.withOpacity(0.25),
                ),
              ),
            ),
          ),
        ],
      ),
    );
  }
}

// ─────────────────────────────────────────────────────────────────────────────
// _PlannerColumnWidget
// ─────────────────────────────────────────────────────────────────────────────

class _PlannerColumnWidget extends StatefulWidget {
  final bool isOverdue;
  final bool isToday;
  final String headerLabel;
  final String? headerCount;
  final double headerHeight;
  final String? colDueDay;
  final String colKey;
  final List<Task> unscheduledTasks;
  final List<Task> scheduledTasks;
  final Map<String, Project> projects;
  final Map<String, Color> projectColors;
  final Map<String, String> effectiveProjectIds;
  final List<String> allTags;
  final Task? draggingTask;
  final String? dragOverCol;
  final void Function(Task) onDragStart;
  final VoidCallback onDragEnd;
  final void Function(String colKey) onDragEnter;
  final void Function(Task, String? dueDay, bool inScheduledZone) onDrop;
  final void Function(Task task)? onAddTask;
  final void Function(Task) onTaskTap;
  final void Function(Task) onStatusToggle;
  final void Function(Task, TaskStatus) onStatusSelect;
  final void Function(Task, Offset) onContextMenu;

  const _PlannerColumnWidget({
    required this.isOverdue,
    this.isToday = false,
    required this.headerLabel,
    this.headerCount,
    required this.headerHeight,
    required this.colDueDay,
    required this.colKey,
    required this.unscheduledTasks,
    required this.scheduledTasks,
    required this.projects,
    required this.projectColors,
    this.effectiveProjectIds = const {},
    required this.allTags,
    required this.draggingTask,
    required this.dragOverCol,
    required this.onDragStart,
    required this.onDragEnd,
    required this.onDragEnter,
    required this.onDrop,
    required this.onAddTask,
    required this.onTaskTap,
    required this.onStatusToggle,
    required this.onStatusSelect,
    required this.onContextMenu,
  });

  @override
  State<_PlannerColumnWidget> createState() => _PlannerColumnWidgetState();
}

class _PlannerColumnWidgetState extends State<_PlannerColumnWidget> {
  bool _addMode = false;
  // Prevents the card-level right-click from also firing when the
  // status icon is right-clicked.
  bool _suppressNextContextMenu = false;
  final TextEditingController _addCtrl = TextEditingController();
  final FocusNode _addFocus = FocusNode();
  String _colorMode = 'project'; // 'project', 'status', 'none'

  // Inline add state – project / due / tags / estimate
  String? _addProjectId;
  String? _addDueDay;
  final List<String> _addTags = [];
  int? _addEstimateMinutes;
  String? _addOpenPanel; // null | 'project' | 'tags'

  @override
  void dispose() {
    _addCtrl.dispose();
    _addFocus.dispose();
    super.dispose();
  }

  void _resetAdd() {
    _addCtrl.clear();
    _addProjectId = null;
    _addDueDay = null;
    _addTags.clear();
    _addEstimateMinutes = null;
    _addOpenPanel = null;
  }

  String _fmtTime(int ms) {
    final dt = DateTime.fromMillisecondsSinceEpoch(ms).toLocal();
    return '${dt.hour.toString().padLeft(2, '0')}:${dt.minute.toString().padLeft(2, '0')}';
  }

  void _commitAdd() {
    FocusManager.instance.primaryFocus?.unfocus();
    final title = _addCtrl.text.trim();
    if (title.isNotEmpty && widget.onAddTask != null) {
      // Parse inline #tag shortcuts
      String cleanTitle = title;
      final tagMatches = RegExp(r'#(\S+)').allMatches(title);
      final inlineTags = tagMatches.map((m) => m.group(1)!).toList();
      cleanTitle = cleanTitle.replaceAll(RegExp(r'#\S+'), '').trim();

      final task = Task(
        id: DateTime.now().millisecondsSinceEpoch.toString(),
        title: cleanTitle.isEmpty ? title : cleanTitle,
        isDone: false,
        projectId:
            _addProjectId ??
            'INBOX_PROJECT', // Feature 7: always default to Inbox
        subTaskIds: [],
        timeSpent: 0,
        dueDay: _addDueDay ?? widget.colDueDay,
        durationMinutes: _addEstimateMinutes ?? 30,
        attachments: [],
        tagIds: [...inlineTags, ..._addTags],
      );
      widget.onAddTask!(task);
    }
    setState(() {
      _addMode = false;
      _resetAdd();
    });
  }

  @override
  Widget build(BuildContext context) {
    final accent = widget.isOverdue
        ? const Color(0xFFEF5350)
        : widget.isToday
        ? const Color(0xFF4FC3F7)
        : Colors.white54;
    final isDropTarget =
        widget.dragOverCol == widget.colKey && widget.draggingTask != null;

    return AnimatedContainer(
      duration: const Duration(milliseconds: 120),
      decoration: BoxDecoration(
        color: isDropTarget ? accent.withOpacity(0.05) : Colors.transparent,
        border: isDropTarget
            ? Border.all(color: accent.withOpacity(0.3))
            : null,
      ),
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.stretch,
        children: [
          // ── Fixed-height header ──────────────────────────────────────
          SizedBox(
            height: widget.headerHeight,
            child: Container(
              padding: const EdgeInsets.fromLTRB(12, 0, 12, 0),
              alignment: Alignment.centerLeft,
              decoration: BoxDecoration(
                border: Border(
                  bottom: BorderSide(color: Colors.white.withOpacity(0.07)),
                ),
              ),
              child: Row(
                children: [
                  Expanded(
                    child: Text(
                      widget.headerLabel,
                      style: TextStyle(
                        fontSize: 13,
                        fontWeight: FontWeight.w700,
                        color: accent,
                        letterSpacing: 0.2,
                      ),
                    ),
                  ),
                  if (widget.headerCount != null)
                    Container(
                      padding: const EdgeInsets.symmetric(
                        horizontal: 6,
                        vertical: 1,
                      ),
                      decoration: BoxDecoration(
                        color: accent.withOpacity(0.12),
                        borderRadius: BorderRadius.circular(8),
                      ),
                      child: Text(
                        widget.headerCount!,
                        style: TextStyle(
                          fontSize: 10,
                          fontWeight: FontWeight.w700,
                          color: accent.withOpacity(0.8),
                        ),
                      ),
                    ),
                  PopupMenuButton<String>(
                    icon: Icon(
                      Icons.palette_outlined,
                      size: 16,
                      color: accent.withOpacity(0.5),
                    ),
                    tooltip: 'Card Color Mode',
                    onSelected: (val) => setState(() => _colorMode = val),
                    itemBuilder: (context) => [
                      const PopupMenuItem(
                        value: 'project',
                        child: Text('Color by Project'),
                      ),
                      const PopupMenuItem(
                        value: 'status',
                        child: Text('Color by Status'),
                      ),
                      const PopupMenuItem(
                        value: 'none',
                        child: Text('No Color'),
                      ),
                    ],
                  ),
                ],
              ),
            ),
          ),

          // ── Scrollable content ───────────────────────────────────────
          Expanded(
            child: DragTarget<Task>(
              onWillAcceptWithDetails: (_) {
                widget.onDragEnter(widget.colKey);
                return true;
              },
              onAcceptWithDetails: (details) =>
                  widget.onDrop(details.data, widget.colDueDay, false),
              builder: (ctx, candidates, rejected) {
                // Upper section: unscheduled cards + add UI (shrink-wraps).
                // Lower section: scheduled DragTarget expands to fill the rest.
                return Column(
                  crossAxisAlignment: CrossAxisAlignment.stretch,
                  children: [
                    // ── Unscheduled section (shrink-wrap) ─────────────
                    ListView(
                      shrinkWrap: true,
                      physics: const NeverScrollableScrollPhysics(),
                      padding: EdgeInsets.zero,
                      children: [
                        // Unscheduled cards
                        if (widget.unscheduledTasks.isEmpty && !_addMode)
                          Padding(
                            padding: const EdgeInsets.fromLTRB(12, 12, 12, 4),
                            child: Text(
                              'No tasks',
                              style: TextStyle(
                                fontSize: 11,
                                color: Colors.white.withOpacity(0.24),
                                fontStyle: FontStyle.italic,
                              ),
                            ),
                          )
                        else
                          ...widget.unscheduledTasks.map(
                            (t) => _buildDraggableCard(context, t),
                          ),

                        // ── Inline add card ───────────────────────────
                        if (_addMode)
                          Padding(
                            padding: const EdgeInsets.fromLTRB(12, 6, 12, 0),
                            child: Container(
                              decoration: BoxDecoration(
                                color: const Color(0xFF1C1F24),
                                borderRadius: BorderRadius.circular(8),
                                border: Border.all(
                                  color: const Color(
                                    0xFF4FC3F7,
                                  ).withOpacity(0.35),
                                ),
                              ),
                              child: Column(
                                crossAxisAlignment: CrossAxisAlignment.stretch,
                                mainAxisSize: MainAxisSize.min,
                                children: [
                                  // ── Title field ──────────────────────
                                  Padding(
                                    padding: const EdgeInsets.fromLTRB(
                                      10,
                                      8,
                                      10,
                                      4,
                                    ),
                                    child: TextField(
                                      controller: _addCtrl,
                                      focusNode: _addFocus,
                                      autofocus: true,
                                      maxLines: 1,
                                      textInputAction: TextInputAction.done,
                                      style: const TextStyle(
                                        fontSize: 12,
                                        color: Colors.white,
                                      ),
                                      decoration: InputDecoration(
                                        hintText: 'Task name…  #tag',
                                        hintStyle: TextStyle(
                                          fontSize: 12,
                                          color: Colors.white.withOpacity(0.28),
                                        ),
                                        isDense: true,
                                        contentPadding: EdgeInsets.zero,
                                        border: InputBorder.none,
                                      ),
                                      onSubmitted: (_) => _commitAdd(),
                                    ),
                                  ),
                                  Container(height: 0.5, color: Colors.white10),
                                  SingleChildScrollView(
                                    scrollDirection: Axis.horizontal,
                                    padding: const EdgeInsets.symmetric(
                                      horizontal: 8,
                                      vertical: 6,
                                    ),
                                    child: Row(
                                      children: [
                                        _InlineAddPill(
                                          icon: Icons.inbox_outlined,
                                          label: _addProjectId != null
                                              ? (widget
                                                        .projects[_addProjectId]
                                                        ?.title ??
                                                    'Project')
                                              : 'Inbox',
                                          active: _addOpenPanel == 'project',
                                          onTap: () => setState(
                                            () => _addOpenPanel =
                                                _addOpenPanel == 'project'
                                                ? null
                                                : 'project',
                                          ),
                                        ),
                                        const SizedBox(width: 6),
                                        _InlineAddPill(
                                          icon: Icons.label_outline,
                                          label: _addTags.isEmpty
                                              ? 'Tags'
                                              : _addTags.join(', '),
                                          active: _addOpenPanel == 'tags',
                                          onTap: () => setState(
                                            () => _addOpenPanel =
                                                _addOpenPanel == 'tags'
                                                ? null
                                                : 'tags',
                                          ),
                                        ),
                                        const SizedBox(width: 6),
                                        _InlineAddPill(
                                          icon: Icons.timer_outlined,
                                          label: _addEstimateMinutes == null
                                              ? 'Estimate'
                                              : _addEstimateMinutes! >= 60
                                              ? '${_addEstimateMinutes! ~/ 60}h${_addEstimateMinutes! % 60 > 0 ? " ${_addEstimateMinutes! % 60}m" : ""}'
                                              : '${_addEstimateMinutes}m',
                                          active: _addOpenPanel == 'estimate',
                                          onTap: () => setState(
                                            () => _addOpenPanel =
                                                _addOpenPanel == 'estimate'
                                                ? null
                                                : 'estimate',
                                          ),
                                        ),
                                      ],
                                    ),
                                  ),
                                  if (_addOpenPanel == 'project') ...[
                                    Container(
                                      height: 0.5,
                                      color: Colors.white10,
                                    ),
                                    Padding(
                                      padding: const EdgeInsets.symmetric(
                                        horizontal: 8,
                                        vertical: 6,
                                      ),
                                      child: Wrap(
                                        spacing: 5,
                                        runSpacing: 5,
                                        children: [
                                          _InlineAddPill(
                                            icon: Icons.inbox_outlined,
                                            label: 'Inbox',
                                            active: _addProjectId == null,
                                            onTap: () => setState(() {
                                              _addProjectId = null;
                                              _addOpenPanel = null;
                                            }),
                                          ),
                                          ...widget.projects.entries.map(
                                            (e) => _InlineAddPill(
                                              icon: Icons.folder_outlined,
                                              label: e.value.title,
                                              active: _addProjectId == e.key,
                                              onTap: () => setState(() {
                                                _addProjectId = e.key;
                                                _addOpenPanel = null;
                                              }),
                                            ),
                                          ),
                                        ],
                                      ),
                                    ),
                                  ],
                                  if (_addOpenPanel == 'tags') ...[
                                    Container(
                                      height: 0.5,
                                      color: Colors.white10,
                                    ),
                                    Padding(
                                      padding: const EdgeInsets.symmetric(
                                        horizontal: 8,
                                        vertical: 6,
                                      ),
                                      child: Wrap(
                                        spacing: 5,
                                        runSpacing: 5,
                                        children: widget.allTags
                                            .map(
                                              (tag) => _InlineAddPill(
                                                icon: Icons.label_outline,
                                                label: tag,
                                                active: _addTags.contains(tag),
                                                onTap: () => setState(() {
                                                  if (_addTags.contains(tag)) {
                                                    _addTags.remove(tag);
                                                  } else {
                                                    _addTags.add(tag);
                                                  }
                                                }),
                                              ),
                                            )
                                            .toList(),
                                      ),
                                    ),
                                  ],
                                  if (_addOpenPanel == 'estimate') ...[
                                    Container(
                                      height: 0.5,
                                      color: Colors.white10,
                                    ),
                                    Padding(
                                      padding: const EdgeInsets.symmetric(
                                        horizontal: 8,
                                        vertical: 6,
                                      ),
                                      child: Wrap(
                                        spacing: 5,
                                        runSpacing: 5,
                                        children: [
                                          for (final mins in [
                                            15,
                                            30,
                                            45,
                                            60,
                                            90,
                                            120,
                                          ])
                                            _InlineAddPill(
                                              icon: Icons.timer_outlined,
                                              label: mins >= 60
                                                  ? '${mins ~/ 60}h${mins % 60 > 0 ? " ${mins % 60}m" : ""}'
                                                  : '${mins}m',
                                              active:
                                                  _addEstimateMinutes == mins,
                                              onTap: () => setState(() {
                                                _addEstimateMinutes =
                                                    _addEstimateMinutes == mins
                                                    ? null
                                                    : mins;
                                                _addOpenPanel = null;
                                              }),
                                            ),
                                        ],
                                      ),
                                    ),
                                  ],
                                  Container(height: 0.5, color: Colors.white10),
                                  Padding(
                                    padding: const EdgeInsets.symmetric(
                                      horizontal: 10,
                                      vertical: 7,
                                    ),
                                    child: Row(
                                      mainAxisAlignment: MainAxisAlignment.end,
                                      children: [
                                        GestureDetector(
                                          onTap: () => setState(() {
                                            _addMode = false;
                                            _resetAdd();
                                          }),
                                          child: Text(
                                            'Cancel',
                                            style: TextStyle(
                                              fontSize: 10,
                                              color: Colors.white.withOpacity(
                                                0.38,
                                              ),
                                            ),
                                          ),
                                        ),
                                        const SizedBox(width: 14),
                                        GestureDetector(
                                          onTap: _commitAdd,
                                          child: Container(
                                            padding: const EdgeInsets.symmetric(
                                              horizontal: 10,
                                              vertical: 4,
                                            ),
                                            decoration: BoxDecoration(
                                              color: const Color(
                                                0xFF4FC3F7,
                                              ).withOpacity(0.15),
                                              borderRadius:
                                                  BorderRadius.circular(4),
                                            ),
                                            child: const Text(
                                              'Add task',
                                              style: TextStyle(
                                                fontSize: 10,
                                                color: Color(0xFF4FC3F7),
                                                fontWeight: FontWeight.w600,
                                              ),
                                            ),
                                          ),
                                        ),
                                      ],
                                    ),
                                  ),
                                ],
                              ),
                            ),
                          ),

                        // Add button
                        if (widget.onAddTask != null && !_addMode)
                          Padding(
                            padding: const EdgeInsets.fromLTRB(12, 6, 12, 0),
                            child: GestureDetector(
                              onTap: () => setState(() => _addMode = true),
                              child: Container(
                                padding: const EdgeInsets.symmetric(
                                  vertical: 6,
                                  horizontal: 8,
                                ),
                                decoration: BoxDecoration(
                                  color: Colors.white.withOpacity(0.03),
                                  borderRadius: BorderRadius.circular(6),
                                  border: Border.all(
                                    color: Colors.white.withOpacity(0.08),
                                  ),
                                ),
                                child: Row(
                                  children: [
                                    Icon(
                                      Icons.add,
                                      size: 13,
                                      color: Colors.white.withOpacity(0.3),
                                    ),
                                    const SizedBox(width: 5),
                                    Text(
                                      'Add',
                                      style: TextStyle(
                                        fontSize: 11,
                                        color: Colors.white.withOpacity(0.3),
                                      ),
                                    ),
                                  ],
                                ),
                              ),
                            ),
                          ),

                        // Divider between unscheduled and scheduled zones
                        Padding(
                          padding: const EdgeInsets.symmetric(
                            vertical: 10,
                            horizontal: 12,
                          ),
                          child: Row(
                            children: [
                              const Icon(
                                Icons.access_time_outlined,
                                size: 11,
                                color: Colors.white24,
                              ),
                              const SizedBox(width: 6),
                              Expanded(
                                child: Container(
                                  height: 1,
                                  color: Colors.white.withOpacity(0.07),
                                ),
                              ),
                            ],
                          ),
                        ),
                      ],
                    ),

                    // ── Scheduled zone — Expanded to fill remaining height ─
                    Expanded(
                      child: DragTarget<Task>(
                        onWillAcceptWithDetails: (_) {
                          widget.onDragEnter(widget.colKey);
                          return true;
                        },
                        onAcceptWithDetails: (details) =>
                            widget.onDrop(details.data, widget.colDueDay, true),
                        builder: (ctx2, cands, rej) {
                          final isOver = cands.isNotEmpty;
                          return AnimatedContainer(
                            duration: const Duration(milliseconds: 100),
                            color: isOver
                                ? const Color(0xFF4FC3F7).withOpacity(0.06)
                                : Colors.transparent,
                            child: widget.scheduledTasks.isEmpty
                                ? Center(
                                    child: Text(
                                      isOver
                                          ? 'Drop to set time…'
                                          : 'No scheduled items',
                                      style: TextStyle(
                                        fontSize: 10,
                                        color: isOver
                                            ? const Color(
                                                0xFF4FC3F7,
                                              ).withOpacity(0.6)
                                            : Colors.white.withOpacity(0.24),
                                        fontStyle: FontStyle.italic,
                                      ),
                                    ),
                                  )
                                : ListView(
                                    padding: const EdgeInsets.only(bottom: 12),
                                    children: widget.scheduledTasks
                                        .map(
                                          (t) => _buildDraggableScheduledCard(
                                            context,
                                            t,
                                          ),
                                        )
                                        .toList(),
                                  ),
                          );
                        },
                      ),
                    ),
                  ],
                );
              },
            ),
          ),
        ],
      ),
    );
  }

  Widget _buildDraggableCard(BuildContext context, Task t) {
    final proj = widget.projects[t.projectId];
    final effPid = widget.effectiveProjectIds[t.id] ?? t.projectId;
    final projColor = widget.projectColors[effPid] ?? Colors.white24;
    final isDone = t.status == TaskStatus.done;

    return Draggable<Task>(
      data: t,
      feedback: Material(
        color: Colors.transparent,
        child: Opacity(
          opacity: 0.85,
          child: SizedBox(
            width: 210,
            child: Container(
              margin: const EdgeInsets.fromLTRB(12, 4, 12, 0),
              padding: const EdgeInsets.fromLTRB(10, 8, 10, 8),
              decoration: BoxDecoration(
                color: const Color(0xFF252830),
                borderRadius: BorderRadius.circular(7),
                border: Border.all(
                  color: const Color(0xFF4FC3F7).withOpacity(0.5),
                ),
                boxShadow: [
                  BoxShadow(
                    color: Colors.black.withOpacity(0.4),
                    blurRadius: 12,
                  ),
                ],
              ),
              child: Text(
                t.title,
                style: const TextStyle(fontSize: 12, color: Colors.white),
                maxLines: 1,
                overflow: TextOverflow.ellipsis,
              ),
            ),
          ),
        ),
      ),
      childWhenDragging: Opacity(
        opacity: 0.25,
        child: _buildCardContent(context, t, proj, projColor, isDone),
      ),
      onDragStarted: () => widget.onDragStart(t),
      onDragEnd: (_) => widget.onDragEnd(),
      child: GestureDetector(
        onTap: () => widget.onTaskTap(t),
        onSecondaryTapDown: (d) {
          if (_suppressNextContextMenu) {
            _suppressNextContextMenu = false;
            return;
          }
          widget.onContextMenu(t, d.globalPosition);
        },
        child: _buildCardContent(context, t, proj, projColor, isDone),
      ),
    );
  }

  Widget _buildCardContent(
    BuildContext context,
    Task t,
    Project? proj,
    Color projColor,
    bool isDone,
  ) {
    final isLight = AppTheme.of(context).isLight;
    final statusColor = t.status.color;
    // Feature 4 & 5: adaptive status icon border
    final statusBorder = adaptiveBorder(statusColor, isLight);
    return Container(
      margin: const EdgeInsets.fromLTRB(12, 4, 12, 0),
      padding: const EdgeInsets.fromLTRB(10, 8, 10, 8),
      decoration: BoxDecoration(
        color: isLight ? Colors.white : const Color(0xFF1C1F24),
        borderRadius: BorderRadius.circular(7),
        border: Border.all(
          color: isLight
              ? const Color(0xFFD0D4DA)
              : Colors.white.withOpacity(0.07),
        ),
      ),
      child: Row(
        crossAxisAlignment: CrossAxisAlignment.start,
        children: [
          GestureDetector(
            onTap: () => widget.onStatusToggle(t),
            onSecondaryTapDown: (details) {
              _suppressNextContextMenu = true;
              showMenu<TaskStatus>(
                context: context,
                position: RelativeRect.fromLTRB(
                  details.globalPosition.dx,
                  details.globalPosition.dy,
                  details.globalPosition.dx + 1,
                  details.globalPosition.dy + 1,
                ),
                color: const Color(0xFF252829),
                shape: RoundedRectangleBorder(
                  borderRadius: BorderRadius.circular(8),
                  side: const BorderSide(color: Colors.white12),
                ),
                items: TaskStatus.values.map((s) {
                  final selected = t.status == s;
                  return PopupMenuItem<TaskStatus>(
                    value: s,
                    padding: const EdgeInsets.symmetric(
                      horizontal: 12,
                      vertical: 4,
                    ),
                    child: Row(
                      children: [
                        Icon(
                          s.icon,
                          size: 14,
                          color: selected ? s.color : s.color.withOpacity(0.6),
                        ),
                        const SizedBox(width: 10),
                        Text(
                          s.label,
                          style: TextStyle(
                            fontSize: 12,
                            color: selected ? Colors.white : Colors.white70,
                            fontWeight: selected
                                ? FontWeight.w600
                                : FontWeight.normal,
                          ),
                        ),
                        if (selected) ...const [
                          Spacer(),
                          Icon(Icons.check, size: 12, color: Colors.white54),
                        ],
                      ],
                    ),
                  );
                }).toList(),
              ).then((picked) {
                if (picked != null) widget.onStatusSelect(t, picked);
              });
            },
            child: Padding(
              padding: const EdgeInsets.only(top: 1, right: 8),
              child: Container(
                width: 18,
                height: 18,
                decoration: BoxDecoration(
                  shape: BoxShape.circle,
                  border: statusBorder,
                ),
                child: Icon(
                  t.status.icon,
                  size: 14,
                  color: (isDone || t.status == TaskStatus.cancelled)
                      ? Colors.white24
                      : statusColor,
                ),
              ),
            ),
          ),
          Expanded(
            child: Column(
              crossAxisAlignment: CrossAxisAlignment.start,
              children: [
                Text(
                  t.title,
                  style: TextStyle(
                    fontSize: 12,
                    color: (isDone || t.status == TaskStatus.cancelled)
                        ? (isLight ? Colors.black26 : Colors.white30)
                        : (isLight
                              ? const Color(0xFF1A1C22)
                              : Colors.white.withOpacity(0.85)),
                    decoration: (isDone || t.status == TaskStatus.cancelled)
                        ? TextDecoration.lineThrough
                        : null,
                    decorationColor: isLight ? Colors.black26 : Colors.white24,
                  ),
                  maxLines: 2,
                  overflow: TextOverflow.ellipsis,
                ),
                if (proj != null) ...[
                  const SizedBox(height: 4),
                  Row(
                    children: [
                      Icon(
                        Icons.folder_outlined,
                        size: 10,
                        color: projColor.withOpacity(0.7),
                      ),
                      const SizedBox(width: 3),
                      Text(
                        proj.title,
                        style: TextStyle(
                          fontSize: 9,
                          color: projColor.withOpacity(0.7),
                        ),
                      ),
                    ],
                  ),
                ],
                if (t.tagIds.isNotEmpty) ...[
                  const SizedBox(height: 3),
                  Wrap(
                    spacing: 4,
                    children: t.tagIds.take(3).map((tag) {
                      // Feature 4 & 5: no fill color for tag chips — neutral border only
                      return Container(
                        padding: const EdgeInsets.symmetric(
                          horizontal: 5,
                          vertical: 1,
                        ),
                        decoration: BoxDecoration(
                          color: isLight
                              ? const Color(0xFFEEF0F3)
                              : Colors.white.withOpacity(0.06),
                          borderRadius: BorderRadius.circular(3),
                        ),
                        child: Text(
                          tag.toString(),
                          style: TextStyle(
                            fontSize: 8,
                            color: isLight
                                ? const Color(0xFF555D6B)
                                : Colors.white38,
                          ),
                        ),
                      );
                    }).toList(),
                  ),
                ],
              ],
            ),
          ),
          if (t.durationMinutes > 0)
            Padding(
              padding: const EdgeInsets.only(left: 6),
              child: Text(
                t.durationMinutes >= 60
                    ? '${t.durationMinutes ~/ 60}h${t.durationMinutes % 60 > 0 ? '${t.durationMinutes % 60}m' : ''}'
                    : '${t.durationMinutes}m',
                style: TextStyle(
                  fontSize: 9,
                  color: isLight ? Colors.black38 : Colors.white30,
                ),
              ),
            ),
          // Feature 9: explicit Details button — opens the task-details sidebar
          GestureDetector(
            onTap: () => widget.onTaskTap(t),
            child: Padding(
              padding: const EdgeInsets.only(left: 4),
              child: Tooltip(
                message: 'Open details',
                child: Icon(
                  Icons.open_in_new_rounded,
                  size: 12,
                  color: isLight
                      ? const Color(0xFF9EA7B3)
                      : Colors.white.withOpacity(0.25),
                ),
              ),
            ),
          ),
        ],
      ),
    );
  }

  Widget _buildDraggableScheduledCard(BuildContext context, Task t) {
    Color projColor;
    switch (_colorMode) {
      case 'status':
        projColor = t.status.color;
        break;
      case 'none':
        projColor = Colors.transparent;
        break;
      default: // 'project'
        projColor =
            widget.projectColors[widget.effectiveProjectIds[t.id] ??
                t.projectId] ??
            const Color(0xFF4FC3F7);
    }
    final isDone =
        t.status == TaskStatus.done || t.status == TaskStatus.cancelled;
    // Fallback included just in case
    final timeLabel = t.plannedAt != null ? _fmtTime(t.plannedAt!) : '--:--';

    return Draggable<Task>(
      data: t,
      feedback: Material(
        color: Colors.transparent,
        child: Opacity(
          opacity: 0.85,
          child: SizedBox(
            width: 210,
            child: Container(
              margin: const EdgeInsets.fromLTRB(12, 4, 12, 0),
              padding: const EdgeInsets.all(8),
              decoration: BoxDecoration(
                color: projColor.withOpacity(0.15),
                borderRadius: BorderRadius.circular(7),
                border: Border.all(color: projColor.withOpacity(0.5)),
                boxShadow: [
                  BoxShadow(
                    color: Colors.black.withOpacity(0.4),
                    blurRadius: 12,
                  ),
                ],
              ),
              child: Text(
                t.title,
                style: const TextStyle(fontSize: 11, color: Colors.white),
                maxLines: 1,
                overflow: TextOverflow.ellipsis,
              ),
            ),
          ),
        ),
      ),
      childWhenDragging: Opacity(
        opacity: 0.25,
        child: _buildScheduledCardContent(
          context,
          t,
          projColor,
          isDone,
          timeLabel,
        ),
      ),
      onDragStarted: () => widget.onDragStart(t),
      onDragEnd: (_) => widget.onDragEnd(),
      child: GestureDetector(
        onTap: () => widget.onTaskTap(t),
        onSecondaryTapDown: (d) {
          if (_suppressNextContextMenu) {
            _suppressNextContextMenu = false;
            return;
          }
          widget.onContextMenu(t, d.globalPosition);
        },
        child: _buildScheduledCardContent(
          context,
          t,
          projColor,
          isDone,
          timeLabel,
        ),
      ),
    );
  }

  Widget _buildScheduledCardContent(
    BuildContext context,
    Task t,
    Color
    cardAccentColor, // This is the 'effectiveColor' passed from the parent
    bool isDone,
    String timeLabel,
  ) {
    final isLight = AppTheme.of(context).isLight;
    final neutralColor = isLight ? Colors.black45 : Colors.white38;

    // 1. SAFE PROJECT LOOKUP
    final project = widget.projects[t.projectId];
    final String projectTitle = project?.title ?? 'Inbox';

    // FIX: Instead of project.color (which is causing the error),
    // we use the projectColors map from the widget which we know exists.
    final Color projectLineColor =
        widget.projectColors[t.projectId] ?? Colors.grey;

    return Container(
      margin: const EdgeInsets.fromLTRB(12, 4, 12, 0),
      padding: const EdgeInsets.all(10),
      decoration: BoxDecoration(
        color: cardAccentColor.withOpacity(isLight ? 0.06 : 0.1),
        borderRadius: BorderRadius.circular(8),
        border: Border(left: BorderSide(color: cardAccentColor, width: 4)),
      ),
      child: Row(
        crossAxisAlignment: CrossAxisAlignment.start,
        children: [
          // ── Time + duration (no divider — the left accent border acts as
          //    the visual separator between the time column and the card body)
          Column(
            crossAxisAlignment: CrossAxisAlignment.start,
            mainAxisSize: MainAxisSize.min,
            children: [
              Text(
                timeLabel,
                style: TextStyle(
                  fontSize: 10,
                  fontWeight: FontWeight.w700,
                  color: neutralColor,
                ),
              ),
              if (t.durationMinutes > 0)
                Text(
                  t.durationMinutes >= 60
                      ? '${t.durationMinutes ~/ 60}h${t.durationMinutes % 60 > 0 ? '${t.durationMinutes % 60}m' : ''}'
                      : '${t.durationMinutes}m',
                  style: TextStyle(
                    fontSize: 8,
                    color: neutralColor.withOpacity(0.6),
                  ),
                ),
            ],
          ),
          const SizedBox(width: 8),
          Container(
            width: 1,
            height: 30,
            color: isLight ? Colors.black12 : Colors.white10,
          ),
          const SizedBox(width: 8),
          GestureDetector(
            onTap: () => widget.onStatusToggle(t),
            onSecondaryTapDown: (details) {
              _suppressNextContextMenu = true;
              showMenu<TaskStatus>(
                context: context,
                position: RelativeRect.fromLTRB(
                  details.globalPosition.dx,
                  details.globalPosition.dy,
                  details.globalPosition.dx + 1,
                  details.globalPosition.dy + 1,
                ),
                color: const Color(0xFF252829),
                shape: RoundedRectangleBorder(
                  borderRadius: BorderRadius.circular(8),
                  side: const BorderSide(color: Colors.white12),
                ),
                items: TaskStatus.values.map((s) {
                  final selected = t.status == s;
                  return PopupMenuItem<TaskStatus>(
                    value: s,
                    padding: const EdgeInsets.symmetric(
                      horizontal: 12,
                      vertical: 4,
                    ),
                    child: Row(
                      children: [
                        Icon(
                          s.icon,
                          size: 14,
                          color: selected ? s.color : s.color.withOpacity(0.6),
                        ),
                        const SizedBox(width: 10),
                        Text(
                          s.label,
                          style: TextStyle(
                            fontSize: 12,
                            color: selected ? Colors.white : Colors.white70,
                            fontWeight: selected
                                ? FontWeight.w600
                                : FontWeight.normal,
                          ),
                        ),
                        if (selected) ...const [
                          Spacer(),
                          Icon(Icons.check, size: 12, color: Colors.white54),
                        ],
                      ],
                    ),
                  );
                }).toList(),
              ).then((picked) {
                if (picked != null) widget.onStatusSelect(t, picked);
              });
            },
            child: Padding(
              padding: const EdgeInsets.only(top: 1, right: 8),
              child: Container(
                width: 18,
                height: 18,
                decoration: BoxDecoration(
                  shape: BoxShape.circle,
                  border: adaptiveBorder(t.status.color, isLight),
                ),
                child: Icon(
                  t.status.icon,
                  size: 14,
                  color: isDone
                      ? (isLight ? Colors.black26 : Colors.white24)
                      : t.status.color,
                ),
              ),
            ),
          ),
          // ── Title + project — identical structure to the unscheduled card
          Expanded(
            child: Column(
              crossAxisAlignment: CrossAxisAlignment.start,
              children: [
                Text(
                  t.title.isNotEmpty ? t.title : 'Untitled Task',
                  style: TextStyle(
                    fontSize: 12,
                    color: isDone
                        ? neutralColor
                        : (isLight
                              ? const Color(0xFF1A1C22)
                              : Colors.white.withOpacity(0.85)),
                    decoration: isDone ? TextDecoration.lineThrough : null,
                    decorationColor: isLight ? Colors.black26 : Colors.white24,
                  ),
                  maxLines: 2,
                  overflow: TextOverflow.ellipsis,
                ),
                if (project != null) ...[
                  const SizedBox(height: 4),
                  Row(
                    children: [
                      Icon(
                        Icons.folder_outlined,
                        size: 10,
                        color: projectLineColor.withOpacity(0.7),
                      ),
                      const SizedBox(width: 3),
                      Expanded(
                        child: Text(
                          projectTitle,
                          style: TextStyle(
                            fontSize: 9,
                            color: projectLineColor.withOpacity(0.7),
                          ),
                          overflow: TextOverflow.ellipsis,
                        ),
                      ),
                    ],
                  ),
                ],
              ],
            ),
          ),
        ],
      ),
    );
  }
}

// ─────────────────────────────────────────────────────────────────────────────
// _PlannerContextMenu
// ─────────────────────────────────────────────────────────────────────────────

class _PlannerContextMenu extends StatefulWidget {
  final Task task;
  final Map<String, Project> projects;
  final List<String> allTags;
  final VoidCallback onScheduleToday;
  final VoidCallback onScheduleTomorrow;
  final VoidCallback onScheduleNextWeek;
  final VoidCallback onReschedule;
  final VoidCallback onUnschedule;
  final VoidCallback onMarkDone;
  final VoidCallback onStartFocus;
  final void Function(String tag) onToggleTag;
  final void Function(String projectId) onMoveToProject;
  final VoidCallback onDelete;

  const _PlannerContextMenu({
    required this.task,
    required this.projects,
    required this.allTags,
    required this.onScheduleToday,
    required this.onScheduleTomorrow,
    required this.onScheduleNextWeek,
    required this.onReschedule,
    required this.onUnschedule,
    required this.onMarkDone,
    required this.onStartFocus,
    required this.onToggleTag,
    required this.onMoveToProject,
    required this.onDelete,
  });

  @override
  State<_PlannerContextMenu> createState() => _PlannerContextMenuState();
}

class _PlannerContextMenuState extends State<_PlannerContextMenu> {
  bool _showTags = false;
  bool _showProjects = false;

  @override
  Widget build(BuildContext context) {
    const bg = Color(0xFF1A1D22);
    const border = Color(0xFF2A2D32);

    Widget menuItem(
      IconData icon,
      String label,
      VoidCallback onTap, {
      Color? color,
      bool isDestructive = false,
    }) {
      final c = isDestructive ? Colors.redAccent : (color ?? Colors.white70);
      return GestureDetector(
        onTap: onTap,
        child: Container(
          padding: const EdgeInsets.symmetric(horizontal: 12, vertical: 9),
          child: Row(
            children: [
              Icon(icon, size: 13, color: c.withOpacity(0.8)),
              const SizedBox(width: 10),
              Expanded(
                child: Text(
                  label,
                  style: TextStyle(
                    fontSize: 12,
                    color: c,
                    fontWeight: FontWeight.w500,
                  ),
                ),
              ),
            ],
          ),
        ),
      );
    }

    Widget divider() => Container(
      height: 1,
      color: border,
      margin: const EdgeInsets.symmetric(vertical: 2),
    );

    final isDone = widget.task.status == TaskStatus.done;

    return Container(
      decoration: BoxDecoration(
        color: bg,
        borderRadius: BorderRadius.circular(10),
        border: Border.all(color: border),
        boxShadow: [
          BoxShadow(
            color: Colors.black.withOpacity(0.5),
            blurRadius: 20,
            offset: const Offset(0, 8),
          ),
        ],
      ),
      child: Column(
        mainAxisSize: MainAxisSize.min,
        crossAxisAlignment: CrossAxisAlignment.stretch,
        children: [
          // ── 5 quick-schedule buttons ────────────────────────────────
          Container(
            padding: const EdgeInsets.all(8),
            decoration: const BoxDecoration(
              border: Border(bottom: BorderSide(color: border)),
            ),
            child: Wrap(
              spacing: 4,
              runSpacing: 4,
              children: [
                _schedBtn(
                  'Today',
                  Icons.today_outlined,
                  widget.onScheduleToday,
                ),
                _schedBtn(
                  'Tomorrow',
                  Icons.wb_sunny_outlined,
                  widget.onScheduleTomorrow,
                ),
                _schedBtn(
                  'Next week',
                  Icons.skip_next_outlined,
                  widget.onScheduleNextWeek,
                ),
                _schedBtn(
                  'Reschedule',
                  Icons.edit_calendar_outlined,
                  widget.onReschedule,
                ),
                _schedBtn(
                  'Unschedule',
                  Icons.event_busy_outlined,
                  widget.onUnschedule,
                ),
              ],
            ),
          ),

          // ── Menu items ───────────────────────────────────────────────
          menuItem(
            isDone ? Icons.radio_button_unchecked : Icons.check_circle_outline,
            isDone ? 'Mark as not done' : 'Mark as done',
            widget.onMarkDone,
            color: const Color(0xFF4CAF50),
          ),
          divider(),
          menuItem(
            Icons.center_focus_strong_outlined,
            'Start Focus',
            widget.onStartFocus,
            color: const Color(0xFFFFB74D),
          ),
          divider(),

          // Toggle Tag (expandable)
          GestureDetector(
            onTap: () => setState(() {
              _showTags = !_showTags;
              _showProjects = false;
            }),
            child: Container(
              padding: const EdgeInsets.symmetric(horizontal: 12, vertical: 9),
              child: Row(
                children: [
                  Icon(
                    Icons.label_outline,
                    size: 13,
                    color: Colors.white70.withOpacity(0.8),
                  ),
                  const SizedBox(width: 10),
                  const Expanded(
                    child: Text(
                      'Toggle Tag',
                      style: TextStyle(
                        fontSize: 12,
                        color: Colors.white70,
                        fontWeight: FontWeight.w500,
                      ),
                    ),
                  ),
                  Icon(
                    _showTags
                        ? Icons.expand_less_rounded
                        : Icons.expand_more_rounded,
                    size: 13,
                    color: Colors.white38,
                  ),
                ],
              ),
            ),
          ),
          if (_showTags && widget.allTags.isNotEmpty)
            Container(
              padding: const EdgeInsets.fromLTRB(12, 4, 12, 8),
              color: Colors.white.withOpacity(0.02),
              child: Wrap(
                spacing: 6,
                runSpacing: 4,
                children: widget.allTags.map((tag) {
                  final active = widget.task.tagIds.contains(tag);
                  return GestureDetector(
                    onTap: () => widget.onToggleTag(tag),
                    child: Container(
                      padding: const EdgeInsets.symmetric(
                        horizontal: 8,
                        vertical: 4,
                      ),
                      decoration: BoxDecoration(
                        color: active
                            ? const Color(0xFF4FC3F7).withOpacity(0.15)
                            : Colors.white.withOpacity(0.06),
                        borderRadius: BorderRadius.circular(4),
                        border: Border.all(
                          color: active
                              ? const Color(0xFF4FC3F7).withOpacity(0.4)
                              : Colors.white.withOpacity(0.1),
                        ),
                      ),
                      child: Text(
                        tag,
                        style: TextStyle(
                          fontSize: 10,
                          color: active
                              ? const Color(0xFF4FC3F7)
                              : Colors.white54,
                        ),
                      ),
                    ),
                  );
                }).toList(),
              ),
            ),

          divider(),

          // Move to Project (expandable)
          GestureDetector(
            onTap: () => setState(() {
              _showProjects = !_showProjects;
              _showTags = false;
            }),
            child: Container(
              padding: const EdgeInsets.symmetric(horizontal: 12, vertical: 9),
              child: Row(
                children: [
                  Icon(
                    Icons.folder_outlined,
                    size: 13,
                    color: Colors.white70.withOpacity(0.8),
                  ),
                  const SizedBox(width: 10),
                  const Expanded(
                    child: Text(
                      'Move to Project',
                      style: TextStyle(
                        fontSize: 12,
                        color: Colors.white70,
                        fontWeight: FontWeight.w500,
                      ),
                    ),
                  ),
                  Icon(
                    _showProjects
                        ? Icons.expand_less_rounded
                        : Icons.expand_more_rounded,
                    size: 13,
                    color: Colors.white38,
                  ),
                ],
              ),
            ),
          ),
          if (_showProjects)
            Container(
              constraints: const BoxConstraints(maxHeight: 160),
              color: Colors.white.withOpacity(0.02),
              child: ListView(
                shrinkWrap: true,
                padding: const EdgeInsets.symmetric(vertical: 4),
                children: [
                  // Default Inbox (always first)
                  GestureDetector(
                    onTap: () => widget.onMoveToProject('INBOX_PROJECT'),
                    child: Container(
                      padding: const EdgeInsets.symmetric(
                        horizontal: 12,
                        vertical: 8,
                      ),
                      color: widget.task.projectId == 'INBOX_PROJECT'
                          ? Colors.white.withOpacity(0.06)
                          : Colors.transparent,
                      child: Text(
                        'Inbox',
                        style: TextStyle(
                          fontSize: 11,
                          color: widget.task.projectId == 'INBOX_PROJECT'
                              ? Colors.white
                              : Colors.white60,
                        ),
                      ),
                    ),
                  ),
                  ...widget.projects.entries.map((e) {
                    final active = widget.task.projectId == e.key;
                    return GestureDetector(
                      onTap: () => widget.onMoveToProject(e.key),
                      child: Container(
                        padding: const EdgeInsets.symmetric(
                          horizontal: 12,
                          vertical: 8,
                        ),
                        color: active
                            ? Colors.white.withOpacity(0.06)
                            : Colors.transparent,
                        child: Text(
                          e.value.title,
                          style: TextStyle(
                            fontSize: 11,
                            color: active ? Colors.white : Colors.white60,
                          ),
                        ),
                      ),
                    );
                  }).toList(),
                ],
              ),
            ),

          divider(),
          menuItem(
            Icons.delete_outline,
            'Delete',
            widget.onDelete,
            isDestructive: true,
          ),
        ],
      ),
    );
  }

  Widget _schedBtn(String label, IconData icon, VoidCallback onTap) {
    return GestureDetector(
      onTap: onTap,
      child: Container(
        padding: const EdgeInsets.symmetric(horizontal: 7, vertical: 5),
        decoration: BoxDecoration(
          color: Colors.white.withOpacity(0.06),
          borderRadius: BorderRadius.circular(5),
          border: Border.all(color: Colors.white.withOpacity(0.1)),
        ),
        child: Column(
          mainAxisSize: MainAxisSize.min,
          children: [
            Icon(icon, size: 13, color: Colors.white54),
            const SizedBox(height: 2),
            Text(
              label,
              style: const TextStyle(fontSize: 9, color: Colors.white54),
            ),
          ],
        ),
      ),
    );
  }
}

// ─────────────────────────────────────────────────────────────────────────────
// _InlineAddPill – compact chip used in the Planner column inline add form.
// ─────────────────────────────────────────────────────────────────────────────

class _InlineAddPill extends StatelessWidget {
  final IconData icon;
  final String label;
  final bool active;
  final VoidCallback onTap;

  const _InlineAddPill({
    required this.icon,
    required this.label,
    required this.active,
    required this.onTap,
  });

  @override
  Widget build(BuildContext context) {
    const accent = Color(0xFF4FC3F7);
    return GestureDetector(
      onTap: onTap,
      child: AnimatedContainer(
        duration: const Duration(milliseconds: 120),
        padding: const EdgeInsets.symmetric(horizontal: 8, vertical: 3),
        decoration: BoxDecoration(
          color: active
              ? accent.withOpacity(0.12)
              : Colors.white.withOpacity(0.05),
          borderRadius: BorderRadius.circular(5),
          border: Border.all(
            color: active
                ? accent.withOpacity(0.4)
                : Colors.white.withOpacity(0.1),
          ),
        ),
        child: Row(
          mainAxisSize: MainAxisSize.min,
          children: [
            Icon(icon, size: 11, color: active ? accent : Colors.white38),
            const SizedBox(width: 4),
            Text(
              label,
              style: TextStyle(
                fontSize: 10,
                color: active ? accent : Colors.white38,
                fontWeight: active ? FontWeight.w600 : FontWeight.normal,
              ),
            ),
          ],
        ),
      ),
    );
  }
}

// ─────────────────────────────────────────────────────────────────────────────
// _NewBoardDialog — Title + Type + (Trello) connection fields
// ─────────────────────────────────────────────────────────────────────────────

class _NewBoardDialog extends StatefulWidget {
  final Map<String, Project> projects;
  final List<String> projectOrder;
  final void Function(Map<String, dynamic>) onCreated;

  const _NewBoardDialog({
    required this.projects,
    required this.projectOrder,
    required this.onCreated,
  });

  @override
  State<_NewBoardDialog> createState() => _NewBoardDialogState();
}

class _NewBoardDialogState extends State<_NewBoardDialog> {
  final _titleCtrl = TextEditingController();
  final _apiKeyCtrl = TextEditingController();
  final _tokenCtrl = TextEditingController();
  final _boardIdCtrl = TextEditingController();

  // Only Trello available for now
  String _type = 'Trello';
  String? _selectedProjectId;

  static const _accent = Color(0xFF4FC3F7);
  static const _bg = Color(0xFF1A1C1F);
  static const _card = Color(0xFF1E2124);
  static const _border = Color(0xFF2A2D30);

  @override
  void dispose() {
    _titleCtrl.dispose();
    _apiKeyCtrl.dispose();
    _tokenCtrl.dispose();
    _boardIdCtrl.dispose();
    super.dispose();
  }

  InputDecoration _inputDec(String hint) => InputDecoration(
    hintText: hint,
    hintStyle: TextStyle(fontSize: 12, color: Colors.white.withOpacity(0.2)),
    isDense: true,
    contentPadding: const EdgeInsets.symmetric(horizontal: 10, vertical: 9),
    filled: true,
    fillColor: Colors.white.withOpacity(0.04),
    border: OutlineInputBorder(
      borderRadius: BorderRadius.circular(6),
      borderSide: const BorderSide(color: _border),
    ),
    enabledBorder: OutlineInputBorder(
      borderRadius: BorderRadius.circular(6),
      borderSide: const BorderSide(color: _border),
    ),
    focusedBorder: OutlineInputBorder(
      borderRadius: BorderRadius.circular(6),
      borderSide: const BorderSide(color: _accent),
    ),
  );

  Widget _label(String text) => Padding(
    padding: const EdgeInsets.only(bottom: 5),
    child: Text(
      text,
      style: const TextStyle(
        fontSize: 9,
        fontWeight: FontWeight.w700,
        letterSpacing: 0.8,
        color: Colors.white38,
      ),
    ),
  );

  @override
  Widget build(BuildContext context) {
    return Dialog(
      backgroundColor: _bg,
      shape: RoundedRectangleBorder(
        borderRadius: BorderRadius.circular(10),
        side: BorderSide(color: Colors.white.withOpacity(0.08)),
      ),
      child: SizedBox(
        width: 400,
        child: ConstrainedBox(
          constraints: BoxConstraints(
            maxHeight: MediaQuery.of(context).size.height * 0.85,
          ),
          child: SingleChildScrollView(
            padding: const EdgeInsets.all(22),
            child: Column(
              mainAxisSize: MainAxisSize.min,
              crossAxisAlignment: CrossAxisAlignment.stretch,
              children: [
                // ── Header ──────────────────────────────────────────────
                Row(
                  children: [
                    const Icon(
                      Icons.dashboard_outlined,
                      size: 15,
                      color: _accent,
                    ),
                    const SizedBox(width: 8),
                    const Text(
                      'New Board',
                      style: TextStyle(
                        fontSize: 13,
                        fontWeight: FontWeight.w600,
                        color: Colors.white,
                      ),
                    ),
                    const Spacer(),
                    GestureDetector(
                      onTap: () => Navigator.of(context).pop(),
                      child: const Icon(
                        Icons.close_rounded,
                        size: 16,
                        color: Colors.white38,
                      ),
                    ),
                  ],
                ),
                const SizedBox(height: 20),

                // ── Title ────────────────────────────────────────────────
                _label('TITLE'),
                TextField(
                  controller: _titleCtrl,
                  autofocus: true,
                  style: const TextStyle(fontSize: 12, color: Colors.white),
                  decoration: _inputDec('Board name…'),
                ),
                const SizedBox(height: 16),

                // ── Type ─────────────────────────────────────────────────
                _label('TYPE'),
                Container(
                  decoration: BoxDecoration(
                    color: _card,
                    borderRadius: BorderRadius.circular(8),
                    border: Border.all(color: _border),
                  ),
                  child: Column(
                    children: [
                      _TypeOption(
                        icon: Icons.view_kanban_outlined,
                        label: 'Trello',
                        sublabel: 'Sync cards from a Trello board',
                        selected: _type == 'Trello',
                        enabled: true,
                        onTap: () => setState(() => _type = 'Trello'),
                      ),
                    ],
                  ),
                ),
                const SizedBox(height: 16),

                // ── Trello fields (always shown — only type available) ───
                Container(
                  padding: const EdgeInsets.all(14),
                  decoration: BoxDecoration(
                    color: _card,
                    borderRadius: BorderRadius.circular(8),
                    border: Border.all(
                      color: const Color(0xFF0052CC).withOpacity(0.35),
                    ),
                  ),
                  child: Column(
                    crossAxisAlignment: CrossAxisAlignment.stretch,
                    children: [
                      Row(
                        children: [
                          Container(
                            width: 18,
                            height: 18,
                            decoration: BoxDecoration(
                              color: const Color(0xFF0052CC),
                              borderRadius: BorderRadius.circular(4),
                            ),
                            child: const Icon(
                              Icons.view_kanban_outlined,
                              size: 11,
                              color: Colors.white,
                            ),
                          ),
                          const SizedBox(width: 8),
                          const Text(
                            'Trello Connection',
                            style: TextStyle(
                              fontSize: 11,
                              fontWeight: FontWeight.w600,
                              color: Colors.white70,
                            ),
                          ),
                        ],
                      ),
                      const SizedBox(height: 14),

                      _label('API KEY'),
                      TextField(
                        controller: _apiKeyCtrl,
                        style: const TextStyle(
                          fontSize: 12,
                          color: Colors.white,
                        ),
                        decoration: _inputDec('Your Trello API key'),
                      ),
                      const SizedBox(height: 10),

                      _label('API TOKEN'),
                      TextField(
                        controller: _tokenCtrl,
                        obscureText: true,
                        style: const TextStyle(
                          fontSize: 12,
                          color: Colors.white,
                        ),
                        decoration: _inputDec('Your Trello token'),
                      ),
                      const SizedBox(height: 10),

                      _label('BOARD ID'),
                      TextField(
                        controller: _boardIdCtrl,
                        style: const TextStyle(
                          fontSize: 12,
                          color: Colors.white,
                        ),
                        decoration: _inputDec('e.g. abc123xyz'),
                      ),
                      const SizedBox(height: 4),
                      Text(
                        'Found in your Trello board URL: trello.com/b/{boardId}',
                        style: TextStyle(
                          fontSize: 10,
                          color: Colors.white.withOpacity(0.25),
                          fontStyle: FontStyle.italic,
                        ),
                      ),
                    ],
                  ),
                ),
                const SizedBox(height: 16),

                // ── Internal project link ────────────────────────────────
                _label('LINK TO PROJECT'),
                _ProjectDropdown(
                  selectedId: _selectedProjectId,
                  projects: widget.projects,
                  projectOrder: widget.projectOrder,
                  onChanged: (id) => setState(() => _selectedProjectId = id),
                ),
                const SizedBox(height: 22),

                // ── Actions ──────────────────────────────────────────────
                Row(
                  children: [
                    Expanded(
                      child: GestureDetector(
                        onTap: () => Navigator.of(context).pop(),
                        child: Container(
                          padding: const EdgeInsets.symmetric(vertical: 9),
                          decoration: BoxDecoration(
                            color: Colors.white.withOpacity(0.05),
                            borderRadius: BorderRadius.circular(6),
                            border: Border.all(color: _border),
                          ),
                          child: const Center(
                            child: Text(
                              'Cancel',
                              style: TextStyle(
                                fontSize: 12,
                                color: Colors.white54,
                              ),
                            ),
                          ),
                        ),
                      ),
                    ),
                    const SizedBox(width: 10),
                    Expanded(
                      flex: 2,
                      child: GestureDetector(
                        onTap: () {
                          final title = _titleCtrl.text.trim();
                          if (title.isEmpty) return;
                          final board = <String, dynamic>{
                            'id':
                                'board_${DateTime.now().millisecondsSinceEpoch}',
                            'title': title,
                            'type': _type,
                            'projectId': _selectedProjectId,
                            'trelloApiKey': _apiKeyCtrl.text.trim(),
                            'trelloToken': _tokenCtrl.text.trim(),
                            'trelloBoardId': _boardIdCtrl.text.trim(),
                            // import mode: 'checklists_as_tasks' | 'cards_as_tasks' | 'both'
                            'importMode': 'checklists_as_tasks',
                          };
                          widget.onCreated(board);
                          Navigator.of(context).pop();
                        },
                        child: Container(
                          padding: const EdgeInsets.symmetric(vertical: 9),
                          decoration: BoxDecoration(
                            color: _accent.withOpacity(0.12),
                            borderRadius: BorderRadius.circular(6),
                            border: Border.all(color: _accent.withOpacity(0.4)),
                          ),
                          child: const Center(
                            child: Text(
                              'Create Board',
                              style: TextStyle(
                                fontSize: 12,
                                color: _accent,
                                fontWeight: FontWeight.w600,
                              ),
                            ),
                          ),
                        ),
                      ),
                    ),
                  ],
                ),
              ],
            ),
          ),
        ),
      ),
    );
  }
}

// ─────────────────────────────────────────────────────────────────────────────
// _TypeOption — radio card for board type selection
// ─────────────────────────────────────────────────────────────────────────────

class _TypeOption extends StatefulWidget {
  final IconData icon;
  final String label;
  final String sublabel;
  final bool selected;
  final bool enabled;
  final VoidCallback onTap;

  const _TypeOption({
    required this.icon,
    required this.label,
    required this.sublabel,
    required this.selected,
    required this.enabled,
    required this.onTap,
  });

  @override
  State<_TypeOption> createState() => _TypeOptionState();
}

class _TypeOptionState extends State<_TypeOption> {
  bool _hovered = false;

  @override
  Widget build(BuildContext context) {
    const accent = Color(0xFF4FC3F7);
    final c = widget.enabled ? accent : Colors.white24;
    return MouseRegion(
      cursor: widget.enabled
          ? SystemMouseCursors.click
          : SystemMouseCursors.forbidden,
      onEnter: (_) => setState(() => _hovered = true),
      onExit: (_) => setState(() => _hovered = false),
      child: GestureDetector(
        onTap: widget.enabled ? widget.onTap : null,
        child: AnimatedContainer(
          duration: const Duration(milliseconds: 120),
          padding: const EdgeInsets.symmetric(horizontal: 14, vertical: 12),
          decoration: BoxDecoration(
            color: widget.selected
                ? c.withOpacity(0.1)
                : (_hovered
                      ? Colors.white.withOpacity(0.03)
                      : Colors.transparent),
            borderRadius: BorderRadius.circular(8),
          ),
          child: Row(
            children: [
              Container(
                width: 32,
                height: 32,
                decoration: BoxDecoration(
                  color: c.withOpacity(0.12),
                  borderRadius: BorderRadius.circular(7),
                ),
                child: Icon(widget.icon, size: 16, color: c),
              ),
              const SizedBox(width: 12),
              Expanded(
                child: Column(
                  crossAxisAlignment: CrossAxisAlignment.start,
                  children: [
                    Text(
                      widget.label,
                      style: TextStyle(
                        fontSize: 12,
                        fontWeight: FontWeight.w600,
                        color: widget.enabled ? Colors.white : Colors.white38,
                      ),
                    ),
                    const SizedBox(height: 2),
                    Text(
                      widget.sublabel,
                      style: TextStyle(
                        fontSize: 10,
                        color: Colors.white.withOpacity(
                          widget.enabled ? 0.35 : 0.15,
                        ),
                      ),
                    ),
                  ],
                ),
              ),
              AnimatedContainer(
                duration: const Duration(milliseconds: 120),
                width: 16,
                height: 16,
                decoration: BoxDecoration(
                  shape: BoxShape.circle,
                  border: Border.all(
                    color: widget.selected ? c : Colors.white24,
                    width: 1.5,
                  ),
                  color: widget.selected
                      ? c.withOpacity(0.15)
                      : Colors.transparent,
                ),
                child: widget.selected
                    ? Center(
                        child: Container(
                          width: 7,
                          height: 7,
                          decoration: BoxDecoration(
                            shape: BoxShape.circle,
                            color: c,
                          ),
                        ),
                      )
                    : null,
              ),
            ],
          ),
        ),
      ),
    );
  }
}

// ─────────────────────────────────────────────────────────────────────────────
// _ProjectDropdown — compact picker for internal project
// ─────────────────────────────────────────────────────────────────────────────

class _ProjectDropdown extends StatelessWidget {
  final String? selectedId;
  final Map<String, Project> projects;
  final List<String> projectOrder;
  final void Function(String?) onChanged;

  const _ProjectDropdown({
    required this.selectedId,
    required this.projects,
    required this.projectOrder,
    required this.onChanged,
  });

  @override
  Widget build(BuildContext context) {
    const accent = Color(0xFF4FC3F7);
    final selectedTitle = selectedId != null
        ? (projects[selectedId]?.title ?? selectedId!)
        : 'No project';

    return GestureDetector(
      onTap: () {
        showDialog<String>(
          context: context,
          barrierColor: Colors.transparent,
          builder: (_) => _ProjectPickerOverlay(
            selectedId: selectedId,
            projects: projects,
            projectOrder: projectOrder,
            onSelected: onChanged,
          ),
        );
      },
      child: Container(
        padding: const EdgeInsets.symmetric(horizontal: 10, vertical: 9),
        decoration: BoxDecoration(
          color: Colors.white.withOpacity(0.04),
          borderRadius: BorderRadius.circular(6),
          border: Border.all(color: const Color(0xFF2A2D30)),
        ),
        child: Row(
          children: [
            Icon(
              Icons.folder_outlined,
              size: 13,
              color: selectedId != null ? accent : Colors.white38,
            ),
            const SizedBox(width: 8),
            Expanded(
              child: Text(
                selectedTitle,
                style: TextStyle(
                  fontSize: 12,
                  color: selectedId != null ? Colors.white70 : Colors.white38,
                ),
              ),
            ),
            const Icon(
              Icons.expand_more_rounded,
              size: 14,
              color: Colors.white38,
            ),
          ],
        ),
      ),
    );
  }
}

class _ProjectPickerOverlay extends StatelessWidget {
  final String? selectedId;
  final Map<String, Project> projects;
  final List<String> projectOrder;
  final void Function(String?) onSelected;

  const _ProjectPickerOverlay({
    required this.selectedId,
    required this.projects,
    required this.projectOrder,
    required this.onSelected,
  });

  @override
  Widget build(BuildContext context) {
    return GestureDetector(
      onTap: () => Navigator.of(context).pop(),
      child: Material(
        color: Colors.transparent,
        child: Center(
          child: Container(
            width: 260,
            constraints: const BoxConstraints(maxHeight: 320),
            decoration: BoxDecoration(
              color: const Color(0xFF1E2124),
              borderRadius: BorderRadius.circular(8),
              border: Border.all(color: Colors.white.withOpacity(0.1)),
              boxShadow: [
                BoxShadow(
                  color: Colors.black.withOpacity(0.5),
                  blurRadius: 20,
                  offset: const Offset(0, 8),
                ),
              ],
            ),
            child: ClipRRect(
              borderRadius: BorderRadius.circular(8),
              child: ListView(
                padding: const EdgeInsets.symmetric(vertical: 6),
                shrinkWrap: true,
                children: [
                  // None option
                  _item(context, null, 'No project'),
                  const Divider(
                    height: 1,
                    color: Color(0xFF2A2D30),
                    indent: 14,
                    endIndent: 14,
                  ),
                  ...projectOrder
                      .where((id) => projects.containsKey(id))
                      .map((id) => _item(context, id, projects[id]!.title)),
                ],
              ),
            ),
          ),
        ),
      ),
    );
  }

  Widget _item(BuildContext context, String? id, String title) {
    final selected = id == selectedId;
    return GestureDetector(
      onTap: () {
        onSelected(id);
        Navigator.of(context).pop();
      },
      child: Container(
        padding: const EdgeInsets.symmetric(horizontal: 14, vertical: 9),
        color: selected
            ? const Color(0xFF4FC3F7).withOpacity(0.08)
            : Colors.transparent,
        child: Row(
          children: [
            Expanded(
              child: Text(
                title,
                style: TextStyle(
                  fontSize: 12,
                  color: selected ? const Color(0xFF4FC3F7) : Colors.white70,
                  fontWeight: selected ? FontWeight.w600 : FontWeight.normal,
                ),
              ),
            ),
            if (selected)
              const Icon(
                Icons.check_rounded,
                size: 13,
                color: Color(0xFF4FC3F7),
              ),
          ],
        ),
      ),
    );
  }
}

// ─────────────────────────────────────────────────────────────────────────────
// _BoardView — content area for an individual board
// ─────────────────────────────────────────────────────────────────────────────

class _BoardView extends StatefulWidget {
  final Map<String, dynamic> board;
  final Map<String, Project> projects;
  final List<String> projectOrder;
  final void Function(Map<String, dynamic>) onBoardUpdated;
  final void Function(List<Task>) onTasksUpserted;
  final void Function(
    String trelloId,
    bool isCard,
    Map<String, dynamic>? cardData,
    List<Map<String, dynamic>>? checklists,
  )
  onConvertTask;
  final void Function(String trelloId) onRemoveTask;
  final List<Task> allTasks;

  const _BoardView({
    super.key,
    required this.board,
    required this.projects,
    required this.projectOrder,
    required this.onBoardUpdated,
    required this.onTasksUpserted,
    required this.onConvertTask,
    required this.onRemoveTask,
    required this.allTasks,
  });

  @override
  State<_BoardView> createState() => _BoardViewState();
}

class _BoardViewState extends State<_BoardView> {
  bool _loading = false;
  String? _error;

  // Import-as-Tasks popup overlay (board level)
  final LayerLink _importLayerLink = LayerLink();
  OverlayEntry? _importOverlay;
  bool _importOpen = false;

  List<Map<String, dynamic>> _lists = [];
  // timestamp of last successful sync
  DateTime? _lastSynced;

  @override
  void initState() {
    super.initState();
    final b = widget.board;
    final ok =
        (b['trelloApiKey'] as String? ?? '').isNotEmpty &&
        (b['trelloToken'] as String? ?? '').isNotEmpty &&
        (b['trelloBoardId'] as String? ?? '').isNotEmpty;
    if (ok) _sync();
  }

  @override
  void didUpdateWidget(_BoardView old) {
    super.didUpdateWidget(old);
    // Re-sync if credentials changed
    if (old.board['trelloBoardId'] != widget.board['trelloBoardId'] ||
        old.board['trelloApiKey'] != widget.board['trelloApiKey'] ||
        old.board['trelloToken'] != widget.board['trelloToken']) {
      _lists = [];
      _error = null;
      _sync();
    }
  }

  // ── Trello REST helpers ─────────────────────────────────────────────────

  /// Public entry-point so the parent can trigger a sync (e.g. from the tab-bar button).
  Future<void> sync() => _sync();

  String get _key => widget.board['trelloApiKey'] as String? ?? '';
  String get _token => widget.board['trelloToken'] as String? ?? '';
  String get _boardId => widget.board['trelloBoardId'] as String? ?? '';

  Uri _url(String path, [Map<String, String>? extra]) {
    final params = {'key': _key, 'token': _token, ...?extra};
    return Uri.https('api.trello.com', '/1$path', params);
  }

  Future<String> _readBody(HttpClientResponse res) async {
    final chunks = <List<int>>[];
    await for (final chunk in res) {
      chunks.add(chunk);
    }
    final bytes = chunks.expand((c) => c).toList();
    return utf8.decode(bytes);
  }

  Future<dynamic> _get(String path, [Map<String, String>? extra]) async {
    final client = HttpClient();
    try {
      final req = await client.getUrl(_url(path, extra));
      final res = await req.close();
      final body = await _readBody(res);
      if (res.statusCode != 200) {
        throw Exception('Trello ${res.statusCode}: $body');
      }
      return jsonDecode(body);
    } finally {
      client.close();
    }
  }

  // Trello REST accepts credentials + fields as URL query params for POST/PUT.
  Future<dynamic> _post(String path, Map<String, dynamic> fields) async {
    final params = <String, String>{
      'key': _key,
      'token': _token,
      ...fields.map((k, v) => MapEntry(k, v.toString())),
    };
    final uri = Uri.https('api.trello.com', '/1$path', params);
    final client = HttpClient();
    try {
      final req = await client.postUrl(uri);
      req.headers.contentLength = 0;
      final res = await req.close();
      final body = await _readBody(res);
      if (res.statusCode != 200 && res.statusCode != 201) {
        throw Exception('Trello ${res.statusCode}: $body');
      }
      return jsonDecode(body);
    } finally {
      client.close();
    }
  }

  Future<dynamic> _put(String path, Map<String, dynamic> fields) async {
    final params = <String, String>{
      'key': _key,
      'token': _token,
      ...fields.map((k, v) => MapEntry(k, v.toString())),
    };
    final uri = Uri.https('api.trello.com', '/1$path', params);
    final client = HttpClient();
    try {
      final req = await client.putUrl(uri);
      req.headers.contentLength = 0;
      final res = await req.close();
      final body = await _readBody(res);
      if (res.statusCode != 200) {
        throw Exception('Trello ${res.statusCode}: $body');
      }
      return jsonDecode(body);
    } finally {
      client.close();
    }
  }

  // ── Sync: fetch lists + cards + checklists, upsert tasks ──────────────────

  // 'none' | 'single' | 'cascade'
  String get _importCardMode =>
      widget.board['importCardMode'] as String? ?? 'none';
  String get _importChecklistMode =>
      widget.board['importChecklistMode'] as String? ?? 'none';
  String get _importItemMode =>
      widget.board['importItemMode'] as String? ?? 'single';
  // legacy helper — kept for _sync branching
  String get _importMode {
    if (_importCardMode != 'none') return 'both';
    return 'checklists_as_tasks';
  }

  Future<void> _sync() async {
    if (_loading) return;
    setState(() {
      _loading = true;
      _error = null;
    });
    try {
      final mode = _importMode;

      // 1. Lists
      final listsRaw =
          await _get('/boards/$_boardId/lists', {
                'filter': 'open',
                'fields': 'id,name,pos',
              })
              as List;

      // 2. Cards (include checklists field only if we need them)
      final cardFields = mode == 'cards_as_tasks'
          ? 'id,name,desc,idList,due,dueComplete,labels,url,pos'
          : 'id,name,desc,idList,due,dueComplete,labels,url,pos,idChecklists';
      final cardsRaw =
          await _get('/boards/$_boardId/cards', {
                'filter': 'open',
                'fields': cardFields,
              })
              as List;

      // 3. Fetch checklists when needed
      // Map cardId → list of checklist objects {id, name, checkItems:[{id,name,state}]}
      final Map<String, List<Map<String, dynamic>>> checklists = {};
      if (mode != 'cards_as_tasks') {
        // Fetch all checklists for the board in one request
        final clRaw =
            await _get('/boards/$_boardId/checklists', {
                  'fields': 'id,name,idCard,checkItems',
                  'checkItems': 'all',
                  'checkItem_fields': 'id,name,state,pos',
                })
                as List;
        for (final raw in clRaw) {
          final cl = Map<String, dynamic>.from(raw as Map);
          final cardId = cl['idCard'] as String;
          checklists.putIfAbsent(cardId, () => []).add(cl);
        }
        // Sort checkItems by pos inside each checklist
        for (final cls in checklists.values) {
          for (final cl in cls) {
            final items = cl['checkItems'] as List? ?? [];
            items.sort(
              (a, b) => ((a as Map)['pos'] as num? ?? 0).compareTo(
                (b as Map)['pos'] as num? ?? 0,
              ),
            );
          }
        }
      }

      // 4. Group cards by list
      final Map<String, List<Map<String, dynamic>>> byList = {};
      for (final raw in cardsRaw) {
        final card = Map<String, dynamic>.from(raw as Map);
        // Attach checklists to card map
        card['_checklists'] = checklists[card['id'] as String] ?? [];
        final lid = card['idList'] as String;
        byList.putIfAbsent(lid, () => []).add(card);
      }

      // 5. Build list objects
      final lists =
          listsRaw.map((r) {
            final l = Map<String, dynamic>.from(r as Map);
            final cards = (byList[l['id']] ?? [])
              ..sort(
                (a, b) => ((a['pos'] as num?) ?? 0).compareTo(
                  (b['pos'] as num?) ?? 0,
                ),
              );
            return {...l, 'cards': cards};
          }).toList()..sort(
            (a, b) =>
                ((a['pos'] as num?) ?? 0).compareTo((b['pos'] as num?) ?? 0),
          );

      // 6. Upsert internal tasks
      _upsertTasks(lists, mode);

      setState(() {
        _lists = lists;
        _lastSynced = DateTime.now();
      });
    } catch (e) {
      setState(() => _error = e.toString());
    } finally {
      setState(() => _loading = false);
    }
  }

  /// Build and push Tasks into the parent based on the current [mode]:
  ///
  /// • `checklists_as_tasks` (default) — each card's checklist items become
  ///   Tasks linked to a parent "card" Task via subTaskIds. Cards without any
  ///   checklist items are skipped (they become parents only).
  ///
  /// • `cards_as_tasks` — every card is its own Task; checklists are ignored.
  ///
  /// • `both` — every card is a Task AND each checklist item is also a Task
  ///   linked as a subtask of the card Task.
  void _upsertTasks(List<Map<String, dynamic>> lists, String mode) {
    final projectId = widget.board['projectId'] as String? ?? 'INBOX_PROJECT';
    final addCards = _importCardMode != 'none';
    final addChecklists =
        _importCardMode == 'cascade' || _importChecklistMode != 'none';
    final addSubtasks =
        _importCardMode == 'cascade' ||
        _importChecklistMode == 'cascade' ||
        _importItemMode != 'none';
    final tasks = <Task>[];

    for (final list in lists) {
      final cards = list['cards'] as List<Map<String, dynamic>>? ?? [];
      final listName = (list['name'] as String? ?? '').toLowerCase();
      final listDone =
          listName == 'done' ||
          listName == 'finished' ||
          listName == 'complete';

      for (final card in cards) {
        final cardId = card['id'] as String;
        final cardInternalId = 'trello_card_$cardId';
        final cardIsDone =
            listDone || ((card['dueComplete'] as bool?) ?? false);
        final cardLabels = (card['labels'] as List? ?? [])
            .map((l) => (l as Map)['name']?.toString() ?? '')
            .where((s) => s.isNotEmpty)
            .toList();
        String? dueDay;
        final dueRaw = card['due'];
        if (dueRaw is String) dueDay = dueRaw.split('T').first;

        final cardChecklists =
            card['_checklists'] as List<Map<String, dynamic>>? ?? [];

        if (addCards) {
          // ── Card → Task
          // subTaskIds = checklist tasks (if addChecklists) OR flat items (if addSubtasks only)
          final List<String> cardSubIds = [];

          for (final cl in cardChecklists) {
            final clId = cl['id'] as String;
            final clName = cl['name'] as String? ?? '';
            final clInternalId = 'trello_checklist_$clId';
            final clItems = (cl['checkItems'] as List? ?? [])
                .map((r) => Map<String, dynamic>.from(r as Map))
                .toList();

            if (addChecklists) {
              // Checklist → subtask of card, items → sub-subtasks
              final clSubIds = addSubtasks
                  ? clItems.map((i) => 'trello_item_${i['id']}').toList()
                  : <String>[];
              final clDone =
                  clItems.isNotEmpty &&
                  clItems.every((i) => (i['state'] as String?) == 'complete');

              tasks.add(
                Task(
                  id: clInternalId,
                  title: clName,
                  isDone: clDone,
                  status: clDone ? TaskStatus.done : TaskStatus.none,
                  projectId: projectId,
                  subTaskIds: clSubIds,
                  timeSpent: 0,
                  attachments: [],
                  tagIds: [],
                ),
              );
              cardSubIds.add(clInternalId);

              if (addSubtasks) {
                for (final item in clItems) {
                  final itemDone = (item['state'] as String?) == 'complete';
                  tasks.add(
                    Task(
                      id: 'trello_item_${item['id']}',
                      title: item['name'] as String? ?? '',
                      isDone: itemDone,
                      status: itemDone ? TaskStatus.done : TaskStatus.none,
                      projectId: projectId,
                      subTaskIds: [],
                      timeSpent: 0,
                      attachments: [],
                      tagIds: clName.isNotEmpty ? [clName] : [],
                    ),
                  );
                }
              }
            } else if (addSubtasks) {
              // No checklist grouping: items go directly as card subtasks
              for (final item in clItems) {
                final itemId = 'trello_item_${item['id']}';
                final itemDone = (item['state'] as String?) == 'complete';
                tasks.add(
                  Task(
                    id: itemId,
                    title: item['name'] as String? ?? '',
                    isDone: itemDone,
                    status: itemDone ? TaskStatus.done : TaskStatus.none,
                    projectId: projectId,
                    subTaskIds: [],
                    timeSpent: 0,
                    attachments: [],
                    tagIds: clName.isNotEmpty ? [clName] : [],
                  ),
                );
                cardSubIds.add(itemId);
              }
            }
          }

          tasks.add(
            Task(
              id: cardInternalId,
              title: card['name'] as String? ?? '(no title)',
              isDone: cardIsDone,
              status: cardIsDone ? TaskStatus.done : TaskStatus.none,
              projectId: projectId,
              subTaskIds: cardSubIds,
              timeSpent: 0,
              attachments: [],
              tagIds: cardLabels,
              dueDay: dueDay,
              notes: card['desc'] as String?,
            ),
          );
        } else {
          // Card not imported — checklist items become standalone tasks
          for (final cl in cardChecklists) {
            final clName = cl['name'] as String? ?? '';
            final clItems = (cl['checkItems'] as List? ?? [])
                .map((r) => Map<String, dynamic>.from(r as Map))
                .toList();
            if (addSubtasks) {
              for (final item in clItems) {
                final itemDone = (item['state'] as String?) == 'complete';
                tasks.add(
                  Task(
                    id: 'trello_item_${item['id']}',
                    title: item['name'] as String? ?? '',
                    isDone: itemDone,
                    status: itemDone ? TaskStatus.done : TaskStatus.none,
                    projectId: projectId,
                    subTaskIds: [],
                    timeSpent: 0,
                    attachments: [],
                    tagIds: clName.isNotEmpty ? [clName] : [],
                  ),
                );
              }
            }
          }
        }
      }
    }

    widget.onTasksUpserted(tasks);
  }

  // ── Trello writes ────────────────────────────────────────────────────────

  Future<void> _createCard(String listId, String name) async {
    setState(() => _loading = true);
    try {
      await _post('/cards', {'idList': listId, 'name': name});
      await _sync();
    } catch (e) {
      setState(() {
        _error = e.toString();
        _loading = false;
      });
    }
  }

  Future<void> _updateCard(String cardId, Map<String, dynamic> fields) async {
    setState(() => _loading = true);
    try {
      await _put('/cards/$cardId', fields);
      await _sync();
    } catch (e) {
      setState(() {
        _error = e.toString();
        _loading = false;
      });
    }
  }

  Future<void> _moveCard(String cardId, String toListId) async {
    await _updateCard(cardId, {'idList': toListId});
  }

  Future<void> _archiveCard(String cardId) async {
    setState(() => _loading = true);
    try {
      await _put('/cards/$cardId', {'closed': true});
      await _sync();
    } catch (e) {
      setState(() {
        _error = e.toString();
        _loading = false;
      });
    }
  }

  // ── UI ───────────────────────────────────────────────────────────────────

  @override
  Widget build(BuildContext context) {
    final board = widget.board;
    final apiKey = board['trelloApiKey'] as String? ?? '';
    final token = board['trelloToken'] as String? ?? '';
    final boardId = board['trelloBoardId'] as String? ?? '';
    final linkedProject = board['projectId'] as String?;
    final projectTitle = linkedProject != null
        ? (widget.projects[linkedProject]?.title ?? linkedProject)
        : null;
    final missingCreds = apiKey.isEmpty || token.isEmpty || boardId.isEmpty;

    return Container(
      color: const Color(0xFF141618),
      child: missingCreds
          ? _buildSetupPrompt(board)
          : Column(
              crossAxisAlignment: CrossAxisAlignment.stretch,
              children: [
                _buildInfoBar(board, projectTitle),
                if (_error != null) _buildErrorBanner(),
                Expanded(
                  child: _lists.isEmpty && _loading
                      ? const Center(
                          child: CircularProgressIndicator(
                            strokeWidth: 2,
                            color: Color(0xFF4FC3F7),
                          ),
                        )
                      : _lists.isEmpty
                      ? _buildEmptySync()
                      : _buildKanban(),
                ),
              ],
            ),
    );
  }

  /// Remove all Trello-sourced tasks matching the selected modes (board-wide).
  void _cleanByModes(String cardMode, String checklistMode, String itemMode) {
    final removeCards = cardMode != 'none';
    final removeChecklists = checklistMode != 'none';
    final removeItems = itemMode != 'none';
    final toRemove = <String>{};
    for (final t in widget.allTasks) {
      if (removeCards && t.id.startsWith('trello_card_')) toRemove.add(t.id);
      if (removeChecklists && t.id.startsWith('trello_checklist_'))
        toRemove.add(t.id);
      if (removeItems && t.id.startsWith('trello_item_')) toRemove.add(t.id);
    }
    for (final id in toRemove) widget.onRemoveTask(id);
  }

  // ── Board-level Import-as-Tasks popup ────────────────────────────────────

  void _openImportPopup() {
    final overlay = Overlay.of(context);
    _importOverlay = OverlayEntry(builder: (_) => _buildImportPopup());
    overlay.insert(_importOverlay!);
    setState(() => _importOpen = true);
  }

  void _closeImportPopup() {
    _importOverlay?.remove();
    _importOverlay = null;
    if (mounted) setState(() => _importOpen = false);
  }

  Widget _buildImportPopup() {
    // Local mutable copies so the popup can be stateful
    String cardMode = _importCardMode;
    String checklistMode = _importChecklistMode;
    String itemMode = _importItemMode;

    return GestureDetector(
      onTap: _closeImportPopup,
      behavior: HitTestBehavior.translucent,
      child: Stack(
        children: [
          Positioned.fill(child: Container(color: Colors.transparent)),
          CompositedTransformFollower(
            link: _importLayerLink,
            showWhenUnlinked: false,
            offset: const Offset(0, 38),
            targetAnchor: Alignment.bottomRight,
            followerAnchor: Alignment.topRight,
            child: Align(
              alignment: Alignment.topRight,
              child: GestureDetector(
                onTap: () {}, // absorb inside taps
                child: StatefulBuilder(
                  builder: (ctx, setPopup) {
                    return Material(
                      color: Colors.transparent,
                      child: Container(
                        width: 300,
                        decoration: BoxDecoration(
                          color: const Color(0xFF1E2124),
                          borderRadius: BorderRadius.circular(10),
                          border: Border.all(
                            color: Colors.white.withOpacity(0.09),
                          ),
                          boxShadow: [
                            BoxShadow(
                              color: Colors.black.withOpacity(0.5),
                              blurRadius: 20,
                              offset: const Offset(0, 8),
                            ),
                          ],
                        ),
                        child: Column(
                          mainAxisSize: MainAxisSize.min,
                          children: [
                            // Header
                            Padding(
                              padding: const EdgeInsets.fromLTRB(
                                14,
                                12,
                                12,
                                10,
                              ),
                              child: Row(
                                children: [
                                  const Icon(
                                    Icons.filter_alt_outlined,
                                    size: 13,
                                    color: Color(0xFF4FC3F7),
                                  ),
                                  const SizedBox(width: 8),
                                  const Expanded(
                                    child: Text(
                                      'Import as Tasks',
                                      style: TextStyle(
                                        fontSize: 12,
                                        fontWeight: FontWeight.w600,
                                        color: Colors.white70,
                                      ),
                                    ),
                                  ),
                                  GestureDetector(
                                    onTap: _closeImportPopup,
                                    child: const Icon(
                                      Icons.close_rounded,
                                      size: 14,
                                      color: Colors.white38,
                                    ),
                                  ),
                                ],
                              ),
                            ),
                            const Divider(height: 1, color: Color(0xFF2A2D30)),
                            Padding(
                              padding: const EdgeInsets.all(14),
                              child: Column(
                                crossAxisAlignment: CrossAxisAlignment.stretch,
                                children: [
                                  _ImportTriState(
                                    label: 'Card',
                                    sublabel: 'Trello card',
                                    mode: cardMode,
                                    onChanged: (v) =>
                                        setPopup(() => cardMode = v),
                                  ),
                                  const SizedBox(height: 10),
                                  _ImportTriState(
                                    label: 'Checklist',
                                    sublabel: 'Checklist inside card',
                                    mode: checklistMode,
                                    onChanged: (v) =>
                                        setPopup(() => checklistMode = v),
                                  ),
                                  const SizedBox(height: 10),
                                  _ImportTriState(
                                    label: 'Item',
                                    sublabel: 'Item inside checklist',
                                    mode: itemMode,
                                    allowCascade: false,
                                    onChanged: (v) =>
                                        setPopup(() => itemMode = v),
                                  ),
                                  const SizedBox(height: 14),
                                  Row(
                                    children: [
                                      // Clean button
                                      Expanded(
                                        child: GestureDetector(
                                          onTap: () {
                                            _closeImportPopup();
                                            _cleanByModes(
                                              cardMode,
                                              checklistMode,
                                              itemMode,
                                            );
                                          },
                                          child: Container(
                                            padding: const EdgeInsets.symmetric(
                                              vertical: 9,
                                            ),
                                            decoration: BoxDecoration(
                                              color: Colors.red.withOpacity(
                                                0.07,
                                              ),
                                              borderRadius:
                                                  BorderRadius.circular(6),
                                              border: Border.all(
                                                color: Colors.red.withOpacity(
                                                  0.25,
                                                ),
                                              ),
                                            ),
                                            child: const Center(
                                              child: Text(
                                                'Clean',
                                                style: TextStyle(
                                                  fontSize: 12,
                                                  color: Colors.redAccent,
                                                  fontWeight: FontWeight.w600,
                                                ),
                                              ),
                                            ),
                                          ),
                                        ),
                                      ),
                                      const SizedBox(width: 8),
                                      // Import & Refresh button
                                      Expanded(
                                        flex: 2,
                                        child: GestureDetector(
                                          onTap: () {
                                            _closeImportPopup();
                                            final updated =
                                                Map<String, dynamic>.from(
                                                    widget.board,
                                                  )
                                                  ..['importCardMode'] =
                                                      cardMode
                                                  ..['importChecklistMode'] =
                                                      checklistMode
                                                  ..['importItemMode'] =
                                                      itemMode;
                                            widget.onBoardUpdated(updated);
                                            Future.microtask(sync);
