  Widget _buildInfoBar(Map<String, dynamic> board, String? projectTitle) {
    final synced = _lastSynced;
    String syncLabel = 'Not synced';
    if (synced != null) {
      final diff = DateTime.now().difference(synced);
      if (diff.inSeconds < 60)
        syncLabel = 'Just synced';
      else if (diff.inMinutes < 60)
        syncLabel = '${diff.inMinutes}m ago';
      else
        syncLabel = '${diff.inHours}h ago';
    }
    return Container(
      decoration: const BoxDecoration(
        color: Color(0xFF1A1C1F),
        border: Border(bottom: BorderSide(color: Color(0xFF2A2D30))),
      ),
      child: Column(
        mainAxisSize: MainAxisSize.min,
        children: [
          // ── Top row: board name + sync ──────────────────────────────
          Padding(
            padding: const EdgeInsets.symmetric(horizontal: 16, vertical: 10),
            child: Row(
              children: [
                Container(
                  width: 20,
                  height: 20,
                  decoration: BoxDecoration(
                    color: const Color(0xFF0052CC),
                    borderRadius: BorderRadius.circular(4),
                  ),
                  child: const Icon(
                    Icons.view_kanban_outlined,
                    size: 12,
                    color: Colors.white,
                  ),
                ),
                const SizedBox(width: 10),
                Text(
                  board['title'] as String? ?? 'Board',
                  style: const TextStyle(
                    fontSize: 12,
                    fontWeight: FontWeight.w600,
                    color: Colors.white70,
                  ),
                ),
                if (projectTitle != null) ...[
                  const SizedBox(width: 8),
                  Container(
                    padding: const EdgeInsets.symmetric(
                      horizontal: 6,
                      vertical: 2,
                    ),
                    decoration: BoxDecoration(
                      color: const Color(0xFF4FC3F7).withOpacity(0.08),
                      borderRadius: BorderRadius.circular(4),
                      border: Border.all(
                        color: const Color(0xFF4FC3F7).withOpacity(0.25),
                      ),
                    ),
                    child: Text(
                      projectTitle,
                      style: const TextStyle(
                        fontSize: 10,
                        color: Color(0xFF4FC3F7),
                      ),
                    ),
                  ),
                ],
                const Spacer(),
                Text(
                  syncLabel,
                  style: TextStyle(
                    fontSize: 10,
                    color: Colors.white.withOpacity(0.3),
                  ),
                ),
                const SizedBox(width: 10),
                if (_loading)
                  const SizedBox(
                    width: 14,
                    height: 14,
                    child: CircularProgressIndicator(
                      strokeWidth: 2,
                      color: Color(0xFF4FC3F7),
                    ),
                  )
                else
                  Tooltip(
                    message: 'Sync now',
                    child: GestureDetector(
                      onTap: _sync,
                      child: const Icon(
                        Icons.sync_rounded,
                        size: 15,
                        color: Colors.white38,
                      ),
                    ),
                  ),
                const SizedBox(width: 8),
                // Import as Tasks button
                CompositedTransformTarget(
                  link: _importLayerLink,
                  child: Tooltip(
                    message: 'Import as Tasks settings',
                    child: GestureDetector(
                      onTap: _importOpen ? _closeImportPopup : _openImportPopup,
                      child: AnimatedContainer(
                        duration: const Duration(milliseconds: 120),
                        padding: const EdgeInsets.symmetric(
                          horizontal: 8,
                          vertical: 5,
                        ),
                        decoration: BoxDecoration(
                          color: _importOpen
                              ? const Color(0xFF4FC3F7).withOpacity(0.12)
                              : Colors.white.withOpacity(0.04),
                          borderRadius: BorderRadius.circular(5),
                          border: Border.all(
                            color: _importOpen
                                ? const Color(0xFF4FC3F7).withOpacity(0.4)
                                : Colors.white.withOpacity(0.1),
