  Widget _buildKanban() {
    return ListView.builder(
      scrollDirection: Axis.horizontal,
      padding: const EdgeInsets.all(16),
      itemCount: _lists.length + 1, // +1 for "Add list" phantom
      itemBuilder: (_, i) {
        if (i == _lists.length) return _buildAddListHint();
        return _buildColumn(_lists[i]);
      },
    );
  }

  Widget _buildColumn(Map<String, dynamic> list) {
    final cards = list['cards'] as List<Map<String, dynamic>>? ?? [];
    final listId = list['id'] as String;
    final listName = list['name'] as String? ?? '';
    final addCtrl = TextEditingController();
    bool adding = false;

    return Container(
      width: 260,
      margin: const EdgeInsets.only(right: 12),
      decoration: BoxDecoration(
        color: const Color(0xFF1A1C1F),
        borderRadius: BorderRadius.circular(8),
        border: Border.all(color: const Color(0xFF2A2D30)),
      ),
      child: Column(
        children: [
          // Column header
          Padding(
            padding: const EdgeInsets.fromLTRB(12, 12, 8, 10),
            child: Row(
              children: [
                Expanded(
                  child: Text(
                    listName,
                    style: const TextStyle(
                      fontSize: 12,
                      fontWeight: FontWeight.w600,
                      color: Colors.white70,
                    ),
                  ),
                ),
                Text(
                  '${cards.length}',
                  style: TextStyle(
                    fontSize: 11,
                    color: Colors.white.withOpacity(0.3),
                  ),
                ),
              ],
            ),
          ),
          const Divider(height: 1, color: Color(0xFF2A2D30)),

          // Cards
          Expanded(
            child: ListView.builder(
              padding: const EdgeInsets.all(8),
              itemCount: cards.length,
              itemBuilder: (_, j) => _buildCard(cards[j], list),
            ),
          ),

          // Add card row
          StatefulBuilder(
            builder: (ctx, setLocal) {
              return Padding(
                padding: const EdgeInsets.fromLTRB(8, 4, 8, 8),
                child: adding
                    ? Column(
                        children: [
                          TextField(
                            controller: addCtrl,
                            autofocus: true,
                            style: const TextStyle(
                              fontSize: 12,
                              color: Colors.white,
                            ),
                            decoration: InputDecoration(
                              hintText: 'Card title…',
                              hintStyle: TextStyle(
                                fontSize: 12,
                                color: Colors.white.withOpacity(0.25),
                              ),
                              isDense: true,
                              contentPadding: const EdgeInsets.symmetric(
                                horizontal: 10,
                                vertical: 8,
                              ),
                              filled: true,
                              fillColor: Colors.white.withOpacity(0.06),
                              border: OutlineInputBorder(
                                borderRadius: BorderRadius.circular(6),
                                borderSide: const BorderSide(
                                  color: Color(0xFF4FC3F7),
                                ),
                              ),
                              enabledBorder: OutlineInputBorder(
                                borderRadius: BorderRadius.circular(6),
                                borderSide: const BorderSide(
                                  color: Color(0xFF4FC3F7),
                                ),
                              ),
                              focusedBorder: OutlineInputBorder(
                                borderRadius: BorderRadius.circular(6),
                                borderSide: const BorderSide(
                                  color: Color(0xFF4FC3F7),
                                ),
                              ),
                            ),
                          ),
                          const SizedBox(height: 6),
                          Row(
                            children: [
                              GestureDetector(
                                onTap: () {
                                  final name = addCtrl.text.trim();
                                  if (name.isNotEmpty)
                                    _createCard(listId, name);
                                  setLocal(() => adding = false);
                                  addCtrl.clear();
                                },
                                child: Container(
                                  padding: const EdgeInsets.symmetric(
                                    horizontal: 12,
                                    vertical: 6,
                                  ),
                                  decoration: BoxDecoration(
                                    color: const Color(
                                      0xFF4FC3F7,
                                    ).withOpacity(0.12),
                                    borderRadius: BorderRadius.circular(5),
                                    border: Border.all(
                                      color: const Color(
                                        0xFF4FC3F7,
                                      ).withOpacity(0.35),
                                    ),
                                  ),
                                  child: const Text(
                                    'Add',
                                    style: TextStyle(
                                      fontSize: 11,
                                      color: Color(0xFF4FC3F7),
                                      fontWeight: FontWeight.w600,
                                    ),
                                  ),
                                ),
                              ),
                              const SizedBox(width: 8),
                              GestureDetector(
                                onTap: () {
                                  setLocal(() => adding = false);
                                  addCtrl.clear();
                                },
                                child: const Icon(
                                  Icons.close_rounded,
                                  size: 16,
                                  color: Colors.white38,
                                ),
                              ),
                            ],
                          ),
                        ],
                      )
                    : GestureDetector(
                        onTap: () => setLocal(() => adding = true),
                        child: Row(
                          children: [
                            const Icon(
                              Icons.add,
                              size: 14,
                              color: Colors.white30,
                            ),
                            const SizedBox(width: 6),
                            Text(
                              'Add card',
                              style: TextStyle(
                                fontSize: 11,
                                color: Colors.white.withOpacity(0.3),
                              ),
                            ),
                          ],
                        ),
                      ),
              );
            },
          ),
        ],
      ),
    );
  }

  Widget _buildCard(Map<String, dynamic> card, Map<String, dynamic> list) {
    final cardId = card['id'] as String;
    final name = card['name'] as String? ?? '';
    final desc = card['desc'] as String? ?? '';
    final isDone = (card['dueComplete'] as bool?) ?? false;
    final dueRaw = card['due'] as String?;
    final labels = (card['labels'] as List? ?? [])
        .map((l) => (l as Map))
        .where((l) => (l['name'] as String?)?.isNotEmpty == true)
        .toList();
    final otherLists = _lists.where((l) => l['id'] != list['id']).toList();

    DateTime? due;
    if (dueRaw != null) due = DateTime.tryParse(dueRaw);
    final overdue = due != null && !isDone && due.isBefore(DateTime.now());

    return Container(
      margin: const EdgeInsets.only(bottom: 6),
      decoration: BoxDecoration(
        color: const Color(0xFF1E2124),
        borderRadius: BorderRadius.circular(6),
        border: Border.all(
          color: overdue
              ? Colors.redAccent.withOpacity(0.4)
              : Colors.white.withOpacity(0.06),
        ),
      ),
      child: Material(
        color: Colors.transparent,
        borderRadius: BorderRadius.circular(6),
        child: InkWell(
          borderRadius: BorderRadius.circular(6),
          onTap: () => _showCardDetail(card, list),
          child: Padding(
            padding: const EdgeInsets.all(10),
            child: Column(
              crossAxisAlignment: CrossAxisAlignment.start,
              children: [
                // Labels
                if (labels.isNotEmpty) ...[
                  Wrap(
                    spacing: 4,
                    children: labels.map((l) {
                      final colorHex = (l['color'] as String?) ?? 'grey';
                      final c = _trelloColor(colorHex);
                      return Container(
                        padding: const EdgeInsets.symmetric(
                          horizontal: 6,
                          vertical: 2,
                        ),
                        decoration: BoxDecoration(
                          color: c.withOpacity(0.2),
                          borderRadius: BorderRadius.circular(3),
                        ),
                        child: Text(
                          l['name'] as String? ?? '',
                          style: TextStyle(fontSize: 9, color: c),
                        ),
                      );
                    }).toList(),
                  ),
                  const SizedBox(height: 6),
                ],

                // Title
                Text(
                  name,
                  style: TextStyle(
                    fontSize: 12,
                    color: isDone ? Colors.white38 : Colors.white70,
                    decoration: isDone ? TextDecoration.lineThrough : null,
                  ),
                ),

                if (desc.isNotEmpty) ...[
                  const SizedBox(height: 4),
                  Text(
                    desc.length > 80 ? '${desc.substring(0, 80)}…' : desc,
                    style: TextStyle(
                      fontSize: 10,
                      color: Colors.white.withOpacity(0.3),
                    ),
                  ),
                ],

                // Due date
                if (due != null) ...[
                  const SizedBox(height: 6),
                  Row(
                    children: [
                      Icon(
                        isDone
                            ? Icons.check_circle_rounded
                            : Icons.access_time_rounded,
                        size: 11,
                        color: isDone
                            ? const Color(0xFF4CAF50)
                            : overdue
                            ? Colors.redAccent
                            : Colors.white38,
                      ),
                      const SizedBox(width: 4),
                      Text(
                        '${due.day}/${due.month}/${due.year}',
                        style: TextStyle(
                          fontSize: 10,
                          color: isDone
                              ? const Color(0xFF4CAF50)
                              : overdue
                              ? Colors.redAccent
                              : Colors.white38,
                        ),
                      ),
                    ],
                  ),
                ],

                // Move to list + archive row
                const SizedBox(height: 8),
                Builder(
                  builder: (context) {
                    final cardInternalId = 'trello_card_$cardId';
                    final isTask = widget.allTasks.any(
                      (t) => t.id == cardInternalId,
                    );
                    return Row(
                      children: [
                        _TrelloToggleBtn(
                          isActive: isTask,
                          onTap: () => widget.onConvertTask(
                            cardInternalId,
                            true,
                            card,
                            card['_checklists']
                                    as List<Map<String, dynamic>>? ??
                                [],
                          ),
                        ),
                        const Spacer(),
                        if (otherLists.isNotEmpty)
                          PopupMenuButton<String>(
                            tooltip: 'Move to list',
                            color: const Color(0xFF1E2124),
                            icon: const Icon(
                              Icons.arrow_forward_rounded,
                              size: 13,
                              color: Colors.white30,
                            ),
                            itemBuilder: (_) => otherLists
                                .map(
                                  (l) => PopupMenuItem<String>(
                                    value: l['id'] as String,
                                    height: 36,
                                    child: Text(
                                      l['name'] as String? ?? '',
                                      style: const TextStyle(
                                        fontSize: 12,
                                        color: Colors.white70,
                                      ),
                                    ),
                                  ),
                                )
                                .toList(),
                            onSelected: (lid) => _moveCard(cardId, lid),
                          ),
                        GestureDetector(
                          onTap: () => _archiveCard(cardId),
                          child: Padding(
                            padding: const EdgeInsets.only(left: 4),
                            child: Tooltip(
                              message: 'Archive card',
                              child: Icon(
                                Icons.archive_outlined,
                                size: 13,
                                color: Colors.white.withOpacity(0.25),
                              ),
                            ),
                          ),
                        ),
                      ],
                    );
                  },
                ),
              ],
            ),
          ),
        ),
      ),
    );
  }

  Widget _buildAddListHint() => Container(
    width: 200,
    decoration: BoxDecoration(
      color: Colors.white.withOpacity(0.03),
      borderRadius: BorderRadius.circular(8),
      border: Border.all(color: Colors.white.withOpacity(0.06)),
    ),
    child: Center(
      child: Text(
        'Lists are managed in Trello',
        textAlign: TextAlign.center,
        style: TextStyle(fontSize: 11, color: Colors.white.withOpacity(0.2)),
      ),
    ),
  );

  void _showCardDetail(Map<String, dynamic> card, Map<String, dynamic> list) {
    Navigator.of(context).push(
      MaterialPageRoute(
        builder: (_) => _TrelloCardPage(
          card: card,
          list: list,
          apiKey: _key,
          token: _token,
          onUpdate: (fields) => _updateCard(card['id'] as String, fields),
          onArchive: () => _archiveCard(card['id'] as String),
          trelloColor: _trelloColor,
          onConvertTask: widget.onConvertTask,
          onRemoveTask: widget.onRemoveTask,
          allTasks: widget.allTasks,
        ),
      ),
    );
  }

  Color _trelloColor(String name) {
    const map = {
      'red': Color(0xFFEB5A46),
      'orange': Color(0xFFFF9F1A),
      'yellow': Color(0xFFF2D600),
      'green': Color(0xFF61BD4F),
      'sky': Color(0xFF00C2E0),
      'blue': Color(0xFF0079BF),
      'purple': Color(0xFFC377E0),
      'pink': Color(0xFFFF78CB),
      'lime': Color(0xFF51E898),
      'black': Color(0xFF344563),
    };
    return map[name] ?? Colors.white38;
  }

  Widget _buildSetupPrompt(Map<String, dynamic> board) {
    return Center(
      child: Column(
        mainAxisSize: MainAxisSize.min,
        children: [
          Container(
            width: 48,
            height: 48,
            decoration: BoxDecoration(
              color: const Color(0xFF0052CC).withOpacity(0.15),
              borderRadius: BorderRadius.circular(12),
            ),
            child: const Icon(
              Icons.view_kanban_outlined,
              size: 24,
              color: Color(0xFF0052CC),
            ),
          ),
          const SizedBox(height: 16),
          Text(
            board['title'] as String? ?? 'Board',
            style: const TextStyle(
              fontSize: 16,
              fontWeight: FontWeight.w600,
              color: Colors.white70,
            ),
          ),
          const SizedBox(height: 8),
          Text(
            'Trello credentials are incomplete.',
            style: TextStyle(
              fontSize: 12,
              color: Colors.white.withOpacity(0.35),
            ),
          ),
          const SizedBox(height: 20),
          GestureDetector(
            onTap: _showEditDialog,
            child: Container(
              padding: const EdgeInsets.symmetric(horizontal: 20, vertical: 9),
              decoration: BoxDecoration(
                color: const Color(0xFF4FC3F7).withOpacity(0.1),
                borderRadius: BorderRadius.circular(7),
                border: Border.all(
                  color: const Color(0xFF4FC3F7).withOpacity(0.35),
                ),
              ),
              child: const Text(
                'Configure',
                style: TextStyle(
                  fontSize: 12,
                  color: Color(0xFF4FC3F7),
                  fontWeight: FontWeight.w600,
                ),
              ),
            ),
          ),
        ],
      ),
    );
  }

  void _showEditDialog() {
    showDialog(
      context: context,
      builder: (_) => _EditBoardDialog(
        board: widget.board,
        projects: widget.projects,
        projectOrder: widget.projectOrder,
        onSaved: widget.onBoardUpdated,
        onRefreshImport: () {
          widget.onBoardUpdated(widget.board); // persist bools
          Future.microtask(sync); // re-sync
        },
      ),
    );
  }
}

// ─────────────────────────────────────────────────────────────────────────────
// _EditBoardDialog — edit existing board credentials
// ─────────────────────────────────────────────────────────────────────────────

class _EditBoardDialog extends StatefulWidget {
  final Map<String, dynamic> board;
  final Map<String, Project> projects;
  final List<String> projectOrder;
  final void Function(Map<String, dynamic>) onSaved;
  final VoidCallback? onRefreshImport;

  const _EditBoardDialog({
    required this.board,
    required this.projects,
    required this.projectOrder,
    required this.onSaved,
    this.onRefreshImport,
  });

  @override
  State<_EditBoardDialog> createState() => _EditBoardDialogState();
}

class _EditBoardDialogState extends State<_EditBoardDialog> {
  late TextEditingController _titleCtrl;
  late TextEditingController _apiKeyCtrl;
  late TextEditingController _tokenCtrl;
  late TextEditingController _boardIdCtrl;
  String? _selectedProjectId;
  late String _importCardMode;
  late String _importChecklistMode;
  late String _importItemMode;

  @override
  void initState() {
    super.initState();
    final b = widget.board;
    _titleCtrl = TextEditingController(text: b['title'] as String? ?? '');
    _apiKeyCtrl = TextEditingController(
      text: b['trelloApiKey'] as String? ?? '',
    );
    _tokenCtrl = TextEditingController(text: b['trelloToken'] as String? ?? '');
    _boardIdCtrl = TextEditingController(
      text: b['trelloBoardId'] as String? ?? '',
    );
    _selectedProjectId = b['projectId'] as String?;
    _importCardMode = b['importCardMode'] as String? ?? 'none';
    _importChecklistMode = b['importChecklistMode'] as String? ?? 'none';
    _importItemMode = b['importItemMode'] as String? ?? 'single';
  }

  @override
  void dispose() {
    _titleCtrl.dispose();
    _apiKeyCtrl.dispose();
    _tokenCtrl.dispose();
    _boardIdCtrl.dispose();
    super.dispose();
  }

  InputDecoration _inputDec(String hint) => InputDecoration(
    hintText: hint,
    hintStyle: TextStyle(fontSize: 12, color: Colors.white.withOpacity(0.2)),
    isDense: true,
    contentPadding: const EdgeInsets.symmetric(horizontal: 10, vertical: 9),
    filled: true,
    fillColor: Colors.white.withOpacity(0.04),
    border: OutlineInputBorder(
      borderRadius: BorderRadius.circular(6),
      borderSide: const BorderSide(color: Color(0xFF2A2D30)),
    ),
    enabledBorder: OutlineInputBorder(
      borderRadius: BorderRadius.circular(6),
      borderSide: const BorderSide(color: Color(0xFF2A2D30)),
    ),
    focusedBorder: OutlineInputBorder(
      borderRadius: BorderRadius.circular(6),
