// ─────────────────────────────────────────────────────────────────────────────
// _TrelloCardPage — full-screen card detail view
// ─────────────────────────────────────────────────────────────────────────────

class _TrelloCardPage extends StatefulWidget {
  final Map<String, dynamic> card;
  final Map<String, dynamic> list;
  final String apiKey;
  final String token;
  final Future<void> Function(Map<String, dynamic>) onUpdate;
  final Future<void> Function() onArchive;
  final Color Function(String) trelloColor;
  final void Function(
    String trelloId,
    bool isCard,
    Map<String, dynamic>? cardData,
    List<Map<String, dynamic>>? checklists,
  )
  onConvertTask;
  final void Function(String trelloId) onRemoveTask;
  final List<Task> allTasks;

  const _TrelloCardPage({
    required this.card,
    required this.list,
    required this.apiKey,
    required this.token,
    required this.onUpdate,
    required this.onArchive,
    required this.trelloColor,
    required this.onConvertTask,
    required this.onRemoveTask,
    required this.allTasks,
  });

  @override
  State<_TrelloCardPage> createState() => _TrelloCardPageState();
}

class _TrelloCardPageState extends State<_TrelloCardPage> {
  late TextEditingController _nameCtrl;
  late TextEditingController _descCtrl;
  bool _isDone = false;
  bool _saving = false;
  bool _loadingChecklists = true;
  String? _clError;

  /// Checklists fetched fresh from Trello:
  /// [ { 'id', 'name', 'checkItems': [ { 'id', 'name', 'state', 'pos' } ] } ]
  List<Map<String, dynamic>> _checklists = [];

  // Track which item IDs are being toggled (show per-item spinner)
  final Set<String> _togglingItems = {};

  /// Local set of trello IDs that are currently Chaos Control tasks.
  /// Owned by this page so toggles update instantly without needing
  /// a parent rebuild (the page is a Navigator route, outside the
  /// parent's widget tree).
  late Set<String> _localInCanvas;

  // +Add dropdown overlay
  final LayerLink _addLayerLink = LayerLink();
  OverlayEntry? _addOverlay;
  bool _addOpen = false;

  // Chaos Control status for this card's task (if it exists in allTasks)
  TaskStatus _chaosControlStatus = TaskStatus.none;

  // Card-level Import-as-Tasks overlay
  final LayerLink _cardImportLayerLink = LayerLink();
  OverlayEntry? _cardImportOverlay;
  bool _cardImportOpen = false;
  // Per-card import modes (independent of board defaults)
  String _cardImportCardMode = 'none';
  String _cardImportChecklistMode = 'none';
  String _cardImportItemMode = 'single';

  static const _bg = Color(0xFF141618);
  static const _card = Color(0xFF1A1C1F);
  static const _card2 = Color(0xFF1E2124);
  static const _border = Color(0xFF2A2D30);
  static const _accent = Color(0xFF4FC3F7);
  static const _trello = Color(0xFF0052CC);

  @override
  void initState() {
    super.initState();
    _nameCtrl = TextEditingController(
      text: widget.card['name'] as String? ?? '',
    );
    _descCtrl = TextEditingController(
      text: widget.card['desc'] as String? ?? '',
    );
    _isDone = (widget.card['dueComplete'] as bool?) ?? false;
    // Seed local canvas state from the task list passed at creation time
    _localInCanvas = {};
    // Seed Chaos Control status from existing task if any
    final cardIntId = 'trello_card_${widget.card['id']}';
    final existing = widget.allTasks.where((t) => t.id == cardIntId).toList();
    if (existing.isNotEmpty) _chaosControlStatus = existing.first.status;
    _fetchChecklists();
  }

  /// Toggle a Trello item in/out of Chaos Control and keep local state in sync.
  void _handleConvert(
    String id,
    bool isCard,
    Map<String, dynamic>? itemData,
    List<Map<String, dynamic>>? checklists,
  ) {
    setState(() {
      if (_localInCanvas.contains(id)) {
        _localInCanvas.remove(id);
        // Also un-mark items if this was a checklist toggle-off
        if (checklists != null && checklists.isNotEmpty) {
          for (final item in (checklists.first['checkItems'] as List? ?? [])) {
            _localInCanvas.remove('trello_item_${(item as Map)['id']}');
          }
        }
      } else {
        _localInCanvas.add(id);
        // Also mark items as in-canvas when toggling checklist on
        if (checklists != null && checklists.isNotEmpty) {
          for (final item in (checklists.first['checkItems'] as List? ?? [])) {
            _localInCanvas.add('trello_item_${(item as Map)['id']}');
          }
        }
      }
    });
    widget.onConvertTask(id, isCard, itemData, checklists);
  }

  @override
  void dispose() {
    _closeAddMenu();
    _closeCardImportPopup();
    _nameCtrl.dispose();
    _descCtrl.dispose();
    super.dispose();
  }

  // ── API ──────────────────────────────────────────────────────────────────

  Uri _url(String path, [Map<String, String>? extra]) => Uri.https(
    'api.trello.com',
    '/1$path',
    {'key': widget.apiKey, 'token': widget.token, ...?extra},
  );

  Future<String> _readBody(HttpClientResponse res) async {
    final chunks = <List<int>>[];
    await for (final c in res) chunks.add(c);
    return utf8.decode(chunks.expand((c) => c).toList());
  }

  Future<dynamic> _get(String path, [Map<String, String>? extra]) async {
    final client = HttpClient();
    try {
      final req = await client.getUrl(_url(path, extra));
      final res = await req.close();
      final body = await _readBody(res);
      if (res.statusCode != 200) throw Exception('${res.statusCode}: $body');
      return jsonDecode(body);
    } finally {
      client.close();
    }
  }

  Future<dynamic> _put(String path, Map<String, dynamic> fields) async {
    final params = <String, String>{
      'key': widget.apiKey,
      'token': widget.token,
      ...fields.map((k, v) => MapEntry(k, v.toString())),
    };
    final client = HttpClient();
    try {
      final req = await client.putUrl(
        Uri.https('api.trello.com', '/1$path', params),
      );
      req.headers.contentLength = 0;
      final res = await req.close();
      final body = await _readBody(res);
      if (res.statusCode != 200) throw Exception('${res.statusCode}: $body');
      return jsonDecode(body);
    } finally {
      client.close();
    }
  }

  // ── Data ─────────────────────────────────────────────────────────────────

  Future<void> _fetchChecklists() async {
    setState(() {
      _loadingChecklists = true;
      _clError = null;
    });
    try {
      final cardId = widget.card['id'] as String;
      final raw =
          await _get('/cards/$cardId/checklists', {
                'checkItems': 'all',
                'checkItem_fields': 'id,name,state,pos',
              })
              as List;
      final cls = raw.map((r) {
        final cl = Map<String, dynamic>.from(r as Map);
        final items =
            (cl['checkItems'] as List? ?? [])
                .map((i) => Map<String, dynamic>.from(i as Map))
                .toList()
              ..sort(
                (a, b) => ((a['pos'] as num?) ?? 0).compareTo(
                  (b['pos'] as num?) ?? 0,
                ),
              );
        cl['checkItems'] = items;
        return cl;
      }).toList();
      setState(() => _checklists = cls);
    } catch (e) {
      setState(() => _clError = e.toString());
    } finally {
      setState(() => _loadingChecklists = false);
    }
  }

  Future<void> _toggleItem(
    String checklistId,
    String itemId,
    bool current,
  ) async {
    setState(() => _togglingItems.add(itemId));
    try {
      final cardId = widget.card['id'] as String;
      final newState = current ? 'incomplete' : 'complete';
      await _put('/cards/$cardId/checkItem/$itemId', {'state': newState});
      // Update local state immediately
      setState(() {
        for (final cl in _checklists) {
          if (cl['id'] == checklistId) {
            final items = cl['checkItems'] as List<Map<String, dynamic>>;
            for (final item in items) {
              if (item['id'] == itemId) {
                item['state'] = newState;
              }
            }
          }
        }
      });
    } catch (e) {
      if (mounted) {
        ScaffoldMessenger.of(context).showSnackBar(
          SnackBar(content: Text('Error: $e'), backgroundColor: Colors.red),
        );
      }
    } finally {
      setState(() => _togglingItems.remove(itemId));
    }
  }

  Future<void> _saveCard() async {
    setState(() => _saving = true);
    try {
      await widget.onUpdate({
        'name': _nameCtrl.text.trim(),
        'desc': _descCtrl.text.trim(),
        'dueComplete': _isDone,
      });
      if (mounted) Navigator.of(context).pop();
    } catch (e) {
      setState(() => _saving = false);
      if (mounted) {
        ScaffoldMessenger.of(context).showSnackBar(
          SnackBar(
            content: Text('Error saving: $e'),
            backgroundColor: Colors.red,
          ),
        );
      }
    }
  }

