  Future<void> _createChecklist(String name) async {
    final cardId = widget.card['id'] as String;
    try {
      // POST /checklists with idCard + name
      final params = <String, String>{
        'key': widget.apiKey,
        'token': widget.token,
        'idCard': cardId,
        'name': name,
      };
      final uri = Uri.https('api.trello.com', '/1/checklists', params);
      final client = HttpClient();
      try {
        final req = await client.postUrl(uri);
        req.headers.contentLength = 0;
        final res = await req.close();
        final body = await _readBody(res);
        if (res.statusCode != 200 && res.statusCode != 201) {
          throw Exception('${res.statusCode}: $body');
        }
      } finally {
        client.close();
      }
      await _fetchChecklists();
    } catch (e) {
      if (mounted) {
        ScaffoldMessenger.of(context).showSnackBar(
          SnackBar(
            content: Text('Error creating checklist: $e'),
            backgroundColor: Colors.red,
          ),
        );
      }
    }
  }

