  /// Remove from Chaos Control all Trello-sourced tasks that match the selected
  /// modes across the entire board.
  void _cleanByModes(String cardMode, String checklistMode, String itemMode) {
    final removeCards = cardMode != 'none';
    final removeChecklists = checklistMode != 'none';
    final removeItems = itemMode != 'none';
    final toRemove = <String>{};

    for (final t in widget.allTasks) {
      if (removeCards && t.id.startsWith('trello_card_')) toRemove.add(t.id);
      if (removeChecklists && t.id.startsWith('trello_checklist_'))
        toRemove.add(t.id);
      if (removeItems && t.id.startsWith('trello_item_')) toRemove.add(t.id);
    }
    for (final id in toRemove) widget.onRemoveTask(id);
  }

  /// Remove from Chaos Control the tasks belonging to *this specific card* that
  /// match the selected modes.
  void _cleanCardByModes(String cardMode, String checkMode, String itemMode) {
    final cardId = widget.card['id'] as String;
    final toRemove = <String>{};

    if (cardMode != 'none') {
      toRemove.add('trello_card_$cardId');
    }
    if (checkMode != 'none') {
      for (final cl in _checklists) {
        toRemove.add('trello_checklist_${cl['id']}');
      }
    }
    if (itemMode != 'none') {
      for (final cl in _checklists) {
        for (final raw in (cl['checkItems'] as List? ?? [])) {
          toRemove.add('trello_item_${(raw as Map)['id']}');
        }
      }
    }

    for (final id in toRemove) widget.onRemoveTask(id);
    // Also update local canvas state
    setState(() => _localInCanvas.removeAll(toRemove));
  }

  /// Apply per-card import settings: convert this card/checklists/items
  /// according to the selected modes, respecting cascade rules.
  /// Always ADDS — never toggles off tasks that already exist.
  void _applyCardImport(String cardMode, String checkMode, String itemMode) {
    final addCard = cardMode != 'none';
    final addChecklists = cardMode == 'cascade' || checkMode != 'none';
    final addItems =
        cardMode == 'cascade' || checkMode == 'cascade' || itemMode != 'none';

    final cardId = 'trello_card_${widget.card['id']}';
    final clsRaw = _checklists; // already fetched

    // Only call onConvertTask for IDs not yet in allTasks to avoid
    // the toggle-off behaviour (which removes rather than adds).
    bool notInCanvas(String id) => !widget.allTasks.any((t) => t.id == id);

    if (addCard && notInCanvas(cardId)) {
      // Situation 1-style: card + optional checklists + optional items
      widget.onConvertTask(
        cardId,
        true,
        widget.card,
        addChecklists
            ? clsRaw.map((cl) {
                if (!addItems) {
                  return {...cl, 'checkItems': <dynamic>[]};
                }
                return cl;
              }).toList()
            : [],
      );
    } else if (!addCard && addChecklists) {
      // Checklists only, no card
      for (final cl in clsRaw) {
        final clId = 'trello_checklist_${cl['id']}';
        if (notInCanvas(clId)) {
          widget.onConvertTask(
            clId,
            false,
            {'name': cl['name']},
            addItems
                ? [cl]
                : [
                    {...cl, 'checkItems': <dynamic>[]},
                  ],
          );
        }
      }
    } else if (!addCard && !addChecklists && addItems) {
      // Items only
      for (final cl in clsRaw) {
        for (final raw in (cl['checkItems'] as List? ?? [])) {
          final item = Map<String, dynamic>.from(raw as Map);
          final itemId = 'trello_item_${item['id']}';
          if (notInCanvas(itemId)) {
            widget.onConvertTask(itemId, false, {'name': item['name']}, null);
          }
        }
      }
    }

    // Update local canvas state
    setState(() {
      if (addCard) _localInCanvas.add(cardId);
      for (final cl in clsRaw) {
        final clId = 'trello_checklist_${cl['id']}';
        if (addChecklists) _localInCanvas.add(clId);
        for (final raw in (cl['checkItems'] as List? ?? [])) {
          final item = Map<String, dynamic>.from(raw as Map);
          final itemId = 'trello_item_${item['id']}';
          if (addItems) _localInCanvas.add(itemId);
        }
      }
    });
  }

