  // ── Trello write helpers for card page ────────────────────────────────────

  Future<void> _updateChecklistName(String clId, String name) async {
    try {
      await _put('/checklists/$clId', {'name': name});
      await _fetchChecklists();
    } catch (e) {
      if (mounted)
        ScaffoldMessenger.of(context).showSnackBar(
          SnackBar(content: Text('Error: $e'), backgroundColor: Colors.red),
        );
    }
  }

  Future<void> _updateItemName(
    String cardId,
    String itemId,
    String name,
  ) async {
    try {
      await _put('/cards/$cardId/checkItem/$itemId', {'name': name});
      await _fetchChecklists();
    } catch (e) {
      if (mounted)
        ScaffoldMessenger.of(context).showSnackBar(
          SnackBar(content: Text('Error: $e'), backgroundColor: Colors.red),
        );
    }
  }

  Future<void> _addChecklistItem(String clId, String name) async {
    final cardId = widget.card['id'] as String;
    final params = <String, String>{
      'key': widget.apiKey,
      'token': widget.token,
      'name': name,
      'idChecklist': clId,
    };
    final uri = Uri.https(
      'api.trello.com',
      '/1/cards/$cardId/checkItem',
      params,
    );
    final client = HttpClient();
    try {
      final req = await client.postUrl(uri);
      req.headers.contentLength = 0;
      final res = await req.close();
      final body = await _readBody(res);
      if (res.statusCode != 200 && res.statusCode != 201) {
        throw Exception('${res.statusCode}: $body');
      }
      await _fetchChecklists();
    } finally {
      client.close();
    }
  }

  Future<void> _deleteChecklistItem(String itemId) async {
    final cardId = widget.card['id'] as String;
    final params = <String, String>{
      'key': widget.apiKey,
      'token': widget.token,
    };
    final uri = Uri.https(
      'api.trello.com',
      '/1/cards/$cardId/checkItem/$itemId',
      params,
    );
    final client = HttpClient();
    try {
      final req = await client.deleteUrl(uri);
      final res = await req.close();
      await _readBody(res);
      await _fetchChecklists();
    } finally {
      client.close();
    }
  }

  Future<void> _reorderChecklistItem(
    String cardId,
    String itemId,
    double newPos,
  ) async {
    try {
      await _put('/cards/$cardId/checkItem/$itemId', {
        'pos': newPos.toStringAsFixed(4),
      });
    } catch (e) {
      debugPrint('_reorderChecklistItem error: $e');
    }
  }

  Future<void> _deleteChecklist(String clId) async {
    final params = <String, String>{
      'key': widget.apiKey,
      'token': widget.token,
    };
    final uri = Uri.https('api.trello.com', '/1/checklists/$clId', params);
    final client = HttpClient();
    try {
      final req = await client.deleteUrl(uri);
      final res = await req.close();
      await _readBody(res);
      await _fetchChecklists();
    } finally {
      client.close();
    }
  }

