  // ── Checklist ────────────────────────────────────────────────────────────

  Widget _buildChecklist(Map<String, dynamic> cl) {
    final clId = cl['id'] as String;
    final clName = cl['name'] as String? ?? '';
    final items = cl['checkItems'] as List<Map<String, dynamic>>? ?? [];
    final done = items
        .where((i) => (i['state'] as String?) == 'complete')
        .length;
    final pct = items.isEmpty ? 0.0 : done / items.length;
    final cardId = widget.card['id'] as String;
    final clNameCtrl = TextEditingController(text: clName);
    bool addingItem = false;
    final addItemCtrl = TextEditingController();

    return StatefulBuilder(
      builder: (_, setLocal) {
        return Padding(
          padding: const EdgeInsets.only(bottom: 28),
          child: Column(
            crossAxisAlignment: CrossAxisAlignment.stretch,
            children: [
              // ── Checklist header ─────────────────────────────────────────
              Row(
                children: [
                  const Icon(
                    Icons.checklist_rounded,
                    size: 16,
                    color: Colors.white54,
                  ),
                  const SizedBox(width: 8),
                  Expanded(
                    child: TextField(
                      controller: clNameCtrl,
                      style: const TextStyle(
                        fontSize: 14,
                        fontWeight: FontWeight.w600,
                        color: Colors.white70,
                      ),
                      decoration: const InputDecoration(
                        border: InputBorder.none,
                        isDense: true,
                        contentPadding: EdgeInsets.zero,
                      ),
                      onSubmitted: (v) {
                        if (v.trim().isNotEmpty && v.trim() != clName) {
                          _updateChecklistName(clId, v.trim());
                        }
                      },
                    ),
                  ),
                  Text(
                    '$done / ${items.length}',
                    style: TextStyle(
                      fontSize: 11,
                      color: Colors.white.withOpacity(0.35),
                    ),
                  ),
                  const SizedBox(width: 8),
                  _TrelloToggleBtn(
                    isActive: _localInCanvas.contains('trello_checklist_$clId'),
                    onTap: () => _handleConvert(
                      'trello_checklist_$clId',
                      false,
                      {'name': clName},
                      [cl],
                    ),
                  ),
                  const SizedBox(width: 4),
                  // Delete checklist
                  Tooltip(
                    message: 'Delete checklist',
                    child: GestureDetector(
                      onTap: () => _deleteChecklist(clId),
                      child: const Icon(
                        Icons.delete_outline_rounded,
                        size: 14,
                        color: Colors.white30,
                      ),
                    ),
                  ),
                ],
              ),
              const SizedBox(height: 8),
              ClipRRect(
                borderRadius: BorderRadius.circular(3),
                child: LinearProgressIndicator(
                  value: pct,
                  minHeight: 5,
                  backgroundColor: Colors.white.withOpacity(0.07),
                  color: pct == 1.0 ? const Color(0xFF4CAF50) : _accent,
                ),
              ),
              const SizedBox(height: 12),

              // ── Items (drag-to-reorder) ────────────────────────────────
              ReorderableListView(
                shrinkWrap: true,
                physics: const NeverScrollableScrollPhysics(),
                buildDefaultDragHandles: false,
                onReorder: (oldIdx, newIdx) async {
                  if (oldIdx == newIdx) return;
                  // Flutter's ReorderableListView passes newIdx after removal
                  final adjusted = newIdx > oldIdx ? newIdx - 1 : newIdx;
                  final moved = items.removeAt(oldIdx);
                  items.insert(adjusted, moved);
                  setLocal(() {});

                  // Compute interpolated pos for Trello API
                  double newPos;
                  if (items.length == 1) {
                    newPos = 65536;
                  } else if (adjusted == 0) {
                    final nextPos =
                        (items[1]['pos'] as num?)?.toDouble() ?? 65536;
                    newPos = nextPos / 2.0;
                  } else if (adjusted == items.length - 1) {
                    final prevPos =
                        (items[adjusted - 1]['pos'] as num?)?.toDouble() ?? 0;
                    newPos = prevPos + 65536;
                  } else {
                    final prevPos =
                        (items[adjusted - 1]['pos'] as num?)?.toDouble() ?? 0;
                    final nextPos =
                        (items[adjusted + 1]['pos'] as num?)?.toDouble() ??
                        prevPos + 131072;
                    newPos = (prevPos + nextPos) / 2.0;
                  }
                  moved['pos'] = newPos;
                  await _reorderChecklistItem(
                    cardId,
                    moved['id'] as String,
                    newPos,
                  );
                },
                children: items.asMap().entries.map((entry) {
                  final idx = entry.key;
                  final item = entry.value;
                  final itemId = item['id'] as String;
                  final isComplete = (item['state'] as String?) == 'complete';
                  final toggling = _togglingItems.contains(itemId);
                  final itemCtrl = TextEditingController(
                    text: item['name'] as String? ?? '',
                  );

                  return Padding(
                    key: ValueKey(itemId),
                    padding: const EdgeInsets.only(bottom: 2),
                    child: Row(
                      children: [
                        // Drag handle
                        ReorderableDragStartListener(
                          index: idx,
                          child: const Padding(
                            padding: EdgeInsets.only(right: 6),
                            child: Icon(
                              Icons.drag_indicator,
                              size: 14,
                              color: Colors.white24,
                            ),
                          ),
                        ),
                        // Check toggle
                        if (toggling)
                          const SizedBox(
                            width: 18,
                            height: 18,
                            child: CircularProgressIndicator(
                              strokeWidth: 2,
                              color: _accent,
                            ),
                          )
                        else
                          GestureDetector(
                            onTap: () => _toggleItem(clId, itemId, isComplete),
                            child: AnimatedContainer(
                              duration: const Duration(milliseconds: 120),
                              width: 18,
                              height: 18,
                              decoration: BoxDecoration(
                                color: isComplete
                                    ? const Color(0xFF4CAF50).withOpacity(0.2)
                                    : Colors.transparent,
                                borderRadius: BorderRadius.circular(4),
                                border: Border.all(
                                  color: isComplete
                                      ? const Color(0xFF4CAF50)
                                      : Colors.white.withOpacity(0.25),
                                  width: 1.5,
                                ),
                              ),
                              child: isComplete
                                  ? const Icon(
                                      Icons.check_rounded,
                                      size: 11,
                                      color: Color(0xFF4CAF50),
                                    )
                                  : null,
                            ),
                          ),
                        const SizedBox(width: 10),
                        // Editable item name
                        Expanded(
                          child: TextField(
                            controller: itemCtrl,
                            style: TextStyle(
                              fontSize: 13,
                              color: isComplete
                                  ? Colors.white38
                                  : Colors.white70,
                              decoration: isComplete
                                  ? TextDecoration.lineThrough
                                  : null,
                              decorationColor: Colors.white38,
                            ),
                            decoration: const InputDecoration(
                              border: InputBorder.none,
                              isDense: true,
                              contentPadding: EdgeInsets.zero,
                            ),
                            onSubmitted: (v) {
                              if (v.trim().isNotEmpty) {
                                _updateItemName(cardId, itemId, v.trim());
                              }
                            },
                          ),
                        ),
                        // Convert toggle
                        _TrelloToggleBtn(
                          isActive: _localInCanvas.contains(
                            'trello_item_$itemId',
                          ),
                          onTap: () => _handleConvert(
                            'trello_item_$itemId',
                            false,
                            {'name': item['name']},
                            null,
                          ),
                        ),
                        // Delete item
                        Tooltip(
                          message: 'Delete item',
                          child: GestureDetector(
                            onTap: () => _deleteChecklistItem(itemId),
                            child: const Icon(
                              Icons.close_rounded,
                              size: 14,
                              color: Colors.white30,
                            ),
                          ),
                        ),
                      ],
                    ),
                  );
                }).toList(),
              ),

              // ── Add item row ──────────────────────────────────────────────
              if (addingItem)
                Padding(
                  padding: const EdgeInsets.only(top: 6),
                  child: Row(
                    children: [
                      const SizedBox(width: 28), // align with items
                      Expanded(
                        child: TextField(
                          controller: addItemCtrl,
                          autofocus: true,
                          style: const TextStyle(
                            fontSize: 13,
                            color: Colors.white,
                          ),
                          decoration: InputDecoration(
                            hintText: 'Add an item…',
                            hintStyle: TextStyle(
                              fontSize: 13,
                              color: Colors.white.withOpacity(0.25),
                            ),
                            isDense: true,
                            contentPadding: const EdgeInsets.symmetric(
                              horizontal: 8,
                              vertical: 7,
                            ),
                            filled: true,
                            fillColor: Colors.white.withOpacity(0.05),
                            border: OutlineInputBorder(
                              borderRadius: BorderRadius.circular(5),
                              borderSide: const BorderSide(color: _accent),
                            ),
                            enabledBorder: OutlineInputBorder(
                              borderRadius: BorderRadius.circular(5),
                              borderSide: const BorderSide(color: _accent),
                            ),
                            focusedBorder: OutlineInputBorder(
                              borderRadius: BorderRadius.circular(5),
                              borderSide: const BorderSide(color: _accent),
                            ),
                          ),
                        ),
                      ),
                      const SizedBox(width: 6),
                      GestureDetector(
                        onTap: () async {
                          final name = addItemCtrl.text.trim();
                          setLocal(() => addingItem = false);
                          addItemCtrl.clear();
                          if (name.isNotEmpty)
                            await _addChecklistItem(clId, name);
                        },
                        child: Container(
                          padding: const EdgeInsets.symmetric(
                            horizontal: 10,
                            vertical: 7,
                          ),
                          decoration: BoxDecoration(
                            color: _accent.withOpacity(0.12),
                            borderRadius: BorderRadius.circular(5),
                            border: Border.all(color: _accent.withOpacity(0.4)),
                          ),
                          child: const Text(
                            'Add',
                            style: TextStyle(
                              fontSize: 11,
                              color: _accent,
                              fontWeight: FontWeight.w600,
                            ),
                          ),
                        ),
                      ),
                      const SizedBox(width: 6),
                      GestureDetector(
                        onTap: () {
                          setLocal(() => addingItem = false);
                          addItemCtrl.clear();
                        },
                        child: const Icon(
                          Icons.close_rounded,
                          size: 16,
                          color: Colors.white38,
                        ),
                      ),
                    ],
                  ),
                )
              else
                Padding(
                  padding: const EdgeInsets.only(top: 4),
                  child: GestureDetector(
                    onTap: () => setLocal(() => addingItem = true),
                    child: Row(
                      children: [
                        const SizedBox(width: 28),
                        const Icon(Icons.add, size: 14, color: Colors.white30),
                        const SizedBox(width: 6),
                        Text(
                          'Add an item',
                          style: TextStyle(
                            fontSize: 11,
                            color: Colors.white.withOpacity(0.3),
                          ),
                        ),
                      ],
                    ),
                  ),
                ),
            ],
          ),
        );
      },
    );
  }

