// ─────────────────────────────────────────────────────────────────────────────
// _CanvasSectionMenuPanel
// Dropdown panel for a category header row's three-dot button.
// Contains: inline search field (auto-focused, non-dismissing), sort toggle,
// filter/group/sort item, and delete (custom categories only).
// ─────────────────────────────────────────────────────────────────────────────

class _CanvasSectionMenuPanel extends StatefulWidget {
  final String sectionName;
  final bool isFav;
  final bool isAll;
  final String initialQuery;
  final bool sortAsc;
  final ValueChanged<String> onQueryChanged;
  final VoidCallback onFilterGroupSort;
  final VoidCallback? onSettings;
  final VoidCallback? onDelete;

  const _CanvasSectionMenuPanel({
    required this.sectionName,
    required this.isFav,
    required this.isAll,
    required this.initialQuery,
    required this.sortAsc,
    required this.onQueryChanged,
    required this.onFilterGroupSort,
    this.onSettings,
    this.onDelete,
  });

  @override
  State<_CanvasSectionMenuPanel> createState() =>
      _CanvasSectionMenuPanelState();
}

class _CanvasSectionMenuPanelState extends State<_CanvasSectionMenuPanel> {
  late final TextEditingController _ctrl;

  static const _bg = Color(0xFF1E2124);
  static const _surface = Color(0xFF252830);
  static const _border = Color(0xFF2C2F35);
  static const _accent = Color(0xFF4FC3F7);

  @override
  void initState() {
    super.initState();
    _ctrl = TextEditingController(text: widget.initialQuery);
  }

  @override
  void dispose() {
    _ctrl.dispose();
    super.dispose();
  }

  Widget _menuItem({
    required IconData icon,
    required String label,
    required VoidCallback onTap,
    Color iconColor = const Color(0xFF9E9E9E),
    Color labelColor = const Color(0xFFCCCCCC),
    String? badge,
    String? subtitle,
  }) {
    return InkWell(
      onTap: onTap,
      child: Padding(
        padding: const EdgeInsets.symmetric(horizontal: 12, vertical: 9),
        child: Row(
          children: [
            Icon(icon, size: 15, color: iconColor),
            const SizedBox(width: 10),
            Expanded(
              child: Column(
                crossAxisAlignment: CrossAxisAlignment.start,
                mainAxisSize: MainAxisSize.min,
                children: [
                  Text(
                    label,
                    style: TextStyle(
                      fontSize: 12,
                      color: labelColor,
                      fontWeight: FontWeight.w500,
                    ),
                  ),
                  if (subtitle != null)
                    Text(
                      subtitle,
                      style: const TextStyle(
                        fontSize: 10,
                        color: Color(0xFF6E7580),
                      ),
                    ),
                ],
              ),
            ),
            if (badge != null)
              Container(
                margin: const EdgeInsets.only(left: 4),
                padding: const EdgeInsets.symmetric(horizontal: 6, vertical: 2),
                decoration: BoxDecoration(
                  color: _accent.withOpacity(0.15),
                  borderRadius: BorderRadius.circular(4),
                ),
                child: Text(
                  badge,
                  style: const TextStyle(
                    fontSize: 9,
                    color: _accent,
                    fontWeight: FontWeight.w700,
                  ),
                ),
              ),
          ],
        ),
      ),
    );
  }

  @override
  Widget build(BuildContext context) {
    final searchActive = _ctrl.text.isNotEmpty;

    return Container(
      decoration: BoxDecoration(
        color: _bg,
        borderRadius: BorderRadius.circular(8),
        border: Border.all(color: _border),
        boxShadow: [
          BoxShadow(
            color: Colors.black.withOpacity(0.5),
            blurRadius: 16,
            offset: const Offset(0, 4),
          ),
        ],
      ),
      child: Column(
        mainAxisSize: MainAxisSize.min,
        crossAxisAlignment: CrossAxisAlignment.stretch,
        children: [
          // ── Section 1: Inline Search field ────────────────────────────
          Container(
            padding: const EdgeInsets.fromLTRB(10, 8, 10, 6),
            decoration: const BoxDecoration(
              color: _surface,
              borderRadius: BorderRadius.vertical(top: Radius.circular(8)),
            ),
            child: TextField(
              controller: _ctrl,
              autofocus: true,
              onChanged: (v) {
                setState(() {}); // refresh clear-button visibility
                widget.onQueryChanged(v);
              },
              style: const TextStyle(color: Colors.white70, fontSize: 12),
              decoration: InputDecoration(
                isDense: true,
                hintText: 'Search in ${widget.sectionName}…',
                hintStyle: const TextStyle(
                  color: Color(0xFF4A4E57),
                  fontSize: 12,
                ),
                prefixIcon: const Icon(
                  Icons.search,
                  color: Color(0xFF6E7580),
                  size: 14,
                ),
                suffixIcon: searchActive
                    ? GestureDetector(
                        onTap: () {
                          _ctrl.clear();
                          widget.onQueryChanged('');
                          setState(() {});
                        },
                        child: const Icon(
                          Icons.close_rounded,
                          size: 13,
                          color: Color(0xFF6E7580),
                        ),
                      )
                    : null,
                filled: true,
                fillColor: _bg,
                border: OutlineInputBorder(
                  borderRadius: BorderRadius.circular(5),
                  borderSide: const BorderSide(color: _border),
                ),
                enabledBorder: OutlineInputBorder(
                  borderRadius: BorderRadius.circular(5),
                  borderSide: const BorderSide(color: _border),
                ),
                focusedBorder: OutlineInputBorder(
                  borderRadius: BorderRadius.circular(5),
                  borderSide: const BorderSide(color: _accent),
                ),
                contentPadding: const EdgeInsets.symmetric(
                  vertical: 6,
                  horizontal: 8,
                ),
              ),
            ),
          ),

          const Divider(height: 1, color: _border),

          // ── Section 2: Filter / Group / Sort ──────────────────────────
          _menuItem(
            icon: Icons.filter_list_rounded,
            label: 'Filter / Group / Sort',
            iconColor: _accent,
            onTap: widget.onFilterGroupSort,
          ),

          // ── Section 3: Settings (custom categories only) ─────────────
          if (widget.onSettings != null) ...[
            const Divider(height: 1, color: _border),
            _menuItem(
              icon: Icons.settings_outlined,
              label: 'Category Settings',
              iconColor: const Color(0xFF9E9E9E),
              onTap: widget.onSettings!,
            ),
          ],

          // ── Section 4: Delete (custom categories only) ────────────────
          if (widget.onDelete != null) ...[
            const Divider(height: 1, color: _border),
            _menuItem(
              icon: Icons.delete_outline,
              label: 'Delete Category',
              iconColor: Colors.redAccent,
              labelColor: Colors.redAccent,
              onTap: widget.onDelete!,
            ),
          ],

          const SizedBox(height: 4),
        ],
      ),
    );
  }
}

// ─────────────────────────────────────────────────────────────────────────────
// _ProjectFolderMenuPanel
// Dropdown panel for a project folder header row's three-dot button.
// Contains: inline task search, Filter/Group/Sort, canvas-specific actions
// (Favorite, Change Color, Add to Category), shared project actions, Delete.
// ─────────────────────────────────────────────────────────────────────────────

class _ProjectFolderMenuPanel extends StatefulWidget {
  final String projectId;
  final String initialQuery;
  final ValueChanged<String> onQueryChanged;
  final ValueChanged<String> onAction;
  final VoidCallback onFilterGroupSort;

  // Canvas-specific (optional — omit for Tasks sidebar use)
  final bool isFav;
  final List<String> categories;
  final Map<String, bool> categoryMembership;
  final VoidCallback? onToggleFavorite;
  final VoidCallback? onChangeColor;

  /// Called with (categoryName, nowInCategory) when a checkbox is toggled.
  final void Function(String cat, bool nowIn)? onToggleCategory;

  /// When false the "Delete Project" row is hidden (e.g. for the Inbox
  /// pseudo-project which cannot be deleted).
  final bool showDelete;

  const _ProjectFolderMenuPanel({
    required this.projectId,
    required this.initialQuery,
    required this.onQueryChanged,
    required this.onAction,
    required this.onFilterGroupSort,
    this.isFav = false,
    this.categories = const [],
    this.categoryMembership = const {},
    this.onToggleFavorite,
    this.onChangeColor,
    this.onToggleCategory,
    this.showDelete = true,
  });

  @override
  State<_ProjectFolderMenuPanel> createState() =>
      _ProjectFolderMenuPanelState();
}

class _ProjectFolderMenuPanelState extends State<_ProjectFolderMenuPanel> {
  late final TextEditingController _ctrl;
  late bool _localIsFav;
  late Map<String, bool> _localCatMembership;
  bool _categoryExpanded = false;

  static const _bg = Color(0xFF1E2124);
  static const _surface = Color(0xFF252830);
  static const _border = Color(0xFF2C2F35);
  static const _accent = Color(0xFF4FC3F7);

  @override
  void initState() {
    super.initState();
    _ctrl = TextEditingController(text: widget.initialQuery);
    _localIsFav = widget.isFav;
    _localCatMembership = Map.from(widget.categoryMembership);
  }

  @override
  void dispose() {
    _ctrl.dispose();
    super.dispose();
  }

  Widget _item(
    IconData icon,
    String label,
    String action, {
    Color color = const Color(0xFFCCCCCC),
  }) {
    return InkWell(
      onTap: () => widget.onAction(action),
      child: Padding(
        padding: const EdgeInsets.symmetric(horizontal: 12, vertical: 9),
        child: Row(
          children: [
            Icon(icon, size: 15, color: color),
            const SizedBox(width: 10),
            Text(
              label,
              style: TextStyle(
                fontSize: 12,
                color: color,
                fontWeight: FontWeight.w500,
              ),
            ),
          ],
        ),
      ),
    );
  }

  Widget _canvasActionRow({
    required IconData icon,
    required String label,
    required Color color,
    required VoidCallback onTap,
    Widget? trailing,
  }) {
    return InkWell(
      onTap: onTap,
      child: Padding(
        padding: const EdgeInsets.symmetric(horizontal: 12, vertical: 9),
        child: Row(
          children: [
            Icon(icon, size: 15, color: color),
            const SizedBox(width: 10),
            Expanded(
              child: Text(
                label,
                style: TextStyle(
                  fontSize: 12,
                  color: color,
                  fontWeight: FontWeight.w500,
                ),
              ),
            ),
            if (trailing != null) trailing,
          ],
        ),
      ),
    );
  }

  @override
  Widget build(BuildContext context) {
    final searchActive = _ctrl.text.isNotEmpty;
    final hasCanvasActions =
        widget.onToggleFavorite != null ||
        widget.onChangeColor != null ||
        widget.onToggleCategory != null;

    return Container(
      decoration: BoxDecoration(
        color: _bg,
        borderRadius: BorderRadius.circular(8),
        border: Border.all(color: _border),
        boxShadow: [
          BoxShadow(
            color: Colors.black.withOpacity(0.5),
            blurRadius: 16,
            offset: const Offset(0, 4),
          ),
        ],
      ),
      child: Column(
        mainAxisSize: MainAxisSize.min,
        crossAxisAlignment: CrossAxisAlignment.stretch,
        children: [
          // ── Inline task search ─────────────────────────────────────────
          Container(
            padding: const EdgeInsets.fromLTRB(10, 8, 10, 6),
            decoration: const BoxDecoration(
              color: _surface,
              borderRadius: BorderRadius.vertical(top: Radius.circular(8)),
            ),
            child: TextField(
              controller: _ctrl,
              autofocus: true,
              onChanged: (v) {
                setState(() {});
                widget.onQueryChanged(v);
              },
              style: const TextStyle(color: Colors.white70, fontSize: 12),
              decoration: InputDecoration(
                isDense: true,
                hintText: 'Search tasks…',
                hintStyle: const TextStyle(
                  color: Color(0xFF4A4E57),
                  fontSize: 12,
                ),
                prefixIcon: const Icon(
                  Icons.search,
                  color: Color(0xFF6E7580),
                  size: 14,
                ),
                suffixIcon: searchActive
                    ? GestureDetector(
                        onTap: () {
                          _ctrl.clear();
                          widget.onQueryChanged('');
                          setState(() {});
                        },
                        child: const Icon(
                          Icons.close_rounded,
                          size: 13,
                          color: Color(0xFF6E7580),
                        ),
                      )
                    : null,
                filled: true,
                fillColor: _bg,
                border: OutlineInputBorder(
                  borderRadius: BorderRadius.circular(5),
                  borderSide: const BorderSide(color: _border),
                ),
                enabledBorder: OutlineInputBorder(
                  borderRadius: BorderRadius.circular(5),
                  borderSide: const BorderSide(color: _border),
                ),
                focusedBorder: OutlineInputBorder(
                  borderRadius: BorderRadius.circular(5),
                  borderSide: const BorderSide(color: _accent),
                ),
                contentPadding: const EdgeInsets.symmetric(
                  vertical: 6,
                  horizontal: 8,
                ),
              ),
            ),
          ),

          const Divider(height: 1, color: _border),

          // ── Filter / Group / Sort ──────────────────────────────────────
          InkWell(
            onTap: widget.onFilterGroupSort,
            child: Padding(
              padding: const EdgeInsets.symmetric(horizontal: 12, vertical: 9),
              child: Row(
                children: const [
                  Icon(Icons.filter_list_rounded, size: 15, color: _accent),
                  SizedBox(width: 10),
                  Text(
                    'Filter / Group / Sort',
                    style: TextStyle(
                      fontSize: 12,
                      color: _accent,
                      fontWeight: FontWeight.w500,
                    ),
                  ),
                ],
              ),
            ),
          ),

          const Divider(height: 1, color: _border),

          // ── Canvas-specific actions ────────────────────────────────────
          if (hasCanvasActions) ...[
            // Favorite toggle
            if (widget.onToggleFavorite != null)
              _canvasActionRow(
                icon: _localIsFav
                    ? Icons.star_rounded
                    : Icons.star_border_rounded,
                label: _localIsFav ? 'Remove Favorite' : 'Mark as Favorite',
                color: _localIsFav
                    ? const Color(0xFFFFCA28)
                    : const Color(0xFFCCCCCC),
                onTap: () {
                  setState(() => _localIsFav = !_localIsFav);
                  widget.onToggleFavorite!();
                },
              ),

            // Change Color
            if (widget.onChangeColor != null)
              _canvasActionRow(
                icon: Icons.palette_outlined,
                label: 'Change Color',
                color: const Color(0xFFCCCCCC),
                onTap: widget.onChangeColor!,
              ),

            // Add to Category — inline expandable with scrollable checkboxes
            if (widget.onToggleCategory != null &&
                widget.categories.isNotEmpty) ...[
              _canvasActionRow(
                icon: Icons.folder_copy_outlined,
                label: 'Add to Category',
                color: const Color(0xFFCCCCCC),
                onTap: () =>
                    setState(() => _categoryExpanded = !_categoryExpanded),
                trailing: AnimatedRotation(
                  turns: _categoryExpanded ? 0.25 : 0,
                  duration: const Duration(milliseconds: 150),
                  child: const Icon(
                    Icons.chevron_right_rounded,
                    size: 14,
                    color: Color(0xFF6E7580),
                  ),
                ),
              ),
              // Inline scrollable category checkbox list
              AnimatedCrossFade(
                duration: const Duration(milliseconds: 180),
                crossFadeState: _categoryExpanded
                    ? CrossFadeState.showSecond
                    : CrossFadeState.showFirst,
                firstChild: const SizedBox.shrink(),
                secondChild: Container(
                  constraints: const BoxConstraints(maxHeight: 152),
                  decoration: const BoxDecoration(
                    color: _surface,
                    border: Border(
                      top: BorderSide(color: _border),
                      bottom: BorderSide(color: _border),
                    ),
                  ),
                  child: ListView.builder(
                    shrinkWrap: true,
                    padding: const EdgeInsets.symmetric(vertical: 4),
                    itemCount: widget.categories.length,
                    itemBuilder: (_, idx) {
                      final cat = widget.categories[idx];
                      final inCat = _localCatMembership[cat] ?? false;
                      return InkWell(
                        onTap: () {
                          final nowIn = !inCat;
                          setState(() => _localCatMembership[cat] = nowIn);
                          widget.onToggleCategory!(cat, nowIn);
                        },
                        child: Padding(
                          padding: const EdgeInsets.symmetric(
                            horizontal: 14,
                            vertical: 7,
                          ),
                          child: Row(
                            children: [
                              AnimatedSwitcher(
                                duration: const Duration(milliseconds: 120),
                                child: Icon(
                                  inCat
                                      ? Icons.check_box_rounded
                                      : Icons.check_box_outline_blank_rounded,
                                  key: ValueKey(inCat),
                                  size: 15,
                                  color: inCat
                                      ? _accent
                                      : const Color(0xFF555A64),
                                ),
                              ),
                              const SizedBox(width: 10),
                              Expanded(
                                child: Text(
                                  cat,
                                  style: TextStyle(
                                    fontSize: 12,
                                    color: inCat
                                        ? Colors.white70
                                        : const Color(0xFF888D97),
                                    fontWeight: inCat
                                        ? FontWeight.w500
                                        : FontWeight.normal,
                                  ),
                                  overflow: TextOverflow.ellipsis,
                                ),
                              ),
                            ],
                          ),
                        ),
                      );
                    },
                  ),
                ),
              ),
            ],

            const Divider(height: 1, color: _border),
          ],

          // ── Shared project actions ─────────────────────────────────────
          _item(Icons.history_rounded, 'Quick History', 'quick_history'),
          _item(Icons.calendar_today_outlined, 'Worklog', 'worklog'),
          _item(Icons.sync_rounded, 'Metrics', 'metrics'),
          _item(Icons.settings_outlined, 'Settings', 'settings'),

          if (widget.showDelete) ...[
            const Divider(height: 1, color: _border),
            _item(
              Icons.delete_outline,
              'Delete Project',
              'delete',
              color: Colors.redAccent,
            ),
          ],

          const SizedBox(height: 4),
        ],
      ),
    );
  }
}

// ─────────────────────────────────────────────────────────────────────────────
// _TrelloToggleBtn — convert/remove toggle used on cards and checklist items.
// When isActive (already a Chaos Control task) it shows teal with a tick icon;
// on hover it switches to red "Remove from Chaos Control" affordance.
// ─────────────────────────────────────────────────────────────────────────────

class _TrelloToggleBtn extends StatefulWidget {
  final bool isActive;
  final VoidCallback onTap;

  const _TrelloToggleBtn({required this.isActive, required this.onTap});

  @override
  State<_TrelloToggleBtn> createState() => _TrelloToggleBtnState();
}

class _TrelloToggleBtnState extends State<_TrelloToggleBtn> {
  bool _hovered = false;

  @override
  Widget build(BuildContext context) {
    const accent = Color(0xFF4FC3F7);
    const green = Color(0xFF4CAF50);
    const red = Colors.redAccent;

    // When active + hovered → show "remove" affordance in red
    final showRemove = widget.isActive && _hovered;
    final color = showRemove
        ? red
        : widget.isActive
        ? green
        : (_hovered ? accent : const Color(0x554FC3F7));

    final icon = showRemove
        ? Icons.remove_circle_outline_rounded
        : widget.isActive
        ? Icons.task_alt_rounded
        : Icons.add_task_rounded;

    final tooltip = showRemove
        ? 'Remove from Chaos Control'
        : widget.isActive
        ? 'In Chaos Control (click to remove)'
        : 'Convert to Chaos Control task';

    return MouseRegion(
      cursor: SystemMouseCursors.click,
      onEnter: (_) => setState(() => _hovered = true),
      onExit: (_) => setState(() => _hovered = false),
      child: Tooltip(
        message: tooltip,
        child: GestureDetector(
          onTap: widget.onTap,
          child: AnimatedContainer(
            duration: const Duration(milliseconds: 130),
            width: 22,
            height: 22,
            decoration: BoxDecoration(
              color: (widget.isActive || _hovered)
                  ? color.withOpacity(0.15)
                  : Colors.transparent,
              borderRadius: BorderRadius.circular(5),
            ),
            child: Icon(icon, size: 14, color: color),
          ),
        ),
      ),
    );
  }
}

// ─────────────────────────────────────────────────────────────────────────────
// _ImportTriState — 3-state import selector: none / single / cascade
// ─────────────────────────────────────────────────────────────────────────────

class _ImportTriState extends StatefulWidget {
  final String label;
  final String sublabel;

  /// 'none' | 'single' | 'cascade'
  final String mode;
  final bool allowCascade;
  final void Function(String) onChanged;

  const _ImportTriState({
    required this.label,
    required this.sublabel,
    required this.mode,
    required this.onChanged,
    this.allowCascade = true,
  });

  @override
  State<_ImportTriState> createState() => _ImportTriStateState();
}

class _ImportTriStateState extends State<_ImportTriState> {
  bool _hovered = false;

  static const _accent = Color(0xFF4FC3F7);

  void _cycle() {
    final states = widget.allowCascade
        ? ['none', 'single', 'cascade']
        : ['none', 'single'];
    final next = states[(states.indexOf(widget.mode) + 1) % states.length];
    widget.onChanged(next);
  }

  @override
  Widget build(BuildContext context) {
    final mode = widget.mode;
    final isNone = mode == 'none';
    final isSingle = mode == 'single';
    final isCascade = mode == 'cascade';
    final isActive = !isNone;

    return MouseRegion(
      cursor: SystemMouseCursors.click,
      onEnter: (_) => setState(() => _hovered = true),
      onExit: (_) => setState(() => _hovered = false),
      child: GestureDetector(
        onTap: _cycle,
        child: Row(
          crossAxisAlignment: CrossAxisAlignment.center,
          children: [
            // ── 3-state box ───────────────────────────────────────────
            AnimatedContainer(
              duration: const Duration(milliseconds: 130),
              width: 20,
              height: 20,
              decoration: BoxDecoration(
                color: isActive
                    ? _accent.withOpacity(0.15)
                    : (_hovered
                          ? Colors.white.withOpacity(0.05)
                          : Colors.transparent),
                borderRadius: BorderRadius.circular(5),
                border: Border.all(
                  color: isActive
                      ? _accent.withOpacity(0.7)
                      : Colors.white.withOpacity(0.22),
                  width: 1.5,
                ),
              ),
              child: Center(
                child: isNone
                    ? null
                    : isSingle
                    ? Text(
                        '1',
                        style: TextStyle(
                          fontSize: 11,
                          fontWeight: FontWeight.w800,
                          color: _accent,
                          height: 1,
                        ),
                      )
                    : Icon(Icons.filter_alt_rounded, size: 12, color: _accent),
              ),
            ),
            const SizedBox(width: 10),
            // ── Label + sublabel ──────────────────────────────────────
            Expanded(
              child: Column(
                crossAxisAlignment: CrossAxisAlignment.start,
                children: [
                  Text(
                    widget.label,
                    style: TextStyle(
                      fontSize: 12,
                      color: isActive ? Colors.white : Colors.white54,
                      fontWeight: isActive
                          ? FontWeight.w600
                          : FontWeight.normal,
                    ),
                  ),
                  Text(
                    _modeHint(mode, widget.sublabel),
                    style: TextStyle(
                      fontSize: 10,
                      color: Colors.white.withOpacity(isActive ? 0.45 : 0.25),
                    ),
                  ),
                ],
              ),
            ),
            // ── Mode badge ────────────────────────────────────────────
            if (!isNone)
              AnimatedContainer(
                duration: const Duration(milliseconds: 130),
                padding: const EdgeInsets.symmetric(horizontal: 6, vertical: 2),
                decoration: BoxDecoration(
                  color: _accent.withOpacity(0.1),
                  borderRadius: BorderRadius.circular(4),
                ),
                child: Text(
                  isSingle ? 'Only this' : 'Cascades',
                  style: const TextStyle(
                    fontSize: 9,
                    color: _accent,
                    fontWeight: FontWeight.w600,
                    letterSpacing: 0.3,
                  ),
                ),
              ),
          ],
        ),
      ),
    );
  }

  String _modeHint(String mode, String sublabel) {
    switch (mode) {
      case 'single':
        return '$sublabel → Task only';
      case 'cascade':
        return '$sublabel → Task + children';
      default:
        return sublabel;
    }
  }
}
